INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 1, 'Article 1er. - Le présent décret s''applique à l''enseignement maternel, primaire,', 'Article 1er. - Le présent décret s''applique à l''enseignement maternel, primaire, 
fondamental, secondaire, ordinaire et spécialisé, de plein exercice ou en alternance, 
secondaire artistique à horaire réduit ou de promotion sociale, organisé ou 
subventionné par la Communauté française, à l''exception des sections 4 et 5 des 
Chapitres Ier, II et III du Titre III. 
 
Complété par D. 13-09-2018 ; modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 2, 'Article 2. - § 1er. Pour l''application du présent décret, il y a lieu d''entendre par :', 'Article 2. - § 1er. Pour l''application du présent décret, il y a lieu d''entendre par : 
1° «directeur» : le membre du personnel titulaire, à quelque titre que ce soit, de la 
fonction de promotion de directeur d''école maternelle, de directeur d''école primaire, de 
directeur d''école fondamentale, de directeur de l''enseignement secondaire inférieur, de 
directeur, de directeur d''établissement de promotion sociale telles qu''énumérées aux 
articles 3 et 4, § 1er, 1° et 2°, et § 2, du décret du 4 janvier 1999 relatif aux fonctions de 
promotion et de sélection, ou de directeur de l''enseignement secondaire artistique à 
horaire réduit tel que prévu à l''article 50, 2°, du décret du 2 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française; [remplacé par D. 14-03-2019] 
2° «équipe éducative» : l''ensemble des membres du personnel exerçant toute ou 
partie de leur(s) fonction(s) dans un même établissement ou dans une même 
implantation, à l''exclusion du personnel administratif, et du personnel de maîtrise, 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
gens de métier et de service. 
3° «pouvoir organisateur» : l''autorité publique ou la personne morale qui assume 
la responsabilité de l''organisation d''une école organisée ou subventionnée par la 
Communauté française; [inséré par D. 13-09-2018] 
4° «organes locaux de concertation sociale » : les instances de concertation locale 
instituées en vertu de la loi du 19 décembre 1974 organisant les relations entre les 
autorités publiques et les syndicats des agents relevant de ces autorités, de la loi du 20 
septembre 1948 portant organisation de l''économie, de l''arrêté du Gouvernement de la 
Communauté française du 13 septembre 1995 relatif à la création, à la composition et 
aux attributions des commissions paritaires locales dans l''enseignement officiel 
subventionné, de l''arrêté du Gouvernement de la Communauté française du 27 mars 
1996 rendant obligatoire la décision du 24 janvier 1996 de la Commission paritaire de 
l''Enseignement fondamental libre confessionnel relative à la création d''une instance 
de concertation locale entre pouvoirs organisateurs et délégations syndicales et de 
l''arrêté du Gouvernement de la Communauté française du 18 juin 1999 rendant 
obligatoire la décision du 31 mai 1999 de la Commission paritaire de l''enseignement 
fondamental libre non confessionnel relative à la création d''une instance de 
concertation locale entre pouvoirs organisateurs et délégations syndicales, soit : 
a)dans l''enseignement organisé par la Communauté française, le comité de 
concertation de base; 
b) dans l''enseignement officiel subventionné, la commission paritaire locale; 
c) dans l''enseignement libre subventionné, le conseil d''entreprise ou, à défaut, le 
Comité pour la prévention et protection au travail ou, à défaut, l''instance de 
concertation locale ou, à défaut, la délégation syndicale. [Inséré par D. 13-09-2018] ; 
5° plan de pilotage : le dispositif visé à l''article 67, § 2, du décret du 24 juillet 
1997 définissant les missions prioritaires de l''enseignement fondamental et de 
l''enseignement secondaire et organisant les structures propres à les atteindre; [inséré 
par D. 14-03-2019] 
6° : fédérations de pouvoirs organisateurs : les organes de représentation et de 
coordination visés à l''article 5 de la loi du 29 mai 1959 modifiant certaines dispositions 
de la législation de l''enseignement. [Inséré par D. 14-03-2019] 
 
Le terme «élève» utilisé dans le présent décret doit s''entendre comme «étudiant» 
pour ce qui concerne l''enseignement de promotion sociale. [Inséré par D. 14-03-2019] 
 
§ 2. L''emploi dans le présent décret des noms masculins pour les différents titres 
et fonctions est épicène en vue d''assurer la lisibilité du texte nonobstant les 
dispositions du décret du 21 juin 1993 relatif à la féminisation des noms de métier. 
 
TITRE II. - Des dispositions communes aux directeurs de tous les réseaux 
 
Intitulé modifié par D. 14-03-2019 
CHAPITRE Ier. - Du profil de fonction des directeurs  
 
Intitulé remplacé par D. 14-03-2019 
Section Ire. - Des responsabilités du directeur 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 3, 'Article 3. - Le directeur a une compétence générale de pilotage et d''organisation', 'Article 3. - Le directeur a une compétence générale de pilotage et d''organisation 
de l''établissement. 
 
Il assume les responsabilités que son pouvoir organisateur lui confie selon le 
cadre fixé par la lettre de mission visée au chapitre III du présent titre. 
 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 4, 'Article 4. - Dans l''enseignement organisé par la Communauté française, le', 'Article 4. - Dans l''enseignement organisé par la Communauté française, le 
directeur d''une école maternelle, primaire ou fondamentale annexée, assume ses 
responsabilités sans préjudice des responsabilités confiées au directeur de 
l''établissement auquel son école est annexée. 
 
Intitulé remplacé par D. 14-03-2019 
Section II. – Du profil de fonction 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 5, 'Article 5. - § 1er. Le Gouvernement arrête un profil de fonction-type du directeur (partie 1)', 'Article 5. - § 1er. Le Gouvernement arrête un profil de fonction-type du directeur d''école et le met à la disposition des pouvoirs organisateurs qui peuvent l''utiliser en vue de construire le profil de fonction visé au § 2. Le profil de fonction-type comprend un référentiel de responsabilités et une liste des compétences comportementales et techniques attendues. Les responsabilités décrites dans le profil de fonction-type sont structurées en sept catégories : 1° production de sens; 2° pilotage stratégique et opérationnel global de l''école; 3° pilotage des actions et des projets pédagogiques; 4° gestion des ressources et des relations humaines; 5° communication interne et externe; 6° gestion administrative, financière et matérielle de l''établissement.; 7° planification et gestion active de son propre développement professionnel. Les compétences comportementales et techniques attendues sont assorties d''indicateurs de maîtrise. § 2. En vue de tout appel à candidatures à une fonction de directeur visée au chapitre V, le pouvoir organisateur établit un profil de fonction, qu''il joint à tout appel à candidatures à une fonction de directeur. Le profil de fonction définit : 1° les responsabilités principales du directeur; 2° les compétences comportementales et techniques nécessaires à leur exercice. Les compétences comportementales et techniques visées à l''alinéa précédent sont assorties d''indicateurs de maîtrise. Le pouvoir organisateur construit le profil de fonction, d''une part, à partir du profil de fonction-type visé au § 1er et, d''autre part, en tenant compte des besoins spécifiques liés à son projet éducatif et pédagogique ainsi que des caractéristiques propres de l''école dans laquelle le poste de directeur est à pourvoir. Le profil de fonction reprend les critères principaux de sélection des candidats et la pondération attribuée à chacun d''eux. Il peut comprendre des conditions de recrutement complémentaires, soit obligatoires, soit constituant un atout pour le poste à pourvoir. § 3. Dans le profil de fonction visé au paragraphe précédent, les responsabilités du directeur sont structurées en sept catégories, conformément au profil de fonction- type. § 4. Dans les catégories visées au paragraphe précédent, pour que la Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Communauté française soit assurée que toutes les écoles reprennent dans le profil de fonction qu''elles établissent, les responsabilités essentielles d''un directeur, le profil de fonction reprend, a minima, les responsabilités suivantes : 1° production de sens : le directeur explique régulièrement aux acteurs de l''école quelles sont les valeurs sur lesquelles se fonde l''action pédagogique et éducative, développée au service des élèves, dans le cadre du projet du pouvoir organisateur et donne ainsi du sens à l''action collective et aux actions individuelles, en référence à ces valeurs ainsi qu''aux missions prioritaires et particulières du système éducatif de la Communauté française et aux finalités de l''enseignement de promotion sociale et de l''enseignement secondaire artistique à horaire réduit; 2° pilotage stratégique et opérationnel global de l''école : a) dans l''enseignement maternel et dans l''enseignement obligatoire, le directeur est le garant des projets éducatif et pédagogique du pouvoir organisateur, définis dans le respect des finalités et des missions prioritaires et particulières du système éducatif de la Communauté française; dans l''enseignement de promotion sociale, le directeur est le garant du projet pédagogique du pouvoir organisateur définis dans le respect des finalités de cet enseignement; dans l''enseignement secondaire artistique à horaire réduit, le directeur est le garant des projets éducatif et pédagogique du pouvoir organisateur et du projet pédagogique et artistique de l''établissement, définis dans le respect des finalités de cet enseignement; b) dans l''enseignement maternel et dans l''enseignement obligatoire, en tant que leader pédagogique et éducatif, le directeur pilote la co-construction du projet d''établissement et du plan de pilotage de l''école, en menant à bien le processus de contractualisation y afférent ainsi que la mise en oeuvre collective du contrat d''objectifs (ou le cas échéant, le protocole de collaboration); 3° pilotage des actions et des projets pédagogiques : a) le directeur garantit le soutien et l''accompagnement du parcours scolaire de chacun des élèves et leur orientation positive; b) le directeur favorise un leadership pédagogique partagé; c) le directeur assure le pilotage pédagogique de l''établissement; 4° gestion des ressources et des relations humaines : a) le directeur organise les services de l''ensemble des membres du personnel, coordonne leur travail, fixe les objectifs dans le cadre de leurs compétences et des textes qui régissent leur fonction. Il assume, en particulier, la responsabilité pédagogique et administrative de décider des horaires et attributions des membres du perso');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 6, 'Article 5. - § 1er. Le Gouvernement arrête un profil de fonction-type du directeur (partie 2)', 'b) dans l''enseignement maternel et dans l''enseignement obligatoire, le directeur développe avec l''équipe éducative une dynamique collective et soutient le travail collaboratif dans une visée de partage de pratiques et d''organisation apprenante; dans l''enseignement de promotion sociale, le directeur soutient le travail en équipe dans une visée de partage de pratiques et d''organisation apprenante; c) le directeur collabore avec le pouvoir organisateur pour construire, une équipe éducative et enseignante centrée sur l''élève, son développement et ses apprentissages; d) le directeur soutient le développement professionnel des membres du personnel; e) le directeur accompagne les équipes éducatives dans les innovations qu''elles mettent en oeuvre et le changement; f) le directeur veille à l''accueil et à l''intégration des nouveaux membres du personnel ainsi qu''à l''accompagnement des personnels en difficulté; g) le directeur veille, le cas échéant, à la bonne organisation des organes locaux de concertation sociale légaux et conventionnels; h) le directeur est le représentant du pouvoir organisateur auprès des Services du Gouvernement; i) le directeur peut nouer des contacts avec le monde économique et socioculturel local de même qu''avec des organismes de protection de la jeunesse, d''aide à l''enfance Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 et d''aide à la jeunesse; 5° communication interne et externe : le directeur recueille et fait circuler de l''information en la formulant de manière adaptée et au moyen des dispositifs adéquats à l''attention, respectivement, du Pouvoir organisateur, des membres du personnel, des élèves, et, s''il échet, des parents et des agents du Centre psycho-médico-social, ainsi que, en tant qu''interface, avec les partenaires et interlocuteurs extérieurs; 6° gestion administrative, financière et matérielle de l''établissement : a) le directeur veille au respect des dispositions légales et réglementaires; b) le directeur assure la gestion du budget pour lequel il a reçu délégation, en vue de parvenir à un fonctionnement optimal de l''école et à la réalisation de ses objectifs; 7° planification et gestion active de son propre développement professionnel : a) le directeur s''enrichit continûment de nouvelles idées, compétences et connaissances; b) le directeur a des entretiens de fonctionnement réguliers avec le pouvoir organisateur ou les délégués de celui-ci, en référence à sa lettre de mission et à son auto-évaluation. § 5. Pour que la Communauté française soit assurée que toutes les écoles reprennent dans le profil de fonction qu''elles établissent, les compétences essentielles d''un directeur, le profil de fonction reprend, a minima, les compétences comportementales et les compétences techniques attendues suivantes : 1° compétences comportementales : a) être cohérent dans ses principes, ses valeurs et son comportement, avoir le sens de l''intérêt général et respecter la dignité de la fonction; b) être capable de fédérer des équipes autour de projets communs et de gérer des projets collectifs; c) être capable d''accompagner le changement; d) être capable de prendre des décisions et de s''y tenir après avoir instruit la question à trancher et/ou au terme d''un processus participatif; e) avoir une capacité d''observation objective et d''analyse du fonctionnement de son école en vue, le cas échéant, de dégager des pistes d''action alternatives; f) avoir le sens de l''écoute et de la communication; être capable de manifester de l''empathie, de l''enthousiasme et de la reconnaissance; 2° compétences techniques : a) avoir la capacité de lire et comprendre un texte juridique; b) disposer de compétences pédagogiques et montrer un intérêt pour la recherche en éducation adaptée au niveau d''enseignement concerné; c) dans l''enseignement secondaire artistique à horaire réduit, disposer de compétences artistiques; d) être capable de gérer des réunions; e) être capable de gérer des conflits; f) être capable de piloter l''implémentation du numérique dans les dispositifs d''enseignement et de gouvernance dans le cadre du développement de l''environnement numérique de son établissement et de l''enseignement en Communauté française ainsi que pouvoir utiliser les outils informatiques de base. § 6. Le profil de fonction élaboré par le pouvoir organisateur est utilisé : 1° au moment du recrutement d''un directeur : il documente les candidats sur les attentes du pouvoir organisateur et du système éducatif; il sert de référence pour fonder le choix d''un des candidats par le pouvoir organisateur; 2° au moment de la prise de fonction du directeur et avant la définition concertée de sa lettre de mission; il fait l''objet d''un échange approfondi entre pouvoir organisateur et directeur, de telle sorte que chaque partie ait une claire connaissance de ce que chacune attend de l''autre; à cette fin, le pouvoir organisateur et le directeur Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 s''accordent sur la comp');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 7, 'Article 5. - § 1er. Le Gouvernement arrête un profil de fonction-type du directeur (partie 3)', 'des indicateurs de maîtrise des compétences requises ainsi que sur les indicateurs de réalisation ou de résultats qui permettront d''objectiver l''exercice des responsabilités. Insérée par D. 13-09-2018 ; renumérotée par D. 14-03-2019 Section III - Dispositions spécifiques en matière de gestion des ressources humaines Modifié par D. 14-03-2019 ; D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 8, 'Article 6 - § 1er. - La compétence générale d''organisation visée à l''article 5', 'Article 6 - § 1er. - La compétence générale d''organisation visée à l''article 5 
comprend la gestion des ressources humaines de l''établissement en concertation avec 
le pouvoir organisateur, ce qui implique notamment que le directeur participe à la 
constitution de l''équipe éducative. 
 
§ 2. Sauf dans les cas où le pouvoir organisateur a donné, conformément à 
l''article 26, § 2, alinéa 2 une délégation au directeur en matière de primo-recrutement 
et/ou de constitution de son équipe éducative, une concertation est organisée entre le 
pouvoir organisateur ou son délégué et le directeur sur les matières suivantes : 
1° l''organisation, dans le respect des dispositions statutaires applicables, de la 
gestion des recrutements et, autant que possible, de la rencontre des candidats par le 
directeur; 
2° l''utilisation de la base de données visée à l''article 27 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et secondaire 
organisé et subventionné par la Communauté française; 
3° l''activation des accroches cours-fonction visées au titre Ier, chapitre III, du 
décret du 11 avril 2014 précité; 
4° les primo-recrutements au sens de l''article 25 du décret du 11 avril 2014 
précité; 
5° les dérogations à la priorisation des titres visées aux articles 31bis, 32 et 33 du 
décret du 11 avril 2014 précité; 
6° les autres désignations, engagements et changements d''affectation, dans le 
respect des dispositions statutaires applicables. 
 
Par dérogation à l''alinéa précédent, la concertation visée aux points 2° à 5° ne 
vise pas l''enseignement supérieur de promotion sociale et l''enseignement secondaire 
artistique à horaire réduit. 
 
§ 3. A l''issue de la concertation visée au paragraphe 2, le pouvoir organisateur ou 
son délégué communique sa proposition de décision au directeur. 
 
Après réception de la proposition de décision du pouvoir organisateur ou de son 
délégué, le directeur a la faculté d''exiger une deuxième concertation avec le pouvoir 
organisateur. 
 
Le délai dans lequel le directeur a la faculté d''exiger ladite deuxième concertation 
est précisé dans la lettre de mission, conformément à l''article 26, § é, alinéa 3, et est, 
au moins, d''un jour ouvrable. 
 
Dans le cas où le directeur n''exige pas la concertation visée à l''alinéa 2 : 
a) la proposition visée à l''alinéa 1er devient définitive si elle a été formulée par le 
pouvoir organisateur; 
b) la proposition visée à l''alinéa 1er est soumise au pouvoir organisateur si elle a 
été formulée par son délégué; si le pouvoir organisateur ne rend pas la proposition de 
son délégué définitive, il propose une deuxième concertation au directeur. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 4. Les échanges entre le directeur et les membres ou les représentants du 
pouvoir organisateur ayant participé aux concertations visées aux §§ 2 et 3 sont 
secrets. 
 
Remplacé par D. 14-03-2019 
CHAPITRE II. - De la formation initiale des directeurs 
 
Section Ire. - Des objectifs de la formation initiale des directeurs 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 9, 'Article 7. - La formation initiale du directeur a pour objectifs de permettre au', 'Article 7. - La formation initiale du directeur a pour objectifs de permettre au 
directeur : 
1° de prendre conscience de la réalité du métier de directeur et de s''y préparer; 
2° d''appréhender les rôles d''un directeur dans ses différents aspects (relationnel, 
pédagogique, administratif, matériel, financier, organisationnel) en vue de préciser le 
cadre global de la fonction; 
3° d''acquérir des connaissances, notamment conceptuelles et légales en lien avec 
le système éducatif, ainsi que des outils d''analyse; 
4° de développer les compétences de base, notamment en matière de gestion des 
ressources humaines, nécessaires à l`exercice des responsabilités décrites par les 
profils de fonction visés à la section II du chapitre Ier; 
5° de travailler le changement de posture professionnelle et la capacité de 
prendre du recul par rapport à sa pratique. 
 
Section II. - De l''organisation et de la certification de la formation initiale 
des directeurs 
 
Sous-section Ire. - Dispositions générales 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 10, 'Article 8. - § 1er. La formation initiale des directeurs comprend deux volets :', 'Article 8. - § 1er. La formation initiale des directeurs comprend deux volets : 
1° un volet «inter-réseaux», commun à l''ensemble des réseaux; 
2° un volet «réseau», propre à chaque réseau. 
 
§ 2. Au long de leur formation initiale, les directeurs sont invités à constituer un 
dossier de développement professionnel («portfolio»). 
 
Le «portfolio» est un outil formatif facilitant le soutien aux apprentissages et le 
développement d''une analyse réflexive. Les directeurs peuvent y consigner les traces 
qu''ils jugent utiles et pertinentes au sujet du cheminement de leur développement 
professionnel. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 11, 'Article 9. - Les pouvoirs organisateurs qui ne sont pas affiliés à une fédération', 'Article 9. - Les pouvoirs organisateurs qui ne sont pas affiliés à une fédération 
de pouvoirs organisateurs sont, pour ce qui les concerne, responsables de 
l''organisation du volet «réseau». 
 
Ils peuvent établir avec une fédération de pouvoirs organisateurs ou le pouvoir 
organisateur de l''enseignement organisé par la Communauté française une convention 
lui confiant l''organisation de tout ou partie de ce volet. 
 
Remplacé par D. 03-05-2019 ; modifié par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 12, 'Article 10. - § 1er. La formation «inter-réseaux» visée à l''article 8, 1°, se centre', 'Article 10. - § 1er. La formation «inter-réseaux» visée à l''article 8, 1°, se centre 
sur : 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
1° les enjeux et orientations du système éducatif et notamment sur les valeurs, 
les finalités, les objectifs et missions prioritaires du système éducatif, en vue de 
développer chez les directeurs une vision pédagogique et une capacité de pilotage de 
leur école en cohérence avec ceux-ci; 
2° les responsabilités et compétences communes à tous les directeurs tels que 
développées dans le profil de fonction-type visé à l''article 5, § 1er. 
 
§ 2. La formation «inter-réseaux», qui comporte en tout nonante heures, est 
structurée en deux axes : l''axe «administratif» (12 heures) et l''axe «pilotage» (78 
heures). 
 
§ 3. L''axe «administratif» est développé dans un module visant à : 
1° acquérir les éléments de base pour appréhender le cadre légal et 
réglementaire, la hiérarchie des normes et les principes généraux de droit; 
2° appréhender les principales bases légales pertinentes du niveau concerné; 
3° s''initier à une démarche de recherche dans les bases légales et réglementaires 
pour pouvoir résoudre des cas pratiques simples et actualiser et approfondir ses 
connaissances sur une problématique donnée. 
 
Ce module doit être suivi préalablement à la première partie du module «vision 
pédagogique et pilotage» visé au § 4, alinéa 2, 1°, a) de la formation «inter-réseaux» et 
au module «administratif, matériel et financier» de la formation «réseau». 
 
Il doit avoir été suivi avant la fin de la 1ère année de stage. 
 
§ 4. L''axe «pilotage» vise à développer : 
1° une vision pédagogique en lien avec les orientations du système éducatif, à 
partir de laquelle le directeur exercera le leadership pédagogique qui lui revient et 
organisera le pilotage de son école; 
2° des compétences et aptitudes relationnelles, interpersonnelles et groupales, 
notamment, en organisation scolaire, en vue d''atteindre les objectifs et missions 
prioritaires du système éducatif. 
 
Cet axe est développé dans deux modules comptant chacun 39 heures : 
1° le module «vision pédagogique et pilotage», qui est scindé lui-même en deux 
parties : 
 a) une première partie de 18 heures est centrée principalement sur le 
développement d''une vision pédagogique; cette partie est suivie par les directeurs de 
préférence avant leur entrée en fonction et, en tout cas, avant la fin de la 1re année de 
stage; 
 b) une seconde partie de 21 heures, qui ne peut être suivie avant la première, 
centrée principalement sur le pilotage. 
2° le module «développement des compétences et aptitudes relationnelles, 
interpersonnelles et groupales et construction de l''identité professionnelle» est 
structuré par trois fils conducteurs : 
 a) la prise de conscience et l''analyse du changement de posture en lien avec 
l''identité professionnelle de la fonction de directeur; 
 b) le leadership en milieu scolaire; 
 c) l''auto-évaluation de ses modes de fonctionnement dans les relations 
professionnelles. 
 
Le module visé au point 2° de l''alinéa précédent est scindé en deux parties : 
a) une première partie de 30 heures est centrée sur trois thèmes; 
 1° la gestion des ressources et relations humaines dans le cadre d''une 
organisation scolaire; 
 2° la communication en organisation scolaire; 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
 3° la prévention et gestion des conflits en organisation; 
b) une seconde partie de 9 heures, permet aux directeurs d''approfondir un des 
trois thèmes de la première partie, en fonction d''une auto-évaluation réalisée à l''issue 
de la première partie des comportements qu''ils ont à développer prioritairement. 
 
La première partie visée au point a) de l''alinéa précédent est suivie par les 
directeurs de préférence avant leur entrée en fonction et en tout cas avant la fin de la 
1re année de stage. 
 
Modifié par D. 03-05-2019 ; D. 17-06-2021 
§ 5. Les directeurs temporaires désignés ou engagés pour une durée initiale au 
moins égale à un an sont également tenus de suivre les formations visées aux §§ 3 et 
4, alinéa 2, 1°, a), et alinéa 3, a). 
 
Le pouvoir organisateur met fin d''office aux fonctions du directeur temporaire 
visé à l''alinéa précédent qui n''a pas suivi ces formations sauf si l''Institut interréseaux 
de la Formation professionnelle continue atteste que le directeur n''a pu être inscrit 
dans ces formations au cours de sa première année de fonction. Dans ce cas l''obligation 
de formation est reportée à l''année suivante. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 13, 'Article 11. - § 1er. La formation «réseau» visée à l''article 8, § 1er, 2°, se centre', 'Article 11. - § 1er. La formation «réseau» visée à l''article 8, § 1er, 2°, se centre 
sur : 
1° les enjeux et orientations propres au réseau, notamment son projet éducatif et 
pédagogique ou pédagogique et artistique et ses modèles organisationnels; 
2° les dispositions spécifiques en matière juridique et administrative ainsi qu''en 
matière de gestion matérielle et financière; 
3° l''accompagnement de l''insertion professionnelle des directeurs. 
 
§ 2. La formation «réseau» comporte nonante heures et est composée : 
1° d''une formation de base de 60 heures structurée en deux modules (un module 
«administratif, matériel et financier» et un module «éducatif et pédagogique»; 
2° d''une formation/accompagnement d''intégration au moment de l''insertion 
professionnelle. 
 
§ 3. Le module «administratif, matériel et financier» (30 heures) vise l''étude et 
l''application des dispositions légales et réglementaires spécifiques à chaque réseau, 
notamment le statut des membres du personnel, le règlement de travail, les organes 
locaux de concertation sociale, ainsi que la gestion des infrastructures de l''école et des 
ressources financières, dans la limite des responsabilités exercées en la matière par les 
directeurs selon leur réseau. 
 
Le module «éducatif et pédagogique» (30 heures) vise à développer des 
connaissances et des compétences notamment en matière de : 
a) exercice du leadership pédagogique; 
b) gestion du projet éducatif et pédagogique; 
c) co-construction de la culture d''école; 
d) co-construction et mise en oeuvre du projet d''établissement; 
e) projet pédagogique et artistique dans l''enseignement secondaire artistique à 
horaire réduit; 
f) co-construction et mise en oeuvre du plan de pilotage/suivi du contrat 
d''objectifs dans l''enseignement maternel et dans l''enseignement obligatoire; 
g) programmes et outils pédagogiques du réseau. 
 
§ 4. La formation/accompagnement d''intégration au moment de l''insertion 
professionnelle (30 heures) a pour finalité d''accompagner les directeurs lors de leur 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
entrée en fonction et de les aider à transférer dans leur quotidien les acquis des 
modules de formation «inter-réseaux» et «réseau». 
 
La formation/accompagnement d''intégration favorise le développement de 
l''identité professionnelle du directeur par la clarification de son rôle, l''analyse de ses 
forces et des améliorations à apporter et l''identification de ses besoins en matière de 
développement professionnel. 
 
Elle développe l''analyse réflexive, notamment à partir de situations du quotidien 
ou d''incidents critiques rapportés par le directeur. Elle peut soutenir le directeur dans 
différents domaines qui lui posent question : par exemple, la mobilisation de l''équipe 
éducative, la gestion de son temps, la priorisation de ses actions ou l''application 
concrète des dispositions légales et réglementaires. 
 
Elle peut prendre la forme de séances d''intervision avec d''autres directeurs. 
 
Dans le cadre de la formation/accompagnement, le directeur procède à une auto-
évaluation personnalisée qui mette en évidence les forces et les points à améliorer au 
terme de la formation. Le directeur qui le souhaite peut mobiliser cette évaluation 
personnalisée dans le cadre de l''évaluation de son fonctionnement avec le pouvoir 
organisateur. Le pouvoir organisateur ne peut y accéder, en tout ou en partie, que si le 
directeur la lui communique. 
 
La formation/accompagnement d''intégration est aussi l''occasion d''une évaluation 
formative préparatoire à l''évaluation de fin de stage. 
 
La formation/accompagnement d''intégration est prise en charge par des 
formateurs/accompagnateurs sans lien hiérarchique avec les directeurs concernés. Elle 
se déploie [, autant que possible,]1 sur les trois années suivant l''entrée en fonction du 
directeur. Elle est obligatoire. 
 
Remplacé par D. 14-03-2019 ; D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 14, 'Article 12. - Sur la base d''une proposition formulée par l''Institut interréseaux de', 'Article 12. - Sur la base d''une proposition formulée par l''Institut interréseaux de 
la Formation professionnelle continue, le Gouvernement détermine un plan de 
formation relatif au volet inter-réseaux de la formation initiale des directeurs, qui fixe, 
notamment, les objectifs et le contenu des différents modules visés à l''article 10, §§ 3 
et 4, ainsi que les compétences à développer. 
 
Le plan de formation peut être décliné par niveau ou par type d''enseignement. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 15, 'Article 13. - Le pouvoir organisateur de l''enseignement organisé par la', 'Article 13. - Le pouvoir organisateur de l''enseignement organisé par la 
Communauté française, chaque fédération de pouvoirs organisateurs déterminent 
chacun un plan de formation relatif au volet «réseaux» de la formation initiale des 
directeurs, qui fixe notamment : 
a) les objectifs et le contenu des deux modules visés à l''article 11, § 3, ainsi que 
les compétences à développer; 
b) un descriptif du dispositif de formation/accompagnement d''intégration au 
moment de l''insertion professionnelle visé à l''article 11, § 4, des objectifs spécifiques 
poursuivis, de la méthodologie proposée et des moyens humains mobilisés. 
 
Inséré par D. 04-02-2021 
Les pouvoirs organisateurs non affiliés adhèrent au plan de formation déterminé 
par l''une des fédérations de pouvoirs organisateurs ou par le pouvoir organisateur de 
 
1Inséré par le D. 16-05-2024 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
l''enseignement organisé par la Communauté française. 
 
Le plan de formation peut être décliné par niveau ou par type d''enseignement. 
 
Chaque plan de formation est soumis à l''approbation du Gouvernement. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 16, 'Article 14. - La formation initiale de directeur est gratuite. Sauf nécessité liée à', 'Article 14. - La formation initiale de directeur est gratuite. Sauf nécessité liée à 
leur contenu, les modules de formation «inter-réseaux» et les modules de la formation 
«réseau» visés à l''article 11, § 3, sont organisés en dehors des périodes normales de 
fonctionnement des établissements scolaires. Les membres du personnel qui suivent 
une formation sont considérés comme en activité de service. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 17, 'Article 15. - § 1er. Les modules de formation visés aux articles 10, §§ 3 et 4, et', 'Article 15. - § 1er. Les modules de formation visés aux articles 10, §§ 3 et 4, et 
11, § 3, se clôturent par une épreuve sanctionnée par une attestation de réussite. 
 
Tous les candidats qui ont suivi un module de formation reçoivent une 
attestation de fréquentation. Seuls les candidats qui fournissent une attestation 
prouvant qu''ils ont effectivement suivi au moins 75 % de la durée du module sont 
admis à présenter l''épreuve qui le sanctionne. Pour chaque épreuve, les candidats sont 
soit admis, soit refusés. Aucun classement n''est établi. 
 
L''Institut de la Formation en cours de carrière délivre aux directeurs qui la lui 
demandent une attestation de suivi pour l''ensemble des formations visées à l''article 
10, § 3, et à l''article 10, § 4, alinéa 2, 1°, a), et alinéa 3, a). 
 
La formation/accompagnement visée à l''article 11, § 4, n''est pas certifiée mais est 
sanctionnée par une attestation de suivi délivrée par le réseau ou le pouvoir 
organisateur qui l''a assurée. 
 
§ 2. Les attestations de réussite ou de suivi visées au § 1er, alinéas 1er et 4, ont 
une durée de validité de six ans commençant à courir le lendemain de la date de 
délivrance de la dernière attestation. 
 
Par dérogation à l''alinéa 1er, la durée de validité des attestations d''un membre du 
personnel est suspendue pendant les périodes où il exerce la fonction de directeur. 
 
Pour prolonger de six ans la durée de validité de leurs attestations de réussite, 
les membres du personnel titulaires des cinq attestations de réussite visées au § 1er, 
alinéa 1er, sont tenus de suivre à nouveau les cinq modules de la formation initiale des 
directeurs; ils sont dispensés des épreuves certificatives; une attestation de 
fréquentation leur est délivrée aux conditions visées à l''article 15, § 1er, alinéa 2. Ces 
attestations , pour autant qu''elles prouvent que les membres du personnel ont 
effectivement suivi au moins 75% de la formation, prolongent d''office pour une 
nouvelle durée de six ans la validité des attestations de réussite obtenues 
antérieurement. Le nouveau délai de validité débute le lendemain de la date de 
délivrance de la dernière attestation. 
 
Le Gouvernement peut arrêter des dispositions permettant aux membres du 
personnel visés à l''alinéa précédent de valider les acquis de leur expérience 
professionnelle et personnelle et les formations qu''ils ont suivies, de sorte qu''ils 
puissent être dispensés de suivre, à nouveau, tout ou partie de la formation initiale 
des directeurs. 
 
§ 3. Les directeurs définitifs désignés ou engagés dans un autre emploi de 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
directeur sont réputés répondre à la condition visée aux articles 36bis, alinéa 1er, 2°, 
58, 1°, et 81, 1°. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 18, 'Article 16. - § 1er. Nul ne peut s''inscrire à l''un des modules de formation si, à la', 'Article 16. - § 1er. Nul ne peut s''inscrire à l''un des modules de formation si, à la 
date d''introduction de sa demande de formation, il n''est pas titulaire:  
1° du titre de capacité visé à l''article 35, § 1er, alinéa 3, 1°, et d''un des titres de 
capacité visés au 2° du même article, pour l''enseignement organisé par la 
Communauté française;  
2° du titre de capacité visé à l''article 57, alinéa 1er, 1°, et d''un des titres de 
capacité visés au 2° du même article, pour l''enseignement officiel subventionné; 
3° du titre de capacité visé à l''article 80, § 1er, alinéa, 1°, et d''un des titres de 
capacité visés au 2° du même article, pour l''enseignement libre subventionné. 
 
Par dérogation à l''alinéa 1er, la personne qui a été déclarée éligible comme 
candidat à la fonction de directeur par la commission visée à l''article 29 peut s''inscrire 
à l''un des modules de formation. 
 
§ 2. Les opérateurs de formation accordent une priorité à l''inscription aux 
directeurs en fonction ou dont l''entrée en fonction se fera dans les six mois. 
 
Sous-section II. - De l''organisation et de la certification 
 
Remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 19, 'Article 17. - § 1er. La formation «inter-réseaux» est organisée et certifiée, sur la', 'Article 17. - § 1er. La formation «inter-réseaux» est organisée et certifiée, sur la 
base du plan de formation visé à l''article 12, par l''Institut de la formation en cours de 
carrière. 
 
L''Institut de la formation en cours de carrière peut confier l''organisation, la 
certification et la dispense de certains modules ou parties de module aux organismes 
suivants: 
1° les Universités; 
2° les Hautes Ecoles; 
3° les Etablissements d''enseignement de promotion sociale organisant de 
l''enseignement supérieur. 
 
§ 2. Un membre du personnel d''une institution universitaire, d''une Haute Ecole 
ou d''un établissement d''enseignement de promotion sociale ne peut suivre de volet de 
formation au sein de celle-ci/celui-ci, sauf dérogation accordée par le Gouvernement à 
la suite d''une demande motivée du membre du personnel concerné. A défaut de 
réponse dans les trois mois suivant la réception de la demande, la dérogation est 
présumée accordée. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 20, 'Article 18. - § 1er. La formation «réseau» et les épreuves qui sanctionnent les', 'Article 18. - § 1er. La formation «réseau» et les épreuves qui sanctionnent les 
modules de formation sont organisés sur la base du plan de formation visé à l''article 
13 : 
a) par le pouvoir organisateur de l''enseignement organisé par la Communauté 
française pour les membres du personnel de l''enseignement organisé par la 
Communauté française; 
b) par les fédérations de pouvoirs organisateurs pour les membres du personnel 
de l''enseignement subventionné par la Communauté française. 
 
Inséré par D. 04-02-2021 
Les pouvoirs organisateurs non affiliés à une fédération de pouvoirs 
organisateurs confient l''organisation et la certification de ces formations à la 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
fédération de pouvoirs organisateurs ou au pouvoir organisateur avec laquelle/lequel 
ils ont conclu une convention en vertu de l''article 9. 
 
Chaque fédération de pouvoirs organisateurs peut déléguer sa compétence 
d''organisation et de certification de la formation visée au présent paragraphe à un ou 
plusieurs pouvoirs organisateurs affiliés auprès de lui. Dans ce cas, le ou les pouvoirs 
organisateurs concernés assument les obligations des fédérations de pouvoirs 
organisateurs, telles que décrites aux articles suivants. 
 
§ 2. Pour l''organisation de la formation «réseau», le Gouvernement peut agréer 
notamment les opérateurs de formation suivants : 
1° les Universités; 
2° les Hautes Ecoles; 
3° les Ecoles et Instituts supérieurs pédagogiques; 
4° les Etablissements d''enseignement de promotion sociale organisant de 
l''enseignement supérieur; 
5° les Centres de formation des réseaux. 
 
§ 3. Le Gouvernement fixe les conditions auxquelles doivent en outre répondre les 
opérateurs de formation visés au § 2, point 5, afin de vérifier leur capacité à dispenser 
des formations. Ces conditions auront notamment trait à l''expérience de l''opérateur, 
aux formations qu''il a déjà dispensées, aux garanties professionnelles et financières 
qu''il présente. 
 
§ 4. Un membre du personnel d''une institution universitaire, d''une Haute Ecole 
ou d''un établissement d''enseignement de promotion sociale ne peut suivre de volet de 
formation au sein de celle-ci/celui-ci, sauf dérogation accordée par le Gouvernement à 
la suite d''une demande motivée du membre du personnel concerné. A défaut de 
réponse dans les trois mois suivant la réception de la demande, la dérogation est 
présumée accordée. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 21, 'Article 19. - Les épreuves de certification des modules de formation sont', 'Article 19. - Les épreuves de certification des modules de formation sont 
organisées au moins une fois tous les deux ans. 
 
Par dérogation à l''alinéa précédent, les épreuves de certification des formations 
visées à l''article 10, § 3, et à l''article 10, § 4, alinéa 2, 1°, a), et alinéa 3, a), sont 
organisées au moins une fois par an. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 22, 'Article 20. - Sur proposition conjointe de l''Institut de la Formation en cours de', 'Article 20. - Sur proposition conjointe de l''Institut de la Formation en cours de 
carrière, du pouvoir organisateur de l''enseignement organisé par la Communauté 
française et des fédérations de pouvoirs organisateurs, le Gouvernement peut fixer 
pour les opérateurs de formation la forme des épreuves à organiser pour chaque 
module de formation ainsi que les critères d''évaluation. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 23, 'Article 21. - § 1er. Pour tenir compte du portefeuille de compétences des', 'Article 21. - § 1er. Pour tenir compte du portefeuille de compétences des 
candidats, les organes certificateurs visés à l''article 17, § 1er, peuvent les dispenser du 
suivi d''un ou de plusieurs module(s) du volet «inter-réseaux» et des épreuves y 
relatives : 
1° soit s''ils sont titulaires d''un autre brevet relatif à une fonction de sélection ou 
de promotion; 
2° soit s''ils fournissent la preuve qu''ils ont suivi et, le cas échéant, réussi des 
formations équivalentes. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 2. Les opérateurs de formations visés à l''article 18, § 1er, peuvent, selon les 
conditions fixées au § 1er, dispenser les candidats du suivi d''un ou plusieurs module(s) 
du volet «réseau» et des épreuves y relatives. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 24, 'Article 22. - Les voies de recours habituellement applicables au sein des', 'Article 22. - Les voies de recours habituellement applicables au sein des 
Universités, Hautes Ecoles et Etablissements d''enseignement de promotion sociale 
sont d''application pour ce qui concerne les décisions prises par ces établissements dans 
le cadre de la certification des formations qu''ils dispensent en vertu de la présente 
sous-section. Le cas échéant, les modalités d''application de ces voies de recours sont 
adaptées par les établissements aux spécificités du présent décret. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 25, 'Article 23. - Les Services du Gouvernement sont chargés du contrôle, selon les', 'Article 23. - Les Services du Gouvernement sont chargés du contrôle, selon les 
modalités fixées par le Gouvernement, de la mise en oeuvre, dans le respect des 
dispositions du présent chapitre, des plans de formations visés aux articles 17 et 18. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 26, 'Article 24. - L''Institut de la formation en cours de carrière, les autres organes', 'Article 24. - L''Institut de la formation en cours de carrière, les autres organes 
certificateurs visés à l''article 17, § 1er, le pouvoir organisateur de l''enseignement 
organisé par la Communauté française, chaque fédération de pouvoirs organisateurs 
et chaque pouvoir organisateur non affilié à une de ces fédérations remettent, 
d''initiative ou à la demande du Gouvernement, des avis sur l''application des 
dispositions organisant les formations et les épreuves qui les sanctionnent 
conformément au présent chapitre, chacun pour ce qui le concerne. 
 
Remplacé par D. 14-03-2019 ; complété par D. 28-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 27, 'Article 25. - Tous les trois ans au moins, l''Institut de la formation en cours de', 'Article 25. - Tous les trois ans au moins, l''Institut de la formation en cours de 
carrière, la Commission permanente visée à l''article 22 du décret du 4 janvier 1999, le 
pouvoir organisateur de l''enseignement organisé par la Communauté française, 
chaque fédération de pouvoirs organisateurs et chaque pouvoir organisateur non affilié 
à un de ces organes, chacun pour ce qui le concerne, transmet à la Commission de 
pilotage créée par le décret du 27 mars 2002 relatif au pilotage du système éducatif de 
la Communauté française, un rapport d''évaluation sur l''organisation et la certification 
de la formation initiale des directeurs, conformément au présent chapitre. 
 
Le Gouvernement peut fixer un modèle commun de rapport d''évaluation. Il peut 
créer un organe chargé de lui proposer ce modèle commun et de préparer, avec les 
organismes visés à l''alinéa précédent, un rapport global à l''attention de la Commission 
de pilotage. 
 
La Commission de pilotage peut, dans son rapport annuel, remettre des avis ou 
formuler des propositions au Gouvernement au sujet de la cohérence de l''organisation 
et de la certification de la formation initiale des directeurs organisée conformément au 
présent chapitre. 
 
Le pouvoir organisateur de l''enseignement organisé par la Communauté 
française, chaque fédération de pouvoirs organisateurs qui serait tenu d''établir un 
rapport de suivi en application de de l''article 15 du décret du 28 mars 2019 relatif aux 
Cellules de soutien et d''accompagnement de l''enseignement organisé ou subventionné 
par la Communauté française et au statut des Conseillers au soutien et à 
l''accompagnement est dispensé, dans ce cas, d''établir et de transmettre le rapport 
d''évaluation visé à l''alinéa 1er. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
CHAPITRE III. - De la lettre de mission 
 
Remplacé par D. 13-09-2018 ; renuméroté et modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 28, 'Article 26. - § 1er. Dès l''entrée en fonction du directeur stagiaire, le pouvoir', 'Article 26. - § 1er. Dès l''entrée en fonction du directeur stagiaire, le pouvoir 
organisateur lui confie une lettre de mission. 
 
§ 2. Le pouvoir organisateur y spécifie les missions du directeur stagiaire et les 
priorités qui lui sont assignées, en fonction des besoins de l''établissement au sein 
duquel le directeur est affecté et en cohérence avec le profil de fonction visé à l''article 
5, § 5. 
 
La lettre de mission précise la nature et l''étendue des délégations données au 
directeur, notamment dans les domaines suivants : 
a) la constitution de son équipe pédagogique et en particulier, dans 
l''enseignement maternel et dans l''enseignement obligatoire, le primo-recrutement des 
membres de son personnel dans le respect des dispositions statutaires applicables; 
b) la gestion du personnel ouvrier; 
c) l''exécution de petits travaux; 
d) la gestion financière et l''utilisation des frais de fonctionnement. 
 
Elle précise aussi le délai visé à l''article 6, § 3, alinéa 3. 
 
§ 3. Préalablement à la rédaction de la lettre de mission, le pouvoir organisateur 
consulte l''organe local de concertation sociale. 
 
La lettre de mission est rédigée après concertation avec le directeur. 
 
Modifié par D. 13-09-2018 ; complété par D. 13-09-18(1) ; renuméroté et modifié 
par D. 14-03-2019 ; complété par D. 04-02-2021 ; D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 29, 'Article 27. - § 1er. La lettre de mission a une durée de six ans.', 'Article 27. - § 1er. La lettre de mission a une durée de six ans. 
 
§ 2. Le contenu de la lettre de mission peut être modifié notamment en raison de 
l''évolution du fonctionnement ou des besoins de l''établissement avant son échéance, 
au plus tôt après deux ans, par le pouvoir organisateur, soit d''initiative, soit à la 
demande du directeur. 
 
Par dérogation à l''alinéa 1er, le contenu de la lettre de mission des directeurs 
stagiaires peut être modifié au plus tôt après six mois. 
 
Par dérogation au même alinéa, le contenu de la lettre de mission peut être 
modifié avant son échéance, de commun accord entre le directeur et le pouvoir 
organisateur. 
 
§ 3. Pour toute nouvelle lettre de mission ou modification de celle-ci, la procédure 
de consultation visée à l''article 26, § 3, doit être respectée. 
 
§ 4. Par dérogation aux paragraphes 1er à 3, lorsque qu''un contrat d''objectifs a été 
conclu conformément à l''article 67, § 6, du décret du 24 juillet 1997 définissant les 
missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire 
et organisant les structures propres à les atteindre ou lorsque ce contrat d''objectifs a 
été modifié en application des paragraphes 10, 12 et 15, du même article, le pouvoir 
organisateur de l''école organisée ou subventionnée par la Communauté française peut 
modifier le contenu de la lettre de mission afin d''en assurer la cohérence avec ce 
contrat d''objectifs. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Par dérogation aux paragraphes 1er à 3, le pouvoir organisateur de l''école 
organisée ou subventionnée par la Communauté française peut également modifier le 
contenu de la lettre de mission, lorsqu''un protocole de collaboration a été conclu 
conformément à l''article 68, § 7, du décret du 24 juillet 1997 définissant les missions 
prioritaires de l''enseignement fondamental et de l''enseignement secondaire et 
organisant les structures propres à les atteindre ou lorsque ce protocole été modifié en 
application du paragraphe 12, du même article afin d''en assurer la cohérence avec ce 
protocole de collaboration. 
 
Inséré par D. 17-06-2021 
Par dérogation aux paragraphes 1er à 3, lorsque qu''une annexe au contrat 
d''objectifs a été établie au sein de l''école siège d''un pôle territorial, conformément à 
l''article 6.2.4.-1 du Code de l''enseignement fondamental et de l''enseignement 
secondaire, le pouvoir organisateur de l''école siège organisée ou subventionnée par la 
Communauté française est tenu de modifier le contenu de la lettre de mission afin d''en 
assurer la cohérence avec la mise en oeuvre des missions du pôle territorial et le(s) 
objectif(s) spécifique(s) repris dans cette annexe. 
 
Inséré par D. 04-02-2021 
§ 5. Par dérogation aux paragraphes 1er et 2, le pouvoir organisateur de l''école 
organisée ou subventionnée par la Communauté française modifie d''office le contenu 
de la lettre de mission du directeur qui bénéficie d''une mise en disponibilité partielle 
pour convenances personnelles précédant la pension de retraite ou d''une interruption 
partielle de la carrière professionnelle après 58 ans. 
 
La lettre de mission modifiée reprécise, le cas échéant, la nature et l''étendue des 
délégations données au directeur. Elle précise la manière dont il exerce son leadership 
pédagogique, les missions qu''il ne peut déléguer ainsi que les missions exercées 
antérieurement qu''il délègue. 
 
Elle définit l''organisation de ses prestations et les modalités de concertation avec 
le ou les membres du personnel appelés à le seconder. 
 
Modifié par D. 13-09-2018 ; renuméroté et modifié par D. 14-03-2019 ; D. 04-02-
2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 30, 'Article 28. - § 1er. Le pouvoir organisateur, si besoin en est, peut confier une', 'Article 28. - § 1er. Le pouvoir organisateur, si besoin en est, peut confier une 
lettre de mission au membre du personnel désigné à titre temporaire dans la fonction 
de directeur.  
 
Le pouvoir organisateur confie d''office une lettre de mission au membre du 
personnel désigné à titre temporaire dans la fonction de directeur pour une durée 
égale ou supérieure à un an, ou lorsque la durée de la désignation atteint au moins un 
an.  
 
§ 2. La lettre de mission visée au présent article peut consister dans la 
confirmation de la lettre de mission du directeur faisant l''objet d''un remplacement ou 
dans un nouveau document. 
 
Dans l''hypothèse où le pouvoir organisateur n''estime pas nécessaire de confier 
une nouvelle lettre de mission au membre du personnel désigné à titre temporaire 
dans la fonction de directeur pour une durée inférieure à un an, la lettre de mission 
confiée au directeur remplacé est alors présumée confirmée. 
 
§ 3. La procédure visée à l''article 26,  § 3 doit être respectée en cas de rédaction 
d''une nouvelle lettre de mission conformément au présent article. L''article 27 
s''applique mutatis mutandis à cette dernière. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Inséré par D. 14-03-2019 
CHAPITRE IV. - De la commission de valorisation de l''expérience dans 
l''enseignement 
 
Inséré par D. 14-03-2019 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 31, 'Article 29 - § 1er. - Le Gouvernement institue une commission de valorisation de (partie 1)', 'Article 29 - § 1er. - Le Gouvernement institue une commission de valorisation de l''expérience dans l''enseignement, ci-après dénommée la Commission. La Commission a pour mission de reconnaître, sur base d''un dossier, l''expérience dans l''enseignement des demandeurs qui ne répondent pas à toutes les conditions d''accès à cette fonction, fixées à l''article 35, § 1er, alinéa 3, 1°, 2° et 3°, pour l''enseignement organisé par la Communauté française, à l''article 57, alinéa 1er, 1°, 2° et 3°, pour l''enseignement officiel subventionné et à l''article 80, alinéa 1er, 1°, 2° et 3°, pour l''enseignement libre subventionné, pour qu''ils puissent être candidats à la fonction de directeur. § 2. La Commission compte 16 membres ayant voix délibérative et est composée comme suit : 1° le directeur général ayant la gestion des membres des personnels de l''enseignement dans ses attributions ou son délégué, de rang 10 au moins; 2° un autre délégué, de rang 10 au moins, du directeur général visé au 1° ; 3° le directeur général de l''enseignement obligatoire, ou son délégué, de rang 10 au moins; 4° le directeur général de l''enseignement non obligatoire ou son délégué, de rang 10 au moins; 5° deux délégués du Service général de l''Inspection; 6° deux représentants du Conseil général de l''enseignement fondamental; 7° deux représentants du Conseil général de l''enseignement secondaire; 8° deux représentants du Conseil général de l''enseignement de promotion sociale; 9° un représentant du Conseil général de l''enseignement secondaire artistique à horaire réduit; 10° trois représentants des organisations syndicales représentatives au sens de l''article 7 de la loi du 19 décembre 1974 organisant les relations entre les autorités publiques et les syndicats des agents relevant de ces autorités. Deux délégués du Gouvernement participent aux travaux de la Commission; ils n''ont pas voix délibérative. La Commission peut solliciter l''avis d''experts et, occasionnellement, associer ceux-ci à ses travaux. § 3. La présidence de la Commission est assurée par le membre visé au paragraphe 2, 1°. Le secrétariat de la Commission est assuré au sein de l''Administration générale de l''Enseignement par les services du Gouvernement. Le secrétaire de la Commission tient à jour la liste des membres. Il appartient aux organismes représentés au sein de la Commission de lui communiquer les modifications de leur délégation au sein de celle-ci. § 4. Les personnes qui souhaitent que leur expérience dans l''enseignement, en dehors de l''enseignement organisé ou subventionné par la Communauté française, soit valorisée de telle sorte que leur candidature à un poste de directeur/directrice soient reconnue éligible, même s''ils ne répondent pas à toutes les conditions d''accès rappelées Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 à l''article 30, introduisent, un dossier attestant de leur expérience dans l''enseignement. Le dossier comprend : 1° une lettre de demande de valorisation; 2° un curriculum vitae précis; 3° une copie certifiée conforme des titres de capacités obtenus; 4° des attestations originales des services rendus dans l''enseignement en Belgique ou à l''étranger, dans des institutions publiques ou dans des institutions privées; 5° tout document jugé utile à l''appui de la demande. § 5. Le dossier visé au paragraphe précédent est envoyé par voie postale avec copie par voie électronique à l''Administration générale de l''Enseignement. Le secrétariat de la Commission en accuse réception au demandeur dans les dix jours de sa réception. Le cas échéant, il invite le demandeur à compléter le dossier. Il informe immédiatement le président des demandes qui ont été introduites. § 6. Les dossiers de demande de valorisation sont traités dans un délai d''ordre de quatre mois. A cet effet, le président convoque la Commission chaque fois que nécessaire. A l''ordre du jour est jointe une copie électronique du dossier. A titre exceptionnel, le président peut proposer aux membres de tenir une réunion électronique. Les modalités d''application relatives à la tenue des réunions électroniques sont les suivantes : 1° avec le dossier, une proposition de décision est envoyée par courrier électronique à tous les membres; ceux-ci sont invités par ledit courrier à faire connaître leurs remarques dans le délai déterminé; ce délai ne peut pas être inférieur à trois jours ouvrables; 2° à défaut de réaction dans le délai fixé, la proposition est considérée comme acceptée; 3° en cas d''approbation selon les modalités précitées, celle-ci est actée au procès- verbal; ce procès-verbal est communiqué aux membres sans délai; 4° à défaut d''une telle approbation ou à la demande d''une des organisations constituantes, une réunion «physique» doit être tenue. § 7. La Commission vérifie la recevabilité du dossier : seuls sont recevables les dossiers des titulaires d''un diplôme de master ou assimilé. Elle analyse les services rendus par le demandeur dans l''enseignement et décide quels services peuvent êtr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 32, 'Article 29 - § 1er. - Le Gouvernement institue une commission de valorisation de (partie 2)', 'valorisés. La Commission peut décider d''entendre le demandeur. § 8. La Commission délibère valablement si la moitié au moins des membres sont présents. Les décisions sont prises sur base d''un consensus ou, à défaut, à la majorité des deux-tiers des voix des membres présents, les abstentions n''étant pas prises en compte. En cas de parité, la voix du président est prépondérante. § 9. Les procès-verbaux des réunions reprennent synthétiquement les avis émis en réunion, les décisions prises et leur motivation. Ils sont transmis aux membres par voie électronique pour approbation. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Si après un délai de cinq jours ouvrables après l''envoi, aucune remarque n''a été formulée au secrétariat de la Commission, le procès-verbal est considéré comme approuvé. § 10. Si les services valorisés ont une durée d''au moins trois années, la Commission délivre au demandeur une attestation précisant la durée des services valorisés et déclarant qu''il est éligible à une fonction de directeur. Si la Commission constate que la demande n''est pas recevable ou si elle ne peut valoriser les services rendus dans l''enseignement à hauteur de trois années, elle en informe le demandeur par voie recommandée. Celui-ci dispose alors d''un délai de quinze jours ouvrables pour donner à la Commission des compléments d''information. Après examen de ces éléments, la Commission prend une décision définitive. Les décisions visées aux alinéas précédents sont communiquées au demandeur dans un délai maximal de quatre mois après la réception du dossier de demande. § 11. La Commission peut proposer à l''approbation du Gouvernement un règlement d''ordre intérieur précisant des modalités de fonctionnement complémentaires aux présentes dispositions, un modèle de formulaire de demande de valorisation de l''expérience dans l''enseignement ainsi qu''un modèle de l''attestation visée au paragraphe 10, alinéa 1er. Après avoir pris l''avis de la Commission, le Gouvernement peut fixer des critères de reconnaissance de l''expérience dans l''enseignement. § 12. Les délais prévus aux articles précédents sont suspendus entre le lendemain du dernier jour de l''année scolaire et la veille du premier jour de l''année scolaire suivante inclus. [Modifié par D. 31-03-2022] § 13. Les frais de fonctionnement de la Commission sont à charge du budget de l''Administration générale de l''Enseignement. § 14. Les membres de la Commission, de même que les experts ayant siégé dont la résidence administrative n''est pas située à Bruxelles, ont droit aux indemnités réglementaires pour les frais de parcours. Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 33, 'Article 30. -  Par dérogation aux conditions définies à l''article 35, § 1er, alinéa 3,', 'Article 30. -  Par dérogation aux conditions définies à l''article 35, § 1er, alinéa 3, 
1° à 3°, pour l''enseignement organisé par la Communauté française, à l''article 
57, § 1er, 1° à 3°, pour l''enseignement officiel subventionné et à l''article 80, § 1er, 1° à 
3°, pour l''enseignement libre subventionné, toute personne qui justifie d''une 
expérience dans l''enseignement, en Belgique ou à l''étranger, peut introduire un 
dossier auprès de la commission visée à l''article 29 en vue d''être reconnu éligible 
comme candidat à une fonction de directeur dans l''enseignement organisé ou 
subventionné par la Communauté française. 
 
Inséré par D. 14-03-2019 
CHAPITRE V. - De l''appel à candidatures 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 34, 'Article 31. - Le modèle des appels à candidatures visés aux articles 35, 56 et 79', 'Article 31. - Le modèle des appels à candidatures visés aux articles 35, 56 et 79 
est fixé par le Gouvernement, sur proposition conjointe de la Commission permanente 
de la promotion et de la sélection de l''enseignement organisé par la Communauté 
française, de la Commission paritaire centrale de l''enseignement officiel subventionné, 
de la Commission paritaire centrale de l''enseignement libre non confessionnel et de la 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Commission Paritaire Centrale de l''enseignement libre confessionnel. 
 
Le Gouvernement peut fixer le modèle d''initiative au cas où les Commissions 
visées à l''alinéa précédent ne lui ont pas adressé de proposition conjointe dans un 
délai de 30 jours après l''adoption du présent décret. 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 35, 'Article 32. - Le pouvoir organisateur qui lance un appel à candidatures précise', 'Article 32. - Le pouvoir organisateur qui lance un appel à candidatures précise 
l''extension des destinataires auxquels l''appel s''adresse soit aux seuls membres du 
personnel exerçant leurs fonctions au sein du pouvoir organisateur, soit à toute 
personne remplissant les conditions d''accès à la fonction. 
 
Renuméroté et modifié par D. 14-03-2019 
CHAPITRE VI. - Du déroulement du stage des directeurs 
 
Modifié par D. 17-10-2013 ; D. 13-09-2018 ; remplacé par D. 14-03-2019 ; modifié 
par D. 03-05-2019 ; D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 36, 'Article 33. - § 1er. Sans préjudice des § 2, alinéa 8, § 3, alinéa 4, et § 4, alinéa 5, (partie 1)', 'Article 33. - § 1er. Sans préjudice des § 2, alinéa 8, § 3, alinéa 4, et § 4, alinéa 5, le stage de directeur a une durée de trois ans. Pour le calcul de la durée du stage accompli, sont seuls pris en considération les services effectifs rendus pendant la durée du stage, en ce compris les vacances annuelles, les congés prévus aux articles 5, 5bis [,6]2 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, ainsi que les congés en vue de l''adoption et de la tutelle officieuse et les congés de maternité prévus respectivement, au chapitre IIbis et au chapitre XIII du même arrêté royal. La durée du stage est réduite à concurrence du temps déjà presté sans interruption, à titre temporaire, par le directeur occupant cet emploi, à la suite d''une procédure d''appel. Toutefois, le directeur qui ne compte pas une ancienneté de 6 ans au terme de son stage voit celui-ci prolongé jusqu''à ce qu''il atteigne cette ancienneté. Le présent alinéa ne s''applique pas dans la situation visée aux articles 56 § 3. B) et 79 § 3. B). L''admission au stage à la fonction de directeur ne peut avoir lieu qu''en cas de vacance d''emploi de la fonction à conférer. Pendant la durée du stage, le membre du personnel reste titulaire de l''emploi dans lequel il est nommé ou engagé à titre définitif, le cas échéant auprès de son pouvoir organisateur d''origine. Sauf disposition contraire, le membre du personnel admis au stage est assimilé à un membre du personnel nommé ou engagé à titre définitif dans la fonction de directeur. Pendant la durée de son stage, l''obligation de formation qui s''impose au membre du personnel en vertu soit du décret du 11 juillet 2002 relatif à la formation en cours de carrière des membres du personnel des établissements d''enseignement fondamental ordinaire soit du décret du 11 juillet 2002 relatif à la formation en cours de carrière dans l''enseignement spécialisé, l''enseignement secondaire ordinaire et les Centres psycho-médico-sociaux et à la création d''un Institut de la formation en cours 2 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 de carrière soit du décret du 30 juin 1998 relatif à la formation en cours de carrière des membres du personnel directeur et enseignant et du personnel auxiliaire d''éducation de l''enseignement de promotion sociale, soit du décret du 15 mars 1999 relatif à la formation en cours de carrière des membres du personnel directeur et enseignant et du personnel auxiliaire d''éducation de l''enseignement secondaire artistique à horaire réduit subventionné par la Communauté française est centrée spécifiquement sur sa qualité de directeur stagiaire. § 2. Entre le 9e mois effectif et la fin du 12e mois effectif de la première année du stage, le pouvoir organisateur procède à l''évaluation du directeur stagiaire. Toutefois, l''évaluation peut être organisée au retour du directeur stagiaire lorsque celui-ci est en congé en vue de l''adoption et de la tutelle officieuse ou en congé de maternité. A défaut d''évaluation réalisée dans ce délai, celle-ci est présumée favorable. Pour l''application de l''alinéa 1er, le pouvoir organisateur peut s''entourer d''experts. L''évaluation se fonde sur l''exécution de la lettre de mission visée au chapitre III du Titre II. Elle tient compte du contexte global dans lequel est amené à évoluer le directeur stagiaire et des moyens qui sont mis à sa disposition. Le Gouvernement détermine les modalités selon lesquelles l''évaluation se déroule et fixe le modèle du rapport d''évaluation. L''évaluation aboutit à l''attribution d''une des mentions suivantes : 1° «favorable»; 2° «réservée»; 3° «défavorable». Lorsque l''évaluation aboutit à l''attribution de la mention «réservée», la mention attribuée lors de l''évaluation suivante, est soit «favorable» soit «défavorable». Il est mis fin d''office au stage du directeur stagiaire qui a obtenu la mention «défavorable» en fin de première année de stage ou qui n''a pas suivi les formations visées à l''article 10, § 3, et à l''article 10, § 4, alinéa 2, 1°, a), et alinéa 3, a), sauf si l''Institut de la Formation en cours de carrière atteste que le directeur n''a pu être inscrit dans ces formations au cours de sa première année de stage. Dans ce cas l''obligation de formation est reportée à la deuxième année de stage. § 3. Le directeur stagiaire qui a obtenu la mention «favorable» ou «réservée» en fin de première année de stage, est, à nouveau, évalué entre le 9e mois effectif et la fin du 12e mois effectif de la deuxième année du stage, selon les mêmes modalités qu''');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 37, 'Article 33. - § 1er. Sans préjudice des § 2, alinéa 8, § 3, alinéa 4, et § 4, alinéa 5, (partie 2)', '§ 2, alinéas 4 à 7. Toutefois, l''évaluation peut être organisée au retour du directeur stagiaire lorsque celui-ci est en congé en vue de l''adoption et de la tutelle officieuse ou en congé de maternité. A défaut d''évaluation réalisée dans ce délai, l''évaluation est présumée favorable. Il est mis fin d''office au stage si le directeur obtient la mention «défavorable» à l''issue de cette deuxième évaluation ou si ayant vu son obligation de formation Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 reportée conformément au paragraphe 2, il n''a pas suivi les formations visées à l''article 10, § 3, et à l''article 10, § 4, 1°, a), et alinéa 3, a). § 4. Le directeur stagiaire qui a obtenu la mention «favorable» ou «réservée», en fin de deuxième année de stage, est à nouveau évalué entre le 9e mois effectif et la fin du 12e mois effectif de la troisième année du stage, selon les mêmes modalités qu''au § 2, alinéas 4 à 6. Toutefois, l''évaluation peut être organisée au retour du directeur stagiaire lorsque celui-ci est en congé en vue de l''adoption et de la tutelle officieuse ou en congé de maternité. Par dérogation à l''alinéa 1er, la troisième évaluation ne peut, toutefois, aboutir à la mention «réservée». A défaut d''évaluation réalisée dans ce délai, elle est présumée favorable. Le directeur est nommé ou engagé à titre définitif s''il obtient la mention «favorable» à l''issue de cette troisième évaluation. Il est mis fin d''office au stage si le directeur obtient la mention «défavorable» à l''issue de cette troisième évaluation. § 5. La mention obtenue par le directeur stagiaire, au terme de chaque évaluation est portée à la connaissance de ce dernier soit par lettre recommandée, soit par la remise d''une lettre de la main à la main avec accusé de réception. § 6. L''attribution d''une mention «réservée» en cours de stage peut conduire le pouvoir organisateur à adapter la lettre de mission et à repréciser ses attentes au directeur. § 7. Le directeur stagiaire qui se voit attribuer une mention «défavorable» peut introduire par recommandé une réclamation écrite contre cette mention dans les dix jours de sa notification, selon le cas auprès de la chambre de recours respectivement créée par : a) le chapitre IX, section 2 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, selon les cas, le directeur stagiaire est entendu par le 5e, 7e, 9e ou 14e comité visé à l''article 136 de l''arrêté royal du 22 mars 1969; b) le chapitre X du décret du 6 juin 1994 fixant le statut des membres du personnel subsidié de l''enseignement officiel subventionné; c) le chapitre IX, section 3 du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné. Le membre du personnel transmet immédiatement au pouvoir organisateur une copie de son recours. Les règles de procédure et de fonctionnement prévues par ces dispositions s''appliquent au recours organisé en vertu du présent paragraphe. Un membre de la Chambre de recours ne peut participer aux travaux de cette dernière pour l''examen d''un recours introduit par le directeur stagiaire chargé de la direction de l''établissement où il est affecté. Il est dans ce cas remplacé, pour l''examen de ce recours, par son suppléant. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 La Chambre de recours visée à l''alinéa 1er, a), b), ou c) remet son avis au pouvoir organisateur dans un délai maximum d''un mois à partir de la date de réception du recours. Le pouvoir organisateur prend sa décision et attribue la mention d''évaluation au directeur stagiaire dans un délai maximum d''un mois à dater de la réception de l''avis. § 8. Dans l''enseignement libre subventionné, le pouvoir organisateur motive l''attribution d''une mention «défavorable» au directeur stagiaire au sens de l''article 3, § 11, du décret du 1er février 1993 précité. § 9. Le membre du personnel n''est pas nommé ou engagé à titre définitif comme directeur si au plus tard à l''issue de son stage, il n''a pas obtenu les attestations de réussite visées à l''article 15, § 1er, alinéa 1er, et l''attestation de suivi visée à l''article 15, § 1er, alinéa 4. Dans ce cas s''il échet, le membre du personnel réintègre à titre définitif sa fonction et son affectation d''origine. Toutefois, le membre du personnel qui, au terme de son stage, ne dispose pas des attestations de réussite visées à l''article 15, § 1er, alinéa 1er, et de l''attestation de suivi visée à l''article 15, § 1er, alinéa 4, parce qu''il n''a pu suivre les différents modules de la formation visés aux articles 10, §§ 3 et 4, et 11, § 3, en raison d''un manque d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 38, 'Article 33. - § 1er. Sans préjudice des § 2, alinéa 8, § 3, alinéa 4, et § 4, alinéa 5, (partie 3)', 'places disponibles attesté, selon le cas, par l''Institut de la Formation en cours de carrière ou par l''organisme de formation en charge de la formation «réseau» peut obtenir deux prolongations de six mois de son stage. Dans ce cas, l''évaluation en fin de troisième année du stage est reportée à due concurrence. Alinéa inséré par D. 04-02-2021 Le directeur stagiaire qui n''a pu suivre un/des modules de la formation «réseau» en raison de l''absence d''affiliation de son pouvoir organisateur à une fédération de pouvoirs organisateurs peut obtenir une prolongation de son stage d''un an afin de pouvoir suivre et réussir le/les modules réseaux qui lui manque/nt. Modifié par D. 13-09-2018 ; D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 39, 'Article 34. - § 1er. Dans l''enseignement organisé par la Communauté française,', 'Article 34. - § 1er. Dans l''enseignement organisé par la Communauté française, 
tout membre du personnel admis au stage ou désigné à titre temporaire dans une 
fonction de directeur, conformément à l''article 35 peut renoncer à sa désignation à 
quelque moment que ce soit. Dans ce cas, le membre du personnel réintègre à titre 
définitif sa fonction et son affectation d''origine et, sauf circonstances exceptionnelles 
dûment motivées, ne pourra être désigné pour une nouvelle affectation qu''après avoir 
répondu à un nouvel appel lancé conformément à l''article 35, § 1er. 
 
Dans l''enseignement subventionné, il peut être mis fin au stage du directeur à sa 
demande à quelque moment que ce soit. Dans ce cas, le membre du personnel 
réintègre à titre définitif sa fonction et son affectation d''origine. 
 
En cas d''absence de réaction du pouvoir organisateur dans les trente jours 
calendrier à dater de la demande du membre du personnel, celle-ci est réputée 
acceptée. 
 
Remplacé par D. 14-03-2019 
§ 2. Dans l''enseignement organisé par la Communauté française, en cas de 
prolongation du stage d''un directeur au-delà de la durée de trois ans initialement 
prévue afin de lui permettre de remplir les conditions de nomination définies à l''article 
36bis, le pouvoir organisateur peut mettre fin à ce stage selon les modalités prévues à 
l''article 43. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Dans l''enseignement libre subventionné, il peut être mis fin au stage du directeur 
conformément aux dispositions de la section III du chapitre VIII du décret du 1er 
février 1993 précité. 
 
Dans l''enseignement officiel subventionné, il peut être mis fin au stage de 
directeur selon les mêmes modalités qu''à l''article 61, § 4. 
 
Remplacé par D. 14-03-2019 
§ 3. Le pouvoir organisateur peut, pour assurer la continuité dans la fonction de 
direction ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter la 
réintégration du membre du personnel dans sa fonction et son affectation d''origine de 
15 semaines à dater de la demande du membre du personnel ou de la fin d''office du 
stage. Durant ce délai, le directeur stagiaire continue à prester ses fonctions de 
directeur. 
 
Si, au-delà de la période visée à l''alinéa précédent, le poste de directeur n''a pas 
pu être pourvu, la réintégration peut encore être reportée de maximum 15 semaines 
de commun accord entre le pouvoir organisateur et le membre du personnel. 
 
[Chapitre VII. - De la mise à disposition d''ordinateurs portables]3 
 
[Article 34bis. - Les établissements d''enseignement obligatoire, d''enseignement 
pour adultes et d''enseignement secondaire artistique à horaire réduit reçoivent, tous 
les 5 ans, un ordinateur portable fourni par l''ETNIC en vertu de l''article 3, §1er, 1°, du 
décret du 25 octobre 2018 relatif à l''Entreprise Ier publique des Technologies 
Numériques de l''Information et de la Communication de la Communauté française 
(ETNIC). L''ordinateur est mis à la disposition pour un usage professionnel de la 
personne qui exerce les prérogatives de la direction, afin d''accomplir les missions 
définies au Chapitre Ier. 
 
Chaque année, doit être établie la liste des écoles visées par le déploiement.]4 
 
 
TITRE III. - Des dispositions spécifiques à chaque réseau 
 
CHAPITRE Ier. - De l''enseignement organisé par la Communauté française 
 
Section Ire. - Conditions générales d''accès et de dévolution des emplois de 
directeur 
 
Modifié par D. 23-01-2009 ; D. 13-01-2011 ; D. 13-09-2018 ; remplacé par D. 14-03-
2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 40, 'Article 35. - § 1er. Lorsque le pouvoir organisateur doit procéder à une (partie 1)', 'Article 35. - § 1er. Lorsque le pouvoir organisateur doit procéder à une désignation dans un emploi vacant ou dans un emploi qui n''est pas vacant mais dont le titulaire de la fonction est temporairement absent pour une durée de plus de 15 semaines 1° il arrête le profil de la fonction de directeur à pourvoir conformément à l''article 5, § 2, du présent décret; 2° il lance un appel à candidatures selon le modèle visé à l''article 31. Avant d''arrêter le profil de fonction, le pouvoir organisateur : 1° consulte le comité de concertation de base sur le profil de la fonction de directeur à pourvoir; 3Inséré par le D. 16-07-2025 4Inséré par le D. 16-07-2025 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 2° reçoit des membres du personnel toute information que ceux-ci jugent utile de lui communiquer. Pour être désigné en application de l''alinéa 1er, tout candidat doit 1° être porteur d''un titre de niveau bachelier au moins; [modifié par D. 04-02-2021] 2° être porteur d''un titre pédagogique constituant un titre de capacité tel que défini à l''article 17 du décret 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française; 3° compter une ancienneté de service de trois ans au sein de l''enseignement organisé ou subventionné par la Communauté française; 4° avoir répondu à l''appel à candidatures. Par dérogation à l''alinéa précédent 1° à 3°, un candidat peut introduire sa candidature dans un emploi de directeur à condition que la Commission visée à l''article 29 l''ait reconnu éligible comme candidat à une fonction de directeur. Si pouvoir organisateur atteste avoir lancé un appel à candidatures et n''a pas reçu de candidature valable après ce 1er appel, il peut lancer un second appel auquel pourront répondre les candidats ne comptant pas une ancienneté de service de 3 ans au sein de l''enseignement organisé ou subventionné par la Communauté française. Si le candidat à une désignation en application du présent article n''exerce pas de fonction dans l''enseignement organisé ou subventionné par la Communauté française au moment de sa désignation, il ne sera désigné que s''il rencontre également les conditions suivantes : 1° jouir des droits civils et politiques; 2° satisfaire aux dispositions légales et réglementaires relatives au régime linguistique; 3° être de conduite irréprochable; 4° satisfaire aux lois sur la milice. Les candidatures introduites dans le cadre de l''alinéa 1er sont examinées par la Commission de sélection visée à l''article 36ter du présent décret. Au terme de cet examen, la Commission de sélection transmet au pouvoir organisateur le classement des candidats en indiquant les motifs qui fondent ce classement. Après transmission du classement établi en application de l''alinéa précédent, le pouvoir organisateur désigne un des candidats ayant répondu à l''appel dans l''emploi visé à l''alinéa 1er. § 2. Lorsqu''il doit procéder à une désignation temporaire dans un emploi non vacant pour une durée égale ou inférieure à quinze semaines, le pouvoir organisateur désigne un membre du personnel qui répond aux conditions mentionnées à l''alinéa 3 ou 4 du § 1er sans faire application de la procédure prévue à l''alinéa 1er de ce même paragraphe. Cette désignation pour 15 semaines maximum peut être renouvelée pour autant que la durée totale de désignation n''excède pas 12 mois. Si l''absence du titulaire de la fonction se prolonge, le pouvoir organisateur lance un appel à candidatures au plus tard le dernier jour de la période de désignation visée à l''alinéa précédent. L''engagement visé à l''alinéa 1er est prolongé pendant la période entre l''appel à candidatures et la désignation d''un candidat. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Le Pouvoir organisateur désigne un candidat dans les trois mois qui suivent l''appel à candidatures. A défaut, au terme de ces trois mois, l''emploi n''est plus subventionné sauf si le pouvoir organisateur atteste qu''il n''a pu obtenir, à la suite de cet appel, de candidature qui réponde aux critères du profil de fonction. Dans ce cas, par dérogation à l''alinéa précédent, un délai supplémentaire, ne dépassant pas 15 semaines, est octroyé au pouvoir organisateur afin de désigner un directeur au terme d''une nouvelle procédure d''appel. La désignation initiale visée à l''alinéa précédent n''est pas subventionnée au-delà de ce deuxième appel. § 3. Le pouvoir organisateur peut lancer un appel à candidatures conformément aux règles mentionnées au § 1er pour procéder à une désignation temporaire dans un emploi non vacant pour une durée égale ou inférieure à quinze semaines s''il présume, au moment de lancer cet appel, que l''emploi deviendra vacant. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 § 4. Un membre du personnel nommé dans un emploi de directeur dans l''enseignement organisé par la Communauté française qui est désigné dans un autre emploi de directeur du même ense');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 41, 'Article 35. - § 1er. Lorsque le pouvoir organisateur doit procéder à une (partie 2)', 'suite à un appel à candidatures visé au §§ 1er et 3 se voit accorder un changement d''affectation temporaire par le pouvoir organisateur, à condition, toutefois, que l''emploi dans lequel il est désigné soit vacant et que l''emploi de directeur dans lequel il était nommé relève du même pouvoir organisateur. Par dérogation à l''alinéa précédent, le membre du personnel ne peut obtenir un changement d''affectation qu''après avoir exercé ses fonctions dans l''emploi qu''il occupe durant un délai de trois ans. Le directeur ainsi désigné est mis en congé pour stage pour une durée d''un an conformément à l''article 9 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécialisé, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. Après un an, le pouvoir organisateur effectue une évaluation du directeur désigné en application du présent paragraphe. Cette évaluation est axée sur l''adéquation aux éléments du profil de fonction spécifiques à l''établissement. Si cette évaluation est favorable, le membre du personnel démissionne de son emploi d''origine et est affecté définitivement dans l''emploi qu''il occupe. En cas d''évaluation défavorable, il est mis fin à son changement d''affectation et il réintègre l''emploi de directeur dans lequel il était nommé avant son changement d''affectation. Le membre du personnel qui se voit accorder un changement d''affectation temporaire en application du présent paragraphe réintègre l''emploi de directeur qu''il occupait avant son changement d''affectation s''il en fait la demande auprès du pouvoir organisateur. § 5. Lorsqu''un directeur définitif dans l''enseignement subventionné par la Communauté française est désigné, suite à un appel à candidatures, dans un emploi de directeur dans l''enseignement organisé par la Communauté française, ce dernier l''admet au stage si l''emploi est définitivement vacant ou le désigne à titre temporaire si l''emploi est temporairement vacant. Durant cette période, le directeur reste titulaire de son emploi d''origine. Par dérogation à l''alinéa précédent, le membre du personnel ne peut être admis au stage ou désigné à titre temporaire qu''après avoir exercé ses fonctions dans l''emploi qu''il occupe durant un délai de trois ans. Après un an, le pouvoir organisateur effectue une évaluation axée sur l''adéquation aux éléments du profil de fonction spécifique à l''établissement. En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son l''emploi d''origine. Après deux ans, le pouvoir organisateur effectue une deuxième évaluation axée sur l''adéquation aux éléments du profil de fonction spécifique à l''établissement. Si cette évaluation est favorable, le directeur est nommé à titre définitif dans l''emploi qu''il occupe, lorsque celui-ci est définitivement vacant. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son emploi d''origine. Il peut, en outre, être mis fin à la fonction conformément aux articles 33 et 34. Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 42, 'Article 36. - Le membre du personnel désigné dans un emploi de directeur en', 'Article 36. - Le membre du personnel désigné dans un emploi de directeur en 
application de l''article 35, §§ 1er et 3, est admis au stage dans cet emploi à condition 
qu''il soit vacant. 
 
La durée du stage d''un membre du personnel qui a été désigné initialement dans 
un emploi non vacant en application de l''article 35, §§ 1er et 3, est réduite à 
concurrence du temps déjà presté, à titre temporaire, dans cet emploi. 
 
Les évaluations du membre du personnel visé à l''alinéa précédent se font, 
mutatis mutandis, conformément à l''article 33, §§ 2 à 5. 
 
Le membre du personnel qui a été désigné à titre temporaire en application de 
l''article 35, §§ 1er et 3, dans un emploi non vacant, et ce de manière ininterrompue, 
depuis 3 ans au moins à la date à laquelle l''emploi devient vacant, est nommé dans cet 
emploi, à condition qu''il remplisse les conditions de nomination prévues à l''article 
36bis. 
Insérée par D. 14-03-2019 
Section Ibis. - Conditions de nomination dans la fonction de directeur 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 43, 'Article 36bis. - Pour être nommé dans la fonction de directeur, le membre du', 'Article 36bis. - Pour être nommé dans la fonction de directeur, le membre du 
personnel doit remplir les conditions suivantes : 
1° avoir été désigné dans un emploi de directeur en application de la procédure 
prévue à l''article 35; 
2° avoir obtenu les attestations de réussite visées à l''article 15, § 1er, alinéa 1er, et 
l''attestation de suivi visée à l''article à l''article 15, § 1er, alinéa 4; 
3° compter une ancienneté de service de 6 ans; 
4° avoir obtenu trois évaluations dont la dernière a abouti à la mention 
«favorable». 
 
L''ancienneté de service reprise au point 3° de l''alinéa précédent est calculée selon 
les règles définies à l''article 3sexies de l''arrêté royal du 18 janvier 1974 pris en 
application de l''article 164 de l''arrêté royal du 22 mars 1969 fixant le statut des 
membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du 
personnel paramédical des établissements d''enseignement gardien, primaire, spécial, 
moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé de la 
surveillance de ces établissements. 
 
Insérée par D. 14-03-2019 
Section Iter. - Des Commissions de sélection des directeurs 
 
Inséré par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 44, 'Article 36ter. - § 1er. Le pouvoir organisateur crée une ou des commissions de', 'Article 36ter. - § 1er. Le pouvoir organisateur crée une ou des commissions de 
sélection des directeurs. Il en fixe la composition. 
 
Au sein de la Commission, doivent néanmoins être désignés au moins un membre 
disposant d''une expertise pédagogique et un ou plusieurs membres extérieurs au 
pouvoir organisateur disposant d''une expérience en ressources humaines et en matière 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
de sélection de personnel. 
 
La composition de la commission de sélection est communiquée aux services du 
Gouvernement selon les modalités qu''ils fixent. 
 
§ 2. La sélection des candidats se fonde sur le profil de fonction élaboré par le 
pouvoir organisateur conformément à l''article 5, § 2, et annexé à l''appel à 
candidatures et, plus particulièrement, sur l''évaluation des compétences techniques et 
comportementales des candidats, assorties d''indicateurs de maîtrise, et leur 
compatibilité avec le projet éducatif et pédagogique du pouvoir organisateur. 
 
La commission de sélection peut opérer un tri des candidatures sur dossier et 
n''entendre que les candidats retenus suite à cette sélection. 
 
Au terme des auditions, celle-ci établit un rapport classant les candidats et 
fournissant toutes informations utiles pour motiver le classement. 
 
Ce rapport est adressé au pouvoir organisateur qui, sur cette base, prend la 
décision d''admission au stage. 
 
A la demande de tout candidat, le pouvoir organisateur lui communique les 
informations 
relatives 
à 
l''évaluation 
de 
ses 
compétences 
techniques 
et 
comportementales et à la compatibilité de ces compétences avec les critères de 
sélection définis et pondérés par le profil de fonction. 
 
Section II. - De la Commission d''évaluation des directeurs […] Abrogée par  D. 
14-03-2019 
 
Articles 37 à 38 – […] Abrogés par D. 14-03-2019 
 
Section III. – [Des mécanismes de soutien, de développement des 
compétences professionnelles et d’évaluation]5');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 45, 'Article 39. – [Cette section s''applique aux directeurs nommés à titre définitif. (partie 1)', 'Article 39. – [Cette section s''applique aux directeurs nommés à titre définitif. Elle s''applique également au membre du personnel désigné à titre temporaire dans la fonction de directeur pour une durée égale ou supérieure à un an. La dénomination «directeur» visée à la présente section vise également ce membre du personnel. Les membres du pouvoir organisateur chargés de l''évaluation ont accès à la formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, au développement des compétences professionnelles et à l''évaluation des personnels de l''enseignement. Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en ressources humaines pour procéder aux entretiens et/ou évaluations visés à la sous-section II.]6 5 Intitulé remplacé par le décret du 20 juillet 2023 6 Remplacé par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 [Sous-section I. – Du mécanisme de soutien et de développement des compétences professionnelles]7 Remplacé par D. 14-03-2019 [Article 40. – §1er. Le mécanisme de soutien et de développement des compétences professionnelles est composé, notamment, d''entretiens de développement professionnel entre le directeur et son pouvoir organisateur ou son délégué et d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Ces entretiens de développement professionnel sont organisés à l''initiative du pouvoir organisateur mais peuvent également être demandés par le directeur à tout moment de l''année. Un délai de minimum cinq jours ouvrables doit être garanti entre la convocation à l''entretien de développement professionnel et la date de l''entretien de développement professionnel. L''entretien de développement professionnel doit faire l''objet d''un compte-rendu. Un entretien de développement professionnel doit avoir lieu dans la mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. L''entretien de développement professionnel porte sur l''exécution de la lettre de mission visée au chapitre III du Titre 1er et sur la mise en œuvre du contrat d''objectifs, quand celui-ci existe. Dans le cadre de l''entretien de développement professionnel, il est tenu compte du contexte global dans lequel est amené à évoluer le directeur et des moyens mis à sa disposition. Dans ce cadre, le pouvoir organisateur ou son délégué prend en considération : a) dans l''enseignement maternel et dans l''enseignement obligatoire, les dispositions relatives aux projets éducatif et pédagogique du pouvoir organisateur et au projet d''établissement visés au titre 5 du Code de l''enseignement fondamental et de l''enseignement secondaire; b) dans l''enseignement de promotion sociale, les dispositions relatives au projet pédagogique visé à l''article 36ter, du décret du 16 avril 1991 précité. §2. A la suite du premier entretien de développement professionnel ou à la demande du pouvoir organisateur ou du directeur, un plan de développement des compétences professionnelles est mis en place. Ce plan de développement des compétences professionnelles est élaboré par le pouvoir organisateur ou son délégué en concertation avec le directeur. §3. Ce plan de développement des compétences professionnelles est formalisé dans un document cosigné par le directeur et le pouvoir organisateur ou son délégué, tel que visé à l''article 41 et contient des engagements mutuels des deux parties tels que des objectifs individualisés, spécifiques, réalistes et adaptés au directeur ainsi que les moyens mis à sa disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. L''obligation de co-signature visée à l''alinéa précédent est réputée remplie dès lors 7 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 que le pouvoir organisateur ou son délégué fait la preuve que la demande de signature pour prise de connaissance a été adressée au membre du personnel. En cas de refus de signature du directeur, la procédure suit normalement son cours dans la mise en œuvre du plan de développement des compétences professionnelles. Ce document peut, le cas échéant, servir de base à la rédaction du rapport d''évaluation visé à l''article 42. §4. Sa périodicité est adaptée de manière à permettre au directeur de mettre en place les conseils dispensés ou de suivre les formations recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement des compétences professionnelles par année scolaire. Toutefois, durant une même année scolaire, un membre du personnel faisant l''objet d''un plan de développement des compétences professionnelles peut également être amené à avoir un plan d''accompagnement individualisé élaboré suite à une première évaluation avec mention « défavorable ». §5. Le plan de développement des compétences professionnelles peut faire l''objet d''ajustements à l''initiative du pouvoir organisateur ou son délégué ou à la demande du directeur. Ces ajustements sont cosignés par le');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 46, 'Article 39. – [Cette section s''applique aux directeurs nommés à titre définitif. (partie 2)', 'directeur et le membre du personnel. En cas de refus de signature du membre du personnel, la procédure de mise en œuvre du plan de développement des compétences professionnelles se poursuit valablement. §6. Le plan de développement des compétences professionnelles donne lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois après la mise en place du plan de développement des compétences professionnelles et au plus tard deux ans après celle-ci. L''entretien de clôture est mené par le pouvoir organisateur ou son délégué. L''entretien de clôture fait l''objet d''un compte-rendu. §7. Pour le calcul des délais de six mois et deux ans précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]8. Remplacé par D. 14-03-2019 [Article 41. – Le Gouvernement fixe le modèle de plan de développement des compétences professionnelles pouvant servir de base d’évaluation visée dans la sous- section II]9. 8 Remplacé par le décret du 20 juillet 2023 9 Remplacé par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 [Sous-section II. – Du mécanisme d’évaluation]10 Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 47, 'Article 42. – [En fonction de cette évaluation, le pouvoir organisateur convient (partie 1)', 'Article 42. – [En fonction de cette évaluation, le pouvoir organisateur convient avec le directeur, à la suite de l''entretien d''évaluation, des améliorations à apporter]11. [Article 42bis. - §1er. Après un délai de minimum six mois d''exercice de la fonction entre la communication au directeur du plan d''accompagnement individualisé convenu lors de l''évaluation avec mention défavorable qui précède, une nouvelle 10 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 11 Remplacé par le décret du 20 juillet 2023 à partir du premier jour de l’année scolaire 2026-2027 par : « Article 42. - §1er. Une évaluation ne peut avoir lieu qu''une fois par année scolaire. §2. Toute première évaluation doit être précédée d''un plan de développement des compétences professionnelles et d''un entretien de clôture tels que visés à la sous-section I. §3. Au plus tôt six mois après avoir communiqué ce plan de développement des compétences professionnelles au directeur et pour autant que l''entretien de clôture visé à l''article 40, §6 ait eu lieu, en cas de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste et répétée à atteindre les objectifs identifiés avec le directeur dans le cadre du plan de développement des compétences professionnelles, le pouvoir organisateur peut procéder à une évaluation de celui-ci. Ce délai est calculé conformément à l''article 42bis. §4. Le directeur doit avoir été entendu préalablement à l''attribution de la mention d''évaluation, par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel en activité de service ou retraités de l''enseignement organisé par la Communauté française ou par un représentant d''une organisation syndicale représentative. §5. L''évaluation débouche sur une mention « favorable » ou « défavorable ». Elle est formalisée selon le document visé à l''article 42quinquies et notifiée au membre du personnel. La mention d''évaluation est motivée sur base du plan de développement des compétences professionnelles. En l''absence de rapport d''évaluation, tout membre du personnel est réputé bénéficier de la mention « favorable ». §6. En cas d''évaluation débouchant sur la mention « défavorable », un entretien entre le directeur et le pouvoir organisateur ou son délégué est, ensuite, fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation et prenant en compte le plan de développement des compétences professionnelles. Celui-ci détermine les objectifs que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de quatre objectifs peut être fixé. Le plan d''accompagnement individualisé donne lieu à un entretien de clôture. L''entretien de clôture fait l''objet d''un compte-rendu, préalablement à toute nouvelle évaluation. ». Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 évaluation peut avoir lieu. Toutefois, après une évaluation avec mention « défavorable », l''évaluation suivante doit intervenir dans un délai maximum de deux ans suivant la communication du plan d''accompagnement individualisé faisant suite à la précédente évaluation. A défaut, elle est réputée favorable. Ce délai doit permettre au directeur de remédier aux carences constatées. Une évaluation ne peut avoir lieu qu''une fois par année scolaire. Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir dans un délai plus long en cas de prolongation du plan d''accompagnement individualisé telle que visée à l''article 42ter. §2. Pour le calcul des délais de six mois et deux ans visés au §1er, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]12. [Article 42ter. - §1er. Le rapport d''évaluation faisant suite à une première évaluation définitive avec mention « défavorable » est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, en cas d''un commun accord entre le membre du personnel et le pouvoir organisateur sur');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 48, 'Article 42. – [En fonction de cette évaluation, le pouvoir organisateur convient (partie 2)', 'la prolongation du plan d''accompagnement individualisé. Le rapport d''évaluation est formalisé selon le document visé à l''article 42quinquies ainsi que notifié au directeur. La prolongation du plan d''accompagnement individualisé est de minimum trois mois et de maximum un an. La mention d''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le membre du personnel peut se faire assister par un défenseur choisi parmi les membres du personnel de l''enseignement organisé par la Communauté française, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. §2. En cas de prolongation du plan d''accompagnement individualisé, un entretien 12 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolair 2026- 2027) Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 entre, d''une part, le pouvoir organisateur et, d''autre part, le directeur est fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan d''accompagnement individualisé précédent que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé. Le plan d''accompagnement individualisé donne lieu à un entretien de clôture. L''entretien de clôture fait l''objet d''un compte-rendu. §3. Après prolongation du plan d''accompagnement individualisé, une nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai maximum d''un an d''exercice de la fonction à partir de la communication au membre du personnel du plan d''accompagnement individualisé adapté à la suite de la prolongation du plan d''accompagnement individualisé. Ce délai doit permettre au directeur de remédier aux carences constatées. A défaut, elle est réputée favorable. §4. Pour le calcul des délais de trois mois et un an visés au §4, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. §5. Le rapport d''évaluation faisant suite à une prolongation du plan d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » et est formalisé selon le document visé à l''article 42quinquies ainsi que notifié au directeur. La mention d''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le membre du personnel peut se faire assister par un défenseur choisi parmi les membres du personnel de l''enseignement organisé par la Communauté française, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. Une évaluation ne peut avoir lieu qu''une fois par année scolaire]13. [Article 42quater. - §1er. En cas d''évaluation avec mention « défavorable », le directeur peut, dans les 10 jours ouvrables, introduire un recours conformément aux 13 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolair 2026- 2027) Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 modalités décrites aux articles 121/16 à 121/24 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de c');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 49, 'Article 42. – [En fonction de cette évaluation, le pouvoir organisateur convient (partie 3)', 'établissements, applicables mutatis mutandis. Le directeur qui fait usage de son droit de recours en notifie immédiatement une copie à son pouvoir organisateur. Ce recours est suspensif. §2. Il est mis fin d''office aux fonctions du directeur qui fait l''objet deux mentions « défavorable » consécutives sur deux années scolaires distinctes conformément à l''article 169, alinéa 1er, 5° de l''arrêté royal du 22 mars 1969 précité, et devenues définitives après épuisement des procédures devant la chambre d''appel, telles que visées à l''article 121/13 de l''arrêté royal du 22 mars 1969 précité]14. [Article 42quinquies. - Le Gouvernement fixe les modèles de plan d''accompagnement individualisé et de rapport d''évaluation]15. [Article 42sexies. - Toute notification de document, de décision ou de convocation mentionnée dans la présente sous-section se fait par courrier recommandé avec accusé de réception ou par une remise de la main à la main avec accusé de réception. »]16. [Sous-section III.- Dès règles de déontologie]17 [Article 42septies. - Dans le cadre des entretiens et évaluations visés à la présente section, le membre du personnel et son évaluateur sont tenus au respect des devoirs suivants : a) la discrétion ; b) le respect mutuel. En outre, l''évaluateur est tenu de : a) motiver, de manière adéquate et constructive, ses instructions, conseils et échanges avec le membre du personnel ainsi que la mention d''évaluation ; b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; c) respecter les devoirs d''impartialité et d''objectivité]18. 14 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 15 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 16 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 17 Ajouté par le décret du 20 juillet 2023 18 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Inséré par D.10-02-2011 Section IIIbis. Du retrait des fonctions supérieures de directeur à titre temporaire Modifié par D. 11-07-2018(1) ; D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 50, 'Article 43. - Moyennant un préavis de 15 jours, le pouvoir organisateur peut', 'Article 43. - Moyennant un préavis de 15 jours, le pouvoir organisateur peut 
mettre fin à la désignation d''un membre du personnel désigné en application de 
l''article 35. 
 
Préalablement à  toute décision du pouvoir organisateur, le membre du personnel 
doit avoir été invité à se faire entendre par le pouvoir organisateur ou son délégué. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le pouvoir 
organisateur envisage de mettre fin à la désignation du membre du personnel lui sont 
notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à 
la poste, soit par la remise d''une lettre de la main à la main avec accusé de réception. 
Lors de l''audition, le membre du personnel peut se faire assister ou représenter par un 
avocat, par un défenseur choisi parmi les membres du personnel en activité de service 
ou pensionnés de l''enseignement organisé par la Communauté française ou par un 
représentant d''une organisation syndicale représentant les membres du personnel de 
l''enseignement de la Communauté française affiliée à des organisations siégeant au 
Conseil national du Travail. L''audition fait l''objet d''un procès-verbal. La procédure se 
poursuit valablement lorsque le membre du personnel dûment convoqué ne se 
présente pas à l''audition ou n''y est pas représenté. 
 
Le pouvoir organisateur prend sa décision dans les 10 jours de la transmission du 
procès-verbal dressé par le pouvoir organisateur ou son délégué. 
 
Section IV. - Des passerelles entre fonctions de promotion, de sélection et de 
recrutement');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 51, 'Article 44. - Dans l''article 14ter, § 1er, alinéa 2, de l''arrêté royal du 22 mars 1969', 'Article 44. - Dans l''article 14ter, § 1er, alinéa 2, de l''arrêté royal du 22 mars 1969 
fixant le statut des membres du personnel directeur et enseignant, du personnel 
auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, 
gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de 
l''Etat, des internats dépendant de ces établissements et des membres du personnel du 
service d''inspection chargé de la surveillance de ces établissements, modifié par le 
décret du 29 mars 2001, il est ajouté un point 9° libellé comme suit : 
«9° en matière de nouvelle affectation, conformément à l''article 50, § 2, b), § 3 
et § 4.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 52, 'Article 45. - Dans l''article 14quater, § 1er, alinéa 2, du même arrêté, modifié par', 'Article 45. - Dans l''article 14quater, § 1er, alinéa 2, du même arrêté, modifié par 
le décret du 29 mars 2001, il est ajouté un point 6° libellé comme suit : 
«6° en matière de nouvelle affectation, conformément à l''article 50, § 2, a), § 4 
et § 5, a).»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 53, 'Article 46. - Dans l''article 46, § 3 du même arrêté, remplacé par l''arrêté du', 'Article 46. - Dans l''article 46, § 3 du même arrêté, remplacé par l''arrêté du 
Gouvernement de la Communauté française du 10 juin 1993, est ajouté l''alinéa 
suivant : 
«Une nouvelle affectation dans une fonction de recrutement conformément à 
l''article 50, ne peut être accordée dans un emploi occupé par un temporaire 
prioritaire.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 54, 'Article 47. - L''article 49 du même arrêté, abrogé par l''arrêté du Gouvernement', 'Article 47. - L''article 49 du même arrêté, abrogé par l''arrêté du Gouvernement 
de la Communauté française du 10 juin 1993 et rétabli par l''arrêté du Gouvernement 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
de la Communauté française du 4 juillet 1994 est complété par les termes suivants : 
«et sur le membre du personnel visé à l''article 50, § 5, a).»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 55, 'Article 48. - L''article 50 du même arrêté, abrogé par l''arrêté du Gouvernement', 'Article 48. - L''article 50 du même arrêté, abrogé par l''arrêté du Gouvernement 
de la Communauté française du 10 juin 1993, est rétabli et inséré dans une nouvelle 
Section 3bis libellée comme suit : 
 
«Section 3bis. - Des passerelles entre fonctions de recrutement, de sélection et de 
promotion.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 56, 'Article 50. - § 1er. Un membre du personnel nommé à titre définitif dans une', 'Article 50. - § 1er. Un membre du personnel nommé à titre définitif dans une 
fonction de sélection ou de promotion peut, à sa demande, obtenir une nouvelle 
affectation dans un emploi vacant d''une fonction de recrutement, de sélection ou de 
promotion qui donne accès à sa fonction actuelle. 
 
Le membre du personnel qui bénéficie du présent mécanisme ne peut plus se 
porter candidat à l''exercice de la fonction qu''il a quittée, sauf dérogation justifiée par 
des circonstances exceptionnelles et accordée par le Gouvernement, durant un délai de 
dix ans débutant au jour d''introduction de sa demande prévue au § 2. 
 
§ 2. a) Le membre du personnel qui désire obtenir une nouvelle affectation 
conformément au § 1er dans une fonction de recrutement ou de sélection, dans un 
établissement de la zone au sein de laquelle il est affecté, introduit, par pli 
recommandé, une demande motivée par des circonstances exceptionnelles auprès du 
Gouvernement dans le courant du mois de janvier. Il en adresse copie au président de 
la commission zonale d''affectation compétente. 
 
Le Gouvernement accorde la nouvelle affectation si le membre du personnel 
remplit toutes les conditions d''accès à la fonction concernée et moyennant avis 
favorable de la commission précitée. Cette nouvelle affectation produit ses effets le 1er 
juillet suivant. 
 
b) Le membre du personnel qui désire obtenir une nouvelle affectation 
conformément au § 1er dans une fonction de recrutement ou de sélection, dans un 
établissement d''une autre zone introduit, par pli recommandé, une demande motivée 
par les circonstances exceptionnelles auprès du Gouvernement dans le courant du 
mois de janvier. Il en adresse copie au président de la commission interzonale 
d''affectation compétente. 
 
Le Gouvernement accorde la nouvelle affectation si le membre du personnel 
remplit toutes les conditions d''accès à la fonction concernée et moyennant avis 
favorable de la commission précitée. 
 
Cette nouvelle affectation produit ses effets le 1er juillet suivant. 
 
c) Le membre du personnel visé au présent paragraphe auquel le Gouvernement 
accorde une nouvelle affectation dans une fonction de recrutement conformément 
au § 1er est appelé en service avant toute désignation en qualité de temporaire 
prioritaire, telle que prévue à l''article 37. 
 
§ 3. Le membre du personnel qui désire obtenir une nouvelle affectation 
conformément au § 1er dans une fonction de promotion autre que celle dans laquelle il 
est nommé à titre définitif d''un établissement de la même zone ou d''une autre zone, 
introduit, par pli recommandé, une demande motivée par les circonstances 
exceptionnelles auprès du Gouvernement dans le courant du mois d''octobre. Il en 
adresse copie au président de la commission interzonale d''affectation compétente. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Le Gouvernement accorde la nouvelle affectation si le membre du personnel 
remplit toutes les conditions d''accès à la fonction concernée et moyennant avis 
favorable de la commission précitée. 
 
Cette nouvelle affectation produit ses effets le 1er janvier suivant. 
 
Le présent paragraphe ne s''applique pas au personnel du service d''inspection. 
 
§ 4. Une nouvelle affectation conformément au § 1er peut s''opérer provisoirement 
dans un emploi non vacant, si cet emploi est libéré pour une année scolaire au moins. 
 
La nouvelle affectation dans un emploi non vacant s''opère selon les modalités 
définies respectivement au § 2 et au § 3. 
 
§ 5. Le membre du personnel qui a bénéficié de l''application du § 4 est 
définitivement affecté au sein de l''établissement dans un emploi vacant de la fonction : 
a) le premier jour de l''année scolaire qui suit la notification visée à l''article 17bis, 
pour autant que la commission zonale d''affectation et la commission interzonale 
d''affectation se soient réunies entre la date de la notification précitée et le premier 
jour de l''année scolaire, si la nouvelle affectation a lieu dans une fonction de 
recrutement; 
b) le 1er jour du mois qui suit la notification visée à l''article 17bis si la nouvelle 
affectation a lieu dans une fonction de sélection ou de promotion. 
 
§ 6. L''emploi dont était titulaire un membre du personnel affecté conformément 
au § 4 est vacant si celui-ci ne réintègre pas cet emploi après deux années scolaires 
consécutives. La vacance est notifiée conformément à l''article 17bis.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 57, 'Article 51. - Le membre du personnel visé à l''article 50 se voit attribuer l''échelle', 'Article 51. - Le membre du personnel visé à l''article 50 se voit attribuer l''échelle 
de traitement de la fonction dans laquelle il est affecté conformément à cette 
disposition. 
 
Toutefois, le membre du personnel visé à l''article 50, qui a exercé à titre définitif 
pendant au moins dix ans la fonction de sélection ou de promotion qu''il quitte, 
bénéficie d''un mécanisme dégressif d''échelles de traitement pour rejoindre à partir de 
la 3e année l''échelle de traitement de la fonction dans laquelle il est affecté 
conformément à l''article 50, fixé comme suit : 
a) Au cours de la première année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 66 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté; 
b) Au cours de la deuxième année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 33 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 58, 'Article 49. - L''article 78, alinéa 3 du même arrêté est complété par les termes / Article 50. - L''article 92, alinéa 2 du même arrêté est complété par les termes', 'Article 49. - L''article 78, alinéa 3 du même arrêté est complété par les termes 
suivants : «ou par application de l''article 50.»

Article 50. - L''article 92, alinéa 2 du même arrêté est complété par les termes 
suivants : «ou par application de l''article 50.» 
 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Section V. - Dispositions modificatives');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 59, 'Article 51. - Dans l''arrêté royal du 22 mars 1969 précité, sont apportées les', 'Article 51. - Dans l''arrêté royal du 22 mars 1969 précité, sont apportées les 
modifications suivantes : 
 
a) L''article 78, modifié par l''arrêté royal du 16 février 1983, par l''arrêté de 
l''Exécutif du 24 août 1992 et par l''arrêté du Gouvernement de la Communauté 
française du 10 juin 1993 est complété par les alinéas suivants : 
 
«Moyennant un préavis de quinze jours, le Gouvernement peut, soit sur 
proposition du directeur, soit d''initiative, mettre fin à la désignation d''un membre du 
personnel exerçant une fonction de sélection désigné à titre temporaire. 
 
Préalablement à toute décision du Gouvernement, le membre du personnel doit 
avoir été invité à se faire entendre par le fonctionnaire général désigné par le 
Gouvernement ou son délégué lorsque la décision est prise d''initiative, par le directeur 
lorsque ce dernier est à la base de proposition. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le 
Gouvernement envisage de mettre fin à la désignation du membre du personnel ou en 
raison desquels le directeur envisage d''en faire la proposition au Gouvernement, lui 
sont notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste, soit par la remise d''une lettre de la main à la main avec 
accusé de réception. Lors de l''audition, le membre du personnel peut se faire assister 
ou représenter par un avocat, par un défenseur choisi parmi les membres du personnel 
en activité de service ou pensionnés de l''enseignement organisé par la Communauté 
française ou par un représentant d''une organisation syndicale représentant les 
membres du personnel de l''enseignement de la Communauté française affiliée à des 
organisations siégeant au Conseil national du Travail. L''audition fait l''objet d''un 
procès-verbal. La procédure se poursuit valablement lorsque le membre du personnel 
dûment convoqué ne se présente pas à l''audition ou n''y est pas représenté. 
 
Lorsque la proposition est formulée par le directeur, elle est soumise au membre 
du personnel au moment où elle est formulée. Ce dernier vise et date la proposition. Il 
la restitue le jour même. S''il estime que la proposition n''est pas fondée, il la vise en 
conséquence, la date et la restitue dans le même délai. Le directeur transmet, le jour 
même, la proposition au Gouvernement. 
 
Le Gouvernement prend sa décision dans les dix jours de cette transmission ou 
de la transmission du procès-verbal dressé par l''Administrateur général de 
l''Enseignement et de la Recherche scientifique ou son délégué». 
 
b) L''alinéa 1er de l''article 83, tel que modifié par le décret du 3 mars 2004, est 
modifié comme suit : 
1. au 3°bis, les termes «3 000 jours» sont remplacés par les termes «1 800 jours»; 
2. au 4°, les termes «1 800 jours» sont remplacés par les termes «600 jours». 
 
c) Les articles 78 à 91 du chapitre VII, tel que modifié par l''arrêté du 
Gouvernement du 10 juin 1993 forment une section intitulée «Section 1re. -
 Dispositions générales». 
 
d) Une section 2, intitulée «Section 2. - De la lettre de mission et de l''évaluation 
de certaines fonctions de sélection de l''enseignement de promotion sociale», rédigée 
comme suit, est insérée entre l''article 91 et l''article 92 : 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
«Section 2. - De la lettre de mission et de l''évaluation de certaines fonctions de 
sélection de l''enseignement de promotion sociale.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 60, 'Article 91bis. - § 1er. La présente section s''applique aux membres du personnel', 'Article 91bis. - § 1er. La présente section s''applique aux membres du personnel 
titulaires d''une fonction de sélection telle que visée à l''article 6ter, 6°, b de l''arrêté de 
l''Exécutif de la Communauté française du 2 octobre 1968 déterminant et classant les 
fonctions des membres du personnel directeur et enseignant, du personnel auxiliaire 
d''éducation, du personnel paramédical, du personnel psychologique et du personnel 
social des établissements d''enseignement préscolaire, primaire, spécialisé, moyen, 
technique, artistique, de promotion sociale et supérieur non universitaire de la 
Communauté française et les fonctions des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements dans l''enseignement de 
plein exercice. 
 
§ 2. Pour l''application de la présente section, il faut entendre par «directeur» le 
membre du personnel titulaire, à quelque titre que ce soit, de la fonction de promotion 
de directeur d''établissement de promotion sociale telle que prévue à l''article 6ter, 6°, a 
de l''arrêté de l''Exécutif de la Communauté française du 2 octobre 1968 déterminant et 
classant les fonctions des membres du personnel directeur et enseignant, du personnel 
auxiliaire d''éducation, du personnel paramédical, du personnel psychologique et du 
personnel social des établissements d''enseignement préscolaire, primaire, spécialisé, 
moyen, technique, artistique, de promotion sociale et supérieur non universitaire de la 
Communauté française et les fonctions des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements dans l''enseignement de 
plein exercice. 
 
Sous-section Ire. - De la lettre de mission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 61, 'Article 91ter. - Dès l''entrée en fonction du membre du personnel visé à l''article', 'Article 91ter. - Dès l''entrée en fonction du membre du personnel visé à l''article 
91bis du présent arrêté, le directeur lui confie une lettre de mission, approuvée 
préalablement par la Commission d''évaluation visée à l''article 37 du décret du 2 
février 2007 fixant le statut des directeurs. 
 
Le directeur y spécifie les missions du membre du personnel visé à l''article 91bis 
et les priorités qui lui sont assignées, en fonction des besoins de l''établissement au 
sein duquel il est affecté et en fonction des objectifs contenus dans la lettre de mission 
que ce dernier a lui-même reçue, conformément au chapitre III du titre II du décret du 
2 février 2007 fixant le statut des directeurs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 62, 'Article 91quater. - § 1er. La lettre de mission a une durée de six ans.', 'Article 91quater. - § 1er. La lettre de mission a une durée de six ans. 
 
§ 2. Le contenu de la lettre de mission peut être modifié avant son échéance, au 
plus tôt après deux ans, par le directeur, en raison de l''évolution des besoins et du 
fonctionnement de l''établissement. 
 
Par dérogation à l''alinéa 1er, le contenu de la lettre de mission peut être modifié 
avant son échéance, de commun accord entre le directeur et le membre du personnel 
visé à l''article 91bis.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 63, 'Article 91quinquies. - § 1er. Par dérogation à l''article 91ter, alinéa 1er, le', 'Article 91quinquies. - § 1er. Par dérogation à l''article 91ter, alinéa 1er, le 
directeur, si besoin est, peut confier une lettre de mission au membre du personnel 
désigné à titre temporaire dans l''exercice d''une fonction visée à l''article 91bis du 
présent décret. 
 
Le directeur confie d''office une lettre de mission au membre du personnel désigné 
à titre temporaire dans l''exercice d''une fonction visée à l''article 91bis pour une durée 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
égale ou supérieure à un an, ou dont la durée de la désignation a atteint au moins un 
an. 
 
§ 2. La lettre de mission visée au présent article peut consister dans la 
confirmation de la lettre de mission du membre du personnel visé à l''article 91bis 
faisant l''objet d''un remplacement ou dans un nouveau document. 
 
Sous-section II. - De l''évaluation formative');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 64, 'Article 91sexies. - Cette section s''applique au membre du personnel nommé à', 'Article 91sexies. - Cette section s''applique au membre du personnel nommé à 
titre définitif. 
 
Elle s''applique également au membre du personnel désigné à titre temporaire 
dans l''exercice d''une fonction visée à l''article 91bis pour une durée égale ou supérieure 
à un an, ou dont la durée de la désignation a atteint au moins un an. La dénomination 
«membre du personnel» visée à la présente section vise également ce membre du 
personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 65, 'Article 91septies. - Tous les cinq ans à dater de sa nomination à titre définitif ou', 'Article 91septies. - Tous les cinq ans à dater de sa nomination à titre définitif ou 
de sa désignation à titre temporaire, chaque membre du personnel fait l''objet d''une 
évaluation effectuée conjointement par le directeur et la Commission d''évaluation 
visée à l''article 37 du décret du 2 février 2007 fixant le statut des directeurs. 
 
Si ce dernier le juge utile, il peut procéder, plus tôt, à une évaluation du membre 
du personnel. 
 
Toutefois, sans préjudice de l''article 91octies, le membre du personnel ne peut 
faire l''objet de plus de deux évaluations par période de dix ans.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 66, 'Article 91octies. - L''évaluation se fonde sur l''exécution de la lettre de mission', 'Article 91octies. - L''évaluation se fonde sur l''exécution de la lettre de mission 
visée à la section I du présent chapitre et, le cas échéant, sur la mise en pratique des 
compétences acquises dans le cadre des formations visées au présent arrêté.  
 
Elle tient compte du contexte global dans lequel est amené à évoluer le membre 
du personnel et des moyens qui sont mis à sa disposition.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 67, 'Article 91novies. - En fonction de cette évaluation, le directeur convient avec le', 'Article 91novies. - En fonction de cette évaluation, le directeur convient avec le 
membre du personnel des améliorations à apporter.» 
 
a) L''article 92 modifié par l''arrêté royal du 16 février 1983, par l''arrêté de 
l''Exécutif du 24 août 1992 et par l''arrêté du Gouvernement de la Communauté 
française du 10 juin 1993 est complété comme suit : 
«Moyennant un préavis de quinze jours, le Gouvernement peut mettre fin à la 
désignation d''un membre du personnel exerçant une fonction de promotion désigné à 
titre temporaire. 
 
Préalablement à toute décision du Gouvernement, le membre du personnel doit 
avoir été invité à se faire entendre par le fonctionnaire général désigné par le 
Gouvernement ou son délégué. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le directeur 
envisage de mettre fin à la désignation du membre du personnel lui sont notifiés cinq 
jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors de 
l''audition, le membre du personnel peut se faire assister ou représenter par un avocat, 
par un défenseur choisi parmi les membres du personnel en activité de service ou 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
pensionnés de l''enseignement organisé par la Communauté française ou par un 
représentant d''une organisation syndicale représentant les membres du personnel de 
l''enseignement de la Communauté française affiliée à des organisations siégeant au 
Conseil national du Travail. L''audition fait l''objet d''un procès-verbal. La procédure se 
poursuit valablement lorsque le membre du personnel dûment convoqué ne se 
présente pas à l''audition ou n''y est pas représenté. 
 
Le Gouvernement prend sa décision dans les dix jours de la transmission du 
procès-verbal dressé par le fonctionnaire général désigné par le Gouvernement ou son 
délégué». 
 
b) A l''article 94, § 1er, tel que modifié par le décret du 1er juillet 2005, un nouvel 
alinéa 2, rédigé comme suit, est inséré : 
«Par dérogation à l''alinéa précédent, le membre du personnel titulaire d''une 
fonction de promotion ne peut demander de changement d''affectation qu''après avoir 
exercé ses fonctions dans l''emploi qu''il occupe durant un délai de trois ans». 
 
c) L''article 97, tel que modifié par le décret du 3 mars 2004, est modifié comme 
suit : 
- à l''alinéa 1er, 3°, les termes «3 000 jours» sont remplacés par les termes «2 400 
jours»; 
- à l''alinéa 1er, 8°, les termes «ou, en ce qui concerne les membres du personnel 
nommés à titre définitif dans l''enseignement de plein exercice visés à l''alinéa 3, du 
brevet de préfet des études et de directeurs» sont supprimés; 
- l''alinéa 3 est supprimé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 68, 'Article 52. - Dans le décret du 4 janvier 1999 précité, sont apportées les (partie 1)', 'Article 52. - Dans le décret du 4 janvier 1999 précité, sont apportées les modifications suivantes : a) L''article 7 est abrogé; b) A l''alinéa 1er de l''article 8, les termes «porteur du titre requis pour la fonction à laquelle il est nommé» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction donnant accès à la fonction de promotion ou de sélection considérée»; c) L''article 8, alinéa 1er, 1°, est remplacé par la disposition suivante : «1° exercer une fonction comprenant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes» d) L''article 8, alinéa 1er, 2°, est remplacé par la disposition suivante : «2° compter l''ancienneté de service et l''ancienneté de fonction suivantes : - pour l''accès à une fonction de sélection, respectivement six ans et deux ans; - pour l''accès à une fonction de promotion, respectivement huit ans et six ans.» e) A l''article 10, alinéa 1er, 2°, les termes «porteur du titre requis pour cette fonction de recrutement» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction de recrutement visée au 1°»; f) A l''article 11, 2°, les termes «porteur du titre requis pour cette fonction de recrutement» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction de recrutement visée au 1°»; g) A l''article 12, 2°, les termes «porteur du titre requis pour la fonction visée au 1°» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction visée au 1°»; Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 h) A l''article 12bis, 2°, les termes «porteur du titre requis pour la fonction visée au 1°» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction visée au 1°»; i) A l''article 13, alinéa 1er, 2°, les termes «porteur du titre requis pour la fonction visée au 1°» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction visée au 1°»; j) dans l''article 13, alinéa 2, les termes «du titre d''agrégé de l''enseignement secondaire inférieur ou d''un titre du niveau supérieur du deuxième degré» sont remplacés par les termes «d''un titre du niveau supérieur»; k) A l''article 14, 2°, les termes «porteur du titre requis pour la fonction visée au 1°» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction visée au 1°»; l) A l''article 15, 2°, les termes «porteur du titre requis pour la fonction visée au 1°» sont remplacés par les termes «porteur d''un titre requis pour l''exercice d''une fonction visée au 1°»; m) dans l''article 15, 3°, les termes «du deuxième degré ou du titre d''agrégé de l''enseignement secondaire inférieur» sont supprimés; n) l''article 18 est complété par l''alinéa suivant : «Le présent article ne s''applique pas aux fonctions de directeur telles que visées à l''article 2, § 1er, 1° du décret du 2 février 2007 fixant le statut des directeurs.». o) Dans l''article 19, alinéa 1er, les termes «de directeur d''école maternelle, de directeur d''école primaire, de directeur d''école fondamentale», «de préfet des études ou directeur» et «de directeur dans l''enseignement secondaire inférieur» sont supprimés. p) A l''article 22, un § 5 est ajouté, rédigé comme suit : «§ 5. La Commission permanente remplit également les fonctions qui lui sont attribuées conformément au chapitre II du titre II du décret du 2 février 2007 fixant le statut des directeurs». q) A l''article 23, l''alinéa 4 est remplacé par la disposition suivante : «Tout membre du personnel est admis à la formation à laquelle il désire s''inscrire sauf si, à la date de l''introduction de sa demande de participation, l''intéressé ne satisfait pas ou plus à toutes les conditions énoncées à l''article 8, alinéa 1er, à l''exception du point 6°, ou à l''alinéa 2, 1° et 2° du même article. Toutefois, l''ancienneté de service requise, visée à l''article 8, alinéa 1er, 2° pour l''admission à la formation est de quatre ans pour les formations donnant accès à une fonction de sélection et de 6 ans pour les formations donnant accès à une fonction de promotion.» r) Dans l''article 24, alinéa 6, les termes «de niveau 1» sont remplacés par les termes «de niveau 2 au moins»; s) Dans l''article 25, les alinéas 1er et 2 sont supprimés; t) L''article 26 est remplacé par la disposition suivante : «Les membres du personnel qui satisfont aux trois épreuves sont titulaires du brevet en rapport avec la fonction» u) Dans l''article 28, § 1er, les termes «à l''article 27» sont remplacés par les termes Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 «aux articles 9, 13, 15 et 27». v) L''article 28, § 1er, alinéa 6 est complété comme suit : «Le Gouvernement peut, pour assurer la continuité dans la fonction de sélection ou de promotion ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter la réintégration du membre du personnel dans sa fonction d''origine de maximum six mois à dater de la demande ');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 69, 'Article 28bis. - § 1er. Le présent chapitre s''applique aux membres du personnel', 'Article 28bis. - § 1er. Le présent chapitre s''applique aux membres du personnel 
titulaires d''une fonction de promotion ou de sélection telle que visée à l''article 4, 3° et 
à l''article 5, 1° et 2° du présent décret ainsi qu''à l''article 7, c, 12° de l''arrêté de 
l''Exécutif de la Communauté française du 2 octobre 1968 déterminant et classant les 
fonctions des membres du personnel directeur et enseignant, du personnel auxiliaire 
d''éducation, du personnel paramédical, du personnel psychologique et du personnel 
social des établissements d''enseignement préscolaire, primaire, spécialisé, moyen, 
technique, artistique, de promotion sociale et supérieur non universitaire de la 
Communauté française et les fonctions des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements dans l''enseignement de 
plein exercice. 
 
§ 2. Pour l''application du présent chapitre, il faut entendre par «directeur» le 
membre du personnel titulaire, à quelque titre que ce soit, de la fonction de promotion 
de directeur d''école maternelle, de directeur d''école primaire, de directeur d''école 
fondamentale, de directeur de l''enseignement secondaire inférieur ou de préfet des 
études ou directeur, telles qu''énumérées aux articles 3 et 4, 1° et 2° du présent décret. 
 
§ 3. Pour l''application du présent chapitre aux administrateurs, il faut entendre 
par «Commission» la Commission d''évaluation visée à l''article 37 du décret du 2 
février 2007 fixant le statut des directeurs, à l''exception de l''article 28ter, dans lequel 
par «directeur» il faut entendre le Gouvernement de la Communauté française, sur 
proposition de la Commission d''évaluation. 
 
Section Ire. - De la lettre de mission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 70, 'Article 28ter. - Dès l''entrée en fonction du membre du personnel visé à l''article', 'Article 28ter. - Dès l''entrée en fonction du membre du personnel visé à l''article 
28bis du présent décret, le directeur lui confie une lettre de mission, approuvée 
préalablement par la Commission d''évaluation visée à l''article 37 du décret du 2 
février 2007 fixant le statut des directeurs. 
 
Le directeur y spécifie les missions du membre du personnel visé à l''article 28bis 
et les priorités qui lui sont assignées, en tenant compte des profils de fonction tels que 
repris à l''arrêté du Gouvernement de la Communauté française du 4 juillet 2002 
précisant les attributions et définissant les profils de fonction des titulaires d''une 
fonction de promotion et de sélection en application de l''article 18 du décret du 4 
janvier 1999 relatif aux fonctions de promotion et de sélection en fonction des besoins 
de l''établissement au sein duquel il est affecté et en fonction des objectifs contenus 
dans la lettre de mission que ce dernier a lui-même reçue, conformément au chapitre 
III du titre II du décret du 2 février 2007 fixant le statut des directeurs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 71, 'Article 28quater. - § 1er. La lettre de mission a une durée de six ans.', 'Article 28quater. - § 1er. La lettre de mission a une durée de six ans. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 2. Le contenu de la lettre de mission peut être modifié avant son échéance, au 
plus tôt après deux ans, par le directeur, en raison de l''évolution des besoins et du 
fonctionnement de l''établissement. Par dérogation à l''alinéa 1er, le contenu de la lettre 
de mission peut être modifié avant son échéance, de commun accord entre le directeur 
et le membre du personnel visé à l''article 28bis.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 72, 'Article 28quinquies. - § 1er. Par dérogation à l''article 28ter, alinéa 1er, le', 'Article 28quinquies. - § 1er. Par dérogation à l''article 28ter, alinéa 1er, le 
directeur, si besoin est, peut confier une lettre de mission au membre du personnel 
désigné à titre temporaire dans l''exercice d''une fonction visée à l''article 28bis du 
présent décret. 
 
Le directeur confie d''office une lettre de mission au membre du personnel désigné 
à titre temporaire dans l''exercice d''une fonction visée à l''article 28bis pour une durée 
égale ou supérieure à un an, ou dont la durée de la désignation a atteint au moins un 
an. 
 
§ 2. La lettre de mission visée au présent article peut consister dans la 
confirmation de la lettre de mission du membre du personnel visé à l''article 28bis 
faisant l''objet d''un remplacement ou dans un nouveau document. 
 
Section II. - De l''évaluation formative');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 73, 'Article 28sexies. - Cette section s''applique au membre du personnel nommé à', 'Article 28sexies. - Cette section s''applique au membre du personnel nommé à 
titre définitif. 
 
Elle s''applique également au membre du personnel désigné à titre temporaire 
dans l''exercice d''une fonction visée à l''article 28bis pour une durée égale ou supérieure 
à un an, ou dont la durée de la désignation a atteint au moins un an. La dénomination 
«membre du personnel» visée à la présente section vise également ce membre du 
personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 74, 'Article 28septies. - Tous les cinq ans à dater de sa nomination à titre définitif ou', 'Article 28septies. - Tous les cinq ans à dater de sa nomination à titre définitif ou 
de sa désignation à titre temporaire, chaque membre du personnel fait l''objet d''une 
évaluation effectuée conjointement par le directeur et la Commission d''évaluation 
visée à l''article 37 du décret du 2 février 2007 fixant le statut des directeurs. 
 
Si ce dernier le juge utile, il peut procéder, plus tôt, à une évaluation du membre 
du personnel. 
 
Toutefois, sans préjudice de l''article 28octies, le membre du personnel ne peut 
faire l''objet de plus de deux évaluations par période de dix ans.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 75, 'Article 28octies. - L''évaluation se fonde sur l''exécution de la lettre de mission', 'Article 28octies. - L''évaluation se fonde sur l''exécution de la lettre de mission 
visée à la section Ire du présent chapitre et, le cas échéant, sur la mise en pratique des 
compétences acquises dans le cadre des formations visées au présent décret. 
 
Elle tient compte du contexte global dans lequel est amené à évoluer le membre 
du personnel et des moyens qui sont mis à sa disposition.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 76, 'Article 28novies. - En fonction de cette évaluation, le directeur convient avec le', 'Article 28novies. - En fonction de cette évaluation, le directeur convient avec le 
membre du personnel des améliorations à apporter.» 
 
x) L''article 43 est complété comme suit : 
«Les membres du personnel désignés ou engagés à titre temporaire à la date 
d''entrée en vigueur du présent décret dans l''enseignement secondaire du degré 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
inférieur ou dans l''enseignement secondaire du degré supérieur, à la fonction de chef 
d''atelier ou à la fonction de chef de travaux d''atelier, sont réputés à la date d''entrée en 
vigueur du présent décret, être désignés ou engagés à titre temporaire à la fonction de 
chef d''atelier ou de chef de travaux d''atelier.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 77, 'Article 53. - L''arrêté du Gouvernement de la Communauté française du 22 avril', 'Article 53. - L''arrêté du Gouvernement de la Communauté française du 22 avril 
1999 pris en application de l''article 8 du décret du 4 janvier 1999 relatif aux fonctions 
de sélection et de promotion, est abrogé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 78, 'Article 54. - Dans l''arrêté du Gouvernement de la Communauté française du 4', 'Article 54. - Dans l''arrêté du Gouvernement de la Communauté française du 4 
juillet 2002 précisant les attributions et définissant les profils de fonction des 
titulaires d''une fonction de promotion et de sélection en application de l''article 18 du 
décret du 4 janvier 1999 relatif aux fonctions de promotion et de sélection, les articles 
1er et 2, ainsi que les annexes 1re et 2 sont abrogés.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 79, 'Article 55. - Dans l''arrêté du Gouvernement de la Communauté française du 18', 'Article 55. - Dans l''arrêté du Gouvernement de la Communauté française du 18 
juillet 2002 organisant les formations des diverses sessions relatives aux fonctions de 
promotion et de sélection visées aux articles 19, 20 et 21, accordant des dispenses et 
organisant les épreuves sanctionnant les formations, en application des articles 23, 24 
et 25 du décret du 4 janvier 1999 relatif aux fonctions de promotion et de sélection et 
constituant les différents jurys chargés de délivrer les brevets y afférents, les 
modifications suivantes sont apportées : 
a) à l''article 1er, § 3, alinéa 1er, les termes «de préfet des études ou directeur ou 
directeur dans l''enseignement secondaire inférieur» et les termes «de directeur d''école 
maternelle, primaire ou fondamentale» sont supprimés; 
b) à l''article 1er, § 3, alinéa 2, les termes «de préfet des études ou directeur ou 
directeur dans l''enseignement secondaire inférieur, de directeur d''école maternelle, 
primaire ou fondamentale» sont supprimés; 
c) à l''article 4, § 1er, le premier tiret est supprimé; 
d) à l''article 6, le § 3 et le § 4, 1° et 2° sont supprimés; 
e) à l''article 9, 2°, les littera a) et b) sont supprimés; 
f) à l''article 10, § 2, le 1° et 2° sont supprimés; 
g) à l''article 13, le 1° et le 5° sont supprimés. 
 
CHAPITRE II. - De l''enseignement officiel subventionné 
 
Intitulé modifié par D. 14-03-2019 
Section Ire. - Conditions générales d''accès au stage et de nomination à titre 
définitif 
 
Modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 80, 'Article 56. - § 1er. Le pouvoir organisateur qui doit admettre au stage à la', 'Article 56. - § 1er. Le pouvoir organisateur qui doit admettre au stage à la 
fonction de promotion de directeur : 
1° consulte la commission paritaire locale sur le profil de la fonction de directeur 
à pourvoir; 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de l''admission au stage. 
 
Remplacé par D. 14-03-2019 
§ 2. Le pouvoir organisateur, après application du § 1er: 
a) arrête le profil de la fonction de directeur à pourvoir. Ce profil de fonction est 
établi conformément à l''article 5, § 2; 
b) lance un appel à candidatures selon le modèle visé à l''article 31. 
 
Inséré par D. 14-03-2019 
§ 3. Par dérogation au paragraphe précédent, un appel à candidatures pour 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
l''admission au stage ne doit pas être lancé, lorsque l''emploi devient définitivement 
vacant, dans les deux cas suivants : 
a) lorsque le membre du personnel a été désigné à titre temporaire, 
conformément aux dispositions du présent chapitre, à la suite d''un appel à 
candidatures pour un emploi temporairement vacant débouchant à terme sur un 
emploi définitivement vacant et dont le modèle est visé au chapitre V du titre II. 
 
Dans ce cas, le pouvoir organisateur admet au stage le directeur désigné à titre 
temporaire à la date de la vacance définitive de l''emploi. La durée du stage est réduite 
à concurrence du temps déjà presté, à titre temporaire, dans cet emploi. 
 
Les évaluations se font, mutatis mutandis, conformément à l''article 33, §§ 2 à 5; 
 
b) lorsque le membre du personnel a été désigné à titre temporaire dans un 
emploi non vacant suite à un appel à candidatures et ce, de manière ininterrompue 
depuis 3 ans au moins à la date à laquelle l''emploi est devenu vacant. 
 
Dans ce cas, le membre du personnel est nommé à titre définitif lorsque l''emploi 
devient vacant, s''il remplit les conditions de l''article 58. 
 
Alinéa inséré par D. 04-02-2021 
Si un directeur exerçant ses fonctions au sein d''un pouvoir organisateur non 
affilié à une fédération de pouvoirs organisateurs, n''a pas obtenu toutes ses 
attestations de réussite, telles que visées à l''article 58 1°, au moment où l''emploi 
devient vacant, il peut demander à son pouvoir organisateur de suivre un stage d''un 
an. 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 81, 'Article 56bis. - § 1er. Le pouvoir organisateur met en place une commission de', 'Article 56bis. - § 1er. Le pouvoir organisateur met en place une commission de 
sélection. Elle est composée de membres ou de délégués du pouvoir organisateur. 
 
Elle comprend au moins un membre disposant d''une expertise pédagogique et un 
ou plusieurs membres extérieurs au pouvoir organisateur, disposant d''une expérience 
en ressources humaines et en matière de sélection de personnel. 
 
La composition de la commission de sélection est communiquée aux Services du 
Gouvernement selon les modalités qu''ils fixent. 
 
§ 2. La sélection des candidats se fonde sur le profil de fonction élaboré par le 
pouvoir organisateur conformément à l''article 5, § 2, et annexé à l''appel à 
candidatures et, plus particulièrement, sur l''évaluation des compétences techniques et 
comportementales attendues des candidats, assorties d''indicateurs de maîtrise, et leur 
compatibilité avec le projet éducatif et pédagogique du pouvoir organisateur ainsi que, 
dans l''enseignement secondaire artistique à horaire réduit, avec le projet pédagogique 
et artistique de l''établissement. 
 
§ 3. La commission de sélection peut opérer un tri des candidatures sur dossier et 
n''entendre que les candidats retenus suite à cette sélection. 
 
Au terme des auditions, celle-ci établit un rapport classant les candidats et 
fournissant toutes informations utiles pour motiver le classement. 
 
Ce rapport est adressé au pouvoir organisateur qui, sur cette base, prend la 
décision d''admission au stage. 
 
A la demande de tout candidat, le pouvoir organisateur lui communique les 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
informations 
relatives 
à 
l''évaluation 
de 
ses 
compétences 
techniques 
et 
comportementales et à la compatibilité de ces compétences avec les critères de 
sélection définis et pondérés par le profil de fonction. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 82, 'Article 57. – § 1er. Nul ne peut être admis au stage dans la fonction de directeur', 'Article 57. – § 1er. Nul ne peut être admis au stage dans la fonction de directeur 
s''il ne répond, au moment de l''admission au stage, aux conditions suivantes : 
1° être porteur d''un titre de niveau bachelier au moins; dans l''enseignement 
secondaire artistique à horaire réduit, les membres du personnel enseignant des 
disciplines pour lesquelles n''existe pas de formation délivrant un titre de niveau 
supérieur du 1er degré, peuvent être admis au stage pour autant qu''ils soient porteurs 
d''un des titres visés aux articles 105 à 108 point a) ou b) du décret du 2 juin 1998 
organisant l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française; [modifié par D. 04-02-2021] 
2° être porteur d''un des titres pédagogiques listés à l''article 100; 
3° avoir une ancienneté de service de 3 ans dans l''enseignement organisé ou 
subventionné par la Communauté française; 
4° avoir répondu à l''appel à candidatures visé à l''article 56. 
 
Remplit les conditions 1° et 2°, le candidat qui possède un diplôme constitutif à la 
fois d''un titre pédagogique et d''un titre de niveau bachelier au moins. 
 
Le directeur admis au stage en vertu de l''article 30 est réputé remplir les 
conditions 1°, 2° et 3° de l''alinéa 1er. 
 
§ 2. Un pouvoir organisateur qui atteste avoir lancé un appel à candidatures et 
n''avoir pas reçu de candidature valable après ce 1er appel, peut lancer un second appel 
à candidatures ne remplissant pas la condition 3° visée au § 1er. 
 
Si la personne admise au stage n''exerce pas de fonction dans l''enseignement 
organisé ou subventionné par la Communauté française au moment de son admission 
au stage, elle ne pourra entrer en fonction que si elle rencontre également les 
conditions suivantes : 
1° jouir des droits civils et politiques; 
2° satisfaire aux dispositions légales et réglementaires relatives au régime 
linguistique; 
3° être de conduite irréprochable; 
4° satisfaire aux lois sur la milice. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 83, 'Article 58. - Un membre du personnel ne peut être nommé à titre définitif dans', 'Article 58. - Un membre du personnel ne peut être nommé à titre définitif dans 
la fonction de directeur que s''il remplit les conditions suivantes : 
1° avoir obtenu les attestations de réussite visées à l''article 15, § 1er, alinéa 1er, et 
l''attestation de suivi visée à l''article 15, § 1er, alinéa 4; 
2° avoir répondu à l''appel à candidatures visé à l''article 56; 
3° avoir acquis une ancienneté de service de six ans au moins, calculée selon les 
modalités fixées à l''article 34 du décret du 6 juin 1994 précité. 
Le membre du personnel qui ne remplit pas cette condition voit son stage 
prolongé jusqu''à ce qu''il remplisse ladite condition; 
4° avoir obtenu trois évaluations dont la dernière a abouti à la mention 
«favorable». 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 84, 'Article 58bis. - § 1er. Un pouvoir organisateur ne peut procéder à une', 'Article 58bis. - § 1er. Un pouvoir organisateur ne peut procéder à une 
nomination à titre définitif dans un emploi vacant d''une fonction de directeur que s''il 
n`est pas tenu, en vertu de la réglementation relative à la mise en disponibilité par 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
défaut d''emploi et à la réaffectation, d''attribuer cet emploi à un membre du personnel 
mis en disponibilité. 
 
§ 2. La nomination à une fonction de directeur ne peut intervenir que si l''emploi 
est occupé en fonction principale. 
 
§ 3. Les nominations ne sont pas permises dans un emploi faisant partie d''un 
établissement, d''une section, d''une implantation, d''un degré, d''un cycle ou d''une autre 
subdivision qui, en application des règles de rationalisation, est en fermeture 
progressive ou qui ne peut être subventionné que pour une période limitée. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 85, 'Article 59. - § 1er. Lorsqu''un directeur définitif est désigné, suite à un appel à', 'Article 59. - § 1er. Lorsqu''un directeur définitif est désigné, suite à un appel à 
candidatures, dans un autre emploi de directeur, tel que défini à l''article 2, par son 
pouvoir organisateur, celui-ci l''admet au stage si l''emploi est définitivement vacant ou 
le désigne à titre temporaire si l''emploi est temporairement vacant. Durant cette 
période, le directeur reste titulaire de son emploi d''origine et bénéficie d''un congé 
conformément aux articles 9 ou 14 l''arrêté royal du 15 janvier 1974 précité. 
 
Par dérogation à l''alinéa précédent, le directeur ne peut être admis au stage ou 
désigné à titre temporaire qu''après avoir exercé ses fonctions dans l''emploi qu''il 
occupe durant un délai de trois ans. 
 
§ 2. Après un an, le pouvoir organisateur effectue une évaluation axée sur 
l''adéquation aux éléments du profil de fonction spécifique à l''établissement. Si cette 
évaluation est favorable, le directeur est nommé à titre définitif dans l''emploi qu''il 
occupe, lorsque celui-ci est définitivement vacant. 
 
En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son 
emploi d''origine. 
 
Il peut en outre être mis fin à la fonction conformément aux articles 33 et 34. 
 
[§3. Par dérogation aux §§ 1 et 2, lorsque l''emploi est définitivement vacant et 
que le Pouvoir organisateur a sélectionné, au terme de la procédure d''appel, l''un de ses 
directeurs définitifs, il peut procéder à un changement d''affectation, conformément à 
l''article 29, §2 du décret du 06 juin 1994 fixant le statut des membres du personnel 
subsidié de l''enseignement officiel subventionné ou, s''il s''agit d''un autre niveau 
d''enseignement, à la nomination immédiate du directeur dans cet emploi. 
 
Cette procédure n''est applicable que si le membre du personnel a exercé ses 
fonctions dans l''emploi qu''il occupe durant un délai de trois ans au moins.]19 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 86, 'Article 59bis. - § 1er. Lorsqu''un directeur définitif est désigné, suite à un appel à', 'Article 59bis. - § 1er. Lorsqu''un directeur définitif est désigné, suite à un appel à 
candidatures, dans un autre emploi de directeur, tel que défini à l''article 2, auprès 
d''un autre pouvoir organisateur que celui auprès duquel il est nommé à titre définitif, 
ce dernier l''admet au stage si l''emploi est définitivement vacant ou le désigne à titre 
temporaire si l''emploi est temporairement vacant. Durant cette période, le directeur 
reste titulaire de son emploi d''origine et bénéficie d''un congé conformément aux 
articles 9 ou 14 de l''arrêté royal du 15 janvier 1974 précité. 
 
Par dérogation à l''alinéa précédent, le membre du personnel ne peut être admis 
au stage ou désigné à titre temporaire qu''après avoir exercé ses fonctions dans l''emploi 
 
19Inséré par le D. 16-05-2024 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
qu''il occupe durant un délai de trois ans. 
 
§ 2. Après un an, le pouvoir organisateur effectue une évaluation axée sur 
l''adéquation aux éléments du profil de fonction spécifique à l''établissement. En cas 
d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son emploi d''origine. 
 
Après deux ans, le pouvoir organisateur effectue une deuxième évaluation axée 
sur l''adéquation aux éléments du profil de fonction spécifique à l''établissement. Si 
cette évaluation est favorable, le directeur est nommé à titre définitif dans l''emploi 
qu''il occupe, lorsque celui-ci est définitivement vacant. 
 
En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son 
emploi d''origine. 
 
Il peut, en outre, être mis fin à la fonction conformément aux articles 33 et 34. 
 
Section II. - De la désignation à titre temporaire dans un emploi de directeur 
 
Modifié par D. 13-12-2007 ; D. 23-01-2009 ; complété par D. 13-07-2016 ; remplacé 
par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 87, 'Article 60. - § 1er. La fonction de directeur peut être confiée temporairement,', 'Article 60. - § 1er. La fonction de directeur peut être confiée temporairement, 
suite à la procédure d''appel visée aux articles 56 et 56bis, appliquée mutatis 
mutandis, à un membre du personnel remplissant toutes les conditions visées à 
l''article 57 : 
1° si le titulaire de la fonction est temporairement absent; 
2° dans l''hypothèse visée à l''article 58bis, § 3. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est nommé à titre définitif. 
 
Il est évalué, mutatis mutandis, conformément à l''article 33, §§ 2 à 5. 
 
§ 2. Pour toute désignation d''une durée égale ou inférieure à 15 semaines, la 
condition de l''article 57, § 1er, 3° et 4°, n''est pas obligatoire. Par ailleurs, les autorités 
visées à l''article 27bis du décret du 6 juin 1994 précité sont habilitées à effectuer ces 
désignations d''une durée égale ou inférieure à quinze semaines. 
 
Cette désignation pour 15 semaines maximum peut être renouvelée pour autant 
que la durée totale de désignation n''excède pas 12 mois. 
 
Si l''absence du titulaire de la fonction se prolonge, le pouvoir organisateur lance 
un appel à candidatures au plus tard le dernier jour de la période de désignation visée 
à l''alinéa précédent. 
 
Par dérogation à l''alinéa 2, la désignation est prolongée pendant la période entre 
l''appel à candidatures et la désignation d''un candidat. 
 
Le pouvoir organisateur désigne un candidat dans les trois mois qui suivent 
l''appel à candidatures. A défaut, au terme de ces trois mois, l''emploi n''est plus 
subventionné sauf si le pouvoir organisateur atteste qu''il n''a pu obtenir, à la suite de 
cet appel, de candidature qui réponde aux critères du profil de fonction. 
 
Dans ce cas, par dérogation aux alinéas 2 et 4, un délai supplémentaire, ne 
dépassant pas 15 semaines, est octroyé au pouvoir organisateur afin de désigner un 
directeur au terme d''une nouvelle procédure d''appel. La désignation initiale visée aux 
alinéas 1, 2 et 4 n''est pas subventionnée au-delà de ce deuxième appel. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Modifié par D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 88, 'Article 61. - § 1er. Toute désignation temporaire dans un emploi de directeur est', 'Article 61. - § 1er. Toute désignation temporaire dans un emploi de directeur est 
établie par écrit, en reprenant les mentions visées à l''article 21 du décret du 6 juin 
1994 précité, à l''exception du 7°. 
 
§ 2. Le pouvoir organisateur ne peut procéder à une désignation temporaire dans 
un emploi de directeur s''il est tenu, par les dispositions relatives à la réaffectation, de 
conférer cet emploi à un membre du personnel mis en disponibilité par défaut 
d''emploi. 
 
§ 3. Une désignation temporaire dans un emploi de directeur prend fin : 
a) d''un commun accord; 
b) par décision du pouvoir organisateur, suite à la procédure visée au § 4 du 
présent article pour le membre du personnel désigné à titre temporaire dans une 
fonction de directeur; 
c) ou par application de l''article 22, alinéa 1er du décret du 6 juin 1994 précité. 
 
Toutefois, la fin de l''année scolaire est sans incidence sur la désignation 
temporaire dans un emploi de directeur. 
 
§ 4. Moyennant un préavis de quinze jours, le pouvoir organisateur peut mettre 
fin à la désignation d''un membre du personnel désigné à titre temporaire dans une 
fonction de directeur. 
 
Préalablement à la notification de toute décision de fin de désignation, le membre 
du personnel doit avoir été invité à se faire entendre par le pouvoir organisateur. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le pouvoir 
organisateur envisage de mettre fin à la désignation du membre du personnel lui sont 
notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à 
la poste, soit par la remise d''une lettre de la main à la main avec accusé de réception. 
Lors de l''audition, le membre du personnel peut se faire assister ou représenter par un 
avocat, par un défenseur choisi parmi les membres du personnel en activité de service 
ou pensionnés de l''enseignement officiel subventionné ou par un représentant d''une 
organisation syndicale représentant les membres du personnel de l''enseignement 
officiel subventionné affiliée à des organisations siégeant au Conseil national du 
Travail. L''audition fait l''objet d''un procès-verbal. La procédure se poursuit 
valablement lorsque le membre du personnel dûment convoqué ne se présente pas à 
l''audition ou n''y est pas représenté. 
 
Section III. – [Des mécanismes de soutien, de développement des 
compétences professionnelles et d’évaluation]20');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 89, 'Article 62. - Cette section s''applique aux directeurs nommés à titre définitif.', 'Article 62. - Cette section s''applique aux directeurs nommés à titre définitif. 
 
Elle s''applique également au membre du personnel désigné à titre temporaire 
dans la fonction de directeur pour une durée égale ou supérieure à un an ou dont la 
durée de la désignation a atteint au moins un an. La dénomination «directeur» visée à 
la présente section vise également ce membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 90, 'Article 63. – [Les membres du pouvoir organisateur chargés de cette évaluation', 'Article 63. – [Les membres du pouvoir organisateur chargés de cette évaluation 
sont soutenus par leur fédération de pouvoir organisateur qui leur apporte 
notamment, une éventuelle expertise technique spécialisée. Par ailleurs, ils ont accès 
 
20 Intitulé remplacé par le décret du 20 juillet 2023 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
à la formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, au 
développement des compétences professionnelles et à l''évaluation des personnels de 
l''enseignement. 
 
 
Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en ressources 
humaines pour procéder aux entretiens et/ou évaluations visés à la sous-section II]21. 
 
[Sous-section I.- Du mécanisme de soutien et de développement des 
compétences professionnelles]22 
 
Modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 91, 'Article 64. – [§1er. Le mécanisme de soutien et de développement des (partie 1)', 'Article 64. – [§1er. Le mécanisme de soutien et de développement des compétences professionnelles est composé, notamment, d''entretiens de développement professionnel entre le directeur et son pouvoir organisateur et d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Ces entretiens de développement professionnel sont organisés à l''initiative du pouvoir organisateur mais peuvent également être demandés par le directeur. Un délai de minimum cinq jours ouvrables doit être garanti entre la convocation à l''entretien de développement professionnel et la date de l''entretien de développement professionnel. L''entretien de développement professionnel doit faire l''objet d''un compte-rendu. Un entretien de développement professionnel doit avoir lieu dans la mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. L''entretien de développement professionnel porte sur l''exécution de la lettre de mission visée au chapitre III du Titre 1er et sur la mise en œuvre du contrat d''objectifs, quand celui-ci existe. Dans le cadre de l''entretien de développement professionnel, il est tenu compte du contexte global dans lequel est amené à évoluer le directeur et des moyens mis à sa disposition. Dans ce cadre, le pouvoir organisateur prend en considération : a) dans l''enseignement maternel et dans l''enseignement obligatoire, les dispositions relatives aux projets éducatif et pédagogique du pouvoir organisateur et au projet d''établissement visés au titre 5 du Code de l''enseignement fondamental et de l''enseignement secondaire ; b) dans l''enseignement de promotion sociale, les dispositions relatives au projet pédagogique visé à l''article 36, §2, du décret du 16 avril 1991 précité; c) dans l''enseignement secondaire artistique à horaire réduit, les dispositions relatives au projet éducatif et au projet pédagogique du pouvoir organisateur visés à l''article 1er du décret du 02 juin 1998 organisant l''enseignement secondaire artistique à horaire réduit subventionné par la Communauté française et les dispositions relatives au projet pédagogique et artistique d''établissement visé à l''article 3bis du même décret. §2. A la suite du premier entretien de développement professionnel ou à la demande du pouvoir organisateur ou du directeur, un plan de développement des 21 Remplacé par le décret du 20 juillet 2023 22 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 compétences professionnelles est mis en place. Ce plan de développement des compétences professionnelles est élaboré par le pouvoir organisateur en concertation avec le directeur. §3. Ce plan de développement des compétences professionnelles est formalisé dans un document cosigné, tel que visé à l''article 65 et contient des engagements mutuels des deux parties tels que des objectifs individualisés, spécifiques, réalistes et adaptés au directeur ainsi que les moyens mis à sa disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. L''obligation de co-signature visée à l''alinéa précédent est réputée remplie dès lors que le pouvoir organisateur ou son délégué fait la preuve que la demande de signature pour prise de connaissance a été adressée au membre du personnel. En cas de refus de signature du directeur, la procédure de mise en œuvre du plan de développement des compétences professionnelles se poursuit valablement. Ce document peut, le cas échéant, servir de base à la rédaction du rapport d''évaluation visé à l''article 65/1. §4. Sa périodicité est adaptée de manière à permettre au directeur de mettre en place les conseils dispensés ou de suivre les formations recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement des compétences professionnelles par année scolaire par membre du personnel. Toutefois, durant une même année scolaire, un membre du personnel faisant l''objet d''un plan de développement des compétences professionnelles peut également être amené à avoir un plan d''accompagnement individualisé élaboré suite à une première évaluation avec mention « défavorable ». §5. Le plan de développement des compétences professionnelles peut faire l''objet d''ajustements à l''initiative du pouvoir organisateur ou à la demande du directeur. Ces ajustements sont cosignés par les deux parties. En cas de refus de signature du membre du personnel, la procédure de mise en œuvre du plan de développement des compétences professionnelles se poursuit valablement. §6. Le plan de développement des compétences professionnelles donne lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois après la mise en place du plan de développement des compétences professionnelles et au plus tard deux ans après celle-ci. L''entretien de clôture est mené par le pouvoir organisateur ou son délégué. L''entretien de clôture fait l''objet d''un compte-rendu. §7. Pour le calcul des délais de six mois et deux ans précités, sont seuls pris en considération les s');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 92, 'Article 64. – [§1er. Le mécanisme de soutien et de développement des (partie 2)', 'effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]23.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 93, 'Article 65. – [Le Gouvernement fixe le modèle de plan de développement des (partie 1)', 'Article 65. – [Le Gouvernement fixe le modèle de plan de développement des compétences professionnelles, pouvant servir de base à l''évaluation visée dans la sous- section 2]24. [Sous-section II. – Du mécanisme d’évaluation]25 [Article 65/1. - §1er. En cas de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste et répétée à atteindre les objectifs identifiés avec le directeur dans le cadre du plan de développement des compétences professionnelles, une procédure d''évaluation peut être engagée par le pouvoir organisateur. L''évaluation est précédée d''un plan de développement des compétences professionnelles. §2. Au plus tôt six mois après avoir communiqué ce plan de développement des compétences professionnelles au directeur et pour autant que l''entretien de clôture visé à l''article 64, §6 ait eu lieu, le pouvoir organisateur peut procéder à une évaluation de celui-ci. Ce délai est calculé conformément à l''article 65/2, §2. §3. Le directeur doit être entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel en activité de service ou pensionnés de l''enseignement officiel subventionné ou par un représentant d''une organisation syndicale représentative. §4. L''évaluation débouche sur une mention « favorable » ou « défavorable ». Elle est formalisée selon le document visé à l''article 65/5 et notifié au membre du personnel. La mention d''évaluation est motivée sur la base du plan de développement des compétences professionnelles. En l''absence de rapport d''évaluation, tout membre du personnel est réputé bénéficier de la mention « favorable ». §5. En cas d''évaluation débouchant sur la mention « défavorable », un entretien entre le directeur et le pouvoir organisateur est, ensuite, fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé. Le plan d''accompagnement individualisé donne lieu à un entretien de clôture. 23 Remplacé par le décret du 20 juillet 2023 24 Remplacé par le décret du 20 juillet 2023 25 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 L''entretien de clôture fait l''objet d''un compte-rendu]26. [Article 65/2. - §1er. Après un délai de minimum six mois d''exercice de la fonction entre la communication au directeur du plan d''accompagnement individualisé convenu lors de l''évaluation avec mention « défavorable » qui précède, une nouvelle évaluation peut avoir lieu. Ce délai doit permettre au directeur de remédier aux carences constatées. Toutefois, après une évaluation avec mention « défavorable », l''évaluation suivante doit intervenir dans un délai maximum de deux ans suivant la communication du plan d''accompagnement individualisé faisant suite à la précédente évaluation. A défaut, elle est réputée favorable. Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir dans un délai plus long en cas de prolongation du plan d''accompagnement individualisé telle que visée à l''article 65/3. §2. Pour le calcul des délais de six mois et deux ans précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]27. [Article 65/3. - §1er. Le rapport d''évaluation faisant suite à une première évaluation définitive avec mention « défavorable » est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, en cas d''un commun accord entre le membre du personnel et le pouvoir organisateur sur la prolongation du plan d''accompagnement individualisé. Le rapport d''évaluation est formalisé selon le document visé à l''article 65/5 ainsi que notifié au directeur. La prolongation du plan d''accompagnement individualisé est de minimum 3 mois et de maximum un an. La mention');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 94, 'Article 65. – [Le Gouvernement fixe le modèle de plan de développement des (partie 2)', 'd''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel des établissements d''enseignement 26 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 27 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 officiel subventionné, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. §2. En cas de prolongation du plan d''accompagnement individualisé, un entretien entre, d''une part, le pouvoir organisateur et, d''autre part, le directeur est fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan d''accompagnement individualisé précédent que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé. Le plan d''accompagnement individualisé donne lieu à un entretien de clôture. L''entretien de clôture fait l''objet d''un compte-rendu. §3. Après une prolongation du plan d''accompagnement individualisé, une nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai maximum d''un an d''exercice de la fonction à partir de la communication au membre du personnel du plan d''accompagnement individualisé adapté à la suite de la prolongation du plan d''accompagnement individualisé. A défaut, elle est réputée favorable. Ce délai doit permettre au directeur de remédier aux carences constatées. §4. Pour le calcul des délais de trois mois et un an précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. §5. Le rapport d''évaluation faisant suite à une prolongation de plan d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » et est formalisé selon le document visé à l''article 65/5 ainsi que notifié au directeur. La prolongation du plan d''accompagnement individualisé est de minimum 3 mois et de maximum un an. La mention d''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel des établissements d''enseignement officiel subventionné, en activité de service ou pensionnés, ou par un représentant Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 d''une organisation syndicale représentative. Une évaluation ne peut avoir lieu qu''une fois par année scolaire]28. [Article 65/4. - §1er. En cas d''évaluation avec mention « défavorable », le directeur peut, dans les 10 jours ouvrables qui suivent la réception du rapport, introduire un recours conformément aux modalités décrites au chapitre Vbis du décret du 06 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné, applicables mutatis mutandis. Le directeur qui fait usage de son droit de recours en notifie immédiatement une copie à son pouvoir organisateur. Ce recours est suspensif. §2. La répétition de deux mentions « défavorable » consécutives sur deux années scolaires distinctes, devenues définitives après épuisement des procédures devant la chambre de recours, telles que visées à l''article 52novies/7 du décret du 6 juin 1994 précité, a pour conséquence de mettre fin d''office aux fonctions d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 95, 'Article 65. – [Le Gouvernement fixe le modèle de plan de développement des (partie 3)', 'directeur conformément à l''article 58 du décret du 06 juin 1994 précité]29. [Article 65/5. - Le Gouvernement fixe le modèle de plan d''accompagnement individualisé et de rapport d''évaluation]30. [Article 65/6. - Toute notification de document, de décision ou de convocation mentionnée dans la présente sous-section se fait par courrier recommandé avec accusé de réception ou par une remise de la main à la main avec accusé de réception]31. [Sous-section III. – Des règles de déontologie]32 [Article 65/7. – Dans le cadre des entretiens et évaluations visés à la présente section, le membre du personnel et son évaluateur sont tenus au respect des devoirs suivants : a) la discrétion ; b) le respect mutuel. En outre, l''évaluateur est tenu de : a) motiver, de manière adéquate et constructive, ses instructions/conseils/échanges avec le membre du personnel ainsi que la mention d''évaluation ; b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; c) respecter les devoirs d''impartialité et d''objectivité]33. 28 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 29 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 30 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 31 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 32 Ajouté par le décret du 20 juillet 2023 33 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Section IV. - Des passerelles entre fonctions de promotion, de sélection et de recrutement');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 96, 'Article 66. - Dans l''article 22, alinéa 1er, 2°, du décret du 6 juin 1994 fixant le', 'Article 66. - Dans l''article 22, alinéa 1er, 2°, du décret du 6 juin 1994 fixant le 
statut des membres du personnel de l''enseignement officiel subventionné, sont ajoutés 
les points cbis) et cter) libellés comme suit : 
«cbis) par application de l''article 29bis, § 1er; 
cter) par application de l''article 29bis, § 2;».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 97, 'Article 67. - Dans l''article 28 du même décret, est ajouté un point 3° libellé / Article 68. - Un article 29bis et un article 29ter libellés comme suit sont insérés', 'Article 67. - Dans l''article 28 du même décret, est ajouté un point 3° libellé 
comme suit : 
«3° s''il a déjà attribué l''emploi conformément aux dispositions prévues à l''article 
29bis.».

Article 68. - Un article 29bis et un article 29ter libellés comme suit sont insérés 
dans le même décret : 
 
«Article 29bis. - § 1er. Un membre du personnel nommé à titre définitif dans une 
fonction de sélection ou de promotion auprès d''un pouvoir organisateur peut, s''il le 
demande et avec l''accord du pouvoir organisateur, être nommé à titre définitif dans un 
emploi définitivement vacant d''une fonction de recrutement, de sélection ou de 
promotion par un pouvoir organisateur auprès duquel il a déjà bénéficié d''une 
nomination à titre définitif dans une fonction de recrutement, de sélection ou de 
promotion qui donne accès à sa fonction actuelle. 
 
Le passage d''un emploi à l''autre conformément au présent paragraphe doit se 
faire sans interruption. 
 
Les modalités de la nomination en vertu du présent paragraphe, sont, pour le 
surplus, fixées par les commissions paritaires locales. 
 
§ 2. Un membre du personnel nommé à titre définitif dans une fonction de 
sélection ou de promotion auprès d''un pouvoir organisateur peut, s''il le demande et 
avec l''accord du pouvoir organisateur être nommé à titre définitif dans un emploi 
définitivement vacant d''une fonction de recrutement, de sélection ou de promotion qui 
donne accès à sa fonction actuelle, par un pouvoir organisateur autre que ceux visés 
au § 1er, si aucun des membres de ce dernier n''est prioritaire. 
 
Le membre du personnel qui bénéficie de l''application du présent paragraphe 
doit démissionner dans le pouvoir organisateur qu''il quitte pour la fonction de 
sélection ou de promotion qu''il y exerce. 
 
Le passage d''un emploi à l''autre conformément au présent paragraphe doit se 
faire sans interruption. 
 
Les modalités de la nomination en vertu du présent paragraphe sont, pour le 
surplus, fixées par la commission paritaire locale constituée au sein du pouvoir 
organisateur qui accueille l''agent. 
 
§ 3. Pour l''application des §§ 1er et 2 et sans préjudice de l''article 28, 1°, la 
nomination à titre définitif peut avoir lieu quelle que soit la date. Elle ne peut être 
accordée que pour autant que le membre du personnel remplisse toutes les conditions 
prévues, selon le cas : 
a) à l''article 30, à l''exception du 8°, du 9° en ce qui concerne l''ancienneté de 
fonction et des 10° et 11°; 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
b) à l''article 40, alinéa 1er, à l''exception du 5°; 
c) à l''article 49, alinéa 1er, à l''exception du 4°; 
d) à l''article 57 du décret du 2 février 2007 fixant le statut des directeurs, à 
l''exception du 4°. 
 
Pour l''application des points b), c) et d) de l''alinéa 1er, l''exigence du suivi de la 
formation relative à une fonction déterminée est d''office réputée remplie si le membre 
du personnel a été titulaire à titre définitif de cette fonction avant l''exercice de sa 
fonction actuelle.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 98, 'Article 29ter. - Le membre du personnel visé à l''article 29bis se voit attribuer', 'Article 29ter. - Le membre du personnel visé à l''article 29bis se voit attribuer 
l''échelle de traitement de la fonction dans laquelle il est nommé à titre définitif 
conformément à cette disposition. 
 
Toutefois, le membre du personnel visé à l''article 29bis, qui a exercé à titre 
définitif pendant au moins dix ans la fonction de sélection ou de promotion qu''il quitte, 
bénéficie d''un mécanisme dégressif d''échelles de traitement pour rejoindre à partir de 
la 3e année l''échelle de traitement de la fonction dans laquelle il est nommé à titre 
définitif conformément à l''article 29bis, fixé comme suit : 
a) Au cours de la première année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 66 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté; 
b) Au cours de la deuxième année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 33 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 99, 'Article 69. - Dans l''article 37 du même décret est ajouté un point 3° libellé / Article 70. - Dans l''article 45 du même décret est ajouté un point 3° libellé', 'Article 69. - Dans l''article 37 du même décret est ajouté un point 3° libellé 
comme suit : 
«3° s''il a déjà attribué l''emploi par application des dispositions prévues à l''article 
29bis.»

Article 70. - Dans l''article 45 du même décret est ajouté un point 3° libellé 
comme suit : 
«3° s''il a déjà attribué l''emploi par application des dispositions prévues à l''article 
29bis.» 
 
Section V. - Dispositions modificatives');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 100, 'Article 71. - Un article 39bis, rédigé comme suit, est inséré dans le décret du 6', 'Article 71. - Un article 39bis, rédigé comme suit, est inséré dans le décret du 6 
juin 1994 précité : 
«Article 39bis. - § 1er. Le pouvoir organisateur qui doit nommer à titre définitif un 
membre du personnel dans une fonction de sélection : 
1° consulte la commission paritaire locale sur le profil de la fonction de sélection à 
pourvoir; 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de la nomination à titre définitif. 
 
§ 2. Le pouvoir organisateur après application du § 1er : 
1° arrête le profil de la fonction de sélection à pourvoir. Dans ce cadre, le pouvoir 
organisateur peut ajouter des critères complémentaires aux conditions de nomination 
à titre définitif visées à l''article 40; 
2° lance un appel aux candidats selon les formes déterminées par le 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Gouvernement sur proposition de la commission paritaire centrale.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 101, 'Article 72. - Dans l''article 40 du décret du 6 juin 1994 précité, sont apportées les', 'Article 72. - Dans l''article 40 du décret du 6 juin 1994 précité, sont apportées les 
modifications suivantes : 
a) au point 2° de l''alinéa 1er, les termes «depuis deux ans au moins» sont 
supprimés. 
b) le point 3° de l''alinéa 1er, est remplacé par la disposition suivante : 
«3° être titulaire, à titre définitif, d''une fonction comportant au moins la moitié 
du nombre minimum d''heures requis pour former une fonction à prestations complètes 
dans l''enseignement organisé par le pouvoir organisateur concerné;» 
c) le point 4° de l''alinéa 1er est remplacé comme suit : 
«4° exercer à titre définitif au sein du pouvoir organisateur une ou plusieurs 
fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre 
de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut 
des directeurs;» 
d) le point 5° de l''alinéa 1er est remplacé comme suit : 
«5° répondre à un appel dont la forme sera déterminée par le Gouvernement, sur 
proposition de la commission paritaire locale.» 
e) le 3e alinéa est remplacé par la disposition suivante : 
«Par dérogation à l''alinéa 1er, 3°, dans l''enseignement secondaire artistique à 
horaire réduit, la condition de l''exercice d''une fonction comportant au moins une demi-
charge est remplie si celle-ci est prestée dans l''enseignement organisé au sein d''un ou 
de plusieurs pouvoirs organisateurs.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 102, 'Article 73. - Les articles 42 à 44 du même décret sont remplacés par les', 'Article 73. - Les articles 42 à 44 du même décret sont remplacés par les 
dispositions suivantes : 
«Article 42. - § 1er. Une fonction de sélection peut être confiée temporairement à 
un membre du personnel remplissant toutes les conditions de l''article 40 : 
1° si le titulaire de la fonction est temporairement absent; 
2° dans l''hypothèse visée à l''article 39. Pendant cette période le membre du 
personnel reste titulaire de l''emploi dans lequel il est nommé définitivement. 
 
§ 2. Par dérogation au § 1er, alinéa 1er, pour toute désignation d''une durée égale 
ou inférieure à quinze semaines, les conditions visées à l''article 40, 5° et 6°, ne sont 
pas exigées.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 103, 'Article 43. - Une fonction de sélection peut être confiée temporairement à un', 'Article 43. - Une fonction de sélection peut être confiée temporairement à un 
membre du personnel remplissant toutes les conditions visées à l''article 40, dans 
l''attente d''une nomination définitive. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est nommé à titre définitif. 
 
Le membre du personnel visé à l''alinéa 1er est nommé à titre définitif dans la 
fonction de sélection au plus tard au terme d''un délai de deux ans si le pouvoir 
organisateur ne l''en a pas déchargé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 104, 'Article 44. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 1)', 'Article 44. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions visées à l''article 40, peut confier temporairement la fonction de sélection à un membre de son personnel nommé à titre définitif et remplissant les conditions suivantes : 1° être titulaire, à titre définitif, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de sélection, le membre du personnel reste titulaire de l''emploi dans lequel il est nommé à titre définitif. Tout pouvoir organisateur qui démontre n''avoir qu''un seul membre du personnel répondant aux conditions de l''article 40, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 3 ne dispense pas le pouvoir organisateur de lancer un appel aux candidats à la nomination définitive à la fonction de sélection au cours des trois exercices qui suivent celui au cours duquel la fonction de sélection a fait l''objet d''une désignation temporaire en application de l''alinéa 1er. Toutefois, si au terme des trois exercices visés à l''alinéa précédent, le membre du personnel qui s''est vu confier temporairement la fonction de sélection en application de l''alinéa 1er ne remplit pas encore la condition visée à l''article 40, alinéa 1er, 6°, le pouvoir organisateur doit procéder chaque année à un appel aux candidats à la nomination définitive à la fonction de sélection. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. Les dispositions des alinéas 3 et 4 ne sont pas applicables dans les hypothèses visées à l''article 42, § 1er, 1° et 2°. § 2. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel nommé à titre définitif conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre de son personnel temporaire prioritaire, remplissant les conditions suivantes : 1° être titulaire, à titre temporaire, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 40 et n''avoir qu''un seul membre du personnel répondant aux conditions du § 1er, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 2 ne dispense pas le pouvoir organisateur de lancer chaque année un appel aux candidats à la nomination définitive à la fonction de sélection. Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 Le membre du personnel temporaire prioritaire désigné conformément au présent article sera réputé remplir la condition exigée à l''article 40, alinéa 1er, 1° et 2°, à l''expiration d''un délai de six années d''exercice temporaire de la fonction de sélection. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. § 3. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel nommé à titre définitif ou temporaire prioritaire conformément aux dispositions qui précèdent, peut faire appel à un membre du personnel nommé');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 105, 'Article 44. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 2)', 'à titre définitif relevant d''un autre pouvoir organisateur officiel subventionné et remplissant les conditions suivantes : 1° être titulaire, à titre définitif, au sein de cet autre pouvoir organisateur d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de sélection, le membre du personnel reste titulaire de l''emploi dans lequel il est nommé à titre définitif au sein de son pouvoir organisateur d''origine. Le membre du personnel désigné temporairement dans une fonction de sélection en vertu du présent paragraphe est nommé à titre définitif dans ladite fonction au terme d''un délai de six années s''il remplit à ce moment les conditions prescrites par l''article 40, alinéa 1er, 5° et 6°, et si le pouvoir organisateur ne l''en a pas déchargé. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 40 et du § 1er du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 2, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 4 ne dispense pas le pouvoir organisateur de lancer un appel aux candidats à la nomination définitive à la fonction de sélection au cours des trois exercices qui suivent celui au cours duquel la fonction de sélection a fait l''objet d''une désignation temporaire en application de l''alinéa 1er. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. Les dispositions des alinéas 3 et 4 ne sont pas applicables dans les hypothèses visées à l''article 42, § 1er, 1° et 2°. § 4. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre de son personnel temporaire, remplissant les conditions suivantes : Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 1° être titulaire, à titre temporaire, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 40, du § 1er et du § 2 du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 2 ne dispense pas le pouvoir organisateur de lancer chaque année un appel aux candidats à la nomination définitive à la fonction de sélection. Le membre du personnel temporaire désigné conformément au présent article sera réputé remplir la condition exigée à l''article 40, alinéa 1er, 1° et 2°, à l''expiration d''un délai de six années d''exercice temporaire de la fonction de sélection. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 106, 'Article 44bis. - § 1er. Toute désignation temporaire dans un emploi de sélection', 'Article 44bis. - § 1er. Toute désignation temporaire dans un emploi de sélection 
est établie par écrit, en reprenant les mentions visées à l''article 21, à l''exception du 7°. 
 
§ 2. Le pouvoir organisateur ne peut procéder à une désignation temporaire dans 
un emploi de sélection s''il est tenu, par les dispositions relatives à la réaffectation, de 
conférer cet emploi à un membre du personnel mis en disponibilité par défaut 
d''emploi. 
 
§ 3. Une désignation temporaire dans un emploi de sélection prend fin : 
a) d''un commun accord; 
b) par décision du pouvoir organisateur suite à la procédure visée au § 4 du 
présent article ou pour ce qui concerne le membre du personnel de l''enseignement de 
plein exercice suite à l''application des dispositions du chapitre Vbis. 
c) ou par application de l''article 22, alinéa 1er. 
 
Toutefois, la fin de l''année scolaire est sans incidence sur la désignation 
temporaire dans un emploi de sélection. 
 
§ 4. Moyennant un préavis de quinze jours, le pouvoir organisateur soit sur 
proposition du directeur, soit d''initiative peut mettre fin à la désignation d''un membre 
du personnel désigné à titre temporaire dans une fonction de sélection. 
 
Préalablement à la notification de toute décision de fin de désignation, le membre 
du personnel doit avoir été invité à se faire entendre par le pouvoir organisateur. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le pouvoir 
organisateur envisage de mettre fin à la désignation du membre du personnel lui sont 
notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
la poste, soit par la remise d''une lettre de la main à la main avec accusé de réception. 
Lors de l''audition, le membre du personnel peut se faire assister ou représenter par un 
avocat, par un défenseur choisi parmi les membres du personnel en activité de service 
ou pensionnés de l''enseignement officiel subventionné ou par un représentant d''une 
organisation syndicale représentant les membres du personnel de l''enseignement 
officiel subventionné affiliée à des organisations siégeant au Conseil national du 
Travail. L''audition fait l''objet d''un procès-verbal. La procédure se poursuit 
valablement lorsque le membre du personnel dûment convoqué ne se présente pas à 
l''audition ou n''y est pas représenté.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 107, 'Article 44ter. - Tout membre du personnel peut renoncer à sa nomination en', 'Article 44ter. - Tout membre du personnel peut renoncer à sa nomination en 
vertu de l''article 40 dans les six cents jours qui suivent sa première entrée en fonction 
dans une fonction de sélection. Dans ce cas, il réintègre à titre définitif sa fonction 
d''origine. 
 
Le pouvoir organisateur peut, pour assurer la continuité dans la fonction de 
sélection ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter la 
réintégration du membre du personnel dans sa fonction d''origine de maximum six 
mois à dater de la demande du membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 108, 'Article 74. - A l''article 46 du même décret, un alinéa 2, rédigé comme suit, est', 'Article 74. - A l''article 46 du même décret, un alinéa 2, rédigé comme suit, est 
ajouté : 
«Par dérogation à l''alinéa précédent, le membre du personnel titulaire d''une 
fonction de promotion ne peut demander de changement d''affectation qu''après avoir 
exercé ses fonctions dans l''emploi qu''il occupe durant un délai de trois ans».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 109, 'Article 75. - Un article 48bis, rédigé comme suit, est inséré dans le même', 'Article 75. - Un article 48bis, rédigé comme suit, est inséré dans le même 
décret : 
«Article 48bis. - § 1er. Le pouvoir organisateur qui doit nommer à titre définitif un 
membre du personnel dans une fonction de promotion : 
1° consulte la commission paritaire locale sur le profil de la fonction de promotion 
à pourvoir; 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de la nomination à titre définitif. 
 
§ 2. Le pouvoir organisateur après application du § 1er : 
1° arrête le profil de la fonction de promotion à pourvoir. Dans ce cadre, le 
pouvoir organisateur peut ajouter des critères complémentaires aux conditions de 
nomination à titre définitif visées à l''article 49; 
2° lance un appel aux candidats selon les formes déterminées par le 
Gouvernement sur proposition de la commission paritaire centrale.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 110, 'Article 76. - Dans l''article 49 du même décret, sont apportées les modifications', 'Article 76. - Dans l''article 49 du même décret, sont apportées les modifications 
suivantes : 
a) dans le point 1° de l''alinéa 1er, les termes «avoir acquis à titre définitif une 
ancienneté de service de six ans» sont remplacés par les termes «avoir acquis une 
ancienneté de service de sept ans» 
b) le point 2° de l''alinéa 1er est remplacé comme suit : 
«2° être titulaire, à titre définitif, d''une fonction comportant au moins la moitié 
du nombre minimum d''heures requis pour former une fonction à prestations complètes 
dans l''enseignement organisé par le pouvoir organisateur concerné» 
c) le point 3° de l''alinéa 1er est remplacé comme suit : 
«3° exercer au sein du pouvoir organisateur une ou plusieurs fonctions donnant 
accès à la fonction de promotion à conférer et être porteur d''un titre de capacité, 
conformément à l''article 102 du décret du 2 février 2007 fixant le statut des 
directeurs.» 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
d) le point 4° de l''alinéa 1er est remplacé comme suit : 
«4° répondre à un appel dont la forme sera déterminée par le Gouvernement, sur 
proposition de la commission paritaire locale.» 
e) l''alinéa 2 est remplacé comme suit : 
«Par dérogation à l''alinéa 1er, 3°, dans l''enseignement secondaire artistique à 
horaire réduit, la condition de l''exercice d''une fonction comportant au moins une demi-
charge est remplie si celle-ci est prestée dans l''enseignement organisé au sein d''un ou 
de plusieurs pouvoirs organisateurs.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 111, 'Article 77. - Les articles 50 à 52 du même décret sont remplacés par les', 'Article 77. - Les articles 50 à 52 du même décret sont remplacés par les 
dispositions suivantes : 
 
«Article 50. - § 1er. Une fonction de promotion peut être confiée temporairement à 
un membre du personnel remplissant toutes les conditions de l''article 49 : 
1° si le titulaire de la fonction est temporairement absent; 
2° dans l''hypothèse visée à l''article 47; 
 
Pendant cette période le membre du personnel reste titulaire de l''emploi dans 
lequel il est nommé définitivement. 
 
§ 2. Par dérogation au § 1er, alinéa 1er, pour toute désignation d''une durée égale 
ou inférieure à quinze semaines, les conditions visées à l''article 49, 4° et 5°, ne sont 
pas exigées. Le Pouvoir organisateur, après consultation de la commission paritaire 
locale, fixe la procédure de désignation.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 112, 'Article 51. - Une fonction de promotion peut être confiée temporairement à un', 'Article 51. - Une fonction de promotion peut être confiée temporairement à un 
membre du personnel remplissant toutes les conditions visées à l''article 49, dans 
l''attente d''une nomination définitive. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est nommé à titre définitif. 
 
Le membre du personnel visé à l''alinéa 1er est nommé à titre définitif dans la 
fonction de promotion au plus tard au terme d''un délai de deux ans si le pouvoir 
organisateur ne l''en a pas déchargé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 113, 'Article 52. - Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir (partie 1)', 'Article 52. - Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel remplissant les conditions visées à l''article 49, peut confier temporairement la fonction de promotion à un membre de son personnel nommé à titre définitif et remplissant les conditions suivantes : 1° être titulaire, à titre définitif, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de promotion, le membre du personnel reste titulaire de l''emploi dans lequel il est nommé à titre définitif. Tout pouvoir organisateur qui démontre n''avoir qu''un seul membre du personnel répondant aux conditions de l''article 49, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 3 ne dispense pas le pouvoir organisateur de lancer un appel aux candidats à la nomination définitive à la fonction de promotion au cours des trois exercices qui suivent celui au cours duquel la fonction de promotion a fait l''objet d''une désignation temporaire en application de l''alinéa 1er. Toutefois, si au terme des trois exercices visés à l''alinéa précédent, le membre du personnel qui s''est vu confier temporairement la fonction de promotion en application de l''alinéa 1er ne remplit pas encore la condition visée à l''article 49, alinéa 1er, 5°, le pouvoir organisateur doit procéder chaque année à un appel aux candidats à la nomination définitive à la fonction de promotion. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. Les dispositions des alinéas 3 et 4 ne sont pas applicables dans les hypothèses visées à l''article 50, § 1er, 1° et 2°. § 2. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel nommé à titre définitif conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre de son personnel temporaire prioritaire, remplissant les conditions suivantes : 1° être titulaire, à titre temporaire, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 49 et n''avoir qu''un seul membre du personnel répondant aux conditions du § 1er, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 2 ne dispense pas le pouvoir organisateur de lancer chaque année un appel aux candidats à la nomination définitive à la fonction de promotion. Le membre du personnel temporaire prioritaire désigné conformément au présent article sera réputé remplir la condition exigée à l''article 49, alinéa 1er, 1°, à l''expiration d''un délai de six années d''exercice temporaire de la fonction de promotion. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. § 3. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel nommé Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 titre définitif ou temporaire prioritaire conformément aux dispositions qui précèdent, peut faire appel à un membre du personnel nommé à titre défi');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 114, 'Article 52. - Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir (partie 2)', 'relevant d''un autre pouvoir organisateur officiel subventionné remplissant les conditions suivantes : 1° être titulaire, à titre définitif, au sein de cet autre pouvoir organisateur d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de promotion, le membre du personnel reste titulaire de l''emploi dans lequel il est nommé à titre définitif au sein de son pouvoir organisateur d''origine. Le membre du personnel désigné temporairement dans une fonction de promotion en vertu du présent paragraphe est nommé à titre définitif dans ladite fonction au terme d''un délai de six années s''il remplit à ce moment les conditions prescrites par l''article 49, alinéa 1er, 4° et 5°, et si le pouvoir organisateur ne l''en a pas déchargé. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 49 et du § 1er du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 2, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 4 ne dispense pas le pouvoir organisateur de lancer un appel aux candidats à la nomination définitive à la fonction de promotion au cours des trois exercices qui suivent celui au cours duquel la fonction de promotion a fait l''objet d''une désignation temporaire en application de l''alinéa 1er. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. Les dispositions des alinéas 2 et 3 ne sont pas applicables dans les hypothèses visées à l''article 50, § 1er, 1° et 2°. § 4. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre de son personnel temporaire, remplissant les conditions suivantes : 1° être titulaire, à titre temporaire, d''une fonction comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 49, du § 1er et du § 2 du présent article, et n''avoir qu''un seul Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. L''application de l''alinéa 1er ou de l''alinéa 2 ne dispense pas le pouvoir organisateur de lancer chaque année un appel aux candidats à la nomination définitive à la fonction de promotion. Le membre du personnel temporaire désigné conformément au présent article sera réputé remplir la condition exigée à l''article 40, alinéa 1er, 1° et 2°, à l''expiration d''un délai de six années d''exercice temporaire de la fonction de promotion. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur.» § 5. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion dans un établissement de promotion sociale un à un membre du personnel, conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre du personnel remplissant les conditions suivantes : 1° avoir acquis une ancienneté de service de sept ans au sein du pouvoir organisateur dans une des fonctions de recrutement, de sélection o');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 115, 'Article 52. - Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir (partie 3)', 'de promotion de la catégorie en cause, calculée selon les modalités fixées à l''article 34 du décret du 6 juin 1994 précité; 2° être titulaire, à titre définitif, d''une fonction ou plusieurs fonctions comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement organisé par le pouvoir organisateur concerné; 3° exercer à titre définitif une ou plusieurs fonctions dans l''enseignement secondaire et/ou dans une Haute Ecole, et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs; Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 49, du § 1er et du § 2 du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celles de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 116, 'Article 52bis. - § 1er. Toute désignation temporaire dans un emploi de promotion', 'Article 52bis. - § 1er. Toute désignation temporaire dans un emploi de promotion 
est établie par écrit, en reprenant les mentions visées à l''article 21, à l''exception du 7°. 
 
§ 2. Le pouvoir organisateur ne peut procéder à une désignation temporaire dans 
un emploi de promotion s''il est tenu, par les dispositions relatives à la réaffectation, de 
conférer cet emploi à un membre du personnel mis en disponibilité par défaut 
d''emploi. 
 
§ 3. Une désignation temporaire dans un emploi de promotion prend fin : 
a) d''un commun accord; 
b) par décision du pouvoir organisateur suite à la procédure visée au § 4 du 
présent article ou à la suite de l''application des dispositions du chapitre Vbis ; 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
c) ou par application de l''article 22, alinéa 1er. 
 
Toutefois, la fin de l''année scolaire est sans incidence sur la désignation 
temporaire dans un emploi de promotion. 
 
§ 4. Moyennant un préavis de quinze jours, le pouvoir organisateur peut mettre 
fin à la désignation d''un membre du personnel désigné à titre temporaire dans une 
fonction de promotion. 
 
Préalablement à la notification de toute décision de fin de désignation, le membre 
du personnel doit avoir été invité à se faire entendre par le pouvoir organisateur. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le pouvoir 
organisateur envisage de mettre fin à la désignation du membre du personnel lui sont 
notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à 
la poste, soit par la remise d''une lettre de la main à la main avec accusé de réception. 
Lors de l''audition, le membre du personnel peut se faire assister ou représenter par un 
avocat, par un défenseur choisi parmi les membres du personnel en activité de service 
ou pensionnés de l''enseignement officiel subventionné ou par un représentant d''une 
organisation syndicale représentant les membres du personnel de l''enseignement 
officiel subventionné affiliée à des organisations siégeant au Conseil national du 
Travail. L''audition fait l''objet d''un procès-verbal. La procédure se poursuit 
valablement lorsque le membre du personnel dûment convoqué ne se présente pas à 
l''audition ou n''y est pas représenté.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 117, 'Article 52ter. - Tout membre du personnel peut renoncer à sa nomination en', 'Article 52ter. - Tout membre du personnel peut renoncer à sa nomination en 
vertu de l''article 49 dans les six cents jours qui suivent sa première entrée en fonction 
de promotion. Dans ce cas, il réintègre à titre définitif sa fonction d''origine. 
 
Le pouvoir organisateur peut, pour assurer la continuité dans la fonction de 
promotion ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter 
la réintégration du membre du personnel dans sa fonction d''origine de maximum six 
mois à dater de la demande du membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 118, 'Article 52quater. - Les articles 49 à 52ter ne s''appliquent pas aux fonctions de', 'Article 52quater. - Les articles 49 à 52ter ne s''appliquent pas aux fonctions de 
promotion de directeur d''école maternelle, directeur d''école primaire, directeur d''école 
fondamentale, directeur de l''enseignement secondaire inférieur ou de préfet des études 
ou directeur, régies par le décret du 2 février 2007 fixant le statut des directeurs.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 119, 'Article 78. - Il est inséré dans le même décret un chapitre Vbis libellé comme', 'Article 78. - Il est inséré dans le même décret un chapitre Vbis libellé comme 
suit : 
«CHAPITRE Vbis. - De la lettre de mission, de l''évaluation et de la fin de l''exercice de 
certaines fonctions de promotion et de sélection');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 120, 'Article 52quinquies. - § 1er. Le présent chapitre s''applique aux membres du', 'Article 52quinquies. - § 1er. Le présent chapitre s''applique aux membres du 
personnel titulaires d''une fonction de promotion ou de sélection telle que visée aux 
articles 4, 3° et 5, 1° et 2° du décret du 4 janvier 1999 relatif aux fonctions de 
promotion et de sélection dans l''enseignement de plein exercice, et à l''article 50 du 
décret du 2 juin 1998 organisant l''enseignement secondaire artistique à horaire réduit 
subventionné par la Communauté française. 
 
Elle s''applique également aux membres du personnel titulaires d''une fonction de 
sélection telle que visée à l''article 6ter, 6°, b, de l''arrêté de l''Exécutif de la 
Communauté française du 2 octobre 1968 déterminant et classant les fonctions des 
membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du 
personnel paramédical, du personnel psychologique et du personnel social des 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
établissements d''enseignement préscolaire, primaire, spécialisé, moyen, technique, 
artistique, de promotion sociale et supérieur non universitaire de la Communauté 
française et les fonctions des membres du personnel du service d''inspection chargé de 
la surveillance de ces établissements dans l''enseignement de plein exercice. 
 
§ 2. Pour l''application du présent chapitre, il faut entendre par «directeur» le 
membre du personnel titulaire, à quelque titre que ce soit, de la fonction de promotion 
de directeur d''école maternelle, de directeur d''école primaire, de directeur d''école 
fondamentale, de directeur de l''enseignement secondaire inférieur ou de préfet des 
études ou directeur, telles qu''énumérées aux articles 3 et 4, 1° et 2° du décret du 4 
janvier 1999 relatif aux fonctions de promotion et de sélection ou de la fonction de 
promotion de directeur d''établissement de promotion sociale telle que prévue à l''article 
6ter, 6°, a de l''arrêté de l''Exécutif de la Communauté française du 2 octobre 1968 
déterminant et classant les fonctions des membres du personnel directeur et 
enseignant, du personnel auxiliaire d''éducation, du personnel paramédical, du 
personnel psychologique et du personnel social des établissements d''enseignement 
préscolaire, primaire, spécialisé, moyen, technique, artistique, de promotion sociale et 
supérieur non universitaire de la Communauté française et les fonctions des membres 
du personnel du service d''inspection chargé de la surveillance de ces établissements 
dans l''enseignement de plein exercice. 
 
Section 1re. - De la lettre de mission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 121, 'Article 52sexies. - Dès l''entrée en fonction du membre du personnel visé à', 'Article 52sexies. - Dès l''entrée en fonction du membre du personnel visé à 
l''article 52quinquies du présent décret, le directeur lui confie une lettre de mission 
approuvée préalablement par le pouvoir organisateur. 
 
Celle-ci spécifie les missions du membre du personnel visé à l''article 52quinquies 
et les priorités qui lui sont assignées, en fonction des besoins de l''établissement au 
sein duquel il est affecté et en fonction des objectifs contenus dans la lettre de mission 
que le directeur a lui-même reçue, conformément au chapitre III du titre II du décret 
du 2 février 2007 fixant le statut des directeurs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 122, 'Article 52septies. - § 1er. La lettre de mission a une durée de six ans.', 'Article 52septies. - § 1er. La lettre de mission a une durée de six ans. 
 
§ 2. Le contenu de la lettre de mission peut être modifié avant son échéance, au 
plus tôt après deux ans, par le directeur, en raison de l''évolution des besoins et du 
fonctionnement de l''établissement. 
 
Par dérogation à l''alinéa 1er, le contenu de la lettre de mission peut être modifié 
avant son échéance, de commun accord entre le directeur et le membre du personnel 
visé à l''article 52quinquies. 
 
La lettre de mission modifiée est soumise à l''approbation du pouvoir 
organisateur.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 123, 'Article 52octies. - § 1er. Par dérogation à l''article 52sexies, § 1er, alinéa 1er, le', 'Article 52octies. - § 1er. Par dérogation à l''article 52sexies, § 1er, alinéa 1er, le 
directeur, si besoin est et moyennant approbation préalable du pouvoir organisateur, 
peut confier une lettre de mission au membre du personnel désigné à titre temporaire 
dans l''exercice d''une fonction visée à l''article 52quinquies du présent décret. 
 
Le directeur confie d''office une lettre de mission, approuvée préalablement par le 
pouvoir organisateur, au membre du personnel désigné à titre temporaire dans 
l''exercice d''une fonction visée à l''article 52quinquies pour une durée égale ou 
supérieure à un an, ou dont la durée de la désignation a atteint au moins un an. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 2. La lettre de mission visée au présent article peut consister dans la 
confirmation de la lettre de mission du membre du personnel visé à l''article 
52quinquies faisant l''objet d''un remplacement ou dans un nouveau document. 
 
Section 2. - De l''évaluation formative');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 124, 'Article 52novies. - Cette section s''applique au membre du personnel nommé à', 'Article 52novies. - Cette section s''applique au membre du personnel nommé à 
titre définitif. 
 
Elle s''applique également au membre du personnel désigné à titre temporaire 
dans l''exercice d''une fonction visée à l''article 52quinquies pour une durée égale ou 
supérieure à un an, ou dont la durée de la désignation a atteint au moins un an. La 
dénomination «membre du personnel» visée à la présente section vise également ce 
membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 125, 'Article 52decies. - Tous les cinq ans à dater de sa nomination à titre définitif ou', 'Article 52decies. - Tous les cinq ans à dater de sa nomination à titre définitif ou 
de sa désignation à titre temporaire, chaque membre du personnel fait l''objet d''une 
évaluation effectuée conjointement par le pouvoir organisateur et le directeur. 
 
Si ces derniers le jugent utile, ils peuvent procéder, plus tôt, à une évaluation du 
membre du personnel. 
 
Toutefois, le membre du personnel ne peut faire l''objet de plus de deux 
évaluations par période de dix ans.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 126, 'Article 52undecies. - L''évaluation se fonde sur l''exécution de la lettre de mission', 'Article 52undecies. - L''évaluation se fonde sur l''exécution de la lettre de mission 
visée à la section Ire du présent chapitre et sur la mise en pratique des compétences 
acquises dans le cadre des formations visées par l''article 40, 6° du présent décret en ce 
qui concerne les fonctions de sélection et à l''article 49, 5° du présent décret pour les 
fonctions de promotion. 
 
Elle tient compte du contexte global dans lequel est amené à évoluer le membre 
du personnel et des moyens qui sont mis à sa disposition.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 127, 'Article 52duodecies. - En fonction de cette évaluation, le pouvoir organisateur et', 'Article 52duodecies. - En fonction de cette évaluation, le pouvoir organisateur et 
le directeur conviennent avec le membre du personnel des améliorations à apporter. 
 
Section 3. - De la fin de l''exercice de certaines fonctions de promotion et de sélection 
par les membres du personnel enseignant désignés à titre temporaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 128, 'Article 52terdecies. - Moyennant un préavis de quinze jours, le pouvoir', 'Article 52terdecies. - Moyennant un préavis de quinze jours, le pouvoir 
organisateur peut, soit sur proposition du directeur, soit d''initiative, mettre fin à la 
désignation d''un membre du personnel visé à l''article 52quinquies désigné à titre 
temporaire. 
 
Préalablement à la notification de toute décision de fin de désignation, le membre 
du personnel doit avoir été invité à se faire entendre par le pouvoir organisateur. 
 
La convocation à l''audition, ainsi que les motifs en raison desquels le pouvoir 
organisateur envisage de mettre fin à la désignation du membre du personnel ou en 
raison desquels le directeur envisage d''en faire la proposition au pouvoir organisateur 
lui sont notifiés cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste, soit par la remise d''une lettre de la main à la main avec 
accusé de réception portant ses effets à la date figurant sur cet accusé de réception. 
Lors de l''audition, le membre du personnel peut se faire assister ou représenter par un 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
avocat, par un défenseur choisi parmi les membres du personnel en activité de service 
ou pensionnés de l''enseignement officiel subventionné ou par un représentant d''une 
organisation syndicale représentant les membres du personnel de l''enseignement 
officiel subventionné affiliée à des organisations siégeant au Conseil national du 
Travail. La procédure se poursuit valablement lorsque le membre du personnel 
dûment convoqué ne se présente pas à l''audition ou n''y est pas représenté.». 
 
CHAPITRE III. - De l''enseignement libre subventionné 
 
Intitulé modifié par D. 14-03-2019 
Section Ire. - Conditions générales d''accès au stage et d’engagement à titre 
définitif 
 
Modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 129, 'Article 79. - § 1er. Le pouvoir organisateur qui doit admettre au stage à la', 'Article 79. - § 1er. Le pouvoir organisateur qui doit admettre au stage à la 
fonction de promotion de directeur : 
1° consulte l''organe local de concertation sociale, sur le profil de la fonction de 
directeur à pourvoir; [remplacé par D. 14-03-2019] 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de l''admission au stage. 
 
Remplacé par D. 14-03-2019 
§ 2. Le pouvoir organisateur après application du paragraphe 1er : 
1° arrête le profil de la fonction de directeur à pourvoir. Ce profil de fonction est 
établi conformément à l''article 5, § 2; 
2° lance un appel à candidatures, selon le modèle visé à l''article 31. 
 
Remplacé par D. 14-03-2019 
§ 3. Par dérogation aux paragraphes précédents, un appel à candidatures pour 
l''admission au stage ne doit pas être lancé, lorsque l''emploi devient définitivement 
vacant, dans les deux cas suivants : 
a) lorsque le membre du personnel a été engagé à titre temporaire, conformément 
aux dispositions du présent chapitre, à la suite d''un appel à candidatures pour un 
emploi temporairement vacant débouchant à terme sur un emploi définitivement 
vacant et dont le modèle est visé à l''article 31. 
 
Dans ce cas, le pouvoir organisateur admet au stage le directeur engagé à titre 
temporaire à la date de la vacance définitive de l''emploi. La durée du stage est réduite 
à concurrence du temps déjà presté, à titre temporaire, dans cet emploi. 
 
Les évaluations se font, mutatis mutandis, conformément à l''article 33, §§ 2 à 5; 
 
b) lorsque le membre du personnel a été engagé à titre temporaire dans un 
emploi non vacant, suite à un appel à candidatures, et ce, de manière ininterrompue 
depuis 3 ans au moins à la date à laquelle l''emploi est devenu vacant. 
 
Dans ce cas, le membre du personnel est engagé à titre définitif lorsque l''emploi 
devient vacant, s''il remplit les conditions de l''article 81. 
 
Alinéa inséré par D. 04-02-2021 
Si un directeur exerçant ses fonctions au sein d''un pouvoir organisateur non 
affilié à une fédération de pouvoirs organisateurs, n''a pas obtenu toutes ses 
attestations de réussite, telles que visées à l''article 81 1°, au moment où l''emploi 
devient vacant, il peut demander à son pouvoir organisateur de suivre un stage d''un 
an. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 130, 'Article 79bis. - § 1er. Le pouvoir organisateur met en place une commission de', 'Article 79bis. - § 1er. Le pouvoir organisateur met en place une commission de 
sélection. Elle est composée de membres ou de délégués du pouvoir organisateur. 
 
Elle comprend au moins un membre disposant d''une expertise pédagogique et un 
ou plusieurs membres extérieurs au pouvoir organisateur, disposant d''une expérience 
en ressources humaines et en matière de sélection du personnel. 
 
La composition de la commission de sélection est communiquée aux Services du 
Gouvernement selon les modalités qu''ils fixent. 
 
§ 2. La sélection des candidats se fonde sur le profil de fonction élaboré par le 
pouvoir organisateur conformément à l''article 5, § 2, et annexé à l''appel à 
candidatures et, plus particulièrement, sur l''évaluation des compétences techniques et 
comportementales des candidats, assorties d''indicateurs de maîtrise, et leur 
compatibilité avec le projet éducatif et pédagogique du pouvoir organisateur, ainsi que, 
dans l''enseignement secondaire artistique à horaire réduit, avec le projet pédagogique 
et artistique de l''établissement. 
 
§ 3. La commission de sélection peut opérer un tri des candidatures sur dossier et 
n''entendre que les candidats retenus suite à cette sélection. Au terme des auditions, 
celle-ci établit un rapport classant les candidats et fournissant toutes informations 
utiles pour motiver le classement. 
 
Ce rapport est adressé au pouvoir organisateur qui, sur cette base, prend la 
décision d''admission au stage. 
 
§ 4. Le pouvoir organisateur communique aux candidats les motifs de son choix 
du directeur stagiaire eu égard aux critères fixés dans le profil de la fonction 
déterminé conformément au présent article. 
 
§ 5. A sa demande, tout candidat recevra communication de la façon dont a été 
évaluée la correspondance de ses compétences comportementales et techniques avec 
les critères de sélection définis et pondérés par le profil de fonction. 
 
Remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 131, 'Article 80. - § 1er. Nul ne peut être admis au stage dans la fonction de directeur', 'Article 80. - § 1er. Nul ne peut être admis au stage dans la fonction de directeur 
s''il ne répond, au moment de l''admission au stage, aux conditions suivantes : 
1° être porteur d''un titre de niveau bachelier au moins; dans l''enseignement 
secondaire artistique à horaire réduit, les membres du personnel enseignant des 
disciplines pour lesquelles n''existe pas de formation délivrant un titre de niveau 
supérieur du 1er degré, peuvent être admis au stage pour autant qu''ils soient porteurs 
d''un des titres visés aux articles 105 à 108 point a) ou b) du décret du 2 juin 1998 
organisant l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française; 
2° être porteur d''un des titres pédagogiques listés à l''article 100; 
3° avoir une ancienneté de service de 3 ans dans l''enseignement organisé ou 
subventionné par la Communauté française; 
4° avoir répondu à l''appel à candidatures visé à l''article 79. 
 
Remplit les conditions 1° et 2°, le candidat qui possède un diplôme constitutif à la 
fois d''un titre pédagogique et d''un titre du titre de niveau bachelier au moins. 
 
Le directeur admis au stage en vertu de l''article 30 est réputé remplir les 
conditions 1°, 2° et 3° de l''alinéa 1er. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 2. Un pouvoir organisateur qui atteste avoir lancé un appel à candidatures et 
n''avoir pas reçu de candidature valable après ce 1er appel, peut lancer un second appel 
à candidatures ne remplissant pas la condition 3° visée au § 1er. 
 
Si la personne admise au stage n''exerce pas de fonction dans l''enseignement 
organisé ou subventionné par la Communauté française au moment de son admission 
au stage, elle ne pourra entrer en fonction que si elle rencontre également les 
conditions suivantes : 
1° jouir des droits civils et politiques; 
2° satisfaire aux dispositions légales et réglementaires relatives au régime 
linguistique; 
3° être de conduite irréprochable; 
4° satisfaire aux lois sur la milice. 
 
Remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 132, 'Article 81. - Un membre du personnel ne peut être engagé à titre définitif dans', 'Article 81. - Un membre du personnel ne peut être engagé à titre définitif dans 
la fonction de promotion de directeur que s''il remplit les conditions suivantes : 
1° avoir obtenu les attestations de réussite visées à l''article 15, § 1er, alinéa 1er, et 
l''attestation de suivi visée à l''article 15, § 1er, alinéa 4; 
2° avoir répondu à l''appel à candidatures visé à l''article 79; 
3° avoir acquis une ancienneté de service de six ans au moins calculée selon les 
modalités fixées à l''article 29bis ou 29ter du décret du 1er février 1993 précité. 
Le membre du personnel qui ne remplit pas cette condition voit son stage 
prolongé jusqu''à ce qu''il remplisse ladite condition; 
4° avoir obtenu 3 évaluations dont la dernière a abouti à la mention «favorable ». 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 133, 'Article 81bis. - § 1er. Un pouvoir organisateur ne peut procéder à un', 'Article 81bis. - § 1er. Un pouvoir organisateur ne peut procéder à un 
engagement à titre définitif dans un emploi vacant d''une fonction de directeur que s''il 
n''est pas tenu, par les dispositions en vigueur sur la réaffectation ou la remise au 
travail, d''engager à cet emploi un membre du personnel mis en disponibilité par 
défaut d''emploi. 
 
§ 2. L''engagement à une fonction de directeur ne peut intervenir que si l''emploi 
est occupé en fonction principale. 
 
§ 3. L''engagement à titre définitif, n''est pas permis dans un emploi faisant partie 
d''un établissement, d''une section, d''une implantation, d''un degré, d''un cycle ou d''une 
autre subdivision qui, en application des règles de rationalisation est en voie de 
fermeture progressive ou dans un emploi faisant partie d''un établissement dont la 
période d''admission aux subventions est limitée par une décision de l''Exécutif 
préalablement signifiée au pouvoir organisateur. 
 
Complété par D. 18-07-2008 ; modifié par D. 25-01-2009 ; D. 11-04-2014 ; remplacé 
par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 134, 'Article 82. - § 1er. Lorsqu''un directeur définitif est engagé, suite à un appel à', 'Article 82. - § 1er. Lorsqu''un directeur définitif est engagé, suite à un appel à 
candidatures, dans un autre emploi de directeur, tel que défini à l''article 2, par son 
pouvoir organisateur, celui-ci l''admet au stage si l''emploi est définitivement vacant ou 
l''engage à titre temporaire si l''emploi est temporairement vacant. Durant cette 
période, le directeur reste titulaire de son emploi d''origine et bénéficie d''un congé 
conformément aux articles 9 ou 14 de l''arrêté royal du 15 janvier 1974 précité. 
 
Par dérogation à l''alinéa précédent, le directeur ne peut être admis au stage ou 
engagé à titre temporaire qu''après avoir exercé ses fonctions dans l''emploi qu''il occupe 
durant un délai de trois ans. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
§ 2. Après un an, le pouvoir organisateur effectue une évaluation axée sur 
l''adéquation aux éléments du profil de fonction spécifique à l''établissement. Si cette 
évaluation est favorable, le directeur est engagé à titre définitif, lorsque l''emploi est 
définitivement vacant. 
 
En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son 
emploi d''origine. 
 
Il peut en outre être mis fin à la fonction conformément aux articles 33 et 34. 
 
Inséré par D. 13-07-2016 ; remplacé par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 135, 'Article 82bis. - § 1er. Lorsqu''un directeur définitif est engagé, suite à un appel à', 'Article 82bis. - § 1er. Lorsqu''un directeur définitif est engagé, suite à un appel à 
candidatures, dans un autre emploi de directeur, tel que défini à l''article 2, auprès 
d''un autre pouvoir organisateur que celui auprès duquel il est engagé à titre définitif, 
ce dernier l''admet au stage si l''emploi est définitivement vacant ou l''engage à titre 
temporaire si l''emploi est temporairement vacant. Durant cette période, le directeur 
reste titulaire de son emploi d''origine et bénéficie d''un congé conformément aux 
articles 9 ou 14 de l''arrêté royal du 15 janvier 1974 précité. 
 
Par dérogation à l''alinéa précédent, le membre du personnel ne peut être admis 
au stage ou engagé à titre temporaire qu''après avoir exercé ses fonctions dans l''emploi 
qu''il occupe durant un délai de trois ans. 
 
§ 2. Après un an, le pouvoir organisateur effectue une évaluation axée sur 
l''adéquation aux éléments du profil de fonction spécifique à l''établissement. En cas 
d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son l''emploi 
d''origine. 
 
Après deux ans, le pouvoir organisateur effectue une deuxième évaluation axée 
sur l''adéquation aux éléments du profil de fonction spécifique à l''établissement. Si 
cette évaluation est favorable, le directeur est engagé à titre définitif dans l''emploi 
qu''il occupe, lorsque celui-ci est définitivement vacant. 
 
En cas d''évaluation défavorable, il est mis fin à sa fonction et il réintègre son 
emploi d''origine. 
 
Il peut, en outre, être mis fin à la fonction conformément aux articles 33 et 34. 
 
Section II. - De l''engagement à titre temporaire dans un emploi de directeur 
 
Modifié par D. 13-12-2007 ; complété par D. 23-01-2009 ; modifié par D.10-02-
2011 ; remplacé par D. 14-03-2019 ; modifié par D. 04-02-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 136, 'Article 83. - § 1er. La fonction de directeur peut être confiée temporairement,', 'Article 83. - § 1er. La fonction de directeur peut être confiée temporairement, 
suite à la procédure d''appel visée aux articles 79 et 79bis, appliquée mutatis 
mutandis, à un membre du personnel remplissant toutes les conditions visées à 
l''article 80 : 
1° si le titulaire de la fonction est temporairement absent; 
2° dans l''hypothèse visée à l''article 81bis, § 3. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est engagé à titre définitif. 
 
Il est évalué, mutatis mutandis, conformément à l''article 33, §§ 2 à 5. 
 
§ 2. Pour tout engagement d''une durée égale ou inférieure à 15 semaines, la 
condition de l''article 80, § 1er, 3°et 4° n''est pas obligatoire. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Cet engagement pour 15 semaines maximum peut être renouvelé pour autant 
que la durée totale de désignation n''excède pas 12 mois. 
 
Si l''absence du titulaire de la fonction se prolonge, le pouvoir organisateur lance 
un appel à candidatures au plus tard le dernier jour de la période d''engagement visée 
à l''alinéa précédent. 
 
Par dérogation à l''alinéa 2, l''engagement est prolongé pendant la période entre 
l''appel à candidatures et l''engagement d''un candidat. 
 
Le pouvoir organisateur engage un candidat dans les trois mois qui suivent 
l''appel à candidatures. A défaut, au terme de ces trois mois, l''emploi n''est plus 
subventionné sauf si le pouvoir organisateur atteste qu''il n''a pu obtenir, à la suite de 
cet appel, de candidature qui réponde aux critères du profil de fonction. 
 
Dans ce cas, par dérogation aux alinéas 2 et 4, un délai supplémentaire, ne 
dépassant pas 15 semaines, est octroyé au pouvoir organisateur afin d''engager un 
directeur au terme d''une nouvelle procédure d''appel. L''engagement initial visé aux 
alinéas 1er, 2 et 4 n''est pas subventionné au-delà de ce deuxième appel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 137, 'Article 84. - § 1er Tout engagement temporaire dans un emploi de directeur est', 'Article 84. - § 1er Tout engagement temporaire dans un emploi de directeur est 
établi par écrit, conformément aux dispositions de l''article 31 du décret du 1er février 
1993 précité, à l''exception du 8°. 
 
§ 2 L''engagement temporaire dans un emploi de directeur n''est possible qu''après 
application par le pouvoir organisateur de la disposition de l''article 55, 1° du décret du 
1er février 1993 précité. 
 
§ 3. Un engagement temporaire dans un emploi de directeur prend fin 
conformément à l''article 71nonies du décret du 1er février 1993 précité. 
 
La fin de l''année scolaire est sans incidence sur l''engagement temporaire dans un 
emploi de directeur. 
 
Section III. – [Des mécanismes de soutien et de développement des 
compétences professionnelles et d’évaluation]34');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 138, 'Article 85. - Cette section s''applique aux directeurs engagés à titre définitif.', 'Article 85. - Cette section s''applique aux directeurs engagés à titre définitif. 
 
Elle s''applique également au membre du personnel auquel est confiée à titre 
temporaire une fonction de directeur pour une durée égale ou supérieure à un an, ou 
dont la durée de la désignation a atteint au moins un an. La dénomination «directeur» 
visée à la présente section vise également ce membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 139, 'Article 86. – [Les membres du pouvoir organisateur chargés de cette évaluation', 'Article 86. – [Les membres du pouvoir organisateur chargés de cette évaluation 
sont soutenus par leur fédération de pouvoir organisateur qui leur apporte 
notamment, une éventuelle expertise technique spécialisée. Par ailleurs, ils ont accès 
à la formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, au 
développement des compétences professionnelles et à l''évaluation des personnels de 
l''enseignement. 
 
Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en ressources 
 
34 Intitulé remplacé par le décret du 20 juillet 2023 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
humaines pour procéder aux entretiens et/ou évaluations visés à la sous-section II]35. 
 
[Sous-section I.- Du mécanisme de soutien et de développement des 
compétences professionnelles]36 
 
Modifié par D.10-02-2011 ; D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 140, 'Article 87. – [§1er. Le mécanisme de soutien et de développement des (partie 1)', 'Article 87. – [§1er. Le mécanisme de soutien et de développement des compétences professionnelles est composé, notamment, d''entretiens de développement professionnel entre le directeur et son pouvoir organisateur et d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Ces entretiens de développement professionnel sont organisés à l''initiative du pouvoir organisateur mais peuvent également être demandés par le directeur. Un délai de minimum cinq jours ouvrables doit être garanti entre la convocation à l''entretien de développement professionnel et la date de l''entretien de développement professionnel. L''entretien de développement professionnel doit faire l''objet d''un compte-rendu. Un entretien de développement professionnel doit avoir lieu dans la mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. L''entretien de développement professionnel porte sur l''exécution de la lettre de mission visée au chapitre III du Titre 1er et sur la mise en oeuvre du contrat d''objectifs, quand celui-ci existe. Dans le cadre de l''entretien de développement professionnel, il est tenu compte du contexte global dans lequel est amené à évoluer le directeur et des moyens mis à sa disposition. Dans ce cadre, le pouvoir organisateur prend en considération : a) dans l''enseignement maternel et dans l''enseignement obligatoire, les dispositions relatives aux projets éducatif et pédagogique du pouvoir organisateur et au projet d''établissement visés au titre 5 du Code de l''enseignement fondamental et de l''enseignement secondaire ; b) dans l''enseignement de promotion sociale, les dispositions relatives au projet pédagogique visé à l''article 36, §2, du décret du 16 avril 1991 précité ; c) dans l''enseignement secondaire artistique à horaire réduit, les dispositions relatives au projet artistique et au projet pédagogique du pouvoir organisateur visés à l''article 1er, 7° et 8° du décret du 02 juin 1998 organisant l''enseignement secondaire artistique à horaire réduit subventionné par la Communauté française et les dispositions relatives au projet éducatif et artistique d''établissement visé à l''article 3bis du même décret. §2. A la suite de cet entretien et à la demande du pouvoir organisateur ou du directeur, un plan de développement des compétences professionnelles est mis en place. Ce plan de développement des compétences professionnelles est élaboré par le pouvoir organisateur ou son délégué en concertation avec le directeur. 35 Remplacé par le décret du 20 juillet 2023 36 Ajouté par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 §3. Ce plan de développement des compétences professionnelles est formalisé dans un document cosigné, tel que visé à l''article 88 et contient des engagements mutuels des deux parties tels que des objectifs individualisés, spécifiques, réalistes et adaptés au directeur ainsi que les moyens mis à sa disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. L''obligation de co-signature visée à l''alinéa précédent est réputée remplie dès lors que le pouvoir organisateur ou son délégué fait la preuve que la demande de signature pour prise de connaissance a été adressée au membre du personnel. En cas de refus de signature du directeur, la procédure de mise en œuvre du plan de développement des compétences professionnelles se poursuit valablement. §4. Sa périodicité est adaptée de manière à permettre au directeur de mettre en place les conseils dispensés ou de suivre les formations recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement des compétences professionnelles par année scolaire. Toutefois, durant une même année scolaire, un membre du personnel faisant l''objet d''un plan de développement des compétences professionnelles peut également être amené à avoir un plan d''accompagnement individualisé élaboré suite à une première évaluation avec mention défavorable. §5. Le plan de développement des compétences professionnelles peut faire l''objet d''ajustements à l''initiative du pouvoir organisateur ou à la demande du directeur. Ils sont cosignés par les deux parties. §6. Le plan de développement des compétences professionnelles donne lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois après la mise en place du plan de développement des compétences professionnelles et au plus tard deux ans après celle-ci. L''entretien de clôture est mené par le pouvoir organisateur ou son délégué. L''entretien de clôture fait l''objet d''un compte-rendu. §7. Pour le calcul des délais de six mois et deux ans précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 141, 'Article 87. – [§1er. Le mécanisme de soutien et de développement des (partie 2)', 'personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]37. [Article 88. - Le Gouvernement fixe le modèle de plan de développement des compétences professionnelles, pouvant servir de base à l''évaluation visée dans la sous- section 2. »]38. 37 Remplacé par le décret du 20 juillet 2023 38 Remplacé par le décret du 20 juillet 2023 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 [Sous-section II.- Du mécanisme d’évaluation]39 [Article 88/1. - §1er. En cas de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste et répétée à atteindre les objectifs identifiés avec le directeur dans le cadre du plan de développement des compétences professionnelles, une procédure d''évaluation peut être engagée par pouvoir organisateur. Toute première évaluation est précédée d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Une évaluation ne peut avoir lieu qu''une fois par année scolaire. §2. Au plus tôt six mois après avoir communiqué ce plan de développement des compétences professionnelles au directeur et pour autant que l''entretien de clôture visé à l''article 87, §6 ait eu lieu, le pouvoir organisateur peut procéder à une évaluation de celui-ci. Ce délai est calculé conformément à l''article 88/2, §2. §3. Le directeur doit être entendu préalablement à toute attribution d''une mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel des établissements d''enseignement libre subventionné, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. §4. L''évaluation débouche sur une mention « favorable » ou « défavorable ». Elle est formalisée selon le document visé à l''article 88/5 et notifiée au membre du personnel. La mention d''évaluation est motivée sur la base des éléments du plan de développement des compétences professionnelles, pour la première évaluation. En l''absence de rapport d''évaluation, tout membre du personnel est réputé bénéficier de la mention « favorable ». §5. En cas d''évaluation débouchant sur la mention « défavorable », un entretien entre le directeur et le pouvoir organisateur ou son délégué est, ensuite, fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé]40. [Article 88/2. - §1er. Après un délai de minimum six mois d''exercice de la fonction entre la communication au directeur du plan d''accompagnement individualisé convenu lors de l''évaluation avec mention « défavorable » qui précède, une nouvelle évaluation peut avoir lieu. Ce délai doit permettre au directeur de remédier aux carences constatées. Toutefois, après une évaluation avec mention « défavorable », l''évaluation 39 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027) 40 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 suivante doit intervenir dans un délai maximum de deux ans suivant la communication du plan d''accompagnement individualisé faisant suite à la précédente évaluation. A défaut, elle est réputée favorable. Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir dans un délai plus long en cas de prolongation du plan d''accompagnement individualisé telle que visée à l''article 88/3. §2. Pour le calcul des délais de six mois et deux ans précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements]41. [Article');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 142, 'Article 87. – [§1er. Le mécanisme de soutien et de développement des (partie 3)', '88/3. - §1er. Le rapport d''évaluation faisant suite à une première évaluation définitive avec mention « défavorable » est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, en cas d''un commun accord entre le membre du personnel et le pouvoir organisateur sur la prolongation du plan d''accompagnement individualisé. Le rapport d''évaluation est formalisé selon le document visé à l''article 88/5 ainsi que notifié au directeur. La prolongation du plan d''accompagnement individualisé est de minimum 3 mois et de maximum un an. La mention d''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel des établissements d''enseignement libre subventionné, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. §3. En cas de prolongation du plan d''accompagnement individualisé, un entretien entre, d''une part, le pouvoir organisateur et, d''autre part, le directeur est fixé afin de mettre en place un plan d''accompagnement individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan d''accompagnement individualisé précédent que le directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un maximum de quatre objectifs peut être fixé. Le plan d''accompagnement individualisé donne lieu à un entretien de clôture. 41 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 L''entretien de clôture fait l''objet d''un compte-rendu. §4. Après prolongation du plan d''accompagnement individualisé, une nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai maximum d''un an d''exercice de la fonction à partir de la communication au membre du personnel du plan d''accompagnement individualisé adapté à la suite de la prolongation du plan d''accompagnement individualisé. A défaut, elle est réputée favorable. Ce délai doit permettre au directeur de remédier aux carences constatées. §5. Pour le calcul des délais de trois mois et un an précités, sont seuls pris en considération les services effectifs rendus pendant l''exercice de la fonction, en ce compris : - les vacances annuelles, à l''exclusion des vacances d''été ; - les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. §6. Le rapport d''évaluation faisant suite à une prolongation de plan d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il débouche sur une mention « favorable » ou « défavorable » et est formalisé selon le document visé à l''article 88/5 ainsi que notifié au directeur. La mention d''évaluation est motivée sur la base des éléments du plan d''accompagnement individualisé. Le directeur doit avoir été entendu préalablement à l''attribution de sa mention d''évaluation par le pouvoir organisateur. La convocation doit lui être notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit par la remise d''une lettre de la main à la main avec accusé de réception. Lors de l''entretien d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi les membres du personnel des établissements d''enseignement libre subventionné, en activité de service ou pensionnés, ou par un représentant d''une organisation syndicale représentative. Une évaluation ne peut avoir lieu qu''une fois par année scolaire]42. [Article 88/4. - §1er. En cas d''évaluation avec mention « défavorable », le directeur peut, dans les 10 jours ouvrables qui suivent la réception du rapport, introduire un recours conformément aux modalités décrites au chapitre Vbis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné, applicables mutatis mutandis. Le directeur qui fait usage de son droit de recours en notifie immédiatement une copie à son pouvoir organisateur. Ce recours est suspensif. 42 Ajouté');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 143, 'Article 87. – [§1er. Le mécanisme de soutien et de développement des (partie 4)', 'par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026- 2027 Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 §2. La répétition de deux mentions « défavorable » consécutives sur deux années scolaires distinctes, devenues définitives après épuisement des procédures devant la chambre de recours, telles que visées à l''article 61decies/6 du décret du 1er février 1993 précité, a pour conséquence de mettre fin d''office aux fonctions du directeur en application de l''article 72, §1er, 12° du décret du 1er février 1993 précité]43. [Article 88/5. - Le Gouvernement fixe le modèle de plan d''accompagnement individualisé et de rapport d''évaluation]44. [Article 88/6. - Toute notification de document, de décision ou de convocation mentionnée dans la présente sous-section se fait par courrier recommandé avec accusé de réception ou par une remise de la main à la main avec accusé de réception]45. [Sous-section III.- Des règles de déontologie]46 [Article 88/7. - Dans le cadre des entretiens et évaluations visées à la présente section, le membre du personnel et son évaluateur sont tenus au respect des devoirs suivants : a) la discrétion ; b) le respect mutuel. En outre, l''évaluateur est tenu de : a) motiver, de manière adéquate et constructive, ses instructions/conseils/échanges avec le membre du personnel ainsi que la mention d''évaluation ; b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; c) respecter les devoirs d''impartialité et d''objectivité]47. Section IV. - Des passerelles entre fonctions de promotion, de sélection et de recrutement');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 144, 'Article 89. - L''article 41ter du décret du 1er février 1993, inséré par le décret du', 'Article 89. - L''article 41ter du décret du 1er février 1993, inséré par le décret du 
10 avril 1995 et modifié par le décret du 19 décembre 2002, est remplacé par la 
disposition suivante : 
«Article 41ter. - Un membre du personnel engagé à titre définitif dans une 
fonction de sélection ou de promotion auprès d''un pouvoir organisateur peut, s''il le 
demande et avec l''accord du pouvoir organisateur, être engagé à titre définitif dans un 
emploi définitivement vacant d''une fonction de recrutement, de sélection ou de 
promotion qui donne accès à sa fonction actuelle par un pouvoir organisateur auprès 
duquel il a déjà bénéficié d''un engagement à titre définitif dans une fonction de 
recrutement, de sélection ou de promotion conformément aux dispositions de l''article 
29quater, 1°. 
 
43 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026-
2027 
44 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026-
2027 
45 Ajouté par le décret du 20 juillet 2023 (entre en vigueur le premier jour de l’année scolaire 2026-
2027 
46 Ajouté par le décret du 20 juillet 2023 
47 Ajouté par le décret du 20 juillet 2023 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Un membre du personnel engagé à titre définitif dans une fonction de sélection 
ou de promotion auprès d''un pouvoir organisateur peut, s''il le demande et avec l''accord 
du pouvoir organisateur être engagé à titre définitif dans un emploi définitivement 
vacant d''une fonction de recrutement, de sélection ou de promotion qui donne accès à 
sa fonction actuelle par un pouvoir organisateur autre que ceux visés à l''alinéa 1er, 
conformément aux dispositions de l''article 29quater, 3°. 
 
Pour l''application des alinéas 1er et 2 et sans préjudice de l''article 29quinquies, 
l''engagement peut avoir lieu quelle que soit la date. Il ne peut être accordé que pour 
autant que le membre remplisse toutes les conditions prévues selon le cas : 
a) à l''article 42, § 1er, à l''exception du 8° en ce qui concerne l''ancienneté de 
fonction et des 10° et 12°; 
b) à l''article 51, les conditions devant être remplies dans l''enseignement 
subventionné; 
c) à l''article 59, les conditions devant être remplies dans l''enseignement 
subventionné; 
d) à l''article 80 du décret du 2 février 2007 fixant le statut des directeurs, les 
conditions devant être remplies dans l''enseignement subventionné. 
 
Pour l''application des points b), c) et d) de l''alinéa 3, l''exigence du suivi de la 
formation relative à une fonction déterminée est d''office réputée remplie si le membre 
du personnel a été titulaire à titre définitif de cette fonction avant l''exercice de sa 
fonction actuelle. 
 
Le membre du personnel visé au présent article se voit attribuer l''échelle de 
traitement de la fonction dans laquelle il est engagé à titre définitif conformément à 
cette disposition. 
 
Toutefois, le membre du personnel visé au présent article, qui a exercé pendant 
au moins dix ans à titre définitif la fonction de sélection ou de promotion qu''il quitte, 
bénéficie d''un mécanisme dégressif d''échelles de traitement pour rejoindre à partir de 
la 3ème année l''échelle de traitement de la fonction dans laquelle il est engagé à titre 
définitif conformément au présent article fixé comme suit : 
a) Au cours de la première année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 66 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté; 
b) Au cours de la deuxième année qui suit sa nouvelle affectation, le membre du 
personnel bénéficie de l''échelle de traitement de la fonction dans laquelle il est affecté, 
augmentée d''un montant équivalent à 33 % de la différence entre d''une part l''échelle 
de traitement dont il bénéficiait dans la fonction qu''il a quittée et d''autre part l''échelle 
de traitement de la fonction dans laquelle il est affecté.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 145, 'Article 90. - Le point 2° de l''article 48 du même décret est complété par les / Article 91. - Le point 2° de l''article 55 du même décret est complété par les', 'Article 90. - Le point 2° de l''article 48 du même décret est complété par les 
termes suivants : «ou est engagé dans cet emploi conformément à l''article 41ter.».

Article 91. - Le point 2° de l''article 55 du même décret est complété par les 
termes suivants : «ou est engagé dans cet emploi conformément à l''article 41ter.». 
 
Section V. - Dispositions modificatives');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 146, 'Article 92. - Un article 50bis, rédigé comme suit, est ajouté au décret du 1er', 'Article 92. - Un article 50bis, rédigé comme suit, est ajouté au décret du 1er 
février 1993 précité : 
«Article 50bis. - § 1er. Le pouvoir organisateur qui doit engager à titre définitif un 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
membre du personnel dans une fonction de sélection : 
1° consulte le directeur de l''établissement ainsi que, selon le cas, le conseil 
d''entreprise, l''instance de concertation locale, ou à défaut, la délégation syndicale sur 
le profil de la fonction de sélection à pourvoir; 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de l''engagement à titre définitif. 
 
§ 2. Le pouvoir organisateur après application du § 1er : 
1° arrête le profil de la fonction de sélection à pourvoir. Dans ce cadre, le pouvoir 
organisateur peut ajouter des critères complémentaires aux conditions d''engagement à 
titre définitif visées à l''article 51; 
2° lance un appel aux candidats selon les formes déterminées par le 
Gouvernement. 
 
§ 3. Le pouvoir organisateur communique aux candidats les motifs de son choix 
du membre du personnel engagé à titre définitif dans la fonction de sélection eu égard 
aux critères fixés dans le profil de la fonction déterminé conformément au présent 
article».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 147, 'Article 93. - L''article 51 du décret du 1er février 1993 précité est remplacé par la', 'Article 93. - L''article 51 du décret du 1er février 1993 précité est remplacé par la 
disposition suivante : 
 
«Article 51. - Nul ne peut être engagé à titre définitif dans une fonction de 
sélection s''il ne répond au moment de l''engagement aux conditions suivantes : 
 
1° Avoir acquis une ancienneté de service de six ans au sein de l''enseignement 
subventionné, dans une des fonctions de recrutement, de sélection ou de promotion de 
la catégorie en cause calculée selon les modalités fixées à l''article 29bis ; 
2° Etre engagé à titre définitif dans une de ces fonctions dans l''enseignement 
libre subventionné du caractère concerné; 
3° Etre titulaire, à titre définitif, avant cet engagement, d''une fonction 
comportant au moins une demi-charge dans l''enseignement libre subventionné du 
caractère concerné; 
4° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction 
de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 
101 du décret du 2 février 2007 fixant le statut des directeurs; 
5° avoir suivi au préalable une formation spécifique sanctionnée par un certificat 
de fréquentation; 
6° avoir répondu à l''appel aux candidats visé à l''article 50bis».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 148, 'Article 94. - Les articles 53 à 54 du même décret sont remplacés par les', 'Article 94. - Les articles 53 à 54 du même décret sont remplacés par les 
dispositions suivantes : 
 
«Article 53. - § 1er. Une fonction de sélection peut être confiée temporairement à 
un membre du personnel remplissant toutes les conditions de l''article 51 au moment 
de l''engagement : 
1° si le titulaire de la fonction est temporairement absent; 
2° dans le cas visé à l''article 50. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est engagé à titre définitif le cas échéant auprès de son pouvoir organisateur 
d''origine. 
 
§ 2. Par dérogation au § 1er, alinéa 1er, pour tout engagement d''une durée égale 
ou inférieure à 15 semaines, les conditions visées à l''article 51, 5° et 6°, ne sont pas 
exigées. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 149, 'Article 54. - Une fonction de sélection peut être confiée temporairement à un', 'Article 54. - Une fonction de sélection peut être confiée temporairement à un 
membre du personnel remplissant toutes les conditions de l''article 51 dans l''attente 
d''un engagement à titre définitif. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est engagé à titre définitif le cas échéant auprès de son pouvoir organisateur 
d''origine. 
 
Le membre du personnel visé à l''alinéa 1er est engagé à titre définitif dans la 
fonction de sélection au plus tard au terme d''un délai de deux ans si le pouvoir 
organisateur ne l''a pas licencié de cette fonction de sélection selon les dispositions du 
chapitre VIII.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 150, 'Article 54bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 1)', 'Article 54bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement la fonction de sélection à un membre du personnel remplissant toutes les conditions d''accès à la fonction de sélection visées à l''article 51, peut confier temporairement la fonction de sélection à un membre du personnel engagé à titre définitif remplissant les conditions suivantes : 1° Etre titulaire, à titre définitif, avant cet engagement d''une fonction comportant au moins une demi-charge dans un pouvoir organisateur de l''enseignement subventionné du caractère concerné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de sélection, le membre du personnel reste titulaire de l''emploi dans lequel il est engagé à titre définitif, le cas échéant auprès de son pouvoir organisateur d''origine. Tout pouvoir organisateur qui démontre n''avoir qu''un seul candidat à l''admission au stage répondant aux conditions de l''article 51, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur conformément aux dispositions du chapitre VIII. § 2. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre du personnel engagé à titre définitif conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre du personnel temporaire prioritaire de l''enseignement subventionné du caractère concerné remplissant les conditions suivantes : 1° Etre titulaire, à titre temporaire, avant cet engagement d''une fonction comportant au moins une demi-charge dans un pouvoir organisateur de l''enseignement subventionné du caractère concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 51 et n''avoir qu''un seul candidat à l''admission au stage Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 répondant aux conditions du § 1er, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel visé à l''alinéa 1er ou à l''alinéa 3 sera réputé remplir la condition exigée à l''article 51, 1° et 2° à l''expiration d''un délai de six années d''exercice temporaire de la fonction de sélection. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur conformément aux dispositions du chapitre VIII. § 3. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre du personnel engagé à titre définitif ou temporaire prioritaire conformément aux dispositions qui précèdent, peut faire appel à un membre du personnel engagé à titre définitif dans l''enseignement subventionné et remplissant, les conditions suivantes : 1° Etre titulaire, à titre définitif, avant cet engagement d''une fonction comportant au moins une demi-charge dans l''enseignement subventionné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs Pendant la période durant laquelle il exerce temporairement la fonction de sélection, le membre du personnel reste titulaire de l''emploi dans lequel il est engagé à titre définitif au sein de son pouvoir organisateur d''origine. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 51 et du § 1er du présent article, et n''avoir qu''un seul candidat à l''admission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 151, 'Article 54bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 2)', 'au stage répondant aux conditions du § 2, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel désigné temporairement dans une fonction de sélection en vertu du présent paragraphe est engagé à titre définitif dans ladite fonction au terme d''un délai de six années s''il remplit à ce moment la condition prescrite par l''article 51, 5°, et si le pouvoir organisateur ne l''a pas licencié de cette fonction de sélection selon les dispositions du chapitre VIII. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur conformément aux dispositions du chapitre VIII. § 4. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction : a) soit à un membre de son personnel temporaire, remplissant les conditions suivantes : 1° Etre titulaire, à titre temporaire, avant cet engagement d''une fonction comportant au moins une demi-charge dans un pouvoir organisateur de Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 l''enseignement subventionné du caractère concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de sélection à conférer et être porteur d''un titre de capacité conformément à l''article 101 du décret du 2 février 2007 fixant le statut des directeurs. b) soit à un membre du personnel titulaire à titre définitif depuis six ans au moins, d''une fonction de recrutement ou de sélection comportant au moins une demi- charge dans un centre psycho-médico-social subventionné et porteur d''un des titres visés à l''article 51, 4°. Le membre du personnel visé à l''alinéa 1er, point a), sera réputé remplir la condition exigée à l''article 51, 1° et 2° à l''expiration d''un délai de six années d''exercice temporaire de la fonction de sélection. Le membre du personnel qui s''est vu confier temporairement une fonction de sélection en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur conformément aux dispositions du chapitre VIII. Pendant la période durant laquelle il exerce temporairement la fonction de sélection, le membre du personnel visé à l''alinéa 1er, point b), reste titulaire de son emploi d''origine dans lequel il est engagé à titre définitif. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de sélection à un membre de son personnel répondant aux conditions de l''article 51, du § 1er et du § 2 du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel désigné temporairement dans une fonction de sélection en vertu de l''alinéa 1er, point b), est engagé à titre définitif dans ladite fonction au terme d''un délai de quatre années s''il remplit à ce moment la condition prescrite par l''article 51, 5°, et si le pouvoir organisateur ne l''a pas licencié de cette fonction de sélection selon les dispositions du chapitre VIII.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 152, 'Article 54ter. - Tout engagement temporaire dans un emploi de sélection est', 'Article 54ter. - Tout engagement temporaire dans un emploi de sélection est 
établi par écrit, conformément aux dispositions de l''article 31, à l''exception du 8°. 
 
Un engagement temporaire dans un emploi de sélection prend fin d''un commun 
accord, par décision du pouvoir organisateur, ou par application du chapitre VIII. 
Toutefois, la fin de l''année scolaire est sans incidence sur l''engagement temporaire 
dans un emploi de sélection. 
 
L''engagement temporaire dans une fonction de sélection n''est possible qu''après 
application par le pouvoir organisateur de la disposition de l''article 48, 1°.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 153, 'Article 54quater. - Tout membre du personnel peut renoncer à son engagement à', 'Article 54quater. - Tout membre du personnel peut renoncer à son engagement à 
titre définitif en vertu de l''article 51 dans les 720 jours qui suivent sa première entrée 
en fonction dans une fonction de sélection. Dans ce cas, il réintègre à titre définitif sa 
fonction d''origine. 
 
Le pouvoir organisateur peut, pour assurer la continuité dans la fonction de 
sélection ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter la 
réintégration du membre du personnel dans sa fonction d''origine de maximum 6 mois 
à dater de la demande du membre du personnel. » 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 154, 'Article 95. - A l''article 56 du même décret, un nouvel alinéa 3, rédigé comme', 'Article 95. - A l''article 56 du même décret, un nouvel alinéa 3, rédigé comme 
suit, est inséré : 
«Par dérogation aux alinéas précédents, le membre du personnel titulaire d''une 
fonction de promotion ne peut demander de mutation ou de changement d''affectation 
qu''après avoir exercé ses fonctions dans l''emploi qu''il occupe durant un délai de trois 
ans».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 155, 'Article 96. - Un article 58bis, rédigé comme suit, est ajouté au décret du 1er', 'Article 96. - Un article 58bis, rédigé comme suit, est ajouté au décret du 1er 
février 1993 précité : 
 
«Article 58bis. - § 1er. Le pouvoir organisateur qui doit engager à titre définitif un 
membre du personnel dans une fonction de promotion : 
1° consulte le directeur de l''établissement ainsi que, selon le cas, le conseil 
d''entreprise, l''instance de concertation locale, ou à défaut, la délégation syndicale sur 
le profil de la fonction de promotion à pourvoir; 
2° reçoit des membres du personnel toute information que ceux-ci jugent utile de 
lui communiquer en vue de l''engagement à titre définitif. 
 
§ 2. Le pouvoir organisateur après application du § 1er : 
1° arrête le profil de la fonction de promotion à pourvoir. Dans ce cadre, le 
pouvoir organisateur peut ajouter des critères complémentaires aux conditions 
d''engagement à titre définitif visées à l''article 59; 
2° lance un appel aux candidats selon les formes déterminées par le 
Gouvernement, sur proposition de la commission paritaire centrale. 
 
§ 3. Le pouvoir organisateur communique aux candidats les motifs de son choix 
du membre du personnel engagé à titre définitif dans la fonction de promotion eu 
égard aux critères fixés dans le profil de la fonction déterminé conformément au 
présent article.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 156, 'Article 97. - Les articles 59 à 61 du même décret sont remplacés par les', 'Article 97. - Les articles 59 à 61 du même décret sont remplacés par les 
dispositions suivantes : 
«Article 59. - Nul ne peut être engagé à titre définitif dans une fonction de 
promotion s''il ne répond au moment de l''engagement aux conditions suivantes : 
1° Etre titulaire depuis sept ans au moins au sein de l''enseignement 
subventionné du caractère concerné, d''une des fonctions de recrutement, de sélection 
ou de promotion de la catégorie en cause. Cette ancienneté est calculée conformément 
à l''article 29bis ; 
2° Etre titulaire, à titre définitif, avant cet engagement d''une fonction 
comportant au moins une demi-charge dans l''enseignement subventionné du caractère 
concerné; 
3° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction 
de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 
102 du décret du 2 février 2007 fixant le statut des directeurs. 
4° avoir suivi au préalable une formation spécifique sanctionnée par un certificat 
de fréquentation. 
5° avoir répondu à l''appel aux candidats visé à l''article 58bis. 
 
Les conditions fixées à l''alinéa 1er, 1°, 2°, 3° pour ce qui concerne l''ancienneté 
acquise à titre définitif, 4° et 5° ne sont pas requises pour la fonction de chef de 
travaux d''atelier.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 157, 'Article 60. - § 1er. Une fonction de promotion peut être confiée temporairement à', 'Article 60. - § 1er. Une fonction de promotion peut être confiée temporairement à 
un membre du personnel remplissant toutes les conditions de l''article 59 : 
1° si le titulaire de la fonction est temporairement absent; 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
2° dans le cas visé à l''article 57. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est engagé à titre définitif. 
 
§ 2. Par dérogation au § 1er, alinéa 1er, pour tout engagement d''une durée égale 
ou inférieure à 15 semaines, la condition visée à l''article 59, alinéa 1er, 4° et 5°, n''est 
pas exigée.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 158, 'Article 61. - Une fonction de promotion peut être confiée temporairement à un', 'Article 61. - Une fonction de promotion peut être confiée temporairement à un 
membre du personnel remplissant toutes les conditions de l''article 59 dans l''attente 
d''un engagement à titre définitif. 
 
Pendant cette période, le membre du personnel reste titulaire de l''emploi dans 
lequel il est engagé à titre définitif. 
 
Le membre du personnel visé à l''alinéa 1er est engagé à titre définitif dans la 
fonction de promotion au plus tard au terme d''un délai de deux ans si le pouvoir 
organisateur ne l''a pas licencié de cette fonction de promotion selon les dispositions du 
chapitre VIII.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 159, 'Article 61bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 1)', 'Article 61bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre du personnel remplissant toutes les conditions d''accès à la fonction de promotion visées à l''article 59, peut confier temporairement la fonction de promotion à un membre du personnel engagé à titre définitif remplissant les conditions suivantes : 1° Etre titulaire, à titre définitif, avant cet engagement d''une fonction comportant au moins une demi-charge dans l''enseignement subventionné du caractère concerné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de promotion, le membre du personnel reste titulaire de l''emploi dans lequel il est engagé à titre définitif, le cas échéant auprès de son pouvoir organisateur d''origine. Tout pouvoir organisateur qui démontre n''avoir qu''un seul membre du personnel répondant aux conditions de l''article 59, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur en vertu des dispositions du chapitre VIII. § 2. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre du personnel engagé à titre définitif conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre du personnel temporaire prioritaire remplissant les conditions suivantes : 1° Etre titulaire, à titre temporaire, avant cet engagement d''une fonction comportant au moins une demi-charge dans l''enseignement subventionné du caractère concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 59 et n''avoir qu''un seul membre du personnel répondant aux conditions du § 1er, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel visé à l''alinéa 1er ou à l''alinéa 2 sera réputé remplir la condition exigée à l''article 59, alinéa 1er, 1° à l''expiration d''un délai de six années d''exercice temporaire de la fonction de promotion. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur en vertu des dispositions du chapitre VIII. § 3. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre du personnel engagé à titre définitif ou temporaire prioritaire conformément aux dispositions qui précèdent, peut faire appel à un membre du personnel engagé à titre définitif dans l''enseignement subventionné et remplissant les conditions suivantes : 1° Etre titulaire, à titre définitif, avant cet engagement d''une fonction comportant au moins une demi-charge dans l''enseignement subventionné; 2° exercer à titre définitif une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. Pendant la période durant laquelle il exerce temporairement la fonction de promotion, le membre du personnel reste titulaire de l''emploi dans lequel il est engagé à titre définitif au sein de son pouvoir organisateur d''origine. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 59 et du § 1er du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 2, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 160, 'Article 61bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 2)', 'de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel désigné temporairement dans une fonction de promotion en vertu du présent paragraphe est engagé à titre définitif dans ladite fonction au terme d''un délai de six années s''il remplit à ce moment la condition prescrite par l''article 59, alinéa 1er, 4°, et si le pouvoir organisateur ne l''a pas licencié de cette fonction de promotion selon les dispositions du chapitre VIII. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être licencié de ladite fonction par le pouvoir organisateur en vertu des dispositions du chapitre VIII. § 4. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction : a) soit à un membre de son personnel temporaire, remplissant les conditions suivantes : 1° Etre titulaire, à titre temporaire, avant cet engagement d''une fonction comportant au moins une demi-charge dans l''enseignement subventionné du caractère concerné; 2° exercer à titre temporaire une ou plusieurs fonctions donnant accès à la fonction de promotion à conférer et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs. b) soit à un membre du personnel titulaire à titre définitif depuis six ans au moins, d''une fonction de recrutement ou de sélection comportant au moins une demi- charge dans un centre psycho-médico-social subventionné et porteur d''un des titres visés à l''article 59, alinéa 1er, 3°. Le membre du personnel temporaire désigné conformément à l''alinéa 1er, point a), sera réputé remplir la condition exigée à l''article 51, alinéa 1er, 1° et 2°, à l''expiration d''un délai de six années d''exercice temporaire de la fonction de promotion. Le membre du personnel qui s''est vu confier temporairement une fonction de promotion en application du présent paragraphe peut être déchargé de ladite fonction par le pouvoir organisateur. Pendant la période durant laquelle il exerce temporairement la fonction de promotion, le membre du personnel visé à l''alinéa 1er, point b), reste titulaire de son emploi d''origine dans lequel il est engagé à titre définitif. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de promotion à un membre de son personnel répondant aux conditions de l''article 59, du § 1er et du § 2 du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel. Le membre du personnel désigné temporairement dans une fonction de promotion en vertu de l''alinéa 1er, point b), est engagé à titre définitif dans ladite fonction au terme d''un délai de quatre années, s''il remplit à ce moment la condition prescrite par l''article 59, alinéa 1er, 4°, et si le pouvoir organisateur ne l''a pas licencié de cette fonction de promotion selon les dispositions du chapitre VIII. § 5. Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction de directeur d''un établissement de promotion sociale à un membre du personnel, conformément aux dispositions qui précèdent, peut confier temporairement ladite fonction à un membre du personnel remplissant les conditions suivantes : 1° être titulaire depuis sept ans au moins au sein de l''enseignement libre subventionné du caractère concerné, d''une des fonctions de recrutement, de sélection ou de promotion de la catégorie en cause. Cette ancienneté est calculée selon les modalités fixées à l''article 29bis du décret du 1er février 1993 précité; 2° être titulaire, à titre définitif, avant l''admission au stage, d''une ou plusieurs fonctions comportant au moins la moitié du nombre minimum d''heures requis pour former une fonction à prestations complètes dans l''enseignement libre subventionné du caractère concerné; 3° exercer à titre définitif une ou plusieurs fonctions dans l''enseignement Statuts /Personnel enseignant/CF/LS/OS/ Lois 31886 D. 02-02-2007 secondaire et/ou dans une Haute Ecole, et être porteur d''un titre de capacité conformément à l''article 102 du décret du 2 février 2007 fixant le statut des directeurs; Tout pouvoir organisateur qui démontre l''impossibilité de pouvoir confier temporairement une fonction');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 161, 'Article 61bis. - § 1er. Tout pouvoir organisateur qui démontre l''impossibilité de (partie 3)', 'de promotion à un membre de son personnel répondant aux conditions de l''article 59, du § 1er et du § 2 du présent article, et n''avoir qu''un seul membre du personnel répondant aux conditions du § 3, peut mettre en concurrence sa candidature avec celle de membres du personnel répondant aux conditions de l''alinéa 1er. Dans ce cas, il lance un nouvel appel aux candidats à destination des membres du personnel répondant aux conditions de l''alinéa 1er, sauf si lesdits membres du personnel étaient déjà visés par l''appel aux candidats originel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 162, 'Article 61ter. - Tout engagement temporaire dans un emploi de promotion est', 'Article 61ter. - Tout engagement temporaire dans un emploi de promotion est 
établi par écrit, conformément aux dispositions de l''article 31, à l''exception du 8°. 
 
Un engagement temporaire dans un emploi de promotion prend fin d''un commun 
accord, par décision du pouvoir organisateur, ou par application du chapitre VIII. 
Toutefois, la fin de l''année scolaire est sans incidence sur l''engagement temporaire 
dans un emploi de promotion. 
 
L''engagement temporaire dans une fonction de promotion n''est possible qu''après 
application par le pouvoir organisateur de la disposition de l''article 55, 1°.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 163, 'Article 61quater. - Tout membre du personnel peut renoncer à son engagement à', 'Article 61quater. - Tout membre du personnel peut renoncer à son engagement à 
titre définitif en vertu de l''article 59 dans les 720 jours qui suivent sa première entrée 
en fonction de sélection. Dans ce cas, il réintègre à titre définitif sa fonction d''origine. 
 
Le pouvoir organisateur peut, pour assurer la continuité dans la fonction de 
promotion ou afin de ne pas perturber la stabilité des équipes pédagogiques, reporter 
la réintégration du membre du personnel dans sa fonction d''origine de maximum six 
mois à dater de la demande du membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 164, 'Article 61quinquies. - Les articles 58bis à 61quater ne s''appliquent pas aux', 'Article 61quinquies. - Les articles 58bis à 61quater ne s''appliquent pas aux 
fonctions de promotion de directeur d''école maternelle, directeur d''école primaire, 
directeur d''école fondamentale, directeur de l''enseignement secondaire inférieur ou de 
préfet des études ou directeur, régies par le décret du 2 février 2007 fixant le statut 
des directeurs.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 165, 'Article 98. - Il est inséré un Chapitre Vbis libellé comme suit : / Article 61sexies. - § 1er. Le présent chapitre s''applique aux membres du personnel', 'Article 98. - Il est inséré un Chapitre Vbis libellé comme suit : 
 
«CHAPITRE Vbis. - De la lettre de mission et de l''évaluation de certaines fonctions de 
promotion et de sélection

Article 61sexies. - § 1er. Le présent chapitre s''applique aux membres du personnel 
titulaires d''une fonction de promotion ou de sélection telle que visée à l''article 4, 3° et 
à l''article 5, 1° et 2° du décret du 4 janvier 1999 relatif aux fonctions de promotion et 
de sélection dans l''enseignement de plein exercice. 
 
Elle s''applique également aux membres du personnel titulaires d''une fonction de 
sélection telle que visée à l''article 6ter, 6°, b) de l''arrêté de l''Exécutif de la 
Communauté française du 2 octobre 1968 déterminant et classant les fonctions des 
membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du 
personnel paramédical, du personnel psychologique et du personnel social des 
établissements d''enseignement préscolaire, primaire, spécialisé, moyen, technique, 
artistique, de promotion sociale et supérieur non universitaire de la Communauté 
française et les fonctions des membres du personnel du service d''inspection chargé de 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
la surveillance de ces établissements dans l''enseignement de plein exercice. 
 
§ 2. Pour l''application du présent chapitre, il faut entendre par «directeur» le 
membre du personnel titulaire, à quelque titre que ce soit, de la fonction de promotion 
de directeur d''école maternelle, de directeur d''école primaire, de directeur d''école 
fondamentale, de directeur de l''enseignement secondaire inférieur ou de préfet des 
études ou directeur, telles qu''énumérées aux articles 3 et 4, 1° et 2° du décret du 4 
janvier 1999 relatif aux fonctions de promotion et de sélection ou de la fonction de 
promotion de directeur d''établissement de promotion sociale telle que prévue à l''article 
6ter, 6°, a de l''arrêté de l''Exécutif de la Communauté française du 2 octobre 1968 
déterminant et classant les fonctions des membres du personnel directeur et 
enseignant, du personnel auxiliaire d''éducation, du personnel paramédical, du 
personnel psychologique et du personnel social des établissements d''enseignement 
préscolaire, primaire, spécialisé, moyen, technique, artistique, de promotion sociale et 
supérieur non universitaire de la Communauté française et les fonctions des membres 
du personnel du service d''inspection chargé de la surveillance de ces établissements 
dans l''enseignement de plein exercice.. 
 
Section Ire. - De la lettre de mission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 166, 'Article 61septies. - Dès l''entrée en fonction du membre du personnel visé à', 'Article 61septies. - Dès l''entrée en fonction du membre du personnel visé à 
l''article 61sexies du présent décret, le directeur lui confie une lettre de mission 
approuvée préalablement par le pouvoir organisateur. 
 
Celle-ci spécifie les missions du membre du personnel visé à l''article 61sexies et 
les priorités qui lui sont assignées, en fonction des besoins de l''établissement au sein 
duquel il est affecté et en fonction des objectifs contenus dans la lettre de mission que 
le directeur a lui-même reçu, conformément au chapitre III du décret du 2 février 2007 
fixant le statut des directeurs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 167, 'Article 61octies. - § 1er. La lettre de mission a une durée de six ans.', 'Article 61octies. - § 1er. La lettre de mission a une durée de six ans. 
 
§ 2. Le contenu de la lettre de mission peut être modifié avant son échéance, au 
plus tôt après deux ans, par le directeur, en raison de l''évolution des besoins et du 
fonctionnement de l''établissement. 
 
Par dérogation à l''alinéa 1er, le contenu de la lettre de mission peut être modifié 
avant son échéance, de commun accord entre le directeur et le membre du personnel 
visé à l''article 61sexies. 
 
La lettre de mission modifiée est soumise à l''approbation du pouvoir 
organisateur.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 168, 'Article 61nonies. - § 1er. Par dérogation à l''article 61septies, alinéa 1er, le', 'Article 61nonies. - § 1er. Par dérogation à l''article 61septies, alinéa 1er, le 
directeur, si besoin est et moyennant approbation préalable du pouvoir organisateur, 
peut confier une lettre de mission au membre du personnel engagé à titre temporaire 
dans l''exercice d''une fonction visée à l''article 61sexies du présent décret. 
 
Le directeur confie d''office une lettre de mission approuvée préalablement par le 
pouvoir organisateur au membre du personnel engagé à titre temporaire dans 
l''exercice d''une fonction visée à l''article 61sexies pour une durée égale ou supérieure à 
un an, ou dont la durée de la désignation a atteint au moins un an. 
 
§ 2. La lettre de mission visée au présent article peut consister dans la 
confirmation de la lettre de mission du membre du personnel visé à l''article 61sexies 
faisant l''objet d''un remplacement ou dans un nouveau document. 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007 
Section II. - De l''évaluation formative');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 169, 'Article 61decies. - Cette section s''applique au membre du personnel engagé à', 'Article 61decies. - Cette section s''applique au membre du personnel engagé à 
titre définitif. 
 
Elle s''applique également au membre du personnel engagé à titre temporaire 
dans l''exercice d''une fonction visée à l''article 61sexies pour une durée égale ou 
supérieur à un an. La dénomination «membre du personnel» visée à la présente 
section vise également ce membre du personnel.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 170, 'Article 61undecies. - Tous les cinq ans à dater de son engagement à titre définitif', 'Article 61undecies. - Tous les cinq ans à dater de son engagement à titre définitif 
ou de son engagement à titre temporaire, chaque membre du personnel fait l''objet 
d''une évaluation effectuée conjointement par le pouvoir organisateur et le directeur. 
 
Si ces derniers le jugent utile, ils peuvent procéder, plus tôt, à une évaluation du 
membre du personnel. 
 
Toutefois, sans préjudice de l''article 61terdecies, le membre du personnel ne peut 
faire l''objet de plus de deux évaluations par période de dix ans.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 171, 'Article 61duodecies. - L''évaluation se fonde sur l''exécution de la lettre de mission', 'Article 61duodecies. - L''évaluation se fonde sur l''exécution de la lettre de mission 
visée à la section I du présent chapitre et sur la mise en pratique des compétences 
acquises dans le cadre des formations visées par l''article 51, § 1er, 5° du présent décret 
en ce qui concerne les fonctions de sélection et à l''article 59, § 1er, 4° du présent décret 
pour les fonctions de promotion. 
 
Elle tient compte du contexte global dans lequel est amené à évoluer le membre 
du personnel et des moyens qui sont mis à sa disposition. 
 
Le directeur motive sa décision au sens de l''article 3, § 11 du présent décret.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 172, 'Article 61terdecies. - En fonction de cette évaluation, le pouvoir organisateur et le', 'Article 61terdecies. - En fonction de cette évaluation, le pouvoir organisateur et le 
directeur conviennent avec le membre du personnel des améliorations à apporter. » 
 
TITRE IV. - De l''accès aux fonctions de sélection et de promotion dans 
l''enseignement subventionné 
 
Complété par D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 173, 'Article 99. - Pour l''application du présent titre, les niveaux de titres y', 'Article 99. - Pour l''application du présent titre, les niveaux de titres y 
mentionnés sont déterminés en référence aux articles 2 et 3 de l''arrêté de l''Exécutif de 
la Communauté française du 22 avril 1969 fixant les titres requis des membres du 
personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel 
paramédical des établissements d''enseignement gardien, primaire, spécialisé, moyen, 
technique, artistique et normal de l''Etat et des internats dépendant de ces 
établissements et en vertu du chapitre 4 du décret du 11 avril 2014. 
 
Toutefois, les titres du niveau supérieur du premier degré, de candidat, de cours 
normaux 
techniques 
moyens, 
d''instituteur 
primaire, 
d''instituteur 
gardien, 
d''instituteur maternel, d''instituteur préscolaire et d''éducateur spécialisé visés à 
l''article 2, point 3, b), c), e), h), i) et j) de l''arrêté susmentionné n''entrent en ligne de 
compte que pour autant qu''ils soient spécifiquement mentionnés. 
 
Complété par D. 17-10-2013 ; D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 174, 'Article 100. - Pour l''application du présent titre, il y a lieu d''entendre par «titre', 'Article 100. - Pour l''application du présent titre, il y a lieu d''entendre par «titre 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
