Modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 176, 'Article 102. - Les titres de capacité et les fonctions visés à l’article 50, § 1er, 2° et', 'Article 102. - Les titres de capacité et les fonctions visés à l’article 50, § 1er, 2° et 
