qui suit (voir tableau II), sont ceux et celles figurant en regard de ladite fonction dans 
les colonnes 2 et 3 du même tableau. 
 
Statuts /Personnel enseignant/CF/LS/OS/ 
 
Lois 31886 
 
    D. 02-02-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 177, 'Article 103. - A l''article 2 de l''arrêté royal du 17 mars 1967 fixant les titres de', 'Article 103. - A l''article 2 de l''arrêté royal du 17 mars 1967 fixant les titres de 
capacité jugés suffisants pour les membres du personnel des établissements libres 
d''enseignement moyen et normal, sont apportées les modifications suivantes : 
a) au point 1, a), les mots «directeur, sous-directeur et» sont supprimés; 
b) au point 3, les mots «directeur, sous-directeur et» sont supprimés.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 178, 'Article 104. - A l''arrêté royal du 20 juin 1975 relatif aux titres jugés suffisants', 'Article 104. - A l''arrêté royal du 20 juin 1975 relatif aux titres jugés suffisants 
dans l''enseignement gardien et primaire, les modifications suivantes sont apportées : 
1° La section II du chapitre II est supprimée. 
2° Le § 1er de l''article 13 est remplacé comme suit : 
«La subvention-traitement du membre du personnel exerçant une fonction de 
promotion est calculée d''après les modalités prévues dans la présente section.» 
3° Le § 2 de l''article 13 est supprimé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 179, 'Article 105. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975', 'Article 105. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975 
relatif aux titres jugés suffisants dans les établissements d''enseignement 
subventionnés d''enseignement technique et d''enseignement professionnel secondaire 
de plein exercice et de promotion sociale sont supprimés.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 180, 'Article 106. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975', 'Article 106. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975 
relatif aux titres jugés suffisants dans l''enseignement secondaire dispensé dans les 
établissements d''enseignement moyen ou d''enseignement normal officiels sont 
supprimés.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('31886', 181, 'Article 107. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975', 'Article 107. - Les articles 12, § 1er et 13, § 1er de l''arrêté royal du 30 juillet 1975 
relatif aux titres suffisants dans l''enseignement secondaire dispensé dans les 
établissements 
libres 
