INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 9, 'Article 3. - § 1er.1 [Les services de l''Etat à gestion séparée de l''enseignement de (partie 6)', 'à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6609 % d''augmentation; - de la classe numérotée 20, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6623 % d''augmentation; b) 0,6062 % pour les écoles fondamentales, à l''exception des implantations : - des classes numérotées de 1 à 3a, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6001 % d''augmentation; - de la classe numérotée 13, conformément à l''article 4, alinéa 5, du décret du 30 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 avril 2009 précité qui bénéficieront de 0,6093 % d''augmentation; - de la classe numérotée 14, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6106 % d''augmentation; - de la classe numérotée 15, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6119 % d''augmentation; - de la classe numérotée 16, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6132 % d''augmentation; - de la classe numérotée 17, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6145 % d''augmentation; - de la classe numérotée 18, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6158 % d''augmentation; - de la classe numérotée 19, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6172 % d''augmentation; - de la classe numérotée 20, conformément à l''article 4, alinéa 5, du décret du 30 avril 2009 précité qui bénéficieront de 0,6185 % d''augmentation. Inséré par D. 14-12-2022 [16° de 0,473% de 2023 à 2024, à l''exception des dotations forfaitaires visées à l''alinéa 5, 17°.]4 Complémentairement aux augmentations visées à l''alinéa 7, les dotations relatives à l''enseignement maternel et primaire ordinaire sont augmentées de 11,58 EUR en 2003, 2004 et 2005, et de 13,21 EUR en 2006. Ces majorations sont fixées à l''indice 88,63 de l''indice général des prix à la consommation en base 2004. Elles sont indexées annuellement, comme indiqué ci-dessous : a) jusque et y compris l''année civile 2011, sur l''indice général des prix à la consommation de janvier en base 2004; b) pour l''année civile 2012, sur base du rapport 119,03/115,66 (indice général des prix à la consommation de janvier 2011, en base 2004); c) pour l''année civile 2013, en appliquant aux augmentations de l''année 2012 une indexation de 0 %; [modifié par D. 18-12-2013] d) pour l''année civile 2014, en appliquant aux montants de l''année civile 2013, une indexation égale au rapport entre l''indice général des prix à la consommation de janvier 2014 et l''indice général des prix à la consommation de janvier 2013. [Remplacé par D. 12-07-2012 ; modifié par D. 17-07-2013 ; remplacé par D. 17-12-2014] e) pour les années civiles 2015 et 2016, en appliquant aux montants de l''année civile 2014, une indexation de 0 %; [inséré par D. 17-12-2014] f) à partir de l''année civile 2017, en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente. [Inséré par D. 17- 12-2014] [g) pour l''année civile 2026, en appliquant aux dotations forfaitaires de l''année civile 2025, une indexation de 0 %.]5 [Pour les Ecoles supérieures des Arts, par étudiant régulièrement inscrit et finançable [tel qu''arrêté au 15 juin de l''année qui précède]6, il est attribué une dotation forfaitaire de fonctionnement déterminée par domaine et correspondant aux montants suivants : - domaine « les arts plastiques, visuels et de l''espace » : 1.466,00 EUR ; - domaine « la musique » : 1.466,00 EUR ; - domaine « le théâtre et les arts de la parole » : 1.375,00 EUR ; - domaine « les arts du spectacle et technique de diffusion et de communication » : 2.750,00 EUR ; 4remplacé par le D. 16-07-2025 5Inséré par le D. 17-12-2025 6inséré par le D. 11-12-2024 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 - domaine « la danse » : 1.375,00 EUR. Les montants visés à l''alinéa 1er sont indexés en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente]7. [A partir de l''année 2025, les montants des dotations forfaitaires relatives à l''enseignement fondamental et l''enseignement secondaire ordinaire et spécialisé, obtenus en application des alinéas précédents, sont réduits cumulativement d''un point de pourcentage par an jusqu''à l''année 2034 incluse.]8 [A partir de l''année 2026, sans préjudice de l''alinéa 1er, dans l''enseignement fondamental ordinaire et spécialisé, l''accès aux dotations de fonctionnement est conditionné par la mise à la disposition des élèves, gratuitement, par le Pouvoir');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 10, 'Article 3. - § 1er.1 [Les services de l''Etat à gestion séparée de l''enseignement de (partie 7)', 'organisateur, dans le cadre de ses dotations, de fournitures scolaires définies comme étant tous les matériels nécessaires à l''atteinte des savoirs, savoir-faire et compétences définis dans le référentiel de compétences initiales et les référentiels du tronc commun. Les dotations de fonctionnement peuvent également couvrir les frais scolaires liés à l''organisation d''activités pédagogiques ou de séjours pédagogiques avec nuitée(s) des élèves.]9 [Conformément au principe d''autonomie, le Pouvoir organisateur organise librement l''accès gratuit à ces fournitures, en fonction de sa réalité de terrain et de ses priorités pédagogiques.]10 [Au-delà des moyens visés ci-avant, il est, dans le cadre de l''alinéa précédent, octroyé : a. pour l''enseignement maternel ordinaire et spécialisé, le montant forfaitaire de 20,46 euros par élève. Il est calculé sur la base du nombre d''élèves régulièrement inscrits dans l''école à la date du 15 janvier de l''année en cours ; b. pour l''enseignement primaire ordinaire et spécialisé, le montant forfaitaire de 24,52 euros par élève. Il est calculé sur la base du nombre d''élèves régulièrement inscrits dans l''école à la date du 15 janvier de l''année en cours.]11 [A partir de l''année 2026, une dotation forfaitaire complémentaire de 54,2 EUR par élève est octroyée pour l''enseignement fondamental spécialisé.]12 [A partir de l''année 2027, les montants visés aux deux alinéas précédents sont indexés en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente.]13 Modifié par D. 18-12-2013 ; D. 11-4-2014(1) ; D. 17-12-2014 ; D.14-07-2015; D. 20-12-2017 § 3bis. [« Les [établissements d’enseignement pour adultes] et les Ecoles supérieures des Arts reçoivent 75% de la dotation forfaitaire établie conformément au §3. Les établissements d''enseignement fondamental, d''enseignement secondaire 7 Ajouté par D. 19-10-2023 8Inséré par le D. 11-12-2024 9Inséré par le D. 17-12-2025 10Inséré par le D. 17-12-2025 11Inséré par le D. 17-12-2025 12Inséré par le D. 17-12-2025 13Inséré par le D. 17-12-2025 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 ordinaire et spécialisé reçoivent 74% de la dotation forfaitaire établie conformément au §3.]14 Pour l''enseignement fondamental et l''enseignement secondaire ordinaires et spécialisés, une partie du solde est répartie par application d''un mécanisme de différenciation conformément au décret du 28 avril 2004 relatif à la différenciation du financement des établissements d''enseignement fondamental et secondaire ordinaires et spécialisés et le reste, augmenté du prélèvement de 14 % visé à l''article 18, § 1er, du décret du 12 juillet 2001 visant à améliorer les conditions matérielles des établissements de l''enseignement fondamental et secondaire est réparti par le Gouvernement selon la procédure et les critères fixés à l''alinéa 2 entre l''ensemble des établissements d''enseignement fondamental et secondaire ordinaires et spécialisés. Pour l''enseignement de promotion sociale [d''une part et les Ecoles supérieures des Arts d''autre part,]15 le solde est réparti par [le pouvoir organisateur]16 selon la procédure et les critères fixés à l''alinéa 2 entre l''ensemble des établissements […]17. [Pour les répartitions visées à l''alinéa 1er, le pouvoir organisateur se base sur un ou plusieurs des critères suivants :]18 a) le nombre ou la situation particulière des membres du personnel ouvrier ou de maîtrise; b) les besoins énergétiques; c) la spécificité de certaines options nécessitant des moyens de fonctionnement particulièrement importants; d) des locaux et/ou superficies surdimensionnés par rapport à la population scolaire; e) la situation budgétaire et/ou financière; f) des situations ponctuelles relevant de circonstances exceptionnelles ou de force majeure. Par dérogation à l''alinéa 1er : a) en 2014, chaque établissement reçoit 70,95 % de la dotation forfaitaire établie conformément au § 3 et 4,05 % restent acquis au Trésor; b) en 2015, chaque établissement reçoit 70,33 % de la dotation forfaitaire établie conformément au § 3 et 4,67 % restent acquis au Trésor; [remplacé par D. 14-07-2015] c) en 2016, chaque établissement reçoit 72,31 % de la dotation forfaitaire établie conformément au § 3 et 2,69 % restent acquis au Trésor; d) en 2017, chaque établissement reçoit 73,66 % de la dotation forfaitaire établie conformément au § 3 et 1,34 % restent acquis au Trésor. [Alinéa remplacé par D. 17-12-2014] Alinéas insérés par D. 20-12-2017 Par dérogation à l''alinéa 1er, un prélèvement correspondant à 80% de l''économie estimée dans le cadre du marché public d''achat groupé d''énergie est effectué, pour chaque établissement concerné, par nouvelle répartition de crédits sur les masses globales des dotations : a) Des CPMS; b) Des centres de dépaysement et de plein air, les centres de formation et d''auto- formation, le centre horticole de Gemblo');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 11, 'Article 3. - § 1er.1 [Les services de l''Etat à gestion séparée de l''enseignement de (partie 8)', 'et le centre de Strée; c) Des établissements d''enseignement fondamental, y compris les internats; d) Des établissements d''enseignement secondaire, y compris les internats; e) Des établissements d''enseignement spécialisé, y compris les internats; f) Des [établissements d''enseignement pour adultes]; g) Des établissements supérieurs des arts. 14Remplacé par le D. 11-12-2024 15 Inséré par D. 19-10-2023 16 Remplacé par D. 19-10-2023 17 Supprimé par D. 19-10-2023 18 Remplacé par D. 19-10-2023 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 Le montant prélevé, visé à l''alinéa précédent, est inscrit au Fonds des bâtiments scolaires du réseau organisé par la FWB en vue de réaliser des investissements économiseurs d''énergie dans les établissements participant au marché groupé. Les modalités du prélèvement, visé à l''alinéa 4, sont déterminées par le gouvernement, en tenant compte de l''entrée progressive des établissements scolaires dans le marché groupé d''énergie. Il est prélevé un montant de 20.573,18 EUR par membre du personnel ouvrier ou de maîtrise, en ce compris les préparateurs, nommés à titre définitif et affectés à l''établissement. Ce montant est réduit à due concurrence au prorata de la charge exercée en cas de nomination à temps partiel. Ce montant est réduit à due concurrence en cas de réduction totale ou partielle des prestations, d''absence ou de maladie de plus d''un mois du membre du personnel pendant l''année civile en cours. Ce montant est indexé annuellement sur l''indice des prix à la consommation défini par l''arrêté royal du 24 décembre 1993 portant exécution de la loi du 6 janvier 1989 de sauvegarde de la compétitivité du pays. [A partir du 1er janvier 2025, il est prélevé, selon les mêmes dispositions que l''alinéa précédent, un montant complémentaire correspondant à une moitié de la différence entre le coût annuel moyen d''un membre du personnel ouvrier ou de maîtrise admis au stage ou nommé à titre définitif et le montant de l''alinéa précédent. Le coût annuel moyen est établi en divisant le coût annuel global de l''année précédente des personnels ouvriers ou de maîtrise des établissements de l''Enseignement organisé par la Communauté française en stage ou nommés à titre définitif, en ce compris les préparateurs, par le nombre annuel moyen d''équivalents temps plein qu''ils ont représenté au cours de la même année pour l''ensemble des établissements. Il est prélevé, en 2026, une moitié complémentaire.]19 Lorsqu''un établissement utilise les locaux affectés à titre principal à un autre établissement, les chefs d''établissement concluent une convention d''utilisation des locaux qui répartit les charges proportionnellement à l''occupation. Lorsque les chefs d''établissement échouent à conclure une telle convention, celle-ci est établie par l''administration. Chaque établissement peut conclure des conventions visant à disposer de locaux complémentaires, notamment pour les activités sportives et d''éducation physique. Nul ne peut cependant imposer une telle convention à un établissement si celui-ci, par la voix de son chef d''établissement, en estime le coût mis à sa charge excessif par rapport à l''usage qu''il en retire. Toute convention contraire au présent alinéa sera réputée nulle douze mois après l''entrée en vigueur du présent décret. Chaque établissement peut autoriser l''usage de ses locaux par des associations non commerciales, en particulier culturelles ou sportives, pour autant que l''usage que celles-ci en font ne nuise ni à la bonne organisation, ni au renom, ni à la neutralité, ni aux intérêts matériels de l''établissement. Les bénéfices éventuels de ces mises à disposition sont ajoutés à la dotation globale de l''établissement. Information en est donnée à l''Administration. Le fait de disposer de tels bénéfices ne limite en rien le droit de l''établissement à bénéficier de la partie fixe de la dotation visée au § 3. § 3ter. Le chef d''établissement informe le comité de concertation de base de l''utilisation de la dotation visée à l''alinéa 1er du paragraphe 1er et permet, sur 19Les alinéas 8 et 9, tels qu''insérés par le décret du 18 janvier 2024, ont été remplacés par cet alinéa unique lui-même inséré par D.-programme du 16 juillet 2025 portant diverses dispositions relatives à l''enseignement, aux bâtiments scolaires et aux relations intra-belges. Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 demande de cette instance, la consultation des justifications probantes. L''information visée à l''alinéa précédent comprend notamment la part de la dotation qui est consacrée au matériel pédagogique. [inséré par D. 04-02-2016] § 3quater. Complémentairement aux dotations visées au § 3, à l''occasion de l''ouverture d''un établissement d''enseignement spécialisé, d''un établissement d''enseignement secondaire ordinaire ou d''un établissement ou implantation d''enseignement maternel, primaire ou fondamental ordinaire, une prime unique est octroyée à l''établissement/l''implantation concerné(e) pour la prise en charge de se');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 12, 'Article 3. - § 1er.1 [Les services de l''Etat à gestion séparée de l''enseignement de (partie 9)', 'frais de fonctionnement. L''octroi de cette prime, pour l''enseignement ordinaire, est conditionné au fait que l''établissement concerné soit situé dans une zone en tension démographique au sens de l''article 6, § 2, alinéa 2, du décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice et de l''article 2bis, alinéa 2, du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement. Cette prime peut être sollicitée auprès des Services du Gouvernement dès que le Gouvernement s''est prononcé sur la création de l''école et, au plus tard, avant le 1er octobre de l''année d''ouverture. Le montant de cette prime est fixé sur la base du nombre de places que l''établissement déclare ouvrir à la première rentrée scolaire, multiplié par la dotation forfaitaire par élève. Le Gouvernement fixe le modèle par lequel l''établissement introduit cette déclaration. Les Services du Gouvernement sont habilités à vérifier la pertinence du nombre de places déclarées eu égard aux capacités réelles de l''infrastructure prévue. En cas de discordance, le Gouvernement peut adapter le montant de la prime aux capacités réelles. [inséré par D. 12-12-2018] § 4. A partir de l''année scolaire 1981-1982 au cycle secondaire inférieur et à partir de 1983-1984 au cycle secondaire supérieur de l''enseignement de type II, tel que défini ci-dessus, aucune nouvelle section ou année d''études n''est créée ou subventionnée par l''Etat. Par dérogation à l''alinéa précédent, à partir de l''année scolaire 1983-1984, des sections de haute fréquence peuvent être créées ou subventionnées dans un établissement d''enseignement secondaire de type II appartenant à un centre d''enseignement et qui organise progressivement l''enseignement secondaire de type I, selon les dispositions du chapitre II de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire : 1° dans les années de perfectionnement ou de spécialisation des cycles inférieur et supérieur ; 2° dans le cycle supérieur. Par dérogation aux alinéas 1er et 2, de nouvelles sections de haute fréquence du cycle supérieur de l''enseignement secondaire professionnel ainsi que des septièmes années de l''enseignement secondaire professionnel peuvent être créées ou subventionnées par l''Etat, à partir de l''année scolaire 1987-1988, dans un établissement d''enseignement secondaire de type II appartenant à un centre d''enseignement. Remplacé par D. 09-07-2020 § 5. - Le calcul des dotations et subventions de fonctionnement des écoles, tel que Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 fixé par le présent article, prend en compte : - 88,6 % des élèves de l''enseignement maternel ordinaire, organisé et subventionné par la Communauté française qui ne sont pas soumis à l''obligation scolaire, régulièrement inscrits à la date du 15 janvier; - 100% des élèves de l''enseignement maternel ordinaire, organisé et subventionné par la Communauté française en âge d''obligation scolaire. Modifié par L. 11-07-1973; L. 14-07-1975; A.R. n°468 du 09-10-1986; D. 27-10-1994 ; D. 17-12-2003 Articles 4 à 6. – […] Abrogés par D. 03-05-2019 (code)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 13, 'Article 7. - Un arrêté royal détermine de manière uniforme le régime des congés', 'Article 7. - Un arrêté royal détermine de manière uniforme le régime des congés 
