INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 16, 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, (partie 1)', 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, selon le cas, l''article 3 et les articles 32 et 34 de la présente loi. § 1bis. Le produit de ce droit d''inscription est déduit de la première tranche de subventions de fonctionnement accordées aux établissements concernés. Pour l''année scolaire 1990-1991, ce droit est fixé à 124 EUR. Il est ramené à 62 EUR pour les bénéficiaires d''allocations d''études. § 2. Un minerval est imposé aux étudiants des établissements d''enseignement supérieur de plein exercice de type court et de type long. Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 Sans que ces montants ne puissent dépasser les plafonds visés à l''alinéa 14, le Gouvernement fixe le montant de ce minerval: 1° dans l''enseignement supérieur de type court, entre 124 EUR et 161 EUR ; 2° (…) 3° dans l''enseignement supérieur de type long, entre 248 EUR et 372 EUR ; 4° à 50 EUR pour l''inscription à une agrégation de l''enseignement secondaire supérieur ou à une épreuve complémentaire. En ce qui concerne les étudiants bénéficiant d''une allocation octroyée par le service d''allocations d''études de la Communauté française en vertu de la loi du 19 juillet 1971 relative à l''octroi d''allocations et de prêts d''études et du décret du 7 novembre 1983 réglant pour la Communauté française les allocations et les prêts d''études coordonné le 7 novembre 1983, ainsi que les étudiants titulaires d''une attestation de boursier délivrée par l''administration générale de la Coopération au Développement, ces montants sont ramenés à zéro euro tant dans l''enseignement supérieur de type court que dans l''enseignement supérieur de type long. En outre, pour les étudiants visés par le présent alinéa, il ne peut être prélevé aucun droit complémentaire et aucun frais apprécié au coût réel. Pour les étudiants qui ne sont pas visés à l''alinéa 3, ces droits complémentaires ne peuvent excéder le montant de 422 euros pour l''enseignement supérieur de type long et de 282 euros pour l''enseignement supérieur de type court. En outre, ces droits complémentaires ne peuvent excéder les montants imposés par les établissements pour l''année académique 2004-2005. Les commissaires du Gouvernement vérifient le respect de la présente disposition. Les plafonds fixés à l''alinéa 4 sont diminués chaque année académique de dix pour cent du montant initial. Pour les étudiants de condition modeste, ces plafonds sont diminués chaque année académique de vingt pour cent du montant initial. Le Gouvernement définit ce qu''il y a lieu d''entendre par étudiant de condition modeste. Pour les étudiants qui ne sont pas visés à l''alinéa 3, qui demandent à être inscrits dans une haute école et pour lesquels l''article 8 du décret du 9 septembre 1996 relatif au financement des hautes écoles organisées ou subventionnées par la Communauté française s''applique, il ne peut y avoir de différence de traitement par rapport aux étudiants demandant leur inscription dans une même catégorie de la même haute école, qui ne sont pas visés à l''alinéa 3 et pour lesquels l''article 8 du décret du 9 septembre 1996 précité ne s''applique pas. Pour les étudiants qui ne sont pas visés à l''alinéa 3, qui demandent à être inscrits dans un établissement d''enseignement supérieur artistique, visé à l''article 6, § 1er, du décret du 5 août 1995 portant diverses mesures en matière d''enseignement supérieur et pour lesquels l''article 9 du décret du 5 août 1995 précité s''applique, il ne peut y avoir de différence de traitement par rapport aux étudiants demandant leur inscription dans une même section du même établissement d''enseignement artistique supérieur ou supérieur artistique visé à l''alinéa 6, § 1er, du décret du 5 août 1995 précité, qui ne sont pas visés à l''article 3 et pour lesquels l''article 9 du décret du 5 août 1995 précité ne s''applique pas. Les montants visés au présent paragraphe sont liés à l''indice des prix à la consommation, selon la formule suivante: Montant de base x indice du mois de novembre précédant l''ouverture de l''année académique concernée Indice de novembre 1991 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 L''Exécutif fixe le mode de recouvrement du minerval. A la fin exclusive de calculer le montant des allocations complémentaires visées à l''article 21sexies du décret du 9 septembre 1996 relatif au financement des Hautes Ecoles organisées ou subventionnées par la Communauté française et à l''article 57bis du décret du 20 décembre 2001 fixant les règles spécifiques à l''Enseignement supérieur des Arts (organisation, financement, encadrement, statut des personnels, droits et devoirs des étudiants), pour l''année académique 2013 -2014, les montants visés au présent paragraphe sont indexés en fonction de l''indice des prix à la consommation, selon la formule suivante : Montant de base X Indice de novembre 2011/Indice de novembre 1991. A la fin exclusive de calculer le montant des allocations complémentaires visées à l''article 21sexies du décret du 9 septembr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 17, 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, (partie 2)', '1996 relatif au financement des Hautes Ecoles organisées ou subventionnées par la Communauté française et à l''article 57bis du décret du 20 décembre 2001 fixant les règles spécifiques à l''Enseignement supérieur des Arts (organisation, financement, encadrement, statut des personnels, droits et devoirs des étudiants), à partir de l''année académique 2014 -2015, les montants visés au présent paragraphe sont indexés annuellement en fonction de l''indice des prix à la consommation, selon la formule suivante : Montant de base tel qu''indexé pour l''année 2013-2014 X Indice de novembre précédant l''ouverture de l''année académique concernée/Indice de novembre 2012. [inséré par D. 17-07-2013] […]20 Pour l''année académique 2006-2007 et les années académiques suivantes, le Gouvernement fixe, respectivement, pour les Hautes Ecoles, les Ecoles supérieures des Arts et les Instituts supérieurs d''Architecture la liste des frais appréciés au coût réel afférents aux biens et services fournis aux étudiants qui ne sont pas considérés comme perception d''un droit complémentaire. Ces frais sont mentionnés dans le règlement des études propre à chaque établissement. La liste des frais mentionnés dans le règlement des études, visée à l''alinéa précédent, est établie sur la base de l''avis conforme d''une commission de concertation créée au sein de chaque établissement et composée de représentants de la direction de l''établissement, de membres du personnel et de représentants des étudiants. Le Gouvernement peut fixer les règles de composition et de fonctionnement de cette commission. Les frais non spécifiques à une formation sont mutualisés entre les étudiants d''un même type d''enseignement. Le montant total réclamé à l''étudiant en vertu de l''alinéa 2, de l''alinéa 4 et de l''alinéa 11, ne peut excéder le plafond de 593 euros. Pour les étudiants visés à l''alinéa 3, ce plafond est égal à zéro euro. Aucun montant ne peut donc être réclamé à ces étudiants. Pour les étudiants de condition modeste, ce plafond est identique à celui visé à l''article 39, § 2, alinéa 4, de la loi du 27 juillet 1971 sur le financement et le contrôle des institutions universitaires. Toutefois, pour les établissements qui, pour l''année académique 2005-2006, ont perçu un montant total supérieur aux plafonds fixés à l''alinéa précédent, ce plafond est égal, pour les années académiques 2006-2007 à 2010-2011, au montant total perçu 20 Abrogé par D. 19-10-2023 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 pour l''année académique 2005-2006, diminué chaque année, à partir de l''année académique 2007-2008, de 20 pour cent de la différence entre ce montant et les plafonds fixés à l''alinéa précédent. A partir de l''année académique 2010-2011, le présent alinéa n''est plus d''application pour les étudiants visés à l''alinéa 3 et les étudiants de condition modeste. Pour l''année académique 2010-2011, le Gouvernement arrête le montant qui aurait dû être perçu par les établissements en vertu du présent alinéa et fixe les modalités de répartition entre les établissements concernés au prorata de la dernière tranche qui aurait dû être perçue. A l''exception des étudiants visés à l''alinéa 3 et des étudiants de condition modeste, les deux alinéas précédents ne sont pas applicables aux Ecoles supérieures des Arts, ni aux Instituts supérieurs d''Architecture. Dans le cas d''une inscription à un programme régi par une convention de coopération pour l''organisation d''études telle que visée à l''article 26, § 7, du décret du 5 août 1995 fixant l''organisation générale de l''enseignement supérieur en hautes écoles, à l''article 28, § 5, du décret du 20 décembre 2001 fixant les règles spécifiques à l''Enseignement supérieur artistique organisé en Ecoles supérieures des Arts (organisation, financement, encadrement, statut des personnels, droits et devoirs des étudiants) ou à l''article 9bis, § 3, de la loi du 7 juillet 1970 relative à la structure générale de l''enseignement supérieur, les montants visés aux alinéas 2 à 5 sont réduits de façon proportionnelle au nombre de crédits réellement suivis dans l''institution rapporté à la somme des crédits réellement suivis au cours de l''année académique. Pour les étudiants de condition modeste, les montants visés à l''alinéa 2, 1° et 3° sont diminués de 78,65 EUR. Pour une année académique déterminée, le Gouvernement peut déroger à l''application de l''indexation prévue à l''alinéa 8. Cette dérogation est d''office appliquée pour les années académiques 2011-2012, 2012-2013, 2013-2014, 2014-2015 et 2015- 2016, 2016-2017 et à partir de l’année académique 2017-18. Dans ce cas, les montants prévus au présent paragraphe restent identiques à ceux de l''année académique qui précède. [Modifié par D. 10-12-2015 ; D. 19-7-2017] Lorsque, pour une année académique déterminée (N), il n''est plus dérogé à l''application de l''indexation prévue à l''alinéa 8, les montants visés au présent paragraphe sont indexés en fonction de l''indice des prix à la consommation selon la formule suivante :');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 18, 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, (partie 3)', '(Montant de l''année académique N - 1) x (indice du mois de novembre de l''année N - 1) : / (indice du mois de novembre de l''année N - 2) Ces montants sont arrondis à l''euro inférieur. § 2bis. Les montants perçus par une Ecole supérieure des Arts au titre de minerval visé au § 2, pour la totalité pour ce qui concerne le minerval payé par les étudiants qui s''inscrivent à des études classées dans l''enseignement de type court et la moitié pour ce qui concerne le minerval payé par les étudiants qui s''inscrivent dans des études classées dans l''enseignement supérieur de type long [, ainsi que les montants des droits d''inscription spécifiques perçus en application de l''article 105, §1er, alinéa 4 du décret du 07 novembre 2013,]21 sont déduits du montant que la Communauté verse, selon le cas, au titre de subvention de fonctionnement ou de dotation à l''Ecole supérieure des Arts concernée. § 2ter. Les montants perçus au titre de minerval visés au § 2 perçus par les 21 Remplacé par le D. 11-12-2024 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 institutions de type long de plein exercice organisées ou subventionnées par la Communauté française, sont versés, en partie, dans le patrimoine de l''institution et sont, entre autres, destinés au service social. L''Exécutif fixe la partie versée au patrimoine de l''institution. Cette partie doit représenter au moins 50% du montant perçu au titre de minerval par l''institution. Le présent paragraphe n''est pas applicable aux Ecoles supérieures des Arts. Remplacé par D. 29-11-2018 § 2ter-bis. Les montants perçus par une Haute Ecole à titre de minerval fixé au § 2 pour les étudiants qui s''inscrivent à des études classées dans l''enseignement supérieur de type court [, ainsi que les montants des droits d''inscription spécifiques perçus en application de l''article 105, §1er, alinéa 4, du décret du 07 novembre 2013,]22 pour les étudiants étrangers visés à l''article 3, § 3, du décret du 11 avril 2014 adaptant le financement des établissements d''enseignement supérieur à la nouvelle organisation des études, qui sont financés, sont déduits de l''allocation annuelle globale de la Haute Ecole concernée. Les paragraphes 2bis et 2ter du présent article ne sont pas applicables aux Hautes Ecoles. § 2quater. Les étudiants dont le minerval imposé au § 2 n''a pas été payé au plus tard le 1er février de l''année académique en cours, n''entrent pas en ligne de compte pour le financement. § 2quinquies. Les articles 1er et 2 de l''arrêté de l''Exécutif de la Communauté française du 13 août 1990 fixant le montant minimum et les conditions d''exonération du minerval imposé par l''article 12, § 2, de la loi du 29 mai 1959 sont abrogés. Modifié par D. 09-02-2017 ; D. 20-07-2022 ; D. 14-12-2022 § 3. Par année scolaire, le montant du droit d''inscription dans l''enseignement de promotion sociale est déterminé sur la totalité des périodes de cours de 50 minutes des sections, formations ou unités de formation auxquelles un étudiant s''inscrit et dont la date du premier dixième de la durée se situe durant ladite année scolaire. Modifié par D. 18-12-2013 ; remplacé par D. 10-12-2015 Ce droit d''inscription se calcule comme suit : 1. une partie fixe se montant, à partir du 1er septembre 2015, à 25 euros; 2. une partie calculée en fonction du nombre de périodes de 50 minutes sur laquelle porte l''inscription : a) dans l''[enseignement pour adultes de niveau secondaire]: - à partir du 1er septembre 2015 : 0,22 euro par période de 50 minutes jusqu''à la 800ème période. Au-delà, aucun droit d''inscription n''est perçu; b) dans l''[enseignement pour adultes de niveau supérieur]: - à partir du 1er septembre 2015 : 0,35 euro par période de 50 minutes jusqu''à la 800ème période. Au-delà, aucun droit d''inscription n''est perçu. Lorsqu''un étudiant s''inscrit simultanément dans des sections ou des unités de formation de l''enseignement secondaire et de l''enseignement supérieur de promotion sociale, pour déterminer le montant du droit d''inscription, les périodes du niveau secondaire sont prises en considération avant les périodes du niveau supérieur. Si des inscriptions dans les niveaux secondaire et supérieur sont réalisées dans 22Remplacé par le D. 11-12-2024 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 deux ou plusieurs établissements, la disposition visée à l''alinéa précédent s''applique au sein de chacun des établissements considérés, dans l''ordre chronologique dans lequel les inscriptions sont réalisées. Au-delà de 800 périodes, aucun droit d''inscription n''est perçu. Lorsqu''un étudiant s''inscrit simultanément dans deux établissements ou plus, la partie fixe du droit d''inscription est due dans l''établissement où la première inscription est effectuée. A partir du 1er septembre 2016, les montants fixés à l''alinéa 2, 1° et 2°, sont liés à l''indice des prix à la consommation. Ils sont adaptés annuellement en fonction de l''évolution de cet indice tel qu''il est fixé dans le courant du mois de janvier de la même année civile, pour aut');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 19, 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, (partie 4)', 'que l''indice des prix à la consommation de l''année N+1 soit supérieur à l''indice des prix à la consommation de l''année N. Les montants de la partie fixe et du tarif par période dans l''[enseignement pour adultes] sont liés à l''indice des prix à la consommation selon la formule suivante : DI (2015+N) = DI (2015) X Indice des prix à la consommation (2015+N) Indice des prix à la consommation (2015) Sont exemptés du droit d''inscription visé à l''alinéa 2, 1° et 2° : - Les mineurs, soumis à l''obligation scolaire; - les chômeurs complets indemnisés et les travailleurs à temps partiel bénéficiant de l''allocation de garantie de revenus; [remplacé par D. 14-12-2022] - les chômeurs complets indemnisés en formation professionnelle organisée ou subventionnée par le service de placement; [remplacé par D. 14-12-2022] - les demandeurs d''emploi inoccupés inscrits obligatoirement, les jeunes en stage d''insertion professionnelle, les demandeurs d''emploi en formation professionnelle, les demandeurs d''allocations et les demandeurs d''emploi sans revenu dont le conjoint ou la personne avec laquelle ledit demandeur vit en couple, également demandeur d''emploi ou d''allocations, bénéficie du taux cohabitant avec charge de famille; [inséré par D. 14-12-2022] - les demandeurs d''emplois inscrits dans des programmes d''aide à l''emploi à l''exclusion des personnes sous contrat ACS (agents contractuels subventionnés) ou APE (aides à la promotion de l''emploi); [inséré par D. 14-12-2022] - Les personnes en situation de handicap qui fournissent un document probant, c''est-à-dire toute preuve ou attestation délivrée par une administration publique compétente ou toute décision judiciaire reconnaissant un handicap, une invalidité, une maladie professionnelle, un accident de travail ou de droit commun ayant entraîné une incapacité permanente. Ces preuves et attestations sont établies par écrit ou sous toute autre forme imposée par l''organe chargé de les délivrer; [remplacé par D. 30-06-2016] - Les personnes qui bénéficient du revenu d''intégration sociale (RIS) ou d’une aide financière équivalente au revenu d’intégration sociale (ERIS) [remplacé par D. 09-02- 2017] - Les miliciens; - Les membres du personnel directeur, enseignant et auxiliaire d''éducation de l''enseignement organisé ou subventionné, pour lesquels la section, la formation ou l''unité de formation à laquelle ils s''inscrivent est reconnue dans le cadre de la formation continuée ou de la formation en cours de carrière des membres du personnel enseignant; - Les membres du personnel de l''enseignement organisé ou subventionné par la Communauté française, pour lesquels la section, la formation ou l''unité de formation considérée constitue un recyclage dans le cadre de leur(s) fonction(s) dans l''enseignement; - Les personnes soumises à une obligation imposée par une autorité publique ; [modifié par D. 20-07-2022] Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 - les personnes s''inscrivant dans les unités d''enseignement de français langue étrangère positionnées maximum au niveau A2 du Cadre européen commun de référence pour les langues ; [complété par D. 20-07-2022] - les personnes s''inscrivant dans les unités d''enseignement d''alphabétisation ainsi que dans les autres unités d''enseignement classées au niveau secondaire inférieur et dont le CEB ne constitue pas le titre tenant lieu de capacités préalables requises. [Complété par D. 20-07-2022] [- les étudiants qui suivent des unités de formation dans le cadre d’un programme d’études conjoint menant à une côdiplomation impliquant au moins un établissement d’enseignement supérieur de plein exercice en Communauté française identifié comme établissement référent dans la convention de codiplômation.]23 [- au cours des années académiques 2025-2026, 2026-2027 et 2027-2028, les élèves non visés à l’article 17, § 1er, 1°, a) et e) ainsi que 2°, a), b), et c) de l’arrêté royal du 29 juin 1984 relatif à l''organisation de l''enseignement secondaire dans la mesure où ils ne peuvent plus poursuivre leurs études dans l’enseignement secondaire de plein exercice ou en alternance, et à condition que ces élèves aient été inscrits dans l’enseignement secondaire de plein exercice ou en alternance au cours de l’année précédant leur inscription dans l’Enseignement pour Adultes et produisent une attestation relative à cette inscription émise par l’établissement d’enseignement secondaire de plein exercice ou en alternance concerné.]24 Le droit d''inscription est payé avant le premier dixième de la durée de la section, de la formation ou de l''unité de formation choisie. Les élèves et étudiants qui, sans en être exemptés, n''ont pas payé le droit d''inscription visé à l''alinéa 2, 1° et 2°, dans le délai prévu à l''alinéa précédent ne sont pas pris en considération pour le calcul de l''encadrement, pour l''ajustement de la dotation de périodes et pour le montant des crédits et subventions de fonctionnement. La somme des montants des droits d''inscription établis pour tous les');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 20, 'Article 12. - § 1er. L''Etat supporte les charges financières comme le prévoient, (partie 5)', 'élèves et étudiants repris aux documents annuels précisant la population scolaire au premier dixième de toutes les sections, formations ou unités de formations, dont le premier dixième de la durée de fonctionnement se situe durant l''année scolaire, constitue le droit d''inscription calculé pour l''établissement pour l''année scolaire. Les montants du droit d''inscription dû en vertu de l''alinéa 1er du présent paragraphe sont déduits des montants des crédits de fonctionnement des [établissements d’enseignement pour adultes] organisés par la Communauté française et des subventions de fonctionnement des [établissements d’enseignement pour adultes] subventionnés par la Communauté française. Lorsque les montants du droit d''inscription dû en vertu de l''alinéa 1er du présent paragraphe sont supérieurs aux montants des crédits de fonctionnement des [établissements d’enseignement pour adultes] organisés par la Communauté française ou des subventions de fonctionnement des [établissements d’enseignement pour adultes] subventionnés par la Communauté française, la différence entre les montants du droit d''inscription et les crédits ou subventions de fonctionnement est versée au budget des Voies et Moyens de la Communauté française. § 4. Un minerval direct ou indirect peut être perçu par les [établissements d’enseignement pour adultes]. 23 Ajouté par le décret du 9 novembre 2023 (qui entre en vigueur à partir de l’année scolaire 2024- 2025) 24Inséré par le D. 16-07-2025 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 § 5. Lors de son inscription dans une unité de formation ou section de l''[enseignement pour adultes], chaque étudiant doit être informé des montants respectifs du droit d''inscription, de l''éventuel droit d''inscription occupationnel, et du montant de l''éventuel minerval direct ou indirect propre à l''établissement. Ces montants respectifs doivent également être affichés dans un lieu accessible à l''ensemble des étudiants. Inséré par L. 11-07-1973 ; complété par D. 11-04-2014(2) ; D. 17-07-2020 ; modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 21, 'Article 12bis. - § 1er. Les statuts du personnel de l''enseignement de l''Etat et du (partie 1)', 'Article 12bis. - § 1er. Les statuts du personnel de l''enseignement de l''Etat et du personnel de l''enseignement subventionné garantissent la protection, en dehors de l''école, de la vie privée contre des décisions arbitraires du pouvoir organisateur. § 2. Par arrêté délibéré en Conseil des Ministres, après consultation du conseil général créé par le décret du 27 octobre 1994 pour ce qui concerne l’enseignement secondaire, le Roi fixe d''une manière uniforme pour tous les réseaux d''enseignement et pour tous les membres du personnel rémunérés ou subsidiés par l''Etat, les titres requis pour l''exercice des différentes fonctions et, à défaut de porteurs des titres requis, les titres jugés suffisants ainsi que, par type d''enseignement libre, l''équivalence de certains titres à caractère religieux ou idéologique avec les titres requis ou les titres jugés suffisants. (voir A.E. 22-04-69 - 02699) En cas de pénurie, dûment constatée suivant des modalités que le Roi fixe, de candidats porteurs des titres requis, de titres jugés suffisants ou de titres jugés équivalents, il peut être procédé au recrutement temporaire d''un candidat porteur d''autres titres. Ce recrutement est limité à la durée de l''année scolaire en cours. En cas de pénurie persistante, le recrutement est renouvelable annuellement, sans pouvoir aboutir à la nomination à titre définitif. Le présent alinéa ne s''applique qu''à l''enseignement supérieur de promotion sociale. [Inséré par D. 11-04-2014(2) ; modifié par D. 17-07-2020] § 3. Par arrêté délibéré en Conseil des Ministres, le Roi fixe d''une manière uniforme pour tous les réseaux d''enseignement subventionné et pour tous les membres du personnel subsidiés : a) les règles de base qui déterminent le recrutement, la nomination, la sélection et la promotion; b) les positions administratives et les règles de réaffectation des membres du personnel mis en disponibilité; c) le régime des congés; d) les incompatibilités essentielles communes; e) les devoirs fondamentaux communs. Ces dispositions statutaires seront, autant que faire se peut, identiques à celles de l''Etat. (voir D. 01-02-1993 - 17322 et D. 06-06-1994 - 18533) Inséré par D. 17-07-2020 ; modifié par D. 24-02-2022 § 4. Avant d''adopter de nouvelles dispositions législatives ou réglementaires limitant l''accès à une fonction des personnels de l''enseignement ou à son exercice ou avant de modifier de telles dispositions existantes, il est procédé à un examen de proportionnalité. Sont également soumises à l''examen de proportionnalité visé à l''alinéa 1er, les exigences spécifiques relatives à la prestation temporaire ou occasionnelle de services, prévues au titre II de la directive 2005/36/CE du Parlement européen et du Conseil du 7 septembre 2005 relative à la reconnaissance des qualifications professionnelles, Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 dont: - l''inscription temporaire automatique ou l''adhésion pro forma à une organisation professionnelle ou à un organisme professionnel, visés à l''article 6, premier alinéa, point a), de la directive 2005/36/CE précitée; - une déclaration préalable conformément à l''article 7, paragraphe 1, de la directive 2005/36/CE précitée, la fourniture de documents exigés conformément au paragraphe 2 dudit article ou toute autre exigence équivalente; - le versement d''une redevance ou des frais requis pour les procédures administratives, liés à l''accès à des professions réglementées ou à leur exercice, à la charge du prestataire de services. L''alinéa précédent ne s''applique pas aux mesures destinées à garantir le respect des conditions de travail et d''emploi appliquées conformément au droit de l''Union. Les modalités de l''examen de proportionnalité visé à l''alinéa 1er sont fixées par le Gouvernement en vue d''assurer la transposition de la directive 2018/958 du Parlement européen et du Conseil du 28 juin 2018 relative à un contrôle de proportionnalité avant l''adoption d''une nouvelle réglementation de professions. L''adoption des dispositions visées aux alinéas 1er et 2 est en outre précédée de la mise à disposition, selon les modalités définies par le Gouvernement, d''information à destination des citoyens, des bénéficiaires de services et des autres parties prenantes concernées, y compris celles qui ne sont pas des membres de la profession concernée. Toutes les parties concernées sont dûment associées et peuvent exprimer leur point de vue. Lorsque cela est pertinent et approprié, des consultations publiques sont menées. Par dérogation aux alinéas précédents, lorsque des exigences spécifiques concernant la réglementation d''une profession donnée sont établies dans un acte distinct de l''Union qui ne laisse pas aux Etats membres le choix de leur mode de transposition, les dispositions du présent article ne s''appliquent pas. Inséré par L. 11-07-1973');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 22, 'Article 12ter.', 'Article 12ter. 25- Par arrêté royal délibéré en Conseil des Ministres, le Roi fixe 
