INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 33, 'Article 32. (partie 1)', 'Article 32. 28- § 1er. Des subventions de fonctionnement annuelles et forfaitaires sont accordées pour couvrir les frais afférents au fonctionnement et à l''équipement de l''établissement et de l''internat, et à la distribution gratuite de manuels et de fournitures scolaires aux élèves soumis à l''obligation scolaire et à l''aide spécifique29 aux directions d''écoles maternelles, primaires et fondamentales. Toute location de bâtiments, locaux, mobilier, matériel et installations doit faire l''objet d''une convention écrite et les charges ne peuvent dépasser le prix normal pratiqué pour des biens analogues. En ce qui concerne les bâtiments, locaux, mobilier, matériel, et installations loués, seul l''entretien locatif peut être mis à charge des subventions de fonctionnement. § 2. Dans les limites des crédits budgétaires visés à l''alinéa suivant, le montant des subventions de fonctionnement par élève régulièrement inscrit est égal à 75 % des dotations forfaitaires fixées à l''article 3, § 3. L''augmentation des subventions de fonctionnement, hors plan de rattrapage de 28 N’est pas applicable aux Hautes Ecoles l''article 32 (D. 09-09-1996 – M.B. 15-10-1996, article 73). 29 Par «aide spécifique», il faut entendre toute forme de soutien mise en oeuvre dans le cadre de la gestion d''un établissement scolaire, à l''exception des tâches pédagogiques. (D. 20-07-2006 (2), art.73) Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 l''enseignement fondamental par l''article 56 du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement, et en tenant compte d''une hypothèse d''inflation de 1,7 % annuelle, doit s''inscrire dans les limites budgétaires suivantes et sans préjudice du § 3 : - pour l''année 2003 : 2 768 970,67 EUR; - pour l''année 2004 : 9 816 583,58 EUR; - pour l''année 2005 : 35 324 827,28 EUR; - pour l''année 2006 : 43 609 428,88 EUR; - pour l''année 2007 : 63 346 711,32 EUR; - pour l''année 2008 : 67 898 036,44 EUR; - pour l''année 2009 : 85.728.825,85 EUR; - pour l''année 2010 : 101.812.418,34 euro ; - pour l''année 2011 : 101.812.418,34 euro ; - pour l''année 2012 : 109.854.214,59 euro ; - pour l''année 2013 : 109.854.214,59 € ; - pour l''année 2014 : 109.854.214,59 euros. - pour l''année 2015: 109.854.214,59 €;[remplacé par D. 17-07-2013 ; D. 18-12-2013 ; D. 17- 12-2014] - pour l''année 2016: 112.362.597,54 €; [inséré par D. 17-12-2014] - pour l''année 2017: 114.870.980,49 €; à partir de l''année 2018: 117.379.363, 44 € Une subvention forfaitaire annuelle de 4.659,65 EUR est accordée aux écoles fondamentales ou secondaires ordinaires et spécialisé qui ont un internat et aux internats autonomes, qui répondent aux conditions de rationalisation et de programmation fixées par un arrêté royal délibéré en Conseil des Ministres; une subvention de fonctionnement de 139,79 EUR [par élève interne de l''enseignement fondamental ou secondaire ordinaire ou de l’enseignement pour adultes leur est en outre accordée.]30 (voir A.R. n°456 du 10-09-86 - 12376) Les montants visés à l’alinéa précédent sont majorés ou diminués : a) pour moitié31, en fonction de l''évolution de l''indice des prix à la consommation, dans les conditions fixées par la loi organisant le régime de liaison à l''indice des prix à la consommation; les montants ci-dessus sont liés à l''indice moyen des prix pour 1972; b) pour l''autre moitié, en fonction de l''évolution des gains horaires bruts par heure, tels qu''ils sont établis par la Banque Nationale de Belgique, dans les conditions fixées par arrêté royal; les taux ci-dessus sont liés à l''indice moyen de l''année 1972. (voir A.R. 26-09-74 - 01757) Par dérogation à l''alinéa 1er, le montant des subventions de fonctionnement accordé par élève régulier, hors enseignement universitaire, hors enseignement supérieur organisé dans les hautes écoles, est fixé pour l''année scolaire 1999-2000 au montant accordé pour l''année scolaire 1998-1999, tel qu''il a été établi sur la base de l''article 9 du décret-programme du 17 juillet 1998 portant diverses mesures concernant la gestion budgétaire, les fonds budgétaires, les bâtiments scolaires, l''enseignement et la promotion de la santé, augmenté de 1 %. Par dérogation à l''alinéa 1er, le montant des subventions de fonctionnement accordé par élève régulier, hors enseignement universitaire, hors enseignement supérieur 30Remplacé par le D. 16-07-2025 31 Pour les années 1976-1977 et 1977-1978, les mots "pour moitié" sont remplacés par les mots "pour 2/3" et les mots "pour l''autre moitié" par les mots "pour 1/3" (L.22-12- 77). Cette disposition reste d''application pour les années scolaires 1978-1979 (L.05-08- 78) et 1979-1980 (L.08-08-80). Pour chaque année scolaire suivante, le calcul se fait sur base de l''année scolaire précédente (donc du rapport 2/3 - 1/3). Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 organisé dans les hautes écoles, est fixé pour l''année scolaire 2000-2001 au montant accordé pour l''année s');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 34, 'Article 32. (partie 2)', '1999-2000, tel qu''il a été établi sur la base de l''article 2 du décret-programme du 23 décembre 1999 portant diverses mesures concernant les fonds budgétaires, l''enseignement, l''enfance et les fonds structurels, augmenté de 2,5 pour cent. Par dérogation à l''alinéa 1er, le montant des subventions de fonctionnement accordé par élève régulier […]32 dans l''enseignement secondaire artistique à horaire réduit est fixé, à partir de l''année 2003, au montant accordé pour l''année 2002, tel qu''il a été établi sur base de l''article 21, alinéa 2, du décret du 12 juillet 2001 visant à améliorer les conditions matérielles des établissements de l''enseignement fondamental et secondaire, et indexé comme indiqué ci-dessous : a) jusque et y compris l''année civile 2011, sur l''indice général des prix à la consommation de janvier en base 2004; b) pour l''année civile 2012, sur base du rapport 119,03/115,66 (indice général des prix à la consommation de janvier 2011, en base 2004); c) pour l''année civile 2013, en appliquant aux montants de l''année 2012 une indexation de 0 %; [modifié par D. 18-12-2013] d) pour l''année civile 2014, en appliquant aux montants de l''année civile 2013, une indexation égale au rapport entre l''indice général des prix à la consommation de janvier 2014 et l''indice général des prix à la consommation de janvier 2013. [remplacé par D. 17-07-2012 ; D. 17-12-2014] e) pour les années civiles 2015 et 2016, en appliquant aux montants de l''année civile 2014, une indexation de 0 %; [inséré par D. 17-12-2014] f) à partir de l''année civile 2017, en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente. [inséré par D. 17- 12-2014] A partir de l''année scolaire 2010-2011, le montant des subventions de fonctionnement des internats est fixé en fonction du montant accordé pour l''année scolaire précédente et indexé comme indiqué ci-dessous : a) pour l''année scolaire 2010-2011, sur l''indice général des prix à la consommation de janvier en base 2004; b) pour l''année civile 2012, sur base du rapport 119,03/115,66 (indice général des prix à la consommation de janvier 2011, en base 2004); c) pour l''année civile 2013, en appliquant aux montants de l''année 2012 une indexation de 0 %; [modifié par D. 18-12-2013] d) pour l''année civile 2014, en appliquant aux montants de l''année civile 2013, une indexation égale au rapport entre l''indice général des prix à la consommation de janvier 2014 et l''indice général des prix à la consommation de janvier 2013. [remplacé par D. 17-07-2012 ; D. 17-12-2014] e) pour les années civiles 2015 et 2016, en appliquant aux montants de l''année civile 2014, une indexation de 0 %; [inséré par D. 17-12-2014] f) à partir de l''année civile 2017, en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente. [inséré par D. 17- 12-2014] [g) pour l''année civile 2026, en appliquant aux montants de l''année civile 2025, une indexation de 0 %.]33 [Pour l''année 2025, pour l''enseignement fondamental et l''enseignement secondaire ordinaire et spécialisé, le pourcentage visé à l''alinéa 1er est augmenté de 1.52 point de pourcentage et porté à 76.52%. A partir de 2026, ce pourcentage est 32 Abrogé par D. 19-10-2023 33Inséré par le D. 17-12-2025 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 augmenté de 1.72 point de pourcentage par an pour atteindre 92% en 2034.]34 [A partir de l''année 2026, dans l''enseignement fondamental ordinaire et spécialisé, l''accès aux subventions de fonctionnement est conditionné par la mise à la disposition des élèves, gratuitement, par les Pouvoirs organisateurs, dans le cadre de leurs subventions, de fournitures scolaires définies comme étant tous les matériels nécessaires à l''atteinte des savoirs, savoir-faire et compétences définis dans le référentiel de compétences initiales et les référentiels du tronc commun. Les subventions de fonctionnement peuvent également couvrir les frais scolaires liés à l''organisation d''activités pédagogiques ou de séjours pédagogiques avec nuitée(s) des élèves.]35 [Conformément au principe d''autonomie, les Pouvoirs organisateurs organisent librement l''accès gratuit à ces fournitures, en fonction de leurs réalités de terrain et de leurs priorités pédagogiques.]36 [Par dérogation à l''alinéa 1er, il est, dans le cadre de l''alinéa précédent, octroyé : a. pour l''enseignement maternel ordinaire et spécialisé, le montant forfaitaire de 20,46 euros par élève. Il est calculé sur la base du nombre d''élèves régulièrement inscrits dans l''école à la date du 15 janvier de l''année en cours ; b. pour l''enseignement primaire ordinaire et spécialisé, le montant forfaitaire de 24,52 euros par élève. Il est calculé sur la base du nombre d''élèves régulièrement inscrits dans l''école à la d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 35, 'Article 32. (partie 3)', 'du 15 janvier de l''année en cours.]37 [A partir de l''année 2026, une subvention forfaitaire complémentaire de 54,2 EUR par élève est octroyée pour l''enseignement fondamental spécialisé.]38 [A partir de l''année 2027, les montants visés aux deux alinéas précédents sont indexés en appliquant aux montants de l''année civile précédente, le rapport entre l''indice général des prix à la consommation de janvier de l''année civile en cours et l''indice de janvier de l''année civile précédente.]39 Inséré par D. 04-02-2016 § 2bis. Le montant des subventions est calculé en fonction du nombre d''élèves régulièrement inscrits à la date du 15 janvier, sauf pour l''[enseignement pour adultes] de régime 1 où le nombre d''élèves pris en compte est la moyenne entre les nombres d''élèves réguliers au 1er et au 5e dixièmes de l''unité de formation. Par dérogation à l''alinéa précédent, l''élève qui fait l''objet d''une exclusion définitive après le 15 janvier n''est pas considéré comme régulièrement inscrit à la date du 15 janvier dans l''établissement qui l''a exclu, mais bien dans celui qui, le cas échéant, l''accueille après cette exclusion. L''établissement scolaire qui accueille un élève exclu après le 15 janvier en informe l''Administration au plus tard le 15 juillet suivant. A défaut, l''élève n''est pas pris en considération pour le calcul des subventions visé au paragraphe 2. [Par dérogation aux alinéas précédents, le montant des subventions de 34Inséré par le D. 11-12-2024 35Inséré par le D. 17-12-2025 36Inséré par le D. 17-12-2025 37Inséré par le D. 17-12-2025 38Inséré par le D. 17-12-2025 39Inséré par le D. 17-12-2025 Enseignement en général I.A.01 Lois 05108 L. 29-05-1959 fonctionnement des écoles supérieures des arts est calculé en fonction du nombre d''étudiants régulièrement inscrits et finançables tel qu''arrêté au 15 juin de l''année qui précède.]40 § 3. Un mécanisme de solidarité est créé entre les établissements d''enseignement fondamental et secondaire subventionné par l''affectation à une réserve commune d''un pourcentage de leurs subventions de fonctionnement. Trois réserves sont constituées; une pour les pouvoirs organisateurs de l''enseignement officiel subventionné, une pour les pouvoirs organisateurs de l''enseignement libre subventionné de caractère confessionnel et une pour les pouvoirs organisateurs de l''enseignement libre subventionné de caractère non confessionnel. Les montants ainsi constitués sont répartis entre les implantations conformément au décret du 28 avril 2004 relatif à la différenciation du financement des établissements d''enseignement fondamental et secondaire. § 4. Les subventions de fonctionnement sont consacrées pour au moins 20 p.c. dans l''enseignement gardien et primaire et pour au moins 20 p.c. dans l''enseignement secondaire et supérieur aux salaires du personnel de maîtrise, gens de métier, et de service. Toutefois, les établissements qui confient tout ou partie de l''entretien à une entreprise spécialisée, peuvent imputer à cette part réservée de la subvention un pourcentage du prix à payer, dont le taux sera fixé par arrêté royal. § 5. Les salaires du personnel de maîtrise, gens de métier et de service rémunérés à charge des subventions de fonctionnement sont ceux qui sont fixés par la commission paritaire compétente. § 6. Les subventions de fonctionnement accordées en application de l''alinéa 3 du § 2 doivent être consacrées entièrement au fonctionnement de l''internat et à l''encadrement des élèves internes. Inséré par D. 12-12-2018 § 7. Complémentairement aux subventions de fonctionnement visées au § 1er, à l''occasion de l''ouverture d''un établissement d''enseignement spécialisé, d''un établissement d''enseignement secondaire ordinaire ou d''un établissement ou implantation d''enseignement maternel, primaire ou fondamental ordinaire, une prime unique est octroyée à l''établissement/l''implantation concerné(e) pour la prise en charge de ses frais de fonctionnement. L''octroi de cette prime, pour l''enseignement ordinaire, est conditionné au fait que l''établissement concerné soit situé dans une zone en tension démographique au sens de l''article 6, § 2, alinéa 2, du décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice et de l''article 2bis, alinéa 2, du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement. Cette prime peut être sollicitée auprès des Services du Gouvernement dès que le Gouvernement s''est prononcé sur l''admission aux subventions de l''école, et au plus tard avant le 1er octobre de l''année d''ouverture. Le montant de cette prime est fixé sur la base du nombre de places que le pouvoir organisateur déclare ouvrir à la première rentrée scolaire, multiplié par la subvention de fonctionnement forfaitaire par élève. Le Gouvernement fixe le modèle par lequel le Pouvoir organisateur introduit cette déclaration. 40Inséré par le D. 11-12-2024 Enseignement en général I.A.01 Lois 05108 L.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 36, 'Article 32. (partie 4)', '29-05-1959 Les Services du Gouvernement sont habilités à vérifier la pertinence du nombre de places déclarées eu égard aux capacités réelles de l''infrastructure prévue. En cas de discordance, le Gouvernement peut adapter le montant de la prime aux capacités réelles. Modifié par L. 27-06-1962; L. 11-07-1973 ; D. 07-06-2001');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 37, 'Article 33.', 'Article 33.41 - Sans préjudice des dispositions dérogatoires prévues par la présente 
loi, l''intervention financière des communes, des provinces et de la Commission 
communautaire française au profit de l''enseignement libre est limitée à la tutelle 
sanitaire et aux avantages sociaux accordés aux élèves tels qu''ils sont prévus par le 
décret du 7 juin 2001 relatif aux avantages sociaux. En ce qui concerne la tutelle 
sanitaire, les communes, les provinces et la Commission communautaire française ne 
peuvent faire aucune distinction entre les enfants quelles que soient les écoles qu''ils 
fréquentent. Elles n''ont toutefois aucune obligation vis-à-vis des enfants fréquentant 
les écoles de la Communauté française. 
 
Les décisions des conseils communaux, provinciaux et de l''Assemblée de la 
Commission communautaire française accordant des avantages à des établissements 
visés par la présente loi, mais dont ils ne sont pas pouvoir organisateur, sont 
communiquées, endéans les dix jours de la décision, au Gouvernement qui peut les 
annuler pour violation de la présente disposition et du décret du 7 juin 2001 relatif 
aux avantages sociaux dans un délai de quarante jours à partir de leur 
communication. 
 
Les communes, les provinces et la Commission communautaire française 
transmettent chaque année avant le 31 mars au Gouvernement un relevé des 
dépenses faites et des exonérations de taxes et rétributions accordées au profit des 
établissements visés à l''alinéa précédant. 
 
Lorsqu’une commune, une province ou la Commission communautaire française a 
accordé un avantage financier en violation aux dispositions de l''alinéa premier, le 
Gouvernement peut récupérer le montant de cet avantage à charge des frais de 
fonctionnement qui reviennent à l''établissement qui a bénéficié de cet avantage. 
 
Inséré par L. 14-07-1975');
