INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 47, 'Article 49. - […] abrogé par D. 25-04-2008 / Article 49bis. - Pour l''année budgétaire 2020, dans le cadre de la lutte contre la', 'Article 49. - […] abrogé par D. 25-04-2008 
 
Inséré par D. 09-12-2020

Article 49bis. - Pour l''année budgétaire 2020, dans le cadre de la lutte contre la 
pandémie de COVID-19, un montant de 20.000.000 d''euros est octroyé aux écoles 
d''enseignement 
spécialisé, 
aux 
écoles 
d''enseignement 
maternel, 
primaire, 
fondamental, secondaire ordinaire, aux Centres d''éducation et de formation en 
alternance (CEFA) aux Internats du fondamental et du secondaire, ainsi qu''aux écoles 
d''enseignement secondaire artistique à horaire réduit, pour les soutenir dans la mise 
en place, passée ou à venir, de protocoles sanitaires.  
 
Un montant est octroyé par école ou établissement, sur base d''un forfait par élève, 
liquidé au plus tard le 31 décembre 2020, forfait déterminé sur la base du nombre 
d''élèves régulièrement inscrits dans l''école, ou dans chaque établissement coopérant 
du CEFA, à la date du 15 janvier 2020. Pour les écoles ou implantations créées ou 
admises aux subventions au 1er septembre 2020, le montant est calculé sur la base des 
élèves régulièrement inscrits au 30 septembre ou au 1er octobre 2020, selon le niveau 
et la forme d''enseignement concernés. 
 
CHAPITRE XII - Abrogatoire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 48, 'Article 50. - Sont abrogés :', 'Article 50. - Sont abrogés : 
1. La loi du 9 avril 1955 réglant l''octroi, par les communes, de suppléments de 
traitements au personnel enseignant des écoles primaires et gardiennes et leur  
financement; 
2. L''article 15 de la loi du 14 mai 1955, sur l''enseignement artistique pour autant 
qu''elle vise les établissements d''enseignement artistique autres que les écoles de 
musique; 
3. L''article 46 de la loi du 27 juillet 1955 fixant les règles d''organisation de 
l''enseignement de l''Etat, des provinces et des communes, et de subvention, par l''Etat, 
d''établissements d''enseignement moyen, normal et technique; 
4. La loi du 28 juillet 1955 réglant l''enseignement de la religion et l''enseignement 
de la morale dans les établissements d''enseignement secondaire de l''Etat; 
5. Les articles 15 à 19, 26, 28 à 30, 33 à 48, 50 à 57, 75 et 76 des lois coordonnées 
sur l''enseignement moyen du 30 avril 1957; 
6. Les articles 5 à 8, 12 à 31, 33 à 40, 43 à 46, 49, des lois coordonnées sur 
l''enseignement normal du 30 avril 1957; 
7. 
a) les articles 4, alinéas 2, 3 et 4, 19, 28, § 2, 30 à 41, 43 à 55, 57 à 64, 68, 69, 
70 et 71 des lois coordonnées sur l''enseignement technique du 30 avril 1957; 
 
b) les mots "et notamment sur celles qui sont prévues aux articles 39, 49, 51, 
52 et 53" de la dernière phrase du 1er alinéa de l''article 66 des lois coordonnées sur 
l''enseignement technique du 30 avril 1957; 
8. Les articles 7 modifié par l''article 1er de la loi du 17 mars 1958, 16 à 19, 33 à 37, 
38, modifié par la loi du 31 décembre 1957, 39 à 45, 46 modifié par la loi du 17 mars 
1958, 47 à 49, 52, 53, 68, 70 modifié par la loi du 21 avril 1958, 72, 73, 75, alinéa 2, 78 
et 82 des lois coordonnées sur l''enseignement primaire du 20 août 1957; 
9. Les articles 7, alinéa 3, et 8 de la loi du 22 avril 1958 portant création d''un Fonds 
des Constructions scolaires et parascolaires de l''Etat et d''un Fonds des Constructions 
de l''enseignement supérieur et des Cités universitaires de l''Etat. 
 
CHAPITRE XIII. - Autorisation de coordination');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 49, 'Article 51.- Le Roi peut coordonner les dispositions en vigueur des lois organiques', 'Article 51.- Le Roi peut coordonner les dispositions en vigueur des lois organiques 
de l''enseignement primaire, et de l''enseignement normal, de l''enseignement moyen, de 
l''enseignement technique et de l''enseignement artistique avec les modifications 
Enseignement en général                                                                                   I.A.01 
Lois 05108                                                                                                                            L. 29-05-1959  
                 expresses ou implicites que ces lois ont ou auront subies au moment où les 
coordinations seront réalisées.  
 
A cette fin, il peut  
1° modifier l''ordre et la numérotation  des titres, chapitres, sections et articles des 
lois à coordonner et les regrouper sous d''autres divisions; 
2° modifier les références contenues dans les lois à coordonner en vue de les mettre 
en concordance avec la numérotation nouvelle; 
3° modifier la rédaction des dispositions à coordonner en vue d''assurer leur 
concordance et d''uniformiser la terminologie. 
 
CHAPITRE XIV. - Dispositions finales.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 50, 'Article 52. - Les contrats d''adoption en vertu desquels les provinces et les', 'Article 52. - Les contrats d''adoption en vertu desquels les provinces et les 
communes subventionnent des établissements d''enseignement libre cessent d''avoir 
effet le 1er septembre 1958 en ce qui concerne les enseignements moyen, normal, 
technique et artistique, et le 1er janvier 1959 en ce qui concerne les enseignements 
gardien et primaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('5108', 51, 'Article 53. - La présente loi produit ses effets le 1er septembre 1958, sauf :', 'Article 53. - La présente loi produit ses effets le 1er septembre 1958, sauf : 
1° l''article 32, qui produit ses effets le 1er janvier 1959 en tant qu''il concerne les 
subventions 
de 
fonctionnement 
à 
accorder 
aux 
