INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 59, 'Article 51. - § 1er. Certaines années d''études sont sanctionnées par un certificat de', 'Article 51. - § 1er. Certaines années d''études sont sanctionnées par un certificat de 
qualification : 
 
 
1° (...) 
 
 
 
 
2° (...) 
 
 
 
 
3° le certificat de qualification de sixième année de l''enseignement secondaire 
délivré aux élèves réguliers qui ont fréquenté la sixième année de l''enseignement 
technique, artistique ou professionnel de type II, et qui ont subi avec succès les 
épreuves de qualification; 
 
 
 
 
4° le certificat de qualification de septième année de perfectionnement ou de 
spécialisation délivré aux élèves réguliers qui ont fréquenté cette année de 
perfectionnement ou de spécialisation de l''enseignement technique de type II, qui ont 
subi avec succès les épreuves de qualification; 
 
 
 
 
5° le certificat de qualification de septième année de perfectionnement ou de 
spécialisation de l''enseignement secondaire professionnel, délivré aux élèves réguliers 
qui ont fréquenté cette septième année de perfectionnement ou de spécialisation de  
type II comprenant au moins 50 pc. de formation professionnelle et qui ont subi avec 
succès les épreuves de qualification. 
 
 
§ 2. Un certificat relatif aux connaissances de gestion de base est délivré aux élèves 
qui ont satisfait aux exigences du programme prévu à l''article 6 de l''arrêté royal du 21 
octobre 1998 portant exécution du Chapitre Ier du Titre II de la loi-programme du 10 
février 1998 pour la promotion de l''entreprise indépendante. 
 
 
Inséré par A.Gt 20-06-1994');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 60, 'Article 51bis. - Une attestation de compétences intermédiaires est délivrée à tout', 'Article 51bis. - Une attestation de compétences intermédiaires est délivrée à tout 
élève ayant au moins terminé une quatrième année d''études de l''enseignement 
professionnel ou technique, au moment où il quitte l''établissement. 
 
L''attestation est délivrée par le Conseil de classe. Elle précise, pour chaque élève, les 
compétences acquises. 
 
L''attestation de compétences intermédiaires est rédigée en fonction des profils de 
formation lorsque ceux-ci ont été définis. 
 
Modifié par A.Gt 02-04-1998');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 61, 'Article 52. - La sanction des études conduisant aux titres visés aux articles 48, 49,', 'Article 52. - La sanction des études conduisant aux titres visés aux articles 48, 49, 
50 et 51, § 2, est de la compétence du conseil de classe. 
 
Les attestations et certificats visés aux articles 48, 49, 50 et 51 § 2 sont également 
Secondaire 
 
IV.A.10 
Lois 10450 
 
A.R. 29-06-1984  
délivrés en exécution d''une décision du Conseil de recours. 
 
La sanction des études visée à l''article 51, § 1er est de la compétence du jury de 
qualification.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 62, 'Article 53. - Pour la sanction des études conduisant à des certificats de', 'Article 53. - Pour la sanction des études conduisant à des certificats de 
qualification et pour chacune des sections sanctionnées par ce certificat, le jury de 
qualification comprend le chef d''établissement ou son délégué, des membres du 
personnel enseignant et des membres étrangers à l''établissement dont le nombre ne 
peut dépasser celui des membres du corps professoral. 
 
Les membres étrangers à l''établissement : 
 
 
1° sont choisis en raison de leur compétence dans la qualification qu''il s''agit de 
sanctionner; 
 
 
 
 
2° sont désignés dans les premiers mois de l''année scolaire par le pouvoir 
organisateur ou son délégué. 
 
Le jury est présidé soit par le délégué du pouvoir organisateur, soit par le chef 
d''établissement ou son délégué. 
 
TITRE IV : Dispositions finales. 
 
CHAPITRE Ier. - Dispositions particulières.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 63, 'Article 54. - Aucun membre d''un jury ou d''un conseil ou de ce qui en tient lieu dans', 'Article 54. - Aucun membre d''un jury ou d''un conseil ou de ce qui en tient lieu dans 
l''enseignement secondaire de type II ne peut délibérer ou participer à toute décision 
concernant un récipiendaire dont il est le conjoint, le parent ou l''allié jusqu''au 
quatrième degré inclusivement ou à qui il a donné un enseignement sous forme de 
leçons particulières ou de cours par correspondance. 
 
Modifié par D. 12-07-2012');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 64, 'Article 55. - § 1er. Nul ne peut se présenter plus de deux fois par an pour', 'Article 55. - § 1er. Nul ne peut se présenter plus de deux fois par an pour 
l''obtention d''un même titre dans le même établissement d''enseignement. 
 
§ 2.  Toutes les décisions certificatives du Conseil de classe visé à l''article 21bis, 
et du Jury de qualification visé à l''article 2 1ter, sont actées dans un procès-verbal, 
signé par le président et deux membres au moins du Conseil de classe ou du Jury de 
qualification. Ces procès-verbaux sont conservés pendant trente ans. 
 
La notification d''une décision du Conseil de recours visé à l''article 2, 15°, 
réformant et remplaçant une décision certificative du Conseil de classe est jointe au 
procès-verbal de celui-ci. 
 
Les avis favorables du Conseil d''admission visé à l''article 2, 13°, sont actés dans 
un procès-verbal, signé par le président et deux membres au moins du Conseil 
d''admission. Celui-ci est versé au dossier scolaire de l''élève. [Remplacé par D. 12-07-2012] 
 
 
Modifié par A.R. 03-07-1985;  A.E. 30-08-1989;  A.Gt 24-04-1995; A.Gt 15-07-1996 ; A.Gt 
05-05-1999 ; D. 12-07-2012 ; D. 14-03-2019 ; D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 65, 'Article 56. - Le Ministre ou son délégué peut, en raison de circonstances', 'Article 56. - Le Ministre ou son délégué peut, en raison de circonstances 
