INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 72, 'Article 63. - Les porteurs des titres suivants obtenus dans l''enseignement de plein', 'Article 63. - Les porteurs des titres suivants obtenus dans l''enseignement de plein 
exercice sont considérés comme porteurs du certificat de qualification : 
 
 
1° de quatrième année de l''enseignement secondaire : 
 
 
a) le porteur du diplôme d''enseignement secondaire du deuxième degré; 
 
 
b) le porteur du diplôme ou du certificat d''études techniques secondaires 
inférieures délivré dans les établissements d''enseignement moyen; 
 
 
c) le porteur du diplôme ou du certificat d''école technique secondaire 
inférieure; 
 
 
d) le porteur du diplôme de sortie de quatrième année moyenne commerciale; 
 
 
e) le porteur du brevet ou du certificat d''études professionnelles secondaires 
inférieures délivré par les établissements d''enseignement moyen; 
 
 
f) le porteur du brevet ou du certificat d''école professionnelle secondaire 
inférieure; 
 
 
g) le porteur du diplôme d''enseignement technique secondaire inférieur; 
 
 
h) le porteur du diplôme d''enseignement professionnel secondaire inférieur; 
 
 
 
 
2° de cinquième année de perfectionnement ou de spécialisation : 
 
 
a) le porteur du diplôme complémentaire d''enseignement secondaire du 
deuxième degré; 
 
 
b) le porteur du diplôme ou du certificat d''études techniques secondaires 
inférieures, délivré dans les établissements d''enseignement moyen à l''issue d''une 
cinquième année de perfectionnement et/ou de spécialisation; 
 
 
c) le porteur du diplôme ou du certificat de l''année de perfectionnement ou de 
spécialisation de l''école technique inférieure; 
 
 
d) le porteur du brevet ou du certificat d''études professionnelles secondaires 
inférieures délivré dans les établissements d''enseignement moyen, à l''issue d''une 
cinquième année de perfectionnement ou de spécialisation; 
 
 
e) le porteur du brevet ou du certificat de l''année de perfectionnement ou de 
spécialisation de l''école professionnelle secondaire inférieure; 
 
 
f) le porteur du diplôme complémentaire d''enseignement technique secondaire 
inférieur; 
 
 
g) le porteur du diplôme complémentaire d''enseignement professionnel 
secondaire inférieur; 
 
 
 
3° de sixième année de l''enseignement secondaire : 
 
 
a) le porteur du diplôme d''école technique secondaire supérieure; 
 
 
b) le porteur du certificat d''école technique secondaire supérieure délivré avant 
l''année scolaire 1975-1976; 
 
 
c) le porteur du brevet ou du certificat d''école professionnelle secondaire 
supérieure; 
 
 
d) le porteur du diplôme ou du certificat de l''enseignement secondaire 
supérieur artistique; 
 
 
 
4° de septième année technique : le porteur du diplôme ou du certificat de la 
quatrième année de perfectionnement ou de spécialisation d''école technique 
secondaire supérieure; [remplacé par D. 12-07-2012] 
 
 
 
 
5° de septième année professionnelle : le porteur du brevet ou du certificat de 
la quatrième année de perfectionnement ou de spécialisation de l''école professionnelle 
secondaire supérieure. [Ajouté par D. 12-07-2012] 
  
Modifié par A.R. 03-07-1985');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 73, 'Article 64. - § 1er. Le diplôme d''école technique secondaire inférieure est considéré', 'Article 64. - § 1er. Le diplôme d''école technique secondaire inférieure est considéré 
comme équivalent au certificat de qualification de quatrième année de l''enseignement 
secondaire technique accompagné de l''attestation d''orientation A sanctionnant ladite 
Secondaire 
 
IV.A.10 
Lois 10450 
 
A.R. 29-06-1984  
année. 
 
 
§ 2. Le brevet d''école professionnelle secondaire supérieure est considéré comme 
équivalent au certificat de qualification de sixième année de l''enseignement secondaire 
professionnel accompagné de l''attestation d''études de la sixième année d''études de 
l''enseignement secondaire professionnel, délivrée pendant les années scolaires 1975-
1976 à 1983-1984, ou du certificat d''études visé aux articles 24, § 3, et 49, § 3, du 
présent arrêté. 
 
§ 3. Le brevet d''école professionnelle secondaire inférieure est considéré comme 
équivalent au certificat de qualification de quatrième année de l''enseignement 
secondaire professionnel accompagné de l''attestation d''orientation A sanctionnant 
ladite année. 
 
Inséré par A.R. 03-07-1985');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 74, 'Article 64bis. - Les élèves réguliers qui ont terminé avec fruit pendant l''année', 'Article 64bis. - Les élèves réguliers qui ont terminé avec fruit pendant l''année 
scolaire 1983-1984 une première année d''études de l''enseignement secondaire 
