Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('10450', 77, 'Article 64quinquies. - L''attestation de qualification de la septième année', 'Article 64quinquies. - L''attestation de qualification de la septième année 
