INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('16421', 28, 'Article 18. - Pour le calcul des emplois du personnel auxiliaire d''éducation et du', 'Article 18. - Pour le calcul des emplois du personnel auxiliaire d''éducation et du 
personnel administratif et de directeur adjoint, les élèves inscrits dans l''enseignement 
secondaire en alternance sont pris en compte dans l''établissement d''enseignement de 
Secondaire 
 
IV.A.10b 
Lois 16421 
 
D. 03-07-1991  
plein exercice où ils suivent la majorité de leur formation professionnelle. Les élèves 
qui suivent les cours dans un établissement d''enseignement de promotion sociale sont 
pris en compte dans l''établissement siège du CEFA. Le nombre d''élèves est affecté du 
coefficient 0,5.  
  
Pour le calcul des périodes-professeurs visé à l''article 14 et des périodes 
d''accompagnement visé à l''article 15, sont pris en considération les élèves inscrits au 
15 janvier de l''année scolaire précédente, qui remplissaient à cette date, pour ce qui 
concerne les douze mois précédents, les conditions de fréquentation régulière des cours 
et des stages ou conventions au sein du centre d''éducation et de formation en 
alternance où ils sont inscrits. Lorsqu''un établissement de plein exercice devient 
coopérant d''un autre Centre d''éducation et de formation en alternance, les élèves 
inscrits au 15 janvier de l''année scolaire précédente dans cet établissement coopérant 
sont soustraits du calcul relatif au CEFA avec lequel il a été mis fin à la coopération et 
ajoutés dans le calcul relatif au CEFA avec lequel la coopération a été actée ou 
autorisée, selon le cas. 
 
Par dérogation à l''alinéa précédent, n''est pas considéré comme inscrit au 15 
janvier de l''année précédente dans l''établissement qui l''a exclu, l''élève qui fait l''objet 
d''une exclusion définitive à un moment quelconque de cette année, mais bien dans 
celui qui, le cas échéant, l''accueille après cette décision. 
 
Pour l’application des minima de population scolaire visés aux articles 3 et 4 du 
décret du 29 juillet 1992 portant organisation de l’enseignement secondaire de plein 
exercice, le nombre d’élèves réguliers au 1er octobre est pris en considération pour la 
moitié. Ce nombre est ajouté à la population scolaire de l’établissement où les élèves 
suivent la majorité de leurs heures de pratique professionnelle. 
 
Cet article n''est pas applicable à l''enseignement secondaire spécialisé. 
 
Remplacé par D. 04-01-1999 ; modifié par D. 19-07-2001 ; D. 12-05-2004 ; D. 26-03-
2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('16421', 29, 'Article 19. – Les élèves inscrits dans l''enseignement secondaire en alternance', 'Article 19. – Les élèves inscrits dans l''enseignement secondaire en alternance 
sont pris en compte pour la fonction de chef d''atelier ou de chef de travaux d''atelier 
dans l''établissement où ils suivent la majorité de leurs heures de pratique 
professionnelle. Le nombre d''élèves est affecté du coefficient visé à l''article 
21quinquies du décret du 29 juillet 1992 portant organisation de l''enseignement 
secondaire de plein exercice. 
 
L''alinéa premier n''est pas applicable aux établissements d''enseignement de 
promotion sociale qui dispensent des cours de pratique professionnelle à des élèves de 
l''enseignement secondaire en alternance. 
 
Cet article n''est pas applicable à l''enseignement secondaire spécialisé. 
 
CHAPITRE IV. - Membres du personnel 
 
Modifié par D. 18-03-1996 ; modifié par D. 19-07-2001');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('16421', 30, 'Article 20. - § 1er. La situation administrative et pécuniaire des membres du', 'Article 20. - § 1er. La situation administrative et pécuniaire des membres du 
personnel de l''enseignement secondaire en alternance organisé dans les centres 
d''éducation et de formation en alternance, au siège de l''établissement ou dans les 
établissements 
d''enseignement 
coopérants 
est 
réglée 
conformément 
à 
la 
réglementation en vigueur pour les membres du personnel qui exercent une fonction 
dans l''enseignement secondaire de plein exercice ou dans l''enseignement de promotion 
sociale, selon le cas. 
Secondaire 
 
IV.A.10b 
Lois 16421 
 
D. 03-07-1991  
§ 2. Lorsque le centre d''éducation et de formation en alternance compte des 
élèves régulièrement inscrits dans l''enseignement secondaire professionnel inférieur 
et des élèves régulièrement inscrits dans l''enseignement secondaire professionnel 
supérieur, la répartition des périodes d''accompagnement entre le degré inférieur et le 
degré supérieur est proportionnelle au nombre d''élèves inscrits dans l''un et l''autre 
degré. 
 
Toutefois, si le nombre d''élèves inscrits dans l''un ou l''autre degré ne permet pas 
de constituer une charge d''accompagnateur à prestations complètes, les élèves sont 
considérés comme inscrits dans l''un des degrés. 
 
L''alinéa 2 ne peut avoir pour effet de placer en disponibilité ou en charge 
partielle un accompagnateur nommé à titre définitif dans l''un des degrés et d''ouvrir 
simultanément un emploi d''accompagnateur dans l''autre degré. 
 
Modifié par D. 18-03-1996 ; complété par D. 17-07-1998 ;  remplacé  par D. 19-07-
2001 ; modifié par D. 20-12-2001 ; D ; 26-03-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('16421', 31, 'Article 21. - A l''exception de celles de coordonnateur et d''accompagnateur, la', 'Article 21. - A l''exception de celles de coordonnateur et d''accompagnateur, la 
charge d''un professeur prestant dans des classes relevant de l''enseignement 
secondaire en alternance est rémunérée au même barème et sur la base du même 
volume horaire que ceux qui lui sont ou lui seraient attribués dans l''enseignement 
secondaire de plein exercice. 
  
Toutefois dans le calcul de l''encadrement vise à l''article 14 du décret du 3 juillet 
1991, une charge à prestations complètes comporte le même nombre de périodes que 
celui requis pour une fonction de professeur de cours généraux, à prestations 
complètes, dans l''enseignement de plein exercice. 
 
La différence éventuelle entre le nombre de périodes déterminé par l''alinéa 1er et 
celui déterminé par l''alinéa 2 est consacrée à des périodes permettant d''assurer 
l''organisation de périodes complémentaires de formation professionnelle prévues à 
l''article 2ter, § 1er, alinéa 3, et § 2, alinéa 3, l''organisation de modules de formation 
individualisés prévus conformément à l''article 2bis, § 4, et la coordination de la 
formation pratique avec les cours généraux, les cours techniques et la formation en 
entreprise. 
 
Cet article n''est pas applicable à l''enseignement secondaire spécialisé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('16421', 32, 'Article 22. – […] abrogé par D. 18-03-1996 / Article 23. – […] abrogé par D. 18-03-1996', 'Article 22. – […] abrogé par D. 18-03-1996

