INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 1, 'Article 1er. - Le présent décret s''applique à l''enseignement secondaire de plein', 'Article 1er. - Le présent décret s''applique à l''enseignement secondaire de plein 
exercice de la Communauté française ou subventionné par elle. Il ne s''applique pas à 
l''enseignement secondaire spécialisé. 
 
[Par dérogation à l''alinéa 1er, le présent décret et ses arrêtés d''exécution 
s''appliquent à l''enseignement secondaire qualifiant uniquement pour ce qui n''est pas 
spécialement réglé par ou en vertu du décret du 22 juin 2023 relatif à la gouvernance 
de l''offre d''options de base groupées dans l''enseignement secondaire qualifiant de 
plein exercice et en alternance]1. 
 
Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 2, 'Article 1erbis. - Pour l''application du présent décret, on entend par :', 'Article 1erbis. - Pour l''application du présent décret, on entend par : 
1° «Classe bilingue français-langue des signes» : classe au sein de laquelle une 
partie des élèves bénéficie d''un enseignement en langue française pendant que 
simultanément des élèves sourds ou malentendants bénéficient d''un apprentissage en 
immersion en langue des signes et en français écrit; 
2° «Enseignant de culture sourde» : enseignant qui maîtrise la spécificité 
culturelle de la langue des signes et dont la langue des signes est la langue maternelle. 
 
Modifié par D. 05-08-1995; remplacé par D. 02-04-1996');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 3, 'Article 2. - Tout établissement d''enseignement secondaire de type I comprend', 'Article 2. - Tout établissement d''enseignement secondaire de type I comprend 
soit les quatre degrés, soit les trois premiers degrés, soit les premier et deuxième 
degrés, soit les deuxième et troisième degrés, soit les deuxième, troisième et quatrième 
degrés, soit le quatrième degré seul, soit le premier degré seul. 
 
Remplacé par D. 05-08-1995');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 4, 'Article 3. - Tout établissement d''enseignement secondaire doit compter, le 1er', 'Article 3. - Tout établissement d''enseignement secondaire doit compter, le 1er 
octobre, au moins 400 élèves pour être organisé ou subventionné l''année scolaire 
suivante. 
 
Remplacé par D. 05-08-1995; modifié par D. 02-04-1996; D. 25-07-1996 ; D. 07-12-
2007 ; D. 30-04-2009 ; complété par D. 19-07-2011');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 5, 'Article 4. - Le nombre minimum fixé à l''article 3 est réduit à : (partie 1)', 'Article 4. - Le nombre minimum fixé à l''article 3 est réduit à : 1° 350, pour un établissement n''organisant que deux degrés de l''enseignement secondaire de type I; 2° 300, pour un établissement n''organisant que le premier degré de l''enseignement secondaire de type I; 3° 300, pour un établissement n''organisant que le deuxième et le troisième degrés de l''enseignement secondaire de type I, s''il réunit en outre les conditions suivantes: a) n''organiser que l''enseignement secondaire général; b) être le seul établissement d''enseignement du caractère concerné de la commune à organiser ces degrés et cette forme d''enseignement; c) être situé à une distance de plus de 8 km par rapport à l''établissement de même caractère le plus proche qui organise ces degrés et cette forme d''enseignement; 4° 300, pour un établissement n''organisant que le cycle supérieur de l''enseignement secondaire de type II, s''il n''organise que l''enseignement secondaire technique ou professionnel ou ces deux formes d''enseignement; 5° 250, pour un établissement n''organisant que le premier degré de l''enseignement secondaire de type I, s''il réunit en outre les conditions suivantes: 1 Inséré par D. 22/06/2023 (art. 41). Secondaire IV.B.01 Lois 17144 D. 29-07-1992 a) être le seul établissement d''enseignement du caractère concerné de la commune à organiser ce degré; b) être situé à une distance de plus de 8 km par rapport à l''établissement de même caractère le plus proche qui organise ce degré; 6° 250, pour un établissement n''organisant que le deuxième et le troisième degrés de l''enseignement secondaire de type I, s''il réunit en outre les conditions suivantes: a) n''organiser que l''enseignement secondaire technique ou professionnel ou ces deux formes d''enseignement; b) être le seul établissement d''enseignement du caractère concerné de la commune à organiser ces degrés et ces formes d''enseignement; c) être situé à une distance de plus de 8 km par rapport à l''établissement de même caractère le plus proche qui organise ces degrés et ces formes d''enseignement; 7° 250, pour un établissement n''organisant que le deuxième et le troisième degrés de l''enseignement secondaire de type I, s''il réunit en outre les conditions suivantes: a) n''organiser que l''enseignement secondaire technique ou professionnel ou ces deux formes d''enseignement; b) organiser dans ces deux formes des options n''appartenant qu''à un ou deux secteurs, tels que visés à l''article 24, alinéa 1er, 2°; pour l''application de cette disposition, le Gouvernement peut décider de considérer deux secteurs comme un seul pour l''ensemble des établissements; le Gouvernement s''appuiera, pour la détermination des secteurs concernés, sur l''ensemble des données disponibles dans les instances sous-régionales de pilotage inter-réseaux créées en application du décret du 30 avril 2009 relatif à la création d''instances sous-régionales de pilotage et à l''octroi d''incitants visant un redéploiement plus efficient de l''offre d''enseignement qualifiant dans une perspective de développement territorial; 8° 250, pour un établissement dont la ou les implantations d''enseignement secondaire sont bénéficiaires de l''encadrement différencié et appartiennent à la classe 1 tel que déterminée par le décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité. 9° 250, pour un établissement situé à plus de 8 km de tout établissement d''enseignement du caractère concerné, s''il est en outre le seul établissement d''enseignement du caractère concerné de la commune et si la densité de population de cette dernière est inférieure à 250 habitants au km2; 10° 200, pour un établissement situé à plus de 20 km de tout établissement d''enseignement du caractère concerné; 11° 200, pour un établissement situé à plus de 12 km de tout établissement d''enseignement du caractère concerné, s''il est en outre le seul établissement d''enseignement du caractère concerné de la commune et si la densité de population de cette dernière est inférieure à 125 habitants au km2; 12° 200, pour un établissement n''organisant qu''un ou deux degrés de l''enseignement secondaire de type I s''il réunit en outre les conditions suivantes: a) être le seul établissement d''enseignement du caractère concerné de la commune; b) être situé à plus de 8 km de tout établissement d''enseignement du caractère concerné; c) être situé dans une commune dont la densité de population est inférieure à 250 habitants au km2; 13° 150, pour un établissement n''organisant qu''un ou deux degrés de l''enseignement secondaire de type I s''il réunit en outre les conditions suivantes: a) être le seul établissement d''enseignement du caractère concerné de la commune; b) être situé à plus de 12 km de tout établissement d''enseignement du caractère concerné; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 c) être situé dans une commune dont la densi');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 6, 'Article 4. - Le nombre minimum fixé à l''article 3 est réduit à : (partie 2)', 'de population est inférieure à 125 habitants au km2; 14° 150, pour un établissement n''organisant qu''un ou deux degrés de l''enseignement secondaire de type I s''il réunit en outre les conditions suivantes: a) être le seul établissement d''enseignement du caractère concerné de la commune; b) être situé à plus de 20 km de tout établissement d''enseignement du caractère concerné; 15° 250, pour un établissement n''organisant que le quatrième degré de l''enseignement professionnel secondaire complémentaire ainsi que l''année préparatoire à l''enseignement professionnel secondaire complémentaire et, éventuellement, l''année préparatoire à l''enseignement supérieur paramédical ou le seul quatrième degré de l''enseignement professionnel secondaire complémentaire. 16° 250, pour un établissement n''organisant au niveau de l''enseignement secondaire de type I que la forme artistique. 17° 350, pour un établissement n''organisant que les deuxième et troisième degrés de l''enseignement secondaire technique et/ou professionnel ainsi que le quatrième degré de l''enseignement professionnel. Remplacé par D. 05-08-1995 ; modifié par D. 14-03-2019 ; D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 7, 'Article 5. - Pour l''application du présent décret, les distances sont mesurées sur', 'Article 5. - Pour l''application du présent décret, les distances sont mesurées sur 
la partie de la voie publique aménagée pour la circulation des véhicules en général. 
 
Pour l''application des minima de population scolaire sont pris en considération 
les élèves régulièrement inscrits au 1er octobre, à l''exception des élèves visés à l''article 
1.7.1-9, alinéa 2, du Code de l''enseignement fondamental et de l''enseignement 
secondaire. 
 
Inséré par D. 05-08-1995; complété par D. 24-07-1997 ; modifié par D. 19-07-2011 ; 
D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 8, 'Article 5bis. - § 1er. L''établissement qui n''atteint pas au 1er octobre les minima', 'Article 5bis. - § 1er. L''établissement qui n''atteint pas au 1er octobre les minima 
fixés aux articles 3 et 4 alors qu''il les atteignait le 1er octobre de l''année scolaire 
précédente est classé en « maintien 1 ».  
 
L''établissement qui n''atteint pas au 1er octobre les minima fixés aux articles 3 et 
4, alors qu''il était classé en « maintien 1 » l''année scolaire précédente, est classé en 
«maintien 2 ».  
 
L''établissement qui n''atteint pas au 1er octobre les minima fixés aux articles 3 et 
4, alors qu''il était classé en « maintien 2 » l''année scolaire précédente, est classé en « 
maintien 3 ».  
 
Les Services du Gouvernement communiquent aux établissements concernés la 
situation dans laquelle ils se trouvent avant le 31 décembre. 
 
 § 2. Tout établissement classé en maintien 3 au 1er octobre d''une année scolaire 
n''est plus organisé ni subventionné au premier jour de l''année scolaire suivante.  
 
La disposition de l''alinéa 1er s''applique également aux établissements créés en 
application de l''article 4 de la loi du 29 mai 1959 modifiant certaines dispositions de la 
législation de l''enseignement. 
 
Inséré par D. 05-08-1995 ; modifié par D. 17-12-2003 ; D. 19-07-2011 ; complété par 
D. 12-07-2012(2) ; modifié par D. 14-03-2019 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 9, 'Article 5ter. - § 1er. Tout établissement peut être fusionné à l''initiative de son (partie 1)', 'Article 5ter. - § 1er. Tout établissement peut être fusionné à l''initiative de son pouvoir organisateur avec un ou plusieurs établissements. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Par dérogation à l''article 5bis, § 2, alinéa 1er, l''établissement qui opère une fusion conformément à l''alinéa 1er est maintenu jusqu''à cette fusion. § 2. Par fusion, il faut entendre: 1° la réunion en un seul établissement de plusieurs établissements qui disparaissent simultanément; 2° la réunion de plusieurs établissements dont l''un continue à exister et absorbe l''autre ou les autres. § 3. La fusion s''opère en un temps au premier jour d''une année scolaire. A l''issue de la fusion visée au § 2, l''établissement n''a qu''un seul pouvoir organisateur, un seul chef d''établissement et un seul éducateur-économe. § 4. Une fusion d''établissements ne peut s''opérer qu''entre établissements appartenant au même type d''enseignement. Toutefois, une fusion peut s''opérer entre établissements de types d''enseignement différents, à condition que la transformation en un enseignement de type I soit entamée au plus tard à la date de la fusion. § 5. Par dérogation à l''article 24, § 2, 8°, de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement, un établissement résultant de la fusion de plusieurs établissements peut être implanté en différents endroits. L''établissement principal forme avec ses diverses implantations une unité pédagogique et administrative. § 6. Les propositions de fusion sont soumises, pour avis, aux conseils de zone et, pour approbation, au comité de concertation du caractère d''enseignement concerné, créés en application de l''article 24. Le comité de concertation transmet les propositions approuvées aux Services du Gouvernement, qui vérifient le respect des dispositions légales et réglementaires. § 7. En vue de favoriser les fusions d''établissements ou les restructurations visées à l''article 5quater, § 1er, alinéas 3 à 5, des incitants sont octroyés à l''établissement issu de la fusion ou aux établissements issus d''une restructuration, en ce qui concerne le NTPP et certaines fonctions de membres du personnel non chargé de cours. Ces incitants sont classés en trois catégories d''après le classement des établissements concernés par la fusion ou la restructuration en application de l''article 5bis, § 1er, au 1er octobre de l''année qui précède la fusion ou la restructuration : 1° Catégorie 1re : lorsqu''aucun des établissements concernés n''est classé en maintien 2 ou en maintien 3. 2° Catégorie 2 : lorsqu''aucun des établissements concernés n''est classé en maintien 3 et qu''un de ceux-ci au moins est classé en maintien 2. 3° Catégorie 3 : lorsqu''au moins un des établissements concernés est classé en maintien 3. § 8. Le calcul des incitants alloués à l''établissement issu de la fusion ou de la restructuration bénéficiant des incitants visés au § 7 se base sur les éléments suivants pendant l''année de la fusion et les cinq années qui suivent : 1° un NTPP A est calculé conformément aux articles 7 à 15, 17 et 22, § 2, pour les années, degrés, formes, sections, options ou cours qui existaient déjà dans les établissements entrés dans la fusion ou la restructuration selon la structure qui existait dans ces établissements au 1er octobre de l''avant-dernière année scolaire qui précède la fusion ou la restructuration; [complété par D. 12-07-12] Secondaire IV.B.01 Lois 17144 D. 29-07-1992 2° un NTPP B est calculé comme suit; le NTPP B est le total des NTPP calculés conformément aux articles 7 à 15, 17 et 22 § 2, séparément pour chaque établissement entré dans la fusion ou la restructuration en attribuant les élèves de l''établissement issu de la fusion à l''un ou l''autre des établissements tels qu''organisés avant la fusion ou la restructuration en fonction des années, degrés, formes, sections, options ou cours organisés par chacun avant la fusion ou la restructuration. Au cas où les mêmes années, degrés, formes, sections, options ou cours étaient organisés dans plus d''un établissement avant la fusion ou la restructuration, une répartition de la population est effectuée au prorata des populations totales de chaque établissement avant la fusion ou la restructuration. La structure des établissements concernés qui est prise en compte pour le calcul du NTPP B est celle qui existait au 1er octobre de l''avant-dernière année scolaire qui précède la fusion ou la restructuration. § 9. Les incitants en NTPP visés au § 7 sont calculés comme suit : 1° Catégorie 1re : si la différence entre le NTPP B et le NTPP A est positive, cette différence est ajoutée au NTPP de l''établissement à 100 % pour l''année de la fusion ou de la restructuration et les deux années qui suivent, à 75 % pour la quatrième année, à 50 % pour la cinquième année et à 25 % pour la sixième année; 2° Catégorie 2 : si la différence entre le NTPP B et le NTPP A est positive, cette différence est ajoutée au NTPP de l''établissement à 75 % pour l''année de la fusion ou de l');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 10, 'Article 5ter. - § 1er. Tout établissement peut être fusionné à l''initiative de son (partie 2)', 'restructuration et les deux années qui suivent, à 50 % pour la quatrième année, à 25 % pour la 5e année et à 10 % pour la sixième année; 3° Catégorie 3 : si la différence entre le NTPP B et le NTPP A est positive, cette différence est ajoutée au NTPP de l''établissement à 50 % pour l''année de la fusion ou de la restructuration et les deux années qui suivent, à 25 % pour la quatrième année, à 10 % pour la cinquième année et à 5 % pour la sixième année. Les incitants sont ajoutés au NTPP de l''établissement calculé conformément aux articles 7 à 15, 17 et 22, § 2. Modifié par D. 14-03-2019 ; D. 31-03-2022 § 10. Les incitants concernant certaines fonctions de membres du personnel non chargé de cours visés au § 7 se définissent comme suit pour les trois catégories : il est créé, en cadre d''extinction, un nombre d''emplois de directeurs complémentaires, de directeurs adjoints complémentaires, d''éducateurs-économes adjoints, de chefs de travaux d''atelier adjoints et de chefs d''atelier adjoints correspondant au nombre d''emplois excédentaires de directeurs ou de directeurs adjoints, d''éducateurs- économes, de chefs de travaux d''atelier et de chefs d''atelier nommés ou engagés à titre définitif dans les établissements autonomes préexistants à la fusion ou la restructuration. Sans préjudice des règles applicables en matière de mise en disponibilité par défaut d''emploi et de réaffectation, les membres du personnel définitif qui, en application des modalités de fusion ou de restructuration, n''occuperont plus les emplois de directeurs, de directeurs adjoints, d''éducateurs économes, de chefs de travaux d''atelier et de chefs d''atelier de l''établissement fusionné sont rappelés à l''activité ou remis au travail, dans les emplois de directeurs complémentaires ou de directeurs adjoints complémentaires, d''éducateurs-économes adjoints, de chefs de travaux d''atelier adjoints et de chefs d''atelier adjoints visés à l''alinéa 1er. Chaque emploi visé à l''alinéa 1er est supprimé du cadre d''extinction lorsque son titulaire quitte définitivement sa fonction. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 A partir du premier jour du mois qui suit l''extinction d''un emploi de directeur complémentaire visé à l''alinéa 1er, l''établissement concerné bénéficie d''un emploi de directeur adjoint supplémentaire par dérogation à l''article 21quater. A partir du premier jour du mois qui suit l''extinction d''un emploi d''éducateur- économe adjoint visé à l''alinéa 1er, l''établissement concerné bénéficie d''un emploi de surveillant-éducateur supplémentaire par dérogation aux articles 3 à 5 de l''arrêté royal du 15 avril 1977 fixant les règles et les conditions de calcul du nombre d''emplois dans certaines fonctions du personnel auxiliaire d''éducation et du personnel administratif des établissements d''enseignement secondaire. Lorsque la fusion ou la restructuration n''entraîne pas de cadre d''extinction pour un des emplois de directeur ou d''éducateur-économe, l''établissement concerné bénéficie, à partir du premier jour du mois qui suit la fusion, d''un emploi de de directeur adjoint supplémentaire par emploi de chef d''établissement supprimé et d''un emploi de surveillant-éducateur supplémentaire par emploi d''éducateur-économe supprimé. L''emploi supplémentaire de directeur adjoint visé aux alinéas 4 et 6 est supprimé au premier jour de l''année scolaire lorsque, au 1er octobre de l''année précédente, le nombre d''élèves de l''établissement issu de la fusion ou de la restructuration est inférieur de plus de 10 % au nombre d''élèves obtenu par l''addition des populations scolaires, calculées au 1er octobre de l''année précédant la fusion, de chacun des établissements préexistant à la fusion ou à la restructuration. L''emploi supplémentaire de surveillant-éducateur visé aux alinéas 5 et 6 est supprimé au premier jour de l''année scolaire lorsque, au 1er octobre de l''année précédente, le nombre d''élèves de l''établissement issu de la fusion ou de la restructuration est inférieur de plus de 10 % au nombre d''élèves obtenu par l''addition des populations scolaires, calculées au 1er octobre de l''année précédant la fusion ou la restructuration, de chacun des établissements préexistant à la fusion ou à la restructuration. Par dérogation à l''article 21quater, 28 périodes supplémentaires au maximum peuvent être imputées au NTPP en vue de maintenir tout ou partie de l''emploi de directeur adjoint supprimé en application de l''alinéa 7 après avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. Par dérogation à l''article 20, § 5, alinéa 1er, un maximum de 24 périodes supplémentaires peuvent être imputées au NTPP en vue de maintenir, en tou');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 11, 'Article 5ter. - § 1er. Tout établissement peut être fusionné à l''initiative de son (partie 3)', 'ou en partie, l''emploi de surveillant-éducateur supprimé en application de l''alinéa 8. Inséré par D. 05-08-1995; modifié par D. 02-04-1996; complété par D. 25-07-1996 ; D. 08-02-1999 ; D. 12-12-2008 ; modifié par D. 19-07-2011 ; D. 17-10-2013 (1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 12, 'Article 5quater. - § 1er. Sur avis du Conseil général de concertation organisé en', 'Article 5quater. - § 1er. Sur avis du Conseil général de concertation organisé en 
application du décret du 27 octobre 1994 précité, le Gouvernement peut autoriser 
plusieurs établissements à se restructurer. 
 
Par restructuration, il faut entendre la reprise, par un établissement d''une ou 
plusieurs options, années d''études, degrés ou formes d''enseignement d''un autre 
établissement d''enseignement de même caractère.  
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Pour l''établissement qui reprend une ou plusieurs options, années d''études, 
degrés ou formes d''enseignement, il ne s''agit pas d''une création et les normes de 
création fixées par l''arrêté royal n° 49 du 2 juillet 1982 relatif aux normes de création, 
de maintien et de dédoublement et au calcul de crédit d''heures de l''enseignement 
secondaire de type I, concernant la fusion d''établissements ainsi que certains emplois 
du personnel des établissements d''enseignement secondaire de plein exercice de type I 
et de type II ne sont pas d''application au contraire des normes de maintien. [alinéa 
inséré par D. 17-10-2013] 
 
La restructuration de deux ou plusieurs établissements peut amener à 
l''émergence d''un établissement n''organisant que le 1er degré. Dans ce cas, les 
établissements concernés par la restructuration bénéficient des incitants tels que 
définis à l''article 5ter, §§ 7 à 10, pour autant que l''établissement n''organisant que le 
1er degré soit organisé dans une seule implantation, telle que définie à l''article 2, 1°, b) 
du décret du 28 avril 2004 relatif à la différenciation du financement des 
établissements d''enseignement fondamental et secondaire, n''accueillant aucun autre 
établissement d''enseignement secondaire que l''établissement organisant le 1er degré et 
aucun autre niveau, type ou forme d''enseignement secondaire sur le même site. 
L''établissement n''organisant que le 1er degré ne peut pas être subventionné s''il ne 
compte pas 340 élèves au 1er octobre de l''année de la restructuration. Le 
Gouvernement fixe les modalités d''introduction des demandes visant à l''émergence 
d''un établissement n''organisant que le 1er degré.  
 
Par dérogation à l''alinéa précédent, le Gouvernement peut, en raison de 
circonstances particulières liées à l''éloignement, aux transports ou à la configuration 
des bâtiments, accorder les incitants aux établissements concernés par la 
restructuration lorsque l''établissement n''organisant que le 1er degré est organisé sur 
une implantation accueillant d''autres établissements d''enseignement secondaire ou 
plusieurs implantations.  
 
Lorsque la restructuration de plusieurs établissements entraîne la fermeture de 
l''un d''eux au moins, les établissements issus de la restructuration bénéficient 
globalement des incitants tels que définis à l''article 5ter, §§ 7 à 10. 
 
Les restructurations peuvent s''opérer sur le mode de la fusion, telle que décrite à 
l''article 5ter, § 2, 1°, ou sur le mode de la fusion par absorption, telle que décrite à 
l''article 5ter, § 2, 2°. 
 
§ 2. A dater du 1er septembre 1996, aucun degré, année ou option ne peut être 
organisé dans un établissement et implanté dans un autre. 
 
L''alinéa 1er ne s''applique pas aux sections d''enseignement professionnel 
secondaire complémentaire implantées dans une haute école, sur la base d''un accord 
de collaboration, conformément à l''article 92 du décret du 5 août 1995 fixant 
l''organisation générale de l''enseignement supérieur en hautes écoles. 
 
Sur avis du Conseil général de l’enseignement secondaire, le Gouvernement peut 
déroger à l''alinéa 1er. La dérogation est valable pour une période de 5 années 
consécutives. 
 
§ 3. Pour l''application des §§ 1er et 2, l''absence d''avis du Conseil dans le délai de 
deux mois à compter de la demande d''avis qui lui est adressée par le Gouvernement 
est assimilée à un avis favorable. 
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Inséré par D. 05-08-1995 ; modifié par D. 12-12-2008 ; D. 19-07-2011 ; D. 11-04-
2014 ; complété par D. 11-04-2014 (2)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 13, 'Article 5quinquies. - Sur avis du Conseil général de concertation créé par le', 'Article 5quinquies. - Sur avis du Conseil général de concertation créé par le 
décret du 27 octobre 1994 organisant la concertation pour l''enseignement secondaire, 
le Gouvernement peut déroger à la disposition prévue à l''article 5bis, § 2. 
 
Pour l''application de l''alinéa 1er, l''absence d''avis du Conseil dans le délai de deux 
mois à compter de la demande d''avis qui lui est adressée par le Gouvernement est 
assimilée à un avis favorable. 
 
La dérogation est accordée automatiquement aux établissements qui participent 
au plan de redéploiement d''une instance de pilotage interréseaux de l''enseignement 
qualifiant (IPIEQ) en fermant une option, en application de l''article 5 du décret du 30 
avril 2009 relatif à la création d''instances de pilotage interréseaux de l''enseignement 
qualifiant (IPIEQ) et à l''octroi d''incitants visant un redéploiement plus efficient de 
l''offre d''enseignement qualifiant dans une perspective de développement territorial. 
[Inséré par D. 11-04-2014] 
 
Inséré par D. 12-12-2008 ; complété par D. 19-07-2011');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 14, 'Article 5sexies. - Pour les cas prévus aux articles 5quater, § 1er et 2,', 'Article 5sexies. - Pour les cas prévus aux articles 5quater, § 1er et 2, 
5quinquies, 19 §§ 2 et 3, le Gouvernement fonde sa décision notamment sur l''évolution 
de la population scolaire totale, par degré ou par option et les spécificités des projets 
pédagogiques et éducatifs de l''établissement concerné ou encore l''offre d''enseignement 
au sein de la Zone dans laquelle se trouve celui-ci. 
 
Le Gouvernement arrête, au minimum tous les cinq ans, les indicateurs précisant 
les critères généraux visés à l''alinéa 1er.  
 
A cette fin, le Gouvernement soumet pour avis au Conseil général de 
l’enseignement secondaire une proposition d''indicateurs.  
 
Pour l''application de l''alinéa 3, l''absence d''avis du Conseil dans le délai de deux 
mois à compter de la demande d''avis qui lui est adressée par le Gouvernement est 
assimilée à un avis favorable.  
 
Conformément aux dispositions de l''article 2, 1° du décret du 27 octobre 1994 
organisant la concertation pour l''enseignement secondaire, le Conseil général de 
concertation peut aussi formuler d''initiative des propositions d''indicateurs à l''adresse 
du Gouvernement.  
 
L''établissement qui sollicite une dérogation aux nombres minima fixés aux 
articles 3 et 4 accompagne sa demande d''une justification par rapport aux critères et 
indicateurs dont il est question aux deux premiers alinéas et d''un plan de gestion 
visant soit au rattrapage progressif de la norme de maintien soit à la fusion ou la 
restructuration de l''établissement. 
 
Complété par D. 05-08-1995 ; remplacé par D. 19-07-2011 ; D. 03-05-2012 ; modifié 
par D. 19-07-2017(1) ; D. 14-06-2018 ; D. 31-03-2022 ; D. 14-12-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 15, 'Article 6. - § 1er. Un nouvel établissement d''enseignement secondaire de type I (partie 1)', 'Article 6. - § 1er. Un nouvel établissement d''enseignement secondaire de type I ne peut être créé ou subventionné s''il ne compte pas 450 élèves au 1er octobre de l''année de sa création. Un établissement résultant d''une fusion ou d''une restructuration en application de l''article 5ter ou de l''article 5quater, n''est pas considéré comme un nouvel établissement. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Un établissement qui, par la modification de son offre d''enseignement, atteint un des nombres minima fixés à l''article 4, n''est pas considéré comme un nouvel établissement. § 2. - Le Gouvernement met en place un monitoring au sein du Service général du Pilotage du Système Educatif concernant l''offre de places scolaires dans l''enseignement secondaire ordinaire. En fonction des résultats de ce monitoring, le Gouvernement désigne annuellement, dans le courant du mois de septembre, une ou plusieurs zones ou parties de zone d''enseignement où l''offre de places scolaires est inférieure à la demande, ces zones ou parties de zone étant considérées comme étant en tension démographique. La détermination de ces zones ou parties de zone se base sur les critères suivants : 1° un tampon estimé de places disponibles dans les communes amenant à l''identification d''un nombre de places à créer dans chaque commune disposant d''au moins un établissement d''enseignement obligatoire, afin d''assurer une offre de places supérieure au nombre d''élèves scolarisés. Ce tampon est égal ou inférieur à 10% par rapport à la somme des places disponibles dans les écoles de la commune, telle qu''estimée par le Service général du Pilotage du Système Educatif. Ne sont néanmoins pas prises en compte parmi ces communes, celles pour lesquelles ce tampon correspond à un nombre de places à créer inférieur à 100; [complété par D. 14-06-2018] 2° un pourcentage d''exportation permettant d''identifier les communes scolarisant moins d''élèves que ceux domiciliés sur leur territoire. Ce pourcentage est supérieur ou égal à 10% par rapport au nombre d''élèves résidant dans la commune. Ne sont néanmoins pas prise en compte parmi ces communes, celles pour lesquelles le tampon de places disponibles est supérieur ou égal à 20%; [complété par D. 14-06-2018] 3° une distance en kilomètres séparant les centroïdes des communes exportatrices des centroïdes des communes sous le tampon visé au 1). Cette distance est inférieure ou égale à 10 kilomètres; 4° une année de référence pour laquelle les résultats sont générés. Cette année de référence correspond à 5 années supplémentaires à partir de l''année de détermination des zones ou parties de zone en tension démographique. Dans les zones ou parties de zones déterminées sur la base des quatre critères repris à l''alinéa précédent, le Gouvernement fixe un objectif minimal de places à créer correspondant à la somme des places nécessaires pour atteindre un tampon d''au moins 7% dans chaque commune de celles-ci. Il lance dans le courant du mois de novembre 2022 un appel à projets à l''ensemble des pouvoirs organisateurs pour bénéficier des moyens prévus, pour les années 2022, 2023 et 2024, à l''article 13bis du décret du 5 février 1990 relatif aux bâtiments scolaires de l''enseignement non universitaire organisé ou subventionné par la Communauté française. [Modifié par D. 14-12-2022] Seuls sont éligibles les projets situés dans une zone ou partie de zone en tension démographique et permettant l''ouverture d''au moins 25 places scolaires. Les réponses à l''appel à projets sont remises par les pouvoirs organisateurs pour le 30 avril 2023 au plus tard, et ce via un formulaire type. Les demandes introduites contiennent, selon les différentes situations, les éléments suivants: 1. un descriptif des travaux d''aménagements, de rénovation ou d''extension de bâtiments et/ou modules préfabriqués, envisagés; 2. descriptif détaillé des locations/achats de bâtiments et/ou modules préfabriqués envisagés; 3. une estimation financière du coût des travaux/locations/achats envisagés ; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 4. un relevé de la population scolaire de l''établissement visé sur les 3 dernières années et son évolution projetée suite aux travaux/locations/achats envisagés; 5. un rétroplanning des opérations envisagées sur base du modèle prévu par l''appel à projet et mentionnant la date d''ouverture des nouvelles places. Pour être éligible à l''appel à projets, les pouvoirs organisateurs, doivent répondre aux critères cumulatifs suivants: a. viser une implantation scolaire de l''enseignement obligatoire, organisé ou subventionné par la Communauté française et située dans une zone en tension démographique. Par zone en tension démographique il y lieu d''entendre: les zones ou parties de zones telles que définies par le décret du 19 juillet 2017 relatif à l''offre de places dans les zones en tension démographique, aux subsides en matière de bâtiments scolaires, au programme prioritaire de travaux et au subventionnement des établissements d''enseignement obligato');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 16, 'Article 6. - § 1er. Un nouvel établissement d''enseignement secondaire de type I (partie 2)', 'article 9, et approuvé par le Gouvernement et annexé à l''appel à projets; b. pour les demandes liées à des travaux pérennes sur l''infrastructures, disposer d''un droit réel pour une durée minimale de 30 ans sur le bâtiment visé, au plus tard au moment de l''accord ferme de subvention ; c. le projet permet la création de minimum 25 places, à l''exception de l''enseignement spécialisé pour lequel il n''y a pas de minimum et ne peut créer plus de nouvelles places que le nombre de places nécessaires pour atteindre le tampon de 10 pourcents de la zone où il se situe, sous peine de voir les places supplémentaires être non subventionnées; d. les places doivent être créées structurellement pour la rentrée scolaire 2025 au plus tard, à l''exception des locations qui peuvent ne pas être structurelles; e. le pouvoir organisateur demandeur doit disposer d''un accès aux dotations/subventions de fonctionnement; f. le demandeur doit respecter la législation sur les marchés publics de travaux, fournitures et services. Dans le cas de retard dans le délai d''ouverture des places, le Gouvernement peut retirer le droit à la subvention octroyée au pouvoir organisateur. Les bénéficiaires de la présente subvention s''engagent à maintenir une affectation scolaire au sein du bâtiment ayant fait l''objet d''une subvention dans le cadre du présent mécanisme et relative à un achat ou des travaux pérennes pour une durée de 30 années à compter de l''octroi de la subvention. Le bénéficiaire de la subvention est tenu d''informer l''Administration lorsque : a. l''affectation ou la destination des bâtiments scolaires pour lesquels les travaux ont été réalisés avec l''appoint de la subvention est modifiée totalement ou partiellement, ou b. les droits de propriétés, de jouissance, d''usage ou d''habitation de ces bâtiments sont cédés à titre gratuit ou onéreux. Les bénéficiaires de la subvention dont les bâtiments scolaires ont bénéficié d''une subvention en vertu du présent décret et pour lesquels l''affectation scolaire n''est plus rencontrée et/ou cède à titre onéreux les bâtiments remboursent la subvention. Le montant de la partie de la subvention à rembourser pour les locaux sera établi en fonction du nombre de m2 désaffectés, déduction faite du nombre d''années d''occupation. Chaque année d''occupation interviendra pour une trentième du montant de la subvention. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Le montant à rembourser sera fixé par arrêté du Gouvernement de la Communauté française. Le bénéficiaire peut ne pas rembourser la subvention si: - les locaux ont perdu leur destination scolaire suite à des circonstances indépendantes de la volonté du pouvoir organisateur concerné, ou - l''affectation scolaire est maintenue. Le Gouvernement apprécie l''opportunité de procéder au recouvrement de la subvention sur base des éléments présentés par le pouvoir organisateur. Les dépenses éligibles considérées dans le présent mécanisme sont les suivantes et permettant l''augmentation de la capacité d''accueil de l''établissement concerné: a. tous travaux d''aménagement de locaux; b. tous travaux de construction ou rénovation de bâtiment; c. toutes locations de locaux complémentaires ou de modules préfabriqués pour une durée maximale allant jusqu''à la rentrée scolaire 2028; d. tous achats de bâtiments ou modules préfabriqués. Les dépenses éligibles visées ci-dessus le sont dans le respect de l''arrêté du Gouvernement de la Communauté française du 6 février 2014 fixant les règles qui déterminent le besoin en constructions nouvelles ou extensions et les normes physiques et financières pour les bâtiments scolaires, internats et centres psycho- médico-sociaux. Sur base des dossiers introduits, le Gouvernement arrête la liste des dossiers retenus selon les modalités fixées par le présent décret au plus tard le 30 septembre 2023. Préalablement à l''adoption de cette liste, le Gouvernement consulte sur cette liste la Commission inter caractère crée à l''article 11 du décret du 16 novembre 2007 relatif au programme prioritaire de travaux. Cet avis est communiqué au Gouvernement dans un délai de 30 jours à dater de la communication à la Commission inter caractère de la liste des dossiers. Si pour des raisons d''engagement juridique nécessaire sur un achat et/ou en vue d''ouvrir les places visées dès la rentrée scolaire 2023, un pouvoir organisateur ne peut attendre la date du 30 septembre 2023 pour obtenir un accord de financement, ce dernier devra le justifier lors de sa candidature. Par engagement juridique nécessaire sur un achat, il y a lieu d''entendre, la remise d''une offre ferme d''achat ou la signature d''un acte notarié lié à cet achat. Le Gouvernement peut alors se positionner plus rapidement sur ce dossier et ce afin de permettre au pouvoir organisateur de mener à bien son projet. Si les moyens dévolus ne sont pas suffisants pour couvrir l''ensemble des demandes introduites, les dossiers seront priorisés sur base des critères suivants, et ce dans l''ordre de priorité: - les projets');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 17, 'Article 6. - § 1er. Un nouvel établissement d''enseignement secondaire de type I (partie 3)', 'visant des travaux ou aménagement pérenne et structurel; - l''établissement visé se trouve dans une zone en tension où le manque de place est le plus important; - le projet vise une école déjà existante; - la date d''ouverture des places la plus proche; - l''établissement visé se trouve dans une zone en tension où le tampon de 7 pourcents n''est pas encore atteint; - le coût par place créée le moins onéreux. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Ces mêmes critères seront utilisés pour départager les dossiers faisant appel à la dérogation relative au délai de l''appel à projets, dans le cas où ces dossiers seraient à ce point nombreux que les moyens alloués soient insuffisants que pour tous les financer. Le Gouvernement crée ou autorise la création d''un nombre d''établissements qui ne soit pas supérieur au nombre qu''il a déterminés en veillant à assurer un équilibre entre le caractère confessionnel et le caractère non-confessionnel, en vérifiant l''adéquation entre les projets présentés et les besoins recensés, notamment en fonction de la localisation et des possibilités de transports, et en tenant compte de l''offre d''enseignement projetée. Par dérogation au § 1er, les établissements visés à l''alinéa précédent peuvent se créer année par année ou degré par degré. Dans ce cas, ils doivent atteindre : - dès la première année, un nombre minimum de 60 élèves régulièrement inscrits au 1er octobre; - au terme d''un processus dont le Gouvernement fixe la durée, 450 élèves dans le cas d''un établissement organisant trois degrés, 395 élèves dans le cas d''un établissement n''organisant que deux degrés et 340 élèves dans le cas d''un établissement n''organisant qu''un degré. La durée dont il est question à l''alinéa précédent est fixée à : 1° minimum 3 et maximum 4 ans pour un établissement n''organisant qu''un degré; 2° minimum 5 et maximum 6 ans pour un établissement organisant deux degrés; 3° minimum 7 et maximum 8 ans pour un établissement organisant trois degrés. A défaut, l''établissement n''est plus organisé ni subventionné au premier jour de l''année scolaire suivante, sauf dérogation accordée par le Gouvernement. § 3. Les normes de création fixées au § 1er et au § 2 s''appliquent également aux établissements créés en application de l''article 4 de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement. Intitulé remplacé par D. 19-07-2017 CHAPITRE II. - Calcul et utilisation des périodes-professeurs et des périodes pour l''organisation des cours de religion, de morale non confessionnelle ou de philosophie et de citoyenneté Section 1re - Régime général Modifié par D. 27-12-1993; D. 02-04-1996 ; D. 14-06-2001 ; D. 30-06-2006 ; D. 07-12-2007 ; D. 18-05-2012 ; D. 17-10-2013 (1) ; D. 11-04-2014 (3) ; D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 18, 'Article 7. - Le nombre total de périodes-professeurs qui peuvent être organisées', 'Article 7. - Le nombre total de périodes-professeurs qui peuvent être organisées 
par un établissement d''enseignement secondaire est la somme des différents nombres 
intermédiaires de périodes-professeurs. 
 
Les nombres intermédiaires de périodes-professeurs sont les nombres de périodes 
qui peuvent être organisées, par degré, par année ou par groupes d''années, 
respectivement : 
1° pour la formation commune; 
2° pour l''apprentissage des langues modernes comme outils de communication; 
3° pour les autres formations appelées ci-après formations optionnelles; 
4° pour la différenciation des rythmes d''apprentissage et la lutte contre l''échec 
scolaire. 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
L''Exécutif détermine les cours qui font partie de la formation commune, ceux qui 
font partie de la formation optionnelle et ceux qui font partie de l''apprentissage des 
langues modernes comme outils de communication. 
 
Le nombre de périodes-élèves est, pour un cours ou un ensemble de cours, le 
produit du nombre d''élèves par le nombre de périodes que l''Exécutif fixe en application 
de l''article 10, alinéa 5. 
 
Les nombres intermédiaires de périodes-professeurs sont calculés séparément 
pour les années ou groupes d''années suivants: 
1° la première année commune comme défini à l''article 4 du décret du 30 juin 2006 
relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire et 
deuxième année commune de l''enseignement de type I; 
2° la première année différenciée  de l''enseignement de type I; 
3° la deuxième année différenciée de l''enseignement de type I; 
4° le deuxième degré de l''enseignement de transition de type I; 
5° le deuxième degré de la section de qualification de l''enseignement technique ou 
de l''enseignement artistique de type I; 
6° le deuxième degré de l''enseignement professionnel de type I; 
7° le troisième degré de l''enseignement de transition de type I; 
8° le troisième degré de la section de qualification de l''enseignement technique ou 
de l''enseignement artistique de type I; 
9° le troisième degré de l''enseignement professionnel de type I; 
10° les deux premières années de l''enseignement de type II; 
11° les deux premières années de l''enseignement différencié  de type II; 
12° les troisième et quatrième années de l''enseignement général de type II; 
13° les troisième et quatrième années de l''enseignement technique de type II; 
14° les troisième et quatrième années de l''enseignement professionnel de type II; 
15° les cinquième et sixième années de l''enseignement général de type II; 
16° les cinquième et sixième années de l''enseignement technique de type II; 
17° les cinquième et sixième années de l''enseignement professionnel de type II; 
18° les septièmes années et les années préparatoires visées à l''article 13. 
19° le quatrième degré de l''enseignement professionnel secondaire complémentaire. 
20° le DASPA, tel que défini à l''article 2, 5°, du décret du 7 février 2019 visant à 
l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent pas la 
langue de l''enseignement dans l''enseignement organisé ou subventionné par la 
Communauté française [Abrogé par D. 17-10-2013 (1) ; rétabli par D. 24-02-2022] 
 
Sans préjudice de l''alinéa 1er de l''article 3 de l''Arrêté de l''Exécutif de la 
Communauté française du 31 août 1992, les élèves inscrits dans l''année 
supplémentaire au terme du premier degré visée au titre III du décret du 30 juin 2006 
relatif à l''organisation pédagogique du 1er degré de l''enseignement secondaire tel que 
modifié par le décret du 7 décembre 2007 organisant la différenciation structurelle au 
sein du premier degré afin d''amener l''ensemble des élèves à la maîtrise des socles de 
compétences, sont comptabilisés avec les élèves de première année commune comme 
défini à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du 
premier degré de l''enseignement secondaire et deuxième année commune de 
l''enseignement de type I. 
 
Inséré par D. 19-07-2017 ; modifié par D. 24-02-2022 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 19, 'Article 7 (partie 1)', 'Article 7/1. § 1er - Le mode de calcul du nombre de périodes pour l''organisation du cours de religion, de morale non confessionnelle et de philosophie et de citoyenneté lorsque les élèves sont dispensés du cours de religion ou de morale (RLMO) et du nombre de périodes pour l''organisation du cours de philosophie et de citoyenneté (CPC) visé à l''article 8, alinéa 4, de la loi du 29 mai 1959 modifiant certaines Secondaire IV.B.01 Lois 17144 D. 29-07-1992 dispositions de la législation de l''enseignement est fixé au chapitre III de l''arrêté de l''exécutif du 31 août 1992 exécutant le décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice pour les années ou groupes d''années suivants : 1. la première année commune visée à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du 1er degré ; 2. la deuxième année commune visée à l''article 4 du décret du 30 juin 2006 précité, y compris l''année supplémentaire visée à l''article 13, § 1er, du même décret ; 3. la première année différenciée visée à l''article 16, § 1er, du même décret, y compris le DASPA telle que définie à l''article 2, 5°, du décret du 7 février 2019 visant à l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent pas la langue de l''enseignement dans l''enseignement organisé ou subventionné par la Communauté française; 4. la deuxième année différenciée visée à l''article 16, § 1er, du décret du 30 juin 2006 précité ; 5. la troisième année spécifique de différenciation et d''orientation visée à l''article 19 du décret du 30 juin 2006 précité ; 6. la troisième année de l''enseignement général, la troisième année de l''enseignement technique de transition et la troisième année de l''enseignement artistique de transition ; 7. la troisième année de l''enseignement technique de qualification et la troisième année de l''enseignement artistique de qualification ; 8. la troisième année de l''enseignement professionnel ; 9. la quatrième année de l''enseignement général, la quatrième année de l''enseignement technique de transition y compris l''année de réorientation visée à l''article 4, § 1er, 2°, de l''arrêté royal du 29 juin 1984 relatif à l''organisation de l''enseignement secondaire, et la quatrième année de l''enseignement artistique de transition ; 10. la quatrième année de l''enseignement technique de qualification y compris l''année de réorientation visée à l''article 4, § 1er, 2°, de l''arrêté royal du 29 juin 1984 relatif à l''organisation de l''enseignement secondaire, et la quatrième année de l''enseignement artistique de qualification ; 11. la quatrième année de l''enseignement professionnel ; 12. la cinquième année de l''enseignement général, la cinquième année de l''enseignement technique de transition et la cinquième année de l''enseignement artistique de transition ; 13. la cinquième année de l''enseignement technique de qualification et la cinquième année de l''enseignement artistique de qualification ; 14. la cinquième année de l''enseignement professionnel ; 15. la sixième année de l''enseignement général, la sixième année de l''enseignement technique de transition et la sixième année de l''enseignement artistique de transition ; 16. la sixième année de l''enseignement technique de qualification y compris l''année complémentaire visée à l''article 3, § 6, du décret du 20 août 2012 organisant la certification par unités d''acquis d''apprentissage (CPU) dans l''enseignement secondaire qualifiant et modifiant diverses dispositions relatives à l''enseignement secondaire et la sixième année de l''enseignement artistique de qualification ; 17. la sixième année de l''enseignement professionnel y compris l''année complémentaire visée à l''article 3, § 6, du décret du 20 août 2012 organisant la certification par unités d''acquis d''apprentissage (CPU) dans l''enseignement secondaire qualifiant et modifiant diverses dispositions relatives à l''enseignement secondaire; 18. la 7ème année du 3ème degré l''enseignement technique de qualification ; 19. la 7ème année du 3ème degré de l''enseignement professionnel ; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 20. l''année préparatoire à l''enseignement supérieur paramédical visée à l''article 2, § 3, 2°, de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire ; 21. l''année préparatoire à l''enseignement professionnel secondaire complémentaire section «Soins Infirmiers» visée à l''article 2, § 4, de la loi du 19 juillet 1971 précitée. La somme des périodes calculées en application de l''article 14, alinéas 1 et 3, et de l''article 15 de l''arrêté de l''Exécutif du 31 août 1992 exécutant le décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice constituent le RLMOD des établissements visés au § 2. Chaque établissement bénéficie au minimum du nombre de périodes RLMOD qu''il génère. § 2. […] Annulé par la Cour constitutionnelle (arrêt n°51/2020 du 23-04-2020) avec maintien des effets jusque et y compris l');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 20, 'Article 7 (partie 2)', 'scolaire 2019-2020. § 3. En outre, lorsque les périodes octroyées en application des §§ 1er et 2 ne permettent pas d''attribuer, au sein de l''établissement, pour l''enseignement organisé par la Communauté française, ou au sein du Pouvoir organisateur, pour l''enseignement subventionné par la Communauté française, aux membres du personnel définitifs, temporaires prioritaires ou stagiaires un volume de périodes équivalent à leurs attributions au 30 juin 2017, conformément à l''ordre de priorité défini par la section VII du chapitre II du Titre III du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française et par les dispositions transitoires reprises au chapitre XI quater de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant et du chapitre X ter l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres et des professeurs de religion, pour l''enseignement organisé par la Communauté française, et, à défaut, conformément aux règles du statut administratif dont relève le membre du personnel, le chef d''établissement, pour l''enseignement organisé par la Communauté française, ou le Pouvoir organisateur, pour l''enseignement officiel subventionné et pour l''enseignement libre non confessionnel, introduit, auprès de l''Administration, un document justifiant qu''il utilise, pour ce faire, un nombre déterminé de périodes supplémentaires dont il précisera l''affectation par implantations conformément aux dispositions visées ci-après. Les périodes visées à l''alinéa précédent seront utilisées exclusivement pour permettre : 1) l''organisation d''activités, dans le cadre du cours de philosophie et de citoyenneté, au sein d''un même établissement, dont la mise en oeuvre concerne un public plus large qu''un groupe-classe. Ces périodes sont octroyées à raison de maximum 1 période par volume horaire de 6 périodes de philosophie et de citoyenneté organisées au sein du même établissement ; 2) l''organisation d''activités de coordination pédagogique ou de concertation entre membres du personnel en charge des cours de philosophie et de citoyenneté au sein d''une même année d''études ou d''années d''études différentes, dans le cadre du cours de philosophie et de citoyenneté ; 3) le dédoublement d''un groupe-classe de plus de 10 élèves suivant un cours de religion, de morale non confessionnelle ou de philosophie et de citoyenneté pour les élèves dispensés du cours de religion ou de morale non confessionnelle ; 4) l''affectation de deux enseignants à un groupe-classe de minimum 10 élèves suivant un cours de religion, de morale non confessionnelle ou de philosophie et de citoyenneté pour les élèves dispensés du cours de religion ou de morale non confessionnelle, ou suivant le cours de philosophie et de citoyenneté. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Des périodes supplémentaires sont également attribués au membre du personnel définitif, temporaire prioritaire ou stagiaire qui, malgré l''application préalable des dispositions énumérées ci-avant, n''a pas retrouvé un volume de charge horaire équivalent à ses attributions au 30 juin 2017 ou qui devrait effectuer des prestations dans plus de 6 implantations tous Pouvoirs organisateurs confondus. Ces périodes sont octroyées à l''établissement ou au Pouvoir organisateur, selon le cas, auprès duquel le volume de charge horaire du membre du personnel concerné est le plus important au 30 juin 2017. Le chef d''établissement, pour l''enseignement organisé par la Communauté française, ou le Pouvoir organisateur, pour l''enseignement officiel subventionné et pour l''enseignement libre non confessionnel, doit introduire auprès de l''administration un document justifiant de l''utilisation de ces périodes supplémentaires dont il précisera l''affectation par implantation conformément aux dispositions visées ci-après. Le membre du personnel concerné est affecté aux tâches suivantes : 1° organisation et surveillance d''activités au sein de la médiathèque de l''école ou d''une activité de remédiation ; 2° surveillance d''évaluations formatives et sommatives ; 3° accompagnement de groupes d''élèves dans des activités extérieures à l''établissement. L''utilisation de ces périodes supplémentaires est autorisée dès le premier jour de l''année scolaire et ce jusqu''au dernier jour de celle-ci. Cette utilisation est de la compétence du pouvoir organisateur dans l''enseignement subventionné par la Communauté française, et du chef d''établissement dans l''enseignement organisé par la Communauté française. Elle est soumise à l''avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 21, 'Article 7 (partie 3)', 'bureau de conciliation en cas de désaccord. Les services prestés dans le cadre des périodes supplémentaires visée au présent paragraphe sont en tous points assimilés aux services prestés dans le cadre organique. Les emplois ainsi créés peuvent donner lieu à nomination ou engagement à titre définitif. § 4. Le nombre total de périodes de religion et de morale non confessionnelle attribuées au 1er octobre 2014, par établissement visé aux §§ 2 et 3, multiplié par un facteur démographique, constitue le RLMOA de cet établissement, défini à l''arrondi mathématique. Ce facteur démographique est égal au nombre d''élèves du secondaire régulièrement inscrits au 1er octobre 2016 divisé par le nombre d''élèves du secondaire régulièrement inscrits au 1er octobre 2014. La différence entre le RLMOA de l''établissement et son RLMOD détermine un nombre de périodes. Ce nombre, positif ou négatif, est globalisé au niveau des services du Gouvernement de la Communauté française. Les établissements qui n''organisaient pas d''enseignement secondaire au 1er octobre 2014 ne génèrent aucune période à globaliser. De ce nombre de périodes globalisées visé à l''alinéa précédent sont automatiquement prélevées les périodes visées aux §§ 2 et 3. Le nombre de périodes restantes constituent le solde. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 § 5. Pour autant qu''il soit positif, le solde obtenu au § 4, alinéa 4, est attribué aux établissements visés au § 2, pour faciliter et coordonner la mise en oeuvre du cours de philosophie et de citoyenneté. Seuls les établissements qui contribuent positivement au nombre de périodes globalisé reçoivent des périodes en application de l''alinéa 1er. Ce nombre de périodes est égal au solde visé à l''alinéa précédent affecté d''un coefficient égal au rapport entre leur contribution positive au nombre de périodes globalisé et le nombre de périodes globalisé. Le résultat est arrondi à l''unité inférieure. L''utilisation des périodes visées à l''alinéa précédent est autorisée dès communication de leur nombre par les services du Gouvernement et jusqu''au dernier jour de l''année scolaire en cours. Cette utilisation est de la compétence du pouvoir organisateur dans l''enseignement subventionné par la Communauté française et du chef d''établissement dans l''enseignement organisé par la Communauté française, après avoir pris l''avis des organes de concertations locales. Seuls des fonctions de recrutement de la catégorie de personnel enseignant peuvent être activées dans le cadre ces périodes.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 22, 'Article 8. - Le nombre de périodes-professeurs pour les cours liés à la formation', 'Article 8. - Le nombre de périodes-professeurs pour les cours liés à la formation 
commune est obtenu en multipliant le nombre total d''élèves des degrés ou groupes 
d''années par un nombre que l''Exécutif fixe, et en divisant ce produit par les diviseurs 
qu''il assigne aux différentes tranches de population scolaire qu''il détermine.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 23, 'Article 9. - Dans les deux premières années de l''enseignement secondaire, ainsi', 'Article 9. - Dans les deux premières années de l''enseignement secondaire, ainsi 
que dans l''enseignement de transition de type I, et dans l''enseignement général de 
type II, le nombre de périodes-professeurs pour les cours liés à l''apprentissage des 
langues modernes comme outils de communication est obtenu en multipliant le 
nombre d''élèves inscrits à ces cours par un nombre que fixe l''Exécutif et en divisant ce 
produit par les diviseurs qu''il assigne aux différentes tranches de population scolaire 
qu''il détermine. 
 
Modifié par D. 27-12-1993; D. 10-04-1995; D. 02-04-1996 ; complété par D. 30-11-
2000 ; modifié par D. 30-06-2006 ; D. 07-12-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 24, 'Article 10. - En première année commune comme défini à l''article 4 du décret du', 'Article 10. - En première année commune comme défini à l''article 4 du décret du 
30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement 
secondaire et en deuxième année commune de l''enseignement secondaire de type I 
ainsi que dans les deux premières années de l''enseignement de type II, le nombre de 
périodes-professeurs pour les cours liés à la formation optionnelle est fixé par 
l''Exécutif. 
 
Dans les autres degrés ou groupes d''années de l''enseignement de transition de 
type I ou de l''enseignement général de type II, l''Exécutif détermine le nombre de 
périodes-élèves dans les cours liés à la formation optionnelle en distinguant : 
1° les cours de laboratoire organisés dans le cadre ou en complément de cours de 
sciences constituant un cours de la formation commune comprenant quatre périodes 
hebdomadaires au moins ou une option simple ou une option groupée, à raison d''un 
nombre de périodes par élève que fixe l''Exécutif, respectivement pour l''enseignement 
général et pour l''enseignement technique; 
2° l''ensemble des cours spéciaux de dactylographie ou de traitement de texte 
ainsi que l''ensemble des cours d''informatique de gestion, de travaux dirigés 
d''économie appliquée, ou de cours que, sous des intitulés différents, l''Exécutif 
reconnaît comme assimilés aux précédents, s''ils sont organisés en complément d''un 
cours de sciences économiques constituant une option simple, avec un maximum de 
périodes par élève que fixe l''Exécutif; 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
3° les cours faisant partie d''une option groupée reconnue par l''Exécutif comme 
Formation de transition à dominante technologique, à raison d''un nombre de périodes 
par élève que l''Exécutif détermine; 
4° les cours faisant partie d''une option groupée reconnue par l''Exécutif comme 
formation de transition à dominante économique, à raison d''un nombre de périodes 
par élève que l''Exécutif détermine; 
5° les autres cours de la formation optionnelle. 
6° les cours faisant partie d''une option groupée reconnue par le Gouvernement 
comme formation de transition à dominante artistique, à raison d''un nombre de 
périodes par élève que le Gouvernement détermine. 
 
Le Gouvernement réduit le nombre de périodes-élèves pour les élèves qui 
poursuivent une partie de leur formation dans l''enseignement artistique à horaire 
réduit. 
 
Pour les degrés et groupes d''années de la section de qualification de 
l''enseignement technique ou de l''enseignement artistique de type I, de l''enseignement 
technique de type II et de l''enseignement professionnel, l''Exécutif détermine le 
nombre de périodes-élèves dans les cours liés à la formation optionnelle, y compris les 
cours liés à l''apprentissage des langues modernes comme outils de communication, en 
distinguant : 
1° un ensemble de cours dont l''Exécutif admet le comptage séparé en raison des 
exigences spécifiques qu''ils présentent en matière de sécurité, d''équipement et de 
formation; 
2° les autres cours de la formation optionnelle. 
 
Pour 
le 
quatrième 
degré 
de 
l''enseignement 
professionnel 
secondaire 
complémentaire, section "soins infirmiers", le Gouvernement détermine le nombre de 
périodes-élèves dans les cours liés à la formation optionnelle en distinguant: 
a) les cours relevant de l''enseignement clinique; 
b) les autres cours. 
 
Pour l''application des alinéas 2 à 5, le nombre de périodes-professeurs est le 
quotient des différents nombres de périodes-élèves par les diviseurs que l''Exécutif fixe 
selon les tranches de population scolaire qu''il détermine. 
 
Le Gouvernement peut attribuer des périodes-professeur supplémentaires aux 
établissements organisant l''option "Danse" dans l''enseignement artistique afin de 
permettre l''accompagnement musical des activités avec un maximum de 8 périodes-
professeur par année d''études et de 24 périodes-professeur par établissement. 
 
Les élèves qui suivent un cours de formation scientifique à raison de 5 périodes 
hebdomadaires au deuxième degré ou de 6 périodes hebdomadaires au troisième degré 
sont considérés comme suivant deux périodes hebdomadaires de cours de laboratoire. 
 
Complété par D. 02-04-1996; D. 25-07-1996 ; D. 30-06-2006 ; modifié par D. 07-12-
2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 25, 'Article 11. - Pour la différenciation des rythmes d''apprentissage et la lutte', 'Article 11. - Pour la différenciation des rythmes d''apprentissage et la lutte 
contre l''échec scolaire, le nombre de périodes-professeurs est augmenté d''une fraction 
de période par élève que l''Exécutif fixe, en distinguant éventuellement des tranches de 
population scolaire : 
1° au deuxième degré de l''enseignement professionnel de type I ainsi que dans les 
troisième et quatrième années de l''enseignement professionnel de type II; 
2° en première année commune comme défini à l''article 4 du décret du 30 juin 
2006 relatif à l''organisation pédagogique du premier degré de l''enseignement 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
secondaire et en deuxième année commune de l''enseignement secondaire de type I et 
dans les deux premières années de l''enseignement secondaire de type II; 
3° en deuxième année différenciée de l''enseignement secondaire. 
 
Chaque établissement établit, au plus tard à la date du 15 janvier, un rapport 
circonstancié sur l''utilisation des périodes-professeur obtenues sur la base des 
dispositions de l''alinéa 1er et le transmet, avant le 31 janvier, au ministre ayant 
l''enseignement secondaire dans ses attributions. 
 
Modifié par D. 07-12-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 26, 'Article 12. - Par dérogation aux articles 8 à 11 :', 'Article 12. - Par dérogation aux articles 8 à 11 : 
1° dans la première année différenciée organisée dans l''enseignement secondaire 
de type I, le nombre de périodes-professeurs est obtenu en multipliant le nombre 
d''élèves par un nombre que l''Exécutif fixe et en divisant ce produit par les diviseurs 
qu''il assigne aux différentes tranches de population scolaire qu''il détermine. 
2° en deuxième année différenciée de l''enseignement secondaire de type I ainsi 
que dans les deux premières années de l''enseignement secondaire différencié de type 
II, le nombre de périodes-professeurs est obtenu en multipliant le nombre d''élèves par 
un nombre que l''Exécutif fixe et en divisant ce produit par les diviseurs qu''il assigne 
aux différentes tranches de population scolaire qu''il détermine. 
 
Complété par D. 02-04-1996');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 27, 'Article 13. - Par dérogation aux articles 8 à 11, dans les années énumérées ci-', 'Article 13. - Par dérogation aux articles 8 à 11, dans les années énumérées ci-
après et selon les spécificités de chacune, le nombre de périodes-professeurs est obtenu 
en multipliant le nombre d''élèves par le nombre de périodes que l''Exécutif fixe et en 
divisant ce produit par les diviseurs que l''Exécutif fixe pour les différentes tranches de 
périodes-élèves qu''il détermine. 
 
Les années visées à l''alinéa 1er sont: 
1° la septième année préparatoire à l''enseignement supérieur; 
2° la septième année de perfectionnement ou de spécialisation de l''enseignement 
technique de qualification; 
3° la septième année de perfectionnement ou de spécialisation de l''enseignement 
professionnel; 
4° la septième année organisée au terme du troisième degré de l''enseignement 
professionnel en vue de délivrer le certificat d''enseignement secondaire supérieur sans 
que soit en outre délivré un certificat de qualification. 
5° l''année 
préparatoire 
à 
l''enseignement 
professionnel 
secondaire 
complémentaire du quatrième degré; 
6° l''année préparatoire à l''enseignement  supérieur paramédical. 
 
Modifié par D. 02-04-1996 ; D. 07-12-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 28, 'Article 14. - § 1er. Les diviseurs visés aux articles 8, 9, 10, 12 et 13 ne peuvent', 'Article 14. - § 1er. Les diviseurs visés aux articles 8, 9, 10, 12 et 13 ne peuvent 
être inférieurs à 10 ni supérieurs à 24. 
 
§ 2. L''encadrement attribué aux deux premières années de l''enseignement 
secondaire est plus favorable que l''encadrement attribué au deuxième et au troisième 
degrés de l''enseignement de transition. 
 
§ 3. Le diviseur attribué à la première année différenciée est fixé à 10 pour la 
première tranche de population scolaire. Pour les autres tranches, il ne peut être 
supérieur à 14. 
 
Le diviseur attribué à la deuxième année différenciée ne peut être supérieur à 14. 
Une tranche de population scolaire bénéficie d''un diviseur qui ne peut être supérieur à 
12. 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
§ 4. Le diviseur attribué pour la formation optionnelle dans l''enseignement 
professionnel et dans l''enseignement technique de qualification est fixé à 10 pour la 
première tranche de périodes-élèves. Le même diviseur est retenu pour l''ensemble des 
cours à comptage séparé visés à l''article 10, alinéa 4. 
 
Le diviseur attribué à la formation commune au deuxième degré de 
l''enseignement professionnel ne peut être supérieur à 18. Une tranche de population 
scolaire bénéficie d''un diviseur qui ne peut être supérieur à 14. 
 
§ 5. La somme des nombres fixés par l''Exécutif en application des articles 8 et 9 
et du nombre de périodes qui détermine le nombre de périodes-élèves fixé en 
application de l''article 10 ne peut être inférieure à 30 ni supérieure à 34. 
 
Les nombres fixés par l''Exécutif en application des articles 12 et 13 ne peuvent 
être inférieurs à 30 ni supérieurs à 34. Toutefois, au quatrième degré de 
l''enseignement professionnel secondaire complémentaire, le nombre ne peut être 
supérieur à 36. 
 
Les fractions de période par élève fixées par l''Exécutif en application de l''article 
11 ne peuvent être inférieures à un vingtième ni supérieures à six vingtièmes.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 29, 'Article 15. - § 1er. L''Exécutif fixe un encadrement minimum en tenant compte', 'Article 15. - § 1er. L''Exécutif fixe un encadrement minimum en tenant compte 
de la taille de l''établissement et de sa structure, pour les établissements situés à plus 
de 12 km d''un autre établissement de même caractère ou dans des communes dont la 
densité de population est inférieure à 125 habitants au km2 et qui comptent: 
1° moins de 450 élèves s''ils organisent les trois degrés; 
2° moins de 350 élèves s''ils n''organisent que les deux premiers degrés; 
3° moins de 300 élèves s''ils organisent uniquement le deuxième et le troisième 
degré ou le seul premier degré; 
4° moins de 550 élèves s''ils organisent les trois degrés et les trois formes 
d''enseignement au second et au troisième degrés; 
5° moins de 350 élèves s''ils organisent uniquement le second et le troisième 
degrés et les trois formes d''enseignement dans ces deux degrés. 
 
Le présent paragraphe n''est pas applicable lorsque la population scolaire totale 
des établissements de même réseau situés sur le territoire de la même commune est 
supérieure à 1200 élèves. 
 
§ 2. L''Exécutif peut déroger aux règles fixées à l''article 9 tant en matière de 
diviseurs qu''en matière de tranches de population scolaire pour les cours liés à 
l''apprentissage des langues modernes comme outils de communication en faveur des 
établissements situés dans les communes visées à l''article 3, 3° et 4°, de la loi du 30 
juillet 1963 concernant le régime linguistique dans l''enseignement et qui comptent: 
1° moins de 450 élèves s''ils organisent les trois degrés; 
2° moins de 350 élèves s''ils n''organisent que les deux premiers degrés; 
3° moins de 300 élèves s''ils organisent uniquement le deuxième et le troisième 
degré ou le seul premier degré; 
4° moins de 550 élèves s''ils organisent les trois degrés et les trois formes 
d''enseignement au second et au troisième degrés; 
5° moins de 350 élèves s''ils organisent uniquement le second et le troisième 
degrés et les trois formes d''enseignement dans ces deux degrés. 
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Inséré par D. 12-07-2012(1) ; modifié par D. 24-05-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 30, 'Article 15 / Article 15', 'Article 15/1. – […] Abrogé par D. 20-07-2022. 
 
Inséré par D. 20-07-2022

Article 15/2. - Pour le calcul des périodes-professeur, les élèves qui effectuent le 
dispositif de fin de parcours complémentaire au troisième degré de qualification visé à 
l''article 11, § 3, du décret 20 juillet 2022 relatif au parcours d''enseignement qualifiant 
(PEQ) sont pris en compte à concurrence de 1,25 période par élève régulièrement 
inscrit au 1er octobre. Ces périodes sont mobilisables dès le 1er septembre et seront 
utilisées, dans le respect des dispositions statutaires applicables, pour l''encadrement 
de cours prévus à la grille-horaire des élèves et de la remédiation en vue de la 
délivrance de l''un des certifications visées à l''article 4, § 1er, alinéa 3, du décret 20 
juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ). 
 
Inséré par D. 15-12-2010');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 31, 'Article 15bis.  – […] abrogé par D. 03-05-2012', 'Article 15bis.  – […] abrogé par D. 03-05-2012 
 
Modifié par D. 27-10-1994 ; abrogé par D. 30-06-1998 ; rétabli par D. 12-12-2008 ; 
modifié par D. 13-01-2011 ; D 11-04-2014 ; D. 04-02-2016 ; complété par D.14-06-2018 ; 
modifié par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 32, 'Article 16. - § 1er Indépendamment du nombre total de périodes-professeur, il', 'Article 16. - § 1er Indépendamment du nombre total de périodes-professeur, il 
est attribué, par année scolaire, pour tous les établissements d''enseignement 
secondaire organisant soit un premier degré commun et un premier degré différencié 
ou une année constitutive de ce dernier degré soit l''un des deux degrés précités, des 
périodes complémentaires destinées à assurer des conseils de classe, des conseils de 
guidance, des remédiations ou des projets favorisant la liaison entre l''enseignement 
primaire et secondaire.  
 
En fonction du nombre d''élèves régulièrement inscrits au 15 janvier de l''année 
scolaire précédente, les périodes sont calculées de la manière suivante :  
1° En 1re et 2e année commune : 0,5 période-professeur par tranche de 12 élèves;  
2° En 1re et 2ème année différenciée : 0,5 période-professeur par tranche de 6 
élèves;  
3° […] abrogé par D. 11-04-2014 
4° Dans l''année supplémentaire organisée au terme du 1er degré : 0,5 période-
professeur par tranche de 6 élèves;  
5° […] abrogé par D. 11-04-2014 
6° En troisième année de différenciation et d''orientation : 0,5 période-professeur 
par tranche de 7 élèves.  
 
Lorsque le montant global obtenu par chaque établissement suite à la répartition 
visée à l''alinéa 2 n''est pas un nombre entier, ce dernier est arrondi à l''unité 
supérieure, et dans tous les cas, un minimum de 6 périodes-professeur est octroyé à 
chaque établissement.  
 
L''utilisation du nombre de périodes-professeurs complémentaires est soumise à 
l''avis préalable, dans l''enseignement organisé par la Communauté française, du 
comité de concertation de base, dans l''enseignement officiel subventionné par la 
Communauté française, de la commission paritaire locale, et dans l''enseignement libre 
subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la 
délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de 
désaccord.  
 
A titre transitoire pour l''année scolaire 2008-2009, la disposition prévue à l''alinéa 
1er, 3°, s''applique à la deuxième année professionnelle.  
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Au cas où un chef d''établissement dans l''enseignement organisé par la 
Communauté française ou un Pouvoir organisateur dans l''enseignement subventionné 
n''organise plus le premier degré commun ou le premier degré différencié ou une année 
constitutive de l''un ou des deux degrés précités, la ou les périodes octroyées sur base 
de l''alinéa 1er du présent article doivent être utilisées prioritairement dans l''une des 
années constitutives du premier degré ou de la troisième année de différenciation et 
d''orientation. 
Inséré par D. 14-06-2018 
§ 2. Indépendamment du nombre global de périodes-professeur, il est attribué, 
par année scolaire, pour tous les établissements d''enseignement secondaire organisant 
un premier degré commun, quatre mille cinq cents périodes diminuées du nombre de 
périodes obtenues l''année scolaire précédente par l''ensemble des établissements 
scolaires en application de l''article 11, § 1er, 2° et 3° de l''arrêté de l''Exécutif de la 
Communauté française du 31 août 1992 exécutant le présent décret et pour lesquels 
soit la première ou la deuxième année différenciée compte moins de six élèves, soit la 
première et la deuxième année différenciée comptent moins de douze élèves. 
 
Les périodes visées à l''alinéa précédent sont affectées à l''organisation de la 
remédiation et de l''année supplémentaire organisée au terme du premier degré. 
 
Les périodes sont réparties entre les établissements scolaires concernés sur la 
base du nombre d''élèves régulièrement inscrits au 15 janvier de l''année scolaire 
précédente au sein du premier degré commun dans chaque établissement. 
 
Inséré par D. 14-06-2018 
§ 3. L''utilisation des périodes dévolues à chaque établissement scolaire en 
application du paragraphe 2 du présent article est soumise à l''avis préalable, dans 
l''enseignement organisé par la Communauté française, du comité de concertation de 
base, dans l''enseignement officiel subventionné par la Communauté française, de la 
commission paritaire locale, et dans l''enseignement libre subventionné par la 
Communauté française, du conseil d''entreprise ou, à défaut, de la délégation 
syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. 
 
Inséré par D. 26-03-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 33, 'Article 16bis. – […] Abrogé par D. 12-12-2018 / Article 16ter. - Indépendamment du nombre total de périodes-professeur, il est', 'Article 16bis. – […] Abrogé par D. 12-12-2018 
 
Inséré par D. 17-10-2013 (2) ; complété par D. 13-07-2016 ; D. 14-03-2019

Article 16ter. - Indépendamment du nombre total de périodes-professeur, il est 
attribué, par année scolaire, pour tous les établissements d''enseignement secondaire 
organisant des classes bilingues français-langue des signes telles que définies à 
l''article 2, 1°, du décret relatif à l''organisation pédagogique du 1er degré de 
l''enseignement secondaire du 30 juin 2006, sur la base du nombre d''élèves 
régulièrement inscrits sourds ou malentendants, au 1er octobre de l''année scolaire en 
cours : 
a) 8 périodes par élève sourd ou malentendant fréquentant une classe bilingue 
français - langue des signes; 
b) 2 périodes par classe bilingue français-langue des signes réservées au cours de 
langue des signes et de culture des sourds. 
 
Les périodes visées à l''alinéa 1er, a, b, entrent en considération pour l''engagement 
à titre définitif des membres du personnel.  
 
Indépendamment du nombre total de périodes-professeur, il est attribué, par 
année scolaire, pour tous les établissements d''enseignement secondaire organisant des 
classes bilingues français-langue des signes au deuxième degré et au troisième degré 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
de l''enseignement secondaire ordinaire 8 périodes par élève sourd ou malentendant 
fréquentant une classe bilingue français - langue des signes. [Inséré par D. 13-07-2016] 
 
Sans préjudice à l''alinéa précédent, pour permettre l''enseignement en co-
titulariat en langue des signes et en français de l''ensemble des cours, il est accordé, 
par classe organisée, 10 périodes complémentaires si la classe ne comporte que deux 
élèves en immersion bilingue «français-langue des signes. [Inséré par D. 13-07-2016] 
 
 
Les périodes visées aux troisième et quatrième alinéas entrent en considération 
pour l''engagement à titre définitif des membres du personnel. [Inséré par D. 13-07-2016] 
 
Inséré par D. 13-07-2016 (M.B. 09-12-2016)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 34, 'Article 16quater.', 'Article 16quater. § 1er. Dans l''enseignement organisé par la Communauté 
française, sur demande du chef d''établissement, après avoir pris l''avis du conseil de 
participation et après consultation préalable du comité de concertation de base, le 
Gouvernement peut autoriser un établissement à organiser l''ensemble des cours et 
activités pédagogiques de la grille-horaire dans le cadre de classes bilingues français-
langue des signes. 
 
Dans l''enseignement subventionné, le Gouvernement peut autoriser un pouvoir 
organisateur à assurer dans un des établissements qu''il organise l''ensemble des cours 
et activités pédagogiques de la grille-horaire dans le cadre de classes bilingues 
français-langue des signes. La demande est accompagnée de l''avis du conseil de 
participation et du résultat de la consultation préalable de la Commission paritaire 
locale pour les établissements d''enseignement officiel subventionné par la 
Communauté française, du conseil d''entreprise, ou à défaut, de l''instance de 
concertation locale, ou à défaut des délégations syndicales pour les établissements 
d''enseignement libre subventionné par la Communauté française. 
 
Par école concernée aux 2ème et 3ème degrés, un minimum de 4 périodes 
hebdomadaires identifiées parmi les cours de langue française, de langue des signes 
et/ou de langue moderne 1 et/ou de langue moderne 2 doit être assuré par des 
enseignants de culture sourde, à défaut de pouvoir attribuer ces périodes à des 
enseignants de culture sourde, ces cours peuvent être dispensés par des enseignants 
disposant des titres tels que précisés à l''arrêté du Gouvernement de la Communauté 
française du 5 juin 2014 relatif aux fonctions, titres de capacité et barèmes portant 
exécution des articles 7, 16, 50 et 263 du décret du 11 avril 2014 réglementant les 
titres et fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française. 
 
Lorsqu''une école ou une implantation organise des classes bilingues français-
langue des signes, cette organisation est intégrée dans le projet d''établissement. 
 
§ 2. L''élève aborde l''apprentissage par immersion en langue des signes en classe 
bilingue français-langue des signes au niveau de la première année de l''enseignement 
secondaire. Cet apprentissage par immersion en langue des signes en classe bilingue 
français-langue des signes s''inscrit dans le continuum pédagogique relatif à 
l''apprentissage par immersion en langue des signes en classe bilingue français-langue 
des signes développé dans l''enseignement fondamental, quel que soit l''établissement. 
 
Par dérogation à l''alinéa précédent, le conseil de classe peut autoriser un élève à 
aborder cet apprentissage après la 1ère année de l''enseignement secondaire pour 
autant qu''il apporte la preuve d''une maîtrise des compétences nécessaires en langue 
des signes. 
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Une école secondaire qui commence à organiser l''apprentissage par immersion en 
langue des signes en classe bilingue français-langue des signes le fait de manière 
progressive du début de la première année et garantit qu''un élève ayant entamé 
l''apprentissage par immersion puisse poursuivre cet apprentissage durant la suite de 
sa scolarité au sein du même établissement. 
 
Par dérogation à l''alinéa précédent, une école secondaire peut organiser 
l''apprentissage par immersion en langue des signes en classe bilingue français-langue 
des signes à partir du deuxième degré si elle n''organise que les deuxième et troisième 
degrés de l''enseignement secondaire. Elle garantit qu''un élève ayant entamé 
l''apprentissage par immersion puisse poursuivre cet apprentissage durant la suite de 
sa scolarité au sein du même établissement. 
 
Inséré par D. 03-05-2019 ; modifié par D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 35, 'Article 16quater', 'Article 16quater/1. - Lorsqu''il sera nécessaire de valoriser des périodes 
professeurs attribuées à des établissements scolaires, la méthode décrite ci-dessous 
pourra être appliquée. 
6 catégories de périodes sont envisagées : 
- périodes attribuées au degré inférieur (DI) aux professeurs de cours généraux 
(CG); 
- périodes attribuées au DI aux professeurs de cours techniques et artistiques 
(CT+CA); 
- périodes attribuées au DI aux professeurs de pratique professionnelle (PP); 
- périodes attribuées au degré supérieur (DS) aux professeurs de cours généraux 
(CG); 
- périodes attribuées au DS aux professeurs de cours techniques et artistiques 
(CT+CA); 
- périodes attribuées au DS aux professeurs de pratique professionnelle (PP). 
 
Pour chacune des catégories, les services de l''administration calculent 
annuellement un coût moyen de la période selon la méthode suivante : 
- pour les différentes catégories de périodes, le coût annuel moyen d''un équivalent 
temps plein (ETP) est calculé. Le coût annuel moyen d''un ETP est alors divisé par le 
nombre de périodes associé à un ETP de la catégorie concernée pour donner le coût 
annuel moyen de la période; 
- pour calculer le coût annuel moyen d''un ETP par type de cours, on prend en 
compte les barèmes pour les membres du personnel engagés à titre définitif et les 
barèmes pour les membres du personnel engagés à titre temporaire. Ces barèmes sont 
pris à l''ancienneté moyenne calculée des ETP recensés dans les listings de paiement. 
Ces barèmes sont multipliés par le nombre d''ETP visés et divisés par le nombre total 
d''ETP du type de cours concerné. Le total des barèmes ainsi calculés représente le coût 
annuel moyen d''un ETP du type de cours concerné; 
- sur cette base, le coût moyen de la période au DI est le résultat de la moyenne 
arithmétique entre le coût des CG, des CT+CA et des PP. Il en est de même pour le 
DS. 
 
Les services de l''administration calculent le coût annuel moyen de la période 
dans chacune des 6 catégories décrites plus haut pour le dernier jour de chaque année 
scolaire au plus tard. Ce coût annuel moyen des périodes est utilisé pour les périodes 
attribuées au cours de l''année scolaire qui suit. 
 
Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 36, 'Article 16quinquies.- Dans l''enseignement secondaire, l''apprentissage par', 'Article 16quinquies.- Dans l''enseignement secondaire, l''apprentissage par 
immersion en langue des signes en classe bilingue français-langue des signes est 
assuré par des professeurs de cours généraux chargés des cours d''apprentissage par 
immersion en langue des signes. 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Les moyens de fonctionnement peuvent permettre l''engagement d''interprètes 
sous contrat de travail à durée déterminée, sous contrat de prestation de services ou 
sous contrat de collaboration. 
 
Inséré par D. 13-07-2016(1) ; complété et modifié par D. 14-06-2018 ; D. 14-03-
2019 ; D. 14-07-2021 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 37, 'Article 16sexies - Dès le premier jour de l''année scolaire, le Gouvernement (partie 1)', 'Article 16sexies - Dès le premier jour de l''année scolaire, le Gouvernement attribue, dans le strict respect des conditions énumérées à l''alinéa 2 de la présente disposition, des périodes supplémentaires à des établissements qui créent une ou des classes supplémentaires en 1ère année commune ou en 1ère année différenciée, en fonction d''une disponibilité de locaux dans une de ses implantations, dans les zones ou parties de zones visées à l''article 6, § 2. Un établissement d''enseignement secondaire ordinaire peut se voir accorder, dès le premier jour de l''année scolaire 30 périodes-professeur supplémentaires par tranche de 22 élèves supplémentaires en 1ère année commune par rapport au comptage du 15 janvier de la même année dans la même implantation, pour autant que les conditions cumulatives suivantes soient réunies : - pour la 1re année commune, avoir annoncé à la CIRI, instaurée par l''article 79/28 du décret du 24 juillet 1997 définissant les missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire et organisant les structures propres à les atteindre, pour le troisième jour ouvrable après le 15 août de l''année scolaire précédente au plus tard, l''ouverture d''au moins 22 places supplémentaires en 1re année commune dans une implantation par rapport à la déclaration qui a été introduite pour le 31 janvier de l''année scolaire précédente au plus tard, - comptabiliser, sur la (les) implantation(s) concernée(s), à la date du premier jour de l''année scolaire en cours, en 1re année commune, au moins 22 élèves supplémentaires inscrits par rapport au nombre d''élèves régulièrement inscrits en 1re année commune au 15 janvier de l''année scolaire précédente, déduction faite du nombre d''élèves imposés par la CIRI (injonction) le premier lundi suivant la rentrée scolaire de l''année scolaire précédente, - organiser effectivement une classe supplémentaire identifiée comme telle par rapport au nombre de classes organisées au 15 janvier de l''année scolaire précédente, - l''augmentation ne résulte pas d''une restructuration avec un autre établissement. Un établissement d''enseignement secondaire ordinaire peut se voir accorder, dès le premier jour de l''année scolaire, 30 périodes-professeur supplémentaires par tranche de 12 élèves supplémentaires en 1ère année différenciée par rapport au comptage du 15 janvier de la même année dans la même implantation, pour autant que les conditions cumulatives suivantes soient réunies : - comptabiliser, sur la (les) implantation(s) concernée(s), à la date du premier jour de l''année scolaire en cours, en 1ère année différenciée, au moins 12 élèves supplémentaires, - organiser effectivement une classe supplémentaire identifiée comme telle par rapport au nombre de classes organisées au 15 janvier de l''année scolaire précédente, - l''augmentation ne résulte pas d''une restructuration avec un autre établissement. Les périodes attribuées en application des alinéas 2 et 3 ne sont plus attribuées en cas de recomptage au 1er octobre de l''année scolaire en cours. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 La demande de bénéficier de ces 30 périodes professeur supplémentaires doit être introduite auprès des services du Gouvernement avant le 5e jour scolaire ouvrable du mois de septembre. Inséré par D. 14-06-2018 ; complété par D. 14-07-2021 Par dérogation à l''alinéa 1er, le Gouvernement attribue 30 périodes par tranche de 22 élèves supplémentaires en 1ère année commune à des établissements qui bien que ne se situant pas dans des zones ou parties de zone visées à l''article 6, § 2, remplissent les conditions visées à l''alinéa 2 et disposent encore, à la date du 15 juillet et après attribution des places générées par l''ouverture de la classe, d''au moins 10 élèves en liste d''attente. La condition de disposer à la date du 15 juillet d''au moins 10 élèves en liste d''attente après attribution des places générées par l''ouverture de la classe ne s''applique pas pour l''année scolaire 2021-2022. Pour l''année scolaire 2021-2022, l''alinéa 2 du présent article est remplacé par : Un établissement d''enseignement secondaire ordinaire peut se voir accorder, dès le 1er septembre 2021, 30 périodes-professeur supplémentaires, par tranche de 22 élèves supplémentaires en 1ère année commune par rapport au nombre de périodes prévues en conséquence de la déclaration du nombre de places et de classes au 29 janvier 2021 dans la même implantation, pour autant que les conditions cumulatives suivantes soient réunies: - pour la 1ère année commune, avoir annoncé à la CIRI, instaurée par l''article 79/28 du décret du 24 juillet 1997 définissant les missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire et organisant les structures propres à les atteindre, pour le 18 août 2021 au plus tard, l''ouverture d''au moins 22 places supplémentaires en 1re année commune dans une implantation par rapport à la déclaration qui a été introduite pour le 29 janvier 2021 au plus tard; - comptabiliser, à la d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 38, 'Article 16sexies - Dès le premier jour de l''année scolaire, le Gouvernement (partie 2)', 'du 1er septembre 2021, en 1ère année commune, au moins 22 élèves supplémentaires inscrits par rapport au nombre de places déclarées renseignées dans la déclaration initiale introduite pour le 29 janvier 2021; - l''augmentation ne résulte pas d''une restructuration avec un autre établissement. Inséré par D. 11-10-2018 ; modifié par D. 18-12-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 39, 'Article 16sexies', 'Article 16sexies/1. - § 1er. Pour les années scolaires 2019-2020 et 2020-2021, un 
maximum de 1350 périodes-professeur par année scolaire est octroyé à des 
établissements d''enseignement secondaire organisant un premier degré. Ces périodes 
sont destinées à la constitution d''une équipe de trois à cinq professeurs issus du 1er 
degré, à raison de 2 périodes par professeur et d''une période attribuée à l''un de ces 
professeurs pour la coordination de l''équipe, afin de développer, en 1re ou 2e année 
commune, des outils et des pratiques de différenciation et de remédiation, tant dans la 
classe que durant des périodes spécialement dédiées à l''accompagnement personnalisé 
d''élèves. 
 
Elles sont attribuées au 1er septembre, selon des modalités arrêtées par le 
Gouvernement. 
 
§ 2. L''équipe visée au § 1 collabore avec des chercheurs issus d''universités ou de 
hautes écoles, à raison d''un maximum de 10 équipes par chercheur. 
 
§ 3. Pour les années scolaires 2019-2020 et 2020-2021, les établissements visés 
au § 1er bénéficient d''une période-professeur par tranche de 20 élèves régulièrement 
inscrits en 1re année commune au 15 janvier, à concurrence d''un maximum de 1250 
périodes. Ces périodes sont destinées à assurer un accompagnement personnalisé des 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
élèves de 1re année commune nécessitant une prise en charge en fonction de leurs 
besoins, ou des projets en groupes restreints ou à plus grande échelle. 
 
La manière dont les périodes concernées sont utilisées doit être détaillée dans le 
plan de pilotage ou le plan d''action collective du premier degré. 
 
§ 4. Pour soutenir, accompagner et coordonner les actions des acteurs visés au § 1 
et § 3, le Gouvernement est chargé de créer un comité de coordination, présidé par 
l''Administration, dont il fixe les missions, les modalités de fonctionnement, et la 
composition. 
 
§ 5. Le comité de coordination visé au § 4 prévoit les modalités de suivi et de 
monitoring de la mise en oeuvre du dispositif visé au § 1er. Pour le 15 septembre 2020 
et le 15 mai 2021 au plus tard, les chercheurs transmettent au comité de coordination 
un rapport d''évaluation sur la mise en oeuvre dans les établissements scolaires 
concernés des dispositions d''accompagnement personnalisé des élèves. 
 
§ 5bis. Le comité de coordination est soutenu par la cellule de support créée en 
vertu de l''art.4bis, § 5 du décret du 14 mars 1995 relatif à la promotion d''une école de 
la réussite dans l''enseignement fondamental, aux fins de la mise en oeuvre et de 
l''évaluation du dispositif. 
 
§ 6. Le Gouvernement évalue la mise en oeuvre du présent article et en fait 
rapport au Parlement au cours de l''année 2020-2021. 
 
Inséré par D. 12-12-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 40, 'Article 16sexies', 'Article 16sexies/2. - Deux 
périodes-professeurs 
sont 
attribuées 
aux 
établissements qui accueillent, au 1er octobre, entre dix et vingt élèves disposant d''un 
des statuts accordés par le Ministre ayant le sport dans ses attributions, et qui 
remplacent des périodes de cours par des périodes d''entraînement sportif visées à 
l''article 1er, § 3, 2°, de l''arrêté royal du 29 juin 1984 relatif à l''organisation de 
l''enseignement secondaire. 
 
Deux périodes-professeurs supplémentaires sont en outre octroyées par tranche 
entamée de 20 élèves sous statut, dans le respect de la condition prévue à l''alinéa 1er. 
 
Ces périodes sont destinées à l''encadrement des élèves sous statut par un 
membre du personnel référent. 
 
Section 2. Encadrement minimum de base 
 
Modifié par D. 07-12-2007');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 41, 'Article 17. - Dans les établissements organisant un enseignement secondaire de', 'Article 17. - Dans les établissements organisant un enseignement secondaire de 
type I, le nombre de périodes-professeurs obtenu en application des articles 8 à 14 est 
augmenté de manière à atteindre les minima que fixe l''Exécutif. 
 
A l''exception des premiers degrés commun ou différencié, des années 
constitutives de ceux-ci et de l''année de différenciation et d''orientation visée à l''article 
19, intégré par le décret du 7 décembre 2007 organisant la différenciation structurelle 
au sein du premier degré afin d''amener l''ensemble des élèves à la maîtrise des socles 
de compétences dans le décret du 30 juin 2006 relatif à l''organisation pédagogique du 
premier degré de l''enseignement secondaire, l''alinéa 1er n''est pas applicable pendant 
les deux premières années de la création d''une option, d''une année ou d''un degré ni 
pendant les deux premières années de la réouverture d''une option prévue à l''article 
19. 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Section 3. Minima de population scolaire 
 
Modifié par D. 02-04-1996 ; complété par D. 30-11-2000 ; modifié par D. 17-10-2013 
(1) ; complété par D. 03-04-2014 ; D. 04-02-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 42, 'Article 18. - L''Exécutif fixe des minima de population par degré, par cycle, par', 'Article 18. - L''Exécutif fixe des minima de population par degré, par cycle, par 
année, par groupe d''années, par section ou par option: 
1° pour tout établissement organisant un enseignement secondaire, qui réunit les 
conditions suivantes: 
a) être le seul établissement d''enseignement du caractère concerné de la 
commune à organiser le degré et la forme d''enseignement concerné; 
b) être situé à plus de 8 km de tout établissement d''enseignement du caractère 
concerné organisant ce degré et cette forme d''enseignement si la densité de population 
de la commune est inférieure à 250 habitants au km²; 
ou être situé à plus de 12 km de tout établissement d''enseignement du caractère 
concerné organisant ce degré et cette forme d''enseignement si la densité de population 
de la commune est égale ou supérieure à 250 habitants au km²; 
2° pour les autres établissements. 
 
Le Gouvernement peut réduire les minima par option pour les établissements 
situés dans une commune dont la densité de population est inférieure à 125 habitants 
au km². 
 
Le Gouvernement peut réduire de 25 p.c. au plus les minima fixés en application 
de l''alinéa 1er, 1°, pour les établissements situés à plus de 20 km de tout 
établissement ou implantation d''établissement de même caractère organisant ce degré 
et cette forme d’enseignement. 
 
Les minima de population par degré et par option des deuxième et troisième 
degrés de l''enseignement technique de transition ne comprenant que l''option de base 
groupée Scientifique industrielle : Electromécanique sont de 8 élèves pour l''ensemble 
du degré. [Alinéa remplacé par D. 17-10-2013 (1)] 
 
Aucun minimum de population n''est exigé pour les options de base groupées de 7e 
année qui figurent au répertoire des options de base de l''enseignement secondaire et 
qui y sont mentionnées précédées des lettres SN (sans normes). [Complété par D. 03-04-
2014] 
 
[Aucun minimum de population n''est exigé pour le deuxième degré de 
l''enseignement technique de qualification, l''enseignement artistique de qualification et 
l''enseignement professionnel]2. 
 
Modifié par D. 05-08-1995; D. 02-04-1996; D. 25-07-1996 ; D. 17-07-1998 ; modifié 
par D. 12-12-2008 ; D. 19-07-2011, complété par D. 12-07-2012(2) ; D. 11-04-2014 (2) ; 
modifié par D. 03-04-2014 ; complété par D. 11-04-2014 ; D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 43, 'Article 19. - § 1er. Tout degré, tout cycle, toute section, toute option qui n''atteint (partie 1)', 'Article 19. - § 1er. Tout degré, tout cycle, toute section, toute option qui n''atteint pas, pendant deux années scolaires consécutives, le minimum prévu à l''article 18, est fermé, année par année, à partir de l''année scolaire suivante. Lorsque les minima de population portent sur une seule année d''études, celle qui n''atteint pas, pendant deux années scolaires consécutives, le minimum prévu à l''article 18 est fermée l''année scolaire suivante. 2 Inséré par D. 22-06-2023 (art. 42). Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Remplacé par D. 03-04-2014 § 2. Sur avis du Conseil général de l’enseignement secondaire visé à l''article 5quater, le Gouvernement peut déroger aux dispositions du § 1er en matière d''option, d''année ou de degré. Aucune dérogation n''est octroyée pour les options des 2e et 3e degrés dont la moyenne de fréquentation par des élèves régulièrement inscrits au 15 janvier des deux années scolaires antérieures à la demande de dérogation a été inférieure à la moitié de la norme de maintien telle que définie à l''article 12, § 1er, alinéa 4 de l’arrêté de l''Exécutif de la Communauté française du 31 août 1992 exécutant le décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice. Pour l''application de l''alinéa 1er, l''absence d''avis du Conseil général de l’enseignement secondaire dans le délai de deux mois à compter de la réception de la demande d''avis qui lui est adressée par le Gouvernement est assimilée à un avis favorable. § 3. Par dérogation au § 2, sur avis du Conseil général de l’enseignement secondaire visé à l''article 5quater, le Gouvernement peut déroger aux dispositions du § 1er en matière d''option, d''année ou de degré, en faveur des établissements dont au moins une des implantations est reprise dans la liste visée à l''article 4, alinéa 8, du décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité. Pour l''application de l''alinéa 1er, l''absence d''avis du Conseil dans un délai de deux mois à compter de la demande d''avis qui lui est adressée par le Gouvernement est assimilée à un avis favorable. § 4. Les établissements qui bénéficient d''une dérogation en application du § 2 ne peuvent pas bénéficier des minima de base visés à l''article 17 pour les options, année ou degré concernés. Remplacé par D. 03-04-2014 § 5. Un établissement peut suspendre l''organisation d''une option pendant un maximum de deux années scolaires consécutives. Après la période de suspension, il peut réorganiser cette option. Du point de vue de l''application des normes visées à l''article 18 et au paragraphe 1er de l''article 19, cette option est analysée dans la continuité de la situation existant pendant l''année scolaire précédant la suspension. La réorganisation d''une option préalablement suspendue ne constitue pas une création. Si, malgré la suspension, l''option est amenée à être fermée, elle est fermée année par année et ne pourra plus être réouverte au cours des deux années scolaires suivant la fermeture définitive. Après cette période, elle pourra être ouverte à nouveau dans le respect des règles de programmation visées à l''Arrêté de l''Exécutif de Communauté française du 15 mars 1993 fixant les obligations de concertation entre établissements de même caractère dans l''enseignement secondaire de plein exercice. [Les dispositions reprises aux alinéas précédents ne s''appliquent plus aux options de base groupées visées par le décret du 22 juin 2023 relatif à la gouvernance de l''offre Secondaire IV.B.01 Lois 17144 D. 29-07-1992 d''options de base groupées dans l''enseignement secondaire qualifiant de plein exercice et en alternance à partir du premier jour de l''année scolaire 2023-2024]3. § 6. Les normes requises pour la création de la première année commune, de la première année du deuxième ou du troisième degré de l''enseignement général, de l''enseignement technique de transition, de l''enseignement artistique de qualification, de l''enseignement professionnel, de l''enseignement artistique de transition et de l''enseignement artistique de qualification, doivent être atteintes au 1er octobre de l''année de création. Les normes requises pour la création d''une option doivent être atteintes au 1er octobre de l''année de création. [Inséré par D. 12-07-2012 (2)] Section 4. Utilisation des périodes-professeurs Modifié par D. 21-12-1992; D. 22-12-1994; D. 02-04-1996; D. 25-07-1996 complété par D. 24-07-1997 ; D. 14-06-2001 ; modifié par D. 19-07-2001; complété par D. 04-05-2005 ; modifié par D. 12-12-2008 ; D. 26-03-2009 ; D. 30-04-2009 ; D. 17-12-2009 ; D. 03-05- 2012 ; complété par D. 18-05-2012 ; modifié par D. 17-10-2013 (1)D. 11-04-2014 (3) ; D. 11-10-2018 ; D. 12-12-2018 ; D. 14-03-2019 ; complété par D. 09-12-2020 ; modifié par D. 24-02-2022 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 44, 'Article 20. - § 1er. Les transferts de périodes-professeurs attribuées au premier (partie 1)', 'Article 20. - § 1er. Les transferts de périodes-professeurs attribuées au premier degré vers les autres degrés sont autorisés […]4 pour autant que les trois conditions suivantes soient rencontrées : a) les maxima par classe au 1er degré sont respectés; b) la remédiation est organisée au profit des élèves du 1er degré, notamment au travers de l''année complémentaire pour les écoles concernées, conformément aux dispositions du présent décret; c) ce transfert participe au respect des moyennes et/ou des maxima visés à l''article 23bis, § 1er, dans un (des) autre(s) degré(s). […]5 En cas de fermeture définitive d''un premier degré commun ou d''un premier degré différencié alors qu''un établissement scolaire n''organise qu''un seul de ces degrés, ou des deux degrés, les périodes-professeurs générées au 15 janvier de l''année scolaire précédant la fermeture définitive du degré ou des deux degrés peuvent être transférées aux autres degrés de l''établissement scolaire concerné. […]6 § 2. Les transferts de périodes-professeurs entre établissements sont autorisés y compris vers les centres d''éducation et de formation en alternance dans le respect des limites de transfert entre degrés et années fixées au § 1er. [Remplacé par D. 17-10-2013 (1)] (…) [Abrogé par D. 17-10-2013 (1)] L''utilisation du nombre de périodes-professeurs transféré en application de la présente disposition est soumise à l''avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, 3 Inséré par D. 22/06/2023 (art. 43). 4Abrogé par le D. 16-07-2025 5Abrogé par le D. 16-07-2025 6Abrogé par le D. 16-07-2025 Secondaire IV.B.01 Lois 17144 D. 29-07-1992 et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. (…) [Abrogé par D. 17-10-2013 (1)] § 3. Dans le respect des normes de sécurité pour la constitution des groupes d''élèves, le nombre total de périodes-professeurs peut être utilisé librement par le chef d''établissement après consultation du personnel enseignant ainsi que, pour l''enseignement de la Communauté française, du conseil de participation. Modifié par D. 11-10-2018 ; D. 12-12-2018 ; remplacé par D. 14-03-2019 § 4. Un maximum de [5 %]7 du nombre total de périodes-professeurs calculé en application des articles 7, 8 à 14, et 17 du présent décret - après soustraction du prélèvement zonal visé à l''article 21, § 1er, peut être utilisé pour les missions collectives visées aux articles 9, 10 et 11 du décret du 14 mars 2019 portant diverses dispositions relatives à l''organisation du travail des membres du personnel de l''enseignement et octroyant plus de souplesse organisationnelle aux Pouvoirs organisateurs. L''utilisation des périodes-professeurs visées à l''article 21, § 1er, ainsi que celles prévues à l''alinéa 1er, 1°, pour les activités des conseils et des directions de classe concernant les deuxième et troisième degrés et celles utilisées pour assurer les missions définies par l''arrêté du 27 mars 1998 relatif au Service interne pour la Prévention et la Protection au travail n''est en aucun cas à charge des [5 %]8 de périodes susvisés. L''utilisation de périodes-professeurs en application de la présente disposition est soumise à l''avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. Toutefois, le Gouvernement, sur base d''un demande motivée des chefs d''établissement dans le réseau organisé par la Communauté française et des Pouvoirs organisateurs dans l''enseignement subventionné incluant l''avis des organes de concertation tels que prévus au § 4, alinéa 2, du présent article, peut autoriser un dépassement des [5 %]9 visés à l''alinéa 1er sur base des normes régissant la taille des classes définies à l''article 23bis. Le défaut de réponse du Gouvernement dans le délai fixé à 30 jours ouvrables prenant cours dès la date d''envoi de la demande est assimilé à une décision favorable du Gouvernement. Pour l''application de la présente disposition, il faut entendre par jour ouvrable, les lundi, mardi, mercredi, jeudi et vendredi, à l''exception des jours fériés. § 5. Quarante-huit périodes-professeurs au maximum peuvent également être consacrées à un encadrement supplémentaire à raison de l''équivalent d''un emploi à prestations complètes d’éducateur ou d''assistant social ou de logopède, par 24 périodes-professeurs pour assurer un encadrement éducatif et social. 7Remplacé par le D. 16-07-2025 8Remplacé par le D. 16-');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 45, 'Article 20. - § 1er. Les transferts de périodes-professeurs attribuées au premier (partie 2)', '9Remplacé par le D. 16-07-025 Secondaire IV.B.01 Lois 17144 D. 29-07-1992 L''emploi de logopède peut être scindé par quarts temps. [Inséré par D. 11-04-2014(3)] Le transfert de périodes-professeurs visé à l''alinéa 1er cesse d''être facultatif dans le chef de l''établissement qui y a recouru pendant trois années scolaires consécutives pour créer une fonction supplémentaire d''éducateur ou d''assistant social ou de logopède à prestations complètes. L''alinéa 3 cesse d''être applicable à la fonction d’éducateur, d''assistant social ou de logopède lorsque le membre du personnel concerné est mis à la retraite, démissionne ou bénéficie d''un changement d''affectation ou d''une mutation. L''établissement n''est plus tenu par la contrainte de l''alinéa précédent lorsqu''un membre du personnel occupant un emploi d''éducateur généré en application des articles 3 et 4 de l''arrêté royal du 15 avril 1977 fixant les règles et les conditions de calcul du nombre d''emplois dans certaines fonctions du personnel auxiliaire d''éducation et du personnel administratif des établissements d''enseignement secondaire est mis à la retraite, démissionne ou bénéficie d''un changement d''affectation ou d''une mutation. Pour l''application des dispositions statutaires, il n''est en aucun cas opéré de distinction entre les éducateurs selon que la fonction qu''ils exercent est créée ou subventionnée en vertu de l''alinéa 2 ou en vertu de l''article 3 de l''arrêté royal du 15 avril 1977 fixant les règles et les conditions de calcul du nombre d''emplois dans certaines fonctions du personnel auxiliaire d''éducation et du personnel administratif des établissements d''enseignement secondaire et d''enseignement supérieur, à l''exception de l''enseignement universitaire, modifié par l''arrêté royal n°61 du 20 juillet 1982. Aucune nomination ne peut être accordée à titre définitif dans un emploi à prestations incomplètes créé sur base de l''alinéa 1er. L''utilisation de périodes-professeurs en application de la présente disposition est soumise à l''avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. Inséré par D. 11-04-2014 (3) [§ 5/1. Lorsque des périodes supplémentaires au nombre total de périodes- professeurs octroyées à un établissement scolaire conformément à l''article 37, § 1er, du décret du 21 novembre 2013 organisant divers dispositifs scolaires favorisant le bien- être des jeunes à l''école, l''accrochage scolaire, la prévention de la violence à l''école et l''accompagnement des démarches d''orientation scolaire sont consacrées à l''engagement à titre temporaire d''un membre du personnel auxiliaire d''éducation conformément à l''article 37, § 2 du même décret, l''emploi de ce membre du personnel auxiliaire d''éducation peut être scindé par quarts temps.]10 [§5/1. Lorsque des périodes supplémentaires au nombre total de périodes-professeurs octroyées à un établissement scolaire conformément à l''article 1.7.1-50 du Code de l''enseignement fondamental et de l''enseignement secondaire sont consacrées à l''engagement à titre temporaire d''un membre du personnel auxiliaire d''éducation conformément à l''article 1.7.1-50 précité, l''emploi de ce membre du personnel auxiliaire d''éducation peut être scindé 10Le paragraphe 5 est remplacé par le D. 16-05-2024 et entrera en vigueur le 25-08-2025 (voir en dessous) Secondaire IV.B.01 Lois 17144 D. 29-07-1992 par quarts temps.]11 § 6. En cas de doute sur l''utilisation des périodes-professeur, la preuve devra être apportée que celles-ci bénéficient bien aux élèves fréquentant les années et les formes d''enseignement visées ci-dessus. Aucun transfert n''est autorisé en provenance du nombre intermédiaire de périodes-professeurs destinées aux cours relevant de l''enseignement clinique. Modifié par D. 02-04-1996 ; complété par D. 30-06-1998 ; modifié par D. 27-03-2002 ; D. 04-05-2005 ; D. 30-04-2009 ; D. 17-10-2013 (1) ; D. 14-06-2018 ; D. 28-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 46, 'Article 21. - § 1er. Chaque pouvoir organisateur ou chaque groupe de pouvoirs', 'Article 21. - § 1er. Chaque pouvoir organisateur ou chaque groupe de pouvoirs 
organisateurs a le droit de prélever un maximum de 1 p.c. du nombre total de 
périodes-professeurs visé à l’article 7, et 8 à 15 dans les établissements qu''il organise à 
l''exception des implantations bénéficiaires de l''encadrement différencié de classe 1 en 
vertu du décret du 30 avril 2009 précité. Cette disposition vise à permettre un 
meilleur fonctionnement de certains d''entre eux, en particulier l''affectation à des 
tâches utiles à plusieurs établissements de membres du personnel directeur et 
enseignant, non placés en disponibilité totale par défaut d''emploi et à qui n''ont pu être 
attribuées le nombre d''heures de cours pour lesquelles ils sont rétribués. 
 
Dans l''enseignement subventionné, les dispositions de l''alinéa 1er sont de la 
compétence du groupe de pouvoirs organisateurs par zone géographique ou de l''organe 
de coordination et de représentation des pouvoirs organisateurs pour ce qui concerne 
la désignation de Conseillers au soutien et à l''accompagnement en application de 
l''article 6bis du décret du 24 juin 1996 portant réglementation des missions, des 
congés pour mission et des mises en disponibilité pour mission spéciale dans 
l''enseignement organisé ou subventionné par la Communauté française. [Alinéa remplacé 
par D. 17-10-2013 (1)] 
 
Le prélèvement visé à l''alinéa 1er est soumis à l''avis préalable, dans 
l''enseignement organisé par la Communauté française, de la commission zonale 
d''affectation visée à l''article 14quater de l''arrêté royal du 22 mars 1969 fixant le statut 
des membres du personnel directeur et enseignant, du personnel auxiliaire 
d''éducation, du personnel paramédical des établissements d''enseignement gardien, 
primaire, spécial, moyen, technique, de promotion sociale et artistique de l''Etat, des 
internats dépendant de ces établissements et des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements et, dans l''enseignement 
subventionné par la Communauté française, de la commission zonale de gestion des 
emplois visée aux articles 8 et 12 du décret du 12 mai 2004 relatif à la définition de la 
pénurie et à certaines Commissions dans l''enseignement organisé ou subventionné par 
la Communauté française. 
 
A défaut d''avis rendu dans le mois de la saisine de la commission, l''avis de cette 
dernière est réputé positif. 
 
Le pouvoir organisateur ou le groupe de pouvoirs organisateurs visé à l''alinéa 1er 
informe la commission visée à l''alinéa 3 du prélèvement opéré en application de la 
présente disposition et des établissements bénéficiaires. 
 
L''utilisation du nombre de périodes-professeurs prélevé en application de la 
présente disposition est soumise à l''avis préalable, dans l''enseignement organisé par 
la Communauté française, du comité de concertation de base, dans l''enseignement 
officiel subventionné par la Communauté française, de la commission paritaire locale, 
 
11Remplacé par le D. 16-05-2024 et entrera en vigueur le 25-08-2025 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
et dans l''enseignement libre subventionné par la Communauté française, du conseil 
d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau 
de conciliation en cas de désaccord. 
 
§ 2. L''Exécutif peut accorder à chaque réseau un nombre de périodes 
complémentaires à concurrence d''un pourcentage, qu''il détermine, du nombre total de 
périodes-professeurs organisables lors de l''année scolaire précédente dans le réseau 
concerné. 
 
Pendant les cinq années visées à l''article 28, ces périodes-professeurs devront, 
avant toute autre utilisation, être attribuées pour affecter à des tâches utiles à un ou à 
plusieurs établissements les membres du personnel directeur et enseignant placés en 
disponibilité totale par défaut d''emploi ou auxquels n''a pu être attribué le nombre 
d''heures de cours pour lequel ils sont rétribués. 
 
L''utilisation du nombre de périodes complémentaires visé par la présente 
disposition est soumise à l''avis préalable, dans l''enseignement organisé par la 
Communauté française, du comité de concertation de base, dans l''enseignement 
officiel subventionné par la Communauté française, de la commission paritaire locale, 
et dans l''enseignement libre subventionné par la Communauté française, du conseil 
d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau 
de conciliation en cas de désaccord. 
 
Inséré par D. 10-04-1995 ; complété par D. 12-12-2000');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 47, 'Article 21bis. - Le Gouvernement fixe annuellement le nombre total de périodes-', 'Article 21bis. - Le Gouvernement fixe annuellement le nombre total de périodes-
professeurs attribuées à l''Athénée royal de Rösrath afin que celui-ci puisse organiser 
une offre d''enseignement suffisante. 
 
Le Gouvernement fixe annuellement un nombre de périodes-professeurs 
supplémentaires au nombre de périodes-professeurs attribuées à l''Ecole internationale 
du Shape en application du présent décret. 
 
La fixation du nombre de périodes-professeurs supplémentaires visé à l''alinéa 2 
doit dépendre des besoins spécifiques de l''Ecole internationale du Shape, section belge, 
liés à la présence d''élèves de nationalité autre que belge dans cette école, sans que ce 
nombre ne puisse excéder 100 périodes-professeurs. 
 
Inséré par D 02-04-1996 
CHAPITRE IIbis. - De certains emplois 
 
Inséré par D 02-04-1996');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 48, 'Article 21ter. - Il est créé un emploi de chef d''établissement dans tout', 'Article 21ter. - Il est créé un emploi de chef d''établissement dans tout 
établissement d''enseignement secondaire. 
 
Dans tout établissement n''organisant que le quatrième degré de l''enseignement 
professionnel secondaire complémentaire dans la section "soins infirmiers" et, 
éventuellement, l''année préparatoire à l''enseignement professionnel secondaire 
complémentaire section, "soins infirmiers", ainsi que l''année préparatoire à 
l''enseignement supérieur paramédical ou l''une de ces deux années préparatoires 
seulement, l''emploi de chef d''établissement est attribué à un directeur des soins 
infirmiers. 
 
 
 
Inséré par D. 04-02-2021 ; modifié par D. 16-03-2023 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 49, 'Article 
21ter', 'Article 
21ter/1. - Un 
emploi 
de 
directeur 
est 
octroyé 
à 
toute 
école 
d''enseignement secondaire ordinaire organisée ou subventionnée par la Communauté 
française. Cet emploi ne peut être scindé. 
 
Sans préjudice de l''alinéa précédent, l''école dont le directeur obtient une 
réduction de son temps de travail en vertu soit: 
a) de l''article 19 de l''arrêté royal du 15 janvier 1974 pris en application de 
l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du 
personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel 
paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, 
technique, artistique et normal de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé de la 
surveillance de ces établissements; 
b) de l''article 22ter de l''arrêté royal du 15 janvier 1974 précité; 
c) de l''article 10ter de l''arrêté royal n° 297 du 31 mars 1984 relatif aux charges, 
traitements, subventions-traitements et congés pour prestations réduites dans 
l''enseignement et les centres psycho-médico-sociaux; 
d) de l''article 10quatorduodecies/1 de l''arrêté royal n° 297 précité; 
e) de l''article 3, alinéa 1er de l''arrêté de l''exécutif de la Communauté française du 
3 décembre 1992 relatif à l''interruption de la carrière professionnelle dans 
l''enseignement et les centres psycho-médico-sociaux, 
f) de l''article 10duodecies, §8, de l''arrêté royal n° 297 précité, [inséré par D. 16-
03-2023] 
 
se voit octroyer, pour seconder son directeur, un emploi temporaire de directeur 
adjoint à temps partiel à partir de la date d''activation de la disposition visée, et ce, 
respectivement à mi-temps (situations a et b), à quart-temps (situations c, d et f) 
[modifié par D. 16-03-2023] ou à un cinquième-temps (situation e). Cet emploi ne peut 
faire l''objet d''une nomination ou d''un engagement à titre définitif. A l''exception de la 
situation où l''emploi temporaire octroyé dans le cadre du point f est maintenu dans le 
cadre du point d, [inséré par D. 16-03-2023] il est supprimé dès que la disposition visée 
n''est plus d''application. 
 
Le directeur adjoint visé à l''alinéa précédent et qui: 
a) preste un mi-temps, est tenu de prester au minimum quatre demi-journées par 
semaine; 
b) preste un quart-temps ou un cinquième-temps est tenu de prester au minimum 
deux demi-journées par semaine. 
 
Inséré par D 02-04-1996; complété par D. 24-07-1997 ; modifié par D. 04-01-1999 ; 
complété par D. 02-02-2007 ; modifié par D. 30-04-2009 ; D. 19-07-2011 ; D. 13-07-2016 ; 
D. 14-03-2019 ; complété par D. 09-12-2020 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 50, 'Article 21quater. - Il est requis 600 élèves pour un premier emploi, 1500 élèves', 'Article 21quater. - Il est requis 600 élèves pour un premier emploi, 1500 élèves 
pour un deuxième emploi, 2400 élèves pour un troisième emploi de directeur adjoint. 
 
Ces emplois sont maintenus pour autant que le nombre d''élèves ne soit pas 
inférieur respectivement à 550, 1400 et 2250. Si ces minima ne sont pas atteints 
pendant deux années consécutives, les emplois sont supprimés. Ils peuvent être 
rouverts au premier jour d''une année scolaire, si la norme de création est à nouveau 
atteinte le 15 janvier précédent. 
 
Les emplois de directeur adjoint peuvent être confiés à deux membres du 
personnel qui sont chargés chacun d''une demi charge, après avis préalable, dans 
l''enseignement organisé par la Communauté française, du comité de concertation de 
base, dans l''enseignement officiel subventionné par la Communauté française, de la 
commission paritaire locale, et dans l''enseignement libre subventionné par la 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
Communauté française, du conseil d''entreprise ou, à défaut, de la délégation 
syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. 
 
Par dérogation aux alinéas 1 et 2, un emploi de Directeur-adjoint peut être créé 
pendant la période de création telle que fixée soit par l''arrêté du Gouvernement relatif 
à l''admission aux subventions de l''école soit par la décision du Gouvernement relative 
à la création de l''école conformément à l''article 6, § 2, à partir du 1er octobre de l''année 
scolaire au cours de laquelle les conditions cumulatives suivantes sont réunies: 
- le nombre d''élèves régulièrement inscrits est au moins égal à 375 élèves; 
- la moyenne des différences entre le nombre d''élèves régulièrement inscrits au 
1er octobre d''une année scolaire et le nombre d''élèves régulièrement inscrits au 1er 
octobre de l''année scolaire précédente, établies depuis l''année de création de l''école, est 
au moins égale à 75.  
 
Si l''une des conditions prévues à l''alinéa précédent n''est plus remplie au 1er 
octobre d''une année scolaire, l''emploi n''est plus organisé à partir de cette date. 
 
L''emploi créé à l''alinéa 4 ne peut donner lieu à nomination définitive, dans le 
respect des règles statutaires, que si la norme création fixée à l''alinéa 1er a été atteinte 
conformément aux dispositions de l''alinéa 1er au 1er octobre d''une année scolaire dans 
le cadre du processus de création ou conformément aux dispositions de l''article 
22, § 1er, alinéas 1er et 2, du présent décret. 
 
Inséré par D. 04-01-1999 ;  complété par D. 02-02-2007 ; modifié par D. 07-12-2007 ; D. 
13-07-2016 ; D. 24-05-2017 ; complété par D. 04-02-2021 ; D. 31-03-2022 ;  
modifié par D. 16-03-2023');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 51, 'Article 21quinquies. – § 1er. Il est créé un ou plusieurs emplois de chefs (partie 1)', 'Article 21quinquies. – § 1er. Il est créé un ou plusieurs emplois de chefs d''atelier ainsi qu''un ou deux emplois de chefs de travaux d''atelier lorsque l''établissement compte un nombre d''élèves au moins égal aux minima visés ci-après dans l''enseignement de qualification, professionnel, technique ou artistique, dans l''enseignement technique de transition des secteurs «agronomie», «industrie» et «construction», dans l''enseignement artistique de transition et dans la deuxième année du premier degré différencié, dans l''année différenciée supplémentaire visée à l''article 28, § 2, ainsi que dans la troisième année de différenciation et d''orientation visée à l''article 19, intégré par le décret du 7 décembre 2007 organisant la différenciation structurelle au sein du premier degré afin d''amener l''ensemble des élèves à la maîtrise des socles de compétences dans le décret du 30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire. § 2. Pour fixer le nombre d''emplois de chef d''atelier ou de chef de travaux d''atelier, les nombres d''élèves visés sont affectés d''un coefficient. Celui-ci est l''unité dans la deuxième année du premier degré différencié, dans la troisième année de différenciation et d''orientation, ainsi que dans l''enseignement technique et professionnel - y compris la 7ème professionnelle de type C, quel que soit le secteur -, sauf : 1° dans l''enseignement professionnel du secteur «industrie», où il est fixé à 1,5; 2° dans l''enseignement professionnel des secteurs «construction» et «hôtellerie- alimentation» où il est fixé à 1,4; 3° dans l''enseignement professionnel du secteur «agronomie», où il est fixé à 1,3; 4° dans l''enseignement professionnel du secteur «habillement» et du groupe «soins de beauté» dans le secteur «services aux personnes», où il est de 1,2; 5° dans l''enseignement technique et professionnel des secteurs «économie» et «sciences appliquées», où il est de 0,2; 6° dans l''enseignement technique et professionnel du secteur «services aux personnes» - à l''exception, dans l''enseignement professionnel, du groupe «soins de beauté» -, où il est de 0,5; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 7° dans l''enseignement technique et professionnel des groupes «arts décoratifs» et «audiovisuel» du secteur «arts appliqués», où il est de 0,2; 8° dans l''enseignement professionnel secondaire complémentaire, où il est de 0,5; 9° dans l''enseignement artistique, où il est de 0,5; 10° dans l''enseignement technique et professionnel du secteur «arts appliqués», groupe «orfèvrerie», où il est de 0,5; 11° dans l''enseignement technique du secteur «beaux-arts», où il est de 0,5; 12° dans l''enseignement technique de transition des secteurs «hôtellerie- alimentation», «habillement et textile», «arts appliqués», «économie», «services aux personnes» et «sciences appliquées», où il est de 0; 13° dans l''enseignement professionnel du secteur «beaux-arts», où il est de 0. Les résultats sont arrondis à l''unité supérieure. Les emplois de chefs d''atelier ou de chefs de travaux d''atelier peuvent être soit créés, soit maintenus conformément au tableau suivant: Emplois Norme de création Norme de maintien Chef d’atelier 180 150 Chef d’atelier 360 300 Chef de travaux d’atelier 540 450 Chef d’atelier 740 600 Chef d’atelier 940 750 Chef d’atelier 1.140 900 Chef d’atelier 1.340 1.080 Chef de travaux d’atelier 1.540 1.260 Chef d’atelier 1.740 1.440 Il est créé ou maintenu un chef d''atelier supplémentaire respectivement par tranche complète de 200 et de 180. Alinéa remplacé par D. 13-07-2016 ; D. 31-03-2022 Dans chaque établissement, un emploi de chef d''atelier ainsi qu''un emploi de chef de travaux d''atelier peuvent être maintenus pendant deux années scolaires consécutives sous la norme de maintien. Après cette période de deux ans, l''emploi est supprimé. Il peut être rouvert le premier jour d''une année scolaire, si la norme de création est atteinte à nouveau le 15 janvier précédent. § 3. Les emplois nouvellement créés ne sont considérés comme vacants pour une nomination définitive que lorsqu''ils correspondent à la norme de création et que celle- ci a été atteinte pendant les deux dernières années scolaires. Toutefois, le premier emploi de chef d''atelier et le premier emploi de chef de travaux d''atelier, existant au 30 juin 1998, même sous forme de maintien, sont réputés remplir la condition de vacance fixée au présent paragraphe. § 4. Les membres du personnel nommés ou engagés à titre définitif, en activité de service à la date de prise d''effet du décret sont maintenus en activité de service dans leur fonction, sans limitation de durée. Les membres du personnel visés à l''alinéa 1er qui seraient en surnombre peuvent, au plus tard le 1er septembre 2000, bénéficier des dispositions applicables aux membres du personnel mis en disponibilité par défaut d''emploi prévues par l''article 10 de l''arrêté royal n° 297 du 31 mars 1984 relatif aux charges, traitements, subventions- Secondaire IV.B.01 Lois 17144 D. 29');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 52, 'Article 21quinquies. – § 1er. Il est créé un ou plusieurs emplois de chefs (partie 2)', 'traitements et congés pour prestations réduites dans l''enseignement et les centres psycho-médico-sociaux. Les membres du personnel visés à l''alinéa 1er, placés en surnombre à partir de l''entrée en vigueur du décret et qui n''ont pas bénéficié des dispositions de l''alinéa 2, sont affectés au sein de leur pouvoir organisateur à tout emploi de leur fonction qui devient vacant ou provisoirement vacant. § 5. Les emplois de chef d''atelier peuvent être confiés à deux membres du personnel qui sont chargés chacun d''une demi charge, après avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. Inséré par D. 04-02-2021 § 6. L''école d''enseignement secondaire ordinaire organisée ou subventionnée par la Communauté française dont le chef de travaux d''atelier obtient une réduction de son temps de travail en vertu soit: a) de l''article 19 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements; b) de l''article 22ter de l''arrêté royal du 15 janvier 1974 précité; c) de l''article 10ter de l''arrêté royal n° 297 du 31 mars 1984 relatif aux charges, traitements, subventions-traitements et congés pour prestations réduites dans l''enseignement et les centres psycho-médico-sociaux; d) de l''article 10quatorduodecies/1 de l''arrêté royal n° 297 précité; e) de l''article 3, alinéa 1er de l''arrêté de l''exécutif de la Communauté française du 3 décembre 1992 relatif à l''interruption de la carrière professionnelle dans l''enseignement et les centres psycho-médico-sociaux, f) de l''article 10duodecies, §8, de l''arrêté royal n° 297 précité, [inséré par D. 16- 03-2023] se voit octroyer, pour seconder son chef de travaux d''atelier, un emploi temporaire de chef d''atelier à temps partiel à partir de la date d''activation de la disposition visée, et ce, respectivement à mi-temps (situations a et b), à quart-temps (situations c, d et f) [modifié par D. 16-03-2023] ou à un cinquième-temps (situation e). Cet emploi ne peut pas faire l''objet d''une nomination ou d''un engagement à titre définitif. A l''exception de la situation où l''emploi temporaire octroyé dans le cadre du point f est maintenu dans le cadre du point d, [inséré par D. 16-03-2023] il est supprimé dès que la disposition visée n''est plus d''application. CHAPITRE III. - Comptage des élèves Modifié par D. 22-12-1994; D. 05-08-1995; D 02-04-1996 ; D. 30-06-2006 ; D. 08-03- 2007 ; D. 12-12-2008 ; D. 13-01-2011 ; D. 19-07-2011 ; D. 19-07-2017 ; D. 14-06-2018 ; D. 14- 03-2019 ; D. 09-12-2020 ; D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 53, 'Article 22. - § 1er. Le nombre d''élèves pris en considération pour l''application du (partie 1)', 'Article 22. - § 1er. Le nombre d''élèves pris en considération pour l''application du chapitre II et chapitre IIbis est le nombre d''élèves régulièrement inscrits le 15 janvier de l''année scolaire précédente à l''exception des années constitutives du premier degré différencié en cas d''ouverture progressive de ce dernier pour lesquelles le nombre Secondaire IV.B.01 Lois 17144 D. 29-07-1992 d''élèves régulièrement inscrits est alors comptabilisé au 1er octobre de l''année scolaire en cours. Par dérogation à l''alinéa précédent, n''est pas considéré comme élève régulièrement inscrit au 15 janvier de l''année scolaire précédente dans l''établissement qui l''a exclu, l''élève qui fait l''objet d''une décision d''exclusion définitive à un moment quelconque de cette année, mais bien dans celui qui, le cas échéant, l''accueille après cette décision. Les élèves inscrits dans un établissement résultant d''une fusion intervenue après le 30 juin 1994, qui suivent les cours de première année commune comme défini à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire ou de deuxième année commune de l''enseignement secondaire de type I sont comptabilisés séparément si: 1° ils sont au moins 26; 2° ils suivent les cours dans une implantation située à plus de 12 km de tout établissement d''enseignement et de toute implantation d''établissement de même caractère; 3° la densité de la commune de l''implantation est inférieure à 75 habitants au km². Dans ce cas, l''implantation bénéficie pour ces élèves du minimum de base prévu en application de l''article 17. Par implantation, on entend, dans le présent décret, sauf dans le cas des restructurations visées à l''article 5quater, § 1er, alinéa 3, un bâtiment ou un ensemble de bâtiments, situés à une autre adresse que le siège administratif d''un établissement et où cet établissement organise des cours. Les élèves inscrits dans des établissements de même caractère dont les sièges administratifs sont contigus ou ont des implantations contiguës, sont considérés, pour l''ensemble des calculs visés au chapitre II, comme des élèves d''un seul et même établissement. Les périodes-professeur sont ensuite réparties proportionnellement au nombre d''élèves de la catégorie concernée de chaque établissement, pour chaque nombre intermédiaire fixé à l''article 7. Les élèves qui suivent les cours de première année commune comme défini à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire ou de deuxième année commune de l''enseignement secondaire de type I dans des établissements de même caractère dont les sièges administratifs ou certaines implantations sont distants, à vol d''oiseau, de limite de propriété à limite de propriété, de moins de 200 m, sont considérés pour le calcul visé au chapitre II, comme des élèves d''un seul établissement. Les périodes-professeur sont ensuite réparties proportionnellement au nombre d''élèves de la catégorie concernée de chaque établissement. L''alinéa 6 ne s''applique pas: 1° à l''établissement non contigu à un autre de même caractère qui compte au moins 400 élèves en première année commune comme défini à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire et deuxième année commune; 2° à l''établissement qui organise également un deuxième degré où ne figure pas l''enseignement général; 3° aux établissements dont au moins une des implantations est reprise dans la liste visée à l''article 4, alinéa 8 du décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin Secondaire IV.B.01 Lois 17144 D. 29-07-1992 d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité. L''alinéa 6 ne s''applique qu''aux deux établissements les plus proches lorsque ceux-ci totalisent ensemble 400 élèves en première année commune comme défini à l''article 4 du décret du 30 juin 2006 relatif à l''organisation pédagogique du premier degré de l''enseignement secondaire et deuxième année commune. […]12 […]13 § 2. En cas de fusion ou de restructuration entre établissements, conformément aux articles 5ter et 5quater, le nombre d''élèves pris en compte est la somme, par année, degrés et formes des élèves des différents établissements fusionnés et restructurés, considérés comme inscrits dans l''établissement résultant de la fusion ou de la restructuration. § 3. L''Exécutif détermine de manière identique pour tous les réseaux, les modalités de justification des absences. Modifié par D. 19-7-2017 § 4. Le nombre d''élèves pris en compte pour l''organisation des cours de religion, de morale non confessionnelle et de philosophie et de citoyenneté lorsque les élèves sont, le cas échéant, dispensés du cours de religion, et du cours de philosophie et de citoyenneté visé à l''article 8, alinéa 4, de la loi du 29 mai 1959 modifiant');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 54, 'Article 22. - § 1er. Le nombre d''élèves pris en considération pour l''application du (partie 2)', 'certaines dispositions de la législation de l''enseignement est fixé au 1er octobre de l''année scolaire en cours. Modifié par D. 19-7-2017 ; D. 14-06-2018 ; D. 09-12-2020 § 5. Par dérogation au § 1er pour les établissements créés par année ou par degré conformément à l''article 6, le nombre d''élèves pris en considération pour l''application des chapitres II et IIbis, à l''exception de l’article 21quater et des dispositions prévues à l''article 16, § 2, est le nombre d''élèves régulièrement inscrits au 1er octobre de l''année scolaire en cours. A partir de l''année scolaire au cours de laquelle l''établissement organise l''entièreté des années et degrés prévus, le nombre d''élèves pris en considération pour le calcul du NTPP de l''année scolaire suivante est le nombre d''élèves réguliers au 15 janvier de l''année scolaire précédente. [§6. Sont déduits du comptage du 15 janvier 2025, les élèves qui sont inscrits en 2024-2025, mais qui ne seraient plus considérés comme régulièrement inscrits en vertu de la mesure insérée à l''article 17, §1er, de l''arrêté royal du 29 juin 1984 relatif à l''organisation de l`enseignement secondaire si celle-ci avait été d''application dès la rentrée 2024-2025.]14 [§7. Sont déduits du comptage du 15 janvier 2025, les élèves qui sont inscrits en 2024-2025, mais qui ne seraient plus considérés comme régulièrement inscrits en vertu de la mesure insérée à l''article 76 du décret du 24 juillet 1997 définissant les missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire et organisant les structures propres à les atteindre si celle-ci avait été d''application dès la rentrée 20242025.]15 12Abrogé par le D. 17-12-2025 13Abrogé par le D. 17-12-2025 14Inséré par le D. 11-12-2024 15Inséré par le D. 11-12-2024 Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Inséré par D. 03-04-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 55, 'Article 22bis.', 'Article 22bis. Pour l''année scolaire 2009-2010, pour les écoles organisant une 
phase de classement et concernées par la disposition visée à l''article 80, § 1er, alinéa 5, 
1°, et à l''article 88, § 1er, alinéa 4, 1°, du décret du 24 juillet 1997 définissant les 
missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire 
et organisant les structures propres à les atteindre, le nombre d''élèves visés à l''article 
22, § 1er inscrits en 1ère année commune est calculé sur la base du nombre d''élèves 
régulièrement inscrits à la date du 1er octobre 2009. Le NTPP ainsi calculé s''applique 
à partir du 1er septembre 2009.  
 
Inséré par D. 04-02-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 56, 'Article 22ter. - L''établissement scolaire qui accueille un élève exclu après le 15', 'Article 22ter. - L''établissement scolaire qui accueille un élève exclu après le 15 
janvier en informe l''Administration au plus tard le 15 juillet suivant. A défaut, l''élève 
n''est pas pris en considération pour l''application des chapitres II et IIbis. 
 
Inséré par D. 14-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 57, 'Article 22quater. - Les écoles visées à l''article 1.5.2-14 du Code de', 'Article 22quater. - Les écoles visées à l''article 1.5.2-14 du Code de 
l''enseignement fondamental et de l''enseignement secondaire présentant un écart 
significatif de performance en-dessous de la moyenne des écoles comparées, et qui ont 
conclu un protocole de collaboration en vertu de l''article 1.5.2-17 du même Code, se 
voient garantir, en cas de diminution de l''encadrement pendant la durée dudit 
protocole, un encadrement de stabilisation totale ou partielle correspondant à un 
maximum de 5% de l''encadrement applicable lors de la première année scolaire du 
protocole de collaboration, dans la limite de 22 périodes-professeurs par année 
scolaire. L''octroi de cet encadrement de stabilisation totale ou partielle ne peut avoir 
pour effet de dépasser l''encadrement applicable lors de la première année scolaire du 
protocole de collaboration. 
 
Pour l''application du présent article, il faut entendre par «encadrement» le NTPP 
de base visé aux articles 7 et 8 à 15, et l''encadrement minimum de base visé à l''article 
17. 
 
Le calcul de l''encadrement de stabilisation totale ou partielle est arrondi à l''unité 
supérieure si la première décimale est égale ou supérieure à 5, à l''unité inférieure 
dans les autres cas. 
 
L''encadrement de stabilisation totale ou partielle est nécessairement utilisé en 
adéquation avec les objectifs d''ajustement visés à l''article 1.5.2-15 du Code de 
l''enseignement fondamental et de l''enseignement secondaire. 
 
Durant la durée du protocole de collaboration, l''encadrement de stabilisation 
totale ou partielle est appliqué dans le cadre du recomptage au 1er octobre prévu à 
l''article 23, tant que ce recomptage n''aboutit pas à un encadrement dépassant 
l''encadrement applicable lors de la première année scolaire du protocole de 
collaboration.  
 
L''encadrement de stabilisation totale ou partielle ne permet pas de déroger aux 
normes de rationalisation, ni aux normes de création ou de maintien des options, 
années d''études et degrés. 
 
Remplacé par D. 22-12-1994 ; modifié par D. 12-12-2008 ; complété par D. 03-04-2009 ; 
D. 13-01-2011 ; D. 19-07-2011; modifié par D. 17-10-2013 (1) ; complété par D. 09-12-
2020 ; modifié par D. 24-02-2022 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 58, 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation (partie 1)', 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation et du DASPA tel que défini à l''article 2, 5°, du décret du 7 février 2019 visant à Secondaire IV.B.01 Lois 17144 D. 29-07-1992 l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent pas la langue de l''enseignement dans l''enseignement organisé ou subventionné par la Communauté française, lorsqu''il existe une différence positive ou négative de plus de 10 p.c. entre le nombre total d''élèves inscrits au 1er octobre et le nombre total d''élèves obtenu sur base des dispositions de l''article 22, le nombre total de périodes-professeurs est le résultat de la moyenne arithmétique du nombre total de périodes-professeurs obtenu sur base des dispositions de l''article 22 et du nombre total de périodes- professeurs obtenu sur base du nombre d''élèves inscrits le premier jour ouvrable qui suit le 1er octobre. Pour l''application de l''alinéa précédent, l''écart de 10 p.c. est constaté par établissement pour l''enseignement de la Communauté et l''enseignement libre subventionné, par ensemble d''établissements organisés par le même pouvoir organisateur sur le territoire de la même commune pour l''enseignement subventionné officiel. L''alinéa 1er n''est pas d''application pour les établissements bénéficiant pour la première année des incitants prévus aux articles 5ter et 5quater. Même si le comptage établi au 1er octobre fait apparaître une différence de plus de 10 p.c., les périodes-professeurs organisables dès le premier jour de l''année scolaire et durant tout le mois de septembre sont fixées sur base du comptage effectué en application de l''article 22. Les limites aux transferts de périodes fixées par l''article 20 sont calculées après correction des nombres intermédiaires dans la même proportion que la correction du nombre total de périodes-professeurs. Le nombre de périodes obtenues sur la base de l''article 22bis est déduit du nombre total de périodes-professeurs visées à l''alinéa 1er. Le Gouvernement peut décider, pour l''année scolaire 2020-2021 de postposer les effets à la baisse du comptage au 1er octobre 2020 à une date ultérieure, qu''il détermine. [Alinéa inséré par D. 09-12-2020] [Article 23bis.]16 - § 1er. Dans l''enseignement secondaire organisé ou subventionné par la Communauté française les normes régissant la taille des classes- ensemble d''élèves de l''enseignement secondaire d''un même groupe-classe ou du regroupement de deux ou plusieurs groupes classe placés sous la direction d''un enseignant en conformité avec les grilles-horaire légales -sont les suivantes : a) au premier degré commun, aucune classe ne peut compter plus de 24 élèves sauf dérogation accordée en application du paragraphe 4 ; b) en 1ère année différenciée, aucune classe ne peut compter plus de 15 élèves ; c) en 2ème année différenciée, aucune classe ne peut compter plus de 18 élèves ; d) au deuxième degré de l''enseignement général, les classes ne peuvent compter en moyenne plus de 26 élèves avec un maximum de 29 élèves ; les cours de laboratoire ne peuvent compter en moyenne plus de 16 élèves avec un maximum de 19 élèves ; 16Article remplacé par le D. 04-04-2024 Secondaire IV.B.01 Lois 17144 D. 29-07-1992 e) au troisième degré de l''enseignement général, les classes ne peuvent compter en moyenne plus de 29 élèves avec un maximum de 32 élèves ; les cours de laboratoire ne peuvent compter en moyenne plus de 16 élèves avec un maximum de 19 élèves ; f) au deuxième et au troisième degrés de l''enseignement technique de transition et de l''enseignement artistique de transition, les classes ne peuvent compter en moyenne plus de 26 élèves avec un maximum de 29 élèves y compris en cas de regroupement avec des élèves du troisième degré de l''enseignement général ; les cours de laboratoire ne peuvent compter en moyenne plus de 16 élèves avec un maximum de 19 élèves ; g) au deuxième et au troisième degrés de l''enseignement technique de qualification et de l''enseignement artistique de qualification, les classes ne peuvent compter en moyenne plus de 25 élèves avec un maximum de 28 élèves ; la limite est réduite à 16 en moyenne, avec un maximum de 19 élèves pour les cours de pratique professionnelle, à 12 en moyenne avec un maximum de 15 pour les cours de pratique professionnelle relevant du comptage séparé prévu par l''arrêté du 31 août 1992 ; le nombre de 10 en moyenne, avec un maximum de 12 ne sera pas dépassé lorsque la sécurité l''exige ; h) au deuxième degré de l''enseignement professionnel, les classes, et notamment, les classes de cours généraux ne pourront compter en moyenne plus de 19 élèves en moyenne, avec un maximum de 22 élèves ; la limite est réduite à 16 en moyenne avec un maximum de 19 pour les cours de pratique professionnelle, à 12 en moyenne avec un maximum de 15 pour les cours de pratique professionnelle relevant du comptage séparé ; le nombre de 10 en moyenne, avec un maximum de 12, ne sera pas dépassé lorsque la sécurité l''exige ; i) au troisième degré');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 59, 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation (partie 2)', 'de l''enseignement professionnel, les classes ne peuvent compter en moyenne plus de 22 élèves avec un maximum de 25 élèves ; la limite est réduite à 16 en moyenne avec un maximum de 19 pour les cours de pratique professionnelle, à 12 en moyenne avec un maximum de 15 pour les cours de pratique professionnelle relevant du comptage séparé ; le nombre de 10 en moyenne avec un maximum de 12 ne sera pas dépassé lorsque la sécurité l''exige ; j) dans les années préparatoires visées à l''article 2, §3, 2°, et §4, alinéa 2, de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire ordinaire, les classes ne peuvent compter en moyenne plus de 25 élèves. Sur avis du Conseil général de l''enseignement secondaire, qui se fonde sur une proposition que doit lui remettre le Service général de l''Inspection, le Gouvernement arrête une liste des options de base groupées dans lesquelles les cours de pratique professionnelle engendrent un risque tel que la sécurité exige qu''un enseignant ait un nombre limité d''élèves sous sa surveillance. §1er/1. Le pouvoir organisateur ou son délégué présente un tableau récapitulatif à l''organe local de concertation sociale, au plus tard le 15 octobre de l''année scolaire. Le Gouvernement fournit un modèle de tableau permettant : - l''identification de l''établissement scolaire concerné ; - d''indiquer la date de la réunion de l''organe local de concertation sociale ; - l''identification des participants et l''organisation syndicale qu''ils représentent ; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 - l''option de base groupée et l''option de base simple éventuellement en maintien dans les différents degrés et formes concernés ; - d''indiquer les groupes-classes en dépassement par année d''étude, en reprenant par classe concernée : • l''année d''étude, la forme d''enseignement et le type de cours ; • la moyenne à respecter ; • le nombre maximum d''élèves autorisés ; • le nombre d''élèves dépassant la norme autorisée ; • la raison invoquée pour expliquer le dépassement d''après la liste établie ci- dessous et les arguments justifiant le choix de cette raison ; - la mention de l''avis favorable ou défavorable remis en séance par les différents représentants syndicaux présents et, en cas d''avis défavorable, les motifs de ce dernier. 1er/2. Les dépassements des moyennes visées au §1er sont interdits. Les dépassements des maxima visés au §1er ne sont possibles que dans les conditions fixées aux paragraphes 2, 3 et 4. Lors de la séance de présentation du tableau récapitulatif à l''organe local de concertation sociale, les représentants des organisations syndicales remettent chacun un avis favorable ou défavorable. L''avis défavorable est remis dans le cas où un dépassement est constaté et qu''il subsiste un désaccord sur la raison invoquée, ou en l''absence de raison invoquée. Les représentants des organisations syndicales ayant remis un avis défavorable peuvent introduire un recours motivé, non suspensif, par courrier recommandé ou par envoi électronique introduit auprès des Services du Gouvernement dans les cinq jours calendrier prenant cours au lendemain de la remise de l''avis. Si à la date du 15 octobre visée à l''alinéa 1er, le pouvoir organisateur ou son délégué n''a pas présenté le tableau récapitulatif susvisé à l''organe local de concertation sociale, les représentants des organisations syndicales bénéficient également d''un délai de cinq jours calendrier pour introduire un recours, non suspensif, contre cette absence de tableau. Les Services du Gouvernement instruisent le dossier et, le cas échéant, notifient leurs griefs au pouvoir organisateur concerné, qui dispose d''un délai de trente jours calendriers pour présenter ses observations écrites. Selon le cas, le Ministre en charge de l''enseignement secondaire - ou son délégué - ou le Gouvernement rend une décision dans les soixante jours qui suivent la clôture du délai visé à l''alinéa précédent. Une infraction est constatée lorsqu''il apparaît, au terme de la procédure, que le dépassement n''est pas justifié par une raison valable, que la raison invoquée n''est pas fondée ou si le pouvoir organisateur persiste à ne pas invoquer de raison ou remettre de tableau. En cas de constat d''une infraction, le Ministre en charge de l''enseignement secondaire ou son délégué prononce, dans le respect de la procédure énoncée ci-dessus, une des sanctions suivantes : Secondaire IV.B.01 Lois 17144 D. 29-07-1992 1° l''avertissement et le rappel au cadre adressés par l''Administration au pouvoir organisateur ; 2° en cas de récidive endéans les trois ans : - interdiction de bénéficier d''aide dans le cadre de l''octroi de périodes complémentaires visées au §5 durant les deux années scolaires suivantes pour l''école concernée ; - une amende dont le montant ne peut être inférieur à 250 euros ni excéder 2.500 euros. En cas de deuxième récidive constatée par les Services du Gouvernement, le Gouvernement peut appliquer, dans le respect de la procédure é');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 60, 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation (partie 3)', 'ci-dessus, une amende dont le montant équivaut à 5% des dotations ou des subventions de fonctionnement annuelles de l''école concernée. Les subventions et dotations de fonctionnement sont rétablies par le Gouvernement à la date, actée par les Services du Gouvernement, à laquelle toutes les normes relatives à la taille des classes auront été respectées. §2. Un dépassement du nombre d''élèves maximal fixé au §1er, alinéa 1er, d) à i), est possible à concurrence de : - un élève lorsque le maximum fixé est inférieur à 15 ; - deux élèves lorsque le maximum fixé est supérieur ou égal à 15. Ce dépassement n''est toutefois possible que si aucune option de base simple ou groupée du degré et de la forme concernés n''était sous la norme de maintien au 15 janvier de l''année scolaire précédente. Ces dépassements ne valent que pour un groupe-classe par année d''études. Le pouvoir organisateur ou son délégué doit indiquer les raisons de ce ou ces dépassements dans le tableau récapitulatif, visé au §1er/1, remis à l''organe local de concertation sociale, ces raisons peuvent notamment s''inscrire dans les situations reprises ci-dessous : a) en formation commune, dans un cours qui n''est organisé qu''en un ou deux groupes au niveau de l''année concernée ; font partie de la formation commune les cours qui ne font pas partie des options de base simples ou groupées ; b) dans un ou des cours d''une option de base simple ou groupée qui n''est organisée qu''en un seul groupe au niveau de l''année concernée ; c) dans un ou des cours d''une option de base groupée lorsque l''établissement organise au 1er octobre, dans le degré et la forme concernée, au moins, soit : - une option du secteur Industrie ; - une option du secteur Bois-Construction ; - une option dont la création, le maintien ou le regroupement est soutenue sous forme d''octroi de périodes par l''instance sous-régionale de pilotage inter- réseaux (en Secondaire IV.B.01 Lois 17144 D. 29-07-1992 abrégé : IPIEQ) créée par le décret du 30 avril 2009 relatif à la création d''instances de pilotage inter-réseaux de l''enseignement qualifiant (IPIEQ) et à l''octroi d''incitants visant un redéploiement plus efficient de l''offre d''enseignement qualifiant dans une perspective de développement territorial. §3. Un dépassement du nombre d''élèves maximal fixé au §1er, alinéa 1er, d) à i), est possible à concurrence de : - deux élèves lorsque le maximum fixé est inférieur à 15 ; - trois élèves lorsque le maximum fixé est supérieur ou égal à 15. Ce dépassement n''est toutefois possible que si au maximum une option de base simple ou groupée du degré et de la forme concernés était sous la norme de maintien au 15 janvier de l''année scolaire précédente. Le pouvoir organisateur ou son délégué doit indiquer les raisons de ce ou ces dépassements dans le tableau récapitulatif, visé au §1er/1, remis à l''organe local de concertation sociale, ces raisons peuvent notamment s''inscrire dans les situations reprises ci-dessous : d) la spécificité de l''offre de formation de l''établissement conduit à des déséquilibres tels, entre les populations des différentes options simples ou groupées à travers les différents degrés et formes, qu''ils ont des incidences sur un (des) cours de la formation non-optionnelle pour le(s)quel(s) le dépassement est demandé ; e) la spécificité de l''offre de formation de l''établissement conduit à des déséquilibres tels, entre les populations des différentes options de base simples ou groupées à travers les différents degrés et formes, qu''ils ont des incidences sur un (des) cours de la formation optionnelle pour le(s)quel(s) le dépassement est demandé ; f) les locaux, installations et équipements disponibles ne permettent pas une autre organisation, en ce compris pour l''éducation physique, en ce compris lorsque cette organisation résulte d''un cas de force majeure. Par « cas de force majeure », il y a lieu d''entendre un évènement irrésistible, imprévisible et extérieur à la personne qui l''invoque ; g) dans l''enseignement technique de qualification ou dans l''enseignement professionnel, l''organisation de la formation commune dans le respect des maxima obligerait à mettre ensemble des élèves provenant d''options appartenant à des secteurs différents. §4. Le pouvoir organisateur ou son délégué doit indiquer les raisons des dépassements au §1er, alinéa 1er, a), dans le tableau récapitulatif, visé au §1er/1, remis à l''organe local de concertation sociale, ces raisons peuvent notamment s''inscrire dans les situations reprises ci-dessous : 1° pour permettre, dans le cadre de l''application de l''article 1.7.7-30 du Code de l''enseignement fondamental et de l''enseignement secondaire, de dépasser le nombre de places déclaré ; 2° lorsque le nombre d''élèves inscrits en 1ère année commune de l''enseignement secondaire dépasse effectivement le nombre d''élèves déclarés en application de l''article 1.7.7-14, §1er, du Code de l''enseignement fondamental et de l''enseignement secondaire ; Secondaire IV.B.01 Lois 17144 D. 29-07-1992');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 61, 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation (partie 4)', '3° lorsque le dépassement, en 2ème année commune, de la norme fixée au §1er, alinéa 1er, a), est une conséquence de la dérogation accordée en 1ère année commune dans les cas repris en 1° et 2°. Cette dérogation n''est accordée que pour autant que le nombre de classes de 2e année de l''année scolaire pour laquelle la dérogation automatique est accordée soit égal au nombre de classes de 1ère de l''année scolaire précédente ; 4° lorsque l''organisation de classes de 25 élèves résulte de l''imposition d''inscription d''élèves exclus conformément à l''article 1.7.9-9 du code de l''enseignement fondamental et de l''enseignement secondaire en ce qui concerne les établissements organisés par la Communauté française ou à l''article 1.7.9-10 du code précité en ce qui concerne les établissements subventionnés par la Communauté française. §5. 1.471 périodes complémentaires sont affectées à l''enseignement secondaire et peuvent être octroyées aux établissements qui en formulent la demande afin de respecter les maxima prévus au §1er, alinéa 1er. Sous peine de nullité, la demande visée à l''alinéa précédent est introduite par le pouvoir organisateur ou son délégué dans l''enseignement organisé par la Communauté française et par le pouvoir organisateur dans l''enseignement subventionné, par l''intermédiaire de l''outil informatique mis à disposition par les Services du Gouvernement, au plus tard le 12 septembre. La demande motivée introduite par l''établissement est accompagnée des renseignements complets sur les périodes dont il dispose et ce quelle qu''en soit l''origine, y compris l''apport de périodes par les IPIEQ et les périodes obtenues pour l''encadrement différencié. L''octroi de ces périodes complémentaires est réservé aux implantations qui, pour respecter le nombre d''élèves maximal prévu au §1er, alinéa 1er, ont dû puiser dans leur nombre total de périodes professeurs et souhaitent mettre en place ou maintenir des dispositifs pédagogiques identifiés ayant pour but la remédiation, la guidance ou le soutien aux apprentissages. Le dossier de demande devra démontrer que ces dispositifs ne peuvent être mis en place sans ces périodes complémentaires. Les demandes sont analysées selon la procédure suivante : a) les périodes complémentaires sont d''abord attribuées par zone et, au sein de chaque zone, attribuées respectivement pour l''enseignement organisé par la Communauté française, l''enseignement officiel subventionné, l''enseignement libre confessionnel et l''enseignement libre non confessionnel, au prorata du nombre d''élèves régulièrement inscrits au 15 janvier de l''année scolaire précédente ; b) les demandes sont traitées : 1° pour l''enseignement organisé par la Communauté française, par les commissions zonales d''affectation visées à l''article 14quater de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements ou du comité de concertation central ; 2° pour l''enseignement subventionné par la Communauté française, par les commissions zonales de gestion des emplois compétentes pour l''enseignement secondaire visées au Chapitre II du décret du 12 mai 2004 relatif à la définition de la pénurie et à certaines Commissions dans l''enseignement organisé ou subventionné par Secondaire IV.B.01 Lois 17144 D. 29-07-1992 la Communauté française; ces commissions examinent les demandes avant le 23 septembre et attribuent les périodes en fonction de critères de pertinence et d''efficience pédagogique; si la commission le souhaite, le fait pour un établissement de bénéficier de l''encadrement différencié prévu par le décret du 30 avril 2009 peut faire partie des critères de sélection des projets; les commissions prévoient également des modalités de redistribution des périodes qui ne pourraient être attribuées à un ou plusieurs établissements en suivant les mêmes règles définies au 3ème alinéa et en appliquant les mêmes critères de pertinence et d''efficience pédagogique ; c) dans l''hypothèse où le nombre de périodes nécessaires pour satisfaire les demandes retenues excède le total disponible, le pouvoir organisateur visé au b), 1° ou la commission visée au b), 2° peut fixer un maximum par établissement ; d) le pouvoir organisateur visé au b), 1°, et les commissions visées au point b), 2°, transmettent leurs décisions quant à l''attribution des périodes complémentaires avant le 23 septembre aux Services du Gouvernement qui les communique, pour l''enseignement subventionné, aux pouvoirs organisateurs des établissements concernés avec copie à ces derniers. Le nombre de périodes octroyées ne pourra excéder le nombre de périodes demandées par l''école. Les périodes sont disponibles au 1er octobre ; e)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 62, 'Article 23. - A l''exception de la troisième année de différenciation, d''orientation (partie 5)', 'le pouvoir organisateur dont un établissement ne respecte plus au 1er octobre les conditions fixées à l''alinéa 3 du présent article en informe les Services du Gouvernement avant le 05 octobre ; ces périodes sont redistribuées selon les modalités fixées par le pouvoir organisateur visé au b). §6. Le cours de religion, de morale non confessionnelle et de philosophie et citoyenneté lorsque les élèves sont dispensés du cours de religion ou de morale, est organisé dans le respect des normes suivantes : 1° pour les années ou groupes d''années visés à l''article 7/1, alinéa 1er, 1 et 2, du décret du 29 juillet 1992 portant organisation de l''''enseignement secondaire de plein exercice, aucune classe ne peut compter plus de 25 élèves ; 2° pour les années ou groupes d''années visés à l''article 7/1, alinéa 1er, 3, du décret du 29 juillet 1992 portant organisation de l''''enseignement secondaire de plein exercice, aucune classe ne peut compter plus de 15 élèves ; 3° pour les années ou groupes d''années visés à l''article 7/1, alinéa 1er, 4, du décret du 29 juillet 1992 portant organisation de l''''enseignement secondaire de plein exercice, aucune classe ne peut compter plus de 17 élèves ; 4° pour les années ou groupes d''années visés à l''article 7/1, alinéa 1er, 5 à 21, du décret du 29 juillet 1992 portant organisation de l''''enseignement secondaire de plein exercice, aucune classe ne peut compter, en moyenne, plus de 27 élèves. §7. Les tableaux récapitulatifs visés au §1er/1, sont transmis aux Services du Gouvernement au plus tard le dernier jour ouvrable scolaire précédant le début des vacances d''hiver (de Noël). Le Service général de l''Inspection est chargé de procéder à des contrôles systématiques du respect des dispositions visées au présent article selon les modalités définies par le Gouvernement. Tous les trois ans, pour le 31 mars au plus tard, les Services du Gouvernement procèdent à une évaluation du respect des normes relatives à la taille des classes. Secondaire IV.B.01 Lois 17144 D. 29-07-1992 Inséré par D. 12-12-2008 [Article 23ter. - Les Services du Gouvernement sont chargés du contrôle du respect des dispositions visées aux articles 16 et 20.]17 CHAPITRE IV. - Concertation Complété et modifié par D. 21-12-1992; D. 19-07-1993; D. 02-04-1996 ; complété par D. 11-04-2014 ; D. 03-04-2014 ; D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 63, 'Article 24. - Le Gouvernement:', 'Article 24. - Le Gouvernement: 
1° détermine les options et sections qui peuvent être organisées par degré ou 
cycle et par forme d''enseignement; 
2° classe les options et sections en secteurs et, à l''intérieur des secteurs, en 
groupes; 
3° définit, par zone géographique qu''il détermine, les obligations de concertation 
entre les écoles d''enseignement secondaire ordinaire et spécialisé de même caractère; 
[remplacé par D. 25-04-2019] 
4° crée des organes de concertation communs aux écoles d''enseignement 
secondaire ordinaire et spécialisé, dont un comité de concertation par caractère et des 
conseils de zone. Il en fixe les modalités d''organisation. [Inséré par D. 03-04-2014 ; remplacé 
par D. 25-04-2019] 
 
Par dérogation à l''alinéa 1er, 2°, le Gouvernement peut déterminer une ou 
plusieurs options de la 3ème année de l''enseignement de qualification relevant de 
plusieurs secteurs afin de permettre à des élèves de choisir leur orientation en 
connaissance de cause. [Inséré par D. 11-04-2014] 
 
La concertation visée à l''alinéa 1er, 3°, porte notamment sur la programmation et 
sur l''harmonisation de l''offre régionale de formation et l''utilisation des périodes-
professeurs visée à l''article 21.  
 
Remplacé par D. 10-04-1995; modifié par D. 02-04-1996 ; complété par D. 16-06-
2016 ; D. 24-05-2017 ; D. 14-06-2018 ; D. 25-04-2019 ; D. 17-07-2020 ; D. 14-07-2021 ; 
modifié par D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 64, 'Article 25. - Est subordonnée à l''avis favorable issu de la concertation visée à', 'Article 25. - Est subordonnée à l''avis favorable issu de la concertation visée à 
l''article 24, alinéa 1er, 3°, l''organisation ou l''admission aux subventions : 
1° de nouvelles options de l''enseignement secondaire ordinaire et spécialisé de 
forme 4, des formations en alternance visées à l''article 2bis, § 1er, 2° du décret du 3 
juillet 1991 organisant l''enseignement secondaire en alternance, et des formations de 
l''enseignement spécialisé de forme 3 et 4; [complété par D. 25-04-2019] 
2° […] Si un pouvoir organisateur outrepasse un avis défavorable, il perd le 
bénéfice des crédits ou des subventions pour l''ensemble de l''établissement où l''option 
ou l''activité en cause est organisée pendant les années scolaires où elle est organisée. 
 
Le fait pour un pouvoir organisateur de ne pas solliciter l''avis de l''organe de 
concertation visé à l''article 24 est assimilé au fait d''outrepasser un avis défavorable. 
 
Inséré par D. 16-06-2016 ; modifié par D. 17-07-2020 ; D. 20-07-2022 
[Pour les années scolaires 2023-2024 et 2024-2025, l''organisation ou l''admission 
aux subventions de nouvelles options de base groupées dans l''enseignement secondaire 
qualifiant est soumise à l''autorisation du Gouvernement.  
 
Pour l''année scolaire 2023-2024, cette autorisation ne peut être accordée que 
dans les cas suivants :  
 
17Remplacé par le D. 04-04-2024 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992 
1° une option de base groupée que le pouvoir organisateur a proposé de créer en 
4e ou en 5e année, conformément à l''article 24, § 2, de l''Arrêté de l''Exécutif de la 
Communauté française du 15 mars 1993 fixant les obligations de concertation entre 
établissements dans l''enseignement secondaire de plein exercice ;  
2° une option de base groupée R2 approuvée au 2e ou au 3e degré pour l''année 
scolaire 2022-2023 et qui n''a pas pu être organisée en 2022-2023 ;  
3° une option de base groupée que le pouvoir organisateur propose de créer en 
remplacement d''une option de base groupée qu''il supprime et qui compte encore des 
élèves au 1er octobre de l''année scolaire en cours, et ce, dans le respect des éléments 
visés aux alinéas 7 et suivants ; 
4° une option de base groupée qui est inscrite pour la première fois au répertoire 
à partir du 1er septembre 2014 et qui concerne un métier émergent, c''est-à-dire un 
métier pour lequel le S.F.M.Q. a proposé un profil de formation, et qui est lié à une 
option n''ayant jamais figuré au répertoire et ne résultant pas de la transformation 
d''une option du répertoire existant ;  
5° une option de base groupée dans une école en création qui organise pour la 
première fois une 3e, une 4e ou une 7e année ;  
6° pour des motifs exceptionnels et justifiés, une option de base groupée qui est 
représentée en nombre insuffisant dans un bassin, ou une option de base groupée 
nécessaire pour garantir aux élèves de 4e ou de 6e année la continuité de leur 
formation dans l''établissement, respectivement en 5e année ou en 7e année 
professionnelle de type B, ou pour assurer la survie d''un établissement, quel que soit 
son réseau. »]18 
 
L''admission aux subventions de nouvelles options de base groupées dans 
l''enseignement secondaire technique, artistique et professionnel est automatiquement 
examinée par les Services du Gouvernement au terme du processus de 
programmation. [Inséré par D. 24-05-2017] 
 
[Pour l''année scolaire 2024-2025, l''autorisation du Gouvernement ne peut être 
accordée que dans les cas suivants : 1° une option de base groupée qui a été autorisée 
pour l''année scolaire 2023-2024 mais qui n''a pas pu être organisée en 2023-2024 ; 2° 
une option de base groupée qui concerne un métier émergent, c''est-àdire un métier 
pour lequel le S.F.M.Q. a proposé un profil de formation, et qui est lié à une option 
n''ayant jamais figuré au répertoire avant le 1er septembre 2014 et ne résultant pas de 
la transformation d''une option du répertoire existant. Le Gouvernement autorise les 
incitants, sur la base des avis émis d''initiative par les chambres Enseignement pour la 
création, le maintien ou la fermeture d''une option de base groupée pour l''année 
scolaire 2023-2024. Le Gouvernement autorise également les budgets consacrés par 
les chambres Enseignement aux actions collectives et projets visant à favoriser, en 
inter-réseaux, la découverte, la promotion et la valorisation de l''enseignement 
qualifiant pour l''année scolaire 2023-2024. Les incitants autorisés par le 
Gouvernement pour la création d''une option de base groupée qui ont été donnés pour 
l''année scolaire 2023-2024 sont également valables pour l''année scolaire 2024-2025. 
Les options de base groupées pourront être ouvertes en référence à 60% de la norme de 
création. Les incitants sont supprimés à partir de l''année scolaire 2025-2026. »]19 
 
CHAPITRE V. - Dispositions finales');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 65, 'Article 26. - § 1er. Sont abrogés: (partie 1)', 'Article 26. - § 1er. Sont abrogés: 1° les articles 1 à 5, 8 à 16, 19, 20, 21, 22 et 23 du décret du 2 juillet 1990 fixant le mode de calcul et d''utilisation du nombre global de périodes/professeurs pour l''enseignement de plein exercice de type I et de type II; 18 Inséré par D. 22/06/2023 (art. 44) 19 Inséré par D. 22/06/2023 (art. 44) Secondaire IV.B.01 Lois 17144 D. 29-07-1992 2° l''article 2, § 3, de la loi du 19 juillet 1971 relative à l''organisation et à la structure générale de l''enseignement secondaire; 3° l''arrêté royal du 15 décembre 1973 déterminant les normes de dédoublement et de regroupement d''années d''études dans l''enseignement technique, en ce qu''il concerne l''enseignement secondaire de plein exercice; 4° l''article 1er, 2°, de l''arrêté royal du 9 novembre 1981 déterminant les conditions auxquelles doit répondre un centre d''enseignement secondaire; 5° les articles 12, 33, alinéa 2 et 38 de l''arrêté royal du 30 mars 1982 précité. § 2. Dans l''arrêté royal n° 49 du 2 juillet 1982 relatif aux normes de création, de maintien et de dédoublement et au calcul de crédit d''heures de l''enseignement secondaire de type I, concernant la fusion d''établissements, ainsi que certains emplois du personnel des établissements d''enseignement secondaire de plein exercice de type I et de type II, sont apportées les modifications suivantes: 1° l''article 4, modifié par la loi du 29 juin 1983 est remplacé par la disposition suivante: "Art. 4. - § 1er. Au premier et au deuxième degrés sont requis: a) 10 élèves au minimum pour: - une option de base, - une activité complémentaire. Toutefois, lorsqu''une option de la troisième année, dont le ministre admet le caractère polyvalent, est scindée en plusieurs options dans la quatrième année, l''une de celles-ci n''est pas soumise à la norme; b) 8 élèves au minimum pour: - une option en quatrième année de réorientation; - une option en cinquième année de perfectionnement ou de spécialisation ou une moyenne de 8 élèves lorsque plusieurs options sont organisées, à condition que chacune d''entre elles compte au moins 6 élèves. Toutefois, aucune norme n''est requise en cinquième année de perfectionnement ou de spécialisation lorsqu''il s''agit d''une option dans laquelle le certificat de qualification n''est pas délivré à la fin de la quatrième année d''études par application de l''article 23, 3°, de l''arrêté royal du 30 juillet 1976 susvisé; c) 12 élèves au minimum pour une première année B et 15 élèves pour une deuxième année professionnelle. Toutefois ces minima de population sont réduits respectivement à 6 et 12 pour une première création dans un nouveau centre d''enseignement secondaire. § 2. Dans l''année préparatoire à l''enseignement professionnel, pour l''organisation de plus d''un domaine d''activités professionnelles, une moyenne de 10 élèves est requise à condition que chacun d''entre eux compte au moins 8 élèves. En deuxième année professionnelle, pour la création de plus d''une option de base, une moyenne de 10 élèves est requise à condition que chacune d''entre elles compte au moins 8 élèves. § 3. Si, en troisième année de transition et en troisième année de qualification de l''enseignement technique, des options groupées de même appellation sont organisées, une moyenne de 10 élèves est requise à condition que chacune d''entre elles compte au moins 8 élèves. » 2° les mots "de haute fréquence" sont supprimés: à l''article 5, d, modifié par l''arrêté royal n° 539 du 31 mars 1987; 3° les mots "de haute fréquence" sont supprimés: à l''article 5, a, modifié par l''arrêté royal n° 438 du 11 août 1986; 4° les mots "une option de fréquence" sont supprimés: à l''article 5, b; Secondaire IV.B.01 Lois 17144 D. 29-07-1992 5° l''article 8 est abrogé; 6° sont également abrogés: a) l''article 2, § 2; b) l''article 5, c, modifié par l''arrêté royal n° 438 du 11 août 1986; c) l''article 24bis, inséré par la loi du 29 juin 1983. d) l''article 7, § 5, dernier alinéa. § 3. Dans l''arrêté royal du 30 mars 1982 précité, l''Exécutif est habilité à modifier les dispositions qui y ont été introduites par les arrêtés n° 438 du 11 août 1986 établissant pour l''année scolaire 1986-1987 le nombre de périodes-professeurs pour l''enseignement de plein exercice de type I, n° 539 du 31 mars 1987 fixant le nombre de périodes-professeurs pour l''enseignement de plein exercice de type I pour l''année scolaire 1987-1988, et n° 540 du 31 mars 1987 fixant le nombre de périodes- professeurs pour l''enseignement de plein exercice de type II pour l''année scolaire 1987-1988. § 4. Par dérogation à l''article 3, § 2, alinéa 2, de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement, un centre d''enseignement secondaire peut être constitué du seul établissement subsistant à la suite de fusion ou de fermeture d''établissement. L''alinéa 1er n''est applicable que jusqu''à la création des zones géographiques en application de l''article 24, alinéa 1er, 3°. Inséré par D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 66, 'Article 26', 'Article 26/1. - Dans les options de base groupées visées à l''article 51, § 1er, du 
décret 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ), en plein 
exercice, un complément de périodes-professeurs est alloué aux écoles pour les élèves 
de chaque option de base groupée organisée avant le 29 août 2022 dans le cadre de 
l''enseignement expérimental visé à l''article 1er du décret du 14 juin 2018 instituant un 
enseignement expérimental aux 2ème et 3ème degrés de l''enseignement secondaire 
qualifiant en ce qui concerne la certification par unités d''acquis d''apprentissage 
(CPU), et aux 2ème et 3ème degrés de l''enseignement de transition en ce qui concerne 
le dépassement du nombre maximum de périodes hebdomadaires, et portant diverses 
dispositions en matière d''enseignement obligatoire, d''organisation du jury délivrant le 
certificat d''aptitudes pédagogiques et de concertation avec les pouvoirs organisateurs 
et les organisations syndicales. 
 
Ces périodes seront utilisées, dans le respect des dispositions statutaires 
applicables, pour organiser des activités de remédiation au bénéfice des élèves, ainsi 
que l''année complémentaire visée à l''article 11, § 3, du décret 20 juillet 2022 relatif au 
parcours d''enseignement qualifiant (PEQ). 
 
Le complément de périodes-professeur visé à l''alinéa précédent est calculé comme 
suit: 
 
1° pour l''année scolaire 2022-2023: 0,12 période est alloué par élève 
régulièrement inscrit en 5ème année et 0,20 période est alloué par élève régulièrement 
inscrit en 6ème et 7ème années sur la base de la population des élèves de 5ème, de 
6ème et de 7ème au 15 janvier 2022; 
 
2° pour l''année scolaire 2023-2024:0,20 période est alloué par élève régulièrement 
inscrit en 6ème année sur la base de la population des élèves de 6ème au 15 janvier 
2023. 
 
Secondaire 
 
IV.B.01 
Lois 17144 
 
D. 29-07-1992');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 67, 'Article 27. - L''Exécutif peut coordonner les dispositions législatives et décrétales', 'Article 27. - L''Exécutif peut coordonner les dispositions législatives et décrétales 
relatives à l''enseignement secondaire ainsi que les dispositions qui les auraient 
expressément ou implicitement modifiées au moment où cette coordination sera 
établie. 
 
A cette fin, il peut: 
1° modifier l''ordre, le numérotage et, en général, la présentation des dispositions 
à coordonner, sous d''autres divisions; 
2° modifier les références qui seraient contenues dans les dispositions à 
coordonner en vue de les mettre en concordance avec le numérotage nouveau; 
3° modifier la rédaction des dispositions à coordonner, en vue d''assurer leur 
concordance et d''en unifier la terminologie, sans qu''il puisse être porté atteinte aux 
principes inscrits dans ces dispositions. 
 
La coordination portera l''intitulé suivant: 
"Décret relatif à l''enseignement secondaire, coordonné le ... ".');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 68, 'Article 28. - L''Exécutif arrête les mesures transitoires pour les cinq premières', 'Article 28. - L''Exécutif arrête les mesures transitoires pour les cinq premières 
années d''application des chapitres 1er et 2 du présent décret de manière à: 
1° permettre un passage progressif des résultats qui auraient été obtenus par le 
calcul fixé par le décret du 2 juillet 1990 précité aux résultats obtenus par le calcul fixé 
en application du présent décret; 
2° permettre la réaffectation dans une autre fonction des membres du personnel 
nommés à titre définitif, et dont la nomination est agréée là où l''agréation existe, dans 
une fonction de promotion ou dans une fonction de sélection et qui seraient placés en 
disponibilité par défaut d''emploi suite aux dispositions du chapitre 1er; 
3° faciliter l''adaptation à leur nouvelle structure des établissements qui 
fusionnent.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('17144', 69, 'Article 29. - L''Exécutif fixe la date d''entrée en vigueur des dispositions du', 'Article 29. - L''Exécutif fixe la date d''entrée en vigueur des dispositions du 
présent décret, à l''exception: 
a) de l''article 26, § 1er, 4° et 5°, et § 2, 1°, 2°, 3°, 4° et 6°, qui produit ses effets le 
1er juillet 1992; 
b) de l''article 26, § 2, 5°, qui entre en vigueur le 1er juillet 1993. 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur belge. 
 
Bruxelles, le 29 juillet 1992. 
 
Le Ministre-Président de l’Exécutif de la Communauté française chargé de la 
Culture et de la Communication, 
 
B. ANSELME 
 
Le Ministre de l’Enseignement supérieur, de la Recherche scientifique et des 
Relations internationales,  
 
M. LEBRUN 
 
Le Ministre de l’Education, 
 
E. DI RUPO 
 
La Ministre des Affaires sociales et de la Santé, 
 
Mme M. DE GALAN');

