INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 1, 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental et à', 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental et à 
l''enseignement secondaire ordinaire et spéciaux organisés ou subventionnés par la 
Communauté française.  
 
Modifié par D. 03-03-2004 
Articles 2 et 3 […] Abrogés par D. 03-05-2019 (code) 
 
Modifié par D. 03-03-2004 ; D. 07-12-2007 ; D. 12-07-2012 ; D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 2, 'Article 4. - Afin de permettre un parcours pédagogique différencié et mieux', 'Article 4. - Afin de permettre un parcours pédagogique différencié et mieux 
adapté aux besoins des élèves qui ne sont pas titulaires du Certificat d''Etudes de 
Base, les deux premières années de l''enseignement secondaire ordinaire et spécialisé 
de forme 4 sont organisés de manière différenciée, conformément à l''article 2, § 2, de la 
loi du 19 juillet 1971 précitée. 
 
Les troisième, à l''exception de la troisième année de différenciation et 
d''orientation, quatrième, cinquième et sixième années de l''enseignement secondaire 
ordinaire et spécialisé de forme 4 sont organisées en deux sections : 
1° la 
section 
de 
transition, 
comprenant 
les 
humanités 
générales 
et 
technologiques, qui visent à la préparation aux études supérieures mais permettent 
aussi l''entrée dans la vie active; 
2° la section de qualification, comprenant les humanités professionnelles et 
techniques, qui visent à préparer l''entrée dans la vie active par l''attribution d''un 
certificat de qualification mais permettent aussi l''accès aux études supérieures.  
 
Complété par D. 29-03-2001 ; modifié par D. 27-03-2002 ; D. 03-03-2004 ; D. 12-07-
2012(1) ; complété par D. 04-02-2016 ; D. 07-12-2017 ; modifié par D. 13-09-2018 ; 
complété par D. 14-03-2019 ; D. 25-04-2019 ; modifié par D. 28-03-2019 ; D. 09-07-2020 ; 
D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 3, 'Article 5. - Dans l''ensemble de la législation et de la réglementation relative aux (partie 1)', 'Article 5. - Dans l''ensemble de la législation et de la réglementation relative aux niveaux d''enseignement visés au présent chapitre, sont retenues les définitions suivantes : 1° compétence : aptitude à mettre en oeuvre un ensemble organisé de savoirs, de savoir-faire et d''attitudes permettant d''accomplir un certain nombre de tâches; 1° bis. Socles de compétences initiales : référentiel précisant les socles de compétences par cycles compris dans la première étape visée à l''article 13, § 3, et présentant les compétences de base à développer. Elles s''inscrivent dans les cycles et le continuum pédagogique et visent à assurer la transition harmonieuse entre l''enseignement maternel et l''enseignement primaire sans donner lieu à une certification. Les socles de compétences initiales sont inclus dans les socles de compétences tels que définis au 2° ; [inséré par D. 04-02-2016] 2° socles de compétences: référentiel présentant de manière structurée les compétences de base à exercer de la première année de l''enseignement primaire à la deuxième année de l''enseignement secondaire et celles qui sont à maîtriser à la fin de chacune des étapes de celles-ci parce qu''elles sont considérées comme nécessaires à l''insertion sociale et à la poursuite des études; [modifié par D. 09-07-2020] 2°bis. compétences-seuils: référentiel présentant de manière structurée les compétences dont la maîtrise à un niveau déterminé est attendue à la fin de chaque phase de l''enseignement spécialisé de forme 3. 3° compétences terminales : référentiel présentant de manière structurée les compétences dont la maîtrise à un niveau déterminé est attendue à la fin de l''enseignement secondaire; 4° compétences disciplinaires : référentiel présentant de manière structurée les Secondaire IV.A.16 Lois 21557 D. 24-07-1997 compétences à acquérir dans une discipline scolaire; 5° «Métier» : un ensemble cohérent d''activités professionnelles réalisées par une personne dans le cadre d''un processus productif; [remplacé par D. 12-07-2012] 6° «Activités-clés» : les activités indispensables pour remplir les missions qui sont confiées au travailleur dans le cadre de sa fonction; [remplacé par D. 12-07-2012] 7° «Profil de formation SFMQ» : le profil composé des unités d''acquis d''apprentissage associées aux activités clés du métier, d''un profil d''évaluation, d''un indice d''appréciation temporelle et d''un profil d''équipement; le profil de formation est élaboré par le Service francophone des métiers et des qualifications et est approuvé par le Gouvernement; [remplacé par D. 12-07-2012 ; modifié par D. 20-07-2022] 7° bis «Profil de formation CCPQ»: défini à l''article 2, 9° du décret du 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ) ; [inséré par D. 20-07-2022] 8° «Acquis d''apprentissage» : l''énoncé de ce que l''apprenant sait, comprend et est capable de réaliser au terme d''un processus d''apprentissage; les acquis d''apprentissage sont définis en termes de savoirs, aptitudes et compétences professionnels, au sens de la Recommandation du Parlement européen et du Conseil du 23 avril 2008 établissant le cadre européen des certifications pour l''éducation et la formation tout au long de la vie; [remplacé par D. 12-07-2012] 9° «Unité d''acquis d''apprentissage» : l''ensemble cohérent d''acquis d''apprentissage qui peut être évalué ou validé; [remplacé par D. 12-07-2012] 10° «Profil d''évaluation» : le profil qui détermine des seuils de maîtrise minimums exigés en vue de la délivrance d''une attestation de compétence ou en vue de servir de référence à l''élaboration des épreuves certificatives; [remplacé par D. 12-07-12] 11° «Points ECVET» (tels que prévus par la Recommandation du Parlement européen et du Conseil du 18 juin 2009 établissant le système européen de crédit d''apprentissages pour l''enseignement et la formation professionnels" European Credit for vocational education and training") : la représentation numérique du poids global des acquis d''apprentissage exigés pour la délivrance d''un certificat de qualification et du poids relatif de chacune des unités par rapport à la certification; [remplacé par D. 12- 07-2012] 12° «Indice d''appréciation temporelle» : l''indice qui détermine pour chaque activité-clé la durée optimale d''acquisition des savoirs, aptitudes et compétences professionnels qui y sont associés; [remplacé par D. 12-07-2012] 13° «Profil d''équipement» : le profil qui détermine l''équipement et l''infrastructure suffisant à la mise en oeuvre du profil de formation. L''équipement peut être localisé soit dans l''école soit chez un partenaire et, notamment, dans un Centre de compétence, un Centre de référence, un Centre de technologies avancées, une entreprise; [remplacé par D. 12-07-2012] 14° «Profil de certification» défini à l''article 2, 6° du décret du 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ ; [remplacé par D. 12-07-2012 ; D. 20-07- 2022] 15° programmes d''études : référentiel de situations d''apprentissage, de contenus d''apprentissage');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 4, 'Article 5. - Dans l''ensemble de la législation et de la réglementation relative aux (partie 2)', 'obligatoires ou facultatifs, et d''orientations méthodologiques qu''un pouvoir organisateur définit afin d''atteindre les compétences fixées par le Gouvernement pour une année, un degré ou un cycle; 16° compétences transversales : attitudes, démarches mentales et démarches méthodologiques communes aux différentes disciplines à acquérir et à mettre en oeuvre au cours de l''élaboration des différents savoirs et savoir-faire; leur maîtrise vise à une autonomie croissante d''apprentissage des élèves; 17° évaluation formative : évaluation effectuée en cours d''activité et visant à apprécier le progrès accompli par l''élève et à comprendre la nature des difficultés qu''il rencontre lors d''un apprentissage; elle a pour but d''améliorer, de corriger ou de réajuster le cheminement de l''élève; elle se fonde en partie sur l''auto-évaluation; 18° épreuves à caractère sommatif : épreuves situées à la fin d''une séquence d''apprentissage et visant à établir le bilan des acquis des élèves; 19° pédagogie différenciée : démarche d''enseignement qui consiste à varier les méthodes pour tenir compte de l''hétérogénéité des classes ainsi que de la diversité des Secondaire IV.A.16 Lois 21557 D. 24-07-1997 modes et des besoins d''apprentissage des élèves; 20° pilotage : dispositif constitué de la Commission de pilotage créée par le décret du 27 mars 2002 relatif au pilotage du système éducatif de la Communauté française, des groupes de travail, des commissions de programmes et des commissions d''outils d''évaluation visant à mettre en oeuvre les missions prioritaires et particulières définies conformément au décret ; [modifié par D. 13-09-2018] 21° travaux à domicile : activité dont la réalisation peut être demandée à l''élève, en dehors des heures de cours, par un membre du personnel enseignant. 22° besoin spécifique» : besoin résultant d''une particularité, d''un trouble, d''une situation permanents ou semi-permanents d''ordre psychologique, mental, physique, psycho-affectif faisant obstacle au projet d''apprentissage et requérant, au sein de l''école, un soutien supplémentaire pour permettre à l''élève de poursuivre de manière régulière et harmonieuse son parcours scolaire dans l''enseignement ordinaire fondamental ou secondaire ; [inséré par D. 07-12-2017 – En vigueur au 01-09-2018] 23° aménagement raisonnable» : conformément à l''article 3, 9° du décret du 12 décembre 2008 relatif à la lutte contre certaines formes de discrimination, mesures appropriées, prises en fonction des besoins dans une situation concrète, afin de permettre à une personne présentant des besoins spécifiques d''accéder, de participer et de progresser dans son parcours scolaire, sauf si ces mesures imposent à l''égard de l''établissement qui doit les adopter une charge disproportionnée. [Inséré par D. 07-12- 2017 – En vigueur au 01-09-2018] Les n° 24° à 42° sont insérés par D. 13-09-2018 24° directeur de zone : le membre du service général de Pilotage des Ecoles et Centres psycho-médico-sociaux visé à l''article 3 du décret du 13 septembre 2018 portant création du Service général de pilotage des écoles et Centres psycho-médico- sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs qui, pour une zone déterminée, est en charge de : a) la procédure de contractualisation des plans de pilotage, du suivi de leur degré de réalisation et de l''évaluation des contrats d''objectifs visés à l''article 67; b) de l''adoption et du suivi des dispositifs d''ajustement visés à l''article 68 ainsi que de la coordination des délégués au contrat d''objectifs; 25° délégué au contrat d''objectifs : le membre du service général de Pilotage des Ecoles et Centres psycho-médico-sociaux visé à l''article 3 du décret du 13 septembre 2018 portant création du Service général de pilotage des écoles et Centres psycho- médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs qui est en charge, sous l''autorité du directeur de zone, de la procédure de contractualisation des plans de pilotage, du suivi de leur degré de réalisation et de l''évaluation des contrats d''objectifs ainsi que de la procédure de contractualisation des dispositifs d''ajustement, du suivi et de l''évaluation de leur degré de réalisation et de l''évaluation de la mise en oeuvre des protocoles de collaboration; 26° Délégué coordonnateur : le Délégué coordonnateur visé à l''article 3 du décret du 13 septembre 2018 portant création du Service général de pilotage des écoles et Centres psycho-médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs qui dirige le service général de Pilotage des Ecoles et Centres psycho-médico-sociaux 27° plan de pilotage : le plan visé à l''article 67, § 2; 28° contrat d''objectifs : le contrat visé à l''article 67, § 6; 29° pouvoir organisateur : l''autorité publique ou la personne morale qui assume la responsabilité de l''organisation d''une école organisée ou subventionnée par la Communauté française; 30° fédérations de pouvoirs organ');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 5, 'Article 5. - Dans l''ensemble de la législation et de la réglementation relative aux (partie 3)', ': les organes de représentation et de coordination des pouvoirs organisateurs de l''enseignement et des centres P.M.S. reconnus par le Gouvernement, répondant aux critères de l''article 5bis de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement; 31° décret Inspection et Conseiller pédagogique : le décret du 8 mars 2007 relatif au service général de l''inspection, au service de conseil et de soutien pédagogiques de l''enseignement organisé par la Communauté française, aux cellules de conseil et de Secondaire IV.A.16 Lois 21557 D. 24-07-1997 soutien pédagogiques de l''enseignement subventionné par la Communauté française et au statut des membres du personnel du service général de l''inspection et des conseillers pédagogiques; 32° décret Encadrement différencié : le décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité; Ce 33° sera abrogé au 25 août 2025 (D. 20-07-2022 – art. 13. N° 50485) 33° décret CPU : le décret du 12 juillet 2012 organisant la certification par unité d''acquis d''apprentissage (CPU) dans l''enseignement secondaire qualifiant et modifiant diverses dispositions relatives à l''enseignement secondaire; 33°bis «décret PEQ»: le décret du 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ) ; [inséré par D. 20-07-2022] 34° décret de l''enseignement spécialisé : le décret du 3 mars 2004 organisant l''enseignement spécialisé; 35° dispositif d''ajustement : le dispositif visé à l''article 68, § 4; 36° protocole de collaboration : le protocole visé à l''article 68, § 7; 37° organes locaux de concertation sociale : les instances de concertation locale instituées en vertu de la loi du 19 décembre 1974 organisant les relations entre les autorités publiques et les syndicats des agents relevant de ces autorités, de la loi du 20 septembre 1948 portant organisation de l''économie, de l''arrêté du Gouvernement de la Communauté française du 13 septembre 1995 relatif à la création, à la composition et aux attributions des commissions paritaires locales dans l''enseignement officiel subventionné, de l''arrêté du Gouvernement de la Communauté française du 27 mars 1996 rendant obligatoire la décision du 24 janvier 1996 de la Commission paritaire de l''Enseignement fondamental libre confessionnel relative à la création d''une instance de concertation locale entre pouvoirs organisateurs et délégations syndicales et de l''arrêté du Gouvernement de la Communauté française du 18 juin 1999 rendant obligatoire la décision du 31 mai 1999 de la Commission paritaire de l''enseignement fondamental libre non confessionnel relative à la création d''une instance de concertation locale entre pouvoirs organisateurs et délégations syndicales; 38° la Cellule de soutien et d''accompagnement : l''une des Cellules de soutien et d''accompagnement visées par le décret du 28 mars 2019 relatif aux Cellules de soutien et d''accompagnement de l''enseignement organisé ou subventionné par la Communauté française et au statut des Conseillers au soutien et à l''accompagnement; [remplacé par D. 28-03-2019] 39° zones : les zones telles que définies à l''article 1er de l''arrêté de l''Exécutif de la Communauté française du 15 mars 1993 fixant les obligations de concertation entre les établissements dans l''enseignement secondaire de plein exercice; 40° directeur : le directeur au sens du décret du 2 février 2007 fixant le statut des directeurs; 41° jours ouvrables scolaires : le lundi, le mardi, le mercredi, le jeudi, le vendredi, à l''exception de ceux qui tombent durant un jour férié, pendant les vacances scolaires ou tout autre jour de congé scolaire; 42° équipe pédagogique et éducative : le personnel directeur et enseignant, le personnel paramédical, le personnel social, le personnel psychologique, le personnel auxiliaire d''éducation, le personnel administratif et le personnel ouvrier ; 43° frais scolaires» : les frais afférents à des services et fournitures portant sur des activités organisées dans le cadre de l''enseignement dispensé par les écoles organisées ou subventionnées durant les périodes d''apprentissages prévues dans l''horaire des élèves. Sont aussi considérés comme frais scolaires les droits d''accès à la piscine, les droits d''accès aux activités culturelles et sportives et les frais liés aux séjours pédagogiques avec nuitée(s) ; [inséré par D. 14-03-2019] 44° Conseil général de l''enseignement fondamental : le Conseil créé par l''article 21 du décret du 14 mars 1995 relatif à la promotion d''une école de la réussite dans l''enseignement fondamental ; [inséré par D. 14-03-2019] 45° Conseil général de l''enseignement secondaire : le Conseil créé par l''article 1er Secondaire IV.A.16 Lois 21557 D. 24-07-1997 du décret du 27 octobre 1994 organisant la concertation pour l''enseignement secondaire. [Inséré par D. 25-04-2019] Intitulé modi');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 6, 'Article 5. - Dans l''ensemble de la législation et de la réglementation relative aux (partie 4)', 'par D 13-09-2018(1) CHAPITRE II. - Des missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire Modifié par D 13-09-2018(1) Articles 6 à 11. – […] Abrogés par D. 03-05-2019 (code) Intitulé remplacé par D. 13-09-2018(1) CHAPITRE III. - Des missions particulières communes à l''enseignement fondamental et au 1er degré de l''enseignement secondaire Intitulé modifié par D. 03-03-2004 ; complété par D. 04-02-2016 Section 1ère. Des cycles, des degrés de maturité et des socles de compétences Modifié par D 13-09-2018(1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 7, 'Article 12. - […] Abrogé par D. 03-05-2019 (code) / Article 13. - § 1er.', 'Article 12. - […] Abrogé par D. 03-05-2019 (code) 
 
Modifié par D. 03-03-2004 ;  D. 05-02-2009 ; D. 25-04-2019 ; D. 09-07-2020

Article 13. - § 1er. 
Dans 
l''enseignement 
ordinaire, 
la 
formation 
de 
l''enseignement maternel et de la première année de l''enseignement primaire à la 
deuxième année de l''enseignement secondaire constitue un continuum pédagogique 
structuré en trois étapes, visant à assurer à tous les élèves, les socles de compétences 
nécessaires à leur insertion sociale et à la poursuite de leurs études. 
 
§ 2. Les étapes visées au § 1er sont : 
1° de l''entrée dans l''enseignement fondamental à la fin de la deuxième année 
primaire; 
2° de la troisième à la sixième année primaires; 
3° les deux premières années de l''enseignement secondaire. 
 
§ 3. La première étape est organisée en deux cycles : 
1° de l''entrée en maternelle à 5 ans; 
2° de 5 ans à la fin de la deuxième année primaire. 
 
La deuxième étape est organisée en deux cycles : 
1° les troisième et quatrième années primaires; 
2° les cinquième et sixième années primaires. 
 
La troisième étape est organisée en un seul cycle. 
 
§ 3bis. - Dans l''enseignement spécialisé, la formation de l''enseignement 
maternel, primaire et du 1er degré ou de la 1re phase de l''enseignement secondaire 
constitue un continuum pédagogique structuré en trois étapes, visant à assurer à tous 
les élèves, les socles de compétences ou compétences-seuils nécessaires à leur insertion 
sociale et à la poursuite de leurs études.  
 
Les étapes visées à l''alinéa précédent sont :  
1°L''enseignement maternel;  
2° De la maturité I à la maturité IV dans l''enseignement primaire;  
3° Le 1er degré ou la 1re phase de l''enseignement secondaire 
 
Modifié par D. 25-04-2019 
§ 4. Sur proposition conjointe des Conseils généraux visés à l''article 5, 44° et 45°, 
le Gouvernement peut adapter le continuum pédagogique visé au § 3bis pour 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
l''enseignement spécialisé.  
 
Modifié par D. 03-03-2004');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 8, 'Article 14. - Tout établissement organisant l''enseignement fondamental ou', 'Article 14. - Tout établissement organisant l''enseignement fondamental ou 
primaire ou le premier degré ou la première phase d''enseignement secondaire définit, 
dans son projet visé à l''article 67, les moyens qu''il mettra en oeuvre pour faciliter la 
transition entre les deux dernières années de l''enseignement primaire et le premier 
degré ou la première phase de l''enseignement secondaire. Ces moyens pourront 
comprendre notamment l''échange de documents pédagogiques et d''informations 
relatives à la maîtrise des socles de compétences ou des compétences-seuils, à la 
réalisation d''activités en commun et, de manière plus générale, aux concertations en 
matière de projets d''établissement. 
 
Modifié par D. 03-03-2004 ; D. 07-12-2007 ; D. 11-04-2014 (1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 9, 'Article 15. - Chaque établissement d''enseignement permet à chaque élève de', 'Article 15. - Chaque établissement d''enseignement permet à chaque élève de 
progresser à son rythme, en pratiquant l''évaluation formative et la pédagogie 
différenciée. 
 
Dans l''enseignement ordinaire, 
1° l''élève amené à parcourir la deuxième étape de l''enseignement obligatoire en 
cinq ans plutôt qu''en quatre peut suivre l''année complémentaire adaptée à ses besoins 
d''apprentissage dans le même établissement; 
2° l''élève amené à parcourir le premier degré de l''enseignement secondaire en 
trois ans plutôt qu''en deux peut suivre l''année supplémentaire adaptée à ses besoins 
d''apprentissage dans le même établissement.   
 
Dans le cadre des dispositions fixées par le décret du 30 juin 2006 relatif à 
l''organisation pédagogique du premier degré de l''enseignement secondaire, le projet 
d''établissement visé à l''article 67 fixe les modalités selon lesquelles est organisé le 
parcours en trois ans du premier degré ou en cinq ans de la deuxième étape de 
l''enseignement obligatoire. 
 
Dans l''enseignement spécialisé, l''élève évolue selon son rythme d''apprentissage 
et ses potentialités dans les différents degrés de maturité sur avis du Conseil de 
classe. 
 
Modifié par D. 26-04-1999 ; D. 03-03-2004 ; D. 25-04-2019 ; D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 10, 'Article 16. - § 1er. Le Gouvernement détermine les socles de compétences et les', 'Article 16. - § 1er. Le Gouvernement détermine les socles de compétences et les 
soumet à la confirmation du Parlement.  
 
§ 2. Des groupes de travail sont créés, selon les modalités que fixe le 
Gouvernement, afin d''élaborer les socles de compétences en distinguant les trois 
étapes visées à l''article 13.  
 
Les groupes de travail transmettent leurs propositions relatives aux socles de 
compétences aux Conseils généraux visés à l''article 5, 44° et 45°.  
 
S''ils l''estiment nécessaire, les Conseils généraux amendent ces propositions. Ils 
transmettent au Gouvernement les propositions telles qu''ils les ont amendées et les 
propositions originales des groupes de travail.  
 
Selon leur objet, les groupes de travail sont composés de représentants de 
l''enseignement fondamental ou de l''enseignement secondaire ainsi que de l''inspection. 
Les groupes de travail entendent, à titre d''expert, toute personne qu''ils jugent utile. 
Les groupes de travail tiennent aussi des réunions communes afin d''harmoniser les 
propositions relatives à l''enseignement fondamental et à l''enseignement secondaire. 
 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
§ 3. […] Abrogé par D. 03-05-2019 (code) 
 
Inséré par D. 04-02-2016 ; modifié par D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 11, 'Article 16bis. - […] Abrogé par D. 03-05-2019 (code) / Article 17. - § 1er. Le Gouvernement approuve les programmes d''études des', 'Article 16bis. - […] Abrogé par D. 03-05-2019 (code) 
 
Modifié par D. 03-03-2004; D. 04-05-2005 ; D. 25-04-2019 ; D. 03-05-2019(code)

Article 17. - § 1er. Le Gouvernement approuve les programmes d''études des 
cycles, années et degrés de maturité visés au présent chapitre, après avoir pris l''avis 
de la Commission des programmes, et une fois cet avis donné, après avoir consulté la 
Commission de pilotage créée par le décret du 27 mars 2002 relatif au pilotage du 
système éducatif de la Communauté française. [Remplacé par D. 25-04-2019] 
 
§ 2. […] Abrogé par D. 25-04-2019 
 
§ 3. Il est créé une Commission des programmes, selon les modalités que fixe le 
Gouvernement. 
 
La Commission des programmes vérifie si les programmes d''études permettent 
d''atteindre les socles de compétences et/ou, pour l''enseignement spécialisé, s''ils 
permettent aux élèves à besoins spécifiques d''évoluer de manière optimale. 
 
Le contrôle de la Commission des programmes ne porte pas sur les méthodes 
pédagogiques. 
 
§ 4 et § 5. […] Abrogés par D. 03-05-2019 (code) 
 
Articles 18 et 19 - […] Abrogés par D. 03-05-2019 (code).');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 12, 'Article 20. - Pour les étapes et cycles d''études visés à l''article 13, le contrôle du', 'Article 20. - Pour les étapes et cycles d''études visés à l''article 13, le contrôle du 
niveau des études visé aux articles 6 et 24 de la loi du 29 mai 1959 modifiant certaines 
dispositions de la législation de l''enseignement comprend aussi la vérification : 
1° de l''adéquation entre les activités proposées aux élèves et les socles de 
compétences; 
2° du respect des priorités fixées dans les socles de compétences; 
3° de l''équivalence du niveau des épreuves d''évaluation administrées aux élèves à 
celui des épreuves produites par la Commission des outils d''évaluation visée à l''article 
19. 
 
Intitulé remplacé par D. 09-07-2020 
Section 2. De l''orientation après les neuf premières années de scolarité 
obligatoire 
 
Modifié par D. 09-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 13, 'Article 21. - A l''issue des neuf premières années de la scolarité obligatoire, les / Article 22. - Le conseil de classe est responsable de l''orientation. Il associe à', 'Article 21. - A l''issue des neuf premières années de la scolarité obligatoire, les 
élèves sont orientés vers la forme d''enseignement la mieux adaptée à leurs aspirations 
et à leurs capacités.

Article 22. - Le conseil de classe est responsable de l''orientation. Il associe à 
cette fin le centre psycho-médico-social et les parents. A cet effet, il guide chaque élève 
dans la construction d''un projet de vie scolaire et professionnelle selon les modalités 
décrites à l''article 67. 
 
Modifié par D. 05-12-2013');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 14, 'Article 23.', 'Article 23. En collaboration avec le Centre psycho-médico-social, chaque 
établissement d''enseignement secondaire communique aux élèves du premier degré 
ainsi qu''à leurs parents, une information complète : 
1° sur les formations organisées aux 2ème et 3ème degrés des Humanités 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
professionnelles et techniques, en ce compris les formations artistiques; 
2° sur les formations organisées aux 2ème et 3ème degrés des Humanités 
générales et technologiques, en ce compris les formations artistiques; 
3° sur les formations en alternance organisées conformément aux dispositions de 
la loi du 29 juin 1983 concernant l''obligation scolaire. 
 
Chaque établissement d''enseignement secondaire met en contact les élèves du 
premier degré par des visites, telles que visées à l''article 7bis, § 2, de la loi du 19 
juillet 1971 relative à la structure générale et à l''organisation de l''enseignement 
secondaire ou des stages d''observation et d''initiation, tels que visés à l''article 7bis, § 5 
de la même loi, avec des établissements d''enseignement organisant la section de 
transition ou la section de qualification, ou avec des centres de compétence ou de 
référence professionnelle, ou avec des centres de technologies avancées, ou avec des 
entreprises. 
 
L''information, les visites et les stages favorisent une orientation positive des 
élèves à l''issue du premier degré.  
 
Intitulé remplacé par D. 13-09-2018(1) 
CHAPITRE IV. - Des missions particulières des Humanités générales et 
technologiques 
 
Section 1ère. Des compétences et des savoirs requis à l''issue des Humanités 
générales et technologiques 
 
Modifié par D 13-09-2018(1) ; D. 09-02-2023');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 15, 'Article 24. - Les Humanités générales et technologiques assurent une formation', 'Article 24. - Les Humanités générales et technologiques assurent une formation 
humaniste, dans la perspective des missions prioritaires définies à l''article 1.4.1-1 du 
Code de l''enseignement fondamental et de l''enseignement secondaire.  
 
Modifié par D. 26-04-1999 ; D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 16, 'Article 25. - § 1er. Le Gouvernement détermine et soumet à la confirmation du', 'Article 25. - § 1er. Le Gouvernement détermine et soumet à la confirmation du 
Parlement :  
1° les compétences terminales et savoirs communs requis de l''ensemble des 
élèves à l''issue de la section de transition; 
2° les compétences terminales et savoirs requis dans les différentes disciplines de 
la section de transition; 
3° les compétences minimales en matière de communication dans une langue 
moderne autre que le français à l''issue de la section de transition. 
 
§ 2. Des groupes de travail sont créés, selon les modalités que fixe le 
Gouvernement, afin d''élaborer les différents savoirs et compétences. 
 
Les groupes de travail transmettent leurs propositions relatives aux savoirs et 
compétences au Conseil général de l''enseignement secondaire.  
 
S''il l''estime nécessaire, le Conseil général amende ces propositions. Il transmet 
au Gouvernement les propositions telles qu''il les a amendées et les propositions 
originales des groupes de travail. 
 
Les groupes de travail sont composés de représentants de l''enseignement 
secondaire, de l''inspection et de l''enseignement supérieur. Les groupes de travail 
entendent, à titre d''expert, toute personne qu''ils jugent utile. Le nombre total des 
représentants de l''enseignement supérieur ne peut être supérieur au nombre de 
représentants de l''enseignement secondaire.  
 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
Modifié par D. 26-04-1999 ; D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 17, 'Article 26. - § 1er. Le Gouvernement peut déterminer et soumettre à la', 'Article 26. - § 1er. Le Gouvernement peut déterminer et soumettre à la 
confirmation du Parlement : 
1° les compétences et savoirs communs requis de l''ensemble des élèves à l''issue 
du deuxième degré de la section de transition; 
2° les compétences et savoirs requis dans les différentes disciplines à l''issue du 
deuxième degré de la section de transition; 
 
§ 2. Des groupes de travail sont créés, selon les modalités que fixe le 
Gouvernement, afin d''élaborer les différents savoirs et compétences. 
 
Les groupes de travail transmettent leurs propositions relatives aux savoirs et 
compétences au Conseil général de l''enseignement secondaire.  
 
S''il l''estime nécessaire, le Conseil général amende ces propositions. Il transmet 
au Gouvernement les propositions telles qu''il les a amendées et les propositions 
originales des groupes de travail. 
  
Les groupes de travail sont composés de représentants de l''enseignement 
secondaire et de l''inspection. Les groupes de travail entendent, à titre d''expert, toute 
personne qu''ils jugent utile. 
 
La définition des compétences et savoirs requis à l''issue du deuxième degré tient 
compte des compétences et savoirs terminaux fixés en application de l''article 25. 
 
Modifié par D. 04-05-2005 ; D. 25-04-2019 ; D. 03-05-2019(code)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 18, 'Article 27. - § 1. Le Gouvernement approuve, dans le respect des compétences et', 'Article 27. - § 1. Le Gouvernement approuve, dans le respect des compétences et 
savoirs définis aux articles 25 et 26, les programmes d''études des degrés et années 
visés au présent chapitre, après avoir pris l''avis de la Commission des programmes 
des Humanités générales et technologiques, et une fois cet avis donné, après avoir 
consulté la Commission de pilotage créée par le décret du 27 mars 2002 précité. 
 
§ 2. […] Abrogé par D. 25-04-2019 
 
§§ 3 à 5. […] Abrogés par D. 03-05-2019 (code) 
 
Modifié par D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 19, 'Article 28. - Les services pédagogiques de la Communauté française et ceux des', 'Article 28. - Les services pédagogiques de la Communauté française et ceux des 
différents pouvoirs organisateurs pour l''enseignement subventionné produisent des 
outils pédagogiques propres à faciliter la mise en oeuvre des compétences et savoirs 
visés aux articles 25 et 26. Ces outils pédagogiques peuvent être utilisés par n''importe 
quel établissement organisé ou subventionné par la Communauté française.  
 
Le Gouvernement, après avoir pris l''avis des Conseils généraux visés à l''article 5, 
44° et 45°, arrête les modalités de leur diffusion au bénéfice de l''ensemble des pouvoirs 
organisateurs.  
 
Des outils pédagogiques propres à l''enseignement spécialisé peuvent également 
être créés en complément aux outils communs à tous.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 20, 'Article 29. - Il est créé une Commission des outils d''évaluation des Humanités', 'Article 29. - Il est créé une Commission des outils d''évaluation des Humanités 
générales et technologiques. 
  
Cette Commission produit des batteries d''épreuves d''évaluation étalonnées et 
correspondant aux compétences et savoirs fixés aux articles 25 et 26. 
 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
Le gouvernement les diffuse, à titre indicatif, auprès de tous les établissements 
organisés ou subventionnés par la Communauté française selon les modalités qu''il 
définit. Ces batteries d''épreuves sont également communiquées aux institutions 
chargées de la formation initiale ou continuée des enseignants. 
 
Les batteries d''épreuves d''évaluation peuvent également être adaptées pour 
l''enseignement spécialisé, en fonction du handicap et en complément des batteries 
communes à tous. 
 
Modifié par D 13-09-2018(1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 21, 'Article 30. - Dans le cadre de son projet, visé à l''article 67, chaque établissement', 'Article 30. - Dans le cadre de son projet, visé à l''article 67, chaque établissement 
peut répartir les volumes-horaires réservés à une, plusieurs ou toutes les disciplines 
dans des ensembles fonctionnels d''études s''étendant sur plusieurs semaines. Il peut 
aussi regrouper le temps réservé à plusieurs disciplines pour des activités 
interdisciplinaires ou culturelles. La seule obligation de l''établissement, lorsqu''il fait 
appel à la présente disposition, est d''indiquer comment les procédures particulières 
qu''il met en oeuvre, sont de nature à remplir les missions prioritaires visées à l''article 
6 et les compétences et savoirs visés aux articles 25 et 26, dans le cadre des 
programmes d''études adoptés par son pouvoir organisateur. 
 
A l''exception des cours de religion et de morale non confessionnelle et d''éducation 
physique, les cours qui comptent un volume horaire de moins de trois périodes 
hebdomadaires peuvent être regroupés sur une année du degré ou sur un semestre par 
année.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 22, 'Article 31. - Pour les années d''études visées au présent chapitre, le contrôle du', 'Article 31. - Pour les années d''études visées au présent chapitre, le contrôle du 
niveau des études visé aux articles 6 et 24 de la loi du 29 mai 1959 modifiant certaines 
dispositions de la législation de l''enseignement comprend aussi la vérification : 
1° de l''adéquation entre les activités proposées aux élèves et les compétences et 
savoirs requis; 
2° de l''équivalence du niveau des épreuves d''évaluation administrées aux élèves à 
celui des épreuves produites par la Commission des outils d''évaluation visée à l''article 
29. 
 
Section 2. De l''orientation au cours et au terme des Humanités générales et 
technologiques. 
 
Complété par D. 05-12-2013');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 23, 'Article 32. - § 1er. L''orientation associe les équipes d''enseignants, les centres', 'Article 32. - § 1er. L''orientation associe les équipes d''enseignants, les centres 
psycho-médico-sociaux, les parents, les élèves. Elle est une des tâches essentielles du 
Conseil de classe. 
 
§ 2. Le Gouvernement met à la disposition des établissements d''enseignement 
secondaire des informations relatives aux études supérieures avec indication des 
exigences propres à chacune des filières.  
 
Le Gouvernement veille à la concordance entre les exigences à l''entrée dans 
l''enseignement supérieur et les compétences et savoirs définis à l''article 25 et les 
batteries d''épreuves produites par la Commission des outils d''évaluation visée à 
l''article 29. 
 
A la demande de l''élève inscrit en dernière année des Humanités générales et 
technologiques, le centre psycho- médico-social associé à l''établissement amène l''élève 
à découvrir ses motivations et ses capacités à mener à bien ses projets. 
 
Dans le cadre de son projet, visé à l''article 67, chaque établissement peut affecter 
l''équivalent de deux semaines réparties sur l''ensemble du troisième degré à des 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
activités destinées à favoriser la maturation par les élèves de leurs choix 
professionnels et des choix d''études qui en résultent. Ces activités font partie des 
études régulières de l''élève. Les membres du personnel qui coordonnent et guident ces 
activités sont en activité de service. 
 
Ces activités peuvent prendre la forme de stages d''observation et d''initiation, tels 
que visés à l''article 7bis, § 5 de la loi du 19 juillet 1971 relative à la structure générale 
et à l''organisation de l''enseignement secondaire. [Inséré par D. 05-12-2013] 
 
Section 3. Des crédits d''études obtenus dans les Humanités générales et 
technologiques. 
 
Modifié par D. 09-02-2017 ; remplacé par D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 24, 'Article 33.', 'Article 33. Après avoir pris l''avis de l''Académie de recherche et d''enseignement 
supérieur créée par le décret du 7 novembre 2013 définissant le paysage de 
l''enseignement supérieur et l''organisation académique des études, du Conseil général 
de l''enseignement secondaire visé à l''article 5, 25° et du Conseil général de 
l''enseignement de promotion sociale créé par le décret du 16 avril 1991 organisant 
l''enseignement de promotion sociale, le Gouvernement détermine les crédits d''études 
acquis dans le cadre de l''enseignement secondaire qualifiant qui sont valorisables 
dans l''enseignement supérieur organisé dans les Hautes Ecoles et dans l''enseignement 
de promotion sociale, ainsi que les modalités de cette valorisation. 
 
Intitulé remplacé par D. 13-09-2018(1) 
CHAPITRE V. -  Des missions particulières communes aux Humanités 
professionnelles et techniques. 
 
Section 1ère. Des compétences et des savoirs requis en matière de formation 
humaniste à l''issue des Humanités professionnelles et techniques. 
 
Modifié par D. 12-07-2012(1) ; D.13-09-2018(1) ; D. 20-07-2022 ; D. 09-02-2023');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 25, 'Article 34. - Les Humanités professionnelles et techniques assurent une', 'Article 34. - Les Humanités professionnelles et techniques assurent une 
formation humaniste, dans la perspective des missions prioritaires définies à l''article 
1.4.1-1 du Code de l''enseignement fondamental et de l''enseignement secondaire.  
 
Cette formation est réalisée par des cours généraux et par l''ensemble de la 
formation qualifiante.  
 
La formation qualifiante vise la maîtrise des unités d''acquis d''apprentissage pour 
les options de base groupées liées avec des profil(s) de formation élaboré(s) par le 
Service francophone des métiers et des qualifications (SFMQ) et pour lesquelles un 
profil de certification a été établi et approuvé par le Gouvernement, et la maîtrise des 
ensembles de compétences du schéma de passation, fixé par le pouvoir organisateur, 
pour les options de base groupés liées à un profil de formation défini antérieurement 
par la Commission communautaire des Professions et des Qualifications pour 
lesquelles un profil de certification n''a pas encore été défini. [Remplacé par D. 12-07-2012 ; 
D. 20-07-2022] 
 
Modifié par D. 26-04-1999 ; modifié par D. 03-03-2004 ; D. 20-07-2006 ; D. 19-07-
2011 ; D. 12-07-2012(1) ; D. 25-04-2019; D. 28-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 26, 'Article 35. - § 1er. Le Gouvernement détermine et soumet à la confirmation du', 'Article 35. - § 1er. Le Gouvernement détermine et soumet à la confirmation du 
Parlement :  
1° les compétences terminales et les savoirs communs requis de l''ensemble des 
élèves à l''issue de la section de qualification débouchant sur la délivrance du certificat 
d''enseignement secondaire supérieur; 
2° les compétences minimales en mathématiques à l''issue de la section de 
qualification, lorsque l''apprentissage des mathématiques figure au programme 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
d''études; 
3° les acquis d''apprentissage minimaux dans une langue moderne autre que le 
français à l''issue de la section de qualification. [Remplacé par D. 12-07-2012] 
4° les compétences terminales et les savoirs communs requis de l''ensemble des 
élèves à l''issue de la troisième phase de l''enseignement secondaire spécialisé de forme 
3 débouchant sur la délivrance d''un certificat d''enseignement secondaire inférieur 
équivalant au certificat d''enseignement secondaire du deuxième degré. 
 
§ 2. Des groupes de travail sont créés, selon les modalités que fixe le 
Gouvernement, afin d''élaborer les différents savoirs et compétences. 
 
Les groupes de travail transmettent leurs propositions relatives aux savoirs et 
compétences au Conseil général de l''enseignement secondaire.  
 
S''il l''estime nécessaire, le Conseil général amende ces propositions. Il transmet 
au Gouvernement les propositions telles qu''il les a amendées et les propositions 
originales des groupes de travail. 
  
Les groupes de travail sont composés de représentants de l''enseignement 
secondaire, de l''inspection, des Cellules de soutien et d''accompagnement, de 
l''enseignement supérieur et de l''enseignement de promotion sociale. Les groupes de 
travail entendent, à titre d''expert, toute personne qu''ils jugent utile. Les 
représentants de l''enseignement supérieur et de l''enseignement de promotion sociale 
ne peuvent être ensemble en nombre supérieur à celui des représentants de 
l''enseignement secondaire. 
 
Modifié par D. 03-03-2004; D. 04-05-2005 ; D. 25-04-2019 ; D. 03-05-2019(code)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 27, 'Article 36. - § 1er. Le Gouvernement approuve, dans le respect des compétences', 'Article 36. - § 1er. Le Gouvernement approuve, dans le respect des compétences 
et savoirs définis à l''article 35, les programmes d''études des cours spécifiques à la 
formation humaniste durant les degrés et années visés au présent chapitre, après 
avoir pris l''avis de la Commission des programmes des Humanités professionnelles et 
techniques, et une fois cet avis donné, après avoir consulté la Commission de pilotage 
créée par le décret du 27 mars 2002 précité.  
 
§ 2. […] Abrogé par D. 25-04-2019 
 
Remplacé par D. 25-04-2019 
§ 2bis. Pour l''enseignement spécialisé, le Gouvernement approuve, dans le 
respect des compétences et savoirs définis à l''article 35, les programmes d''études des 
cours spécifiques à la formation humaniste durant les phases d''enseignement visées 
au présent chapitre, après avoir pris l''avis de la Commission des programmes visée 
au § 3bis, et une fois cet avis donné, après avoir consulté la Commission de pilotage 
créée par le décret du 27 mars 2002 précité. 
 
§§ 3 à 5. […] Abrogés par D. 03-05-2019 (code) 
 
Modifié par D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 28, 'Article 37.', 'Article 37. Les services pédagogiques de la Communauté française et ceux des 
différents pouvoirs organisateurs pour l''enseignement subventionné produisent des 
outils pédagogiques propres à faciliter la mise en oeuvre des compétences et savoirs 
visés à l''article 35. Ces outils pédagogiques peuvent être utilisés par n''importe quel 
établissement organisé ou subventionné par la Communauté française.  
 
Le Gouvernement, après avoir pris l''avis des Conseils généraux visés à l''article 5, 
44 et 45°, arrête les modalités de leur diffusion au bénéfice de l''ensemble des Pouvoirs 
organisateurs.  
 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
Des outils pédagogiques propres à l''enseignement secondaire spécialisé peuvent 
également être créés en complément aux outils communs à tous.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 29, 'Article 38. - Il est créé une Commission des outils d''évaluation des Humanités', 'Article 38. - Il est créé une Commission des outils d''évaluation des Humanités 
professionnelles et techniques, selon les modalités que fixe le Gouvernement. 
  
Le Gouvernement diffuse, à titre indicatif, auprès de tous les établissements 
d''enseignement organisé ou subventionné par la Communauté française, selon les 
modalités qu''il définit, les batteries d''épreuves d''évaluation étalonnées et 
correspondant aux compétences et savoirs fixés à l''article 35 produites par cette 
Commission. Ces batteries d''épreuves sont également communiquées aux institutions 
chargées de la formation initiale des enseignants.  
 
Les batteries d''épreuves d''évaluation visées à l''alinéa précédent peuvent 
également être adaptées pour l''enseignement spécialisé, en fonction du handicap et en 
complément des batteries communes à tous. 
 
Intitulé remplacé par D. 12-07-2012(1) 
Section 2. - Des savoirs, aptitudes et compétences professionnels fixés 
par les profils de certification et de leur certification à l''issue des Humanités 
professionnelles et techniques. 
 
Modifié par D. 08-02-1999 ; remplacé par D. 12-07-2012(1) ; remplacé par D. 14-
06-2018 ; modifié par D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 30, 'Article 39. -  […] Abrogés par D. 03-05-2019 (code)', 'Article 39. -  […] Abrogés par D. 03-05-2019 (code) 
 
Inséré par D. 03-03-2004; remplacé par D. 12-07-2012 (1); modifié par  D. 11-04-2014 ; 
D. 04-02-2016 ; D. 14-06-2018 ; D. 25-04-2019 ; DF. 28-03-2019 ; D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 31, 'Article 39bis. - § 1er. Les profils de certification visés à l''article 5, 14° :', 'Article 39bis. - § 1er. Les profils de certification visés à l''article 5, 14° : 
1° spécifient l''intitulé de l''option de base groupée ou de la formation concernée ; 
ils précisent également la durée obligatoire en année(s) scolaire(s) sur laquelle est 
organisée ladite option groupée ou ladite formation, sauf pour les options de 
l''enseignement en alternance organisées conformément à l''article 2bis, § 1er, 2° du 
décret du 3 juillet 1991 organisant l''enseignement secondaire en alternance et les 
formations à un métier organisées dans l''enseignement secondaire spécialisé de forme 
3 pour lesquelles la durée est indicative ; 
2° identifient le ou les profils de formation au(x)quel(s) se réfère l''option de base 
groupée ou la formation concernée ; 
3° déterminent, pour l''enseignement de plein exercice, le nombre minimum et le 
nombre maximum de semaines de stage que doivent accomplir les élèves de l''option de 
base groupée ou de la formation concernée, dans le respect des dispositions prises en 
application de l''article 7bis, § 13, de la loi du 19 juillet 1971 relative à la structure 
générale et à l''organisation de l''enseignement secondaire ; 
4° déterminent le ou les certificat(s) de qualification délivré(s) aux élèves qui 
maîtrisent les acquis d''apprentissage fixés par le ou les profil(s) de formation 
concerné(s); 
5° reprennent le positionnement de la certification dans le Cadre francophone de 
certification, tel qu''arrêté par l''Instance de Pilotage et de Positionnement «C.F.C.» 
visée à l''article 4 de l''accord de coopération du 26 février 2015 entre la Communauté 
française, la Région wallonne et la Commission communautaire française concernant 
la création et la gestion d''un Cadre francophone des certifications, en abrégé «C.F.C.», 
ou à défaut un positionnement provisoire ; 
6° reprennent 
 a) le parcours d''apprentissage décliné en unités reprenant ou regroupant 
explicitement les unités d''acquis d''apprentissage du ou des profil(s) de formation; ce 
sont les unités d''acquis d''apprentissage du profil de formation qui font l''objet de la 
validation; 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
 b) les activités-clés du métier auxquelles les unités se réfèrent; 
 c) les recommandations pour l''ordre dans lequel les unités doivent être 
enseignées; les profils de certification peuvent imposer un ordre dans le parcours 
d''apprentissage, si nécessaire, pour tout ou partie des UAA ; 
 d) les indications temporelles suggérées pour chaque unité; 
 e) les points ECVET alloués, d''une part, à l''ensemble de l''option de base groupée 
ou de la formation considérée et, d''autre part, à chacune des unités d''acquis 
d''apprentissage; 
 f) les savoirs, aptitudes et compétences liés aux disciplines de la formation 
générale qui sont nécessaires à l''exercice des compétences professionnelles ; 
 g) le ou les profil(s) d''évaluation; 
 h) le ou les profil(s) d''équipement ; 
 i) le(s) modèle(s) de Supplément au certificat Europass que les établissements 
scolaires doivent délivrer aux élèves titulaires de la certification concernée. [§ remplacé 
par D. 14-06-2018] 
 
Inséré par D. 14-06-2018 ; modifié par D. 25-04-2019 
§ 1bis. Préalablement à la constitution d''un des groupes de travail visés au § 3, le 
Ministre qui a l''enseignement secondaire dans ses attributions : 
a) informe le Conseil général de l''enseignement secondaire du ou des profil(s) de 
formation à partir du(des)quel(s) un profil de certification va être construit ; 
b) sollicite l''avis du Conseil général de l''enseignement secondaire 
- s''il échet, sur la combinaison des profils de formation appelés à faire l''objet d''un 
seul profil de certification ; 
- sur le positionnement de l''option de base ou de la formation visée par le profil de 
certification : dans l''enseignement ordinaire et/ou spécialisé, de plein exercice et/ou en 
alternance ; 
- ainsi sur les années d''études, degrés ou phase concernés. 
 
Le Conseil général de l''enseignement secondaire remet son avis dans un délai 
maximum de cinq semaines après avoir été saisis. 
 
Remplacé par D. 14-06-2018 ; modifié par D. 28-03-2019 
§ 2. […] Abrogé par D. 03-05-2019 (code) 
 
Remplacé par D. 12-07-2012(1) ; D. 14-06-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 32, 'Article 40. – Jusqu''à ce qu''un profil de certification ait été défini par le', 'Article 40. – Jusqu''à ce qu''un profil de certification ait été défini par le 
Gouvernement conformément aux articles 39, 44, 45 et 47, les établissements 
d''enseignement secondaire ordinaire et spécialisés concernés continuent de se référer, 
pour les options de base groupées et les formations qu''ils organisent, aux profils de 
formation définis antérieurement par la Commission communautaire des Professions 
et des Qualifications visée à l''article 7 du décret du 27 octobre 1994 organisant la 
concertation pour l''enseignement secondaire.');
