INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 34, 'Article 43. - A partir des profils de certification, le Gouvernement, après avoir', 'Article 43. - A partir des profils de certification, le Gouvernement, après avoir 
pris l''avis du conseil général de l''enseignement secondaire, détermine et soumet à la 
confirmation du Parlement : 
 
1° le répertoire des options de base groupées, conformément à l''article 24 du 
décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein 
exercice; ce répertoire reprend l''intitulé des options de base groupées et celui du ou des 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
profils de formation élaboré(s) par le Service francophone des Métiers et des 
Qualifications au(x)quels le profil de certification adosse ces options de base groupées. 
[Remplacé par D. 12-07-2012] 
2° les conditions d''admission dans les diverses années, formes et options. 
 
A partir des profils de certification visés à l''article 47, le Gouvernement, après 
avoir pris l''avis du Conseil général de l''enseignement secondaire, détermine et soumet 
à la confirmation du Parlement : 
1° le répertoire des formations à un métier de l''enseignement secondaire 
spécialisé; ce répertoire reprend l''intitulé des formations à un métier et celui du ou des 
profils de formation élaboré(s) par le Service francophone des Métiers et des 
Qualifications au(x)quels le profil de certification adosse ces formations à un métier ; 
2° le répertoire des options de base groupées adossées à un profil de formation 
spécifique visé à l''article 47, § 2 ; 
3° les conditions d''admission dans les divers secteurs, groupes professionnels et 
formations à un métier de l''enseignement secondaire spécialisé de forme 3. [alinéa 
remplacé par D. 14-06-2018] 
 
Remplacé par D. 12-07-2012(1) ; D. 14-06-2018 ; modifié par D. 25-04-2019');
