INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 37, 'Article 48. - […] Abrogé par D. 03-05-2019 (code) / Article 49. - Pour autant que les programmes d''études spécifiques assurent de', 'Article 48. - […] Abrogé par D. 03-05-2019 (code) 
 
Modifié par D. 19-07-2001 (1) ; modifié par D. 03-03-2004 ; D. 12-07-2012

Article 49. - Pour autant que les programmes d''études spécifiques assurent de 
manière identique la réalisation des objectifs de formation fixés en application des 
articles 35 et 39, le Gouvernement peut autoriser la réalisation de certains des profils 
de certification visés aux articles 39, 44 et 47 sous forme de : 
1° formation en alternance, conformément au décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance; 
2° formation organisée par l''enseignement de promotion sociale; 
3° formation organisée par l’enseignement secondaire spécialisé de forme 3 et de 
forme 4. 
 
Modifié par D. 03-03-2004; D. 04-05-2005 ; D. 12-07-2012(1) ; D. 14-06-2018 ; D. 25-
04-2019 ; D. 03-05-2019(code)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 38, 'Article 50. - § 1er. Le Gouvernement approuve, dans le respect des profils de', 'Article 50. - § 1er. Le Gouvernement approuve, dans le respect des profils de 
certification visés aux articles 39, 44, 45 et 47, les programmes d''études des degrés et 
années visés au présent chapitre, après avoir pris l''avis de la Commission des 
programmes des Humanités professionnelles et techniques ou de la Commission des 
programmes de l''enseignement secondaire spécialisé, et une fois cet avis donné, après 
avoir consulté la Commission de pilotage créée par le décret du 27 mars 2002 précité. 
[Remplacé par D. 25-04-2019] 
 
§ 2. […] Abrogé par D. 25-04-2019 
 
§ 2bis. […] Abrogé par D. 14-06-2018 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
§ 3. […] Abrogé par D. 03-05-2019 (code) 
 
Remplacé par D. 11-04-2014 (1) ; modifié par D. 03-05-2019 
§ 4. Les programmes d''études proposent des situations d''apprentissage et 
indiquent des contenus d''apprentissage obligatoires ou facultatifs. Ils fournissent des 
orientations méthodologiques. Les situations et contenus d''apprentissage ainsi que les 
orientations méthodologiques doivent permettre d''acquérir la maîtrise des acquis 
d''apprentissage fixés par les profils de certification visés aux articles 39, 44, 45 et 47. 
 
Par dérogation à l''article 1.3.1-1, 49°, du Code de l''enseignement fondamental et 
de l''enseignement secondaire, pour les options de base groupées ou les formations pour 
lesquelles le Gouvernement a défini un profil de certification, les programmes peuvent 
ne pas proposer des situations d''apprentissage et des contenus d''apprentissage 
obligatoires : les situations d''apprentissage ainsi que les contenus d''apprentissage 
obligatoires sont les parcours d''apprentissage que détermine le profil de certification, 
conformément à l''article 39bis, 6°, a). Ces programmes fournissent en tout cas des 
orientations méthodologiques. 
 
Par dérogation à l''article 1.3.1-1, 47°, du Code de l''enseignement fondamental et 
de l''enseignement secondaire, pour les options de base groupées ou les formations pour 
lesquelles le Gouvernement n''a pas encore défini un profil de certification, les 
programmes se réfèrent aux profils de formation conformément à l''article 40 du 
présent décret et à l''article 1.4.3-2, § 4, alinéa 2, du Code de l''enseignement 
fondamental et de l''enseignement secondaire, sans préjudice de l''article 342 du décret 
du 3 mars 2004 organisant l''enseignement spécialisé. 
  
Modifié par D. 03-03-2004 ; D. 12-07-2012(1) ; D. 25-04-2019 
Articles 51 et 52. -  […] Abrogés par D. 03-05-2019 (code) 
 
Complété par D. 03-03-2004 ; modifié par D. 12-07-2012(1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 39, 'Article 53. – […] Abrogé par D. 05-12-2013. / Article 54. - Dans le cadre de son projet, visé à l''article 67, chaque établissement', 'Article 53. – […] Abrogé par D. 05-12-2013. 
 
Modifié par D. 03-03-2004 ; D. 12-07-2012(1) ; D. 13-09-2018(1)

Article 54. - Dans le cadre de son projet, visé à l''article 67, chaque établissement 
peut répartir les volumes-horaires réservés à une, plusieurs ou toutes les disciplines, 
qu''il s''agisse des cours généraux ou de la formation qualifiante, dans des ensembles 
fonctionnels d''études s''étendant sur plusieurs semaines. Il peut aussi regrouper le 
temps réservé à plusieurs disciplines pour des activités interdisciplinaires ou 
culturelles. La seule obligation de l''établissement, lorsqu''il fait appel à la présente 
disposition, est d''indiquer que les procédures particulières qu''il met en oeuvre, sont de 
nature à remplir : 
1° les missions prioritaires visées à l''article 6; 
2° la formation globale visée à l''article 35; 
3° les acquis d''apprentissage fixés par les profils de certification visés aux articles 
39, 44, 45 et 47 dans le cadre des programmes d''études adoptés par son pouvoir 
organisateur. 
 
A l''exception des cours de religion et de morale non confessionnelle et d''éducation 
physique, les cours qui comptent un volume horaire de moins de trois périodes 
hebdomadaires peuvent être regroupés sur une année du degré ou sur un semestre par 
année.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 40, 'Article 55. - Pour les années d''études visées au présent chapitre, le contrôle du', 'Article 55. - Pour les années d''études visées au présent chapitre, le contrôle du 
niveau des études visé aux articles 6 et 24 de la loi du 29 mai 1959 modifiant certaines 
dispositions de la législation de l''enseignement comprend aussi la vérification : 
1° de l''adéquation entre les activités proposées aux élèves et les compétences et 
Secondaire 
 
