INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 42, 'Article 57. - Après avoir pris l''avis du Conseil général de l’enseignement', 'Article 57. - Après avoir pris l''avis du Conseil général de l’enseignement 
