INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 43, 'Article 58. - Après avoir pris l''avis de l''Académie de recherche et d''enseignement', 'Article 58. - Après avoir pris l''avis de l''Académie de recherche et d''enseignement 
supérieur (ARES) visé à l''article 33, du Conseil général de l''enseignement secondaire 
et du Conseil général de l''enseignement de promotion sociale visé à l''article 33, le 
Gouvernement détermine les crédits d''études acquis dans le cadre d''un profil de 
certification qui sont valorisables dans l''enseignement supérieur, organisé dans les 
Hautes Ecoles et dans l''enseignement de promotion sociale, ainsi que les modalités de 
cette valorisation. 
 
Section 4. De l''orientation au cours et au terme des Humanités 
professionnelles et techniques');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 44, 'Article 59. - L''orientation associe les équipes d''enseignants, les centres psycho-', 'Article 59. - L''orientation associe les équipes d''enseignants, les centres psycho-
médico-sociaux, les parents, les élèves. L''orientation est une des tâches essentielles du 
Conseil de classe.  
 
Modifié par D. 05-12-2013');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 45, 'Article 60. - Le Gouvernement met à la disposition des établissements', 'Article 60. - Le Gouvernement met à la disposition des établissements 
d''enseignement secondaire des informations relatives aux études supérieures avec 
indication des exigences propres à chacune des filières.  
 
Le Gouvernement veille à la concordance entre les exigences de formation globale 
à l''entrée dans l''enseignement supérieur et les compétences et savoirs définis à 
l''article 35, § 1er, 1°, ainsi qu''avec les batteries d''épreuves étalonnées visées à l''article 
52. 
 
A la demande de l''élève inscrit en sixième ou en septième année des Humanités 
professionnelles et techniques, le centre psycho-médico-social associé à l''établissement 
amène l''élève à découvrir ses motivations et ses capacités à mener à bien ses projets. 
 
Dans le cadre de son projet, visé à l''article 67, chaque établissement peut affecter 
l''équivalent de deux semaines réparties sur l''ensemble du troisième degré à des 
activités destinées à favoriser la maturation par les élèves de leurs choix 
professionnels et des choix d''études qui en résultent. Ces activités font partie des 
études régulières de l''élève. Les membres du personnel qui coordonnent et guident ces 
activités sont en activité de service. 
 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
Ces activités prennent notamment la forme de stages de pratique accompagnée, 
tels que visés à l''article 7bis, § 6 de la loi du 19 juillet 1971 précitée et de stages de 
pratique en responsabilité, tels que visés à l''article 7bis, § 7 de la même loi. 
 
Inséré par D. 22-10-2015 ; Abrogé par D. 03-05-2019 
CHAPITRE Vbis. - De l''éducation à la philosophie et à la citoyenneté 
 
