INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 47, 'Article 73bis. - Le chef d''établissement, pour l''enseignement organisé par', 'Article 73bis. - Le chef d''établissement, pour l''enseignement organisé par 
la Communauté   française,   et   le   pouvoir   organisateur   ou   son   délégué,   
pour l''enseignement subventionné par la Communauté française, mettent en oeuvre 
durant les 15 jours de la prise de fonction, avec l''ensemble de l''équipe éducative, un 
dispositif d''accueil des nouveaux enseignants. 
 
Ce dispositif d''accueil comprend au minimum: 
1° un entretien avec le chef d''établissement ; 
2° une visite des locaux ; 
3° la communication des horaires de travail ; 
4°  la  mise  à  disposition  et  l''explication  du  projet  d''établissement,  du  
projet pédagogique et éducatif, du règlement de travail, des référentiels et 
programmes de cours en vigueur, pour lesquels le membre du personnel est désigné ; 
5° une présentation à l''équipe éducative ; 
6° pour le membre du personnel désigné ou engagé à titre temporaire pour 
plus d''une semaine pour la première fois dans l''établissement, la désignation par 
le chef d''établissement dans l''enseignement organisé par la Communauté française 
ou par le pouvoir   organisateur   dans   l''enseignement   subventionné   par   la   
Communauté française, parmi les membres du personnel enseignant de 
l''établissement porteurs d''un titre pédagogique et ayant une expérience d''au moins 5 
ans, d''un référent afin de l''assister et le conseiller dans son insertion socio-
professionnelle et l''exercice de ses fonctions. Il n''est pas attribué de périodes 
complémentaires pour les référents. 
 
Remplacé par D. 21-11-2013 
CHAPITRE VIII. – De l’accès aux établissements 
 
