INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 54, 'Article 801. - § 1er. Toutefois, sans préjudice des dispositions de l''article 79,', 'Article 801. - § 1er. Toutefois, sans préjudice des dispositions de l''article 79, 
paragraphes 1er, 2, 4 et 5, et sauf circonstances exceptionnelles reconnues comme 
telles par le Ministre, les établissements de la Communauté française ne sont pas 
tenus d''inscrire, au sein du premier degré comprenant la deuxième année commune, 
un élève issu d''un autre établissement d''enseignement secondaire qui a été orienté 
vers une année supplémentaire.  
 
Secondaire 
 
