INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 55, 'Article 88. – § 1er. Toutefois, sans préjudice des dispositions de l''article 79,', 'Article 88. – § 1er. Toutefois, sans préjudice des dispositions de l''article 79, 
