INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 57, 'Article 95. - Les décisions relatives au passage de classe, de cycle ou de phase et', 'Article 95. - Les décisions relatives au passage de classe, de cycle ou de phase et 
à la délivrance des diplômes, certificats et attestations de réussite au sein d''un 
établissement d''enseignement sont de la compétence du Conseil de classe.  
 
En outre, dans l''enseignement spécialisé, la décision d''inscription dans une forme 
et le passage d''une forme d''enseignement à une autre sont également de la 
compétence du Conseil de classe.  
 
Le Conseil de classe est présidé par le chef d''établissement ou son délégué et 
comprend tous les membres du personnel enseignant en charge de l''élève. Un membre 
du centre psycho-médico-social ainsi que les éducateurs concernés peuvent y assister 
avec voix consultative.  
 
Dans l''enseignement spécialisé, le Conseil de classe comprend également 
l''ensemble des membres des personnels auxiliaire d''éducation, paramédical, 
psychologique et social qui ont la charge de l''instruction, de l''éducation et de la 
formation d''un groupe d''élèves et qui en portent la responsabilité, ainsi que des chefs 
d''atelier. Les chefs de travaux d''atelier peuvent participer au Conseil de classe. Les 
membres des personnels auxiliaire d''éducation, paramédical, psychologique et social 
siègent avec voix consultative pour toutes les matières visant à l''évaluation 
certificative.  
 
Tout enseignant non titulaire, ayant fonctionné au moins deux mois de l''année 
scolaire, peut assister, avec voix consultative, au Conseil de classe 
 
Modifié par D. 03-03-2004 ; complété par D. 05-02-2009 ; modifié par  D. 12-07-
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
2012(1) ; D. 14-06-2018 ; D. 25-04-2019 ; 24-02-2022 ; D. 31-03-2022 ; D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 58, 'Article 96. - Le Ministre, pour l''enseignement de la Communauté française, le (partie 1)', 'Article 96. - Le Ministre, pour l''enseignement de la Communauté française, le pouvoir organisateur, pour l''enseignement subventionné arrête, dans son règlement des études, les modalités essentielles : 1° d''organisation des différentes épreuves à caractère sommatif; 2° du déroulement des délibérations; 3° de la communication des décisions des conseils de classe aux élèves et à leurs parents ou à la personne investie de l''autorité parentale. Nonobstant le huis clos et le secret des délibérations, le chef d''établissement ou son délégué fournit, le cas échéant, par écrit si la demande expresse lui est formulée par l''élève majeur ou les parents ou la personne responsable d''un élève mineur, la motivation précise d''une décision d''échec ou de réussite avec restriction prise par le Conseil de classe ou d''un refus d''octroi du certificat de qualification pris par le Jury de qualification. En outre, dans l''enseignement spécialisé, le chef d''établissement fournit la motivation de la décision d''inscription dans une forme et du passage d''une forme d''enseignement à une autre selon les mêmes modalités. L''élève majeur, les parents ou la personne investie de l''autorité parentale de l''élève mineur peuvent consulter, autant que faire se peut en présence du professeur responsable de l''évaluation, toute épreuve constituant le fondement ou une partie du fondement de la décision du Conseil de classe. Les parents peuvent se faire accompagner d''un membre de la famille ou par une personne de leur choix. L''élève majeur, les parents ou la personne investie de l''autorité parentale de l''élève mineur peuvent aussi, sur demande écrite adressée au chef d''établissement, obtenir, à prix coûtant, copie de toute épreuve constituant le fondement ou une partie du fondement de la décision du Conseil de classe, dans le respect des dispositions du décret du 22 décembre 1994 relatif à la publicité de l''administration. [ajouté par D. 12-07- 2012] Ni l''élève majeur, ni les parents ou la personne investie de l''autorité parentale de l''élève mineur ne peuvent consulter les épreuves d''un autre élève ni en obtenir une copie. [Ajouté par D. 12-07-2012] Chaque pouvoir organisateur prévoit une procédure interne destinée à instruire les contestations pouvant survenir à propos des décisions des conseils de classe et des décisions des jurys de qualification et à favoriser la conciliation des points de vue. Le délai minimum d''introduction de la procédure de conciliation interne relative aux décisions du Conseil de classe et aux décisions du Jury de qualification doit être prévu par le pouvoir organisateur mais ne peut être inférieur à deux jours ouvrables après la communication de la décision. [Ajouté par D. 12-07-2012] Remplacé par D. 12-07-2012 ; D. 25-04-2019 ; D. 31-03-2022 La notification des décisions prises suite à ces procédures internes est soit remise en mains propres aux demandeurs contre accusé de réception, soit adressée par envoi recommandé: 1° au plus tard le cinquième jour qui précède le dernier jour de l''année scolaire pour les jurys de qualification de fin d''année scolaire et au plus tard le dernier jour de l''année scolaire pour les conseils de classe de fin d''année scolaire; 2° dans les cinq jours qui suivent la délibération pour les jurys de qualification et pour les conseils de classe de début d''année scolaire suivante; 3° au plus tard le 31 janvier pour la première session, dans les 5 jours qui suivent la délibération pour les conseils de classe des sessions suivantes et au plus tard le dernier jour de l''année scolaire pour les conseils de classe de fin d''année scolaire de la 3e année complémentaire du quatrième degré de l''enseignement professionnel Secondaire IV.A.16 Lois 21557 D. 24-07-1997 secondaire complémentaire, sections soins infirmiers visée à l''article 3, § 2 du décret du 11 mai 2017 relatif au quatrième degré de l''enseignement professionnel secondaire complémentaire, section soins infirmiers ; 4° dans les 5 jours qui suivent la délibération pour les jurys de qualification et pour les conseils de classe du dispositif de fin de parcours complémentaire au troisième degré de qualification. [Inséré par D. 250-07-2022] Dans tous les cas, la procédure de conciliation interne relative à un refus d''octroi du certificat de qualification est clôturée avant que le Conseil de classe se réunisse pour délibérer quant à la réussite de l''année. [Ajouté par D. 12-07-2012] Dans l''enseignement secondaire spécialisé, à l''exception de l''enseignement de forme 4, la procédure interne est clôturée : - Le 10 décembre ou le 10 mai pour les décisions relatives à l''inscription dans une forme et au changement de forme; - Le dernier jour de l''année scolaire pour les décisions relatives à la délivrance des certificats et attestations ainsi qu''à l''inscription dans une forme et au changement de forme. Modifié par D. 11-07-2002 ; D. 03-03-2004 ; D. 08-03-2007 ; complété par D. 05-02- 2009 ; D. 14-06-2018 ; D. 14-03-2019 ; D. 25-04-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 59, 'Article 97. - § 1er. Il est créé, par caractère d''enseignement, un Conseil de', 'Article 97. - § 1er. Il est créé, par caractère d''enseignement, un Conseil de 
recours pour les décisions des Conseils de classe dans l''enseignement secondaire 
ordinaire et un Conseil de recours pour les décisions des Conseils de classe dans 
l''enseignement secondaire spécialisé. 
 
§ 2. Le Conseil de recours de l''enseignement de caractère non confessionnel 
comprend l''Inspecteur général coordonnateur ou son délégué, dix membres effectifs et 
cinq membres suppléants désignés par le Ministre sur proposition du Comité de 
concertation de l''enseignement secondaire de caractère non confessionnel et un 
président.  
 
Le Gouvernement nomme le Président parmi les fonctionnaires généraux et les 
inspecteurs généraux en activité de service ou admis à la retraite au cours des dix 
dernières années. 
 
Le Conseil de recours de l''enseignement spécialisé de caractère non confessionnel 
comprend l''inspecteur général coordonnateur ou son délégué, cinq membres effectifs et 
cinq membres suppléants désignés par le Gouvernement sur proposition du Comité de 
concertation de l''enseignement secondaire de caractère non confessionnel et un 
président.  
 
Le Gouvernement nomme le Président parmi les fonctionnaires de rang 12 au 
moins et les inspecteurs coordonnateurs en activité de service ou admis à la retraite 
au cours des dix dernières années. 
 
 
§ 3. Le Conseil de recours de l''enseignement de caractère confessionnel comprend 
l''Inspecteur général coordonnateur ou son délégué, dix membres effectifs et dix 
membres suppléants désignés par le Ministre sur proposition du Comité de 
concertation de l''enseignement secondaire de caractère confessionnel et un président.  
 
Le Gouvernement nomme le Président parmi les fonctionnaires généraux et les 
inspecteurs généraux en activité de service ou admis à la retraite au cours des dix 
dernières années. 
 
Le Conseil de recours de l''enseignement spécialisé de caractère confessionnel 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
comprend l''inspecteur général coordonnateur ou son délégué, cinq membres effectifs et 
cinq membres suppléants désignés par le Gouvernement sur proposition du Comité de 
concertation de l''enseignement secondaire de caractère confessionnel et un président.  
 
Le Gouvernement nomme le Président parmi les fonctionnaires de rang 12 au 
moins et les inspecteurs coordonnateurs en activité de service ou admis à la retraite 
au cours des dix dernières années. 
 
Remplacé par D. 14-06-2018 
§ 4. Les membres désignés sur proposition de chaque Comité de concertation sont 
obligatoirement des chefs d''établissement, des directeurs adjoints, des chefs d''atelier 
ou des chefs de travaux d''atelier en fonction, en congé, admis à la retraite au cours des 
cinq dernières années ou bénéficiant d''une mise en disponibilité pour convenances 
personnelles précédant celle-ci. Les membres admis à la retraite achèvent le mandat 
pour lequel ils ont été désignés. 
 
§ 5. Les Conseils de recours prennent leurs décisions à la majorité des deux tiers. 
Si cette majorité n''est pas atteinte, le recours est rejeté. 
 
Le Gouvernement arrête les autres modalités de fonctionnement des Conseils de 
recours. 
 
§ 6. Les mandats sont d''une [durée de quatre ans]3. Ils sont renouvelables. Leur 
exercice est gratuit. Les membres ont droit à des frais de déplacement selon les 
modalités applicables aux fonctionnaires de rang 12. 
 
Inséré par D. 14-06-2018 
§ 7. Le Gouvernement arrête les indemnités de vacation pour tous les membres 
des conseils de recours 
 
Modifié par D. 08-02-1999 ; complété par D. 03-03-2004 ; D. 05-02-2009 ; D. 12-07-
2012(1) ; A.Gt 25-10-2017 ; modifié par D. 14-06-2018 ; D. 25-04-2019 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 60, 'Article 98. - § 1er. Dans l''enseignement secondaire ordinaire, l''élève, s''il est', 'Article 98. - § 1er. Dans l''enseignement secondaire ordinaire, l''élève, s''il est 
majeur, ses parents ou la personne investie de l''autorité parentale, s''il est mineur, 
peuvent introduire un recours contre une décision d''échec ou de réussite avec 
restriction, pour autant qu''ils aient épuisé la procédure interne visée à l''article 96, 
alinéa 6,  
- jusqu''au 10e jour ouvrable qui suit le dernier jour de l''année scolaire, pour les 
décisions de première session ; 
- jusqu''au cinquième jour ouvrable scolaire qui suit la notification de la décision 
pour les décisions de seconde session. 
 
Inséré par D. 25-04-2019 
En ce qui concerne les décisions rendues par le Conseil de classe de janvier de la 
3e année complémentaire visée à l''article 3, § 2, du décret du 11 mai 2017 relatif au 
quatrième degré de l''enseignement professionnel secondaire complémentaire, section 
soins infirmiers, l''élève, s''il est majeur, ses parents ou la personne investie de 
l''autorité parentale, s''il est mineur, peuvent introduire un recours contre une décision 
d''échec, pour autant qu''ils aient épuisé la procédure interne visée à l''article 96, alinéa 
6, jusqu''au 10 février, ou jusqu''au 1er jour ouvrable qui le suit, si celui-ci est un 
dimanche. 
 
Inséré par D. 25-04-2019 
En ce qui concerne les décisions rendues par le Conseil de classe de fin d''année 
scolaire de la 3e année complémentaire visée à l''article 3, § 2, du décret du 11 mai 
 
3Remplacé par le D. 16-05-2024 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
2017 relatif au quatrième degré de l''enseignement professionnel secondaire 
complémentaire, section soins infirmiers, l''élève, s''il est majeur, ses parents ou la 
personne investie de l''autorité parentale, s''il est mineur, peuvent introduire un 
recours contre une décision d''échec, pour autant qu''ils aient épuisé la procédure 
interne visée à l''article 96, alinéa 6, jusqu''au 10 juillet, ou jusqu''au 1er jour ouvrable 
qui le suit, si celui-ci est un dimanche. 
 
Le recours comprend une motivation précise. Y est jointe toute pièce que le 
requérant juge de nature à éclairer le Conseil de recours. 
 
Le recours ne peut comprendre des pièces relatives aux décisions du Conseil de 
classe relatives à d''autres élèves. 
 
Les décisions des Jurys de qualification ne sont pas susceptibles de recours 
auprès des Conseils de recours visés à l''article 97. 
 
§ 2. [Le recours est adressé par envoi recommandé ou par voie électronique à 
l''Administration qui le transmet au Président du Conseil de recours. Une copie du 
recours introduit à l''Administration par envoi recommandé est adressée par les 
requérants, le même jour, également par lettre recommandée, au chef d''établissement 
concerné. Celui-ci peut adresser à l''Administration tout document de nature à éclairer 
le Conseil de recours. Il peut aussi transmettre au Conseil de recours un avis motivé 
sur le bien-fondé du recours. L''Administration transmet ce document au Président du 
Conseil de recours. 
 
Le Conseil de recours enjoint l''établissement de produire à son intention tout 
document estimé utile à sa prise de décision. Il peut entendre toute personne qu''il juge 
nécessaire. Il peut se faire assister par des experts qu''il choisit. 
 
A la demande du Conseil de classe, son président est entendu par le Conseil de 
recours]4. 
 
 
§ 3. Le Conseil de recours peut remplacer la décision du conseil de classe par une 
décision de réussite avec ou sans restriction. 
 
Dans l''enseignement secondaire spécialisé de forme 3, le conseil de recours peut 
remplacer la décision du conseil de classe par une décision de réussite ou par une 
nouvelle décision. 
 
§ 4. Le Gouvernement arrête les modalités de fonctionnement du Conseil de 
recours ainsi que la forme des attestations et certificats délivrés en exécution de ces 
décisions. 
 
Inséré par D. 05-02-2009 ; A.Gt 25-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 61, 'Article 98bis. - § 1er. Dans l''enseignement secondaire spécialisé, l''élève, s''il est', 'Article 98bis. - § 1er. Dans l''enseignement secondaire spécialisé, l''élève, s''il est 
majeur, ses parents ou la personne investie de l''autorité parentale, s''il est mineur, 
peuvent introduire, pour autant qu''ils aient épuisé la procédure interne visée à 
l''article 96, alinéa 5, dans les dix jours qui suivent la notification de la décision ou sa 
confirmation :  
- En forme 4, un recours contre une décision d''échec ou de réussite avec 
restriction;  
- En forme 3, un recours contre une décision de refus de délivrance de 
l''attestation de réussite de phase, de refus de délivrance des certificats à l''exclusion du 
certificat de qualification, de refus d''autoriser l''élève qui a suivi deux années scolaires 
 
4 Remplacé par le décret du 20 juillet 2024 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
en 3e phase, à présenter l''épreuve de qualification;  
- En forme 1, 2, 3 et 4, un recours contre une décision d''inscription dans une 
forme d''enseignement ou de passage d''une forme d''enseignement vers une autre.  
 
Le recours comprend une motivation précise. Y est jointe toute pièce que le 
requérant juge de nature à éclairer le Conseil de recours.  
 
Le recours ne peut comprendre des pièces relatives aux décisions du Conseil de 
classe concernant d''autres élèves.  
 
[§ 2. Le recours est adressé par envoi recommandé, ou par voie électronique à 
l’Administration qui le transmet au Président du Conseil de recours. Une copie du 
recours introduit à l’Administration par envoie recommandée est adressée par les 
requérants, le même jour, également par lettre recommandée, au chef d’établissement 
concerné. Celui-ci peut adresser à l’Administration tout document de nature à éclairer 
le Conseil de recours. Il peut aussi transmettre au Conseil de recours un avis motivé 
sur le bien-fondé du recours. L’Administration transmet ce document au Président du 
Conseil de recours.  
 
Le Conseil de recours enjoint l’établissement de produire à son intention tout 
document estimé utile à sa prise de décision. Il peut entendre toute personne qu’il juge 
nécessaire. Il peut se faire assister par des experts qu’il choisit.  
 
A la demande du conseil de classe, son président est entendu par le Conseil de 
recours.]5 
 
§ 3. Dans l''enseignement secondaire spécialisé, le Conseil de recours peut 
remplacer la décision du Conseil de classe :  
 
- En forme 4, par une décision de réussite avec ou sans restriction;  
- En forme 3, par une décision de réussite de phase;  
- En forme 1, 2, 3 et 4, par une nouvelle décision en ce qui concerne l''inscription 
dans une forme d''enseignement ou le passage d''une forme d''enseignement vers une 
autre.  
 
§ 4. Le Gouvernement arrête les modalités de fonctionnement du Conseil de 
recours ainsi que la forme des attestations et certificats délivrés en exécution de ces 
décisions 
 
Complété par D. 05-02-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 62, 'Article 99. - Dans l''enseignement secondaire ordinaire, les décisions du Conseil', 'Article 99. - Dans l''enseignement secondaire ordinaire, les décisions du Conseil 
de recours se fondent sur la correspondance entre les compétences acquises par l''élève 
et les compétences qu''il doit normalement acquérir ainsi que sur l''équivalence du 
niveau des épreuves d''évaluation administrées aux élèves à celui des épreuves 
produites par les différentes Commissions des outils d''évaluation. 
 
Aussi longtemps que les compétences n''ont pas été déterminées ou que les 
épreuves d''évaluation n''ont pas été produites, le Conseil de recours prend ses décisions 
en fonction des programmes d''études. 
 
Dans l''enseignement secondaire spécialisé, les décisions du Conseil de recours se 
fondent sur la correspondance entre les compétences acquises par l''élève et les 
compétences qu''il doit normalement acquérir. 
 
Le Conseil de recours prend ses décisions en fonction des programmes d''études et 
 
5Remplacé par le décret du 18 janvier 2024 
Secondaire 
 
IV.A.16 
Lois 21557 
 
D. 24-07-1997 
du plan individuel d''apprentissage de l''élève. 
  
CHAPITRE XI. - De la gratuité de l''accès à l''enseignement 
 
Modifié par D. 12-07-2001 (2) ; complété par D. 25-04-2008 ; modifié par D. 17-10-
