INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 63, 'Article 103. - A l''article 10, des lois sur la collation des grades académiques le', 'Article 103. - A l''article 10, des lois sur la collation des grades académiques le 
programme des examens universitaires coordonnées le 31 décembre 1949, modifié par 
le décret du 5 septembre 1994, sont apportées les modifications suivantes : 
1° le § 3 est restauré dans la disposition suivante : 
« § 3. Il est délivré un certificat d''enseignement secondaire du deuxième degré à 
l''issue de la quatrième année d''études de l''enseignement secondaire. 
Il est également délivré un certificat d''enseignement secondaire du deuxième 
degré par le jury de la Communauté française. 
Ce certificat ne fait pas l''objet d''une homologation. »  
2° au § 4, 1°, le mot "quatrième" est supprimé. 
 
Section 2. - Modification aux lois coordonnées sur l''enseignement technique 
du 30 avril 1957 
 
Modifié par D. 03-05-2019');
