INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 66, 'Article 107. - Dans l''article 10 des lois sur l''enseignement primaire coordonnées', 'Article 107. - Dans l''article 10 des lois sur l''enseignement primaire coordonnées 
