INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 67, 'Article 108. - L''article 11 de la loi du 29 mai 1959 modifiant certaines', 'Article 108. - L''article 11 de la loi du 29 mai 1959 modifiant certaines 
