INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 69, 'Article 110. - L''article 2, § 2, de la loi du 19 juillet 1971 relative à la structure', 'Article 110. - L''article 2, § 2, de la loi du 19 juillet 1971 relative à la structure 
générale de l''enseignement secondaire, est remplacé par la disposition suivante :  
« § 2. L''enseignement secondaire est commun à tous les élèves pour les deux 
premières années.  
 
Ces deux premières années peuvent également être organisées sous la forme d''un 
premier degré différencié. Les modalités de passage de ce premier degré différencié 
vers le premier degré et le deuxième degré sont déterminées par le Gouvernement. »  
 
