INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 71, 'Article 112. - Dans l''article 11, § 1er du même décret, entre les mots "à', 'Article 112. - Dans l''article 11, § 1er du même décret, entre les mots "à 
