INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 72, 'Article 113. - A l''article 18 du décret du 16 avril 1991 organisant l''Enseignement', 'Article 113. - A l''article 18 du décret du 16 avril 1991 organisant l''Enseignement 
