INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 73, 'Article 114. - L''article 20, alinéa 1er, du même décret est complété par la', 'Article 114. - L''article 20, alinéa 1er, du même décret est complété par la 
