INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 74, 'Article 115. - Dans l''article 30, 1°, du décret du 16 avril 1991 organisant', 'Article 115. - Dans l''article 30, 1°, du décret du 16 avril 1991 organisant 
