INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 76, 'Article 117. - L''article 3 du même décret est complété par la disposition', 'Article 117. - L''article 3 du même décret est complété par la disposition 
