INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 77, 'Article 118. - A l''article 7, § 1er, alinéa 1er, du même décret sont apportées les', 'Article 118. - A l''article 7, § 1er, alinéa 1er, du même décret sont apportées les 
