INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 78, 'Article 119. - L''article 1er, 2°, du décret du 14 mars 1995 relatif à la promotion', 'Article 119. - L''article 1er, 2°, du décret du 14 mars 1995 relatif à la promotion 
