INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 81, 'Article 122. - Dans l''article 22 du même décret est inséré l''alinéa suivant :', 'Article 122. - Dans l''article 22 du même décret est inséré l''alinéa suivant : 
