INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 82, 'Article 123. - Par dérogation à l''article 103, dans l''enseignement de promotion', 'Article 123. - Par dérogation à l''article 103, dans l''enseignement de promotion 
