inférieur au moment où ils terminent avec fruit cette formation.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('21557', 83, 'Article 124. - Les pouvoirs organisateurs qui le souhaitent peuvent bénéficier', 'Article 124. - Les pouvoirs organisateurs qui le souhaitent peuvent bénéficier 
