INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 1, 'Article 1er. - Le présent décret s''applique à l''enseignement maternel spécialisé,', 'Article 1er. - Le présent décret s''applique à l''enseignement maternel spécialisé, 
primaire spécialisé, fondamental spécialisé et secondaire spécialisé organisé, 
