INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 2, 'Article 2. - § 1er. L''enseignement spécialisé est destiné aux enfants et aux', 'Article 2. - § 1er. L''enseignement spécialisé est destiné aux enfants et aux 
adolescents qui, sur la base d''un rapport d’inscription effectué par les institutions 
définies à l''article 12 doivent bénéficier d''un enseignement adapté en raison de leurs 
besoins spécifiques et de leurs possibilités pédagogiques. 
 
Ces enfants et adolescents sont désignés ci-dessous par l''expression "enfants et 
adolescents à besoins spécifiques". 
 
§ 2. Il est organisé sur la base de la nature et de l''importance des besoins 
éducatifs et des possibilités psychopédagogiques des élèves et assure le développement 
de leurs aptitudes intellectuelles, psychomotrices, affectives et sociales tout en les 
préparant, selon les cas : 
1. à l''intégration dans un milieu de vie ou de travail adapté; 
2. à l''exercice de métiers ou de professions compatibles avec leur handicap qui 
rende possible leur intégration dans un milieu de vie et de travail ordinaire; 
3. à la poursuite des études jusqu''au terme de l''enseignement secondaire 
supérieur tout en offrant des possibilités de vie active. 
 
§ 3. Il comprend les divers types d''enseignement définis au chapitre II du présent 
décret. 
 
§ 4. Il se caractérise par une coordination entre l''enseignement et les 
interventions orthopédagogiques, médicales, paramédicales, psychologiques et sociales 
d''une part et d''autre part par la collaboration permanente avec l''organisme chargé de 
la guidance des élèves telle que définie à l''article 3 de l''arrêté royal du 27 juillet 1971 
fixant les modalités d''organisation, de la guidance des élèves fréquentant les 
établissements spécialisés. 
 
Complété par D. 26-03-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 3, 'Article 3. - § 1er. L''enseignement spécialisé peut être organisé en écoles', 'Article 3. - § 1er. L''enseignement spécialisé peut être organisé en écoles 
d''enseignement de plein exercice, en enseignement secondaire en alternance et en 
enseignement de promotion sociale. 
 
L''enseignement spécialisé de plein exercice est organisé selon les modalités 
définies dans le présent décret. En outre, il peut être organisé selon les particularités 
de l''enseignement à distance, selon les particularités de l''enseignement à domicile 
définies au chapitre XI du présent décret ou selon les particularités de l''enseignement 
en immersion tel que défini à la Section 4 du chapitre IV et la Section 8 du chapitre V. 
 
L''enseignement secondaire spécialisé en alternance est organisé selon les 
modalités définies dans le décret du 3 juillet 1991 organisant l''enseignement 
secondaire en alternance tel que modifié. 
 
§ 2. Le Gouvernement détermine les titres requis des membres du personnel de 
l''enseignement spécialisé organisé ou subventionné par la Communauté française et 
les échelles de traitement de ce personnel. 
 
§ 3. Le Gouvernement organise l''inspection éducative des instituts, des 
établissements d''enseignement spécialisé, des homes et des familles d''accueil. 
 
Modifié par D. 13-01-2011 ; D. 11-02-2011 ; D. 12-07-2012 (1) ;  complété par D. 17-
10-2013 ; modifié par D. 14-06-2018 ; D. 25-04-2019 ; D. 03-05-2019 ; D. 03-05-2019(code) ; 
D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 4, 'Article 4. - § 1er. Pour l''application du présent décret, on entend par : (partie 1)', 'Article 4. - § 1er. Pour l''application du présent décret, on entend par : 1° établissement ou école : ensemble pédagogique d''enseignement spécialisé de niveau maternel, primaire et ou secondaire organisé ou subventionné par la Spécial VI.A.07 Lois 28737 D. 03-03-2004 Communauté française, situé en un ou plusieurs lieux d''implantation placés sous la direction d''un même directeur. 2° bâtiment principal de l''école : le lieu d''implantation choisi par le pouvoir organisateur comme siège administratif de toute l''école; 3° implantation : bâtiment ou ensemble de bâtiments, situé(s) à une seule adresse où l''on dispense de l''enseignement maternel spécialisé et/ou primaire spécialisé et/ou de l''enseignement secondaire spécialisé; 4° centre d''observation : tout établissement d''enseignement spécialisé où, dans des cas exceptionnels, des enfants et/ou des adolescents à besoins spécifiques sont inscrits temporairement, dans le but de déterminer le type d''enseignement spécialisé qui leur convient; 5° niveau : structure de l''organisation de l''enseignement spécialisé, c''est-à-dire maternel, primaire et secondaire; 6° classe : ensemble d''élèves de l''enseignement maternel spécialisé, primaire spécialisé ou secondaire spécialisé placés sous la direction d''un titulaire de classe; 7° unité pédagogique : ensemble d''élèves relevant d''un même type ou de types d''enseignement spécialisé différents, regroupés de manière temporaire ou permanente, afin de recevoir, au sein d''une même école, une formation adaptée à leurs besoins éducatifs; 8° élève régulier : tout élève qui répond aux conditions d''admission et, s''il échet, de passage et qui suit les activités déterminées en fonction de ses besoins; 9° directeur : responsable d''une école maternelle, primaire, fondamentale ou secondaire d''enseignement spécialisé, 10° conseil de classe : ensemble des membres du personnel directeur et enseignant, du personnel paramédical, psychologique et social et du personnel auxiliaire d''éducation qui a la charge de l''instruction et de l''éducation des élèves d''une classe déterminée et qui en porte la responsabilité. En réunion, il est présidé par le directeur ou par son délégué; 11° horaire hebdomadaire de l''élève : emploi du temps de l''élève précisant la nature des cours et/ou activités éducatives suivis ainsi que les lieux dans lesquels ils sont organisés; 12° horaire hebdomadaire de l''enseignant : emploi du temps de l''enseignant indiquant la nature et les lieux de ses prestations; 13° horaire hebdomadaire du membre du personnel non chargé de cours : emploi du temps du membre du personnel non chargé de cours indiquant les lieux de ses prestations; 14° nombre guide : nombre attribué par : a) type, forme, niveau d''enseignement ou nombre d''élèves b) catégorie de personnel permettant le calcul du capital-périodes d''un établissement d''enseignement spécialisé; 15° immersion dans l''apprentissage d''une langue : procédure visant à favoriser l''apprentissage d''une langue moderne en assurant une partie des cours de la grille horaire dans cette langue; 16° apprentissage par immersion en langue des signes : procédure visant à favoriser chez les enfants malentendants l''acquisition des compétences, notamment l''apprentissage de la lecture centrée sur la maîtrise du sens, en assurant une partie des cours de la grille horaire en langue des signes; 17° cours de langue et de culture d''origine, cours de sensibilisation à la langue et à la culture de pays ou de groupes, de pays ayant été à l''origine d''une importante émigration vers notre communauté, assuré dans la perspective d''une intégration en son sein; 18° moyens et techniques de communication : apprentissage de méthodes et de techniques contribuant à tisser le lien social entre les élèves de l''enseignement spécialisé et les personnes de leur environnement; 19° plan individuel d''apprentissage (P.I.A.) : Outil méthodologique élaboré pour chaque élève et ajusté durant toute sa scolarité par le Conseil de classe, sur la base Spécial VI.A.07 Lois 28737 D. 03-03-2004 des observations fournies par ses différents membres et des données communiquées par l''organisme de guidance des élèves. Il énumère des objectifs particuliers à atteindre durant une période déterminée. C''est à partir des données du P.I.A. que chaque membre de l''équipe pluridisciplinaire met en oeuvre le travail d''éducation, de rééducation et de formation; 20° intervention orthopédagogique : intervention préventive ou curative dans des situations d''apprentissage problématique et de souffrance psychique d''enfants et/ou d''adolescents en difficulté; [21° cours philosophiques : enseignement d''une des religions reconnues, de la morale non confessionnelle et de la philosophie et citoyenneté.]1 [22° conseil de participation : conseil créé par l''article 1.5.3-1 du Code de l''enseignement fondamental et de l''enseignement secondaire.]2 23° chef de famille : les père, mère, le tuteur ou la personne à qui est confiée en droit ou en fait la garde d''un enfant ou d''un adolescent à');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 5, 'Article 4. - § 1er. Pour l''application du présent décret, on entend par : (partie 2)', 'besoins spécifiques. 24° institut d''enseignement spécialisé : tout établissement d''enseignement spécialisé organisé par la Communauté française auquel est annexé un internat. 25° home d''accueil : tout internat où des enfants et/ou des adolescents à besoins spécifiques sont hébergés en vue de leur permettre de fréquenter comme externes un établissement d''enseignement spécialisé. 26° famille d''accueil : toute famille qui accueille des enfants et/ou adolescents à besoins spécifiques en vue de leur permettre de fréquenter comme externes un établissement d''enseignement spécialisé ; 27° classe SSAS : Structure Scolaire d''Aide à la Socialisation ou à la resocialisation, mise en place au sein de l''enseignement primaire spécialisé et dans l''enseignement secondaire spécialisé de forme 2, de forme 3 et de forme 4, proposant à des jeunes présentant des troubles structurels du comportement et/ou de la personnalité, quel que soit le type d''enseignement spécialisé dont ils relèvent, une structure resocialisante et restructurante leur permettant une réintégration dans une structure d''apprentissage. [Inséré par D. 17-10-2013] 28° élèves fréquentant une classe SSAS : élèves présentant des troubles structurels du comportement et/ou de la personnalité pour lesquels tous les moyens orthopédagogiques, sociaux et/ou paramédicaux, propres à chaque type d''enseignement, ont été mis en oeuvre par l''équipe éducative et se sont avérés insuffisants. Ces élèves sont pris en charge de manière momentanée pour qu''ils puissent retrouver l''équilibre nécessaire afin de définir un projet personnel et de leur permettre une réintégration dans une structure d''apprentissage. [Inséré par D. 17-10- 2013] 29° zone : Le Gouvernement détermine les zones organisées au niveau de la gestion de l''enseignement spécialisé et de ses personnels ainsi que les entités géographiques qui les composent. [Inséré par D. 17-10-2013] 29°/1. Conseil général : pour l''enseignement fondamental : le Conseil général de l''enseignement fondamental visé à l''article 21 du décret du 14 mars 1995 relatif à la promotion d''une école de la réussite dans l''enseignement fondamental ; pour l''enseignement secondaire : le conseil général de l''enseignement secondaire visé à l''article 1er du décret du 27 octobre 1994 organisant la concertation pour l''enseignement secondaire ; [Inséré par D. 25-04-2019] 30° plan individuel de transition (P.I.T.) : le plan individuel de transition, intégré dans le plan individuel d''apprentissage (P.I.A.) est une démarche réflexive qui tend à établir, dès l''inscription en enseignement secondaire spécialisé, les liens nécessaires entre les différents partenaires en vue d''élaborer et de favoriser le continuum école-vie adulte. [Inséré par D. 17-10-2013] 31° organisme chargé de la guidance : centre psycho-médico-social desservant un établissement d''enseignement spécialisé ou dans les situations d''intégration, centre 1Remplacé par le D. 16-05-2024 2Remplacé par le D. 16-05-2024 Spécial VI.A.07 Lois 28737 D. 03-03-2004 psycho-médico-social desservant un établissement d''enseignement ordinaire et centre psycho-médico-social desservant un établissement d''enseignement spécialisé. [Inséré par D. 17-10-2013] [32° pôle territorial : le pôle territorial chargé de soutenir les écoles de l''enseignement ordinaire dans la mise en œuvre des aménagements raisonnables et de l''intégration permanente totale visé à l''article 6.2.2-1 du Code de l''enseignement fondamental et de l''enseignement secondaire.]3 § 2. Dans l''enseignement maternel et primaire spécialisé, on entend par : 1° enseignement maternel : enseignement dispensé aux élèves définis à l''article 13 et qui les prépare à l''enseignement primaire; 2° […] Supprimé par D. 03-05-2019 (code); 3° enseignement fondamental : enseignement dispensé aux élèves définis aux articles 13 et 14, 4° école maternelle : école de niveau maternel uniquement; 5° école primaire : école de niveau primaire uniquement; 6° école fondamentale : école de niveau maternel et de niveau primaire; 7° titulaire : instituteur qui assure les cours et les activités pédagogiques prévues à l''horaire des élèves à l''exclusion des cours spéciaux et des cours philosophiques et sans préjudice de l''article 22; 8° maître d''enseignement individualisé : instituteur primaire ou maternel qui assure les activités d''enseignement individualisé; 9° maître d''activités éducatives : instituteur primaire ou maternel, maître d''éducation physique ou maître de travaux manuels qui assure les activités éducatives; [modifié par D. 03-05-2019] 10° maître de morale non confessionnelle : membre du personnel qui assure le cours de morale non confessionnelle; 11° membre du personnel chargé exclusivement du cours de la religion correspondante; [remplacé par D. 03-05-2019] 12° maître d''éducation physique : membre du personnel qui assure les cours d''éducation physique et/ou de psychomotricité; 13° maître de travaux manuels : membre du personnel qui assure les cours de travaux manuels; 14° maître de');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 6, 'Article 4. - § 1er. Pour l''application du présent décret, on entend par : (partie 3)', 'seconde langue : membre du personnel qui assure les cours de langue moderne; 15° grille horaire de la classe : liste des différents cours assurés hebdomadairement avec mention du nombre de périodes affectées à chacun; 16° degré de maturité : L''un des quatre degrés correspondant aux stades d''évolution de l''élève dans l''enseignement primaire : a) pour les élèves atteints de retard mental léger, de troubles instrumentaux, comportementaux, sensoriels et de handicaps physiques, ils sont définis comme suit : - maturité I : niveaux d''apprentissages préscolaires; - maturité Il : éveil des apprentissages scolaires; - maturité Ill : maîtrise et développement des acquis; - maturité IV : utilisation fonctionnelle des acquis selon les orientations envisagées. b) pour les élèves atteints de retard mental modéré ou sévère, ils sont définis comme suit : - maturité I : niveaux d''acquisition de l''autonomie et de la socialisation; - maturité Il : niveaux d''apprentissages préscolaires; - maturité III : éveil des premiers apprentissages scolaires (initiation), - maturité IV : approfondissements; 17° capital-périodes : nombre de périodes permettant d''organiser les activités pédagogiques, paramédicales, sociales, psychologiques permettant de répondre aux 3Inséré par le D. 16-05-2024 Spécial VI.A.07 Lois 28737 D. 03-03-2004 besoins spécifiques des élèves inscrits dans un établissement d''enseignement maternel, primaire ou fondamental spécialisé ; 18° maître de psychomotricité : membre du personnel qui assure les cours de psychomotricité. [Inséré par D. 03-05-2019] Modifié par D. 20-07-2022 § 3. Dans l''enseignement secondaire spécialisé, on entend par : 1° enseignement secondaire : enseignement dispensé aux élèves définis à l''article 15; 2° école secondaire : école de niveau secondaire uniquement; 3° directeur de classe : membre du personnel enseignant à qui est confié une mission d''écoute et de suivi d''une classe ou d''un groupe d''élèves. Il est une personne de référence pour l''élève, dans les démarches que ce dernier aurait à entreprendre, lorsqu''il est confronté à une difficulté liée à sa vie au sein de l''établissement; 4° forme d''enseignement : caractère général et objectifs de l''enseignement dispensé; 5° phase : durée requise pour que l''élève maîtrise les objectifs ou les référentiels des compétences fixés; 6° compétences-seuils : référentiel présentant de manière structurée les compétences dont la maîtrise à un niveau déterminé est attendue à la fin de chaque phase de l''enseignement spécialisé de forme 3, 7° compétence : aptitude à mettre en oeuvre un ensemble organisé de savoirs, de savoir-faire et d''attitudes permettant d''accomplir un certain nombre de tâches; 8° secteur professionnel : ensemble d''éléments socioprofessionnels dans lequel se développent des activités éducatives et des apprentissages visant plus particulièrement la préparation à la vie professionnelle; 9° groupe professionnel : sous-ensemble d''un secteur professionnel. Le groupe professionnel développe une formation polyvalente; 10° métier : ensemble cohérent d''activités professionnelles réalisées par une personne dans le cadre d''un processus productif; [remplacé par D. 12-07-2012] 11° profil de certification : le document de référence visé à l''article 39 ou 47, § 1er, du décret du 24 juillet 1997 définissant les missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire et organisant les structures propres à les atteindre, applicable soit à l''enseignement spécialisé de forme 4, soit à l''enseignement spécialisé de forme 3, défini conformément à l''article 169, alinéa 1er, 4°, du présent décret, et qui : a) spécifie l''intitulé de l''option de base groupée organisée en forme 4 ou de la formation organisée en troisième phase en forme 3 ; b) précise la durée en années scolaires sur laquelle est organisée l''option de base groupée organisée en forme 4 visée en a) et, de manière indicative, la durée en année(s) scolaire(s) sur laquelle est organisée la formation organisée en troisième phase en forme 3 ; c) identifie le ou les profils de formation au(x)quel(s) se réfère l''option de base groupée ou la formation concernée ; d) détermine le nombre minimum et le nombre maximum de semaines de stage que doivent accomplir les élèves de l''option de base groupée ou de la formation concernée, dans le respect, pour les options groupées de la forme 4, des dispositions prises en application de l''article 7bis, § 13, de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire, et pour les formations de la forme 3, des dispositions de l''article 55bis du décret du 3 mars 2004 organisant l''enseignement spécialisé ; e) détermine le ou les certificat(s) de qualification délivré(s) aux élèves qui maîtrisent les acquis d''apprentissage fixés par le ou les profil(s) de formation concerné(s); f) reprend le positionnement de la certification dans le Cadre francophone de certification, tel qu''arrêté par l''Instance de Pilot');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 7, 'Article 4. - § 1er. Pour l''application du présent décret, on entend par : (partie 4)', 'et de Positionnement «C.F.C.» Spécial VI.A.07 Lois 28737 D. 03-03-2004 visée à l''article 4 de l''accord de coopération du 26 février 2015 entre la Communauté française, la Région wallonne et la Commission communautaire française concernant la création et la gestion d''un Cadre francophone des certifications, en abrégé «C.F.C.», ou à défaut un positionnement provisoire ; g) reprend : - le parcours d''apprentissage décliné en unités reprenant ou regroupant explicitement les unités d''acquis d''apprentissage (UAA) du ou des profil(s) de formation; ce sont les unités d''acquis d''apprentissage du profil de formation qui font l''objet de la validation ; - les activités-clés du métier auxquelles les unités se réfèrent ; - les recommandations pour l''ordre dans lequel les unités doivent être enseignées; les profils de certification peuvent imposer un ordre dans le parcours d''apprentissage, si nécessaire, pour tout ou partie des UAA ; - les indications temporelles suggérées pour chaque unité ; - les points ECVET alloués, d''une part, à l''ensemble de l''option de base groupée ou de la formation considérée et, d''autre part, à chacune des unités d''acquis d''apprentissage ; - les savoirs, aptitudes et compétences liés aux disciplines de la formation générale qui sont nécessaires à l''exercice des compétences professionnelles ; - le ou les profil(s) d''évaluation ; - le ou les profil(s) d''équipement ; - le(s) modèle(s) de Supplément au certificat Europass que les établissements scolaires doivent délivrer aux élèves titulaires de la certification concernée. [11° remplacé par D. 14-06-2018] ATTENTION : Ce point 12 a fait l’objet d’une modification dans le Décret du 20 juillet 2022 (Docu n° 50485). Néanmoins un problème de coordination ayant été détecté, la modification corrigée sera apportée par un décret encore à prendre 12° profil de certification spécifique : le document de référence visé à l''article 47, § 2, du décret du 24 juillet 1997 précité, applicable à l''enseignement spécialisé de forme 4, et qui reprend les mêmes spécifications que le profil de certification visé au 11° [12° remplacé par D. 14-06-2018] 13° acquis d''apprentissage : désigne ce qu''un élève sait, comprend, est capable de réaliser au terme d''un processus d''apprentissage; les acquis d''apprentissage sont définis en termes de savoirs, d''aptitudes et de compétences, au sens de la Recommandation du Parlement européen et du Conseil du 23 avril 2008 établissant le cadre européen des certifications pour l''éducation et la formation tout au long de la vie. 14° unités d''acquis d''apprentissage : ensemble cohérent d''acquis d''apprentissage susceptible d''être évalué et d''être validé. Ce 15° sera abrogé au 25 août 2025 (D. 20-07-2022 – art. 13. N° 50485) 15° certification par unités d''acquis d''apprentissage (en abrégé, CPU) : dispositif organisant la certification des savoirs, aptitudes et compétences professionnels en unités d''acquis d''apprentissage. La CPU est organisée dans la section de qualification de l''enseignement secondaire ordinaire ou spécialisé de forme 4 et dans les formations à un métier de la troisième phase de l''enseignement spécialisé de forme 3 conformément au décret du 12 juillet 2012 organisant la certification par unités d''acquis d''apprentissage (CPU) dans l''enseignement secondaire qualifiant et modifiant diverses dispositions relatives à l''enseignement secondaire. [Inséré par D. 12-07-2012] 15° bis « Parcours d''enseignement qualifiant » (en abrégé, PEQ) : défini à l''article 2, 5° du décret 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ) ; [inséré par D 20-07-2022] 16° profil de formation : référentiel présentant de manière structurée les compétences à acquérir en vue de l''obtention d''un certificat de qualification ou d''une attestation de compétences. [Complété par D. 12-07-2012 ; remplacé par D. 14-06-2018]] Spécial VI.A.07 Lois 28737 D. 03-03-2004 17° capital-périodes : nombre de périodes permettant d''organiser les activités pédagogiques, paramédicales, sociales, psychologiques, administratives et auxiliaires d''éducation permettant de répondre aux besoins spécifiques des élèves inscrits dans un établissement d''enseignement secondaire spécialisé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 8, 'Article 5. - L''emploi dans le présent décret des noms masculins pour les', 'Article 5. - L''emploi dans le présent décret des noms masculins pour les 
différents membres des personnels est épicène, en vue d''assurer la lisibilité du texte 
nonobstant les dispositions du décret du 21 juin 1993 relatif à la féminisation des 
noms de métier. 
 
CHAPITRE II. - Des types d''enseignement spécialisé 
 
Modifié par D. 20-07-2006 
Articles 6 et 7. - […] Abrogés par D. 03-05-2019 (code);  
 
Remplacé par D. 05-02-2009 ; modifié par D. 01-02-2012');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 9, 'Article 8. - § 1er. Le type 1 est destiné aux élèves qui ne peuvent être compris', 'Article 8. - § 1er. Le type 1 est destiné aux élèves qui ne peuvent être compris 
parmi ceux qui présentent un retard pédagogique et pour lesquels l''examen 
pluridisciplinaire, visé à l''article 12, § 1er, 1°, conclut à un retard et/ou à un (des) 
trouble(s) léger(s) du développement intellectuel. Leurs possibilités sont telles qu''ils 
peuvent acquérir des connaissances scolaires élémentaires, une habileté et une 
formation professionnelle qui permet de prévoir leur intégration dans un milieu 
socioprofessionnel ordinaire.  
 
§ 2. Le type 2 est destiné aux élèves qui ne peuvent être compris parmi les élèves 
visés à l''article 7, 1°, et pour lesquels l''examen pluridisciplinaire, visé à l''article 
12, § 1er, 1°, conclut à un retard modéré ou sévère du développement intellectuel.  
 
Les possibilités constatées chez les élèves dont le handicap a pour origine le 
retard mental modéré sont telles que, par une éducation sociale et professionnelle 
adaptée, on peut prévoir leur intégration dans un milieu socioprofessionnel adapté.  
 
Les possibilités constatées chez les élèves dont le handicap a pour origine le 
retard mental sévère sont telles que ceux-ci sont susceptibles d''être socialisés par des 
activités éducatives adaptées.  
 
§ 3. Le type 3 est destiné aux élèves pour lesquels l''examen pluridisciplinaire, 
visé à l''article 12, § 1er, 1°, conclut à la présence de troubles structurels et/ou 
fonctionnels de l''aspect relationnel et affectivo-dynamique de la personnalité, d''une 
gravité telle qu''ils exigent le recours à des méthodes éducatives, rééducatives et 
psychothérapeutiques spécifiques.  
 
§ 4. Le type 4 est destiné aux élèves présentant un handicap physique autres que 
ceux visés aux §§ 5, 6 et 7 du présent article et pour lesquels l''examen 
pluridisciplinaire visé à l''article 12, § 1er, 1°, conclut à leur inaptitude à fréquenter 
l''enseignement ordinaire et dont l''état nécessite le recours à des soins médicaux et 
paramédicaux réguliers et à l''emploi de méthodes orthopédagogiques.  
 
§ 5. Le type 5 est destiné aux élèves qui, atteints d''une affection corporelle et/ou 
souffrant d''un trouble psychique ou psychiatrique, sont pris en charge sur le plan de 
leur santé par une clinique, un hôpital ou par une institution médico-sociale reconnue 
par les Pouvoirs publics.  
 
Ce type d''enseignement peut être dispensé quel que soit le lieu où séjourne l''élève 
durant sa maladie ou sa convalescence. 
 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
Ce type d''enseignement est organisé en étroite collaboration avec l''école ordinaire 
ou spécialisée dans laquelle l''élève est inscrit.  
 
Seule l''école d''origine est habilitée à délivrer les certificats, diplômes ou 
attestations concernant ces élèves.  
 
§ 6. Le type 6 est destiné aux élèves pour lesquels l''examen pluridisciplinaire visé 
à l''article 12, § 1er, 3°, a conclu à une déficience visuelle et/ou un définit fonctionnel de 
la vision. Il s''adresse aux élèves qui, pour cause de cécité ou de basse vision 
congénitale ou acquise nécessitent régulièrement des soins médicaux, paramédicaux et 
un accompagnement psychosocial internes ou externes.  
 
§ 7. Le type 7 est destiné aux élèves pour lesquels l''examen pluridisciplinaire visé 
à l''article 12, § 1er, 3°, a conclu à une déficience auditive et/ou une carence importante 
de la communication.  
 
Il s''adresse aux élèves qui, pour cause de surdité et/ou troubles congénitaux ou 
acquis nécessitent régulièrement des soins médicaux, paramédicaux et un 
accompagnement psychosocial internes ou externes.  
 
§ 8. Le type 8 est destiné aux élèves pour lesquels l''examen pluridisciplinaire visé 
à l''article 12, § 1er, 3°, a conclu à des troubles des apprentissages. Ceux-ci peuvent se 
traduire par des difficultés dans le développement du langage ou de la parole et/ou 
dans l''apprentissage de la lecture, de l''écriture ou du calcul, sans qu''il y ait retard 
mental ou déficit majeur sur le plan physique, comportemental ou sensoriel. Ils 
doivent être considérés comme des troubles complexes aux origines multifactorielles. 
 
Inséré par D. 05-02-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 10, 'Article 8bis. - Un enseignement spécialisé pour élèves polyhandicapés peut être', 'Article 8bis. - Un enseignement spécialisé pour élèves polyhandicapés peut être 
organisé dans les types 2, 4, 5, 6 ou 7 d''enseignement spécialisé, aux conditions 
suivantes :  
- Outre le rapport mentionné à l''article 12, § 1er, l''orientation de l''élève est 
subordonnée à la production d''un document conforme au modèle fixé par le 
Gouvernement établi par un centre psycho-médico-social, par un office d''orientation 
scolaire et professionnelle ou par tout autre organisme offrant les mêmes garanties en 
matière d''orientation scolaire ou professionnelle, organisés, subventionnés ou 
reconnus par la Communauté française. Une liste de ces organismes est établie 
annuellement par le gouvernement et communiquée aux instituts, établissements et 
écoles d''enseignement spécialisé ainsi qu''aux commissions consultatives de 
l''enseignement spécialisé.  
- Après consultation préalable du comité de concertation de base pour les 
établissements d''enseignement organisés par la Communauté française, de la 
Commission paritaire locale pour les établissements d''enseignement officiel 
subventionné par la Communauté française ou des instances de concertation locale ou 
à défaut des délégations syndicales pour les établissements d''enseignement libre 
subventionné par la Communauté française.  
 
L''enseignement spécialisé adapté aux élèves polyhandicapés est destiné aux 
élèves pour lesquels l''examen pluridisciplinaire visé à l''article 12, § 1er, 1°, se basant 
sur le rapport d''un médecin neurologue ou d''un orthopédiste ou d''un spécialiste en 
réadaptation fonctionnelle, a conclu à un diagnostic de polyhandicap.  
 
Un enseignement spécialisé adapté aux élèves avec autisme peut être organisé 
dans tous les types d''enseignement spécialisé, aux conditions suivantes :  
- L''orientation de l''élève est subordonnée à la production d''un document conforme 
au modèle fixé par le Gouvernement établi par un centre psycho-médico-social, par un 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
office d''orientation scolaire et professionnelle ou par tout autre organisme offrant les 
mêmes garanties en matière d''orientation scolaire ou professionnelle, organisés, 
subventionnés ou reconnus par la Communauté française.  
- Après consultation préalable du comité de concertation de base pour les 
établissements d''enseignement organisés par la Communauté française, de la 
Commission paritaire locale pour les établissements d''enseignement officiel 
subventionné par la Communauté française ou des instances de concertation locale ou 
à défaut des délégations syndicales pour les établissements d''enseignement libre 
subventionné par la Communauté française.  
 
L''enseignement spécialisé pour élèves avec autisme est destiné aux élèves pour 
lesquels l''examen pluridisciplinaire visé à l''article 12, § 1er, 1°, 2° et 3°, se basant sur 
le rapport d''un pédopsychiatre ou d''un centre de référence agréé, a conclu à un 
diagnostic d''autisme.  
 
Un enseignement spécialisé pour élèves aphasiques ou dysphasiques peut être 
organisé dans tous les types d''enseignement spécialisé, sauf dans l''enseignement de 
type 2, aux conditions suivantes :  
- L''orientation de l''élève est subordonnée à la production d''un document conforme 
au modèle fixé par le Gouvernement établi par un centre psycho-médico-social, par un 
office d''orientation scolaire et professionnelle ou par tout autre organisme offrant les 
mêmes garanties en matière d''orientation scolaire ou professionnelle, organisés, 
subventionnés ou reconnus par la Communauté française.  
- Après consultation préalable du comité de concertation de base pour les 
établissements d''enseignement organisés par la Communauté française, de la 
Commission paritaire locale pour les établissements d''enseignement officiel 
subventionné par la Communauté française ou des instances de concertation locale ou 
à défaut des délégations syndicales pour les établissements d''enseignement libre 
subventionné par la Communauté française.  
 
L''enseignement spécialisé pour élèves aphasiques ou dysphasiques est destiné 
aux élèves pour lesquels l''examen pluridisciplinaire visé à l''article 12, § 1er, 1°, se 
basant sur le rapport d''un médecin neuro-pédiatre, a conclu à un diagnostic d''aphasie 
ou de dysphasie. 
 
Inséré par D. 01-02-2012');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 11, 'Article 8ter. - Un enseignement spécialisé pour élèves avec handicaps physiques', 'Article 8ter. - Un enseignement spécialisé pour élèves avec handicaps physiques 
lourds entravant fortement leur autonomie et nécessitant des actes de soins et de 
nursing importants mais disposant de compétences intellectuelles leur permettant 
d''accéder aux apprentissages scolaires grâce à des moyens orthopédagogiques très 
spécifiques peut être organisé dans les types 4, 5, 6 et 7 d''enseignement spécialisé, aux 
conditions suivantes : 
1° Outre le rapport mentionné à l''article 12, § 1er, l''orientation de l''élève est 
subordonnée à la production d''un document conforme au modèle fixé par le 
Gouvernement établi par un centre psycho-médico-social, par un office d''orientation 
scolaire et professionnelle ou par tout autre organisme offrant les mêmes garanties en 
matière d''orientation scolaire ou professionnelle, organisés, subventionnés ou 
reconnus par la Communauté française. Une liste de ces organismes est établie 
annuellement par le Gouvernement et communiquée aux instituts, établissements et 
écoles d''enseignement spécialisé ainsi qu''aux commissions consultatives de 
l''enseignement spécialisé. 
2° Après consultation préalable du comité de concertation de base pour les 
établissements d''enseignement organisés par la Communauté française, de la 
Commission paritaire locale pour les établissements d''enseignement officiel 
subventionné par la Communauté française ou des instances de concertation locale ou 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
à défaut des délégations syndicales pour les établissements d''enseignement libre 
subventionné par la Communauté française. 
3° L''enseignement spécialisé adapté aux élèves avec handicaps physiques lourds 
entravant fortement leur autonomie et nécessitant des actes de soins et de nursing 
importants mais disposant de compétences intellectuelles leur permettant d''accéder 
aux apprentissages scolaires grâce à des moyens orthopédagogiques très spécifiques 
est destiné aux élèves pour lesquels l''examen pluridisciplinaire visé à l''article 12, § 1er, 
1°, se basant sur le rapport d''un médecin neurologue ou d''un orthopédiste ou d''un 
spécialiste en réadaptation fonctionnelle, a conclu à un diagnostic de pathologie lourde 
définie par une affection neurologique centrale avec déficit moteur étendu. 
 
Inséré par D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 12, 'Article 8quater. - L''enseignement spécialisé peut être organisé au niveau', 'Article 8quater. - L''enseignement spécialisé peut être organisé au niveau 
fondamental et secondaire sous la forme d''une classe ou d''une implantation à visée 
inclusive. 
 
[Une classe à visée inclusive est un groupe classe d''élèves à besoins spécifiques 
inscrits dans l''enseignement spécialisé de type 2 porteurs ou non d''autisme ou de type 
3 pour les élèves porteurs d''autisme implantée au sein d''une école de l''enseignement 
ordinaire. Dans ce dernier cas, la production d''une attestation émanant d''un 
organisme spécialisé dans le domaine de l''autisme stipulant que l''élève inscrit dans 
l''enseignement spécialisé de type 3 est porteur d''autisme, est exigée. L''objectif premier 
pour les élèves qui participent à ce type de projet consiste en une inclusion sociale et 
relationnelle en vue d''acquérir divers apprentissages dans un milieu scolaire de vie 
ordinaire]4. 
 
Une implantation à visée inclusive est composée d''une ou de plusieurs classes à 
visée inclusive. 
 
[Article 8quinquies. - L''enseignement spécialisé peut être organisé au niveau 
fondamental et secondaire sous la forme d''une structure scolaire d''aide à la 
socialisation ou à la resocialisation (SSAS)]5. 
 
Modifié par D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 13, 'Article 9. - Les types 1 et 8 d''enseignement spécialisé ne sont pas organisés au / Article 10. - Après avis motivé du [Conseil général]6 visé à l''article 170, le', 'Article 9. - Les types 1 et 8 d''enseignement spécialisé ne sont pas organisés au 
niveau de l''enseignement maternel spécialisé.

Article 10. - Après avis motivé du [Conseil général]6 visé à l''article 170, le 
Gouvernement peut organiser ou subventionner des Centres d''observation. Ceux-ci 
dispensent un enseignement assimilé administrativement au type 3 d''enseignement 
spécialisé. 
 
CHAPITRE III. - Des conditions d''admission et de maintien');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 14, 'Article 11. - 1. Les avantages du présent décret sont réservés aux élèves âgés de', 'Article 11. - 1. Les avantages du présent décret sont réservés aux élèves âgés de 
deux ans et six mois au moins et de vingt et un an au plus, sans préjudice des articles 
13 et 15. 
 
§ 2. Dans l''enseignement secondaire spécialisé de forme 4, en ce qui concerne les 
conditions d''admission, les conditions d''âge sont identiques à celles fixées par l''arrêté 
royal du 29 juin 1984 relatif à l''organisation de l''enseignement secondaire. 
 
 
4 Remplacé par le décret du 20 juillet 2023 
5 Ajouté par le décret du 20 juillet 2023 
6Remplacé par le décret du 18 janvier 2024 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
Modifié par D. 05-02-2009 ; D. 01-02-2012 ; D. 12-07-2012(2) ; D. 17-10-2013 ; D. 14-
07-2015 ; D. 11-07-2018 ; complété par D. 03-05-2019 ; modifié par D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 15, 'Article 12. - § 1er. L''inscription des enfants et des adolescents dans un (partie 1)', 'Article 12. - § 1er. L''inscription des enfants et des adolescents dans un établissement, une école ou un institut d''enseignement spécialisé est subordonnée à la production d''un rapport précisant le type d''enseignement spécialisé qui correspond aux besoins de l''élève et qui est dispensé dans cet établissement, cette école ou cet institut sauf dérogation accordée par le Gouvernement sur proposition du Conseil général pour les dispositions prévues aux articles 133, § 4 et § 5, 147, alinéa 2, et 147bis. Le rapport d''inscription donne lieu à l''établissement d''une attestation et d''un protocole justificatif. Le Gouvernement détermine le modèle relatif à l''attestation et au protocole justificatif ainsi que leurs modalités de communication. Ce rapport est établi : 1° pour les types 1, 2, 3, 4 et 8, sur la base d''un examen pluridisciplinaire effectué par un centre psycho-médico-social desservant un établissement d’enseignement ordinaire ou par tout autre organisme offrant les mêmes garanties en matière d''orientation scolaire ou professionnelle, organisés, subventionnés ou reconnus par la Communauté française. Une liste de ces organismes est établie annuellement par le Gouvernement et communiquée aux instituts, établissements et écoles d''enseignement spécialisé ainsi qu''aux commissions consultatives de l''enseignement spécialisé. Les conclusions des analyses et des examens pluridisciplinaires, consignées dans ce rapport d''inscription, résultent de l''interprétation et de l''articulation dynamique des données médicales, psychologiques, pédagogiques et socio-familiales. [remplacé par D. 12-07-2012] Pour les types 1, 3 et 8, le rapport d''inscription doit notamment décrire, le cas échéant, selon les modalités fixées par le gouvernement, l''accompagnement et les aménagements raisonnables mis en place dans l''enseignement ordinaire et démontrer que ceux-ci se sont révélés insuffisants pour assurer un apprentissage adapté aux besoins spécifiques de l''élève. Un manque de maîtrise de la langue de l''enseignement ou l''appartenance à un milieu social défavorisé ne constitue pas un motif suffisant d''orientation vers l''enseignement spécialisé. [Inséré par D. 14-07-2015] 2° Pour le type 5, sur la base d''un examen médical dont les conclusions sont consignées dans un rapport d''inscription et qui est effectué par un pédiatre ou le médecin référant du service de pédiatrie, de la clinique, de l''hôpital ou de l''institution médico-sociale reconnue par les pouvoirs publics. 3° pour les types 6 et 7 : a) Soit sur la base d''un examen pluridisciplinaire effectué par un centre psycho- médico-social, desservant un établissement d’enseignement ordinaire ou par tout autre organisme offrant les mêmes garanties en matière d''orientation scolaire ou professionnelle, organisés, subventionnés ou reconnus par la Communauté française. Une liste de ces organismes est établie annuellement par le Gouvernement et communiquée aux instituts, établissements et écoles d''enseignement spécialisé ainsi qu''aux commissions consultatives de l''enseignement spécialisé. Les conclusions de cet examen pluridisciplinaire, consignées dans un rapport d''inscription, résultent de l''interprétation et de l''intégration des données fournies par : - L''examen médical; - L''examen psychologique; - L''examen pédagogique; - L''étude sociale. b) Soit sur la base d''un examen médical dont les conclusions sont consignées dans un rapport d''inscription et qui est effectué pour le type 6, par un médecin Spécial VI.A.07 Lois 28737 D. 03-03-2004 spécialiste en ophtalmologie et, pour le type 7, par un médecin spécialiste en oto-rhino- laryngologie. Inséré par D. 03-05-2019 En outre, l''inscription dans l''enseignement secondaire spécialisé de type 8 est autorisée moyennant le respect des conditions suivantes : - soit l''élève fréquente l''enseignement primaire spécialisé de type 8, entre le 15 octobre et le dernier jour de l''année scolaire précédente, et pour autant qu''il n''ait pas obtenu son CEB ; - soit l''élève possède, entre le 15 octobre et le dernier jour de l''année scolaire précédente, une attestation d''orientation vers l''enseignement spécialisé de type 8 et est en intégration permanente totale dans l''enseignement primaire ordinaire, et pour autant qu''il n''ait pas obtenu son CEB. [- soit, entre le 28 août 2023 et le 15 juin 2029, l''élève fréquente l''enseignement secondaire ordinaire et dispose de son CEB et d''une attestation d''orientation vers l''enseignement spécialisé de type 8. Dans ce cas, cette inscription est soumise à : 1° l''avis conjoint du conseil de classe de l''école d''enseignement secondaire ordinaire, du centre PMS compétent de cette école et le cas échéant, du pôle territorial qui précise que l''accompagnement et les aménagements raisonnables mis en place se sont révélés insuffisants pour assurer l''apprentissage adapté aux besoins spécifiques de l''élève et que, l''élève peut être orienté vers l''enseignement secondaire spécialisé ; 2° l''accord des parents ou de la personne investie de l''autorit');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 16, 'Article 12. - § 1er. L''inscription des enfants et des adolescents dans un (partie 2)', 'parentale si l''élève est mineur ou de l''élève s''il est majeur]7. § 2. Le Gouvernement prend toutes les mesures nécessaires en vue de rendre possible la guidance permanente des élèves de l''enseignement spécialisé. Cette mission est confiée aux organismes et personnes visées au présent article. Remplacé par D. 03-05-2019 § 3. Si un élève qui a quitté l''enseignement spécialisé sollicite sa réinscription dans l''enseignement spécialisé dans un délai de moins de deux ans, un nouveau rapport d''inscription ne doit pas être nécessairement établi sauf si l''élève est réorienté dans un type différent de celui figurant sur l''attestation initiale. Si un élève, en possession d''une attestation d''orientation vers l''enseignement spécialisé, mais qui n''a jamais été inscrit dans l''enseignement spécialisé, sollicite son inscription dans cet enseignement dans un délai de moins de deux ans à compter de la date de la signature de cette attestation d''orientation, un nouveau rapport d''inscription ne doit pas être nécessairement établi sauf si l''élève est réorienté dans un type différent de celui figurant sur l''attestation initiale. Néanmoins, à la demande du directeur de l''établissement d''enseignement spécialisé, un rapport succinct sera fourni par le centre psycho-médico-social de la dernière école fréquentée. Modifié par D. 20-07-2006 ; D. 17-10-2013');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 17, 'Article 13. - § 1er. Les enfants peuvent être inscrits comme élèves réguliers dans', 'Article 13. - § 1er. Les enfants peuvent être inscrits comme élèves réguliers dans 
l''enseignement maternel spécialisé sur la base d''un rapport délivré conformément aux 
dispositions de l''article 12 dès qu''ils atteignent l''âge de 2 ans et 6 mois et jusqu''au 
 
7 Ajouté par le décret du 20 juillet 2023 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
moment où ils atteignent, au plus tard le 31 décembre de l''année en cours, l''âge de 6 
ans. 
 
Ils peuvent néanmoins être admis jusqu''au moment où ils atteignent l''âge de 7 
ans au plus tard le 31 décembre de l''année en cours, sur la base d''un avis motivé joint 
au rapport d''inscription. 
 
§ 2. A titre exceptionnel, nonobstant les dispositions prévues à l''article 14 et sur 
la base d''un avis motivé du conseil de classe assisté de l''organisme chargé de la 
guidance, les élèves peuvent être maintenus dans l''enseignement maternel spécialisé 
après les vacances d''été de l''année au cours de laquelle ils atteignent l''âge de six ans. 
Ce maintien ne peut être renouvelé qu''une seule fois. 
 
§ 3. Le Gouvernement peut autoriser l''accès à l''enseignement spécialisé de type 7 
avant deux ans et six mois à un enfant malentendant ou sourd, lorsqu''un rapport 
émanant d''un service d''aide précoce ou d''un centre d''audiophonologie établit l''absolue 
nécessité de la scolarisation. 
 
Modifié par D. 17-10-2013 ; D. 09-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 18, 'Article 14. - § 1er. Les enfants peuvent être inscrits comme élèves réguliers dans', 'Article 14. - § 1er. Les enfants peuvent être inscrits comme élèves réguliers dans 
l''enseignement primaire spécialisé sur la base d''un rapport d''inscription délivré 
conformément aux dispositions de l''article 12 : 
1° après les vacances d''été de l''année au cours de laquelle ils atteignent l''âge de 
six ans; 
2° s''ils atteignent, au plus tard le 31 décembre de l''année en cours, l''âge de treize 
ou quatorze ans, sur la base d''un avis motivé joint au rapport d''inscription. 
 
§ 2. A titre exceptionnel et dans l''intérêt de l''enfant, si les conditions prévues à 
l''article 1.2.1-3, alinéa 2, du Code de l''enseignement fondamental et de l''enseignement 
secondaire sont respectées, le Gouvernement peut autoriser un élève à fréquenter 
l''enseignement primaire spécialisé dès l''âge de 5 ans. 
 
§ 3. A titre exceptionnel, nonobstant les dispositions prévues à l''article 15 et sur 
la hase d''un avis motivé du conseil de classe assisté de l''organisme chargé de la 
guidance, les élèves peuvent être maintenus dans l''enseignement primaire spécialisé 
après les vacances d''été de l''année au cours de laquelle ils atteignent l''âge de treize 
ans. Ce maintien ne peut être renouvelé qu''une seule fois. 
 
Inséré par D. 05-02-2009');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 19, 'Article 14bis. - Dans l''enseignement primaire spécialisé, sont pris en compte,', 'Article 14bis. - Dans l''enseignement primaire spécialisé, sont pris en compte, 
comme s''ils avaient fréquenté régulièrement l''école, les élèves qui se sont absentés de 
manière injustifiée, pour autant que l''obligation visée à l''article 10, alinéa 1er, des lois 
coordonnées du 20 août 1957 sur l''enseignement primaire ait été respectée. 
 
Complété par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 20, 'Article 15. - § 1er. Les enfants et les adolescents peuvent être inscrits comme', 'Article 15. - § 1er. Les enfants et les adolescents peuvent être inscrits comme 
élèves réguliers dans l''enseignement secondaire spécialisé sur la base d''un rapport 
d''inscription délivré conformément aux dispositions de l''article 12 : 
1° après les vacances d''été de l''année au cours de laquelle ils atteignent l''âge de 
treize ans; 
2° sur la base d''un avis motivé du conseil de classe joint au rapport d''inscription 
après les vacances d''été de l''année au cours de laquelle ils atteignent l''âge de douze 
ans; 
 
§ 2. Les élèves âgés de plus de vingt et un ans, dans l''enseignement de forme 3, 
qui commencent la troisième phase pour la première fois peuvent également être 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
inscrits comme élèves réguliers dans l''enseignement secondaire spécialisé [jusqu’au 
terme leur cycle de formation.]8 
 
§ 3. […]9 
 
§ 4. Le Gouvernement peut autoriser le maintien au-delà de 21 ans d''un élève qui 
ne peut être pris en charge par une entreprise de travail adapté ou un centre 
d''hébergement ou un centre de jour, à condition que le coût de l''accueil ne soit pas mis 
à charge du budget de la Communauté française, sans qu''il soit pour autant dérogé à 
l''obligation de gratuité. 
 
§ 5 La limite d''âge de 21 ans ne s''applique pas aux élèves à besoins spécifiques 
inscrits dans un enseignement spécialisé en alternance tel que prévu à l''article 3 du 
présent décret. 
 
Inséré par D. 05-02-2009 ; remplacé par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 21, 'Article 15bis. - Dans l''enseignement secondaire spécialisé, sont pris en compte,', 'Article 15bis. - Dans l''enseignement secondaire spécialisé, sont pris en compte, 
comme s''ils avaient fréquenté régulièrement l''école, les élèves qui se sont absentés de 
manière injustifiée[…]10. 
 
Inséré par D. 17-10-2013 ; modifié par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 22, 'Article 15ter. - Le Gouvernement peut accorder une dérogation […]11 à une', 'Article 15ter. - Le Gouvernement peut accorder une dérogation […]11 à une 
école d''enseignement fondamental ou secondaire spécialisé qui accepte d''inscrire un 
élève relevant d''un autre type d''enseignement spécialisé que celui ou ceux qu''elle 
organise ou d''une autre forme d''enseignement spécialisé que celle(s) qu''elle organise, 
et ce en vertu d''une situation exceptionnelle [notamment]12 motivée par un manque 
d''offre d''enseignement spécialisé empêchant toute possibilité de scolarisation et sur 
avis favorable du [Conseil général]13. 
 
[L''école d''enseignement spécialisé]14 qui accepte d''inscrire cet élève, bénéficie 
pour l''élève concerné, [pour toute la durée de la scolarité de l''élève, sauf en cas de 
changement d''école, ou lors d''un passage de l''enseignement fondamental vers 
l''enseignement secondaire]15, du taux de subvention ou de la dotation et des périodes 
d''accompagnement générées par le nombre guide relatif au type d''enseignement 
mentionné sur l''attestation d''orientation de l''élève concerné. 
 
Durant la période dérogatoire, l''élève est considéré comme régulièrement inscrit. 
 
CHAPITRE IV. - De l''organisation de l''enseignement maternel spécialisé 
et/ou primaire spécialisé 
 
Section 1re. - De l''horaire des élèves dans l''enseignement maternel 
 
Modifié par D. 13-01-2011');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 23, 'Article 16. - L''enseignement maternel spécialisé s''articule autour du projet', 'Article 16. - L''enseignement maternel spécialisé s''articule autour du projet 
d''établissement. Il est dispensé à raison de vingt-huit périodes hebdomadaires de 
 
