INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 169, 'Article 151. - Dès l’acceptation de proposition d’intégration permanente partielle', 'Article 151. - Dès l’acceptation de proposition d’intégration permanente partielle 
ou d’intégration temporaire partielle par les partenaires, la définition d’un projet 
d’intégration est recherchée conjointement par : 
1° le conseil de classe de l''établissement d''enseignement spécialisé, assisté par 
l''organisme qui assure la guidance des élèves de l''établissement spécialisé; 
2° le titulaire de classe ou le conseil de classe de l''établissement d''enseignement 
ordinaire concerné, assisté par le centre psycho-médico-social qui assure la guidance 
des élèves de l''établissement. 
 
Modifié par D. 11-04-2014 ; D. 11-07-2018 ; D. 03-05-2019 ; D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 170, 'Article 152. - A l''issue de la procédure visée aux articles 150 et 151 un protocole', 'Article 152. - A l''issue de la procédure visée aux articles 150 et 151 un protocole 
est établi. Ce protocole contient : 
1° le projet d''intégration comprenant la fiche d’identification et de parcours de 
l’élève, les objectifs visés, l''énumération des équipements spécifiques et le dispositif de 
liaison entre les écoles; 
2° les modalités de concertation entre le(s) membre(s) du personnel de 
l''enseignement spécialisé et le(s) membre(s) du personnel de l''enseignement ordinaire 
en charge de la classe qui accueille l''élève et, le cas échéant, les équipes psycho-
médico-sociales de [l''école d''enseignement spécialisé]45 et de l''école ordinaire, ainsi que 
les modalités d''évaluation interne de l''intégration permanente partielle ou de 
l''intégration temporaire partielle et la constitution de rapports; 
3° l''avis du centre psycho-médico-social qui accompagne l''élève au moment de 
l''introduction de la proposition d''intégration; [remplacé par D. 11-07-2018 ; D. 03-05-2019] 
4° l''accord soit du directeur pour les établissements organisés par la 
Communauté française soit du pouvoir organisateur ou de son délégué pour les 
établissements subventionnés par la Communauté française, 
5° l''accord des parents, de la personne investie de l''autorité parentale ou de 
l''élève lui-même s''il est majeur. 
 
Remplacé par D. 05-02-2009 ; complété par D. 17-06-2021(1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 171, 'Article 153. - Le protocole visé à l''article 152 est conservé dans l''établissement', 'Article 153. - Le protocole visé à l''article 152 est conservé dans l''établissement 
d''enseignement spécialisé et tenu à disposition du Service général de l''Inspection et 
des Services du Gouvernement.  
 
Dans chaque cas et dès que le protocole est complet, l''information concernant les 
coordonnées de l''élève intégré est transmise aux Services du Gouvernement. 
 
Le cas échéant, l''école d''enseignement spécialisé informe le pôle territorial de la 
mise en place d''un protocole pour les élèves concernés par une possible intégration 
permanente totale. 
 
Remplacé par D. 05-02-2009 ; modifié par D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 172, 'Article 154. - Un nouveau protocole d’intégration est établi lors du changement / Article 155. – […] abrogé par D. 05-02-2009', 'Article 154. - Un nouveau protocole d’intégration est établi lors du changement 
