INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 173, 'Article 156. - Au terme de chaque période d''intégration, chacune des parties', 'Article 156. - Au terme de chaque période d''intégration, chacune des parties 
ayant marqué son accord au protocole, à l''exception du centre psycho-médico-social qui 
assurait la guidance de l''élève avant son entrée en intégration pour autant que celui-ci 
n''assure plus la guidance de cet élève, ou le centre psycho-médico-social qui assure la 
 
