INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 222, 'Article 212bis. - Le Gouvernement lance dans le courant du mois de novembre (partie 1)', 'Article 212bis. - Le Gouvernement lance dans le courant du mois de novembre 2022 un appel à projets à l''ensemble des pouvoirs organisateurs pour bénéficier à hauteur de 10 pourcents maximum des moyens prévus, pour les années 2022, 2023 et 2024, à l''article 13bis du décret du 5 février 1990 relatif aux bâtiments scolaires de l''enseignement non universitaire organisé ou subventionné par la Communauté française. Les réponses à l''appel à projets sont remises par les pouvoirs organisateurs pour le 30 avril 2023 au plus tard, et ce via un formulaire type communiqué. Les demandes introduites contiennent, selon les différentes situations, les éléments suivants: 1. un descriptif des travaux d''aménagements, de rénovation ou d''extension de bâtiments et/ou modules préfabriqués, envisagés; 2. descriptif détaillé des locations/achats de bâtiments et/ou modules préfabriqués envisagés; 3. une estimation financière du coût des travaux/locations/achats envisagés ; 4. un relevé de la population scolaire de l''établissement visé sur les 3 dernières années et son évolution projetée suite aux travaux/locations/achats envisagés; 5. un rétroplanning des opérations envisagées sur base du modèle prévu par l''appel à projet et mentionnant la date d''ouverture des nouvelles places. Pour être éligible à l''appel à projets, les pouvoirs organisateurs, doivent répondre aux critères cumulatifs suivants: a. viser une implantation scolaire de l''enseignement obligatoire, organisé ou subventionné par la Communauté française; b. pour les demandes liées à des travaux pérennes sur l''infrastructures, disposer d''un droit réel pour une durée minimale de 30 ans sur le bâtiment visé, au plus tard au moment de l''accord ferme de subvention; c. les places doivent être créées structurellement pour la rentrée scolaire 2025 au plus tard, à l''exception des locations qui peuvent ne pas être structurelles; d. le pouvoir organisateur demandeur doit disposer d''un accès aux dotations/subventions de fonctionnement; e. le demandeur doit respecter la législation sur les marchés publics de travaux, fournitures et services. Dans le cas de retard dans le délai d''ouverture des places, le Gouvernement peut retirer le droit à la subvention octroyée au pouvoir organisateur. Les bénéficiaires de la subvention dont les bâtiments scolaires ont bénéficié d''une subvention en vertu du présent décret et pour lesquels l''affectation scolaire n''est plus rencontrée et/ou cède à titre onéreux les bâtiments remboursent la subvention. Spécial VI.A.07 Lois 28737 D. 03-03-2004 Le montant de la partie de la subvention à rembourser pour les locaux sera établi en fonction du nombre de m2 désaffectés, déduction faite du nombre d''années d''occupation. Chaque année d''occupation interviendra pour une trentième du montant de la subvention. Le montant à rembourser sera fixé par arrêté du Gouvernement de la Communauté française. Le bénéficiaire peut ne pas rembourser la subvention si: - les locaux ont perdu leur destination scolaire suite à des circonstances indépendantes de la volonté du pouvoir organisateur concerné, ou - l''affectation scolaire est maintenue. Le Gouvernement apprécie l''opportunité de procéder au recouvrement de la subvention sur base des éléments présentés par le pouvoir organisateur. Les dépenses éligibles considérées dans le présent mécanisme sont les suivantes et permettant l''augmentation de la capacité d''accueil de l''établissement concerné: a. tous travaux d''aménagement de locaux; b. tous travaux de construction ou rénovation de bâtiment; c. toutes locations de locaux complémentaires ou de modules préfabriqués pour une durée maximale allant jusqu''à la rentrée scolaire 2028; d. tous achats de bâtiments ou modules préfabriqués. Les dépenses éligibles visées ci-dessus le sont dans le respect de l''arrêté du Gouvernement de la Communauté française du 6 février 2014 fixant les règles qui déterminent le besoin en constructions nouvelles ou extensions et les normes physiques et financières pour les bâtiments scolaires, internats et centres psycho- médico-sociaux. Sur base des dossiers introduits, le Gouvernement arrête la liste des dossiers retenus selon les modalités fixées par le présent décret au plus tard le 30 septembre 2023. Préalablement à l''adoption de cette liste, le Gouvernement consulte sur cette liste la Commission inter caractère crée à l''article 11 du décret du 16 novembre 2007 relatif au programme prioritaire de travaux. Cet avis est communiqué au Gouvernement dans un délai de 30 jours à dater de la communication à la Commission inter caractère de la liste des dossiers. Si pour des raisons d''engagement juridique nécessaire sur un achat et/ou en vue d''ouvrir les places visées dès la rentrée scolaire 2023, un pouvoir organisateur ne peut attendre la date du 30 septembre 2023 pour obtenir un accord de financement, ce dernier devra le justifier lors de sa candidature. Par engagement juridique nécessaire sur un achat, il y a lieu d''entendre, la remise d''une offre ferme d''achat');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 223, 'Article 212bis. - Le Gouvernement lance dans le courant du mois de novembre (partie 2)', 'ou la signature d''un acte notarié lié à cet achat. Le Gouvernement peut alors se positionner plus rapidement sur ce dossier et ce afin de permettre au pouvoir organisateur de mener à bien son projet. Si les moyens dévolus ne sont pas suffisants pour couvrir l''ensemble des demandes introduites, les dossiers seront priorisés sur base des critères suivants, et ce dans l''ordre de priorité: - les projets visant des travaux ou aménagement pérenne et structurel; Spécial VI.A.07 Lois 28737 D. 03-03-2004 - le projet vise une école déjà existante; - la date d''ouverture des places structurelles la plus proche; - le coût par place créée le moins onéreux. Ces mêmes critères seront utilisés pour départager les dossiers faisant appel à la dérogation relative au délai de l''appel à projets, dans le cas où ces dossiers seraient à ce point nombreux que les moyens alloués soient insuffisants que pour tous les financer. [CHAPITRE XVter - De l''organisation de repas, sains et durables au sein des cantines scolaires]73 [Article 212ter.]74 - Dans l''enseignement maternel et primaire spécialisé, les Pouvoirs organisateurs peuvent financer l''organisation de repas sains et durables au sein des cantines scolaires. Dans cette hypothèse : a. les moyens doivent être affectés à l''achat de matériel et/ou à la désignation ou à l''engagement de personnel et/ou à un ou plusieurs marchés de services ou de fournitures liés au service des repas sains et durables visés par le présent décret et à la surveillance de ces repas ; b. les repas peuvent être mis à disposition gratuitement ou contre une contribution financière modique sollicitée auprès des parents. En tout état de cause, cette contribution éventuelle ne peut excéder le prix coûtant du repas, tous frais annexes compris dont l''organisation, l''encadrement et le service ; c. en période scolaire, les repas sains doivent être organisés tous les jours scolaires de la semaine. Les repas ne doivent pas être organisés le mercredi si l''établissement scolaire ne les organise pas de manière habituelle. Les écoles ne peuvent réclamer aucun frais connexe supplémentaire lié au repas ; d. en début de chaque année scolaire, les écoles qui organisent des repas sains et durables au sein des cantines scolaires communiquent aux parents une information claire relative à l''inscription dans le projet ainsi que les modalités et les conséquences concrètes pour les élèves ; e. le Pouvoir organisateur, ou l''école le cas échéant, s''assure du respect des normes et principes imposés par l''Agence fédérale pour la sécurité de la chaîne alimentaire (AFSCA) ; f. le Pouvoir organisateur veillera au respect des orientations suivantes dans l''organisation des repas sains et durables : i. promouvoir une alimentation locale, saine et équilibrée en ayant recours à un maximum de produits issus de l''agriculture biologique, limiter et contrôler le junk food dans les collations et inscrire ces principes dans le projet pédagogique de l''école ; ii. proposer au minimum plusieurs alternatives végétariennes par semaine ; iii. encourager le recours à l''eau comme seule boisson ; 73Inséré par le D. 17-12-2025 74Inséré par le D. 17-12-2025 Spécial VI.A.07 Lois 28737 D. 03-03-2004 iv. encourager, aussi régulièrement que possible, la découverte de saveurs variées, la consommation de fruits et légumes frais et de saison ; v. diminuer la quantité de protéines animales en faveur de plus de légumes et de protéines végétales en se référant aux recommandations de l''Office de la Naissance et de l''Enfance ; vi. éviter le gaspillage alimentaire ; vii. réduire la production de déchets ; viii. compléter l''organisation de repas sains et durables par des activités éducatives, durant ou en dehors des repas, à destination des élèves et/ou des parents ; ix. avoir le label Good Food pour les cantines des écoles ou implantations situées en Région de Bruxelles-Capitale ou le label « Green Deal Cantines durables » pour les cantines des écoles ou implantations situées en Région de langue française ou, pour les repas complets, avoir recours au cahier spécial des charges de repas complets, sains et durables pour les « collectivités d''enfants » de la Communauté française. g. les orientations visées au point e) supra sont évaluées tous les 5 ans par le Service des Politiques publiques du Ministère de la Communauté française en collaboration avec les services de l''Office de la Naissance et de l''Enfance. A titre transitoire, la première évaluation a lieu en 2030. Une analyse complémentaire peut être sollicitée auprès de prestataires externes mandatés par le Gouvernement de la Communauté française. CHAPITRE XVI. - De la disposition particulière relative à la détermination du pourcentage du capital-périodes utilisables Complété par D. 05-02-2009 ; D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 224, 'Article 213. - Le Gouvernement détermine annuellement en fonction des', 'Article 213. - Le Gouvernement détermine annuellement en fonction des 
possibilités budgétaires le pourcentage du capital-périodes utilisable pour les 
catégories du personnel directeur et enseignant, du personnel paramédical, social et 
psychologique, du personnel administratif et auxiliaire d''éducation et qui résulte des 
normes mentionnées aux articles 33, 34, 85, 86, 102, 104, 113, 114 et 132 et ce, de 
façon identique pour tous les réseaux d''enseignement. 
 
Ce pourcentage doit être supérieur ou égal à 97 %. 
 
Par dérogation à l''alinéa précédent, ce pourcentage est de 100% en ce qui 
concerne les catégories du personnel directeur et enseignant, du personnel 
paramédical, social et psychologique encadrant les élèves qui relèvent des pédagogies 
adaptées visées aux articles 8bis et 8ter du présent décret. [Inséré par D. 11-07-2018] 
 
Pour l''application de l''alinéa précédent, les pédagogies adaptées définies aux 
articles 8bis et 8ter du présent décret ne peuvent bénéficier du capital-périodes à 
100% que si les établissements concernés respectent un cahier des charges reprenant 
les dispositions nécessaires à l''organisation de ces dites pédagogies. Ce cahier des 
charges est fixé par le Gouvernement, après avis du [Conseil général]75. [Inséré par D. 11-
07-2018] 
 
 
75Remplacé par le décret du 18 janvier 2024 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
