INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 229, 'Article 218. - A l''article 6 du décret du 27 octobre 1994 sont apportées les', 'Article 218. - A l''article 6 du décret du 27 octobre 1994 sont apportées les 
