INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 230, 'Article 219. - A l''article 8, l''alinéa suivant est inséré entre les alinéas 1er et 2 :', 'Article 219. - A l''article 8, l''alinéa suivant est inséré entre les alinéas 1er et 2 : 
