INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 231, 'Article 220. - Dans le texte du décret du 24 juillet 1997 précité, le mot "spécial" / Article 221. - Aux articles 2 et 3, les mots "aux articles le, et 4 de la loi du 6', 'Article 220. - Dans le texte du décret du 24 juillet 1997 précité, le mot "spécial" 
