INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 232, 'Article 222. - A l''article 4 du même décret sont apportées les modifications', 'Article 222. - A l''article 4 du même décret sont apportées les modifications 
