INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 233, 'Article 223. - Il est inséré dans l''article 5 du même décret, un 2°bis rédigé', 'Article 223. - Il est inséré dans l''article 5 du même décret, un 2°bis rédigé 
