INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 234, 'Article 224. - Dans le titre de la Section 1re du chapitre III, les mots "Des cycles" / Article 225. - A l''article 13 du même décret sont apportées les modifications', 'Article 224. - Dans le titre de la Section 1re du chapitre III, les mots "Des cycles" 
