INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 238, 'Article 229. - A l''article 17 du même décret sont apportées les modifications', 'Article 229. - A l''article 17 du même décret sont apportées les modifications 
