INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 239, 'Article 230. - § 1er. A l''article 35, § 1er, du même décret, il est inséré un 4° rédigé', 'Article 230. - § 1er. A l''article 35, § 1er, du même décret, il est inséré un 4° rédigé 
