INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 240, 'Article 231. - A l''article 36 du même décret sont apportées les modifications', 'Article 231. - A l''article 36 du même décret sont apportées les modifications 
suivantes : 
1° dans le § 1er, les mots "degrés et années" sont remplacés par les mots "degrés, 
années et phases d''enseignement"; 
2° un § 2bis est inséré : 
«§ 2bis. Pour l''enseignement spécialisé subventionné, le Gouvernement approuve, 
dans le respect des compétences et savoirs définis à l''article 35, les programmes 
d''études des cours spécifiques à la formation humaniste durant les phases 
d''enseignement visées au présent chapitre, après avoir pris l''avis de la Commission 
des programmes visée au § 3bis". 
3° un § 3bis est inséré : 
«§ 3bis. II est créé une Commission des programmes de l''enseignement 
secondaire spécialisé, selon les modalités que fixe le Gouvernement. La Commission 
des programmes vérifie si les programmes d''études sont de nature à permettre 
l''acquisition des compétences et savoirs visés à l''article 35. 
 
Le contrôle de la commission des programmes ne porte pas sur les méthodes 
pédagogiques.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 241, 'Article 232. - Un article 39bis est ajouté :', 'Article 232. - Un article 39bis est ajouté : 
