INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 242, 'Article 233. - L''article 43 du même décret est complété par l''alinéa suivant :', 'Article 233. - L''article 43 du même décret est complété par l''alinéa suivant : 
