INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 244, 'Article 236. - A l''article 50, les modifications suivantes sont apportées :', 'Article 236. - A l''article 50, les modifications suivantes sont apportées : 
