INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 285, 'Article 282. - Dans l''arrêté royal du 3 décembre 1974 portant exécution de', 'Article 282. - Dans l''arrêté royal du 3 décembre 1974 portant exécution de 
