INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 308, 'Article 305. - Dans l''arrêté du Gouvernement de la Communauté française du', 'Article 305. - Dans l''arrêté du Gouvernement de la Communauté française du 
28 juillet 1998 portant approbation du règlement des études de l''enseignement 
secondaire spécial de la Communauté française, sont apportées les modifications 
suivantes : 
1° dans l''intitulé de l''arrêté, le mot "spécial" est remplacé par le mot "spécialisé"; 
2° dans l''intitulé de l''annexe, le mot "spécial" est remplacé par le mot "spécialisé"; 
3° dans le texte de l''annexe, le mot "spécial" est remplacé par le mot "spécialisé"; 
4° dans la partie du texte de l''annexe traitant de l''enseignement spécial de forme 
1, les mots "milieu de vie protégé" sont remplacés par les mots "milieu de vie adapté"; 
5° dans la partie du texte de l''annexe traitant de l''enseignement spécial de forme 
3, les mots "comporte deux phases" sont remplacés par les mots "comporte trois 
phases"; 
6° dans la partie du texte de l''annexe traitant de l''enseignement spécial de forme 
3, les mots "Une troisième phase, dite de perfectionnement peut être organisée" sont 
supprimés; 
7° dans la partie du texte de l''annexe traitant "De l''évaluation et du conseil de 
classe,", les mots "pendant la première ou la deuxième phase" sont supprimés; 
8° dans la même partie du texte de l''annexe, les mots "une attestation de 
réussite, à l''issue de la première phase" sont remplacés par : 
«- une attestation de réussite dans un secteur professionnel à l''issue de la 
première phase 
- une attestation de réussite dans un groupe professionnel à l''issue de la 
deuxième phase; 
- un certificat d''enseignement secondaire inférieur équivalant au certificat 
d''enseignement secondaire du deuxième degré à l''issue de la 3e phase»; 
9° dans la même partie, les mots "deuxième phase" sont remplacés par les mots 
"troisième phase"; 
10° dans la même partie, les mots "Un certificat de qualification complémentaire 
à l''issue de la troisième phase, dans ce cas, le conseil de classe est élargi à des 
membres étrangers au personnel de l''établissement et devient alors jury de 
qualification" sont supprimés. 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004');
