INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 336, 'Article 337. - Les élèves régulièrement inscrits pendant l''année scolaire 2004-', 'Article 337. - Les élèves régulièrement inscrits pendant l''année scolaire 2004-
2005 dans l''enseignement spécialisé de forme 3, soit en 2e phase, soit en 4e ou 5e 
année, peuvent avoir accès à un examen de qualification à l''issue de la 2e phase ou de 
la 5e année au plus tard à la fin de l''année scolaire 2006-2007 et peuvent avoir accès à 
l''épreuve de qualification à l''issue de la 3e phase ou 6e année au plus tard à la fin de 
l''année scolaire 2006-2007 selon les mêmes conditions que celles énoncées lors de leur 
entrée en 2e phase ou en 4e année. 
 
Les élèves régulièrement inscrits pendant l''année scolaire 2004-2005 dans 
l''enseignement spécialisé de forme 3, soit en 3e phase, soit en 6e année, peuvent avoir 
accès à un examen de qualification à l''issue de la 3e phase ou de la 6e année au plus 
tard à la fin de l''année scolaire 2006-2007, selon les même conditions que celles 
énoncées lors de leur entrée en 3ème phase ou en 6e année.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 337, 'Article 338. - Les écoles qui', 'Article 338. - Les écoles qui 
modifient 
l''organisation 
de 
l''enseignement 
secondaire spécialisé de forme 3 en application du présent décret peuvent organiser les 
secteurs correspondant aux Sections précédemment organisées pendant l''année 
scolaire 2004-2005. 
 
Après la période de transformation, les règles de programmation seront à 
nouveau applicables.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 338, 'Article 339. - Les membres du personnel nommés à titre définitif dans une', 'Article 339. - Les membres du personnel nommés à titre définitif dans une 
fonction de professeur de pratique professionnelle ou de cours techniques ou de cours 
techniques et de pratique professionnelle, dont la charge a compris, pendant l''année 
scolaire 2003-2004 ainsi que pendant celle qui précède la transformation, des cours de 
pratique professionnelle, des cours techniques ou des cours techniques et de pratique 
professionnelle dans une Section qui est transformée en secteur professionnel 
conformément à l''article 55 du présent décret sont réputés avoir acquis l''expérience 
utile pour les cours de la même spécialité organisés dans le seul nouveau secteur 
résultant de la transformation. 
 
Les membres du personnel qui bénéficient des assimilations visées à l''alinéa 
précédent conservent l''échelle barémique qui leur était attribuée avant la 
transformation si elle est plus favorable que celle à laquelle leurs titres leur donnent 
droit.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 339, 'Article 340. - Par dérogation aux articles 26, § 4 et 47, § 3 du présent décret, les', 'Article 340. - Par dérogation aux articles 26, § 4 et 47, § 3 du présent décret, les 
enseignants et instituteurs qui ont assuré le cours de langue des signes pendant 3 
années scolaires au moins au cours des 10 dernières années scolaires restent chargés 
des cours de langue des signes sans détenir le titre de capacité à la fonction 
d''instituteur chargé des cours en immersion.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 340, 'Article 341. - A partir de l''entrée en vigueur du présent décret, les écoles', 'Article 341. - A partir de l''entrée en vigueur du présent décret, les écoles 
organisant l''enseignement spécialisé de type 7 disposent d''un délai de 5 années 
scolaires pour se conformer aux dispositions de l''article 26, § 4 et 47, § 3 du présent 
décret. 
 
Complété par D. 12-07-2012(1) ; modifié par D. 14-06-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 341, 'Article 342. - Jusqu''à ce que, après avoir pris l''avis du [Conseil général]88, le', 'Article 342. - Jusqu''à ce que, après avoir pris l''avis du [Conseil général]88, le 
Gouvernement constate que l''ensemble des besoins de formation est couvert par un 
 
88Remplacé par le décret du 18 janvier 2024 
Spécial 
 
VI.A.07 
Lois 28737 
 
D. 03-03-2004 
nombre suffisant de profils de certification approuvés conformément à l''article 47 du 
décret du 24 juillet 1997 précité ou, à défaut par des profils de formation élaborés par 
la Commission communautaire des professions et des qualifications visée à l''article 7 
du décret du 27 octobre 1994 précité, les formations organisées antérieurement sont 
maintenues. 
 
Le Gouvernement arrête la liste de celles qui font l''objet d''un certificat de 
qualification. Lorsque le profil est approuvé, un certificat de qualification remplace 
l''attestation de compétences acquises visée à l''article 57, 4°. 
 
Inséré par D. 12-07-2012');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 342, 'Article 342', 'Article 342/1. - Les porteurs du Certificat d''enseignement secondaire inférieur 
(CESI) équivalant au certificat d''enseignement secondaire du deuxième degré sont 
considérés comme porteurs du Certificat d''enseignement secondaire du deuxième 
degré de l''enseignement professionnel (CE2D de l''enseignement professionnel).  
 
Inséré par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 343, 'Article 342bis. - Les élèves qui bénéficient du mécanisme de l''intégration', 'Article 342bis. - Les élèves qui bénéficient du mécanisme de l''intégration 
temporaire totale entre le 15 janvier 2020 et le 3 juillet 2020 bénéficient d''une 
intégration permanente totale au cours de l''année scolaire 2020-2021. 
 
 
CHAPITRE XIX. - De la disposition finale');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('28737', 344, 'Article 343. - Le présent décret entre en vigueur le 1er septembre 2004 à', 'Article 343. - Le présent décret entre en vigueur le 1er septembre 2004 à 
l''exception du chapitre XIII qui entre en vigueur dès sa parution au Moniteur, de 
l''article 280 qui entre en vigueur le 1er juillet 2004 et des articles 54 à 62 qui entrent 
en vigueur le 1er septembre 2005. 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur belge. 
 
 
