INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 1, 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental', 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental 
et secondaire tel que défini aux articles 2 à 4 du décret du 24 juillet 1997 
définissant les missions prioritaires de l''enseignement fondamental et de 
l''enseignement secondaire et organisant les structures propres à les 
atteindre, sauf pour ce qui est mentionné aux articles 16, § 7, et 39, alinéa 2, 
5°. 
 
Il s''applique également à l''enseignement secondaire de promotion 
sociale, tel que défini au titre II, chapitre IV, du décret du 16 avril 1991 
organisant l''[enseignement pour adultes], sauf pour ce qui est mentionné aux 
articles 16, § 7, et 39, alinéa 2, 5°. 
 
Dans les structures et établissements organisés ou subventionnés dans 
le cadre d''un des enseignements visés aux alinéas précédents, en ce compris 
les internats et homes d''accueil, sont seules concernées les fonctions de 
recrutement des catégories de personnel suivantes : 
1° le personnel directeur et enseignant ; [modifié par D. 30-06-2016] 
2° le personnel paramédical; 
3° le personnel social; 
4° le personnel psychologique; 
 
 
Docu 40701 
 
D. 11-04-2014  
5° le personnel auxiliaire d''éducation. 
 
Modifié par D. 19-10-2017 ; D. 14-03-2019 ; D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 2, 'Article 2. - § 1er. Dans le cadre du présent décret, il faut entendre par : (partie 1)', 'Article 2. - § 1er. Dans le cadre du présent décret, il faut entendre par : 1° fonction : la dénomination générique reprenant, au minimum l''item 2°, complété, le cas échéant, d''items visés du 3° au 6° ; 2° fonction de base : une des dénominations listées à l''article 3; 3° fonction enseignante : dénomination déclinée de la fonction de base de la catégorie du personnel directeur et enseignant, par association à cette fonction de base d''un ensemble de cours et/ou d''activités ainsi que, le cas échéant, d''un classement, d''un niveau d''enseignement et d''une spécificité; 4° classement : qualification de toute fonction enseignante de l''enseignement secondaire de plein exercice, en alternance ou de promotion sociale, en l''associant, soit à la formation générale, soit à la formation technique ou technologique, soit à la pratique professionnelle; 5° niveau d''enseignement : distinction entre l''enseignement maternel, l''enseignement primaire, l''enseignement secondaire du degré inférieur et l''enseignement secondaire du degré supérieur. Appartiennent à l''enseignement secondaire du degré inférieur : a) le 1er degré de l''enseignement secondaire ordinaire visé à l''article 1er, § 1er, de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire; b) la première année du 2e degré de la section de transition visé à l''article 1er, § 2, 2°, a, de la même loi; c) le 2e degré de la section de qualification visé à l''article 1er, § 2, 2°, b, de la même loi; d) l''enseignement secondaire spécialisé de forme 1, 2 et 3 organisé conformément au décret du 3 mars 2004 organisant l''enseignement spécialisé; e) l''enseignement secondaire en alternance organisé au 2e degré professionnel conformément à l''article 2ter, §§ 1er, 2 et 3, du décret du 3 juillet 1991 organisant l''enseignement en alternance; f) les sections de l''[enseignement pour adultes] organisées au degré inférieur conformément à l''article 10, § 1er, du décret du 16 juin 1991 organisant l''[enseignement pour adultes]. Modifié par D. 14-03-2019 Appartiennent à l''enseignement secondaire du degré supérieur : a) la deuxième année du 2e degré et le 3e degré de la section de transition visé à l''article 1er, § 2, 2°, a, de la loi du 19 juillet 1971 relative à la structure générale et à l''organisation de l''enseignement secondaire; b) les 3e et 4e degrés de la section de qualification visés respectivement à l''article 1er, § 2, 2°, b, et à l''article 2, § 4, de la même loi; c) l''enseignement secondaire en alternance organisé au 3e degré conformément à l''article 2ter, §§ 1er et 2, du décret du 3 juillet 1991 organisant l''enseignement en alternance; d) les sections de l''[enseignement pour adultes] organisées au degré supérieur conformément à l''article 10, § 1er, du décret du 16 juin 1991 organisant l''[enseignement pour adultes]; 6° spécificité : dénomination spécifique d''une fonction enseignante assurant la liaison entre la matière enseignée et le ou les titres dont doit être porteur l''enseignant qui l''exerce; Docu 40701 D. 11-04-2014 7° cours : subdivision non fractionnable d''une grille d''étude ou d''une unité d''enseignement correspondant à une ou plusieurs périodes comptabilisées dans le capital/périodes, la dotation périodes ou le nombre total de périodes/professeurs attribué à un établissement d''enseignement visé à l''article 1er; 8° accroche cours/fonction : l''association, selon les règles définies au présent décret, d''un ou plusieurs cours à une ou plusieurs fonctions enseignantes; 9° titre de capacité : appellation générique couvrant à la fois les titres de capacité requis, suffisant ou de pénurie visés aux 10°, 11° et 12° ; 10° titre de capacité requis ou titre requis : certification réglementaire déterminant la compétence adéquate exigée pour exercer une fonction; 11° titre de capacité suffisant ou titre suffisant : certification réglementaire déterminant la compétence suffisante exigée pour exercer une fonction; 12° titre de capacité de pénurie ou titre de pénurie : certification réglementaire déterminant la compétence minimale exigée pour exercer une fonction; 13° homme de métier : cette qualification correspond à la composante disciplinaire d''un titre de capacité lorsque celle-ci est constituée de la seule expérience utile visée à l''article 20 du présent décret accompagnée ou non du certificat d''enseignement secondaire supérieur (CESS); 14° toute autre compétence de base, certifiée ou non certifiée, considérée comme pouvant suffire à défaut de titres visés au 10°, 11° et 12°, à l''exercice d''une fonction de base ou d''une fonction enseignante; [remplacé par D. 17-07- 2020] 15° Commission : la Commission interréseaux des titres de capacité définie au chapitre 5 du présent décret; 16° Réseau d''enseignement : l''un des groupements de pouvoirs organisateurs bénéficiaires d''un organe de représentation et de coordination prévus à l''article 5bis de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement; 17° jour ou');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 3, 'Article 2. - § 1er. Dans le cadre du présent décret, il faut entendre par : (partie 2)', 'scolaire : le lundi, le mardi, le mercredi, le jeudi, le vendredi, à l''exception de ceux qui tombent pendant les vacances scolaires ou tout autre jour de congé scolaire; 18° jour ouvrable : le lundi, le mardi, le mercredi, le jeudi, le vendredi, le samedi à l''exception des jours fériés légaux ; 19° Variante : toute dénomination d''une compétence disciplinaire ou pédagogique listée dont la formulation est antérieure et déclarée correspondante à celles reprises dans l''arrêté pris en exécution de l''article 16; [inséré par D. 19-10-2017] 20° Déclassement d''un titre de capacité : décision du Gouvernement qui, sur proposition de la Commission, aboutit à ce qu''un titre de capacité passe de : a) titre requis à titre suffisant ou de pénurie ou à autre titre ; b) titre suffisant à titre de pénurie ou à autre titre ; c) titre de pénurie passe à autre titre ; [inséré par D. 19-10-2017] 21° Mieux titré : qualification donnée à un membre du personnel de l''enseignement porteur d''un : a) titre requis par rapport à un porteur d''un titre suffisant, de pénurie ou d''un autre titre ; b) titre suffisant par rapport à un porteur d''un titre de pénurie ou d''un autre titre ; c) titre de pénurie par rapport au porteur d''un autre titre. [Inséré par D. 19-10-2017] Docu 40701 D. 11-04-2014 § 2. L''emploi dans le présent décret des noms masculins pour les différents titres et fonctions est épicène en vue d''assurer la lisibilité du texte nonobstant les dispositions du décret du 21 juin 1993 relatif à la féminisation des noms de métier. CHAPITRE II. - Des fonctions de recrutement des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical, du personnel social et du personnel psychologique des établissements d''enseignement organisé et subventionné par la Communauté française et des internats y annexés. Complété par D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 4, 'Article 3. - § 1er. Dans l''enseignement fondamental les fonctions de', 'Article 3. - § 1er. Dans l''enseignement fondamental les fonctions de 
base de la catégorie du personnel directeur et enseignant sont : 
1° instituteur maternel; 
2° instituteur primaire; 
3° maître. 
Dans l''enseignement secondaire de plein exercice, ordinaire et 
spécialisé, ainsi que dans l''enseignement en alternance, les fonctions de base 
de la catégorie du personnel directeur et enseignant sont : 
1° professeur; 
2° accompagnateur CEFA. 
 
§ 2. Les fonctions de base de la catégorie du personnel auxiliaire 
d''éducation dans l''enseignement fondamental et secondaire de plein exercice 
sont : 
1° éducateur; 
2° éducateur d''internat filles; 
3° éducateur d''internat garçons; 
4° secrétaire-bibliothécaire. 
 
§ 3. Les fonctions de base de la catégorie du personnel paramédical dans 
l''enseignement fondamental et secondaire sont : 
1° ergothérapeute; 
2° infirmier; 
3° kinésithérapeute; 
4° logopède; 
5° puériculteur ; 
[6° orthoptiste]1. 
 
§ 4. La fonction de base de la catégorie du personnel social dans 
l''enseignement fondamental et secondaire est : 
1° assistant social. 
 
§ 5. La fonction de base de la catégorie du personnel psychologique dans 
l''enseignement fondamental et secondaire est : 
 
1° psychologue. 
 
§ 6. Dans l''[enseignement pour adultes de niveau secondaire], les 
fonctions de base de la catégorie du personnel directeur et enseignant sont : 
 
1 Ajouté par le décret du 20 juillet 2023 
 
 
Docu 40701 
 
D. 11-04-2014  
1° professeur; 
2° coordinateur qualité; 
3° conseiller à la formation. 
 
§ 7. La fonction de base de la catégorie du personnel auxiliaire 
d''éducation dans l''[enseignement pour adultes de niveau secondaire] est : 
1° éducateur - secrétaire. 
 
Inséré par D. 03-05-2019 
§ 8. Les profils de fonction dans l''enseignement ordinaire pour la 
fonction d''accompagnateur CEFA reprise au § 1er et d''éducateur reprise 
au § 2 et dans l''enseignement spécialisé pour les fonctions d''ergothérapeute, 
infirmier, kinésithérapeute, logopède, puéricultrice, assistant social et 
psychologue reprises aux §§ 3, 4 et 5, sont fixés par arrêté du Gouvernement, 
et pour l''enseignement subventionné, après avis de la commission paritaire 
compétente visée à l''article 91, § 1er, 1°, a, et 2°, a, du décret du 1er février 
1993 fixant le statut des membres du personnel subsidié de l''enseignement 
libre subventionné et à l''article 85, 1°, du décret du 6 juin 1994 fixant le 
statut des membres du personnel subsidié de l''enseignement officiel 
subventionné.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 5, 'Article 4. - Toute modification, création, suppression ou changement de', 'Article 4. - Toute modification, création, suppression ou changement de 
catégorie d''une fonction de base visée à l''article 3 fait l''objet d''un avis 
préalable de la Commission. 
 
Modifié par D. 07-02-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 6, 'Article 5. - Les fonctions de base reprises aux §§ 1er et 6 de l''article 3', 'Article 5. - Les fonctions de base reprises aux §§ 1er et 6 de l''article 3 
génèrent les fonctions enseignantes. 
 
La fonction d''enseignante d''instituteur maternel s''exerce au niveau de 
l''enseignement maternel ordinaire et spécialisé, dans l''enseignement 
primaire spécialisé de maturité I et de maturité II de type 2 et dans 
l''enseignement primaire ordinaire en application du décret du 7 février 2019 
visant à l''accueil, la scolarisation et l''accompagnement des élèves qui ne 
maîtrisent pas la langue de l''enseignement dans l''enseignement organisé ou 
subventionné par la Communauté française. [Remplacé par D. 07-02-2019] 
 
La fonction enseignante d''instituteur primaire s''exerce au niveau de 
l''enseignement primaire ordinaire et spécialisé ainsi que dans l''enseignement 
maternel ordinaire en application du décret du 7 février 2019 visant à 
l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent 
pas la langue de l''enseignement dans l''enseignement organisé ou 
subventionné par la Communauté française. [Remplacé par D. 07-02-2019] 
 
La fonction enseignante de maître peut être exercée aux deux niveaux 
de l''enseignement fondamental ordinaire et spécialisé, selon les spécificités 
reprises en regard de chaque fonction enseignante telles qu''elles sont 
déterminées conformément à l''article 7. 
 
La fonction enseignante de professeur s''exerce, soit au niveau de 
l''enseignement secondaire du degré inférieur, ordinaire et spécialisé, soit au 
niveau de l''enseignement secondaire du degré supérieur, ordinaire et 
spécialisé, soit dans le cadre d''une fonction enseignante unique s''exerçant à 
la fois au degré inférieur et supérieur de l''enseignement secondaire ordinaire. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
La fonction enseignante d''accompagnateur CEFA s''exerce dans 
l''enseignement secondaire en alternance visé par le décret du 3 juillet 1991 
organisant l''enseignement secondaire en alternance. 
 
La fonction enseignante de professeur s''exerce également dans 
l''[enseignement pour adultes de niveau secondaire] soit au degré inférieur, 
soit au degré supérieur. 
 
Modifié D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 7, 'Article 6. - § 1er. Chaque fonction enseignante de professeur déclinée', 'Article 6. - § 1er. Chaque fonction enseignante de professeur déclinée 
selon les niveaux précisés à l''article 5 est classée, soit en fonction cours 
généraux (CG), soit en fonction morale non confessionnelle (MOR), soit en 
fonction religion (REL), soit en fonction cours artistiques (CA), soit en 
fonction cours techniques (CT), soit en fonction cours de pratique 
professionnelle (PP), soit en fonction psychologie-pédagogie-méthodologie 
(PPM). 
 
§ 2. Les fonctions de professeur exercées antérieurement en cours 
spéciaux (CS) sont reclassées en fonction cours généraux (CG) ou en fonction 
cours techniques (CT). 
 
§ 3. Les fonctions de professeur exercées antérieurement en cours 
techniques et de pratique professionnelle (CTPP) sont reclassées, pour partie 
en fonction cours techniques (CT) et pour partie en fonction de cours pratique 
professionnelle (PP). 
 
§ 4. Les fonctions de professeur exercées antérieurement en cours de 
langues anciennes (ANC) sont reclassées en fonction de cours généraux (CG).');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 8, 'Article 7. - Le Gouvernement définit, sur avis de la Commission, la', 'Article 7. - Le Gouvernement définit, sur avis de la Commission, la 
spécificité de chaque fonction enseignante autre que l''accompagnateur CEFA, 
le coordinateur qualité et le conseiller à la formation en : 
1° précisant toutes les activités d''enseignement, tous les cours dispensés 
dans le cadre des enseignements visés à l''article 1er, alinéa 1 et 2, hors 
l''enseignement maternel et primaire, et la ou les fonctions auxquelles ils 
peuvent être accrochés; 
2° déterminant les titres de capacité requis, suffisants et de pénurie. 
 
Les arrêtés adoptés conformément au présent article sont soumis à la 
confirmation du Parlement dans un délai de douze mois suivant leur 
adoption. A défaut d''une telle confirmation, ils cessent de produire leurs 
effets à l''issue de ce délai. 
 
CHAPITRE III. - Dispositions relatives au processus d''accroche 
cours/fonction 
 
Section Ire. - Objectifs du processus');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 9, 'Article 8. - Le processus a pour objectifs :', 'Article 8. - Le processus a pour objectifs : 
1° de fixer pour l''ensemble des réseaux d''enseignement, l''enseignement 
organisé par la Communauté française et des pouvoirs organisateurs non 
affiliés à un organe de représentation et de coordination, les titres de capacité 
dont doivent être porteurs les titulaires des fonctions enseignantes en y 
associant un ensemble d''activités d''enseignement et de cours répondant à 
une même spécificité; 
 
 
Docu 40701 
 
D. 11-04-2014  
2° de sécuriser l''octroi et la gestion des attributions par la fixation, pour 
chaque réseau d''enseignement, l''enseignement organisé par la Communauté 
française et chaque pouvoir organisateur non affilié à un organe de 
représentation et de coordination, par arrêté du Gouvernement, des activités 
d''enseignement et des cours susceptibles d''être accrochés par un pouvoir 
organisateur à une fonction enseignante. 
3° de faciliter le respect par chaque pouvoir organisateur, de l''ensemble 
des opérations statutaires auquel il est soumis; 
4° de permettre à chaque postulant à un emploi dans une fonction 
enseignante auprès d''un pouvoir organisateur de connaître précisément 
l''ensemble des activités d''enseignement et de cours que recouvre cet emploi. 
 
Section II. - Fonctions enseignantes pour lesquelles s''exerce le 
processus d''accroche cours/fonction');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 10, 'Article 9. - Le processus d''accroche cours/fonction s''exerce dans toutes', 'Article 9. - Le processus d''accroche cours/fonction s''exerce dans toutes 
les fonctions enseignantes à l''exception de celles de l''enseignement maternel 
et primaire, de la fonction d''accompagnateur CEFA et des fonctions de 
coordinateur qualité et de conseiller à la formation de l''[enseignement pour 
adultes]. 
 
Section III. - Procédures administratives de fixation de l''accroche 
cours/fonction');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 11, 'Article 10. - § 1er. Les accroches cours/fonction visées à l''article 11 sont', 'Article 10. - § 1er. Les accroches cours/fonction visées à l''article 11 sont 
arrêtées par le Gouvernement conformément aux principes fixés dans la 
présente section. Ces arrêtés sont soumis à la confirmation du Parlement 
dans un délai de douze mois suivant leur adoption. A défaut d''une telle 
confirmation, ils cessent de produire leurs effets à l''issue de ce délai. 
 
§ 2. Pour l''enseignement organisé par la Communauté française, les 
accroches cours/fonction sont soumises, par les Services du Gouvernement, à 
l''avis préalable de la Commission qui les transmet au Gouvernement. 
 
Pour l''enseignement subventionné, les accroches cours/fonction sont 
soumises, par les organes de représentation et de coordination, à l''avis 
préalable de la Commission qui les transmet au Gouvernement. 
 
Pour les pouvoirs organisateurs non affiliés à un organe de 
représentation et de coordination, les accroches cours/fonction effectives sont 
soumises à l''avis préalable de la Commission et transmises au Gouvernement 
par chaque pouvoir organisateur. 
 
Par 
dérogation 
aux 
alinéas 
précédents, 
pour 
les 
arrêtés 
du 
Gouvernement fixant les accroches cours/fonction approuvés avant le 1er 
septembre 2014, l''avis préalable d''un groupe de travail dont la composition 
de même que les modalités de fonctionnement sont conformes à celles de la 
Commission telles que fixées aux articles 42 et 47 du présent décret tient lieu 
d''avis préalable de la Commission. Ce groupe de travail est présidé par le 
Ministre ayant l''enseignement obligatoire et l''[enseignement pour adultes] 
dans ses attributions ou par son délégué. 
 
Les accroches arrêtées par le Gouvernement conformément à l''alinéa 
précédent sont remplacées au fur et à mesure de leur élaboration par celles 
arrêtées conformément à l''article 39, alinéa 2, 2°. 
 
 
Docu 40701 
 
D. 11-04-2014  
Ces propositions doivent répondre au prescrit de l''article 11.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 12, 'Article 11. - § 1er. Les accroches cours/fonction sont uniques pour tous', 'Article 11. - § 1er. Les accroches cours/fonction sont uniques pour tous 
les cours présentant un lien direct avec la spécificité d''une fonction telle que 
définie à l''article 2, 6°, du présent décret. 
 
Ce lien direct est établi sur la base des contenus d''apprentissage 
obligatoires et des compétences disciplinaires à atteindre. 
 
Cette unité se traduit, dans l''arrêté du Gouvernement visé à l''article 10, 
par un lien univoque entre un cours et une fonction enseignante. 
 
§ 2. Lorsque, sur la base des contenus d''apprentissage obligatoires et 
des compétences disciplinaires à atteindre, le lien direct ne peut être établi 
de manière univoque entre le cours et la fonction, une accroche cours/fonction 
multiple peut être proposée. 
 
Chaque fonction accrochée doit démontrer un lien substantiel entre les 
contenus d''apprentissage obligatoires, les compétences disciplinaires à 
atteindre dans ce cours et le profil des titres de capacité fixés pour chacune 
de ces fonctions. 
 
Ce lien substantiel peut être établi également entre le profil des titres 
de capacité d''une fonction et la finalité de l''option groupée ou de la section, 
dont le cours fait partie. 
 
Cette accroche cours/fonction multiple se traduit, dans l''arrêté du 
Gouvernement de la Communauté française visé à l''article 10 par le lien d''un 
même cours à plusieurs fonctions.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 13, 'Article 12. - § 1er. Au plus tard le 31 janvier de chaque année scolaire,', 'Article 12. - § 1er. Au plus tard le 31 janvier de chaque année scolaire, 
les Services du Gouvernement pour l''enseignement organisé par la 
Communauté française et chaque organe de représentation et de 
coordination ou chaque pouvoir organisateur visé à l''article 10, § 2, alinéa 3, 
dépose à la Commission les demandes de modifications souhaitées à ses 
accroches cours/fonction. 
 
Toute demande de reprise par un réseau, la Communauté française, ou 
un pouvoir organisateur non affilié à un organe de représentation ou de 
coordination d''une accroche cours/fonction unique ou multiple déjà utilisée 
par un autre réseau d''enseignement, la Communauté française ou un pouvoir 
organisateur non affilié à un organe de représentation ou de coordination ne 
doit pas faire l''objet d''une motivation auprès de la Commission. 
 
En dehors de l''hypothèse visée à l''alinéa précédent, toute demande de 
modification d''une accroche unique ou multiple existante, doit démontrer sa 
conformité aux dispositions de l''article 11 au moyen d''un argumentaire joint 
à la demande. 
 
La Commission se prononce pour le 15 mars de l''année précédent 
l''entrée en vigueur sollicitée par le réseau d''enseignement, l''enseignement 
organisé par la Communauté française ou le pouvoir organisateur non affilié 
à un organe de représentation ou de coordination. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
La procédure prévue par le présent article ne s''applique qu''aux 
accroches cours-fonction pour lesquelles les accroches cours/fonction 
communes à l''ensemble des réseaux d''enseignement, l''enseignement organisé 
par la Communauté française et des pouvoirs organisateurs non affiliés à un 
organe de représentation ou de coordination, prévues à l''article 39, alinéa 2, 
2°, du présent décret, ne sont pas encore entrées en vigueur. 
 
§ 2. Par dérogation au paragraphe précédent, pour l''[enseignement pour 
adultes], les demandes de modifications à des accroches cours-fonctions 
peuvent être introduites à tout moment de l''année scolaire. Dans ce cas, la 
Commission dispose de trente jours pour se prononcer sur le dossier. 
 
§ 3. La date de prise d''effet des modifications aux accroches 
cours/fonctions visées aux §§ 1er et 2 est fixée à la première organisation 
d''enseignement concernée suivant l''approbation par le Gouvernement sur 
avis rendu par la Commission. 
 
§ 4. La procédure et les délais fixés au § 1er sont également d''application 
lors de toute création d''un nouveau cours, soit dans une grille horaire ou une 
unité d''enseignement existante, soit lors de l''adoption d''une nouvelle grille 
horaire ou d''une nouvelle unité d''enseignement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 14, 'Article 13. - § 1er. Chaque pouvoir organisateur doit inscrire ses', 'Article 13. - § 1er. Chaque pouvoir organisateur doit inscrire ses 
accroches cours/fonction au sein de celles retenues par le réseau 
d''enseignement auquel il appartient. 
 
§ 2. A partir de l''année scolaire 2016-2017 et en vue de l''organisation de 
chaque année scolaire, pour toute accroche cours/fonction multiple du 
référentiel qui concerne ses structures scolaires, tout pouvoir organisateur 
doit, au plus tard le 30 juin de l''année scolaire précédente, porter à la 
connaissance de l''administration ses activations effectives. 
 
Les activations effectives visées à l''alinéa précédant ne peuvent aboutir 
à la mise en disponibilité par défaut d''emploi ou à la perte partielle de charge 
d''un membre du personnel nommé ou engagé à titre définitif. 
 
§ 3. Quelle que soit l''activation effectuée par un pouvoir organisateur 
dans le cadre d''une accroche cours/fonction multiple, celui-ci est tenu 
d''appliquer les mesures préalables à la disponibilité et les règles de 
réaffectation auxquelles il est soumis à l''ensemble des fonctions accrochées 
pour ces cours par le réseau d''enseignement auquel il appartient. 
 
Modifié par D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 15, 'Article 14. - Au 15 janvier, la Commission présente son rapport annuel', 'Article 14. - Au 15 janvier, la Commission présente son rapport annuel 
relatif au processus d''accroche cours/fonction. 
 
Ce 
rapport 
présente 
notamment, 
une 
analyse 
des 
accroches 
cours/fonction multiples. 
 
La Commission propose au Gouvernement, avec effet au premier jour de 
l''année scolaire suivante, la suppression, du référentiel propre au réseau 
d''enseignement, à l''enseignement organisé par la Communauté française ou 
au pouvoir organisateur non affilié à un organe de représentation et de 
coordination de toute accroche non activée d''une accroche cours/fonction 
multiple durant les trois années précédentes. Le réseau d''enseignement 
concerné, l''enseignement organisé par la Communauté française ou le 
 
 
Docu 40701 
 
D. 11-04-2014  
pouvoir organisateur non affilié à un organe de représentation et de 
coordination concerné qui, malgré cette proposition, souhaite maintenir 
l''accroche en question devra présenter pour le 15 avril, la demande d''un de 
ses pouvoirs organisateurs d''activer celle-ci au dernier jour de l''année 
scolaire en cours. 
 
Modifié par D. 13-07-2016 
CHAPITRE IV. - Dispositions relatives aux titres de capacité dont 
doivent être porteurs les titulaires d''une fonction 
 
Section Ire. - Généralités');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 16, 'Article 15. - A toute fonction exercée au sein des établissements et des', 'Article 15. - A toute fonction exercée au sein des établissements et des 
catégories de personnels repris dans le champ de l''article 1er sont associés des 
titres de capacité permettant d''exercer cette fonction selon, s''il échet, la 
spécificité qui lui est reconnue. 
 
Ces titres de capacité se déclinent, sauf exception, en quatre catégories : 
les titres requis, les titres suffisants, les titres de pénurie et les autres titres. 
 
Dans l''[enseignement pour adultes de niveau secondaire], l''exercice de 
certaines charges de cours peut être confié à des experts dont le profil de 
compétence 
est 
déterminé 
par 
le 
dossier 
pédagogique 
de 
l''unité 
d''enseignement dans laquelle elle est exercée. 
 
Modifié par D. 19-10-2017 ; D. 14-03-2019 ; D. 17-07-2020 ; complété par 
D. 01-12-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 17, 'Article 16. - § 1er. Les titres de capacité requis, suffisants et de pénurie', 'Article 16. - § 1er. Les titres de capacité requis, suffisants et de pénurie 
sont fixés pour chaque fonction par le Gouvernement, sur avis de la 
Commission. Les arrêtés adoptés conformément au présent article sont 
soumis à la confirmation du Parlement dans un délai de douze mois suivant 
leur adoption. A défaut d''une telle confirmation, ils cessent de produire leurs 
effets à l''issue de ce délai. 
 
Par dérogation à l''alinéa précédent, pour l''arrêté du Gouvernement 
fixant les titres de capacité requis, suffisants et de pénurie approuvés avant 
le 1er septembre 2014, l''avis préalable d''un groupe de travail dont la 
composition de même que les modalités de fonctionnement sont conformes à 
celles de la Commission telles que fixées aux articles 42, 46 et 47 du présent 
décret tient lieu d''avis préalable de la Commission. Ce groupe de travail est 
présidé par le Ministre ayant l''enseignement obligatoire et l''[enseignement 
pour adultes] dans ses attributions ou par son délégué. 
 
Sans préjudice des dispositions relatives à la maîtrise de la langue de 
l''immersion prévue par le décret du 17 juillet 2003 portant des dispositions 
générales à l''enseignement en langue d''immersion et diverses mesures en 
matière d''enseignement, les titres de capacité pour les fonctions en 
immersion linguistique sont ceux fixés, pour les fonctions correspondantes 
exercées hors immersion. 
 
Modifié par D. 17-07-2020 ; complété par D. 01-12-2022 
§ 2. A l''exception de la catégorie des autres titres seuls les diplômes, 
brevets, certificats ou spécialisations délivrés par la Communauté française, 
équivalents, reconnus ou assimilés par la Communauté française peuvent 
être admis comme composante du titre de capacité. 
 
 
Docu 40701 
 
D. 11-04-2014  
Pour les fonctions de langues modernes, peuvent en outre être admis 
comme composante du titre de capacité, les certificats de réussite à des tests 
de langue émis par des organisations belges ou internationales dont le 
gouvernement fixe la liste ainsi que le niveau de réussite requis en référence 
au Cadre européen commun de référence pour les langues: Apprendre, 
enseigner, évaluer. 
 
[Pour les fonctions de conducteur poids lourds, peut en outre être admis 
comme composante du titre de capacité le certificat de réussite de l’examen 
de capacités sectoriel organisé par le Fonds social transport et logistique.]2 
 
§ 3. Pour la catégorie des titres de capacité requis la compétence 
adéquate exigée réunit les composantes ci-dessous : 
1° une compétence disciplinaire acquise et sanctionnée par un titre; 
2° une compétence pédagogique intrinsèque au titre visé ci-dessus ou 
acquise séparément dans un titre; 
3° le cas échéant, lorsque les contenus d''apprentissage obligatoires et les 
compétences disciplinaires le justifient, une expérience utile telle que définie 
à l''article 20. 
 
§ 4. Pour la catégorie des titres de capacité suffisants, la compétence 
suffisante exigée réunit toujours une compétence disciplinaire listée comme 
suffisante et une compétence pédagogique établie selon les mêmes procédures 
que le titre de capacité requis ainsi que, lorsque les contenus d''apprentissage 
obligatoires et les compétences disciplinaires le justifient, une expérience 
utile. 
 
Par dérogation à l''alinéa précédent, moyennant l''avis de la Commission, 
est considéré comme suffisant le master sans composante pédagogique, 
lorsque ce master avec composante pédagogique est considéré comme requis. 
 
Lors de l''entrée en vigueur du présent décret, la mention de tels masters 
en titre suffisant dans l''arrêté du Gouvernement visé à l''article 7 est réputée 
avoir fait l''objet d''un avis favorable de la Commission. 
 
§ 5. Pour la catégorie des titres de capacité de pénurie, la compétence 
minimale exigée présente soit une articulation avec le titre de capacité requis 
ou suffisant permettant l''accession à ceux-ci, soit une possibilité 
d''assimilation à un titre suffisant selon les modalités de l''article 37. 
 
Modifié par D. 17-07-2020 
§ 6. En situation de pénurie de tout porteur de titres fixés par le 
Gouvernement, tout porteur d''autres titres peut être recruté. 
 
Inséré par D. 14-03-2019 
§ 6bis. […] Abrogé par D. 17-07-2020 
 
Inséré par D. 19-10-2017 
§ 7. Le Gouvernement arrête également la liste des variantes anciennes 
des diplômes listés conformément au présent article. Ces variantes valent 
pour tout diplôme listé dans d''autres textes relatifs à la réglementation de 
l''enseignement quel que soit le niveau d''enseignement concerné. 
 
2Inséré par le décret du 18 janvier 2024 
 
 
Docu 40701 
 
D. 11-04-2014  
Section II. - Dispositions relatives aux titres pédagogiques 
constitutifs d''un titre de capacité 
 
Complété par D. 30-06-2016 ; D. 19-10-2017 ; modifié par D. 07-02-2019 ; 
D. 17-07-2020 ; D. 19-07-2021 ; D. 02-12-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 18, 'Article 17. - § 1er. Sauf exception prévue dans l''annexe II de l''arrêté du (partie 1)', 'Article 17. - § 1er. Sauf exception prévue dans l''annexe II de l''arrêté du Gouvernement de la Communauté française du 5 juin 2014 relatif aux relatif aux fonctions, titres de capacité et barèmes portant exécution des articles 7, 16, 50 et 263 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française, exception ne valant que pour la fonction concernée, satisfait à la condition de possession de la composante pédagogique adéquate pour la constitution d''un titre de capacité : 1° au niveau de l''enseignement maternel : a) l''instituteur maternel et b) pour certaines fonctions déterminées par le Gouvernement, l''agrégation de l''enseignement secondaire supérieur (AESS ou master à finalité didactique) ainsi que certaines sections relevant de l''agrégation de l''enseignement secondaire inférieur (AESI) ainsi que le certificat d''aptitude pédagogique (CAP); 2° au niveau de l''enseignement primaire : a) l''instituteur primaire et b) pour certaines fonctions déterminées par le Gouvernement, l''agrégation de l''enseignement secondaire supérieur (AESS ou master à finalité didactique); 3° au niveau de l''enseignement secondaire inférieur : a) l''agrégation de l''enseignement secondaire inférieur (AESI); b) le certificat d''aptitudes pédagogiques (CAP) et le certificat normal technique moyen (CNTM) pour les titres de capacité dont la composante «compétence disciplinaire» ne donne accès ni à l''AESI, ni à l''AESS; c) pour les fonctions spécifiques à l''enseignement secondaire spécialisé de forme 1 et de forme 2: l''instituteur maternel. Par «spécifiques», on entend les fonctions qui ne sont organisées que dans ces deux formes de l''enseignement spécialisé. [Inséré par D. 19-07-2021] 4° au niveau de l''enseignement secondaire supérieur : a) l''agrégation de l''enseignement secondaire supérieur (AESS ou le master à finalité didactique); b) le certificat d''aptitudes pédagogiques (CAP) et le certificat normal technique moyen (CNTM) pour les titres de capacité dont la composante «compétence disciplinaire» ne donne pas accès à l''AESS. Pour la fonction enseignante d''accompagnateur CEFA reprise à l''article 5, alinéa 6, l''ensemble des titres pédagogiques repris sous 3° et 4° justifie de la possession de la composante pédagogique adéquate. Docu 40701 D. 11-04-2014 § 2. La composante pédagogique adéquate pour un niveau donné vaut également pour le niveau directement inférieur lorsqu''il existe et pour le niveau directement supérieur lorsqu''il existe. Pour l''application de l''alinéa précédent, les niveaux visés au § 1er sont considérés comme classés du 1° au 4° dans l''ordre croissant des niveaux. Par dérogation à l''alinéa 1er, le certificat d''aptitudes pédagogiques approprié à l''enseignement supérieur (CAPAES) est considéré comme adéquat uniquement pour l''[enseignement pour adultes de niveau secondaire supérieur] ainsi que pour le 4ème degré de l''enseignement secondaire de plein exercice. Remplacé par D. 07-02-2019, amendé par D. 02-12-2021 § 3. Le porteur d''un master ou d''une licence ouvrant l''accès à un cursus conduisant au grade académique de master en enseignement section 5 peut, en vue de satisfaire à la possession de la composante pédagogique, s''inscrire dans une section d''un établissement d''[enseignement pour adultes] sanctionnée par le certificat d''aptitude pédagogique s''il respecte au minimum la condition suivante: l''annexion au dossier de l''étudiant d''un document attestant de l''impossibilité d''une université, d''une haute école ou d''une école supérieure des arts de son choix de l''inscrire dans un cursus conduisant au grade académique de master en enseignement section 5. Le Gouvernement fixe le modèle du document attestant de l''impossibilité de s''inscrire dans un cursus conduisant au grade académique de master en enseignement section 5 visé à l''alinéa 1er. § 4.3 Le porteur d''un master ou d''une licence ouvrant l''accès à un cursus conduisant au grade académique de master en enseignement section 5 peut, en vue de satisfaire à la possession de la composante pédagogique, s''inscrire dans une section d''un établissement d''[enseignement pour adultes] sanctionnée par le certificat d''aptitude pédagogique et ayant, au préalable signé une convention de collaboration/co-organisation avec une haute école, une université ou une école supérieure des arts, s''il respecte au minimum la condition suivante: l''annexion au dossier de l''étudiant d''un document attestant que, pour des motifs professionnels, sociaux ou matériels, l''organisation pratique du cursus conduisant au grade académique de master en enseignement section 5 la rend manifestement plus accessible. Le Gouvernement fixe le modèle du document attestant de la plus grande accessibilité de la formation si elle est organisée par une université, une haute école ou une école supérieure des arts en collaboration avec un établissement de promotion sociale. Inséré par D. 30-06-2016 § 4. Le « specifieke leraaropleiding');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 19, 'Article 18. - § 1er. Tout porteur d''un titre pédagogique visé à l''article', 'Article 18. - § 1er. Tout porteur d''un titre pédagogique visé à l''article 
17, § 1er, 1°, a), qui possède ou acquiert, pour l''exercice d''une fonction au 
 
3 Cet article comportait déjà un §4. Il est reproduit ici pour respecter à la lettre le décret 
modificatif. 
 
 
Docu 40701 
 
D. 11-04-2014  
même niveau ou au niveau directement supérieur, une autre compétence 
disciplinaire au sens de l''article 16 satisfera à la condition de possession de la 
composante «compétence pédagogique». 
 
§ 2. Tout porteur d''un titre pédagogique visé à l''article 17, § 1er, 2°, a), 
qui possède ou acquiert, pour l''exercice d''une fonction au même niveau ou au 
niveau 
directement 
inférieur 
ou 
supérieur, 
une 
autre 
compétence 
disciplinaire au sens de l''article 16 satisfera à la condition de possession de la 
composante «compétence pédagogique». 
 
§ 3. Tout porteur d''un titre pédagogique visé à l''article 17, § 1er, 3°, qui 
possède ou acquiert, pour l''exercice d''une fonction au même niveau ou au 
niveau 
directement 
inférieur 
ou 
supérieur, 
une 
autre 
compétence 
disciplinaire au sens de l''article 16 satisfera à la condition de possession de la 
composante «compétence pédagogique». 
 
§ 4. Tout porteur d''un titre pédagogique visé à l''article 17, § 1er, 4°, qui 
possède ou acquiert, pour l''exercice d''une fonction au même niveau ou au 
