INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 37, 'Article 29quater. – […] Abrogé par D. 17-07-2020 / Article 30. - Les autorités disposant du pouvoir de recrutement', 'Article 29quater. – […] Abrogé par D. 17-07-2020 
 
Sous-section II. - Dispositions particulières aux règles de 
priorisation 
 
Modifié par D. 30-06-2016 ; complété par D. 19-10-2017

Article 30. - Les autorités disposant du pouvoir de recrutement 
peuvent justifier valablement d''une exception à l''application de l''article 26 à 
l''égard d''un candidat pour les raisons suivantes : 
 
1° le candidat fait ou a fait, au sein du pouvoir organisateur, en qualité 
de temporaire, l''objet d''un licenciement moyennant préavis ou pour faute 
grave; 
2° le candidat fait ou a fait, en qualité de définitif, l''objet d''un 
licenciement pour faute grave, d''une révocation, d''une suspension par mesure 
disciplinaire, d''une mise en disponibilité par mesure disciplinaire, d''une 
rétrogradation disciplinaire ou d''une démission disciplinaire; 
3° le candidat fait ou a fait l''objet d''une suspension préventive justifiée 
par une inculpation, une prévention dans le cadre de poursuites pénales, une 
condamnation pénale non définitive contre laquelle le membre du personnel 
a fait l''usage de ses droits de recours ordinaires; 
4° le candidat fait ou a fait l''objet d''un rapport défavorable écrit et visé 
par le membre du personnel. Cette justification ne peut être évoquée comme 
motif 
d''écartement 
que 
par 
le 
même 
pouvoir 
organisateur 
pour 
l''enseignement 
subventionné ou 
pour 
une même 
désignation 
pour 
l''enseignement organisé par la Communauté française; 
5° le candidat n''est pas de conduite irréprochable; 
6° le candidat n''adhère pas aux spécificités du projet pédagogique et/ou 
éducatif du pouvoir organisateur et/ou n''adhère pas au règlement du travail; 
7° le candidat n''a pas répondu à l''offre d''emploi lui adressée par le 
pouvoir organisateur dans les 24 h comprises dans les jours ouvrables 
scolaires, en cas de désignation pour une période de 5 à 10 jours, ou dans les 
trois jours ouvrables dont au moins un jour ouvrable scolaire, en cas de 
désignation pour une période de plus de 10 jours ; 
8° les pièces jointes visées à l''article 27 ne correspondent pas au titre de 
capacité dont se prévaut le candidat ; [inséré par D. 19-10-2017] 
9° le candidat a refusé l''emploi ou n''y a pas donné suite. [inséré par D. 19-
10-2017] 
 
Le candidat atteste sur l''honneur ne pas être sous le coup d''une des 
restrictions reprises aux points 1° à 3°. 
 
Par dérogation à l’article 2, §1er, 17° du présent décret, à l’alinéa 1er, 
7°, les périodes du 1er au 7 juillet et du 16 au 31 août sont assimilées à des 
jours ouvrables scolaires. [Alinéa inséré par D. 30-06-2016]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 38, 'Article 31. - Les autorités disposant du pouvoir de recrutement', 'Article 31. - Les autorités disposant du pouvoir de recrutement 
peuvent justifier le non respect des règles de priorisation à l''égard d''un 
candidat lorsqu''elles invoquent les situations suivantes : 
 
 
Docu 40701 
 
D. 11-04-2014  
1° l''existence d''une incompatibilité d''horaire après le 15 octobre de 
l''année scolaire ou durant toute l''année scolaire pour l''[enseignement pour 
adultes] avec constatation via l''organe de démocratie sociale. Pour 
l''application de cette exception, il peut être tenu compte des blocs horaires de 
la grille d''étude; 
2° l''écartement du candidat qui ne convient manifestement pas lors de 
l''entretien d''embauche. La justification dont le candidat doit recevoir un 
exemplaire doit être visée par le candidat. Cette obligation est réputée 
remplie dès lors que le pouvoir organisateur fait la preuve que la demande de 
visa a été adressée au candidat. 
 
Inséré par D. 19-10-2017 ; remplacé par D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 39, 'Article 31bis. –  [Par dérogation, dans le champ de la priorisation des', 'Article 31bis. –  [Par dérogation, dans le champ de la priorisation des 
porteurs de titres requis ou suffisants sur les porteurs de titres de pénurie, le 
porteur d''un titre requis ou d''un titre suffisant engagé dans le cadre de 
l''application de l''article 29 ou 29bis et porteur d''un titre pédagogique ou le 
porteur d''un titre de pénurie engagé dans le cadre de l''application de l''article 
29 ou 29bis et porteur d''un titre pédagogique exerçant à ce(s) titre(s) une ou 
plusieurs fonctions à prestations incomplètes formant au total au moins la 
moitié du nombre d''heures requis pour une fonction à prestations complètes 
peut voir sa charge étendue, dans l''enseignement spécialisé de forme 4, dans 
une fonction pour laquelle il possède un titre de pénurie. Cette extension est 
limitée à maximum le quart du nombre d''heures requis pour une fonction à 
prestations complètes. 
 
L''exercice de la dérogation visée à l''alinéa 1er ne peut porter préjudice à 
un membre du personnel mieux titré pour cette même fonction ou une de ces 
fonctions, candidat pour une de ces fonctions au sein du Pouvoir 
organisateur.]7 
 
Cet article sera rétabli dans sa version initiale le premier jour de l’année 
scolaire 2026-2027. A savoir : 
Inséré par D. 19-10-2017 
[Article 31bis. - Par dérogation, dans le champ de la priorisation des porteurs 
de titres requis sur les porteurs de titres suffisants, le porteur d''un titre requis ou d''un 
titre suffisant engagé dans le cadre de l''application de l''article 29 ou 29bis et porteur 
d''un titre pédagogique ou le porteur d''un titre de pénurie engagé dans le cadre de 
l''application de l''article 29 ou 29bis et porteur d''un titre pédagogique exerçant à ce(s) 
titre(s) une ou plusieurs fonctions à prestations incomplètes formant au total au 
moins la moitié du nombre d''heures requis pour une fonction à prestations complètes 
peut voir sa charge étendue dans une fonction pour laquelle il possède un titre 
suffisant. Concernant l''[enseignement pour adultes de niveau secondaire], le seuil de 
prestations repris ci-dessus est fixé à concurrence de 120 périodes. 
 
Dans l''enseignement spécialisé de forme 4, la charge peut en outre être étendue, 
aux conditions fixées à l''alinéa 1er, dans une fonction pour laquelle il possède un titre 
de pénurie. Cette extension est limitée à maximum le quart du nombre d''heures requis 
pour une fonction à prestations complètes. 
 
L''exercice des dérogations visées aux alinéas 1er et 2 ne peut porter préjudice à 
un membre du personnel mieux titré pour cette même fonction ou une de ces fonctions, 
candidat pour une de ces fonctions au sein du Pouvoir organisateur.] 
 
7Remplacé par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année 
scolaire 2026-2027. 
 
 
Docu 40701 
 
D. 11-04-2014  
Sous-section III. - Dispositions dérogatoires aux règles de 
priorisation 
 
Complété par D. 30-06-2016 ; remplacé par D. 19-10-2017 ; D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 40, 'Article 32. - § 1. Par dérogation à la règle de la priorisation des', 'Article 32. - § 1. Par dérogation à la règle de la priorisation des 
porteurs de titres [requis et]8 suffisants sur les porteurs de titres de pénurie, 
un porteur de titre de pénurie, temporaire non prioritaire, peut être à 
nouveau désigné ou engagé, l''année scolaire en cours ou l''année scolaire 
suivante, dans la(les) même(s) fonction(s) à la condition suivante : avoir 
exercé cette(ces) fonction(s) durant 150 jours au cours de l''année scolaire 
2015-2016 et sans interruption depuis l''année scolaire 2015-2016 de plus 
d''une année scolaire, à concurrence d''une fonction à prestations complètes ou 
incomplètes comportant au moins le tiers des heures requises pour l''exercice 
d''une fonction à prestations complètes pour l''enseignement de plein exercice 
et en alternance. Les 150 jours sont calculés selon les modalités reprises à 
l''article 19, § 2. [§ Remplacé par D. 17-07-2020] 
 
Concernant l''[enseignement pour adultes de niveau secondaire], le seuil 
de prestations repris ci-dessus est fixé à concurrence de 120 périodes. 
 
(*) Ce § 1er sera rétabli dans sa version initiale le premier jour de l’année 
scolaire 2026-2027 de la manière suivante et la numérotation sera adaptée en 
conséquence : 
Complété par D. 30-06-2016 ; remplacé par D. 19-10-2017 
(*)§ 1er. Par dérogation, dans le champ de la priorisation des porteurs de 
titres requis sur les porteurs de titres suffisants, un porteur de titre suffisant, 
temporaire non prioritaire, peut être à nouveau désigné ou engagé, l''année scolaire 
en cours ou l''année scolaire suivante, dans la(les) même(s) fonction(s) à la 
condition suivante : avoir exercé cette(ces) fonction(s), à prestations complètes ou 
incomplètes comportant au moins le tiers des heures requises pour l''exercice d''une 
fonction à prestations complètes pour l''enseignement de plein exercice et en 
alternance, durant 150 jours au cours de l''année scolaire précédente calculé selon 
les modalités reprises à l''article 19, § 2.  
 
Concernant l''[enseignement pour adultes de niveau secondaire], le seuil de 
prestations repris ci-dessus est fixé à concurrence de 120 périodes 
 
§ renuméroté par D. 17-07-2020 
§ 2. Par dérogation à la règle de la priorisation des porteurs de titres de 
pénurie sur les porteurs de tout autre titre, un porteur d''un titre de la 
catégorie inférieur au titre de pénurie, temporaire non prioritaire, peut être à 
nouveau désigné ou engagé, l''année scolaire en cours ou l''année scolaire 
suivante, dans la(les) même(s) fonction(s) à la condition suivante : avoir 
exercé cette(ces) fonction(s) durant 150 jours au cours de l''année scolaire 
2015-2016 et sans interruption depuis l''année scolaire 2015-2016 de plus 
d''une année scolaire, à concurrence d''une fonction à prestations complètes ou 
incomplètes comportant au moins le tiers des heures requises pour l''exercice 
d''une fonction à prestations complètes pour l''enseignement de plein exercice 
et en alternance. Les 150 jours sont calculés selon les modalités reprises à 
l''article 19, § 2. 
 
 
8Inséré par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année scolaire 
2026-2027. 
 
 
Docu 40701 
 
D. 11-04-2014  
Concernant l''[enseignement pour adultes de niveau secondaire], le seuil 
de prestations repris ci-dessus est fixé à concurrence de 120 périodes. 
 
§ renuméroté par D. 17-07-2020 
§ 3. Par dérogation à la règle de priorisation, un membre du personnel 
dont le titre a fait l''objet d''une décision de déclassement prise par le 
Gouvernement, temporaire non prioritaire, peut être à nouveau désigné ou 
engagé, l''année scolaire en cours ou l''année scolaire suivante, dans la(les) 
même(s) fonction(s) à la condition suivante : avoir exercé cette(ces) fonction(s) 
durant 150 jours au cours de l''année scolaire précédente, à concurrence d''une 
fonction à prestations complètes ou incomplètes comportant au moins le tiers 
des heures requises pour l''exercice d''une fonction à prestations complètes 
pour l''enseignement de plein exercice et en alternance. Les 150 jours sont 
calculés selon les modalités reprises à l''article 19, § 2. 
 
Concernant l''[enseignement pour adultes de niveau secondaire], le seuil 
de prestations repris ci-dessus est fixé à concurrence de 120 périodes. 
 
§ renuméroté par D. 17-07-2020 
§ 4. L''exercice des dérogations visées aux paragraphes 1 à [3]9 ne peut 
porter préjudice à un membre du personnel mieux titré pour cette (une de 
ces) fonction(s), candidat pour cette fonction ou une de ces fonction(s) au sein 
du Pouvoir organisateur, dans les mêmes conditions d''ancienneté mais 
acquises au cours des trois dernières années scolaires. 
 
Remplacé par D. 19-10-2017 ; modifié par D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 41, 'Article 33. - § 1er. [Par dérogation, un membre du personnel, porteur', 'Article 33. - § 1er. [Par dérogation, un membre du personnel, porteur 
d''un titre requis ou suffisant et nommé ou engagé à titre définitif, exerçant 
ou ayant exercé une ou plusieurs fonctions enseignantes à prestations 
incomplètes formant au total au moins le tiers du nombre d''heures requis 
pour l''exercice d''une fonction à prestations complètes durant l''année scolaire 
précédente ou en cours, peut voir sa charge étendue, dans l''enseignement 
spécialisé de forme 4, dans une ou plusieurs fonction(s) pour la(les)quelle(s) il 
possède un titre de pénurie. Cette extension est limitée à maximum le quart 
du nombre d''heures requis pour une fonction à prestation complète.] 10 
 
(*) Ce § 1er ci-dessous sera rétabli dans sa version initiale le premier jour 
de l’année scolaire 2026-2027 de la manière suivante et la numérotation sera 
adaptée en conséquence : 
Remplacé par D. 19-10-2017 
(*) Article 33. - § 1er. Par dérogation, un membre du personnel, porteur 
d''un titre requis ou suffisant et nommé ou engagé à titre définitif, exerçant 
ou ayant exercé une ou plusieurs fonctions enseignantes à prestations 
incomplètes formant au total au moins le tiers du nombre d''heures requis 
pour l''exercice d''une fonction à prestations complètes durant l''année scolaire 
précédente ou en cours, peut voir sa charge étendue dans une ou plusieurs 
fonction(s) pour la(les)quelle(s) il possède un titre suffisant. 
 
Cette dérogation s''applique également au bénéfice d''un membre du 
personnel, porteur d''un titre requis ou suffisant et nommé ou engagé à titre 
 
9Remplacé par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année 
scolaire 2026-2027. 
10Remplacé par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année 
scolaire 2026-2027. 
 
 
Docu 40701 
 
D. 11-04-2014  
définitif, exerçant une ou plusieurs fonctions enseignantes à prestations 
incomplètes dans l''[enseignement pour adultes de niveau secondaire] 
comportant au total 120 périodes. 
 
Dans l''enseignement spécialisé de forme 4, la charge peut en outre être 
étendue, aux conditions fixées à l''alinéa 1er, dans une fonction pour laquelle il 
possède un titre de pénurie. Cette extension est limitée à maximum le quart 
du nombre d''heures requis pour une fonction à prestation complète. 
 
§ 2. Les dispositions reprises au § 1er du présent article s''appliquent 
également au membre du personnel, porteur d''un titre requis ou suffisant et 
désigné ou engagé comme temporaire prioritaire en vue d''une extension de sa 
charge dans une ou plusieurs fonction(s) pour la(les)quelle(s) il possède un 
titre de pénurie dans le cas de l''enseignement spécialisé de forme 4, à 
condition d''avoir exercé l''année scolaire précédente ou durant l''année scolaire 
en cours la(les) fonction(s) pour laquelle(lesquelles) il possède un titre requis 
ou suffisant durant le nombre de jours et à concurrence du volume de charge 
repris à l''article 32. 
 
§ 3. Les dispositions reprises au § 2 s''appliquent au membre du 
personnel, porteur d''un titre requis ou suffisant ou de pénurie et désigné ou 
engagé à titre temporaire. Lorsqu''il s''agit de membres du personnel désignés 
ou engagés sur base d''un titre suffisant ou de pénurie, ils doivent être 
porteurs d''un titre pédagogique et avoir été engagés dans le cadre de 
l''application de l''article 29 ou 29bis. 
 
§ 4. L''exercice des dérogations visées aux paragraphes 1 à 3 ne peut 
porter préjudice à un membre du personnel mieux titré pour cette(une de ces) 
fonction(s), candidat pour cette fonction ou une de ces fonction(s) au sein du 
Pouvoir organisateur, dans les mêmes conditions d''ancienneté mais acquises 
au cours des trois dernières années scolaires. 
 
Modifié par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 42, 'Article 34. – […]11 / Article 34. - Pour satisfaire à l''application de l''article 16quater du', 'Article 34. – […]11  
 
Cette abrogation cessera de produire ses effets le premier jour de l’année 
scolaire 2026-2027 et sera rétablie dans sa version initiale. A savoir :

Article 34. - Pour satisfaire à l''application de l''article 16quater du 
décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de 
plein exercice et de l''article 13bis du décret du 13 juillet 1998 portant 
organisation de l''enseignement maternel et primaire ordinaire et modifiant la 
réglementation de l''enseignement et de l''article 12bis du décret du 30 juin 
2006 relatif à l''organisation pédagogique du 1er degré de l''enseignement 
secondaire, une dérogation aux règles de priorisation reprise à l''article 26 
peut être octroyée en faveur d''un porteur de titre suffisant dans l''organisation 
des classes bilingues français - langues des signes à la condition de démontrer 
que le recours à ce titre suffisant est le seul moyen permettant de respecter la 
norme fixée en faveur des personnes de culture sourde. 
 
Inséré par D. 19-10-2017 
 
11Abrogé par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année 
scolaire 2026-2027. 
 
 
Docu 40701 
 
D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 43, 'Article 34bis. - Les autorités disposant du pouvoir de recrutement', 'Article 34bis. - Les autorités disposant du pouvoir de recrutement 
peuvent justifier le non-respect des règles de priorisation au profit d''un 
candidat à une fonction dont le titre de capacité comporte une composante 
expérience utile et qui dispose pour cette fonction de l''attestation de retard 
visée à l''article 23, § 1er, alinéa 6. 
 
Cette possibilité ne peut être utilisée que pour un engagement prenant 
cours durant la période de validité de l''attestation. Toutefois, les membres du 
personnel de l''[enseignement pour adultes] engagés sur la base de cette 
possibilité dans une unité d''enseignement qui se termine au-delà de cette 
période peuvent terminer cette unité d''enseignement. 
 
Cette possibilité ne peut porter préjudice à un membre du personnel 
mieux titré, candidat à cette fonction au sein de son Pouvoir organisateur. 
 
Intitulé modifié par D. 07-02-2019 
Sous-section IV. - Disposition dérogatoire aux règles de priorisation 
touchant certaines fonctions s''exerçant dans l''enseignement 
spécialisé et dans l’enseignement ordinaire 
 
Modifié par D. 07-02-2019 ; D. 25-04-2019 ; D. 17-07-2020 ; D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 44, 'Article 35. - Un membre du personnel exerçant sa fonction dans', 'Article 35. - Un membre du personnel exerçant sa fonction dans 
l''enseignement spécialisé des types 6 et 7 ou dans l''enseignement spécialisé 
organisé en application des articles 8bis et 8ter du décret du 3 mars 2004 
organisant l''enseignement spécialisé ou au sein de l''équipe pluridisciplinaire 
d''un pôle territorial constituée sur base de l''article [6.2.6-7]12 du Code de 
l''enseignement fondamental et de l''enseignement secondaire et dans 
l''enseignement ordinaire en application du décret du 7 février 2019 visant à 
l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent 
pas la langue de l''enseignement dans l''enseignement organisé ou 
subventionné par la Communauté française qui est porteur pour sa fonction 
d''un titre de capacité autre que requis [ou suffisant]13 peut être désigné ou 
engagé à titre temporaire par dérogation aux règles de priorisation reprises à 
l''article 26 à la condition de posséder une des compétences particulières 
retenues pour l''exercice effectif de sa fonction dans ce cadre. 
 
Ces compétences particulières sont certifiées ou attestées par un 
organisme de formation reconnu par le Gouvernement ou par une attestation 
visant l''expérience du membre du personnel dans la mise en oeuvre de 
dispositifs d''intégration et/ou d''aménagements raisonnables [ou dans les 
Dispositifs d’Accueil et de Scolarisation des élèves Primo-Arrivants et 
Assimilés ou les dispositifs d’accompagnement en Français langue 
d’apprentissage]14, établie par l''employeur auprès duquel elle a été acquise. 
 
Dans l’enseignement spécialisé, les compétences particulières retenues 
sont arrêtées par le Gouvernement sur proposition conjointe des Conseils 
généraux visés à l''article 5, 44° et 45°, du décret du 24 juillet 1997 
définissant les missions prioritaires de l''enseignement fondamental et de 
l''enseignement secondaire et organisant les structures propres à les 
atteindre. 
 
12 Remplacé par le décret du 6 juillet 2023 
13Inséré par le D. 17-07-2020 et cesse de produire ses effets le premier jour de l’année 
scolaire 2026-2027. 
14 Inséré par le décret du 6 juillet 2023 
 
 
Docu 40701 
 
D. 11-04-2014  
Inséré par D. 07-02-2019 
Dans l''enseignement ordinaire en application du décret du 7 février 
2019 visant à l''accueil, la scolarisation et l''accompagnement des élèves qui ne 
maîtrisent pas la langue de l''enseignement dans l''enseignement organisé ou 
subventionné par la Communauté française, les compétences particulières 
sont arrêtées par le Gouvernement sur proposition du Conseil général de 
l''enseignement fondamental visé par le décret du 14 mars 1995 relatif à la 
promotion d''une école de la réussite dans l''enseignement fondamental ou sur 
proposition du Conseil général de concertation prévu au décret du 27 octobre 
1994 organisant la concertation pour l''enseignement secondaire. 
 
Intitulé modifié par D. 11-07-2018 
Section V. - Dispositions statutaires complémentaires liées à 
l''exercice des fonctions de recrutement visées à l''article 1er, alinéa 3 
 
Modifié par D. 11-07-2018 ; D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 45, 'Article 36. - § 1er. Pour faire valoir ses droits statutaires à la priorité à', 'Article 36. - § 1er. Pour faire valoir ses droits statutaires à la priorité à 
la désignation ou à l''engagement à titre temporaire dans le subventionné ou 
être désigné en qualité de temporaire prioritaire ou protégé dans 
l''enseignement organisé par la Communauté française, le titulaire d''une 
fonction de recrutement visées à l''article 1er, alinéa 3 doit être porteur d''un 
titre de capacité requis ou suffisant comportant, en outre, pour les fonctions 
enseignantes, la composante «compétence pédagogique» répondant au 
prescrit de l''article 17 tenant compte du ou des niveau(x) dans le(s)quel(s) la 
fonction est exercée. 
 
§ 2. De même, la nomination ou l''engagement à titre définitif prévu par 
les statuts administratifs au bénéfice des titulaires de fonctions de 
recrutement visées à l''article 1er, alinéa 3 porteurs d''un titre de capacité 
requis ou suffisant est soumis en outre, pour les fonctions enseignantes, à la 
nécessité de posséder l''un des titres pédagogiques repris à l''article 17 tenant 
compte du ou des niveau(x) dans le(s)quel(s) la fonction est exercée. 
 
Inséré par D. 17-07-2020 
§ 3. Par dérogation aux § 1er et § 2, peut faire valoir ses droits 
statutaires à la priorité à la désignation ou à l''engagement à titre 
temporaire, ou à la nomination ou l''engagement à titre définitif, le titulaire 
d''une fonction de recrutement visée à l''article 1er, alinéa 3, porteur d''un autre 
titre qui : 
1° possède, pour les fonctions enseignantes, un titre pédagogique 
répondant au prescrit de l''article 17 tenant compte du ou des niveau(x) dans 
le(s)quel(s) la fonction est exercée et de l''expérience utile du métier lorsque 
cette dernière est constitutive du titre de capacité suffisant ou requis; 
2° a cumulé 600 jours d''ancienneté dans la fonction dans l''enseignement 
organisé et officiel subventionné ou 720 jours d''ancienneté dans la fonction 
dans l''enseignement libre subventionné, répartis sur au moins 4 années 
consécutives au sein d''un même Pouvoir organisateur et calculés selon les 
modalités propres à chaque statut. 
 
Inséré par D. 17-07-2020 
§ 4. Dans les fonctions pour lesquelles le Gouvernement n''a fixé que des 
titres de capacité requis, un pouvoir organisateur ne peut pas recruter le 
porteur d''un autre titre. 
 
Modifié par D. 11-07-2018 ; D. 14-03-2019 ; D. 17-07-2020 
 
 
Docu 40701 
 
D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 46, 'Article 37. - § 1er. […]15', 'Article 37. - § 1er. […]15 
 
Remplacé par D. 11-07-2018 
§ 2. Les titulaires de fonctions de recrutement des catégories visées à 
l''article 1er, alinéa 3, 2° à 5°, porteurs d''un titre de capacité de pénurie listé 
par le Gouvernement, bénéficient à leur demande de tous les droits attachés 
à la possession d''un titre de capacité suffisant à condition d''avoir acquis, en 
qualité de titre de pénurie listé, le cas échéant, auprès d''établissements 
scolaires de différents réseaux d''enseignement, de l''enseignement organisé 
par la Communauté française ou de pouvoirs organisateurs non affiliés à un 
organe de représentation et de coordination, d''une ancienneté de fonction de 
minimum 450 jours accomplis sur minimum 3 années scolaires au cours de 4 
années scolaires consécutives et calculés selon les modalités reprises à 
l''article 19, § 2. 
 
Pour les titulaires d''une fonction de recrutement de la catégorie visée à 
l''article 1er, alinéa 3, 1°, à la condition visée à l''alinéa précédent s''ajoute la 
condition cumulative d''acquisition d''un des titres pédagogiques visés à 
l''article 17 pour ceux qui en seraient dépourvus et de l''expérience utile du 
métier lorsque cette dernière est constitutive du titre de capacité suffisant ou 
requis. 
 
Inséré par D. 14-03-2019 
§ 2bis. […] Abrogé par D. 17-07-2020 
 
Remplacé par D. 14-03-2019 
§ 3. Les anciennetés de fonction visées au présent article doivent faire 
l''objet d''une validation administrative via un état de service transmis par le 
pouvoir organisateur auprès duquel la demande visée au § 2 est introduite. 
 
CHAPITRE V. - De la Commission interréseaux des titres de capacité 
 
Section Ire. - De la Commission');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 47, 'Article 38. - Il est créé une Commission interréseaux des titres de', 'Article 38. - Il est créé une Commission interréseaux des titres de 
capacité, dénommée Commission. 
 
Section II. - Des missions 
 
Modifié par D. 30-06-2016 ; D. 19-10-2017 ; D. 14-03-2019 ; D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 48, 'Article 39. - La Commission a pour mission de suivre et de faciliter, (partie 1)', 'Article 39. - La Commission a pour mission de suivre et de faciliter, pour chacun des réseaux d''enseignement, l''enseignement organisé par la Communauté française et les pouvoirs organisateurs non affiliés à un organe de représentation et de coordination, la mise en place concertée de la réforme des titres et des fonctions au sein du périmètre défini à l''article 1er. Elle est en charge, plus particulièrement : 1° de mettre le Gouvernement en mesure d''assurer l''adéquation permanente de la liste des fonctions avec l''offre de formation au sein des établissements scolaires; 2° d''évaluer le processus d''accroche cours/fonction et de formuler, à l''attention du Gouvernement, des avis et des propositions portant notamment sur la suppression d''accroches non utilisées. Dans ce cadre également, la 15Abrogé par le décret du 18 janvier 2024 Docu 40701 D. 11-04-2014 Commission proposera au Gouvernement, en vue d''une entrée en vigueur au 1er septembre 2016, des accroches cours/fonction communes à tous les réseaux d''enseignement, l''enseignement organisé par la Communauté française et les pouvoirs organisateurs non affiliés à un organe de représentation et de coordination pour les cours relevant de la formation commune de l''enseignement secondaire, et, en vue d''une entrée en vigueur au 1er septembre 2017, les accroches cours/fonctions communes à tous les réseaux d''enseignement, l''enseignement organisé par la Communauté française et les pouvoirs organisateurs non affiliés à un organe de représentation et de coordination pour l''[enseignement pour adultes] et pour les cours de l''enseignement secondaire ne relevant pas de la formation commune. A défaut d''une proposition de la Commission permettant une entrée en vigueur des accroches cours/fonction aux dates prévues ci-avant, le Gouvernement est habilité à postposer d''un an la date d''entrée en vigueur des accroches cours-fonction communes à tous les réseaux d''enseignement, l''enseignement organisé par la Communauté française et les pouvoirs organisateurs non affiliés à un organe de représentation et de coordination; 3° de proposer au Gouvernement toutes modifications utiles à la fixation des titres de capacité requis, suffisant ou de pénurie notamment par la prise en compte des titres, diplômes, brevets ou certificats visés émis en Communauté française ou par l''intégration ou le reclassement de titres; 4° […] Abrogé par D. 17-07-2020 5° de remettre un avis portant sur des diplômes délivrés par les autres communautés belges dont l''intitulé ne présente pas de correspondance immédiate avec ceux délivrés par la Communauté française pour l''exercice d''une fonction tant dans l''enseignement fondamental et secondaire que dans l''enseignement supérieur; [complété par D. 19-10-2017] 6° d''émettre des avis portant sur l''offre de formations pédagogiques entrant en ligne de compte dans les titres de capacité afin d''offrir un regard objectif permettant de maintenir les moyens en adéquation avec les besoins tenant compte des articles 36 et 37; 7° sans préjudice de l''application de l''article 48 de proposer le cadre réglementaire destiné à prendre les décisions de valorisation de l''expérience utile du métier ou de l''enseignement, de répondre à la saisine des Commissions de gestion des emplois afin d''émettre des avis urgents sur l''élargissement de la reconnaissance d''expérience utile d''un membre du personnel placé en disponibilité ou en perte partielle de charge ainsi qu''émettre les attestations visées à l''article 19, § 3. Lorsqu''il s''agit de la valorisation de l''expérience utile du métier, cela concerne tant l''expérience utile constitutive de certains titres de capacité que l''expérience utile valorisable dans l''ancienneté pécuniaire conformément à l''article 17 de l''arrêté royal du 15 avril 1958 portant statut pécuniaire du personnel enseignant, scientifique et assimilé du Ministère de l''Instruction publique ; [complété par D. 14-03-2019] 8° de remettre annuellement une proposition réglementaire concernant la pénurie dans certaines fonctions selon les critères repris à l''article 4 du décret du 12 mai 2004 relatif à la définition de la pénurie et à certaines Commissions dans l''enseignement organisé ou subventionné par la Communauté française. Dans sa proposition, la commission distingue les fonctions en pénurie sévère par zone [complété par D. 14-03-2019] 9° de rassembler et d''analyser les données visant à assurer au Gouvernement et aux acteurs de l''enseignement une vision claire des fonctions, des titres de capacité et de ses composantes notamment par niveau, région, bassins de vie, zones, catégories de personnels, fonctions en pénurie, pyramides des âges, attractivité des fonctions en regard des potentiels en ressources humaines; Docu 40701 D. 11-04-2014 10° d''examiner toute situation résiduelle portant sur l''application des mesures transitoires reprises au présent décret ainsi que de soumettre toute mesure concrète de modifications légales ou réglementaires visant à l''intégration harmonieuse de la ré');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 49, 'Article 39. - La Commission a pour mission de suivre et de faciliter, (partie 2)', 'avec le cadre législatif et de remettre au Gouvernement un avis portant sur les mesures transitoires adéquates visant à protéger les droits acquis des membres du personnel concerné en cas de modification des grilles horaires et/ou des accroches cours-fonctions. [10° complété par D. 30-06-2016] Docu 40701 D. 11-04-2014 Section III. - Des moyens logistiques');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 50, 'Article 40. - Pour remplir ses missions, la Commission :', 'Article 40. - Pour remplir ses missions, la Commission : 
1° dispose d''un secrétariat dont la composition est fixée par le 
Gouvernement. Celui-ci est établi au sein de l''administration et placé sous 
l''autorité du président de la Commission; 
2° dispose de la base de données constituée conformément à l''article 28. 
Cette base de données est placée sous la responsabilité du Président de la 
Commission. 
Le Gouvernement, sur proposition du Président de la Commission, 
désigne au sein des services du Gouvernement les personnes habilitées à 
collaborer à la mise en oeuvre et à l''exploitation de cette base de données. Il 
détermine, sur proposition de la Commission, les informations qui peuvent 
être collectées et enregistrées, l''usage qui peut être fait de celles-ci et 
restreint toute publication à des ensembles agrégés ne permettant en aucun 
cas d''identifier les personnes physiques et morales ou les établissements 
d''enseignement sur lesquels portent les informations; 
3° se base, notamment, sur les travaux des chambres visées aux articles 
48 et 49. A ce titre, elle coordonne les travaux des chambres précitées et leur 
donne toutes les instructions et injonctions utiles à la bonne fin de leurs 
missions; 
4° est assistée, selon les modalités définies par le Gouvernement, par 
l''Administration 
générale 
des 
personnels 
de 
l''enseignement 
et 
l''Administration générale de l''enseignement et de la recherche scientifique et 
l''ensemble des entités relevant de leur autorité ainsi que par le Service 
général de l''Inspection et par tous les services relevant de la Communauté 
française et assurant une mission en rapport avec les compétences de la 
Commission. 
 
Section IV. - Composition et organisation');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 51, 'Article 41. - La présidence de la Commission est assurée par un / Article 42. - § 1er. La Commission est composée de 34 membres :', 'Article 41. - La présidence de la Commission est assurée par un 
fonctionnaire de rang 16 + d''une Administration générale du secteur de 
l''enseignement.

Article 42. - § 1er. La Commission est composée de 34 membres : 
1° le Directeur général des personnels de l''enseignement de la 
Communauté française ou son délégué; 
2° le Directeur général des personnels de l''enseignement subventionné 
par la Communauté française ou son délégué; 
3° le Directeur général de la Direction générale de l''Enseignement 
obligatoire et/ou le Directeur général de l''Enseignement non obligatoire et de 
la Recherche scientifique ou leur délégué respectif. En cas de vote, les deux 
Directeurs généraux s''expriment d''une seule voix; 
4° le Directeur général-adjoint du Service général de Coordination, de 
Conception et des Relations sociales ou son délégué; 
5° cinq membres représentant l''enseignement libre subventionné dont 
un représentant de l''enseignement libre non confessionnel; 
6° quatre membres représentant l''enseignement organisé par la 
Communauté française; 
7° quatre membres représentant l''enseignement officiel subventionné; 
8° douze membres représentant les trois organisations syndicales 
représentatives à concurrence d''un nombre égal de mandats; 
9° quatre membres du service général d''inspection désignés par 
l''inspecteur général coordonnateur. 
 
 
Docu 40701 
 
D. 11-04-2014  
Les Directeurs généraux et le Directeur général adjoint visés aux points 
1 à 4 ou leurs délégués peuvent se faire assister par des techniciens relevant 
de leur direction générale. De même, les membres visés aux points 5 à 8 
peuvent se faire assister par des techniciens. 
 
§ 2. La vice-présidence de la Commission est assurée alternativement 
pour une période de deux ans par les composantes visées aux points 1° et 2° 
du § 1er. Le vice-président assure la présidence de la Commission en cas 
d''empêchement du Président. 
 
§ 3. En fonction de l''ordre du jour, les organismes et organisations 
syndicales visés aux points 5° à 8° du § 1er composent leur délégation, parmi 
la liste des membres désignés par le gouvernement conformément à l''article 
43.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 52, 'Article 43. - Pour', 'Article 43. - Pour 
permettre 
aux 
organismes 
et 
organisations 
syndicales représentatives visées aux points 5° à 8° d''adapter leur délégation 
à l''ordre du jour, le Gouvernement désigne pour chacun un nombre maximal 
de personnes égal au double des membres prévus pour cette délégation. 
 
Pour permettre la désignation de ces membres, chacun des organismes, 
organisations syndicales représentatives et administrations concernés 
soumet au Gouvernement une liste comportant au maximum deux fois plus 
de candidats que de membres prévus. 
 
Les membres sont désignés pour un terme de quatre ans renouvelable. 
 
Le membre qui cesse d''exercer son mandat avant l''expiration de celui-ci 
est remplacé, pour la période qui reste à couvrir, par la personne désignée 
par le Gouvernement sur base de la liste double proposée par l''organisme, 
l''organisation syndicale représentative ou l''administration concerné à la suite 
de la fin anticipée du mandat.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 53, 'Article 44. - La Commission, selon des modalités reprises au règlement', 'Article 44. - La Commission, selon des modalités reprises au règlement 
d''ordre intérieur, peut constituer des groupes de travail et faire appel à des 
experts. Ces derniers n''ont pas voix délibérative.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 54, 'Article 45. - La Commission est soumise au pouvoir de contrôle d''un', 'Article 45. - La Commission est soumise au pouvoir de contrôle d''un 
délégué du Gouvernement désigné pour la durée d''une législature par le ou 
les ministres ayant l''enseignement obligatoire et l''[enseignement pour 
adultes] dans ses attributions. 
 
Le délégué du Gouvernement assiste avec voix consultative aux 
réunions de la Commission et peut obtenir communication de tout document 
utile à sa mission. 
 
Le délégué du Gouvernement dispose d''un délai de quatre jours 
ouvrables pour introduire un recours motivé contre toute décision de la 
Commission qu''il estime contraire à la législation, aux procédures 
administratives en vigueur, aux dispositions du présent décret ou à l''intérêt 
général. Le recours est suspensif. 
 
Le délai de quatre jours court à partir du jour où la décision de la 
Commission a été prise, sauf si le délégué n''a pas été régulièrement convoqué 
 
 
Docu 40701 
 
D. 11-04-2014  
conformément au règlement intérieur de la Commission, auquel cas le délai 
court à partir du jour où la décision lui a été notifiée. 
 
Le délégué exerce son recours auprès du ou des membres du 
gouvernement 
qu''il 
représente 
selon 
des 
modalités 
fixées 
par 
le 
Gouvernement dans son ordre de mission. 
 
Le Gouvernement peut annuler la décision de la Commission dans un 
délai de trente jours commençant le même jour que le délai prévu au 
troisième alinéa. 
 
La décision d''annulation est notifiée à la Commission.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 55, 'Article 46. - § 1er. Dans l''exercice des missions reprises aux points 3° et', 'Article 46. - § 1er. Dans l''exercice des missions reprises aux points 3° et 
6° de l''article 39, l''ARES est associée aux travaux de la Commission et 
dispose d''une voix délibérative. L''ARES veille à la représentation de chacune 
des composantes suivantes : 
1° les Universités; 
2° les Hautes Ecoles; 
3° les Ecoles supérieures des Arts; 
4° l''[enseignement pour adultes de niveau supérieur]. 
 
Chacune des composantes de ce collège peut être accompagnée d''un 
expert de l''enseignement dont il émane. 
 
§ 2. En cas d''avis divergents entre les composantes de l''ARES, chaque 
composante est habilitée à formuler, individuellement ou collégialement, tout 
avis sur les points de l''ordre du jour de la Commission qui concerne les 
missions reprises au § 1er. Ces avis seront joints au dossier transmis au 
Gouvernement en vue de la prise de décision.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 56, 'Article 47. - § 1er. La Commission décide sur la base du consensus et à', 'Article 47. - § 1er. La Commission décide sur la base du consensus et à 
défaut à la majorité des deux tiers des voix émises. Tout avis comprend, le 
cas échéant, la mention des votes et s''il échoit, une note de minorité. 
 
Lors de la prise d''un avis visé aux articles 7 et 16 du présent décret et 
en cas de vote, la majorité des deux tiers doit contenir une majorité absolue 
au sein de la composante réunissant les points 5° à 7 de l''article 42, § 1er, la 
composante figurant au 8° de l''article 42, § 1er, ainsi qu''au sein de la 
composante réunissant les points 1°, 2°, 3°, 4° et 9° de l''article 42, § 1er. 
 
La Commission arrête son règlement d''ordre intérieur et le soumet à 
l''approbation du Gouvernement. 
 
Le président de la Commission ne prend pas part au vote. 
 
§ 2. Chaque organisation reprise aux Comités visés à l''article 2, § 2, 1°, 
2° et 3°, du décret du 19 mai 2004 relatif à la négociation en Communauté 
française dispose d''une voix délibérative. 
 
De même, chaque organisation représentée au comité de négociation 
créé par l''article 5 du décret du 20 juillet 2006 relatif à la négociation avec les 
organes de représentation et de coordination des pouvoirs organisateurs de 
l''enseignement et des centres PMS subventionnés dispose d''une voix 
délibérative. Les membres de la Commission visés à l''article 42, § 1er, point 
6°, disposent ensemble d''une voix délibérative. 
 
 
Docu 40701 
 
D. 11-04-2014  
Les services du Gouvernement repris à l''article 42, § 1er, points 1°, 2°, 
3°, 4° et 9°, disposent chacune d''une voix délibérative. 
 
§ 3. Aucun avis ni proposition ne peuvent être validés sans la 
constatation de la présence effective de la majorité des organisations visées 
au § 2, alinéa 1er, et de la majorité des organisations visées au § 2, alinéa 2. 
 
Le président acte la présence de ce quorum en début de séance de la 
Commission. 
 
A défaut de quorum, le Président convoque une nouvelle réunion dans 
un délai de 15 jours. Lors de cette réunion, la Commission décide 
valablement même si le quorum prévu à l''alinéa 1er n''est pas atteint. 
 
Modifié par D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 57, 'Article 48. - § 1er. La Commission constitue, en vue de l''exercice des', 'Article 48. - § 1er. La Commission constitue, en vue de l''exercice des 
missions reprises à l''article 39, point 7°, une chambre décisionnelle placée 
sous la présidence d''un agent choisi parmi les fonctionnaires de rang 10 dont 
la voix est prépondérante en cas d''égalité des voix. 
 
§ 2. Cette chambre décisionnelle est composée d''au maximum deux 
représentants effectifs de chaque organisme, organisation syndicale 
représentative ou administration repris à l''article 42, § 1er. 
 
Chaque 
organisme, 
organisation 
syndicale 
représentative 
ou 
administration désigne un membre suppléant ne siégeant qu''en absence d''un 
membre effectif. 
 
§ 3. Les règles de fonctionnement, de prise de décision ainsi que le 
règlement d''ordre intérieur de la chambre décisionnelle sont proposés à 
l''approbation du Gouvernement par la Commission.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 58, 'Article 49. - § 1er. La Commission constitue, en vue de l''exercice de la', 'Article 49. - § 1er. La Commission constitue, en vue de l''exercice de la 
mission reprise à l''article 39, 10°, une chambre placée sous la présidence d''un 
agent choisi parmi les fonctionnaires de rang 10 dont la voix est 
prépondérante en cas d''égalité des voix. 
 
§ 2. Cette chambre est composée d''un représentant effectif de chaque 
organisme, organisation syndicale représentative ou administration repris à 
l''article 41, § 1er. 
 
Chaque 
organisme, 
organisation 
syndicale 
représentative 
ou 
administration désigne un membre suppléant ne siégeant qu''en absence du 
membre effectif. 
 
§ 3. Les règles de fonctionnement, de remise d''avis, de délégation ainsi 
que le règlement d''ordre intérieur de cette chambre sont proposées à 
l''approbation de la Commission. 
 
CHAPITRE VI. - Des échelles barémiques 
 
Modifié par D. 07-02-2019 ; D. 17-07-2020 ; D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 59, 'Article 50. - § 1er. Pour les fonctions enseignantes de l''enseignement (partie 1)', 'Article 50. - § 1er. Pour les fonctions enseignantes de l''enseignement fondamental et secondaire de l''enseignement de plein exercice et en Docu 40701 D. 11-04-2014 alternance, ordinaire et spécialisé du degré inférieur ainsi que de l''[enseignement pour adultes de niveau secondaire] du degré inférieur et sans préjudice, là où il s''applique, de l''arrêté du Gouvernement de la Communauté française du 14 mai 2009 portant revalorisation de certains membres du personnel de l''enseignement porteurs d''un master en application du protocole d''accord du 20 juin 2008, trois échelles barémiques de référence sont fixées par le Gouvernement au porteur d''un titre de capacité requis selon qu''il : 1° 1° par dérogation au 2°, possède une composante disciplinaire acquise dans le cadre d''un «master en Enseignement section 1, 2 ou 3» délivré dans le cadre du décret du 7 février 2019 définissant la formation initiale des enseignants ; [inséré par D. 07-02-2019] 2° possède une composante disciplinaire de niveau master ou bachelier; 3° possède une composante disciplinaire du niveau secondaire supérieur ou la qualité d''homme de métier. Ces échelles sont désignées par un indice qui mentionne le traitement minimum, le traitement maximum, ainsi que le nombre et le montant des augmentations périodiques, annales et biennales. Le porteur d''un titre de capacité suffisant, disposant des mêmes composantes disciplinaires, bénéficiera d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale de l''échelle de référence applicable. Le porteur d''un titre de capacité de pénurie, disposant des mêmes composantes disciplinaires, et le porteur d''un titre de capacité autre, tel que visé à l''article 16, § 6 du présent décret bénéficieront d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale et d''une biennale de l''échelle de référence applicable. § 2. Pour les fonctions enseignantes de l''enseignement secondaire ordinaire et spécialisé du degré supérieur de plein exercice et en alternance, ainsi que de l''[enseignement pour adultes de niveau secondaire] du degré supérieur, une échelle barémique de référence est fixée par le Gouvernement au porteur d''un titre de capacité requis selon qu''il : 1° possède une composante disciplinaire de niveau master; 2° possède une composante disciplinaire de niveau bachelier; 3° possède une composante disciplinaire du niveau secondaire supérieur ou la qualité d''homme de métier. Ces échelles sont désignées par un indice qui mentionne le traitement minimum, le traitement maximum, ainsi que le nombre et le montant des augmentations périodiques, annales et biennales. Le porteur d''un titre de capacité suffisant, disposant des mêmes composantes disciplinaires, bénéficiera d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale de l''échelle de référence applicable. Le porteur d''un titre de capacité de pénurie, disposant des mêmes composantes disciplinaires, et le porteur d''un titre de capacité autre, tel que visé à l''article 16, § 6 du présent décret bénéficieront d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale et d''une biennale de l''échelle de référence applicable. Docu 40701 D. 11-04-2014 § 3. Les dispositions du § 2 sont applicables à la fonction enseignante unique au sens de l''article 5, alinéa 5, ainsi qu''aux fonctions enseignantes d''accompagnateur CEFA, de coordinateur qualité et de conseiller à la formation. § 4. Pour les fonctions de la catégorie du personnel auxiliaire d''éducation visées à l''article 3, § 2 et § 7, une échelle de référence est fixée par le Gouvernement au porteur d''un titre de capacité requis pour les fonctions d''éducateur, de secrétaire-bibliothécaire et d''éducateur-secrétaire et une échelle de référence est fixée par le Gouvernement au porteur d''un titre de capacité requis pour les fonctions d''éducateur d''internat filles et d''éducateur d''internat garçons selon qu''il : 1° possède une composante disciplinaire de niveau master ou bachelier; 2° possède une composante disciplinaire du niveau secondaire supérieur. Ces échelles sont désignées par un indice qui mentionne le traitement minimum, le traitement maximum, ainsi que le nombre et le montant des augmentations périodiques, annales et biennales. Le porteur d''un titre de capacité suffisant, disposant des mêmes composantes disciplinaires, bénéficiera d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale de l''échelle de référence applicable. Le porteur d''un titre de capacité de pénurie, disposant de la composante disciplinaire reprise sous 1°, bénéficiera d''une échelle barémique correspondant à l''échelle de référence de sa fonction diminuée du montant d''une annale et d''une biennale. Le porteur d''un titre de capacité de pénurie, disposant de la composante disciplinaire reprise sous 2°, et le porteur d''un titre de capacité autre, tel que visé à l''a');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 60, 'Article 50. - § 1er. Pour les fonctions enseignantes de l''enseignement (partie 2)', '16, § 6, du présent décret disposant de la composante disciplinaire reprise sous 1° ou 2°, bénéficieront d''une échelle barémique correspondant à l''échelle de référence de sa fonction diminuée du montant d''une biennale. § 5. Pour les fonctions d''assistant social, d''infirmier et de puéricultrice, les dispositions du § 4, telles qu''applicables aux fonctions d''éducateur, de secrétaire-bibliothécaire et d''éducateur-secrétaire, sont d''application. § 6. Pour les fonctions de la catégorie du personnel paramédical, autres que celles visées au § 5 ainsi que pour la fonction de la catégorie du personnel psychologique, une échelle barémique de référence est fixée par le Gouvernement au porteur d''un titre de capacité requis selon qu''il : 1° possède une composante disciplinaire de niveau master; 2° possède une composante disciplinaire de niveau bachelier. Ces échelles sont désignées par un indice qui mentionne le traitement minimum, le traitement maximum, ainsi que le nombre et le montant des augmentations périodiques, annales et biennales. Le porteur d''un titre de capacité suffisant, lorsqu''il existe, disposant des mêmes composantes disciplinaires, bénéficiera d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale de l''échelle de référence applicable. Docu 40701 D. 11-04-2014 Le porteur d''un titre de capacité de pénurie, lorsqu''il existe, disposant des mêmes composantes disciplinaires, bénéficiera d''une échelle barémique correspondant aux échelles de référence diminuées du montant d''une annale et d''une biennale de l''échelle de référence applicable. TITRE II. - Dispositions modificatives propres aux réseaux d''enseignement et à l''enseignement organisé par la Communauté française CHAPITRE Ier. - Dispositions modificatives propres à l''enseignement organisé par la Communauté française Section Ire. - Modifications de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécialisé, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 61, 'Article 51. - L''article 3, alinéa 1er, de l''arrêté royal du 22 mars 1969', 'Article 51. - L''article 3, alinéa 1er, de l''arrêté royal du 22 mars 1969 
fixant le statut des membres du personnel directeur et enseignant, du 
personnel 
auxiliaire 
d''éducation, 
du 
personnel 
paramédical 
des 
établissements 
d''enseignement 
gardien, 
primaire, 
spécialisé, 
moyen, 
technique, artistique et normal de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé 
de la surveillance de ces établissements, modifié en dernier lieu par le décret 
du 28 février 2013 portant des dispositions statutaires en matière 
d''enseignement organisé par la Communauté française, est remplacé par ce 
qui suit : 
«Dans l''enseignement supérieur de promotion sociale l''expérience utile 
est constituée par le temps passé, soit dans un service ou un établissement 
public ou privé, soit dans l''enseignement, soit dans un métier ou une 
profession. Le Ministre décide si l''expérience utile contribue à assurer la 
formation requise pour la fonction à conférer.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 62, 'Article 52. - A l''article 18 du même arrêté, les modifications suivantes', 'Article 52. - A l''article 18 du même arrêté, les modifications suivantes 
sont apportées : 
1° au point 5, les mots «être porteur d''un titre fixé par le Gouvernement 
en rapport avec la fonction à conférer sont remplacés par les mots «être 
porteur dans l''enseignement de plein exercice et en alternance et dans 
l''enseignement secondaire de promotion sociale d''un titre requis fixé par le 
Gouvernement en vertu de l''article 7 du décret du 11 avril 2014 en rapport 
avec la fonction à conférer»; 
2° est inséré un point 5bis rédigé comme suit : 
«5bis. Etre porteur dans l''enseignement supérieur de promotion sociale 
d''un titre requis fixé par le Gouvernement en rapport avec la fonction à 
conférer;»; 
3° au point 9, les mots «dans l''enseignement supérieur de promotion 
sociale» sont insérés entre les mots «l''objet» et les mots «d''une suspension par 
mesure disciplinaire»; 
4° est inséré un point 10 rédigé comme suit : 
 
 
Docu 40701 
 
D. 11-04-2014  
«10. ne pas faire l''objet dans l''enseignement de plein exercice, dans 
l''enseignement en alternance et dans l''enseignement secondaire de 
promotion sociale d''une suspension par mesure disciplinaire, d''une 
suspension disciplinaire, d''une mise en disponibilité par mesure disciplinaire, 
d''une mise en non-activité disciplinaire, d''une démission disciplinaire ou 
d''une révocation infligée par le pouvoir organisateur ou par tout autre 
pouvoir organisateur d''un autre réseau.»; 
5° est inséré un point 11 rédigé comme suit : 
«11. Dans l''enseignement de plein exercice, dans l''enseignement en 
alternance et dans l''enseignement secondaire de promotion sociale ne pas 
faire l''objet, au sein de l''enseignement organisé par la Communauté 
française, d''un licenciement moyennant préavis ou pour faute grave.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 63, 'Article 53. - A 1 ''article 19 du même arrêté, les modifications suivantes', 'Article 53. - A 1 ''article 19 du même arrêté, les modifications suivantes 
sont apportées : 
1° l''alinéa 2 est remplacé par ce qui suit : «Pour l''application de l''alinéa 
1er, dans l''enseignement supérieur de promotion sociale, sont désignées par 
priorité les personnes classées dans le premier groupe visé à l''article 2bis de 
l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont 
classés les candidats à une désignation à titre temporaire dans 
l''enseignement de l''Etat.»; 
2° un nouvel alinéa 3, rédigé comme suit est inséré : «Pour l''application 
de l''alinéa 1er, dans l''enseignement de plein exercice, dans l''enseignement en 
alternance et dans l''enseignement secondaire de promotion sociale, sont 
désignées par priorité les personnes classées à l''article 2, § 1er alinéas 2 et 3 
de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont 
classés les candidats à une désignation à titre temporaire dans 
l''enseignement de l''Etat.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 64, 'Article 54. - A l''article 20 du même arrêté, les modifications suivantes (partie 1)', 'Article 54. - A l''article 20 du même arrêté, les modifications suivantes sont apportées : 1° l''alinéa 1er est remplacé par un paragraphe 1er rédigé comme suit : «§ 1er. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale par dérogation à l''article 18, le Ministre peut, faute de candidats remplissant la condition visée à l''article 18, 5, désigner, à titre temporaire, un candidat qui est porteur du titre de capacité relevant de la catégorie des titres suffisants fixés pour la fonction à conférer. Par titres suffisants il y a lieu d''entendre les titres suffisants tels que définis par le Gouvernement en vertu de l''article 17 du décret du 11 avril 2014.»; 2° est inséré un paragraphe 2 rédigé comme suit : «§ 2.Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale après épuisement de la liste des candidats à une désignation à titre temporaire porteurs du titre de capacité relevant de la catégorie des titres requis et de la catégorie des titres suffisants fixés pour la fonction à conférer, le Ministre peut désigner à titre temporaire, un candidat porteur d''un titre de capacité relevant de la catégorie des titres de pénurie tels qu''énumérés par le Gouvernement en vertu de l''article 7 du décret du 11 avril 2014.». 3° est inséré un paragraphe 3 rédigé comme suit : «§ 3. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale après épuisement de la liste des candidats à une désignation à titre temporaire porteurs du titre de capacité relevant de la catégorie des titres requis, de la Docu 40701 D. 11-04-2014 catégorie des titres suffisants et de la catégorie des titres de pénurie, le Ministre peut désigner à titre temporaire, après avis de la Commission inter réseaux des titres de capacité (Commission) visée à l''article 16, § 6 du décret du 11 avril 2014 un candidat porteur d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie.»; 4° les alinéas 2, 3 et 4 sont remplacés par les paragraphes 4 et 5 rédigés comme suit : «§ 4. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale le candidat porteur du titre de capacité relevant de la catégorie des titres suffisants qui a fait l''objet dans la même fonction de deux rapports défavorables du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé, ne peut être désigné par le Ministre à partir de l''année scolaire suivante, par dérogation à l''article 18. Le candidat porteur du titre de capacité relevant de la catégorie des titres de pénurie qui a fait l''objet dans la même fonction de deux rapports défavorables du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé, ne peut être désigné par le Ministre à partir de l''année scolaire suivante, par dérogation à l''article 18. Pour l''application des deux alinéas précédents, un rapport défavorable couvrant une période de moins de trente jours n''est pas pris en compte s''il est suivi d''un rapport favorable dans la fonction considérée couvrant une période d''au moins 180 jours. Si le candidat porteur d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie a déjà bénéficié, au cours d''une année scolaire, d''une ou de plusieurs désignations effectuées sur base du paragraphe 3, le Ministre ne peut le désigner l''année scolaire suivante, par dérogation à l''article 18, que si, le candidat n''a pas fait l''objet d''un rapport défavorable du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé. Toutefois, un rapport défavorable couvrant une période de moins de trente jours n''est pas pris en compte. Toute désignation faite sur base des §§ 1er à 3 ci-avant est effectuée pour une période déterminée avec pour limite extrême la fin de l''année scolaire au cours de laquelle débute cette période. § 5. Dans l''enseignement supérieur de promotion sociale, par dérogation à l''article 18, le Ministre peut, faute de candidats remplissant la condition visée à l''article 18, 5, désigner, à titre temporaire, un candidat qui n''est pas porteur du titre fixé pour la fonction à conférer. Toutefois, si le candidat a déjà bénéficié, au cours d''une année scolaire, d''une ou de plusieurs désignations effectuées sur base de l''alinéa qui précède, le Ministre ne peut le désigner, par dérogation à l''article 18, pour la totalité ou une partie de l''année scolaire qui suit celle au cours de laquelle ont eu lieu ces désignations, que si, au cours de celle-ci, le candidat n''a pas fait l''objet d''un rapport défavorable du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé. Si le candidat a bénéficié durant deux années scolaires au moins de désignations faites par dérogation à l''article 18, le Ministre ne peut le désigner par après dans la même fonction par dérogation au d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 65, 'Article 54. - A l''article 20 du même arrêté, les modifications suivantes (partie 2)', 'article, que Docu 40701 D. 11-04-2014 si, au cours de celles-ci, le candidat n''a pas fait l''objet d''un rapport défavorable du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé pendant ces années scolaires.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 66, 'Article 55. - A l''article 26bis du même arrêté, les modifications (partie 1)', 'Article 55. - A l''article 26bis du même arrêté, les modifications suivantes sont apportées : 1° au § 1er, alinéa 1er, les mots «dans une fonction considérée» sont remplacés par les mots «dans la fonction ou une autre fonction figurant dans l''accroche cours/fonction telle que définie par le Gouvernement en vertu de l''article 10 du décret du 11 avril 2014,»; 2° le § 1er, 1°, est remplacé par un 1° rédigé comme suit : «1° les temporaires porteurs d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie visés à l''article 2, § 4, de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat, dans l''ordre inverse des priorités;»; 3° le § 1er, 1° bis, est remplacé par un 1° bis rédigé comme suit : «1° bis les temporaires classés dans le troisième groupe visé à l''article 2, § 3, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement;»; 4° au § 1er est inséré un 1° ter rédigé comme suit : «1° ter les temporaires classés dans le deuxième groupe visé à l''article 2, § 3, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement;»; 5° au § 1er est inséré un 1° quater rédigé comme suit : «1° quater les temporaires classés dans le premier groupe visé à l''article 2, § 3, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement;»; 6° le § 1er, 2°, est remplacé par un 2° rédigé comme suit : «2° les temporaires classés dans le troisième groupe visé à l''article 2, § 2, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement;»; 7° au § 1er est inséré un 2° bis rédigé comme suit : «2° bis les temporaires classés dans le deuxième groupe visé à l''article 2, § 2, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement;»; 8° au § 1er est inséré un 2° ter rédigé comme suit : «2° ter les temporaires classés dans le premier groupe visé à l''article 2, § 2, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement;»; 9° au § 1er est inséré un 2° quater rédigé comme suit : «2° quater les temporaires classés dans le troisième groupe visé à l''article 2, § 1er, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement;». 10° au § 1er est inséré un 2° quinquies rédigé comme suit : «2° quinquies les temporaires classés dans le deuxième groupe visé à l''article 2, § 1er, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement;»; 11° le § 1er, 3°, est remplacé par un 3° rédigé comme suit : «3° les temporaires classés dans le premier groupe visé à l''article 2, § 1er, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement;»; 12° au § 2 est inséré un alinéa 2 rédigé comme suit : «Par dérogation dans l''enseignement spécialisé, l''alinéa précédant ne s''applique pas si le membre du personnel désigné à titre temporaire qui occupe les emplois vacants peut justifier d''une compétence particulière telle que définie par l''article 35, alinéas 2 et 3, du décret 11 avril 2014.»; 13° au § 2 est inséré un alinéa 4 rédigé comme suit : «Par dérogation dans l''enseignement spécialisé, l''alinéa précédant ne s''applique pas si le membre du personnel désigné à titre temporaire qui occupe les emplois vacants peut justifier d''une compétence particulière telle que définie par l''article 35, alinéas 2 et 3, du décret 11 avril 2014.»; 14° le dernier alinéa est remplacé par un alinéa rédigé comme suit : Docu 40701 D. 11-04-2014 «Pour l''application des alinéas 1er et 3, il est d''abord mis fin, au sein de la zone où le rappel à l''activité ou le complément de charge est effectué, aux prestations des temporaires titulaires d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie, puis dans l''ordre inverse du classement, des temporaires classés dans le troisième groupe visé à l''article 2, § 3, alinéa 4, de l''arrêté royal du 22 juillet 1969 précité, puis des temporaires classés dans le deuxième groupe visé à l''article 2, § 3, alinéa 3, du même arrêté royal puis, des temporaires classés dans le premier groupe visé à l''article 2, § 3, alinéa 2, puis dans l''ordre verse du classement des temporaires classés dans le troisième groupe visé à l''article 2, § 2, alinéa 4, du même arrêté royal puis, dans l''ordre inverse du classement, des temporaires classés dans le deuxième groupe visé à l''article 2, § 2, alinéa 3, et enfin dans l''ordre inverse du classement, des temporaires classés dans le premier groupe visé à l''article 2, § 2, alinéa 2, du même arrêté royal, puis dans l''ordre inverse des temporaires classés dans le troisième groupe visé à l''article 2, § 1er, alinéa 4, du même arrêté royal puis, dans l''ordre inverse du classement, des temporaires classés dans le deuxième groupe visé à l''article 2, § 1er, alinéa 3, et, enfin, dans l''ordre inverse du classement, des temporaires classés dans le premier groupe visé à l''article 2, § 1er, alinéa 2, du même arrêté royal. Toutefois, si l''emploi totalement ou partiellement libéré par le temporaire le moins bien');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 67, 'Article 55. - A l''article 26bis du même arrêté, les modifications (partie 2)', 'classé entraîne pour les membres du personnel visés aux alinéas 1er et 2 qui en bénéficient un déplacement de plus de quatre heures par jour par les transports en commun, ceux-ci peuvent refuser ce rappel à l''activité ou ce complément de charge. Dans ce cas, il est mis fin, totalement ou partiellement, aux prestations d''abord d''un autre temporaire titulaire d''un autre titre qu''un titre de capacité requis, ou suffisant ou de pénurie, puis d''un autre temporaire classé dans le troisième groupe visé à l''article 2, § 3, alinéa 4, de l''arrêté royal du 22 juillet 1969 précité, puis des temporaires classés dans le deuxième groupe visé à l''article 2, § 3, alinéa 3, du même arrêté royal puis, des temporaires classés dans le premier groupe visé à l''article 2, § 3 alinéa 2, puis des temporaires classés dans le troisième groupe visé à l''article 2, § 2, alinéa 4, du même arrêté royal puis, des temporaires classés dans le deuxième groupe visé à l''article 2, § 2, alinéa 3, puis, des temporaires classés dans le premier groupe visé à l''article 2, § 2, alinéa 2, du même arrêté royal, puis des temporaires classés dans le troisième groupe visé à l''article 2, § 1er, alinéa 4, du même arrêté et à défaut, du temporaire porteur du titre de capacité relevant de la catégorie des titres requis immédiatement mieux classé.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 68, 'Article 56. - L''article 26ter du même arrêté est modifié comme suit : (partie 1)', 'Article 56. - L''article 26ter du même arrêté est modifié comme suit : 1° au § 1er le mot «supérieur» est inséré entre les mots «enseignement» et les mots «de promotion sociale»; 2° le § 1er, 1°, est remplacé par un 1° rédigé comme suit : «1° les temporaires classés dans le quatrième groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat;»; 3° le § 1er, 2°, est remplacé par un point 2° rédigé comme suit : «2° les temporaires classés dans le troisième groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat;»; 4° le § 1er, 3°, du même arrêté est remplacé par un 3° rédigé comme suit : «3° les temporaires classés dans le deuxième groupe visé à l''article 2bis du même arrêté, dans l''ordre inverse du classement;»; Docu 40701 D. 11-04-2014 5° au § 1er est inséré un point 3bis rédigé comme suit : «3° bis les temporaires classés dans le premier groupe visé à l''article 2bis du même arrêté, dans l''ordre inverse du classement;»; 6° un paragraphe 1erbis rédigé comme suit est inséré : «§ 1erbis. Dans l''enseignement secondaire de promotion sociale, au sein d''un établissement, en cas de diminution des prestations disponibles dans la fonction ou une autre fonction figurant dans l''accroche cours/fonction telle que définie par le Gouvernement, il est mis fin, totalement ou partiellement, aux prestations d''un membre du personnel selon l''ordre suivant : 1° les temporaires titulaires d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie visés à l''article 2, § 4, de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat, dans l''ordre inverse des priorités; 1°bis les temporaires classés dans le troisième groupe visé à l''article 2, § 3, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement; 1°ter. Les temporaires classés dans le deuxième groupe visé à l''article 2, § 3, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement; 1°quater les temporaires classés dans le premier groupe visé à l''article 2, § 3, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement; 2° les temporaires classés dans le troisième groupe visé à l''article 2, § 2, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement; 2°bis les temporaires classés dans le deuxième groupe visé à l''article 2, § 2, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement; 3° les temporaires classés dans le premier groupe visé à l''article 2, § 2, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement; 3°bis les temporaires classés dans le troisième groupe visé à l''article 2, § 1er, alinéa 4, du même arrêté royal, dans l''ordre inverse du classement; 3°ter les temporaires classés dans le deuxième groupe visé à l''article 2, § 1er, alinéa 3, du même arrêté royal, dans l''ordre inverse du classement; 3°quater Les temporaires classés dans le premier groupe visé à l''article 2, § 1er, alinéa 2, du même arrêté royal, dans l''ordre inverse du classement; 4° les temporaires protégés, dans l''ordre inverse de leur classement en tant que temporaire; 5° les membres du personnel nommés à titre définitif pour les prestations qui leur sont confiées à titre de complément de charge; 6° les membres du personnel rappelés provisoirement à l''activité de service dans la fonction à laquelle ils sont nommés; 7° les membres du personnel rappelés à l''activité de service pour une durée indéterminée dans la fonction à laquelle ils sont nommés; 8° les membres du personnel nommés à titre définitif dans la fonction qu''ils exercent au sein de l''établissement.»; 7° le § 2, alinéa 2, est remplacé par un alinéa 2 rédigé comme suit : «Pour l''application de l''alinéa 1er, dans l''enseignement supérieur de promotion sociale, il est d''abord mis fin, au sein de la zone où le rappel à l''activité ou le complément de charge est effectué, aux prestations des temporaires classés dans le quatrième groupe visé à l''article 2 bis, alinéa 5 de l''arrêté royal du 22 juillet 1969 précité, puis dans l''ordre inverse du classement des temporaires classés dans le troisième groupe visé à l''article 2 bis, alinéa 4 de l''arrêté royal du 22 juillet 1969 précité, puis des temporaires classés dans le deuxième groupe visé à l''article 2bis, alinéa 3 du même arrêté enfin, dans l''ordre inverse du classement, des temporaires classés dans le premier groupe visé à l''article 2bis, alinéa 2 du même arrêté.»; 8° le § 2, alinéa 3, est remplacé par un alinéa 3 rédigé comme suit : «Pour l''application de l''alinéa 1er, dans l''enseignement secondaire de promotion sociale, il est d''abord mis fin, au sein de la zone où le rappel à Docu 40701 D. 11-04-2014 l''activité ou le complément de charg');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 69, 'Article 56. - L''article 26ter du même arrêté est modifié comme suit : (partie 2)', 'est effectué, aux prestations des temporaire, puis dans l''ordre inverse du classement, des temporaires classés dans le troisième groupe visé à l''article 2, § 3, alinéa 4, de l''arrêté royal du 22 juillet 1969 précité, puis des temporaires classés dans le deuxième groupe visé à l''article 2, § 3, alinéa 3, du même arrêté royal puis, des temporaires classés dans le premier groupe visé à l''article 2, § 3 alinéa 2, puis dans l''ordre verse du classement des temporaires classés dans le troisième groupe visé à l''article 2, § 2, alinéa 4, du même arrêté royal puis, dans l''ordre inverse du classement, des temporaires classés dans le deuxième groupe visé à l''article 2, § 2, alinéa 3, et, enfin, dans l''ordre inverse du classement, des temporaires classés dans le premier groupe visé à l''article 2, § 2, alinéa 2, du même arrêté royal, puis dans l''ordre inverse des temporaires classés dans le troisième groupe visé à l''article 2, § 1er, alinéa 4, du même arrêté royal puis, dans l''ordre inverse du classement, des temporaires classés dans le deuxième groupe visé à l''article 2, § 1er, alinéa 3, et enfin dans l''ordre inverse du classement, des temporaires classés dans le premier groupe visé à l''article 2, § 1er, alinéa 2, du même arrêté royal.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 70, 'Article 57. - A l''article 26quater du même arrêté, les modifications', 'Article 57. - A l''article 26quater du même arrêté, les modifications 
suivantes sont apportées : 
1° au § 1er, premier alinéa les mots «une même fonction» sont remplacés 
par les mots «la fonction ou une autre fonction figurant dans l''accroche 
cours/fonction telle que définie par le Gouvernement»; 
2° le § 1er, 13°, est remplacé par un 13° rédigé comme suit : 
«13° les temporaires classés dans le premier groupe visé à l''article 
2, § 1er, alinéa 2 de l''arrêté royal du 22 juillet 1969 fixant les règles d''après 
lesquelles sont classés les candidats à une désignation à titre temporaire 
dans l''enseignement de l''Etat, dans l''ordre du classement;»; 
3° au § 1er est inséré un 13° bis rédigé comme suit : 
«13° bis les temporaires classés dans le deuxième groupe visé à l''article 
2, § 1er, alinéa 3, du même arrêté royal;»; 
4° au § 1er est inséré un 13° ter rédigé comme suit : 
«13° ter les temporaires classés dans le troisième groupe visé à l''article 
2, § 1er, alinéa 4 du même arrêté royal, dans l''ordre du classement;»; 
5° le § 1er, 14°, est remplacé par un 14° rédigé comme suit : 
«14° Les temporaires classés dans le premier groupe visé à l''article 
2, § 2, alinéa 2 du même arrêté royal;»; 
6° le § 1er, 15°, est remplacé par un 15° rédigé comme suit : 
«15° Les temporaires classés dans le deuxième groupe visé à l''article 
2, § 2, alinéa 3 du même arrêté royal;»; 
7° le § 1er, 16°, est remplacé par un 16° rédigé comme suit : 
«16° les temporaires non titulaires d''un titre de capacité requis, ou 
suffisant ou de pénurie, dans l''ordre des priorités;»; 
8° Au § 2 les mots «dans une même fonction» sont remplacés par les 
mots «la fonction ou une autre fonction figurant dans l''accroche 
cours/fonction telle que définie par le Gouvernement en vertu de l''article 10 
du décret du 11 avril 2014».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 71, 'Article 58. - A l''article 31 du même arrêté les modifications suivantes', 'Article 58. - A l''article 31 du même arrêté les modifications suivantes 
sont apportées : 
1° le 5° est remplacé par un 5° rédigé comme suit : 
«5° être porteur d''un titre requis fixé par le Gouvernement en rapport 
avec la fonction à conférer ou avoir fait l''objet de dérogations prévues à 
l''article 20 pendant au moins 150 jours de service dans la fonction pour le 
temporaire porteur du titre de capacité relevant de la catégorie des titres 
suffisants et pendant au moins 300 jours de service dans la fonction répartis 
 
 
Docu 40701 
 
D. 11-04-2014  
sur 2 années scolaires au moins pour le temporaire porteur d''un titre de 
capacité relevant de la catégorie des titres de pénurie;»; 
2° un 5° bis rédigé comme suit est inséré : 
«5° bis être porteur d''un titre pédagogique tel que défini par le 
Gouvernent;»; 
3° au point 12° les mots «d''une démission disciplinaire ou d''une 
révocation» sont insérés entre les mots «mise en non-activité disciplinaire» et 
les mots «infligée par un pouvoir organisateur»; 
4° un 13° rédigé comme suit est inséré : 
«13° ne pas faire l''objet, au sein de l''enseignement organisé par la 
Communauté française, d''un licenciement moyennant préavis ou pour faute 
grave;».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 72, 'Article 59. - A l''article 31ter du même arrêté les modifications', 'Article 59. - A l''article 31ter du même arrêté les modifications 
suivantes sont apportées : 
1° au 5° les mots «dans l''enseignement supérieur de promotion sociale» 
sont insérés entre les mots «être porteur» et «d''un titre fixé»; 
2° un 5° bis rédigé comme suit est inséré : 
«5° bis être porteur dans l''enseignement secondaire de promotion sociale 
d''un titre requis fixé par le Gouvernement en rapport avec la fonction à 
conférer ou avoir fait l''objet de dérogations successives prévues à l''article 20 
pendant au moins 150 jours de service dans la fonction pour le temporaire 
porteur du titre de capacité relevant de la catégorie des titres suffisants et 
pendant au moins 300 jours de service dans la fonction répartis sur 2 années 
scolaires au moins pour le temporaire porteur d''un titre de capacité relevant 
de la catégorie des titres de pénurie;»; 
3° un 5° ter rédigé comme suit est inséré : 
«5° ter dans l''enseignement secondaire de promotion sociale, être 
porteur d''un titre pédagogique tel que défini par le Gouvernement;»; 
4° le 10° est remplacé par un 10° rédigé comme suit : 
«10° ne pas faire l''objet dans l''enseignement supérieur de promotion 
sociale d''une suspension par mesure disciplinaire, d''une suspension 
disciplinaire, d''une mise en disponibilité par mesure disciplinaire, d''une mise 
en non-activité disciplinaire, infligée par le pouvoir organisateur ou par tout 
autre pouvoir organisateur d''un autre réseau.»; 
5° le 11° est remplacé par un 11° rédigé comme suit : 
«11° ne pas faire l''objet dans l''enseignement secondaire de promotion 
sociale d''une suspension par mesure disciplinaire, d''une suspension 
disciplinaire, d''une mise en disponibilité par mesure disciplinaire, d''une mise 
en non-activité disciplinaire, d''une démission disciplinaire ou d''une 
révocation infligée par le pouvoir organisateur ou par tout autre pouvoir 
organisateur d''un autre réseau.»; 
6° un 12° rédigé somme suit est inséré : 
«12° dans l''enseignement secondaire de promotion sociale ne pas faire 
l''objet, au sein de l''enseignement organisé par la Communauté française, 
d''un licenciement moyennant préavis ou pour faute grave;».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 73, 'Article 60. - L''article 44ter, alinéa 2, du même arrêté est remplacé par', 'Article 60. - L''article 44ter, alinéa 2, du même arrêté est remplacé par 
un alinéa 2 rédigé comme suit : 
«Après épuisement de la liste visée à l''alinéa 1er, le ministre offre 
l''emploi au membre du personnel qui a déjà été engagé dans un emploi de 
même nature dans la même fonction pour laquelle il détient le titre de 
capacité relevant de la catégorie des titres requis ou des titres suffisants et 
qui compte dans cette fonction plus de 600 jours d''ancienneté. Pour les 
fonctions enseignantes, le titre de capacité relevant de la catégorie des titres 
suffisants doit être complété par un titre pédagogique.». 
 
 
Docu 40701 
 
D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 74, 'Article 61. - A l''article 51ter du même arrêté les modifications', 'Article 61. - A l''article 51ter du même arrêté les modifications 
suivantes sont apportées : 
1° le § 1er est remplacé par un § 1er rédigé comme suit : 
«§ 1er. Dans l''enseignement de plein exercice, dans l''enseignement en 
alternance et dans l''enseignement secondaire de promotion sociale le membre 
du personnel victime d''un acte de violence bénéficie du dispositif défini à la 
section 2 s''il est temporaire titulaire d''un autre titre que d''un titre de 
capacité requis, ou suffisant ou de pénurie, à la section 3 s''il est temporaire 
porteur d''un titre de capacité relevant de la catégorie des titres de pénurie, à 
la section 4 s''il est temporaire porteur d''un titre de capacité relevant de la 
catégorie des titres suffisants visés à l''article 2, § 2, de l''arrêté royal du 22 
juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à 
une désignation à titre temporaire dans l''enseignement de l''Etat, à la section 
5 s''il est temporaire porteur d''un titre de capacité relevant de la catégorie des 
titres requis visés à l''article 2, § 1er, de l''arrêté royal du 22 juillet 1969 
précité, à la section 6 s''il est temporaire prioritaire et à la section 7 s''il est 
nommé à titre définitif.»; 
2° un paragraphe 1erbis rédigé comme suit est inséré :  
«§ 1erbis. Dans l''enseignement supérieur de promotion sociale, le 
membre du personnel victime d''un acte de violence bénéficie du dispositif 
défini à la section 2bis s''il est temporaire classé dans le quatrième groupe, à 
la section 3bis s''il est temporaire classé dans le troisième groupe visé à 
l''article 2 bis de l''arrêté royal du 22 juillet 1969 fixant les règles d''après 
lesquelles sont classés les candidats à une désignation à titre temporaire 
dans l''enseignement de l''Etat, à la section 4bis s''il est temporaire classé dans 
le deuxième groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 
précité, à la section 5bis s''il est temporaire classé dans le premier groupe, à 
la section 6bis s''il est temporaire protégé et à la section 7bis s''il est nommé à 
titre définitif.»; 
3° au § 2, les modifications suivantes sont apportées : 
a) à l''alinéa 1er, les mots «au § 1er» sont remplacés par les mots «§§ 1er et 
1er bis»; 
b) à l''alinéa 1er, les mots «section 2 à 5» sont remplacés par les mots 
«section 2 à 7bis».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 75, 'Article 62. - L''intitulé de la section 2 du chapitre IIIbis du même arrêté', 'Article 62. - L''intitulé de la section 2 du chapitre IIIbis du même arrêté 
est modifié comme suit : 
 
«Section 2. - Du droit à une nouvelle désignation des temporaires 
titulaires d''un autre titre que d''un titre de capacité requis, ou 
suffisant ou de pénurie».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 76, 'Article 63. - A l''article 51 quater du même arrêté les modifications', 'Article 63. - A l''article 51 quater du même arrêté les modifications 
suivantes sont apportées : 
 
1° le § 1er, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 1er. Dans l''enseignement de plein exercice, dans l''enseignement en 
alternance et dans l''enseignement secondaire de promotion sociale le membre 
du personnel temporaire titulaire d''un autre titre que d''un titre de capacité 
requis, ou suffisant ou de pénurie victime d''un acte de violence peut solliciter 
sa désignation dans un autre établissement dans le respect des conditions 
visées à la section première.»; 
 
 
 
Docu 40701 
 
D. 11-04-2014  
2° au § 2, alinéa 1er, les mots «non classé» sont remplacés par les mots 
«titulaire d''un titre autre titre que d''un titre de capacité requis, ou suffisant 
ou de pénurie»; 
3° au § 2, a), les mots «candidat classé» sont remplacés par les mots 
«candidat titulaire d''un autre titre que d''un titre de capacité requis, suffisant 
ou de pénurie»; 
4° le § 3, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 3. A défaut d''avoir pu offrir au membre du personnel titulaire d''un 
autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie visé à 
la présente section une nouvelle désignation conformément au § 2, le 
ministre fonctionnel le désigne dans tout emploi de la même fonction déjà 
occupé par un membre du personnel temporaire titulaire d''un autre titre que 
d''un titre d''un titre de capacité requis, ou suffisant ou de pénurie à qui il 
impose de faire une permutation avec le membre du personnel victime d''un 
acte de violence. 
 
L''alinéa précédent ne vaut que pour les désignations qui interviennent 
avant le 15 mai de l''année scolaire en cours.»; 
5° le § 6 est abrogé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 77, 'Article 64. - L''intitulé de la section 3 du chapitre III bis du même', 'Article 64. - L''intitulé de la section 3 du chapitre III bis du même 
arrêté est modifié comme suit : 
 
«Section 2bis. - Du droit à une nouvelle désignation des temporaires 
classés dans le quatrième groupe».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 78, 'Article 65. - A l''article 51quinquies du même arrêté les modifications', 'Article 65. - A l''article 51quinquies du même arrêté les modifications 
suivantes sont apportées : 
1° le § 1er, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 1er. Dans l''enseignement supérieur de promotion sociale, le membre 
du personnel temporaire classé dans le quatrième groupe visé à l''article 2bis 
de l''arrêté royal du 22 juillet 1969 précité victime d''un acte de violence peut 
solliciter sa désignation dans un autre établissement dans le respect des 
conditions visées à la section première.»; 
2° au § 2, alinéa 1er, les mots «temporaire visé à la première section» 
sont remplacés par les mots «classé dans le quatrième groupe visé au présent 
article»; 
3° le § 3, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 3. A défaut d''avoir pu offrir au membre du personnel classé dans le 
quatrième groupe visé à la présente section une nouvelle désignation 
conformément au § 2, le ministre fonctionnel le désigne dans tout emploi de 
la même fonction déjà occupé par un membre du personnel temporaire classé 
dans le quatrième groupe à qui il impose de faire une permutation avec le 
membre du personnel victime d''un acte de violence.»; 
4° le § 6 est abrogé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 79, 'Article 66. - L''intitulé de la section 4 du chapitre IIIbis du même arrêté', 'Article 66. - L''intitulé de la section 4 du chapitre IIIbis du même arrêté 
est modifié comme suit : «Section 3 - Du droit à une nouvelle désignation des 
temporaires porteurs d''un titre de capacité relevant de la catégorie des titres 
de pénurie».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 80, 'Article 67. - A l''article 51sexies du même arrêté, les modifications', 'Article 67. - A l''article 51sexies du même arrêté, les modifications 
suivantes sont apportées : 
1° le § 1er, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
 
 
Docu 40701 
 
D. 11-04-2014  
«§ 1er. Dans l''enseignement de plein exercice, dans l''enseignement en 
alternance et dans l''enseignement secondaire de promotion sociale, le 
membre du personnel temporaire porteur d''un titre de capacité relevant de la 
catégorie des titres pénurie victime d''un acte de violence peut solliciter sa 
désignation dans un autre établissement dans le respect des conditions visées 
à la section première.» 
2° le § 2, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 2. Le ministre fonctionnel désigne le membre du personnel porteur du 
titre de capacité relevant de la catégorie des titres de pénurie visé au présent 
article,»; 
3° le § 2, a), est remplacé par un point a) rédigé comme suit : 
«a) dans tout emploi disponible de la même fonction pour lequel il n''y a 
pas de candidat porteur d''un titre relevant de la catégorie des titres 
suffisants et de la catégorie des titres requis»; 
4° le § 3, alinéa 1er, est remplacé par un alinéa 1er rédigé comme suit : 
«§ 3. A défaut d''avoir pu offrir au membre du personnel porteur d''un 
titre de capacité relevant de la catégorie des titres de pénurie visé à la 
présente section une nouvelle désignation conformément au § 2, le ministre 
fonctionnel le désigne dans tout emploi de la même fonction déjà occupé par 
un membre du personnel temporaire porteur d''un titre de capacité relevant 
de la catégorie des titres de pénurie à qui il impose de faire une permutation 
avec le membre du personnel victime d''un acte de violence.»; 
5° au § 6 les modifications suivantes sont apportées : 
a) l''alinéa premier est abrogé; 
b) à l''alinéa 2, le mot «classé» est supprimé et les mots «porteur d''un 
titre de capacité relevant de la catégorie des titres de pénurie» sont insérés 
entre les mots «le temporaire» et les mots «qui a introduit».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 81, 'Article 68. - L''intitulé de la section 5 du chapitre IIIbis du même arrêté', 'Article 68. - L''intitulé de la section 5 du chapitre IIIbis du même arrêté 
est modifié comme suit : 
 
«Section 3bis. - Du droit à une nouvelle désignation des temporaires 
classés dans le troisième groupe».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 82, 'Article 69. - L''article 51septies du même arrêté est remplacé par un', 'Article 69. - L''article 51septies du même arrêté est remplacé par un 
article 51septies rédigé comme suit : 
 
«Article 51septies. - § 1er. Dans l''enseignement supérieur de promotion 
sociale, le membre du personnel temporaire classé dans le troisième groupe 
visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 précité victime d''un 
acte de violence peut solliciter sa désignation dans un autre établissement 
dans le respect des conditions visées à la section première. 
 
La demande de nouvelle désignation n''est prise en considération que si 
la désignation initiale n''arrive pas à échéance avant l''écoulement d''un délai 
d''un mois à dater de l''introduction de la demande. 
 
La nouvelle désignation visée au présent article ne peut être d''une 
durée inférieure à la durée restant à courir dans le cadre de la désignation 
initiale, sauf accord du membre du personnel concerné. Toutefois, une 
désignation d''une durée inférieure à celle restant à courir dans le cadre de sa 
désignation initiale peut être imposée à la victime d''un acte de violence à 
condition que cet emploi soit disponible pour une durée de quinze semaines 
au moins et que le membre du personnel qui fait l''objet d''une telle 
 
 
Docu 40701 
 
D. 11-04-2014  
désignation ne perde aucun droit pour la période qui représente la différence 
entre cette désignation et la durée de la désignation initiale. 
 
§ 2. Le ministre fonctionnel désigne le membre du personnel classé dans 
le troisième groupe visé au présent article, 
a) dans tout emploi disponible de la même fonction pour lequel il n''y a 
pas de candidat classé dans le deuxième et le premier groupe ou 
b) dans tout emploi de la même fonction occupé par un membre du 
personnel temporaire qui accepte volontairement de permuter avec lui. 
 
Le littera b) ne vaut que pour les désignations qui interviennent avant 
le 15 mai de l''année scolaire en cours. 
 
§ 3. A défaut d''avoir pu offrir au membre du personnel classé dans le 
troisième groupe visé à la présente section une nouvelle désignation 
conformément au § 2, le ministre fonctionnel le désigne dans tout emploi de 
la même fonction déjà occupé par un membre du personnel temporaire classé 
dans le troisième groupe à qui il impose de faire une permutation avec le 
membre du personnel victime d''un acte de violence. 
 
L''alinéa précédent ne vaut que pour les désignations qui interviennent 
avant le 15 mai de l''année scolaire en cours. 
 
§ 4. Durant la période de congé rémunéré dont bénéficie le membre du 
personnel victime d''un acte de violence en incapacité de travail consécutive à 
cet acte, celui-ci est réputé rendre des services effectifs. Sa prise en compte 
dans l''ancienneté de service est toutefois limitée à la durée de la désignation 
initiale. 
 
§ 5. L''année scolaire qui suit celle au cours de laquelle il a été victime 
d''un acte de violence, le membre du personnel temporaire ne peut être à 
nouveau désigné dans l''établissement dans lequel il a été victime de cet acte, 
sauf accord de sa part et à condition qu''il ait été reconnu incapable de 
poursuivre sa (ses) fonction(s) dans l''établissement dans lequel il a été 
victime d''un acte de violence par le service externe de prévention et de 
protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services 
externes pour la prévention et la protection au travail.»');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 83, 'Article 70. - L''intitulé de la section 6 du chapitre III bis du même', 'Article 70. - L''intitulé de la section 6 du chapitre III bis du même 
arrêté est modifié comme suit : 
 
«Section 4. - Du droit à une nouvelle désignation des temporaires 
porteurs d''un titre de capacité relavant des titres suffisants visés à 
l''article 2, § 2, de l''arrêté royal du 22 juillet 1969 précité».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 84, 'Article 71. - L''article 51octies du même arrêté est remplacé par un (partie 1)', 'Article 71. - L''article 51octies du même arrêté est remplacé par un article 51octies rédigé comme suit : «Article 51octies. - § 1er. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale le membre du personnel temporaire porteur d''un titre de capacité relevant de la catégorie des titres suffisants visés à l''article 2, § 2, de l''arrêté royal du 22 juillet 1969 précité, victime d''un acte de violence, peut solliciter sa désignation dans un autre établissement dans le respect des conditions visées à la section première. Docu 40701 D. 11-04-2014 La demande de nouvelle désignation ne sera prise en considération que si la désignation initiale n''arrive pas à échéance avant l''écoulement d''un délai d''un mois à dater de l''introduction de la demande. La nouvelle désignation visée au présent article ne peut être d''une durée inférieure à la durée restant à courir dans le cadre de la désignation initiale, sauf accord du membre du personnel concerné. Toutefois, une désignation d''une durée inférieure à celle restant à courir dans le cadre de sa désignation initiale peut être imposée à la victime d''un acte de violence à condition que cet emploi soit disponible pour une durée de quinze semaines au moins et que le membre du personnel qui fait l''objet d''une telle désignation ne perde aucun droit pour la période qui représente la différence entre cette désignation et la durée de la désignation initiale. § 2. Le ministre fonctionnel désigne le membre du personnel temporaire visé à la présente section a) dans tout emploi disponible de la même fonction pour lequel il n''y a pas de candidat porteur d''un titre relevant de la catégorie des titres requis, appartenant à un établissement de la (des) zone(s) mentionnée(s) dans l''acte de candidature visé à l''article 23 en tenant compte des préférences exprimées quant à la zone ou b) dans l''emploi de la même fonction occupé par un membre du personnel temporaire qui accepte de permuter avec lui. Le littera b) ne vaut que pour les désignations qui interviennent avant le 15 mai de l''année scolaire en cours. § 3. A défaut d''avoir pu offrir au membre du personnel temporaire visé à la présente section une nouvelle désignation conformément au § 2, le ministre fonctionnel le désigne dans tout emploi de la même fonction déjà occupé par : 1° un membre du personnel temporaire non titulaire d''un titre de capacité requis, ou suffisant ou de pénurie à qui il impose de permuter avec le membre du personnel victime d''un acte de violence; 1°bis à défaut, à un membre du personnel temporaire porteur du titre de capacité relevant de la catégorie des titres de pénurie à qui il impose de permuter avec le membre du personnel victime d''un acte de violence; 2° à défaut, un membre du personnel temporaire porteur d''un titre de capacité relevant de la catégorie des titres suffisants visés à l''article 2, § 2, de l''arrêté royal du 22 juillet 1969 précité à qui il impose de permuter avec lui. L''alinéa précédent ne vaut que pour les désignations qui interviennent avant le 15 mai de l''année scolaire en cours. § 4. Durant la période de congé rémunéré dont bénéficie le membre du personnel victime d''un acte de violence en incapacité de travail consécutive à cet acte, celui-ci est réputé rendre des services effectifs. Sa prise en compte dans l''ancienneté de service est toutefois limitée à la durée de la désignation initiale. § 5. A condition que le membre du personnel temporaire ait été reconnu incapable de poursuivre sa (ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux Docu 40701 D. 11-04-2014 services externes pour la prévention et la protection au travail, il ne peut être à nouveau désigné dans l''établissement dans lequel il a été victime de cet acte l''année scolaire qui suit celle au cours de laquelle il a été victime d''un acte de violence, sauf accord de sa part. Néanmoins, cette demande n''est prise en considération que si elle parvient avant le 15 mai au ministre fonctionnel. § 6. Par dérogation à l''article 18, 8°, le temporaire porteur d''un titre de capacité relevant de la catégorie des titres suffisants qui a introduit une candidature valable pour une désignation en qualité de temporaire pour l''année scolaire suivante, peut modifier le choix de zones exprimé après le délai fixé dans l''appel aux candidats à condition qu''il ait été reconnu incapable de poursuivre sa (ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la prévention et la protection au travail. Par dérogation à l''article 31, 9°, le temporaire porteur d''un titre de capacité relevant de la catégorie des titres suffisants qui a introduit une candidature valable po');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 85, 'Article 71. - L''article 51octies du même arrêté est remplacé par un (partie 2)', 'une désignation en qualité de temporaire prioritaire pour l''année scolaire suivante, peut modifier le choix d''établissements exprimé après le délai fixé dans l''appel aux candidats à condition qu''il ait été reconnu incapable de poursuivre sa (ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la prévention et la protection au travail. Cette demande n''est néanmoins prise en considération que si elle parvient avant le 15 mai au ministre fonctionnel.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 86, 'Article 72. - Au chapitre IIIbis du même arrêté est insérée une section', 'Article 72. - Au chapitre IIIbis du même arrêté est insérée une section 
4bis dont l''intitulé est rédigé comme suit : 
 
«Section 4bis. - Du droit à une nouvelle désignation des temporaires 
classés dans le deuxième groupe visé à l''article 2bis de l''arrêté royal 
du 22 juillet 1969 précité».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 87, 'Article 73. - Dans la section 4bis du chapitre IIIbis du même arrêté est', 'Article 73. - Dans la section 4bis du chapitre IIIbis du même arrêté est 
inséré un article 51nonies rédigé comme suit : 
 
«Article 51nonies. - § 1er. Dans l''enseignement supérieur de promotion 
sociale, le membre du personnel temporaire classé dans le deuxième groupe 
visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 précité, victime d''un 
acte de violence, peut solliciter sa désignation dans un autre établissement 
dans le respect des conditions visées à la section première. 
 
La demande de nouvelle désignation ne sera prise en considération que 
si la désignation initiale n''arrive pas à échéance avant l''écoulement d''un 
délai d''un mois à dater de l''introduction de la demande. 
 
La nouvelle désignation visée au présent article ne peut être d''une 
durée inférieure à la durée restant à courir dans le cadre de la désignation 
initiale, sauf accord du membre du personnel concerné. Toutefois, une 
désignation d''une durée inférieure à celle restant à courir dans le cadre de sa 
désignation initiale peut être imposée à la victime d''un acte de violence à 
condition que cet emploi soit disponible pour une durée de quinze semaines 
 
 
Docu 40701 
 
D. 11-04-2014  
au moins et que le membre du personnel qui fait l''objet d''une telle 
désignation ne perde aucun droit pour la période qui représente la différence 
entre cette désignation et la durée de la désignation initiale. 
 
§ 2. Le ministre fonctionnel désigne le membre du personnel temporaire 
visé à la présente section 
a) dans tout emploi disponible de la même fonction, appartenant à un 
établissement de la (des) zone(s) mentionnée(s) dans l''acte de candidature 
visé à l''article 23 en tenant compte des préférences exprimées quant à la zone 
ou 
b) dans l''emploi de la même fonction occupé par un membre du 
personnel temporaire qui accepte de permuter avec lui. 
 
Le littera b) ne vaut que pour les désignations qui interviennent avant 
le 15 mai de l''année scolaire en cours. 
 
§ 3. A défaut d''avoir pu offrir au membre du personnel temporaire visé à 
la présente section une nouvelle désignation conformément au § 2, le 
ministre fonctionnel le désigne dans tout emploi de la même fonction déjà 
occupé par : 
1° un membre du personnel temporaire classé dans le quatrième groupe 
à qui il impose de permuter avec le membre du personnel victime d''un acte 
de violence; 
1°bis à défaut, un membre du personnel temporaire classé dans le 
troisième groupe visé à l''article 2 bis de l''arrêté royal du 22 juillet 1969 
précité à qui il impose de permuter avec lui; 
2° à défaut, un membre du personnel temporaire classé dans le 
deuxième groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 
précité à qui il impose de permuter avec lui. 
 
L''alinéa précédent ne vaut que pour les désignations qui interviennent 
avant le 15 mai de l''année scolaire en cours. 
 
§ 4. Durant la période de congé rémunéré dont bénéficie le membre du 
personnel victime d''un acte de violence en incapacité de travail consécutive à 
cet acte, celui-ci est réputé rendre des services effectifs. Sa prise en compte 
dans l''ancienneté de service est toutefois limitée à la durée de la désignation 
initiale. 
 
§ 5. A condition que le membre du personnel temporaire ait été reconnu 
incapable de poursuivre sa (ses) fonction(s) dans l''établissement dans lequel 
il a été victime d''un acte de violence par le service externe de prévention et 
de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux 
services externes pour la prévention et la protection au travail, il ne peut être 
à nouveau désigné dans l''établissement dans lequel il a été victime de cet 
acte l''année scolaire qui suit celle au cours de laquelle il a été victime d''un 
acte de violence, sauf accord de sa part. Néanmoins, cette demande n''est 
prise en considération que si elle parvient avant le 15 mai au ministre 
fonctionnel. 
 
§ 6. Par dérogation à l''article 18, 8°, le temporaire classé dans le 
deuxième groupe qui a introduit une candidature valable pour une 
désignation en qualité de temporaire pour l''année scolaire suivante, peut 
modifier le choix de zones exprimé après le délai fixé dans l''appel aux 
candidats à condition qu''il ait été reconnu incapable de poursuivre sa (ses) 
fonction(s) dans l''établissement dans lequel il a été victime d''un acte de 
 
 
Docu 40701 
 
D. 11-04-2014  
violence par le service externe de prévention et de protection au travail visé à 
l''arrêté royal du 27 mars 1998 relatif aux services externes pour la 
prévention et la protection au travail.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 88, 'Article 74. - Au chapitre IIIbis du même arrêté est insérée une section', 'Article 74. - Au chapitre IIIbis du même arrêté est insérée une section 
