INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 89, 'Article 75. - Est inséré dans la section 5 du chapitre IIIbis du même (partie 1)', 'Article 75. - Est inséré dans la section 5 du chapitre IIIbis du même arrêté un article 51decies rédigé comme suit : «Article 51decies. - § 1er. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale, le membre du personnel temporaire porteur d''un titre de capacité relevant de la catégorie des titres requis visés à l''article 2, § 1er, de l''arrêté royal du 22 juillet 1969 précité, victime d''un acte de violence, peut solliciter sa désignation dans un autre établissement dans le respect des conditions visées à la section première. La demande de nouvelle désignation ne sera prise en considération que si la désignation initiale n''arrive pas à échéance avant l''écoulement d''un délai d''un mois à dater de l''introduction de la demande. La nouvelle désignation visée au présent article ne peut être d''une durée inférieure à la durée restant à courir dans le cadre de la désignation initiale, sauf accord du membre du personnel concerné. Toutefois, une désignation d''une durée inférieure à celle restant à courir dans le cadre de sa désignation initiale peut être imposée à la victime d''un acte de violence à condition que cet emploi soit disponible pour une durée de quinze semaines au moins et que le membre du personnel qui fait l''objet d''une telle désignation ne perde aucun droit pour la période qui représente la différence entre cette désignation et la durée de la désignation initiale. § 2. Le ministre fonctionnel désigne le membre du personnel temporaire visé à la présente section a) dans tout emploi disponible de la même fonction, appartenant à un établissement de la (des) zone(s) mentionnée(s) dans l''acte de candidature visé à l''article 23 ou b) dans l''emploi de la même fonction occupé par un membre du personnel temporaire qui accepte de permuter avec lui. Le littera b) ne vaut que pour les désignations qui interviennent avant le 15 mai de l''année scolaire en cours. § 3. A défaut d''avoir pu offrir au membre du personnel temporaire visé à la présente section une nouvelle désignation conformément au § 2, le ministre fonctionnel le désigne dans tout emploi de la même fonction déjà occupé par : Docu 40701 D. 11-04-2014 1° un membre du personnel temporaire titulaire d''un autre titre que d''un titre de capacité requis, ou suffisant ou de pénurie à qui il impose de permuter avec le membre du personnel victime d''un acte de violence; 1°bis à défaut, à un membre du personnel temporaire porteur du titre de capacité relevant de la catégorie des titres de pénurie à qui il impose de permuter avec le membre du personnel victime d''un acte de violence; 2° à défaut, un membre du personnel temporaire porteur d''un titre de capacité relevant de la catégorie des titres suffisants visés à l''article 2, § 2, de l''arrêté royal du 22 juillet 1969 précité à qui il impose de permuter avec lui. L''alinéa précédent ne vaut que pour les désignations qui interviennent avant le 15 mai de l''année scolaire en cours. § 4. Durant la période de congé rémunéré dont bénéficie le membre du personnel victime d''un acte de violence en incapacité de travail consécutive à cet acte, celui-ci est réputé rendre des services effectifs. Sa prise en compte dans l''ancienneté de service est toutefois limitée à la durée de la désignation initiale. § 5. L''année scolaire qui suit celle au cours de laquelle il a été victime d''un acte de violence, le membre du personnel temporaire visé à la présente section ne peut être à nouveau désigné dans l''établissement dans lequel il a été victime de cet acte, sauf accord de sa part et à condition qu''il ait été reconnu incapable de poursuivre sa (ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la prévention et la protection au travail. § 6. Par dérogation à l''article 18, 8°, le temporaire classé qui a introduit une candidature valable pour une désignation en qualité de temporaire pour l''année scolaire suivante, peut modifier le choix de zones exprimé après le délai fixé dans l''appel aux candidats à condition qu''il ait été reconnu incapable de poursuivre sa(ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la prévention et la protection au travail. Par dérogation à l''article 31, 9°, le temporaire porteur d''un titre de capacité relevant de la catégorie des titres requis qui a introduit une candidature valable pour une désignation en qualité de temporaire prioritaire pour l''année scolaire suivante, peut modifier le choix d''établissements exprimé après le délai fixé dans l''appel aux candidats à condition qu''il ait été reconnu incapable de poursuivre sa(ses) fonction(s) dans l''établissement dans lequel il a été victime d''un ac');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 90, 'Article 75. - Est inséré dans la section 5 du chapitre IIIbis du même (partie 2)', 'de violence par le service externe de prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la prévention et la protection au travail. Cette demande n''est néanmoins prise en considération que si elle parvient avant le 15 mai au ministre fonctionnel.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 91, 'Article 76. - Au chapitre IIIbis du même arrêté est insérée une section', 'Article 76. - Au chapitre IIIbis du même arrêté est insérée une section 
5bis dont l''intitulé est rédigé comme suit : 
 
 
 
Docu 40701 
 
D. 11-04-2014  
«Section 5bis. - Du droit à une nouvelle désignation des temporaires 
classés dans le premier groupe visé à l''article 2bis de l''arrêté royal 
du 22 juillet 1969 précité».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 92, 'Article 77. - Est inséré dans la section 5bis du chapitre IIIbis du même', 'Article 77. - Est inséré dans la section 5bis du chapitre IIIbis du même 
arrêté un article 51undecies rédigé comme suit : 
 
«Article 51undecies. - § 1er. Dans l''enseignement supérieur de 
promotion sociale, le membre du personnel temporaire classé dans le premier 
groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 précité, victime 
d''un acte de violence, peut solliciter sa désignation dans un autre 
établissement dans le respect des conditions visées à la section première. 
 
La demande de nouvelle désignation ne sera prise en considération que 
si la désignation initiale n''arrive pas à échéance avant l''écoulement d''un 
délai d''un mois à dater de l''introduction de la demande. 
 
La nouvelle désignation visée au présent article ne peut être d''une 
durée inférieure à la durée restant à courir dans le cadre de la désignation 
initiale, sauf accord du membre du personnel concerné. Toutefois, une 
désignation d''une durée inférieure à celle restant à courir dans le cadre de sa 
désignation initiale peut être imposée à la victime d''un acte de violence à 
condition que cet emploi soit disponible pour une durée de quinze semaines 
au moins et que le membre du personnel qui fait l''objet d''une telle 
désignation ne perde aucun droit pour la période qui représente la différence 
entre cette désignation et la durée de la désignation initiale. 
 
§ 2. Le ministre fonctionnel désigne le membre du personnel temporaire 
visé à la présente section 
a) dans tout emploi disponible de la même fonction, appartenant à un 
établissement de la (des) zone(s) mentionnée(s) dans l''acte de candidature 
visé à l''article 23 
ou 
b) dans l''emploi de la même fonction occupé par un membre du 
personnel temporaire qui accepte de permuter avec lui. 
 
Le littera b) ne vaut que pour les désignations qui interviennent avant 
le 15 mai de l''année scolaire en cours. 
 
§ 3. A défaut d''avoir pu offrir au membre du personnel temporaire visé à 
la présente section une nouvelle désignation conformément au § 2, le 
ministre fonctionnel le désigne dans tout emploi de la même fonction déjà 
occupé par : 
1° un membre du personnel temporaire classé dans le quatrième groupe 
visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 précité à qui il impose 
de permuter; 
1°bis à défaut, par un membre du personnel temporaire classé dans le 
troisième groupe visé à l''article 2bis de l''arrêté royal du 22 juillet 1969 
précité à qui il impose de permuter; 
2° à défaut, par un membre du personnel temporaire classé dans le 
deuxième groupe visé à l''article 2 bis de l''arrêté royal du 22 juillet 1969 
précité à qui il impose de permuter. 
 
L''alinéa précédent ne vaut que pour les désignations qui interviennent 
avant le 15 mai de l''année scolaire en cours. 
 
 
Docu 40701 
 
D. 11-04-2014  
§ 4. Durant la période de congé rémunéré dont bénéficie le membre du 
personnel victime d''un acte de violence en incapacité de travail consécutive à 
cet acte, celui-ci est réputé rendre des services effectifs. Sa prise en compte 
dans l''ancienneté de service est toutefois limitée à la durée de la désignation 
initiale. 
 
§ 5. L''année scolaire qui suit celle au cours de laquelle il a été victime 
d''un acte de violence, le membre du personnel temporaire visé à la présente 
section ne peut être à nouveau désigné dans l''établissement dans lequel il a 
été victime de cet acte, sauf accord de sa part et à condition qu''il ait été 
reconnu incapable de poursuivre sa (ses) fonction(s) dans l''établissement 
dans lequel il a été victime d''un acte de violence par le service externe de 
prévention et de protection au travail visé à l''arrêté royal du 27 mars 1998 
relatif aux services externes pour la prévention et la protection au travail. 
 
§ 6. Par dérogation à l''article 18, 8°, le temporaire classé dans le 
premier groupe qui a introduit une candidature valable pour une désignation 
en qualité de temporaire pour l''année scolaire suivante, peut modifier le 
choix de zones exprimé après le délai fixé dans l''appel aux candidats à 
condition qu''il ait été reconnu incapable de poursuivre sa(ses) fonction(s) 
dans l''établissement dans lequel il a été victime d''un acte de violence par le 
service externe de prévention et de protection au travail visé à l''arrêté royal 
du 27 mars 1998 relatif aux services externes pour la prévention et la 
protection au travail.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 93, 'Article 78. - Au chapitre IIIbis du même arrêté est insérée une section', 'Article 78. - Au chapitre IIIbis du même arrêté est insérée une section 
6 dont l''intitulé est rédigé comme suit : 
 
«Section 6. - Du droit au changement d''affectation de circonstance 
des membres du personnel désignés en qualité de temporaire 
prioritaire».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 94, 'Article 79. - Est inséré dans la section 6 du chapitre IIIbis du même', 'Article 79. - Est inséré dans la section 6 du chapitre IIIbis du même 
arrêté un article 51duodecies rédigé comme suit : 
 
 «Article 51duodecies. - § 1er. Dans l''enseignement de plein exercice et 
en alternance, le membre du personnel désigné en qualité de temporaire 
prioritaire peut solliciter un changement d''affectation de circonstance dans 
un autre établissement de la même zone ou d''une autre zone, dans le respect 
des conditions visées à la section première et jusqu''au plus tard à la fin de 
l''année scolaire en cours. 
 
La demande visée à l''article 51ter, § 2, indique dans quelle(s) zone(s) 
d''affectation le membre du personnel demande à bénéficier du changement 
d''affectation de circonstance ainsi que les établissements dans lesquels il 
souhaite être affecté. Le membre du personnel visé à la présente section 
indique en outre s''il accepte d''être désigné dans un emploi non vacant. 
 
La demande visée aux alinéas précédents peut être introduite à tout 
moment de l''année; concomitamment, une copie de cette demande est 
transmise au président de la (des) Commission(s) zonale(s) d''affectation 
concernée(s) et, le cas échéant, au président de la Commission interzonale 
d''affectation. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
La (les) Commission(s) zonale(s) d''affectation concernée(s), et, le cas 
échéant, 
la 
Commission 
interzonale 
d''affectation, 
propose(nt) 
au 
Gouvernement les changements d''affectation de circonstance qu''elle(s) 
juge(nt) les plus adéquats, dans le respect du § 2. 
 
§ 2. Le ministre fonctionnel accorde un changement d''affectation de 
circonstance au membre du personnel visé à la présente section 
a) dans tout emploi disponible de la même fonction, en tenant compte 
des préférences exprimées quant à la zone dans la demande visée au § 1er 
ou 
b) dans un emploi, de la même fonction, occupé par un membre du 
personnel temporaire qui accepte de permuter avec lui en tenant compte des 
préférences exprimées quant à la zone dans la demande visée au § 1er. 
 
Le littera b) ne vaut que pour les changements d''affectation de 
circonstance qui interviennent avant le 15 mai de l''année scolaire en cours. 
 
§ 3. A défaut d''avoir pu offrir au membre du personnel temporaire 
prioritaire visé à la présente section un changement d''affectation de 
circonstance conformément au § 2, le ministre fonctionnel lui accorde ce 
changement d''affectation de circonstance dans tout emploi de la même 
fonction déjà occupé par 
1° un membre du personnel temporaire non titulaire d''un titre de 
capacité requis, ou suffisant ou de pénurie à qui il impose de permuter, en 
tenant compte des préférences exprimées quant à la zone dans la demande 
visée au § 1er; 
1°bis à défaut, à un membre du personnel temporaire porteur du titre 
de capacité relevant de la catégorie des titres de pénurie à qui il impose de 
permuter, en tenant compte des préférences exprimées quant à la zone dans 
la demande visée au § 1er; 
2° à défaut, un membre du personnel temporaire porteur d''un titre de 
capacité relevant de la catégorie des titres suffisants visés à l''article 2, § 2, de 
l''arrêté royal du 22 juillet 1969 précité à qui il impose de permuter en tenant 
compte des préférences exprimées quant à la zone dans la demande visée 
au § 1er. 
 
L''alinéa précédent ne vaut que pour les changements d''affectation de 
circonstance qui interviennent avant le 15 mai de l''année scolaire en cours. 
 
§ 4. Le ministre fonctionnel transmet au président de la Commission 
zonale d''affectation concernée copie de l''acte de changement d''affectation de 
circonstance. 
 
Dans l''hypothèse où le membre du personnel obtient un changement 
d''affectation de circonstance dans un établissement relevant d''une autre zone 
que celle de l''établissement où il a été victime de l''acte de violence, le 
ministre fonctionnel transmet également copie de l''acte de changement 
d''affectation de circonstance au Président de la Commission interzonale 
d''affectation. 
 
§ 5. Par dérogation à l''article 33, alinéa 3, et à l''article 46, § 2, le 
temporaire prioritaire peut demander un changement d''affectation pour 
l''année scolaire suivante ou modifier le choix d''établissements déjà exprimé 
après la date fixée à condition qu''il ait été reconnu incapable de poursuivre 
sa (ses) fonction(s) dans l''établissement dans lequel il a été victime d''un acte 
de violence par le service externe de prévention et de protection au travail 
 
 
Docu 40701 
 
D. 11-04-2014  
visé à l''arrêté royal du 27 mars 1998 relatif aux services externes pour la 
prévention et la protection au travail. Néanmoins, cette demande n''est prise 
en compte que si elle parvient avant le 15 mai au ministre fonctionnel.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 95, 'Article 80. - Au chapitre IIIbis du même arrêté est insérée une section', 'Article 80. - Au chapitre IIIbis du même arrêté est insérée une section 
