INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 98, 'Article 83. - Dans la section 7bis du chapitre IIIbis du même arrêté est', 'Article 83. - Dans la section 7bis du chapitre IIIbis du même arrêté est 
