INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 107, 'Article 91. - L''article 2ter de l''arrêté royal du 22 juillet 1969 précité,', 'Article 91. - L''article 2ter de l''arrêté royal du 22 juillet 1969 précité, 
