INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 108, 'Article 92. - Dans l''arrêté royal du 22 juillet 1969 précité, il est inséré (partie 1)', 'Article 92. - Dans l''arrêté royal du 22 juillet 1969 précité, il est inséré un nouvel article 3 rédigé comme suit : «Article 3. - § 1er. Dans l''enseignement de plein exercice, dans l''enseignement en alternance et dans l''enseignement secondaire de promotion sociale les candidats à une désignation à titre temporaire sont appelés en service, compte tenu des préférences zonales qu''ils ont exprimées et selon l''ordre de leur classement. Par dérogation à l''alinéa 1er, les candidats qui font l''objet d''une suspension préventive justifiée par une inculpation, d''une prévention dans le cadre de poursuites pénales, d''une condamnation pénale non définitive contre laquelle ils ont fait usage de leurs droits de recours ordinaires, sont exclus temporairement du classement et ce jusqu''à l''issue de la procédure pénale. Les candidats porteurs du titre de capacité relevant de la catégorie des titres requis ont priorité sur les candidats porteurs du titre de capacité relevant des catégories des titres suffisants et de pénurie. Les candidats porteurs du titre de capacité relevant de la catégorie des titres suffisants ont priorité sur les candidats porteurs du titre de capacité relevant de la catégorie des titres de pénurie tels qu''énumérés par le Gouvernement en vertu de l''article 16 du décret du 11 avril 2014. Au sein des groupes visés à l''article 2, les candidats du premier groupe ont priorité sur les candidats des deuxième et troisième groupes. Les candidats du deuxième groupe ont priorité sur les candidats du troisième groupe. Docu 40701 D. 11-04-2014 Les candidats porteurs du titre de capacité relevant de la catégorie des titres de pénurie ont priorité sur les candidats porteurs d''un autre titre qu''un titre requis, suffisant ou de pénurie. § 2. Les membres du personnel nommés à titre définitif dans une fonction qui possèdent le titre requis pour une autre fonction dans laquelle ils sollicitent leur désignation à titre temporaire, ainsi que, dans l''enseignement de promotion sociale, les membres du personnel nommés à titre définitif dans une fonction à prestations incomplètes sont insérés dans le classement visé à l''article 2, § 1er. Le nombre de candidatures qui leur est attribué est le nombre d''années complètes d''ancienneté de service, calculée à la date fixée par l''appel aux candidats et conformément à l''article 3sexies de l''arrêté royal du 18 janvier 1974 pris en application de l''article 164 de l''arrêté royal du 22 mars 1969 précité. Dans les groupes visés à l''article 2, les candidats sont classés selon le nombre de candidatures introduites dans le respect des conditions prescrites par l''article 18 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. A nombre égal de candidatures introduites, selon l''année civile au cours de laquelle a été délivré le dernier diplôme, certificat ou brevet constitutif du titre soit requis, soit suffisant, soit de pénurie pour la fonction à conférer, la priorité revient au candidat qui détient le titre requis, suffisant, ou de pénurie depuis le plus grand nombre d''années. Lorsque l''année de délivrance du dernier diplôme, certificat ou brevet requis est la même, selon la date de naissance du candidat, la priorité est accordée au candidat le plus âgé. Les services de longue durée sont attribués de préférence aux candidats qui ont la plus grande priorité. Toutefois, le temporaire du premier groupe visé à l''article 2, § 1er, qui s''est acquitté de sa tâche de manière satisfaisante est, sauf demande contraire de sa part, désigné à nouveau dans l''établissement où il était affecté l''année scolaire précédente. La préférence dont il bénéficie ne peut être opposée à la priorité à la désignation d''un candidat mieux classé. Le temporaire visé à l''article 2, § 1er, qui a fait l''objet d''un rapport défavorable du chef d''établissement sous le contrôle ou l''autorité duquel il a été placé n''est pas désigné à nouveau dans l''établissement où il était affecté l''année scolaire précédente. § 3. A nombre égal de candidatures introduites, la priorité est accordée au candidat ayant presté l''année précédente et qui n''a pas fait l''objet d''un rapport défavorable du chef d''établissement. En l''absence de rapport défavorable et à nombre égal de candidatures introduites, les candidats sont classés selon l''année civile au cours de laquelle a été délivré le dernier diplôme, certificat ou brevet constitutif du titre requis pour la fonction à conférer et dont ils sont porteurs. La priorité revient au Docu 40701 D. 11-04-2014 candidat qui détient le titre requis, suffisant ou de pénurie depuis le plus grand nombre d''années. Lorsque l''année de délivrance du dernier dipl');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 109, 'Article 93. - L''article 3 de l''arrêté royal du 22 juillet 1969 précité,', 'Article 93. - L''article 3 de l''arrêté royal du 22 juillet 1969 précité, 
