INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 110, 'Article 94. - L''article 3bis de l''arrêté royal du 22 juillet 1969 précité', 'Article 94. - L''article 3bis de l''arrêté royal du 22 juillet 1969 précité 
