INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 111, 'Article 95. - A l''article 4 de l''arrêté royal du 22 juillet 1969 précité, les', 'Article 95. - A l''article 4 de l''arrêté royal du 22 juillet 1969 précité, les 
