INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 112, 'Article 96. - A l''article 4bis de l''arrêté royal du 22 juillet 1969 précité', 'Article 96. - A l''article 4bis de l''arrêté royal du 22 juillet 1969 précité 
les modifications suivantes sont apportées : 
