INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 113, 'Article 97. - Dans l''arrêté royal du 22 juillet 1969 précité, il est inséré', 'Article 97. - Dans l''arrêté royal du 22 juillet 1969 précité, il est inséré 
