INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 114, 'Article 98. - L''article 5 de l''arrêté royal du 22 juillet 1969 précité,', 'Article 98. - L''article 5 de l''arrêté royal du 22 juillet 1969 précité, 
