INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 122, 'Article 106. - A l''article 110 du même décret, modifié par le décret du', 'Article 106. - A l''article 110 du même décret, modifié par le décret du 
22 décembre 1994, par le décret du 15 avril 1995 et par le décret du 20 
