INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 123, 'Article 107. - L''article 2 du décret du 6 juin 1994 fixant le statut des', 'Article 107. - L''article 2 du décret du 6 juin 1994 fixant le statut des 
membres du personnel subsidiés de l''enseignement officiel subventionné, 
