INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 124, 'Article 108. - Dans l''article 3, alinéa 1er, du même décret, modifié par le', 'Article 108. - Dans l''article 3, alinéa 1er, du même décret, modifié par le 
