INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 125, 'Article 109. - L''article 4 du même décret, modifié par le décret du 10', 'Article 109. - L''article 4 du même décret, modifié par le décret du 10 
avril 1995, par le décret du 25 juillet 1996, par le décret du 2 juin 1998, par le 
décret du 8 février 1999, par le décret du 12 mai 2004 précité, par le décret 
du 30 avril 2009 concernant la comptabilité des écoles et l''accès à certaines 
fonctions de sélection et de promotion et par le décret du 12 juillet 2012, est 
complété par les points 7° et 8° rédigés comme suit : 
«7° dans l''enseignement fondamental et secondaire, y compris 
secondaire de promotion sociale, on entend par «primo-recrutement», le 
recrutement tel qu''il est défini à l''article 25 du décret du 11 avril 2014; 
8° dans l''enseignement fondamental et secondaire, y compris secondaire 
de promotion sociale, on entend par «titre pédagogique», le titre tel qu''il est 
défini aux articles 17 et 18 du décret du 11 avril 2014».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 126, 'Article 110. - L''article 20 du même décret est complété par un', 'Article 110. - L''article 20 du même décret est complété par un 
paragraphe 3 rédigé comme suit : 
«§ 3. Dans l''enseignement fondamental et secondaire, y compris 
secondaire de promotion sociale, au primo-recrutement, le pouvoir 
organisateur procède à la désignation à titre temporaire dans le respect des 
règles fixées au chapitre 4 du titre 1er du décret du 11 avril 2014».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 127, 'Article 111. - A l''article 24 du même décret, modifié par le décret du 10', 'Article 111. - A l''article 24 du même décret, modifié par le décret du 10 
avril 1995, par le décret du 25 juillet 1996, par le décret du 2 juin 1998, par le 
décret du 8 février 1999 et par le décret du 12 mai 2004 précité, les 
modifications suivantes sont apportées : 
1° au paragraphe 1er, alinéa 3, les modifications suivantes sont 
apportées : 
 
 
Docu 40701 
 
D. 11-04-2014  
 a) dans le 2ème tiret, le point 2°, les termes suivants «et pour laquelle 
il possède un titre jugé suffisant A» sont remplacés par les termes «et pour 
laquelle il possède un titre suffisant. Pour les fonctions enseignantes, le 
membre du personnel doit être porteur d''un titre pédagogique;»; 
 b) un 3ème tiret nouveau, rédigé comme suit est inséré : 
«- dans l''enseignement secondaire de promotion sociale, entrent dans le 
classement des prioritaires, tout membre du personnel qui compte, parmi les 
360 jours exigés, 240 jours de service dans la fonction visée et qui possède le 
titre suffisant. Pour les fonctions enseignantes, le membre du personnel doit 
être porteur d''un titre pédagogique;»; 
 c) dans le 3e tiret, devenant le 4ème tiret, le terme «supérieur» est 
inséré entre les termes «dans l''enseignement» et les termes «de promotion 
sociale»; 
2° au paragraphe 2, les modifications suivantes sont apportées : 
 a) dans l''alinéa 1er, les termes «titre jugé suffisant du groupe A» sont 
remplacés par les termes «titre suffisant»; 
 b) l''alinéa 2 est supprimé; 
 c) deux alinéas rédigés comme suit sont insérés après l''alinéa 1er : 
«Dans l''enseignement secondaire, pour les fonctions enseignantes, le 
membre du personnel doit être porteur d''un titre pédagogique. 
 
Dans l''enseignement secondaire de promotion sociale, le membre du 
personnel visé à l''alinéa 1er doit être nommé à titre définitif dans cet 
enseignement et pour les fonctions enseignantes, être porteur d''un titre 
pédagogique.»; 
3° dans le paragraphe 3, un nouvel alinéa rédigé comme suit est inséré 
entre les alinéas 1er et 2 : 
«Dans l''enseignement fondamental et secondaire, y compris secondaire 
de promotion sociale, pour les fonctions enseignantes, le membre du 
personnel doit être porteur d''un titre pédagogique.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 128, 'Article 112. - Dans l''article 27ter, § 1er, alinéa 2, du même décret,', 'Article 112. - Dans l''article 27ter, § 1er, alinéa 2, du même décret, 
inséré par le décret du 12 mai 2004 précité, les modifications suivantes sont 
