INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 130, 'Article 114. - A l''article 33 du même décret, modifié par le décret du 25', 'Article 114. - A l''article 33 du même décret, modifié par le décret du 25 
juillet 1996 et par le décret du 2 juin 1998, les modifications suivantes sont 
apportées : 
 
 
Docu 40701 
 
D. 11-04-2014  
1° dans l''alinéa 2, les mots «visé à l''article 101» sont abrogés; 
2° dans l''alinéa 3, les modifications suivantes sont apportées : 
 a) les mots «secondaire et supérieur» sont insérés entre les mots «Dans 
l''enseignement» et les mots «de promotion sociale»; 
 b) les mots «, respectivement pour chacun de ces niveaux 
d''enseignement,» sont insérés entre les mots «pour laquelle il possède» et les 
mots «le titre requis»; 
 c) les mots «tel que fixé par le décret du 11 avril 2014 ou tel que» sont 
insérés entre les mots «le titre requis» et les mots «visé à l''article 101»; 
 d) dans l''alinéa 4, les mots «visé à l''article 101» sont remplacés par les 
mots «tel que fixé par le décret du 2 juin 1998 précité».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 131, 'Article 115. - Dans l''article 34, § 2, alinéa 1er, du même décret, modifié', 'Article 115. - Dans l''article 34, § 2, alinéa 1er, du même décret, modifié 
