INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 132, 'Article 116. - L''article 101 du même décret, modifié par le décret du 10', 'Article 116. - L''article 101 du même décret, modifié par le décret du 10 
