INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 134, 'Article 118. - A l''article 3 de l''arrêté du Gouvernement de la', 'Article 118. - A l''article 3 de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, les modifications suivantes 
sont apportées : 
1° à l''alinéa 1er, les mots «, en tenant compte de la distinction entre 
l''enseignement ordinaire et l''enseignement spécialisé» sont supprimés; 
2° au § 1er, les mots «telles que précisées aux articles 6 A et B et 8 de 
l''arrêté de l''Exécutif du 2 octobre 1968 déterminant et classant les fonctions 
des membres du personnel directeur et enseignant, du personnel auxiliaire 
d''éducation, du personnel paramédical des établissements d''enseignement 
gardien, primaire, spécialisé, moyen technique, artistique et normal de la 
Communauté française et les fonctions des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements, modifié en 
dernier lieu par l''arrêté du Gouvernement de la Communauté française du 
 
 
Docu 40701 
 
D. 11-04-2014  
16 janvier 1995» sont remplacés par les mots «telles que définies par le 
Gouvernement en vertu de l''article 7 du décret du 11 avril 2014»; 
3° au § 2, 1°, les mots «qui répond à la définition du § 1er et» sont 
supprimés; 
4° l''article 3 est complété par un § 4 rédigé comme suit : 
«§ 4. Par dérogation, dans l''enseignement spécialisé, pour l''application 
des articles 5 et 8, § 1er, § 2 et § 4 du présent arrêté, la définition de «même 
fonction» reprise au présent article ne s''applique pas au membre du 
personnel temporaire qui doit céder son emploi par l''application des mesures 
préalables prévues ou par une réaffectation, et qui peut justifier d''une 
compétence particulière. 
 
Justifie d''une compétence particulière le membre du personnel 
temporaire qui : 
- a exercé la fonction pendant la durée nécessaire pour que l''emploi soit 
soustrait à la réaffectation et à la remise au travail, conformément à l''article 
15; 
- ou ne possédant pas cette ancienneté, peut justifier d''une formation 
spécifique ou complémentaire attestée, conformément à l''article 35 du décret 
du 11 avril 2014, par un document établi par l''organisme qui a dispensé cette 
formation. Cet organisme doit être repris dans la liste fixée par le Conseil 
général de concertation de l''enseignement spécialisé.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 135, 'Article 119. - A l''article 4, § 1er, de l''arrêté du Gouvernement de la', 'Article 119. - A l''article 4, § 1er, de l''arrêté du Gouvernement de la 
