INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 140, 'Article 124. - A l''article 2 de l''arrêté du Gouvernement de la', 'Article 124. - A l''article 2 de l''arrêté du Gouvernement de la 
