INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 141, 'Article 125. - A l''article 3 de l''arrêté du Gouvernement de la', 'Article 125. - A l''article 3 de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, modifié en par l''arrêté du 
 
 
Docu 40701 
 
D. 11-04-2014  
Gouvernement du 29 août 1996 et par le décret du 8 février 1999, les 
modifications suivantes sont apportées : 
1° au § 1er, les modifications suivantes sont apportées : 
 a) les mots «l''enseignement ordinaire de plein exercice et en 
alternance, l''enseignement spécialisé, l''enseignement secondaire artistique à 
horaire réduit et l''enseignement à horaire réduit» sont remplacés par les 
mots «l''enseignement secondaire ordinaire et spécialisé et l''enseignement 
secondaire artistique à horaire réduit»; 
 b) le 1° est remplacé par ce qui suit : 
«1° la fonction telle que précisée : 
- par le Gouvernement en vertu de l''article 7 du décret du 11 avril 2014; 
- par le décret du 2 juin 1998 organisant l''enseignement secondaire 
artistique à horaire réduit subventionné par la Communauté française.»; 
 c) au 2°, a), alinéa 1er, les mots «, ou toute branche faisant partie d''une 
fonction,» et les mots «ou enseigne cette branche» sont supprimés; 
 d) au 2°, a), l''alinéa 2 est supprimé; 
 e) au 2°, a), alinéa 3, le mot «également» est supprimé; 
 f) au 2°, b), alinéa 1er, les mots «ou toute branche» sont supprimés; 
 g) au 3°, le troisième tiret est complété par les mots «et des 
accompagnateurs CEFA» après les mots «porteurs du titres requis»; 
 h) le § 1er est complété par un 4° rédigé comme suit : 
«4° En ce qui concerne la réaffectation interne au pouvoir organisateur, 
la ou une autre fonction figurant dans l''accroche cours-fonction telle que fixée 
par le Gouvernement en vertu de l''article 10 du décret du 11 avril 2014 pour 
ce 
qui 
concerne 
respectivement 
l''enseignement 
libre 
subventionné 
confessionnel et l''enseignement libre subventionné non confessionnel.»; 
2° le § 2 est supprimé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 142, 'Article 126. - L''article', 'Article 126. - L''article 
5 
de 
l''arrêté 
du 
Gouvernement 
de 
la 
Communauté française du 28 août 1995 précité est remplacé par ce qui suit : 
«Par dérogation, dans l''enseignement spécialisé, pour l''application des 
articles 9 et 12 du présent arrêté, la définition de «même fonction» reprise à 
l''article 3 ne s''applique pas au membre du personnel temporaire qui doit 
céder son emploi par l''application des mesures préalables prévues ou par une 
réaffectation, et qui peut justifier d''une compétence particulière. 
 
Justifie d''une compétence particulière le membre du personnel 
temporaire qui : 
- a exercé la fonction pendant la durée nécessaire pour que l''emploi soit 
soustrait à la réaffectation et à la remise au travail, conformément à l''article 
39; 
- ou ne possédant pas cette ancienneté, peut justifier d''une formation 
spécifique ou complémentaire attestée, conformément à l''article 35 du décret 
du 11 avril 2014, par un document établi par l''organisme qui a dispensé cette 
formation. Cet organisme doit être repris dans la liste fixée par le Conseil 
général de concertation de l''enseignement spécialisé.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 143, 'Article 127. - L''article', 'Article 127. - L''article 
6 
de 
l''arrêté 
du 
Gouvernement 
de 
la 
Communauté française du 28 août 1995 précité est remplacé par ce qui suit : 
 
«Article 6. - § 1er. Pour l''application des articles 9 et 10, le membre du 
personnel engagé à titre définitif avant le 31 août 2016 dans la fonction de 
professeur de langues anciennes (latin-grec) dispensée aux degrés inférieur 
et/ou supérieur de l''enseignement secondaire et bénéficiant des dispositions 
fixées par l''article 264, 2°, du décret du 11 avril 2014 est présumé avoir 
exercé cette fonction aux deux niveaux lorsque tous les titulaires des 
 
 
Docu 40701 
 
D. 11-04-2014  
fonctions de professeurs de CG grec ancien et CG latin au sein d''un 
établissement sont porteurs du titre requis. 
 
§ 2.Dans les établissements où les titulaires des fonctions de professeurs 
de CG grec ancien et CG latin ne sont pas tous porteurs du titre requis pour 
l''exercice de ces fonctions, les mesures préalables à la mise en disponibilité et 
la mise en disponibilité elle-même s''effectuent par niveau pour les membres 
du personnel engagés à titre définitif avant le 31 août 2016 dans la fonction 
de professeur de langues anciennes (latin-grec). 
 
Toutefois les membres du personnel engagés à titre définitif qui sont 
porteurs du titre requis acquièrent le droit de récupérer dans l''autre niveau 
des cours de latin et de grec au détriment de membres du personnel porteurs 
ou non du titre requis à condition que ces derniers possèdent une ancienneté 
de service moins élevée.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 144, 'Article 128. - A l''article 7 de l''arrêté du Gouvernement de la', 'Article 128. - A l''article 7 de l''arrêté du Gouvernement de la 
