INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 145, 'Article 129. - A l''article 7bis de l''arrêté du Gouvernement de la / Article 130. - A l''article 9 de l''arrêté du Gouvernement de la', 'Article 129. - A l''article 7bis de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, les chiffres «20» sont 
remplacé par les chiffres «39».

Article 130. - A l''article 9 de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, les modifications suivantes 
sont apportées : 
a) au 4°, les mots «temporaires autres que ceux visés au 8° ci-après;» 
sont remplacés par les mots «temporaire non prioritaire»; 
b) le 4° est complété par un nouvel alinéa rédigé comme suit : 
«Sauf dans l''enseignement secondaire artistique à horaire réduit, il est 
mis fin à ces prestations dans l''ordre suivant : 
a) membre du personnel non titulaire d''un titre requis, d''un titre 
suffisant, ou d''un titre de pénurie avant celles d''un membre du personnel 
titulaire d''un titre de pénurie; 
b) membre du personnel titulaire d''un titre de pénurie avant celles d''un 
membre du personnel titulaire d''un titre suffisant; 
c) membre du personnel titulaire d''un titre suffisant avant celles d''un 
membre du personnel titulaire d''un titre requis;»; 
c) le § 1er est complété par un alinéa 2 rédigé comme suit : 
«Sauf dans l''enseignement secondaire artistique à horaire réduit, 
préalablement à l''application de l''alinéa 1er, le pouvoir organisateur est tenu 
de confier, par priorité, au membre du personnel visé à l''article 266, alinéa 2, 
du décret du 11 avril 2014, les périodes de cours liées à l''acte d''engagement à 
titre définitif dont il est porteur.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 146, 'Article 131. - A l''article 10 de l''arrêté du Gouvernement de la', 'Article 131. - A l''article 10 de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, les modifications suivantes 
