INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 164, 'Article 153. - L''article 5, 4°, de l''arrêté du Gouvernement de la', 'Article 153. - L''article 5, 4°, de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, modifié par le décret du 12 
mai 2004, est remplacé par ce qui suit : 
«4° mis fin aux prestations des membres de son personnel qui exercent 
la même fonction en qualité de temporaire non prioritaire dans l''ordre 
suivant : 
a) membre du personnel non titulaire d''un titre requis, d''un titre 
suffisant ou d''un titre de pénurie avant celles d''un membre du personnel 
titulaire d''un titre de pénurie; 
b) membre du personnel titulaire d''un titre de pénurie avant celles d''un 
membre du personnel titulaire d''un titre suffisant; 
c) membre du personnel titulaire d''un titre suffisant avant celles d''un 
membre du personnel titulaire d''un titre requis;».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 165, 'Article 154. - A l''article 8 de l''arrêté du Gouvernement de la', 'Article 154. - A l''article 8 de l''arrêté du Gouvernement de la 
