INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 166, 'Article 155. - A l''article 11, § 2, de l''arrêté du Gouvernement de la', 'Article 155. - A l''article 11, § 2, de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, les modifications suivantes 
