INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 167, 'Article 156. - A l''article 15 de l''arrêté du Gouvernement de la', 'Article 156. - A l''article 15 de l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 précité, complété par le décret du 17 
