INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 168, 'Article 157. - A l''article 2 de l''arrêté du Gouvernement de la', 'Article 157. - A l''article 2 de l''arrêté du Gouvernement de la 
