INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 174, 'Article 163. - A l''article 13, § 2, de l''arrêté du Gouvernement de la', 'Article 163. - A l''article 13, § 2, de l''arrêté du Gouvernement de la 
