INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 177, 'Article 166. - A l''article 3, § 1er, alinéa 1er, de l''arrêté du Gouvernement', 'Article 166. - A l''article 3, § 1er, alinéa 1er, de l''arrêté du Gouvernement 
