INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 178, 'Article 167. - A l''article 5, § 1er, de l''arrêté du Gouvernement de la', 'Article 167. - A l''article 5, § 1er, de l''arrêté du Gouvernement de la 
Communauté française du 12 septembre 1995 précité, modifié par le décret 
du 8 février 1999, les modifications suivantes sont apportées : 
1° l''alinéa 1er, 3°, est complété par un nouvel alinéa rédigé comme suit : 
«Dans l''enseignement secondaire de promotion sociale, il est mis fin à 
ces prestations dans l''ordre suivant : 
 a) il est d''abord mis fin aux prestations des membres du personnel non 
titulaires d''un titre requis, d''un titre suffisant, ou d''un titre de pénurie avant 
celles des membres du personnel titulaires d''un titre de pénurie; 
 b) il est ensuite mis fin aux prestations des membres du personnel 
titulaires d''un titre de pénurie avant celles des membres du personnel 
titulaires d''un titre suffisant; 
 c) il est enfin mis fin aux prestations des membres du personnel 
titulaires d''un titre suffisant avant celles des membres du personnel 
titulaires d''un titre requis;»; 
 
 
Docu 40701 
 
D. 11-04-2014  
2° l''alinéa 2 est remplacé par deux alinéas rédigés comme suit : 
«Dans l''enseignement secondaire de promotion sociale, préalablement à 
l''application de l''alinéa 1er, le pouvoir organisateur est tenu de confier, par 
priorité, au membre du personnel visé à l''article 266, alinéa 2, du décret du 
11 avril 2014, les périodes de cours liées à l''acte de nomination à titre 
définitif dont il est porteur. 
 
Pour l''application de l''alinéa précédent, en ce qui concerne les 
établissements situés sur le territoire de la même commune, il y a lieu 
d''opérer une distinction entre l''enseignement secondaire, ordinaire et 
spécialisé, l''enseignement de promotion sociale, et l''enseignement secondaire 
artistique à horaire réduit.».');
