INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 185, 'Article 176. - Dans la loi du 29 mai 1959 modifiant certaines', 'Article 176. - Dans la loi du 29 mai 1959 modifiant certaines 
