INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 235, 'Article 259. - Les articles 2, alinéa 4, et 3 du même décret sont abrogés. / Article 260. - A l''article 4 du même décret, les modifications suivantes', 'Article 259. - Les articles 2, alinéa 4, et 3 du même décret sont abrogés.

