INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 236, 'Article 261. - A l''article 21 du même décret, il est inséré une rubrique', 'Article 261. - A l''article 21 du même décret, il est inséré une rubrique 
d) rédigée comme suit : 
«d) au cours des travaux, le président peut saisir, d''initiative ou la 
demande des membres de la Commission, la chambre de la Commission 
interréseaux des titres de capacité chargée de la valorisation de l''expérience 
utile, créée par le décret du 11 avril 2014, afin qu''elle statue sur 
l''élargissement de la reconnaissance d''expérience utile d''un membre du 
personnel mis en disponibilité par défaut d''emploi et susceptible de faire 
l''objet d''une réaffectation. Cette chambre rend sa décision dans les 15 jours 
ouvrables et en informe les présidents, tant de la Commission zonale que de 
la Commission centrale dont dépend la Commission zonale à l''origine de sa 
saisine.». 
 
CHAPITRE II. - Dispositions transitoires 
 
Section Ire. - Des membres du personnel nommés ou engagés à titre 
définitif titulaires d''une charge partielle ou complète. 
 
Complété par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 237, 'Article 262. - La présente section s''applique aux membres du personnel', 'Article 262. - La présente section s''applique aux membres du personnel 
nommés ou engagés à titre définitif au 31 août 2016 à concurrence d''une 
charge partielle ou complète. 
 
Les membres du personnel qui bénéficient des mesures transitoires de 
la présente section peuvent s''en prévaloir auprès de tout autre Pouvoir 
organisateur dans le respect des règles statutaires applicables à ce dernier et 
en vue du recrutement dans une fonction telle qu''arrêtée par l''arrêté du 
Gouvernement pris en exécution de l''article 7 du présent décret. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Complété par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 238, 'Article 263. - Le membre du personnel nommé ou engagé à titre', 'Article 263. - Le membre du personnel nommé ou engagé à titre 
définitif au 31 août 2016 dans une fonction telle qu''elle existait avant l''entrée 
en vigueur du présent décret est réputé nommé ou engagé à titre définitif à 
partir du 1er septembre 2016, s''il échet, dans la fonction nouvelle 
correspondante portant le même intitulé ou résultant d''une fusion ou d''un 
changement d''appellation de fonction selon le tableau de correspondance 
arrêté par le Gouvernement. 
 
Pour les accompagnateurs CEFA, la disposition prévue à l’alinéa 
premier s’opère d’office auprès du pouvoir organisateur dont dépend 
l’établissement-siège du CEFA concerné. [alinéa inséré par D. 30-06-2016] 
 
Les arrêtés adoptés conformément au présent article sont soumis à la 
confirmation du Parlement dans un délai de douze mois suivant leur 
adoption. A défaut d''une telle confirmation, ils cessent de produire leurs 
effets à l''issue de ce délai. 
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 239, 'Article 264. - Dans le cas où l''application du présent décret entraîne', 'Article 264. - Dans le cas où l''application du présent décret entraîne 
une scission de fonction, le membre du personnel nommé ou engagé à titre 
définitif au 31 août 2016 dans une fonction telle qu''elle existait avant l''entrée 
en vigueur du présent décret, est réputé nommé ou engagé à titre définitif à 
partir du 1er septembre 2016 dans, selon le cas : 
1° chacune des nouvelles fonctions correspondantes sur base du tableau 
de correspondance arrêté par le Gouvernement si le membre du personnel 
dispose d''un titre de capacité requis, suffisant ou de pénurie pour cette/ces 
nouvelles fonctions; 
2° la/les fonction(s) correspondante(s) à laquelle/auxquels est/sont 
accroché(s) le/les cours effectivement dispensés par le membre du personnel 
dans l''enseignement de plein exercice ou en alternance, durant 150 jours 
pour 
l''enseignement 
organisé 
par 
la 
Communauté 
française 
et 
l''enseignement officiel subventionné et durant 180 jours au sein du pouvoir 
organisateur pour l''enseignement libre subventionné, calculés selon les 
modalités propres à chaque statut, au cours des trois dernières années 
scolaires précédant le 1er septembre 2016 si le membre du personnel ne 
dispose pas d''un titre de capacité requis, suffisant ou de pénurie pour la/les 
nouvelle(s) 
fonction(s) 
correspondante(s) 
sur 
base 
du 
tableau 
de 
correspondance arrêté par le Gouvernement. 
 
Pour l''enseignement de promotion sociale, le seuil de prestation repris 
ci-dessus est fixé à concurrence de 40 périodes. 
 
Les périodes de congés, absences ou disponibilités prolongent à due 
concurrence les trois années scolaires visées au point 2°.[alinéa remplacé par D. 
30-06-2016] 
 
Pour les maîtres spéciaux de seconde langue dans l’enseignement 
fondamental, en cas de scission de fonction, les mêmes règles sont 
d’application et le membre du personnel est réputé nommé ou engagé à titre 
définitif dans la/les langues qu’il a exercé(es). [alinéa inséré par D. 30-06-2016]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 240, 'Article 265. - Le cas échéant, dans les cas de scission de fonction, le', 'Article 265. - Le cas échéant, dans les cas de scission de fonction, le 
membre du personnel nommé ou engagé à titre définitif dans la fonction telle 
qu''elle existait avant l''entrée en vigueur du présent décret est réputé nommé 
ou engagé à titre définitif à partir du 1er septembre 2016 dans les nouvelles 
 
 
Docu 40701 
 
D. 11-04-2014  
fonctions correspondantes selon les règles prévues à l''article 264, à 
concurrence des attributions et dans le volume de charge exercés au 31 août 
2016. 
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 241, 'Article 266. - Dans les cas qui ne sont pas couverts par les tableaux de', 'Article 266. - Dans les cas qui ne sont pas couverts par les tableaux de 
correspondance arrêtés par le Gouvernement, le membre du personnel 
nommé ou engagé à titre définitif au 31 août 2016 est réputé nommé ou 
engagé à titre définitif à partir du 1er septembre 2016 dans la (ou une des) 
fonction(s) nouvelle(s) dont relève désormais le cours visé par son acte de 
nomination ou d''engagement à titre définitif en tenant compte de l''accroche 
cours-fonction définie par le Gouvernement si le membre du personnel 
possède un titre de capacité requis ou suffisant ou de pénurie pour la 
nouvelle fonction. 
 
Si le membre du personnel ne possède pas de titre de capacité requis ou 
suffisant ou de pénurie pour la nouvelle fonction, il conserve sa nomination 
ou son engagement à titre définitif conformément aux actes de nomination ou 
d''engagement à titre définitif dont il est porteur antérieurement à l''entrée en 
vigueur du présent décret. 
 
Inséré par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 242, 'Article 266bis. - § 1er. Le membre du personnel nommé à titre définitif', 'Article 266bis. - § 1er. Le membre du personnel nommé à titre définitif 
dans l''enseignement organisé par la Communauté française qui, dans le 
cadre de sa fonction de nomination, a dispensé pendant 150 jours au moins 
au cours des trois années scolaires précédant le 31 août 2016, des cours 
accrochés au 1er septembre 2016 à une autre fonction du même niveau que 
celle dans laquelle il est réputé nommé au 1er septembre 2016, est nommé, à 
sa demande, dans cette autre fonction, dite additionnelle, s''il est titulaire 
d''un titre requis, suffisant ou de pénurie pour celle-ci. Cette nomination 
additionnelle est subordonnée au fait que les cours concernés n''auraient pas 
dû être accrochés à la fonction dans laquelle il était nommé au 30 juin 2016. 
 
Dans l''enseignement secondaire de promotion sociale les prestations 
correspondent à l''exercice de 40 périodes de cours. 
 
§ 2. Si le membre du personnel, dans la situation décrite au § 1er, n''est 
pas titulaire d''un titre requis, suffisant ou de pénurie pour la fonction 
additionnelle, les cours concernés sont, à sa demande, réputés accrochés à la 
fonction dans laquelle il est nommé. 
 
§ 3. Pour bénéficier des dispositions du § 1er du présent article, le 
membre du personnel doit introduire sa demande avant le 31 décembre 2018. 
 
Pour bénéficier des dispositions du § 2 du présent article, le membre du 
personnel doit introduire sa demande avant le 15 janvier 2019.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 243, 'Article 267. - Pour toutes les mesures transitoires susvisées, dans', 'Article 267. - Pour toutes les mesures transitoires susvisées, dans 
l''enseignement subventionné, lorsque le membre du personnel était titulaire, 
avant l''entrée en vigueur du présent décret, d''une nomination ou d''un 
engagement à titre définitif sur base des titres propres à l''enseignement 
professionnel, il conserve sa nomination ou son engagement à titre définitif 
uniquement dans cette forme d''enseignement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 244, 'Article 268. - Lorsque l''acte de nomination ou d''engagement à titre', 'Article 268. - Lorsque l''acte de nomination ou d''engagement à titre 
définitif d''un membre du personnel vise une activité citée à l''article 20, § 4, 
 
 
Docu 40701 
 
D. 11-04-2014  
du décret du 29 juillet 1992 portant organisation de l''enseignement 
secondaire de plein exercice, le pouvoir organisateur nomme ou engage à titre 
définitif ce membre du personnel dans une fonction définie par le 
Gouvernement pour laquelle le membre du personnel dispose, dans l''ordre 
suivant, soit d''un titre requis, soit d''un titre suffisant. 
 
Remplacé par D. 04-02-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 245, 'Article 269. - Dans le cadre des règles prévues à la présente section, le', 'Article 269. - Dans le cadre des règles prévues à la présente section, le 
membre du personnel nommé ou engagé à titre définitif qui s''est vu 
reconnaitre une expérience utile pour une fonction de cours techniques, de 
pratique professionnelle, de cours technique et de pratique professionnelle, 
de cours artistique ou pour la fonction d''accompagnateur CEFA conserve le 
bénéfice de cette reconnaissance dans l''exercice de sa nouvelle fonction de 
professeur 
de 
cours 
technique, 
de 
cours 
artistique, 
de 
pratique 
professionnelle, d''accompagnateur CEFA conformément au tableau de 
correspondance arrêté par le Gouvernement ou à l''accroche cours-fonction 
arrêtée par le Gouvernement. 
 
Complété par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 246, 'Article 270. - A l''exception des membres du personnel visés à l''article', 'Article 270. - A l''exception des membres du personnel visés à l''article 
266, alinéa 2, les membres du personnel nommés ou engagés à titre définitif 
pour une charge à prestation incomplète conservent, dans la nouvelle 
fonction, le bénéfice du droit à étendre leur charge conformément aux 
dispositions statutaires dont ils relèvent. 
 
Les membres du personnel visés à l''article 266, alinéa 2 pour lesquels le 
bénéfice des mesures transitoires est limité aux actes de nomination ou 
d''engagement à titre définitif dont ils sont porteurs antérieurement à l''entrée 
en vigueur du présent décret, conservent le bénéfice du droit à étendre leur 
charge conformément aux dispositions statutaires dont ils relèvent. [Alinéa 
inséré par D. 13-07-2016] 
 
Dans ce cadre, dans l''enseignement subventionné, les membres du 
personnel sont réputés avoir introduit, lors de l''année scolaire 2015-2016, 
leur candidature dans les formes et délais prescrits aux articles 34, 34bis, 
34ter et 42 du décret du 1er février 1993 fixant le statut des membres du 
personnel subsidiés de l''enseignement libre subventionné ainsi qu''aux 
articles 24 et 30 du décret du 6 juin 1994 fixant le statut des membres du 
personnel subsidiés de l''enseignement officiel subventionné.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 247, 'Article 271. - § 1er. Les membres du personnel nommés ou engagés à', 'Article 271. - § 1er. Les membres du personnel nommés ou engagés à 
titre définitif dans une fonction de cours spéciaux à la veille de l''entrée en 
vigueur du présent décret sont réputés nommés ou engagés à titre définitif 
dans une fonction de cours généraux et/ou de cours techniques selon le 
tableau de correspondance arrêté par le Gouvernement et en fonction des 
dispositions prévues à la présente section. 
 
§ 2. Les membres du personnel nommés ou engagés à titre définitif dans 
une fonction de cours techniques et de pratique professionnelle à la veille de 
l''entrée en vigueur du présent décret sont réputés nommés ou engagés à titre 
définitif dans une fonction de cours techniques et/ou de cours de pratique 
professionnelle 
selon 
le 
tableau 
de 
correspondance 
arrêté 
par 
le 
Gouvernement et en fonction des dispositions prévues à la présente section. 
 
§ 3. Les membres du personnel visés aux §§ 1er et 2 conservent dans la 
nouvelle fonction le dénominateur de charge de leur fonction antérieure si 
 
 
Docu 40701 
 
D. 11-04-2014  
celle-ci est plus avantageuse pour le membre du personnel. Le maintien de la 
fraction de charge initiale porte également sur les extensions de charge et les 
mesures liées à la mise en disponibilité et à la réaffectation. 
 
Complété par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 248, 'Article 272. - Les membres du personnel réputés nommés ou engagés à', 'Article 272. - Les membres du personnel réputés nommés ou engagés à 
titre définitif dans une nouvelle fonction en application des articles 
précédents bénéficient de l''échelle de traitement attachée à cette fonction 
sauf si l''échelle de traitement afférente à leur fonction d''origine leur procure 
une rémunération plus élevée. 
 
Les membres du personnel visés à l''article 266, alinéa 2, conservent 
l''échelle de traitement dont ils bénéficiaient avant l''entrée en vigueur du 
présent décret sauf si l''échelle de traitement afférente à la fonction à laquelle 
est accroché le cours, exercée sur base d''un autre titre, leur procurerait une 
rémunération plus élevée en application des dispositions prévues au chapitre 
VI du titre II. Dans ce cas, ce barème plus avantageux leur est accordé pour 
l''exercice de ce cours. 
 
Section II. - Les membres du personnel temporaires titulaires d''une 
charge partielle ou complète');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 249, 'Article 273. - La présente section s''applique aux membres du personnel / Article 274. - Dans l''enseignement organisé par la Communauté', 'Article 273. - La présente section s''applique aux membres du personnel 
temporaires, titulaires d''une charge partielle ou complète. 
 
Modifié par D. 30-06-2016

Article 274. - Dans l''enseignement organisé par la Communauté 
française, en vue des appels aux candidats prévus aux articles 21 et 34 de 
l''arrêté royal du 22 mars 1969 ainsi qu’aux articles 5bis et 13 de l’arrêté royal 
du 25 octobre 1971, pour l''année scolaire 2016 -2017, les fonctions visées au 
chapitre 2 du titre I du présent décret sont d''application. 
 
Au 1er septembre 2016, les membres du personnel titulaires d''un titre de 
capacité relevant de la catégorie des titres suffisants ou des titres de pénurie 
sont insérés dans le classement visé à l''article 2, §§ 2 et 3, de l''arrêté royal du 
22 juillet 1969 précité en leur attribuant, à cette date, comme nombre de 
candidatures le nombre d''années scolaires pendant lesquelles ils ont bénéficié 
d''une désignation dans la fonction. 
 
Les candidats ayant introduit au cours du mois de janvier 2016 une 
candidature pour une désignation à titre temporaire dans l''enseignement 
organisé par la Communauté française et qui au 1er septembre 2016 
acquièrent un titre de capacité relevant de la catégorie des titres requis à la 
suite de l''entrée en vigueur du présent décret, sont réputés avoir rempli la 
condition de titre fixée à l''article 18, 5°, de l''arrêté royal du 22 mars 1969 
précité. 
 
Dans l''enseignement subventionné par la Communauté française, tout 
acte de candidature introduit dans les délais et formes requises, en vue de 
l''exercice d''une priorité pour un engagement ou une désignation à dater du 
1er septembre 2016, dans une des fonctions telles que définies avant l''entrée 
en vigueur du présent décret, est réputée l''avoir été dans la ou les fonction(s) 
correspondante(s) selon le tableau de correspondance arrêté par le 
Gouvernement. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 250, 'Article 275. - Pour l''application des articles 34 et 42 du décret du 1er', 'Article 275. - Pour l''application des articles 34 et 42 du décret du 1er 
février 1993 fixant le statut des membres du personnel subsidiés de 
l''enseignement libre subventionné, dans le cas d''une fusion, d''un changement 
d''appellation de fonction ou dans le cas où l''intitulé d''une fonction reste 
inchangé, les services rendus dans la fonction antérieure à l''entrée en 
vigueur du présent décret par le membre du personnel temporaire, sont 
réputés 
l''avoir 
été 
dans 
la 
(ou 
une 
des) 
fonction(s) 
nouvelle(s) 
correspondante(s) selon le tableau de correspondance arrêté par le 
Gouvernement. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 34 
et 42 du décret du 1er février 1993 précité. 
 
Pour les accompagnateurs CEFA, la disposition prévue à l’alinéa 
premier s’opère d’office auprès du pouvoir organisateur dont dépend 
l’établissement-siège du CEFA concerné. [Alinéa inséré par D. 30-06-2016]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 251, 'Article 276. - Pour l''application des articles 31 et 31ter de l''arrêté royal', 'Article 276. - Pour l''application des articles 31 et 31ter de l''arrêté royal 
du 22 mars 1969 fixant le statut des membres du personnel directeur et 
enseignant, du personnel auxiliaire d''éducation, du personnel paramédical 
des établissements d''enseignement, gardien, primaire, spécialisé, moyen, 
technique, de promotion sociale et artistique de l''Etat, des internats 
dépendant de ces établissements et des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements, dans le cas d''une 
fusion, d''un changement d''appellation de fonction ou dans le cas où l''intitulé 
d''une fonction reste inchangé, les services rendus dans la fonction antérieure 
à l''entrée en vigueur du présent décret par le membre du personnel 
temporaire, sont réputés l''avoir été dans la (ou une des) fonction(s) 
nouvelle(s) correspondante(s) selon le tableau de correspondance arrêté par 
le Gouvernement. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 31 
et 31ter du de l''arrêté royal précité. 
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 252, 'Article 277. - Pour l''application des articles 24 et 30 du décret du 6 juin', 'Article 277. - Pour l''application des articles 24 et 30 du décret du 6 juin 
1994 fixant le statut des membres du personnel subsidiés de l''enseignement 
officiel subventionné, dans le cas d''une fusion, d''un changement d''appellation 
de fonction ou dans le cas où l''intitulé d''une fonction reste inchangé, les 
services rendus dans la fonction antérieure à l''entrée en vigueur du présent 
décret par le membre du personnel temporaire, sont réputés l''avoir été dans 
la (ou une des) fonction(s) nouvelle(s) correspondante(s) selon le tableau de 
correspondance arrêté par le Gouvernement. 
 
Pour les accompagnateurs CEFA, la disposition prévue à l’alinéa 
premier s’opère d’office auprès du pouvoir organisateur dont dépend 
l’établissement-siège du CEFA concerné. [Inséré par D. 30-06-2016] 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 24 
et 30 du décret du 6 juin 1994 précité. 
 
Modifié par D. 30-06-2016 ; complété par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 253, 'Article 278. - Pour l''application des articles 31 et 31ter de l''arrêté royal', 'Article 278. - Pour l''application des articles 31 et 31ter de l''arrêté royal 
du 22 mars 1969 précité, dans les cas de scission de fonction, les services 
rendus dans la fonction antérieure à l''entrée en vigueur du présent décret 
par le membre du personnel temporaire, sont réputés l''avoir été, selon le cas, 
dans : 
1° chacune des nouvelles fonctions correspondantes sur base du tableau 
de correspondance arrêté par le Gouvernement, si le membre du personnel 
dispose d''un titre de capacité requis suffisant ou de pénurie pour les 
nouvelles fonctions; 
2° la/les fonction(s) correspondante(s) à laquelle/auxquelles est/sont 
accroché(s) le/les cour(s) effectivement dispensés par le membre du 
personnel, dans l''enseignement de plein exercice ou en alternance, durant 
150 jours calculés selon les modalités dudit statut au cours des trois 
dernières années scolaires précédant le 1er septembre 2016, si le membre du 
personnel ne dispose pas d''un titre de capacité requis suffisant ou de pénurie 
pour la/les nouvelle(s) fonction(s). 
 
Pour l''enseignement de promotion sociale, le seuil de prestation repris 
ci-dessus est fixé à 40 périodes. 
 
Pour les maîtres spéciaux de seconde langue dans l’enseignement 
fondamental, en cas de scission de fonction, les mêmes règles sont 
d’application et le membre du personnel est réputé nommé ou engagé à titre 
définitif dans la/les langues qu’il a exercé(es).  [Alinéa inséré par D. 30-06-2016] 
 
Par dérogation à l''alinéa 1er, les services rendus par les membres du 
personnel dans une fonction de cours techniques et de pratique 
professionnelle avant l''entrée en vigueur du présent décret sont réputés 
l''avoir été dans la fonction de cours technique et/ou dans la fonction de 
professeur de cours de pratique professionnelle selon le tableau de 
correspondance arrêté par le Gouvernement. [Alinéa inséré par D. 19-10-2017] 
 
Modifié par D. 30-06-2016 ; complété par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 254, 'Article 279. - Pour l''application des articles 34 et 42 du décret du 1er', 'Article 279. - Pour l''application des articles 34 et 42 du décret du 1er 
février 1993 fixant le statut des membres du personnel subsidiés de 
l''enseignement libre subventionné, dans les cas de scission de fonction, les 
services rendus dans la fonction antérieure à l''entrée en vigueur du présent 
décret par le membre du personnel temporaire, sont réputés l''avoir été, selon 
le cas, dans : 
1° chacune des nouvelles fonctions correspondantes sur base du tableau 
de correspondance arrêté par le Gouvernement, si le membre du personnel 
dispose d''un titre de capacité requis suffisant ou de pénurie  pour la/les 
nouvelle(s) fonction(s); 
2° la/les fonction(s) correspondante(s) à laquelle/auxquelles est/sont 
accroché(s) le/les cour(s) effectivement dispensés par le membre du 
personnel, dans l''enseignement de plein exercice ou en alternance, durant 
180 jours au sein du pouvoir organisateur calculés selon les modalités dudit 
statut au cours des trois dernières années scolaires précédant le 1er 
 
 
Docu 40701 
 
D. 11-04-2014  
septembre 2016, si le membre du personnel ne dispose pas d''un titre de 
capacité requis suffisant ou de pénurie  pour la/les nouvelle(s) fonction(s). 
 
Pour l''enseignement de promotion sociale, le seuil de prestation repris 
ci-dessus est fixé à concurrence de 40 périodes. 
 
Les périodes  de congés, absences ou disponibilités prolongent à due 
concurrence les trois années scolaires visées au point 2°. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 34 
et 42 du décret du 1er février 1993 précité. 
 
Pour les maîtres spéciaux de seconde langue dans l’enseignement 
fondamental, en cas de scission de fonction, les mêmes règles sont 
d’application et le membre du personnel est réputé nommé ou engagé à titre 
définitif dans la/les langues qu’il a exercé(es). [Alinéa inséré par D. 30-06-2016] 
 
Par dérogation à l''alinéa 1er, les services rendus par les membres du 
personnel dans une fonction de cours techniques et de pratique 
professionnelle avant l''entrée en vigueur du présent décret sont réputés 
l''avoir été dans la fonction de cours technique et/ou dans la fonction de 
professeur de cours de pratique professionnelle selon le tableau de 
correspondance arrêté par le Gouvernement. [Alinéa inséré par D. 19-10-2017] 
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 255, 'Article 280. - Pour l''application des articles 24 et 30 du décret du 6 juin', 'Article 280. - Pour l''application des articles 24 et 30 du décret du 6 juin 
1994 fixant le statut des membres du personnel subsidiés de l''enseignement 
officiel subventionné, dans les cas de scission de fonction, les services rendus 
dans la fonction antérieure à l''entrée en vigueur du présent décret par le 
membre du personnel temporaire, sont réputés l''avoir été, selon le cas, dans : 
1° chacune des nouvelles fonctions correspondantes sur base du tableau 
de correspondance arrêté par le Gouvernement, si le membre du personnel 
dispose d''un titre de capacité requis suffisant ou de pénurie pour les 
nouvelles fonctions; 
2° la/les fonction(s) correspondante(s) à laquelle/auxquelles est/sont 
accroché(s) le/les cour(s) effectivement dispensés par le membre du 
personnel, dans l''enseignement de plein exercice ou en alternance, durant 
150 jours calculés selon les modalités dudit au cours des trois dernières 
années scolaires précédant le 1er septembre 2016, si le membre du personnel 
ne dispose pas d''un titre de capacité requis suffisant ou de pénurie pour la/les 
nouvelle(s) fonction(s). 
 
Pour l''enseignement de promotion sociale, le seuil de prestation repris 
ci-dessus est fixé à 40 périodes. 
 
Les périodes de congés, absences ou disponibilités prolongent à due 
concurrence les trois années scolaires visées au point 2°. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 24 
et 30 du décret du 6 juin 1994 précité. 
 
 
Docu 40701 
 
D. 11-04-2014  
Pour les maîtres spéciaux de seconde langue dans l’enseignement 
fondamental, en cas de scission de fonction, les mêmes règles sont 
d’application et le membre du personnel est réputé nommé ou engagé à titre 
définitif dans la/les langues qu’il a exercé(es). [Alinéa Inséré par D. 30-06-2016] 
 
Inséré par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 256, 'Article 280bis. - Pour l’application des articles 23 et 31 du décret du 10', 'Article 280bis. - Pour l’application des articles 23 et 31 du décret du 10 
mars 2006 relatif aux statuts des maîtres de religion et professeurs de 
religion, les services rendus dans la fonction antérieure à l’entrée en vigueur 
du présent décret par le membre du personnel temporaire, valorisables selon 
les règles en vigueur antérieurement à l’entrée en vigueur du présent décret, 
sont réputés l’avoir été dans la nouvelle fonction correspondante selon le 
tableau de correspondance arrêté par le Gouvernement. 
 
Dans ce cadre, pour l’année scolaire 2015-2016, les membres du 
personnel sont réputés avoir introduit leur candidature dans les formes et 
délais prescrits aux mêmes articles 23 et 31 du décret du 10 mars 2006 
précité.  
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 257, 'Article 281. - Pour l''application des articles 34 et 42 du décret du 1er', 'Article 281. - Pour l''application des articles 34 et 42 du décret du 1er 
février 1993 fixant le statut des membres du personnel subsidiés de 
l''enseignement libre subventionné, dans les cas qui ne sont pas couverts par 
les tableaux de correspondance arrêtés par le Gouvernement, les services 
rendus par le membre du personnel temporaire antérieurement à l''entrée en 
vigueur du présent décret, sont réputés l''avoir été dans la (ou une des) 
fonction(s) nouvelle(s) dont relève désormais le cours en tenant compte de 
l''accroche cours-fonction définie par le Gouvernement si le membre du 
personnel possède un titre de capacité requis ou suffisant ou de pénurie pour 
la nouvelle fonction. 
 
Pour les membres du personnel visés par la section 3 du présent 
chapitre, si le membre du personnel ne dispose pas d''un titre de capacité 
requis ou suffisant ou de pénurie pour la nouvelle fonction, son ancienneté 
reste acquise selon les modalités applicables avant l''entrée en vigueur du 
présent décret. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 34 
et 42 du décret du 1er février 1993 précité. 
 
Modifié par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 258, 'Article 282. - Pour l''application des articles 24 et 30 du décret du 6 juin', 'Article 282. - Pour l''application des articles 24 et 30 du décret du 6 juin 
1994 fixant le statut des membres du personnel subsidiés de l''enseignement 
officiel subventionné, dans les cas qui ne sont pas couverts par les tableaux 
de correspondance en annexe au présent décret, les services rendus par le 
membre du personnel temporaire antérieurement à l''entrée en vigueur du 
présent décret, sont réputés l''avoir été dans la (ou une des) fonction(s) 
nouvelle(s) dont relève désormais le cours en tenant compte de l''accroche 
cours-fonction définie par le Gouvernement si le membre du personnel 
possède un titre de capacité requis ou suffisant ou de pénurie pour la 
nouvelle fonction. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Pour les membres du personnel visés par la section 3 du présent 
chapitre, si le membre du personnel ne dispose pas d''un titre de capacité 
requis ou suffisant ou de pénurie pour la nouvelle fonction, son ancienneté 
reste acquise selon les modalités applicables avant l''entrée en vigueur du 
présent décret. 
 
Dans ce cadre, pour l''année scolaire 2015-2016, les membres du 
personnel ayant introduit leur candidature pour les fonctions antérieures à 
l''entrée en vigueur du présent décret sont réputés l''avoir fait pour les 
fonctions nouvelles dans les formes et délais prescrits aux mêmes articles 24 
et 30 du décret du 6 juin 1994 précité. 
 
Remplacé par D. 04-02-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 259, 'Article 283. - Dans le cadre des règles prévues à la présente section, le', 'Article 283. - Dans le cadre des règles prévues à la présente section, le 
membre du personnel temporaire qui s''est vu reconnaitre une expérience 
utile pour une fonction de cours techniques, de pratique professionnelle, de 
cours technique et de pratique professionnelle, de cours artistique ou pour la 
fonction 
d''accompagnateur 
CEFA 
conserve 
le 
bénéfice 
de 
cette 
reconnaissance dans l''exercice de sa nouvelle fonction de professeur de cours 
technique, de cours artistique, de pratique professionnelle, d''accompagnateur 
CEFA conformément au tableau de correspondance arrêté par le 
Gouvernement ou à l''accroche cours-fonction arrêtée par le Gouvernement. 
 
Complété par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 260, 'Article 284. - Pour les désignations ou les engagements à titre', 'Article 284. - Pour les désignations ou les engagements à titre 
temporaire débutant le 1er septembre 2016 et prenant fin, au plus tard, le 30 
juin 2017, les membres du personnel visés à la présente section bénéficient 
de l''échelle de traitement attachée à la nouvelle fonction sauf si l''échelle de 
traitement afférente à leur fonction d''origine leur procure une rémunération 
plus élevée. 
 
Les puériculteurs visés par le décret du 12 mai 2004 fixant les droits et 
obligations des puériculteurs et portant diverses dispositions relatives à la 
valorisation des jours prestés par le personnel non statutaire de la 
Communauté française bénéficient également de la disposition prévue à 
l’alinéa précédent. 
 
Section III. - Les membres du personnel temporaires 
prioritaires/protégés ou temporaires non prioritaires comptabilisant 
l''ancienneté définie dans la présente section, à concurrence d''une 
charge partielle ou complète. 
 
Modifié par D. 30-06-2016 ; D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 261, 'Article 285. - Les membres du personnel, titulaires d''une charge (partie 1)', 'Article 285. - Les membres du personnel, titulaires d''une charge partielle ou complète, visés par la présente section sont les suivants : 1° les membres du personnel temporaires visés par les articles 31 et 31ter en ce qui concerne l''enseignement de promotion sociale, de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, disposant d''un titre requis ou de tout autre titre à la veille de l''entrée en vigueur du présent décret; Docu 40701 D. 11-04-2014 2° les membres du personnel temporaires prioritaires au sens de l''article 34 du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné disposant d''un titre requis, d''un titre suffisant A ou un titre visé à l''article 2 de l''arrêté royal du 17 mars 1967 fixant les titres de capacité jugés suffisants pour les membres du personnel des établissements libres d''enseignement moyen et normal à la veille de l''entrée en vigueur du présent décret; 3° les membres du personnel temporaires prioritaires au sens de l''article 24 du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné disposant d''un titre requis ou d''un titre suffisant A à la veille de l''entrée en vigueur du présent décret; 4° les membres du personnel temporaires disposant d''un titre requis à la veille de l''entrée en vigueur du présent décret, classés dans le premier groupe visé à l''article 2, alinéa 2, de l''arrêté royal du 22 juillet 1969 fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat; 5° les membres du personnel temporaires visés par le décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné, disposant d''un titre requis, d''un titre suffisant A ou un titre visé à l''article 2 de l''arrêté royal du 17 mars 1967 fixant les titres de capacité jugés suffisants pour les membres du personnel des établissements libres d''enseignement moyen et normal à la veille de l''entrée en vigueur du présent décret et d''une ancienneté de fonction de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires, calculés conformément à l''article 29bis du décret précité. Pour l''enseignement de promotion sociale, le seuil de prestation repris ci-dessus est fixé à 480 périodes à l''exception du personnel non chargé de cours pour qui il faut compter une ancienneté de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires; [complété par D. 19-10-2017] 6° les membres du personnel temporaires visés par le décret du 6 juin 1994 fixant le statut des membres du personnel subsidié de l''enseignement officiel subventionné disposant d''un titre requis ou d''un titre suffisant A à la veille de l''entrée en vigueur du présent décret et d''une ancienneté de fonction de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires, calculés conformément à l''article 34 du décret précité. Pour l''enseignement de promotion sociale, le seuil de prestation repris ci-dessus est fixé à 480 périodes à l''exception du personnel non chargé de cours pour qui il faut compter une ancienneté de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires; [complété par D. 19-10-2017]; 7° les membres du personnel temporaires visés à l''article 20 de l''arrêté royal du 22 mars 1969 précité à la veille de l''entrée en vigueur du présent décret et disposant d''une ancienneté de fonction de 450 jours répartis sur 3 années scolaires au moins; 8° les membres du personnel temporaires titulaires, à la veille de l''entrée en vigueur du présent décret, d''un titre jugé suffisant du groupe B ou d''un titre y assimilé visés aux articles 6, § 4, de l''arrêté royal du 30 juillet 1975 relatif aux titres jugés suffisants dans l''enseignement secondaire dispensé dans les établissements libres d''enseignement moyen ou d''enseignement normal subventionnés, y compris l''année postsecondaire psychopédagogique, de l''arrêté royal du 30 juillet 1975 relatif aux titres jugés suffisants dans l''enseignement secondaire dispensé dans les établissements d''enseignement moyen ou d''enseignement normal officiels subventionnés, de Docu 40701 D. 11-04-2014 l''arrêté royal du 30 juillet 1975 relatif aux titres jugés suffisants dans les établissements subventionnés d''enseignement technique et d''enseignement professionnel secondaire de plein exercice et');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 262, 'Article 285. - Les membres du personnel, titulaires d''une charge (partie 2)', 'de promotion sociale, à l''article 6, § 5, de l''arrêté royal du 20 juin 1975 relatif aux titres suffisants dans l''enseignement gardien et primaire, ainsi qu''à l''article 6, § 3, de l''arrêté royal du 31 août 1978 relatif aux titres jugés suffisants dans les établissements subventionnés d''enseignement artistique qui dispensent un enseignement secondaire des arts plastiques et ayant fait l''objet de 3 dérogations ministérielles consécutives favorables portant chacune sur un engagement de plus de 15 semaines visées à l''article 6, § 5, alinéa 2, de l''arrêté royal précité ainsi que d''une ancienneté de fonction de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires, calculés conformément aux dispositions propres à chaque statut. Pour l''enseignement de promotion sociale, le seuil de prestation repris ci-dessus est fixé à 480 périodes à l''exception du personnel non chargé de cours pour qui il faut compter une ancienneté de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires; [complété par D. 19-10-2017] 9° les membres du personnel temporaires titulaires, à la veille de l''entrée en vigueur du présent décret, d''un titre suffisant visé à l''article 3 de l''arrêté royal du 17 mars 1967 fixant les titres de capacité jugés suffisants pour les membres du personnel des établissements libres d''enseignement moyen et normal restés en fonction pendant trois années scolaires, avec maintien de la subvention-traitement, à moins qu''avant le 30 juin de la troisième année scolaire, une décision défavorable ne leur ait été notifiée ainsi que d''une ancienneté de fonction de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 3 dernières années scolaires, calculés conformément à l''article 29bis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné. Pour l''enseignement de promotion sociale, le seuil de prestation repris ci-dessus est fixé à 480 périodes à l''exception du personnel non chargé de cours pour qui il faut compter une ancienneté de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires. Ces membres du personnel seront réputés au 1er septembre 2016 comme étant porteur d’un titre qui donne droit, sans limitation de temps, à l’octroi d’une subvention-traitement pour l’exercice de la fonction concernée, au sens de l’article 34, §2, du décret du 1er février 1993 précité. Pour avoir droit à un engagement à titre définitif dans la même fonction pour laquelle ils possèdent ce titre, ils devront cependant l’avoir exercée pendant cinq années scolaires consécutives ; [modifié par 30-06-2016 ; [complété par D. 19-10-2017]] 10° Les puériculteurs visés à l’article 28, §1er alinéa 1, §2 alinéa 1, §3 alinéa 1 du décret du 12 mai 2004 fixant les droits et obligations des puériculteurs et portant diverses dispositions relatives à la valorisation des jours prestés par le personnel non statutaire de la Communauté française ; [inséré par D. 30-06-2016] 11° les membres du personnel de l''enseignement de promotion sociale prestant une fonction accessoire depuis au moins trois années scolaires pour un volume d''au moins 120 périodes par année scolaire; [inséré par D. 19-10-2017] 12° les membres du personnel temporaires prioritaires au sens de l''article 23 du décret du 10 mars 2006 relatif aux statuts des maîtres de religion et professeurs de religion disposant d''un titre requis; [inséré par D. 19- 10-2017] 13° les membres du personnel temporaires visés par le décret du 10 mars 2006 relatif aux statuts des maîtres de religion et professeurs de religion disposant d''un titre requis à la veille de l''entrée en vigueur du Docu 40701 D. 11-04-2014 présent décret et d''une ancienneté de fonction de 315 jours auprès du pouvoir organisateur sur minimum 2 années scolaires, acquises dans les 5 dernières années scolaires, calculés conformément à l''article 18 du décret précité; [inséré par D. 19-10-2017] 14° les membres du personnel stagiaires visés par l''article 12 de l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres de religion, des professeurs de religion et des inspecteurs de religion des religions catholique, protestante, israélite, orthodoxe et islamique des établissements d''enseignement de la Communauté française; [inséré par D. 19-10-2017] 15° les membres du personnel temporaires disposant d''un titre requis à la veille de l''entrée en vigueur du présent décret, classés dans le premier groupe visé à l''article 5 quater, alinéa 3 de l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres de religion, des professeurs de religion et des inspecteurs de religion des religions catholique, protestante, israélite, orthodoxe et islamique des établissements d''enseignement de la Communauté française; [inséré par D. 19-10-2017] 16° les membres du personnel temp');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 263, 'Article 285. - Les membres du personnel, titulaires d''une charge (partie 3)', 'visés par l''article 5 de l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres de religion, des professeurs de religion et des inspecteurs de religion des religions catholique, protestante, israélite, orthodoxe et islamique des établissements d''enseignement de la Communauté française et disposant d''une ancienneté de fonction de 450 jours auprès du pouvoir organisateur acquise sur 3 années scolaires au moins, calculés conformément à l''article 5quinquies de l''arrêté royal précité, à la veille de l''entrée en vigueur du présent décret. [inséré par D. 19-10-2017] Inséré par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 264, 'Article 285bis - Pour toutes les mesures transitoires susvisées, dans', 'Article 285bis - Pour toutes les mesures transitoires susvisées, dans 
l''enseignement subventionné, les membres du personnel temporaires 
prioritaires ou y assimilés en vertu de l''article 285 sur bases de titres propres 
à l''enseignement professionnel conservent la possibilité d''être nommés, 
engagés à titre définitif ainsi que désignés en qualité de temporaires 
prioritaires ou protégés uniquement dans cette forme d''enseignement. 
 
Complété par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 265, 'Article 286. - Les membres du personnel visés à la présente section', 'Article 286. - Les membres du personnel visés à la présente section 
bénéficient des dispositions prévues à la section 2 du présent chapitre. 
 
Les membres du personnel qui bénéficient des mesures transitoires de 
la présente section peuvent s''en prévaloir auprès de tout autre pouvoir 
organisateur dans le respect des règles statutaires applicables à ce dernier et 
en vue du recrutement dans une fonction telle qu''arrêtée par arrêté du 
Gouvernement adopté en application de l''article 7 du présent décret.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 266, 'Article 287. - Dans l''enseignement organisé par la Communauté', 'Article 287. - Dans l''enseignement organisé par la Communauté 
française, toute désignation sortant ses effets à dater du 1 septembre 2016 de 
membre des personnels temporaire prioritaire dans une des fonctions telles 
que définies avant l''entrée en vigueur du présent décret est réputée l''avoir 
été dans la ou les fonctions correspondante(s). 
 
Complété par D. 14-03-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 267, 'Article 288. - § 1er. Les membres du personnel visés à la présente', 'Article 288. - § 1er. Les membres du personnel visés à la présente 
section conservent la possibilité d''être nommés, engagés à titre définitif ainsi 
que désignés en qualité de temporaires prioritaires ou protégés dans les 
conditions statutaires prévalant avant l''entrée en vigueur du présent décret. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Inséré par D. 14-03-2019 
§ 2. Le membre du personnel visé à l''article 285, 1°, qui, dans le cadre 
de sa fonction de désignation, a dispensé pendant 150 jours au moins au 
cours des trois années scolaires précédant le 31 août 2016, des cours 
accrochés au 1er septembre 2016 à une autre fonction du même niveau que la 
fonction dans laquelle il était réputé désigné au 1er septembre 2016, est 
désigné temporaire prioritaire, à sa demande, dans cette autre fonction, dite 
additionnelle, s''il est titulaire d''un titre requis, suffisant ou de pénurie pour 
celle-ci. Cette désignation additionnelle est subordonnée au fait que les cours 
concernés n''auraient pas dû être accrochés à la fonction dans laquelle il était 
désigné au 30 juin 2016. 
 
Inséré par D. 14-03-2019 
§ 3. Le membre du personnel visé à l''article 285, 4° ou 7°, qui dans le 
cadre de sa fonction de désignation, a dispensé pendant 150 jours au moins 
au cours des trois années scolaires précédant le 31 août 2016, des cours 
accrochés au 1er septembre 2016 à une autre fonction du même niveau que la 
fonction dans laquelle il était réputé désigné au 1er septembre 2016, peut 
valoriser, à sa demande, les jours prestés dans cette autre fonction, dite 
additionnelle, s''il est titulaire d''un titre requis, suffisant ou de pénurie pour 
celle-ci. S''il n''a pas formellement déposé sa candidature pour cette fonction 
additionnelle, il, lui est attribué, comme nombre de candidatures le nombre 
d''années scolaires pendant lesquelles il a dispensé ce cours. 
 
Inséré par D. 14-03-2019 
§ 4. Si le membre du personnel, dans une des situations décrites aux 
§§ 2 et 3 n''est pas titulaire d''un titre requis, suffisant ou de pénurie pour la 
fonction additionnelle, les cours concernés sont, à sa demande, réputés 
accrochés à la fonction dans laquelle il est désigné. 
 
Inséré par D. 14-03-2019 
§ 5. Dans l''enseignement secondaire de promotion sociale les prestations 
visées aux §§ 2 et 3 correspondent à l''exercice de 40 périodes de cours. 
 
Pour bénéficier des dispositions des §§ 2 et 3, le membre du personnel 
doit introduire sa demande avant le 31 décembre 2018. 
 
Pour bénéficier des dispositions du § 4, le membre du personnel doit 
introduire sa demande avant le 15 janvier 2019. 
 
Inséré par D. 14-03-2019 
§ 6. Pour l''application des dispositions prévues aux articles 18, 20, 24 à 
26 quater de l''arrêté royal du 22 mars 1969, relatives à la désignation à titre 
temporaire, le membre du personnel visé à l''article 285, 7°, qui, à la suite de 
la réforme des titres et fonctions n''a pas acquis le titre suffisant pour la 
fonction pour laquelle il bénéficie du régime transitoire prévu par la 
disposition susmentionnée, est classé, à la date du 1er septembre 2018, dans 
la catégorie des titres suffisants et il lui est attribué une ancienneté de 
fonction et un nombre de candidatures correspondant aux jours et au nombre 
d''années de désignations dont il a bénéficié après qu''il ait rempli les 
conditions précisée à l''article et au point susmentionné. 
 
Inséré par D. 04-02-2016 ; complété par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 268, 'Article 288bis. - Les membres du personnel visés à la présente section', 'Article 288bis. - Les membres du personnel visés à la présente section 
bénéficient de l''échelle de traitement attachée à la nouvelle fonction dans 
laquelle leur ancienneté est réputée acquise en application des dispositions 
 
 
Docu 40701 
 
D. 11-04-2014  
de la section 2 sauf si l''échelle de traitement afférente à leur fonction 
d''origine leur procure une rémunération plus élevée. 
 
Les membres du personnel visés aux articles 281, alinéa 2 et 282, alinéa 
2 conservent l''échelle de traitement dont ils bénéficiaient avant l''entrée en 
vigueur du présent décret sauf si l''échelle de traitement afférente à la 
fonction à laquelle est accroché le cours, exercée sur base d''un autre titre, 
leur procurerait une rémunération plus élevée en application des dispositions 
prévues au chapitre VI du titre II. Dans ce cas, ce barème plus avantageux 
leur est accordé pour l''exercice de ce cours.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 269, 'Article 289. - § 1er. Les services rendus par les membres du personnel', 'Article 289. - § 1er. Les services rendus par les membres du personnel 
visés par la présente section dans une fonction de cours spéciaux à la veille 
de l''entrée en vigueur du présent décret sont réputés l''avoir été dans une 
fonction de cours généraux et/ou de cours techniques selon le tableau de 
correspondance arrêté par le Gouvernement et en fonction des dispositions 
prévues à la section 2 du présent chapitre. 
 
§ 2. Les services rendus par les membres du personnel visés par la 
présente section dans une fonction de cours techniques et de pratique 
professionnelle à la veille de l''entrée en vigueur du présent décret sont 
réputés l''avoir été dans une fonction de cours techniques et/ou de cours de 
pratique professionnelle selon le tableau de correspondance arrêté par le 
Gouvernement et en fonction des dispositions prévues à la section 2 du 
présent chapitre. 
 
§ 3. Les membres du personnel visés aux § 1 et 2 conservent dans la 
nouvelle fonction le dénominateur de charge de leur fonction antérieure si 
celle-ci est plus avantageuse pour le membre du personnel. Le maintien de la 
fraction de charge initiale porte également sur les extensions de charge et les 
mesures liées à la mise en disponibilité et à la réaffectation.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 270, 'Article 290. - Lorsque l''acte de désignation ou d''engagement à titre', 'Article 290. - Lorsque l''acte de désignation ou d''engagement à titre 
temporaire d''un membre du personnel vise une activité citée à l''article 
20, § 4, du décret du 29 juillet 1992 portant organisation de l''enseignement 
secondaire de plein exercice, le pouvoir organisateur le désigne ou l''engage à 
titre temporaire dans une fonction pour laquelle le membre du personnel 
dispose d''un titre requis ou suffisant et les services prestés dans cette activité 
sont réputé l''avoir été dans cette fonction. 
 
Insérée par D. 19-10-2017 
Section 3bis - dispositions transitoires et fonctions de sélection et de 
promotion 
 
Insérée par D. 19-10-2017 ; Complété par D. 11-07-2018');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 271, 'Article 290bis. - Tout membre du personnel couvert par les mesures', 'Article 290bis. - Tout membre du personnel couvert par les mesures 
transitoires de la section 1 ou répondant aux conditions fixées à l''article 285 
de la section 3 et qui en vertu des dispositions réglementaires en matière de 
titres applicables jusqu''au 31 août 2016 était dans les conditions d''accès à 
une fonction de sélection ou de promotion est considéré comme étant encore 
dans les conditions d''accès à ces fonctions. 
 
Inséré par D. 11-07-2018 
Le membre du personnel nommé ou engagé à titre définitif dans une 
fonction de sélection ou de promotion au 31 août 2016 bénéficie également de 
 
 
Docu 40701 
 
D. 11-04-2014  
la possibilité de retourner dans une fonction de recrutement, dans le respect 
des dispositions statutaires, selon le régime de titres en vigueur avant le 1er 
septembre 2016. 
 
Section IV. - Dispositions transitoires particulières');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 272, 'Article 291. - Les décisions prises par le Ministre compétent en vertu', 'Article 291. - Les décisions prises par le Ministre compétent en vertu 
du décret du 23 janvier 2009 portant des dispositions relatives à la 
reconnaissance des qualifications professionnelles pour l''exercice de fonctions 
dans les établissements d''enseignement préscolaire, primaire, secondaire 
ordinaire et spécialisé, artistique, de promotion sociale et supérieur non 
universitaire, secondaire artistique à horaire réduit de la Communauté 
française et les internats dépendant de ces établissements, et dans les 
centres psycho-médico-sociaux, relatives au congé pour activités sportives et 
diverses mesures urgentes en matière d''enseignement portant sur une ou 
plusieurs fonction(s) existant à la veille de l''entrée en vigueur du présent 
décret sont réputées porter sur une ou plusieurs fonction(s) correspondant 
e(s) selon le tableau de correspondance arrêté par le Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 273, 'Article 292. - La chambre décisionnelle visée à l''article 48 du présent', 'Article 292. - La chambre décisionnelle visée à l''article 48 du présent 
décret dans le cadre la mission visée à l''article 39, 4°, reprend les attributions 
des Commissions visées aux articles 6 de l''arrêté royal du 30 juillet 1975 
relatif aux titres jugés suffisants dans l''enseignement secondaire dispensé 
dans les établissements libres d''enseignement moyen ou d''enseignement 
normal subventionnés, y compris l''année postsecondaire psychopédagogique, 
de l''arrêté royal du 30 juillet 1975 relatif aux titres jugés suffisants dans 
l''enseignement secondaire dispensé dans les établissements d''enseignement 
moyen ou d''enseignement normal officiels subventionnés, de l''arrêté royal du 
30 juillet 1975 relatif aux titres jugés suffisants dans les établissements 
subventionnés d''enseignement technique et d''enseignement professionnel 
secondaire de plein exercice et de promotion sociale, à l''article 6 de l''arrêté 
royal du 20 juin 1975 relatif aux titres suffisants dans l''enseignement 
gardien et primaire, pour toute demande introduite avant le 1er septembre 
2016 auprès desdites Commissions. 
 
Tant que la chambre décisionnelle visée à l''article 48 du présent décret 
n''est pas fonctionnelle, les Commissions visées à l''alinéa précédent 
continuent à fonctionner selon les dispositifs réglementaires antérieurs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 274, 'Article 293. - A titre transitoire, dans le cadre des accroches', 'Article 293. - A titre transitoire, dans le cadre des accroches 
cours/fonction multiples arrêtées par le Gouvernement lors de l''entrée en 
vigueur du présent décret, pour les accroches cours/fonction multiples qui 
associent une fonction de cours généraux (CG) et une fonction de cours 
techniques (CT) dont la fonction de cours généraux (CG) est activée 
majoritairement par les pouvoirs organisateurs conformément à l''article 13 
du présent décret, le § 3 de ce même article n''est pas applicable aux pouvoirs 
organisateurs ayant activé uniquement la fonction de cours généraux (CG). 
 
Le bénéfice de la présente disposition transitoire ne s''applique qu''aux 
membres du personnel prestant, de manière ininterrompue, depuis l''entrée 
en vigueur du présent décret, une fonction de cours techniques (CT) dans le 
cadre des accroches cours/fonctions multiples visée à l''alinéa 1er. De plus, ces 
fonctions de cours techniques (CT) ne sont plus activables par le Pouvoir 
organisateur concerné et n''ouvrent plus de droit au traitement ou à la 
subvention-traitement, dès que le membre du personnel prestant cette 
 
 
Docu 40701 
 
D. 11-04-2014  
fonction quitte les positions administratives d''activité de service ou de 
disponibilité pour maladie. 
 
Pour le 1er janvier 2016, le Gouvernement arrête, sur proposition de la 
Commission, la liste des accroches cours/fonctions multiples concernées par 
les alinéas 1 et 2. 
 
Inséré par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 275, 'Article 293', 'Article 293/1. - En cas de déclassement d''un titre de capacité, le 
membre du personnel nommé, engagé à titre définitif, porteur dudit titre 
continue à bénéficier de l''échelle de traitement antérieure au déclassement 
de son titre. 
 
Ces mêmes membres du personnel conservent le droit d''étendre leur 
charge selon les modalités prévalant avant le déclassement de leur titre. 
 
Inséré par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 276, 'Article 293', 'Article 293/2. - En cas de déclassement d''un titre de capacité, le 
membre du personnel temporaire prioritaire ou protégé porteur dudit titre 
continue à bénéficier de l''échelle de traitement antérieure au déclassement 
de son titre. 
 
Ces mêmes membres du personnel conservent la possibilité d''être 
nommés, engagés à titre définitif, ainsi que désignés en qualité de 
temporaire, temporaire prioritaire ou protégé dans les conditions statutaires 
prévalant avant le déclassement de leur titre. 
 
Inséré par D. 19-10-2017 ; modifié par D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 277, 'Article 293', 'Article 293/3. - Le Gouvernement est habilité à arrêter, sur proposition 
de la Commission visée à l''article 38, un tableau de correspondance des 
fonctions reprenant les modifications opérées au niveau de l''accroche cours-
fonction dans le cadre de l''article 39, alinéa 2, 2°. Les règles reprises aux 
sections 1 et 2 du présent chapitre s''appliquent à ce tableau de 
correspondance en prenant en considération, au lieu des 31 août et 1er 
septembre 2016, les veilles et premier jour de l''année scolaire au cours de 
laquelle l''accroche cours-fonction nouvelle prend effet. 
 
Inséré par D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 278, 'Article 293', 'Article 293/4. - Les membres du personnel ayant bénéficié du 
mécanisme d''assimilation prévu à l''ancien article 37, § 2bis, bénéficient du 
mécanisme dérogatoire prévu à l''article 36, § 3. 
 
Insérée par D. 30-06-2016 
Section V.  - Dispositions transitoires propres aux fonctions de 
religion et de morale non confessionnelle  
 
Inséré par D. 30-06-2016 ; complété par D. 19-07-2017 ; modifié par D. 
14-03-2019 ; D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 279, 'Article 293bis. (partie 1)', 'Article 293bis. § 1er.- Par mesure transitoire, et au plus tard jusqu’au [premier jour de l''année scolaire 2026-2027]16, les titres suivants peuvent tenir lieu du certificat visé à l’article 24bis du présent décret : A. Culte protestant 16Remplacé par le D. 16-05-2024 Docu 40701 D. 11-04-2014 1° Enseignement secondaire du degré supérieur : a) le diplôme de licencié en théologie protestante délivré par la Faculté de théologie protestante de Bruxelles; b) le diplôme d''agrégé d''enseignement religieux protestant du degré secondaire supérieur; c) le diplôme d''agrégé de l''enseignement secondaire supérieur; d) le diplôme de professeur d''école normale, de licencié en pédagogie, de licencié en sciences pédagogiques, de licencié en sciences psychologiques et pédagogiques et de licencié en sciences de l''éducation; e) le grade légal ou scientifique de licencié ou d’ingénieur obtenu après quatre années d''études dans une université, une faculté ou un centre universitaire; f) le certificat d''études en vue de l''enseignement religieux délivré après quatre années d''études par la Faculté de théologie protestante de Bruxelles. 2° Enseignement secondaire du degré inférieur : a) le diplôme d''agrégé d''enseignement religieux protestant du degré secondaire inférieur; b) le diplôme de candidat en théologie protestante délivré après deux années par la Faculté de théologie protestante de Bruxelles; c) le diplôme d''agrégé de l''enseignement secondaire inférieur; d) le diplôme de gradué complété par un certificat d''aptitudes pédagogiques délivré par le jury de la Communauté française institué à cette fin, un certificat de cours normaux techniques moyens, un diplôme d''aptitudes pédagogiques ou un certificat d''aptitude pédagogique délivré par un établissement d''enseignement de promotion sociale ; e) le diplôme, à titre légal ou scientifique, de candidat délivré après deux années d''études par une université, une faculté ou un centre universitaire; f) le diplôme de capacité pédagogique, ou le certificat de compétence pour l''enseignement du degré secondaire inférieur, délivré par le chef du culte ; g) un des titres cités au 1°, b) c), d), e) et f). 3° Enseignement primaire : a) le diplôme d''enseignement religieux protestant du degré inférieur; b) le diplôme d''instituteur primaire; c) le diplôme d''institutrice gardienne complété par le certificat de compétence pour l''enseignement primaire, délivré par le chef du culte; d) le diplôme de fin d''études secondaires du degré supérieur complété par le certificat de compétence délivré par le chef du culte; e) le certificat de compétence pour l''enseignement primaire, délivré par le chef du culte ; f) un des titres cités au 1°, a,), b), c), d), e) et f) et au 2°, a) b), c),d) et e). B. Culte israélite 1° Enseignement secondaire au degré supérieur. a) la maîtrise en histoire, pensée et civilisation juives, délivrée par une université belge ou étrangère, complétée par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le Docu 40701 D. 11-04-2014 président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; b) le diplôme de licence spéciale en histoire, pensée et civilisation juives, délivré par une université belge ou étrangère, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; c) le diplôme de docteur, de licencié ou d’ingénieur, en quelque matière que ce soit, délivré par une université belge ou étrangère, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; d) le diplôme délivré par une école talmudique (Yeshiva) ou un séminaire d''enseignement religieux israélite, belge ou étranger, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; e) le diplôme supérieur en histoire, pensée et civilisation juives, délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 280, 'Article 293bis. (partie 2)', 'Consistoire; f) le certificat en histoire, pensée et civilisation juives, délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; g) le certificat spécial en langue et littérature hébraïques contemporaines délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; h) le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire supérieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire. 2° Enseignement secondaire au degré inférieur. a) la maîtrise en histoire, pensée et civilisation juives, délivrée par une université belge ou étrangère, complétée par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; b) le diplôme de licence spéciale en histoire, pensée et civilisation juives, délivré par une université belge ou étrangère, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement Docu 40701 D. 11-04-2014 par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; c) le diplôme de docteur, de licencié ou d’ingénieur, en quelque matière que ce soit, délivré par une université belge ou étrangère, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; d) le diplôme de gradué complété par un certificat d''aptitudes pédagogiques délivré par le jury de la Communauté française institué à cette fin, un certificat de cours normaux techniques moyens, un diplôme d''aptitudes pédagogiques ou un certificat d''aptitude pédagogique délivré par un établissement d''enseignement de promotion sociale et par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le grand rabbin attaché au Consistoire; e) le diplôme délivré par une école talmudique (Yeshiva) ou un séminaire d''enseignement religieux israélite, belge ou étranger, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; f) le diplôme supérieur en histoire, pensée et civilisation juives, délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; g) le certificat en histoire, pensée et civilisation juives, délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; h) le certificat spécial en langue et littérature hébraïques contemporaines délivré par l''Institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; i) le certificat en histoire juive, délivré par l''In');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 281, 'Article 293bis. (partie 3)', 'd''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; j) le certificat en pensée et civilisation juives, délivré par l''institut d''études du judaïsme, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; k) le certificat d''aptitude à l''enseignement religieux israélite au degré secondaire inférieur, délivré par le Consistoire central israélite de Belgique Docu 40701 D. 11-04-2014 et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire. 3° Enseignement primaire. a) le diplôme d''instituteur primaire, complété par le certificat d''aptitude à l''enseignement religieux israélite au degré primaire, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; b) le certificat d''aptitude à l''enseignement religieux israélite au degré primaire, délivré par le Consistoire central israélite de Belgique et signé conjointement par le président du Consistoire central israélite de Belgique et le grand rabbin de Belgique ou le rabbin attaché au Consistoire; c) les titres prévus aux points f), g, h), i) et j) du point 2°. C. Culte orthodoxe 1° Enseignement secondaire du degré supérieur: a) le diplôme de licencié(e) en théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; b) le certificat portant sur au moins quatre années de théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; c) le diplôme d''agrégé(e) de l''enseignement secondaire supérieur complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique ; d) le diplôme de licencié ou d''ingénieur délivré après quatre années d''études au moins dans une université, un centre universitaire, un institut ou une Haute Ecole en Belgique ou à l''étranger complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique. 2° Enseignement secondaire du degré inférieur: a) le diplôme de licencié(e) en théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; b) le certificat portant sur au moins trois années de théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; c) le diplôme d''agrégé(e) de l''enseignement secondaire inférieur complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique; d) le diplôme d''agrégé(e) de l''enseignement secondaire supérieur complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique ; e) le diplôme de gradué complété par un certificat d''aptitudes pédagogiques délivré par le jury de la Communauté française institue à cette fin, un certificat de cours normaux techniques moyens, un diplôme d''aptitudes pédagogiques ou un certificat d''aptitude pédagogique délivré par un établissement d''enseignement de promotion sociale et par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique. Docu 40701 D. 11-04-2014 3° Enseignement primaire: a) le diplôme d''instituteur en théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; b) le certificat portant sur au moins deux années de théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; c) le diplôme d''agrégé(e) de l''enseignement secondaire inférieur complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique; d) le diplôme de licencié(e) en théologie orthodoxe délivré par un institut/une université de théologie reconnu(e) par la commission pédagogique de l''Eglise orthodoxe en Belgique; e) le diplôme d''agrégé(e) de l''enseignement secondaire supérieur complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique; f) le diplôme d''instituteur primaire complété par le certificat de reconnaissance de la com');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 282, 'Article 293bis. (partie 4)', 'pédagogique de l''Eglise orthodoxe en Belgique; g) le diplôme d''institutrice maternelle complété par le certificat de reconnaissance de la commission pédagogique de l''Eglise orthodoxe en Belgique. D. Culte islamique 1° Enseignement secondaire du degré supérieur : a) le diplôme de licencié en théologie islamique délivré par une université, un institut ou une faculté de théologie islamique en Belgique ou à l''étranger complété par un certificat ou un diplôme pédagogique, reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique, b) le diplôme d''agrégé de l''enseignement secondaire supérieur complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique; c) le diplôme de licencié ou d’ingénieur obtenu après quatre années d''études au moins dans une université, un centre universitaire, un institut ou une Haute Ecole en Belgique ou à l''étranger, complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique et par un certificat ou un diplôme d''aptitude pédagogique reconnus ou délivrés l''un et l''autre par la commission pédagogique de l''Exécutif des Musulmans de Belgique ; d) le diplôme de licencié en pédagogie, de licencié en sciences psychologiques et de licencié en sciences d''éducation, complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique. 2° Enseignement secondaire du degré inférieur : a) le diplôme de licencié en théologie islamique délivré par une université, un institut ou une faculté de théologie islamique en Belgique ou à l''étranger complété par un certificat ou un diplôme pédagogique, reconnu ou Docu 40701 D. 11-04-2014 délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique; b) le diplôme d''agrégé de l''enseignement secondaire inférieur complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique; c) le diplôme de gradué complété par un certificat d''aptitudes pédagogiques délivré par le jury de la Communauté française institué à cette fin, un certificat de cours normaux techniques moyens, un diplôme d''aptitudes pédagogiques ou un certificat d''aptitude pédagogique délivré par un établissement d''enseignement de promotion sociale et par un certificat ou un diplôme d''aptitude à enseignement religieux islamique reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique ; d) le diplôme de candidat délivré après deux années d''études au moins par une université, un centre universitaire, un institut ou une Haute Ecole en Belgique, complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique et par un certificat ou un diplôme d''aptitude pédagogique reconnus ou délivrés l''un et l''autre par la commission pédagogique de l''Exécutif des Musulmans de Belgique; e) le diplôme de gradué complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique et par un certificat ou un diplôme d''aptitude pédagogique reconnus ou délivrés l''un et l''autre par la commission pédagogique de l''Exécutif des Musulmans de Belgique ; f) un des diplômes cités au 1, points b) c), d). 3° Enseignement primaire : a) le diplôme d''instituteur primaire complété un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique; b) le diplôme de licencié en théologie islamique délivré par une université, un institut ou une faculté de théologie islamique en Belgique ou à l''étranger complété par un certificat ou un diplôme pédagogique, reconnu ou délivré par la commission pédagogique de l''Exécutif des Musulmans de Belgique ; c) le diplôme de fin d''études secondaires du degré supérieur complété par un certificat ou un diplôme d''aptitude à l''enseignement religieux islamique et par un certificat ou un diplôme d''aptitude pédagogique reconnus ou délivrés l''un et l''autre par la commission pédagogique de l''Exécutif des Musulmans de Belgique ; d) un des diplômes cités au 1°, points a) b), c), et d) et au 2, points b) c), d), et e). E. Culte catholique 1° Enseignement secondaire du degré supérieur : a) le diplôme d''agrégé d''enseignement religieux du degré secondaire supérieur, délivré par un Institut supérieur des sciences religieuses; b) le diplôme de licencié, délivré par la Faculté de théologie de l''Université catholique de Louvain; c) le diplôme d''agrégé de l''enseignement secondaire supérieur; d) le diplôme de professeur d''école normale, de licencié en pédagogie, de licencié en sciences pédagogiques, de licencié en sciences psychologiques et pédagogiques et de licencié en sciences de l''éducation; Docu 40701 D. 11-04-2014 e) le grade légal ou scientifique de');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 283, 'Article 293bis. (partie 5)', 'licencié ou d’ingénieur obtenu après quatre années d''études dans une université, une faculté ou un centre universitaire. 2° Enseignement secondaire du degré inférieur : a) le diplôme d''agrégé d''enseignement religieux du degré secondaire supérieur, délivré par un institut supérieur de sciences religieuses; b) le diplôme d''agrégé ou de gradué d''enseignement religieux du degré secondaire inférieur ; c) le diplôme d''agrégé de l''enseignement secondaire inférieur; d) le diplôme de gradué complété par un certificat d''aptitudes pédagogiques délivré par le jury de la Communauté française institué à cette fin, un certificat de cours normaux techniques moyens, un diplôme d''aptitudes pédagogiques ou un certificat d''aptitude pédagogique délivré par un établissement d''enseignement de promotion sociale ; e) un certificat portant sur deux années de philosophie et au moins deux années de théologie, suivies avec fruit dans un séminaire organisé ou reconnu comme équivalent par le chef du culte; f) le diplôme, à titre légal ou scientifique, de candidat délivré après deux années d''études par une université, une faculté ou un centre universitaire; g) un des titres cités au 1°, b), c), d) et e). 3° Enseignement primaire : a) le certificat de diplômé d''enseignement religieux du degré inférieur; b) le diplôme d''instituteur primaire ; c) un certificat portant sur deux années de philosophie et au moins une année de théologie, suivies avec fruit dans un séminaire organisé ou reconnu comme équivalent par le chef du culte; d) un des titres cités au 2°, b), c), d), et f). § 2. - Parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l’enseignement supérieur et l’organisation académique des études, peuvent également tenir lieu du certificat visé à l’article 24bis du présent décret, ceux qui ont leur correspondant au paragraphe précédent. Inséré par D. 19-07-2017 ; complété par D. 19-07-2021 § 3. Le membre du personnel dont le titre de capacité fixé par le Gouvernement, pour l''exercice de la fonction de maître ou professeur de religion, exige la possession du certificat prévu à l''article 24bis, alinéa 2, en ce compris les membres du personnel porteurs d''un des titres visés au § 1er du présent article, ne pourra être nommé que lorsqu''il sera détenteur de ce certificat. Par dérogation, durant la même période, les membres du personnel porteurs d''un titre classé antérieurement à l''entrée en vigueur du présent décret comme titre requis pour l''exercice de ces fonctions peuvent y être nommés ou engagés à titre définitif dès qu''ils répondent à toutes les autres conditions statutaires. Docu 40701 D. 11-04-2014 Inséré par D. 30-06-2016 ; complété par D. 19-07-2017 ; modifié par D. 14-03-2019 ; D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 284, 'Article 293ter. - Par mesure transitoire, dans l’attente de la création', 'Article 293ter. - Par mesure transitoire, dans l’attente de la création 
des certificats prévus à l’article 24bis, alinéa 2 du présent décret et au plus 
tard jusqu’au [le premier jour de l''année scolaire 2026-2027]17, la possession 
de ces certificats pour l’exercice des fonctions de morale n’est pas exigée. 
 
Le membre du personnel dont le titre de capacité fixé par le 
Gouvernement, pour l''exercice de la fonction de maître ou professeur de 
morale non confessionnelle, exige la possession du certificat prévu à l''article 
24bis, alinéa 2, ne pourra être nommé que lorsqu''il sera détenteur de ce 
certificat. 
 
Par dérogation, durant la même période, les membres du personnel 
porteurs d''un titre classé antérieurement à l''entrée en vigueur du présent 
décret comme titre requis pour l''exercice de ces fonctions peuvent y être 
nommés ou engagés à titre définitif dès qu''ils répondent à toutes les autres 
conditions statutaires. 
 
Inséré par D. 30-06-2016 ; modifié par D. 14-03-2019 ; D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 285, 'Article 293quater. -  [Le premier jour de l''année scolaire 2026-2027]18,', 'Article 293quater. -  [Le premier jour de l''année scolaire 2026-2027]18, 
les membres du personnel nommés ou engagés à titre définitif, stagiaires ou 
temporaires prioritaires ou protégés, ayant bénéficié de la mesure prévue à 
l’article 293bis ou à l’article 293ter, peuvent conserver leur nomination ou 
leur engagement à titre définitif ou leur statut de stagiaire, de temporaire 
prioritaire ou protégé. 
 
Inséré par D. 30-06-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 286, 'Article 293quinquies.', 'Article 293quinquies.  Les membres du personnel recrutés ou engagés 
à titre temporaire ou nommés ou engagés à titre définitif dans une fonction 
religion avant l’entrée en vigueur du présent décret sont réputés être en 
possession du visa visé à l’article 24 ter du présent décret 
 
Insérée par D. 13-07-2016 
Section VI. - Dispositions transitoires propres à la fonction de maître 
