INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 287, 'Article 293sexies. - Dans l''arrêté royal du 22 mars 1969 fixant le', 'Article 293sexies. - Dans l''arrêté royal du 22 mars 1969 fixant le 
