INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 288, 'Article 169ter. - Le candidat à une désignation à titre temporaire à la', 'Article 169ter. - Le candidat à une désignation à titre temporaire à la 
fonction de maître de morale ayant répondu à l''appel de janvier 2016 et 
ayant acquis une ancienneté de fonction de 150 jours au moins, dans cette 
fonction 
au 
cours 
de 
l''année 
scolaire 
2015-2016, 
peut 
se porter 
volontairement candidat à une désignation à la fonction de maître de 
philosophie et de citoyenneté et se voir confier cette fonction, pour autant 
que : 
1° au moment de cet appel, il soit porteur d''au moins un diplôme 
d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant 
parmi les titres délivrés en application du décret du 7 novembre 2013 
définissant le paysage de l''enseignement supérieur et l''organisation 
académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale ou réussi l''unité d''enseignement 
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
Le candidat qui a fait régulièrement acte de candidature dans le cadre 
des dispositions du présent article à la fonction de maître de philosophie et de 
citoyenneté, est repris dans le classement des candidats à cette fonction en 
bénéficiant de l''ensemble des candidatures dont il dispose dans la fonction de 
maître de morale, le cas échéant. 
 
Le candidat qui dispose en outre d''un titre pédagogique - conformément 
aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française - lorsqu''il se porte volontaire à 
une désignation à la fonction de maître de philosophie et de citoyenneté est 
repris dans un classement distinct, selon les modalités prévues à l''alinéa 
précédent, et bénéficie d''une priorité de désignation dans cette fonction par 
rapport aux candidats ne disposant d''un tel titre. 
 
La désignation à titre temporaire dans cette fonction de maître de 
philosophie et de citoyenneté ne pourra en aucun cas être reconduite après le 
1er septembre 2020 si le candidat ne répond pas à cette date aux conditions 
suivantes : 
1° avoir acquis un titre pédagogique, conformément aux articles 17 et 18 
du décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française; 
 
 
Docu 40701 
 
D. 11-04-2014  
2° avoir acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 289, 'Article 169quater. - Avant le 1er septembre 2020, toute candidat en', 'Article 169quater. - Avant le 1er septembre 2020, toute candidat en 
qualité de temporaire prioritaire à la fonction de maître de morale peut se 
porter volontairement candidat à une désignation, en qualité de temporaire 
prioritaire, à la fonction de maître de philosophie et de citoyenneté, pour 
autant que : 
1° il soit porteur d''au moins un diplôme d''instituteur, de bachelier, de 
graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en 
application du décret du 7 novembre 2013 définissant le paysage de 
l''enseignement supérieur et l''organisation académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale ou réussi l''unité d''enseignement 
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
Les candidats temporaires prioritaires qui disposent en outre d''un titre 
pédagogique - conformément aux articles 17 et 18 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française - lorsqu''ils 
se portent volontaire à une désignation à la fonction de maître de philosophie 
et de citoyenneté sont repris dans un classement distinct, selon les modalités 
prévues à l''alinéa précédent, et bénéficient d''une priorité de désignation dans 
cette fonction par rapport aux candidats ne disposant d''un tel titre. 
 
La nomination dans cette fonction de maître de philosophie et de 
citoyenneté ne pourra intervenir pour autant que le membre du personnel 
ait, avant le 1er septembre 2020 : 
1° acquis un titre pédagogique, conformément aux articles 17 et 18 du 
décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française; 
2° acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française, pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige. 
 
 
 
Docu 40701 
 
D. 11-04-2014');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 290, 'Article 169quinquies. - Avant le 1er septembre 2020, tout membre du', 'Article 169quinquies. - Avant le 1er septembre 2020, tout membre du 
personnel nommé à titre définitif dans une fonction de maître de morale peut 
demander à exercer une fonction de maître de philosophie et de citoyenneté 
et pourra se voir confier dans cette fonction, sur proposition d''une 
commission zonale ou de la commission interzonale visée au chapitre IIbis du 
présent arrêté royal, un nombre de périodes au maximum égal à celui pour 
lequel il est rétribué, et que : 
1° il soit porteur d''au moins un diplôme d''instituteur, de bachelier, de 
graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en 
application du décret du 7 novembre 2013 définissant le paysage de 
l''enseignement supérieur et l''organisation académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale ou réussi l''unité d''enseignement 
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
La période visée à l''alinéa 1er pendant laquelle le membre du personnel 
nommé à titre définitif dans une fonction de maître de philosophie et de 
citoyenneté exerce la fonction de maître de philosophie et de citoyenneté 
avant qu''il ne puisse y être nommé est assimilée à un rappel à l''activité de 
service à durée indéterminée. 
 
La nomination dans cette fonction de maître de philosophie et de 
citoyenneté ne pourra intervenir pour autant que le membre du personnel 
ait, avant le 1er septembre 2020 acquis le certificat en didactique du cours de 
philosophie et de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 
avril 2014 réglementant les titres et fonctions dans l''enseignement 
fondamental et secondaire organisé et subventionné par la Communauté 
française pour autant que le titre de capacité fixé par le Gouvernement, pour 
l''exercice de cette fonction, l''exige.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 291, 'Article 169sexies. - § 1er. La fonction de maître de philosophie et de', 'Article 169sexies. - § 1er. La fonction de maître de philosophie et de 
citoyenneté devra être confiée aux membres du personnel visés aux articles 
129ter à 129quinquies dans la limite des périodes que ces membres du 
personnel perdent du fait d''une réduction des périodes de cours 
philosophiques suite à la création du cours de philosophie et de citoyenneté 
au 1er octobre 2016. 
 
Lorsqu''après application de l''alinéa 1er, des périodes de philosophie et 
citoyenneté restent disponibles, elles sont attribuées aux membres du 
personnel visés aux articles 129ter à 129quinquies sans pour autant qu''un 
membre du personnel puisse, au total des périodes de philosophie et 
citoyenneté et des périodes de morale non confessionnelle qui lui sont 
attribuées, se voir confier un nombre de périodes supérieur au nombre de 
 
 
Docu 40701 
 
D. 11-04-2014  
périodes de morale non confessionnelle qui lui étaient attribuées au 30 juin 
2016. 
 
Lorsqu''après application des alinéas 1er et 2, des périodes de philosophie 
et citoyenneté restent disponibles, elles sont attribuées conformément au 
présent décret et au décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé par la 
Communauté française et à ses arrêtés d''application. 
 
§ 2. La fonction de maître de morale et celle de maître de philosophie et 
de citoyenneté ne peuvent être exercées que dans deux établissements 
différents ou, par dérogation au décret du 31 mars 1994 définissant la 
neutralité de l''enseignement de la Communauté, dans deux implantations 
distinctes d''un même établissement. 
 
Par dérogation à l''alinéa 1er et uniquement dans le cadre de l''application 
du § 1er, alinéa 1er aux membres du personnel visés aux articles 129ter à 
129quinquies, un membre du personnel peut exercer les deux fonctions 
susvisées dans la même implantation, mais pas dans la même classe, pour 
autant que le respect de l''incompatibilité visée à l''alinéa 1er conduise le 
membre du personnel concerné à exercer sa fonction de philosophie et 
citoyenneté et celle de morale non confessionnelle dans plus de 6 
implantations ou à devoir assurer, pour se rendre dans chaque implantation 
concernée, un déplacement de plus 25 km depuis son domicile ou entraînant 
une durée de déplacement supérieure à quatre heures par jour, à l''aide des 
transports en commun. 
 
Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 292, 'Article 293septies. - Dans l''arrêté royal du 25 octobre 1971 fixant le', 'Article 293septies. - Dans l''arrêté royal du 25 octobre 1971 fixant le 
statut des maîtres de religion, des professeurs de religion et des inspecteurs 
de religion des religions catholique, protestante, israélite, orthodoxe, et 
islamique des établissements d''enseignement de la Communauté française, 
est inséré un chapitre Xbis rédigé comme suit : 
 
«CHAPITRE Xbis. - Dispositions transitoires et dérogatoires 
relatives à la création de la fonction de maître de philosophie et de 
citoyenneté.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 293, 'Article 49ter. - Le candidat à une désignation à titre temporaire à la', 'Article 49ter. - Le candidat à une désignation à titre temporaire à la 
fonction de maître de religion ayant répondu à l''appel de janvier 2016 et 
ayant acquis une ancienneté de fonction de 150 jours au moins, dans cette 
fonction 
au 
cours 
de 
l''année scolaire 
2015-2016, 
peut 
se porter 
volontairement candidat à une désignation à la fonction de maître de 
philosophie et de citoyenneté et se voir confier cette fonction, pour autant 
que : 
1° au moment de cet appel, il soit porteur d''au moins un diplôme 
d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant 
parmi les titres délivrés en application du décret du 7 novembre 2013 
définissant le paysage de l''enseignement supérieur et l''organisation 
académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale ou réussi l''unité d''enseignement 
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 
 
Docu 40701 
 
D. 11-04-2014  
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
Le candidat qui a fait régulièrement acte de candidature dans le cadre 
des dispositions du présent article à la fonction de maître de philosophie et de 
citoyenneté, est repris dans le classement des candidats à cette fonction en 
bénéficiant de l''ensemble des candidatures dont il dispose dans la fonction de 
maître de religion, le cas échéant. 
 
Le candidat qui dispose en outre d''un titre pédagogique - conformément 
aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française - lorsqu''il se porte volontaire à 
une désignation à la fonction de maître de philosophie et de citoyenneté est 
repris dans un classement distinct, selon les modalités prévues à l''alinéa 
précédent, et bénéficie d''une priorité de désignation dans cette fonction par 
rapport aux candidats ne disposant d''un tel titre. 
 
La désignation à titre temporaire dans cette fonction de maître de 
philosophie et de citoyenneté ne pourra en aucun cas être reconduite après le 
1er septembre 2020 si le candidat ne répond pas à cette date aux conditions 
suivantes : 
1° avoir acquis un titre pédagogique, conformément aux articles 17 et 18 
du décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française; 
2° avoir acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française, pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 294, 'Article 49quater. - Avant le 1er septembre 2020, tout candidat en', 'Article 49quater. - Avant le 1er septembre 2020, tout candidat en 
qualité de stagiaire à la fonction de maître de religion peut se porter 
volontairement candidat à une désignation, en qualité de temporaire 
prioritaire, à la fonction de maître de philosophie et de citoyenneté pour 
autant que le candidat stagiaire ait atteint le nombre de jours de service fixés 
conformément aux articles 30 et 34 de l''arrêté royal du 22 mars 1969 pour 
être désigné temporaire prioritaire et que : 
1° il soit porteur d''au moins un diplôme d''instituteur, de bachelier, de 
graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en 
application du décret du 7 novembre 2013 définissant le paysage de 
l''enseignement supérieur et l''organisation académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale et réussi l''unité d''enseignement 
 
 
Docu 40701 
 
D. 11-04-2014  
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
Les candidats temporaires prioritaires qui disposent en outre d''un titre 
pédagogique - conformément aux articles 17 et 18 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française - lorsqu''ils 
se portent volontaire à une désignation à la fonction de maître de philosophie 
et de citoyenneté sont repris dans un classement distinct, selon les modalités 
prévues à l''alinéa précédent, et bénéficient d''une priorité de désignation dans 
cette fonction par rapport aux candidats ne disposant d''un tel titre. 
 
La nomination dans cette fonction de maître de philosophie et de 
citoyenneté ne pourra intervenir pour autant que le membre du personnel 
ait, avant le 1er septembre 2020 : 
1° acquis un titre pédagogique, conformément aux articles 17 et 18 du 
décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française; 
2° acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 295, 'Article 49quinquies. - Avant le 1er septembre 2020, tout membre du', 'Article 49quinquies. - Avant le 1er septembre 2020, tout membre du 
personnel nommé à titre définitif dans une fonction de maître de religion 
peut demander à exercer une fonction de maître de philosophie et de 
citoyenneté et pourra se voir confier dans cette fonction, sur proposition d''une 
commission d''affectation visée au chapitre IIbis du présent arrêté royal, un 
nombre de périodes au maximum égal à celui pour lequel il est rétribué, et 
que : 
1° il soit porteur d''au moins un diplôme d''instituteur, de bachelier, de 
graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en 
application du décret du 7 novembre 2013 définissant le paysage de 
l''enseignement supérieur et l''organisation académique des études; 
2° il ait, avant le 1er octobre 2016, bénéficié d''une formation à la 
neutralité via sa formation initiale ou réussi l''unité d''enseignement 
«formation à la neutralité» organisée par l''enseignement de promotion 
sociale. Pour cette unité d''enseignement : 
 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, 
d''apporter la preuve de sa demande d''inscription; 
 b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à 
la première organisation suivante de l''unité d''enseignement et à la suivante 
 
 
Docu 40701 
 
D. 11-04-2014  
encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, 
en cas de nouvel échec. 
 
Les membres du personnel diplômés de l''enseignement officiel organisé 
ou subventionné par la Communauté française au plus tard durant l''année 
scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la 
neutralité visée à l''alinéa 1er, 2°. 
 
La période visée à l''alinéa 1er pendant laquelle le membre du personnel 
nommé à titre définitif dans une fonction de maître exerce la fonction de 
maître de philosophie et de citoyenneté avant qu''il ne puisse y être nommé 
est assimilée à un rappel à l''activité de service à durée indéterminée. 
 
La nomination dans cette fonction de maître de philosophie et de 
citoyenneté ne pourra intervenir pour autant que le membre du personnel 
ait, avant le 1er septembre 2020 acquis le certificat en didactique du cours de 
philosophie et de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 
avril 2014 réglementant les titres et fonctions dans l''enseignement 
fondamental et secondaire organisé et subventionné par la Communauté 
française, pour autant que le titre de capacité fixé par le Gouvernement, pour 
l''exercice de cette fonction, l''exige.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 296, 'Article 49sexies. - § 1er. La fonction de maître de philosophie et de', 'Article 49sexies. - § 1er. La fonction de maître de philosophie et de 
citoyenneté devra être confiée aux membres du personnel visés aux articles 
49ter à 49quinquies dans la limite des périodes que ces membres du 
personnel perdent du fait d''une réduction des périodes de cours 
philosophiques suite à la création du cours de philosophie et de citoyenneté 
au 1er octobre 2016. 
 
Lorsqu''après application de l''alinéa 1er, des périodes de philosophie et 
citoyenneté restent disponibles, elles sont attribuées aux membres du 
personnel visés aux articles 49ter à 49quinquies sans pour autant, qu''un 
membre du personnel puisse, au total des périodes de philosophie et 
citoyenneté et des périodes de religion qui lui sont attribuées, se voir confier 
un nombre de périodes supérieur au nombre de périodes de religion qui lui 
étaient attribuées au 30 juin 2016. 
 
Lorsqu''après application des alinéas 1er et 2, des périodes de philosophie 
et citoyenneté restent disponibles, elles sont attribuées conformément au 
présent décret et au décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé par la 
Communauté française et à ses arrêtés d''application. 
 
§ 2. La fonction de maître de religion et celle de maître de philosophie et 
de citoyenneté ne peuvent être exercées que dans deux établissements 
différents ou, par dérogation au décret du 31 mars 1994 définissant la 
neutralité de l''enseignement de la Communauté, dans deux implantations 
distinctes d''un même établissement. 
 
Par dérogation à l''alinéa 1er et uniquement dans le cadre de l''application 
du § 1er, alinéa 1er aux membres du personnel visés aux articles 49ter à 
49quinquies, un membre du personnel peut exercer les deux fonctions 
susvisées dans la même implantation, mais pas dans la même classe, pour 
autant que le respect de l''incompatibilité visée à l''alinéa 1er conduise le 
membre du personnel concerné à exercer sa fonction de philosophie et 
citoyenneté et celle de religion dans plus de 6 implantations ou à devoir 
 
 
Docu 40701 
 
D. 11-04-2014  
assurer, pour se rendre dans chaque implantation concernée, un déplacement 
de plus 25 km depuis son domicile ou entraînant une durée de déplacement 
supérieure à quatre heures par jour, à l''aide des transports en commun. 
 
Insérée par D. 13-07-2016 
Sous-section 2 : dispositions transitoires propres à l''enseignement 
officiel subventionné 
 
Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 297, 'Article 293octies. - § 1er. Lors de sa création au 1er octobre 2016, et par (partie 1)', 'Article 293octies. - § 1er. Lors de sa création au 1er octobre 2016, et par dérogation aux règles statutaires prévues au chapitre III du décret du 6 juin 1994 fixant le statut des membres du personnel subsidié de l''enseignement officiel subventionné, la fonction de maître de philosophie et de citoyenneté devra être confiée au sein du Pouvoir Organisateur, aux membres de son personnel, - dans la limite des périodes que ces membres du personnel perdent du fait d''une réduction des périodes de cours philosophiques suite à la création du cours de philosophie et de citoyenneté au 1er octobre 2016 - selon l''ordre prévu au § 2 à l''exception du 2°. Lorsqu''après application de l''alinéa 1er, des périodes de philosophie et citoyenneté restent disponibles, elles sont attribuées selon l''ordre prévu au § 2, sans pour autant, qu''un membre du personnel puisse, au total des périodes de philosophie et citoyenneté et des périodes de religion ou de morale non confessionnelle qui lui sont attribuées, se voir confier un nombre de périodes supérieur au nombre de périodes de religion ou de morale non confessionnelle qui lui étaient attribuées au 30 juin 2016. Lorsqu''après application des alinéas 1er et 2, des périodes de philosophie et citoyenneté restent disponibles, elles sont attribuées conformément aux décrets du 6 juin 1994 susvisé et du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé par la Communauté française et à ses arrêtés d''application. § 2. L''ordre d''attribution est le suivant : 1° au(x) membre(s) de son personnel nommé(s) à titre définitif à la veille de l''entrée en vigueur du présent décret, dans une fonction de maître de religion ou de morale non confessionnelle et qui, du fait d''une réduction des périodes de cours philosophiques suite à la création du cours de philosophie et de citoyenneté au 1er octobre 2016 par le décret du 22 octobre 2015 relatif à l''organisation d''un cours et d''une éducation à la philosophie et à la citoyenneté, devraient être mis en disponibilité par défaut d''emploi ou en perte partielle de charge par l''application des mesures préalables, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement ou pour cette dernière : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante Docu 40701 D. 11-04-2014 encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 1°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006 relatif au statut des maîtres de religion et professeurs de religion. Dans ce cas, le membre du personnel est réputé mis en disponibilité par défaut d''emploi ou perte partielle de charge et sa désignation est assimilée, au prorata du volume de charge, à une réaffectation temporaire, au sens de l''article 79, 4°, du décret du 10 mars 2006 précité et de l''article 2, § 3, de l''arrêté du Gouvernement de la Communauté française du 28 août 1995 réglementant la mise en disponibilité par défaut d''emploi, la réaffectation et l''octroi d''une subvention-traitement d''attente dans l''enseignement préscolaire et primaire officiel subventionné, ordinaire et spécial; 2° au(x) membre(s) de son personnel nommé(s) à titre définitif à la veille de l''entrée en vigueur du présent décret dans une fonction de maître de religion ou de morale non confessionnelle, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 298, 'Article 293octies. - § 1er. Lors de sa création au 1er octobre 2016, et par (partie 2)', '7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 2°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus Docu 40701 D. 11-04-2014 grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006; 3° au(x) membre(s) de son personnel désigné(s) dans une fonction de maître de religion ou de morale non confessionnelle au cours de l''année scolaire précédant l''entrée en vigueur du présent décret en qualité de temporaire(s) prioritaire(s), au sens respectivement, pour les maîtres de morale non confessionnelle, de l''article 24 du décret du 6 juin 1994 précité et pour les maîtres de religion, de l''article 23, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir acquis un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française; 3) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 3°, alinéa 1er, 3); 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006 précité; 4° au(x) membre(s) de son personnel désigné(s) dans une fonction de maître de religion ou de morale non confessionnelle à la veille de l''entrée en vigueur du présent décret en qualité de temporaire(s) prioritaire(s), au sens respectivement, pour les maîtres de morale non confessionnelle, de l''article 24 du décret du 6 juin 1994 précité et pour les maîtres de religion, de l''article 23, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en Docu 40701 D. 11-04-2014 application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignemen');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 299, 'Article 293octies. - § 1er. Lors de sa création au 1er octobre 2016, et par (partie 3)', 'de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 4°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006 précité; 5° au(x) membre(s) de son personnel ayant acquis une ancienneté de 150 jours au moins, dans une fonction de maître de religion ou de morale non confessionnelle, à la veille de l''entrée en vigueur du présent décret, en qualité de temporaire, au sens respectivement, pour les maîtres de morale non confessionnelle, de l''article 20 du décret du 6 juin 1994 précité et pour les maîtres de religion, de l''article 20, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir acquis un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française; 3) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Docu 40701 D. 11-04-2014 Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 5°, alinéa 1er, 3); 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006 précité. 6° au(x) membre(s) de son personnel ayant acquis une ancienneté de 150 jours au moins, dans une fonction de maître de religion ou de morale non confessionnelle, à la veille de l''entrée en vigueur du présent décret, en qualité de temporaire, au sens respectivement, pour les maîtres de morale non confessionnelle, de l''article 20 du décret du 6 juin 1994 précité et pour les maîtres de religion, de l''article 20, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unit');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 300, 'Article 293octies. - § 1er. Lors de sa création au 1er octobre 2016, et par (partie 4)', 'd''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 6°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les maîtres de religion, à l''article 18 du décret du 10 mars 2006 précité. Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 301, 'Article 293nonies. - Les maîtres de religion et de morale non', 'Article 293nonies. - Les maîtres de religion et de morale non 
confessionnelle visés aux 1°, 2°, 3° et 4° de l''article 293octies, voient leurs 
 
 
Docu 40701 
 
D. 11-04-2014  
anciennetés de fonction et de service acquises auprès du Pouvoir 
organisateur dans le cadre du décret du 10 mars 2006 précité ou du 6 juin 
1994 précité respectivement, réputées comme ancienneté de fonction acquise 
au sens de l''article 34 du décret du 6 juin 1994 précité en qualité de maître 
de philosophie et de citoyenneté. 
 
Toutefois, ils ne peuvent se prévaloir de cette valorisation que pour 
prétendre à la même fonction. 
 
Inséré par D. 13-07-2016 ; modifié par D. 19-07-2017 ; D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 302, 'Article 293decies. - § 1er. Pour les membres du personnel définitifs', 'Article 293decies. - § 1er. Pour les membres du personnel définitifs 
visés au 1° de l''article 293octies, cette réaffectation temporaire sera 
reconduite automatiquement, selon les règles fixées en la matière par 
l''Arrêté du Gouvernement de la Communauté française du 28 août 1995, 
jusqu''à ce que le membre du personnel réponde aux conditions de nomination 
fixées à l''article 30 du décret du 6 juin 1994 précité à l’exception du 5° de son 
§ 1er, et ce sous condition pour lui d''avoir, avant le 1er septembre 2021 acquis 
le certificat en didactique du cours de philosophie et de citoyenneté visé à 
l''article 24bis, alinéa 3 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française, pour autant que le titre de 
capacité fixé par le Gouvernement, pour l''exercice de cette fonction, l''exige. 
 
Inséré par D. 19-07-2017 
Par dérogation, le membre du personnel peut demander auprès de son 
Pouvoir organisateur, sans qu''il puisse la refuser, la non-reconduction de sa 
réaffectation temporaire. La demande doit avoir été faite auprès du Pouvoir 
organisateur par courrier recommandé avant le 31 mai pour l''année scolaire 
suivante. Pour l''année scolaire 2017-2018, la date limite d''envoi du courrier 
recommandé est fixée au 31 aout 2017. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 2. Pour les membres du personnel définitifs visés au 2° de l''article 
293octies, leur désignation sera reconduite selon les règles fixées en la 
matière par le chapitre III du décret 6 juin 1994 précité, jusqu''à ce que le 
membre du personnel réponde aux conditions de nomination fixées à l''article 
30 du même décret du 6 juin 1994 à l’exception du 5° de son § 1er, et sous 
condition pour lui d''avoir, avant le 1er septembre 2021 acquis le certificat en 
didactique du cours de philosophie et de citoyenneté visé à l''article 24bis, 
alinéa 3 du décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française, pour autant que le titre de capacité fixé par le 
Gouvernement, pour l''exercice de cette fonction, l''exige. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas au 1er 
septembre 2020 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
Modifié par D. 19-07-2017 
§ 3. Pour les membres du personnel temporaire visés au 3° et 4° de 
l''article 293octies, leur désignation sera reconduite selon les règles fixées en 
la matière par le chapitre III du décret 6 juin 1994 précité, jusqu''à ce que le 
membre du personnel réponde aux conditions de nomination fixées à l''article 
 
 
Docu 40701 
 
D. 11-04-2014  
30 du même décret du 6 juin 1994, et sous condition pour lui d''avoir, avant le 
1er septembre 2020 pour le 2°, et avant le 1er septembre 2021 pour le 1°: 
1° acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige; 
2° acquis, dans le cas du 4°, un titre pédagogique, conformément aux 
articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas au à la 
condition fixée par le 1° au 1er septembre 2021, ou par le 2° au 1er septembre 
2020, il perd à la même date le bénéfice des mesures transitoires fixées par le 
présent décret. 
 
Inséré par D. 19-07-2017 
§ 4. Si le membre du personnel refuse les attributions qui lui sont 
proposées, ou demande la non-reconduction de sa réaffectation temporaire, il 
perd le bénéfice des dispositions transitoires de la présente section. 
 
Inséré par D. 03-05-2019 
§ 5. Par dérogation au § 1 de l''article 24 du décret du 6 juin 1994 
précité, les membres du personnel, visés par le présent article et qui 
continuent à répondre au 1er septembre 2021 aux conditions pour pouvoir 
bénéficier des dispositions transitoires, sont réputés être porteur du titre 
requis pour exercer et être nommés dans la fonction de maître de philosophie 
et citoyenneté, sans préjudice du § 3. Cette disposition n''est pas d''application 
pour la fixation du barème. 
 
Inséré par D. 13-07-2016 ; modifié par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 303, 'Article 293undecies. - Au sein du même établissement, les membres', 'Article 293undecies. - Au sein du même établissement, les membres 
du personnel bénéficiant des dispositions fixées à la présente section ne 
peuvent, au cours de la même année scolaire, exercer leur nouvelle fonction 
au sein de la même implantation concomitamment avec une charge de maître 
de religion ou de morale non confessionnelle. 
 
Par dérogation à l''alinéa premier, dans l''enseignement spécialisé, un 
membre du personnel peut exercer les deux fonctions susvisées face au même 
élève; 
 
Par dérogation à l''alinéa 1er, et uniquement dans le cadre de 
l''application de l''article 293octies, § 1er, alinéa 1er, un membre du personnel 
peut exercer les deux fonctions susvisées dans la même implantation, mais 
pas dans la même classe : 
1° dans les Pouvoirs organisateurs comptant moins de 6 implantations 
qui sans cette dérogation ne peuvent attribuer les périodes conformément à 
l''article 293octies, § 1er, alinéa 1er; 
2° dans les Pouvoirs organisateurs comptant au moins 6 implantations, 
si le respect de l''incompatibilité visée à l''alinéa 1er devait conduire le membre 
du personnel concerné à exercer sa fonction de maître de philosophie et 
citoyenneté et celle de maître de religion ou morale non confessionnelle : 
 a) dans plus de 6 implantations; 
 
 
Docu 40701 
 
D. 11-04-2014  
 b) ou à devoir assurer, pour se rendre dans chaque implantation 
concernée, un déplacement de plus 25 km depuis son domicile ou entraînant 
une durée de déplacement supérieure à quatre heures par jour, à l''aide des 
transports en commun. 
 
Lorsque la dérogation visée à l''alinéa précédent concerne un membre du 
personnel qui exerce les fonctions concernées dans plusieurs Pouvoirs 
organisateurs, la dérogation s''impose au(x) Pouvoir(s) organisateur(s) à 
l''origine de l''incompatibilité. 
 
Insérée par D. 13-07-2016 
Sous-section 3. - Dispositions transitoires propres à l''enseignement 
libre subventionné de caractère non confessionnel 
 
Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 304, 'Article 293duodecies. - § 1er. Lors de sa création au 1er octobre 2016, (partie 1)', 'Article 293duodecies. - § 1er. Lors de sa création au 1er octobre 2016, et par dérogation aux règles statutaires prévues au chapitre III du décret du 1er février 1993 fixant le statut des membres du personnel subsidié de l''enseignement libre subventionné, la fonction de maître de philosophie et de citoyenneté devra être confiée au sein du Pouvoir Organisateur aux membres de son personnel, - dans la limite des périodes que ces membres du personnel perdent du fait d''une réduction des périodes de cours philosophiques suite à la création du cours de philosophie et de citoyenneté au 1er octobre 2016 - selon l''ordre prévu au § 2, à l''exception du 2°. Lorsqu''après application de l''alinéa 1er, des périodes de philosophie et citoyenneté restent disponibles, elles sont attribuées selon l''ordre prévu au § 2, sans pour autant, qu''un membre du personnel puisse, au total des périodes de philosophie et citoyenneté et des périodes de religion ou de morale non confessionnelle qui lui sont attribuées, se voir confier un nombre de périodes supérieur au nombre de périodes de religion ou de morale non confessionnelle qui lui étaient attribuées au 30 juin 2016. Lorsqu''après application des alinéas 1er et 2, des périodes de philosophie et citoyenneté restent disponibles, elles sont attribuées conformément aux décrets du 1er février 1993 susvisé et du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé par la Communauté française et à ses arrêtés d''application. § 2. L''ordre d''attribution est le suivant : 1° au(x) membre(s) de son personnel engagé(s) à titre définitif à la veille de l''entrée en vigueur du présent décret dans une fonction de maître de religion ou de morale non confessionnelle et qui, du fait d''une réduction des périodes de cours philosophiques suite à la création du cours de philosophie et de citoyenneté au 1er octobre 2016 par le décret du 22 octobre 2015 relatif à l''organisation d''un cours et d''une éducation à la philosophie et à la citoyenneté, devraient être mis en disponibilité par défaut d''emploi ou en perte partielle de charge par l''application des mesures préalables, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement Docu 40701 D. 11-04-2014 «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 1°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. Dans ce cas, le membre du personnel est réputé mis en disponibilité par défaut d''emploi ou perte partielle de charge et sa désignation est assimilée, au prorata du volume de charge, à une réaffectation temporaire, au sens de l''article 2, § 3, de l''arrêté du Gouvernement de la Communauté française du 28 août 1995 réglementant la mise en disponibilité par défaut d''emploi, la réaffectation et l''octroi d''une subvention-traitement d''attente dans l''enseignement préscolaire et primaire libre subventionné, ordinaire et spécial; 2° au(x) membre(s) de son personnel engagé(s) à titre définitif à la veille de l''entrée en vigueur du présent décret dans une fonction de maître de religion ou de morale non confessionnelle, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutrali');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 305, 'Article 293duodecies. - § 1er. Lors de sa création au 1er octobre 2016, (partie 2)', 'organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 2°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Docu 40701 D. 11-04-2014 Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les maîtres de morale non confessionnelle, conformément à l''article 29bis du décret du 1er février 1993 précité; 3° au(x) membre(s) de son personnel engagé(s) dans une fonction de maître de religion ou de morale non confessionnelle à la veille de l''entrée en vigueur du présent décret en qualité de temporaire(s) prioritaire(s), au sens de l''article 34 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir acquis un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française; 3) il ait, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 3°, alinéa 1er, 3); 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité; 4° au(x) membre(s) de son personnel engagé (s) dans une fonction de maître de religion ou de morale non confessionnelle à la veille de l''entrée en vigueur du présent décret en qualité de temporaire(s) prioritaire(s), au sens de l''article 34 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) il ait, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : Docu 40701 D. 11-04-2014 a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 4°, alinéa 1er, 2). 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sou');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 306, 'Article 293duodecies. - § 1er. Lors de sa création au 1er octobre 2016, (partie 3)', 'peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité; 5° au(x) membre(s) de son personnel ayant acquis une ancienneté de 180 jours au moins, dans une fonction de maître de religion ou de morale non confessionnelle, à la veille de l''entrée en vigueur du présent décret, en qualité de temporaire, au sens de l''article 30 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) d''avoir acquis un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française; 3) il ait, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 5°, alinéa 1er, 3); 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient d''engager celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité; Docu 40701 D. 11-04-2014 6° au(x) membre(s) de son personnel ayant acquis une ancienneté de 180 jours au moins, dans une fonction de maître de religion ou de morale non confessionnelle, à la veille de l''entrée en vigueur du présent décret, en qualité de temporaire, au sens de l''article 30 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) d''au moins d''un diplôme d''instituteur, de bachelier, de graduat, d''AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études; 2) il ait, avant le 1er octobre 2016, bénéficié d''une formation à la neutralité via sa formation initiale ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés de l''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée au § 2, 6°, alinéa 1er, 2); 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur, par lettre recommandée, sous peine de forclusion, avant le 1er septembre 2016. Dans l''hypothèse où le Pouvoir organisateur devrait départager plusieurs candidats, il lui revient d''engager celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. Inséré par D. 13-07-2016');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 307, 'Article 293terdecies. - Les membres du personnel visés aux 1°, 2°, 3°', 'Article 293terdecies. - Les membres du personnel visés aux 1°, 2°, 3° 
et 4°, de l''article 293duodecies, voient leurs anciennetés de fonction acquise 
auprès du Pouvoir organisateur en qualité de maîtres de religion et de 
morale non confessionnelle, réputées comme ancienneté de fonction acquise, 
au sens de l''article 29bis du décret du 1er février 1993 précité, en qualité de 
maître de philosophie et de citoyenneté. 
 
Toutefois, ils ne peuvent se prévaloir de cette valorisation que pour 
prétendre à la même fonction. 
 
Inséré par D. 13-07-2016 ; modifié par D. 03-09-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 308, 'Article 293quatuordecies. - § 1er. Pour les membres du personnel', 'Article 293quatuordecies. - § 1er. Pour les membres du personnel 
définitifs visés au 1° de l''article 293duodecies, cette réaffectation temporaire 
sera reconduite automatiquement, selon les règles fixées en la matière par 
l''arrêté du Gouvernement de la Communauté française du 28 août 1995, 
jusqu''à ce que le membre du personnel réponde aux conditions d''engagement 
à titre définitif fixées à l''article 42 du décret du 1er février 1993 précité à 
l’exception du 3° de son § 1er, et ce sous condition pour lui d''avoir, avant le 1er 
septembre 2021 acquis le certificat en didactique du cours de philosophie et 
de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
 
 
Docu 40701 
 
D. 11-04-2014  
secondaire organisé et subventionné par la Communauté française, pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige. 
 
Inséré par D. 19-07-2017 
Par dérogation, le membre du personnel peut demander auprès de son 
Pouvoir organisateur, sans qu''il puisse la refuser, la non-reconduction de sa 
réaffectation temporaire. La demande doit avoir été faite auprès du Pouvoir 
organisateur par courrier recommandé pour le 15 mai pour l''année scolaire 
suivante. Pour l''année scolaire 2017-2018, la date limite d''envoi du courrier 
recommandé est fixée au 31 aout 2017. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas au 1er 
septembre 2020 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 2. Pour les membres du personnel définitifs visés au 2° de l''article 
293duodecies, leur engagement sera reconduit selon les règles fixées en la 
matière par le chapitre III du décret 1er février 1993 précité, jusqu''à ce que le 
membre du personnel réponde aux conditions d''engagement à titre définitif 
fixées à l''article 42 du même décret à l’exception du 3° de son § 1er, et sous 
conditions pour lui d''avoir, avant le 1er septembre 2021 acquis le certificat en 
didactique du cours de philosophie et de citoyenneté visé à l''article 24bis, 
alinéa 3 du décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française, pour autant que le titre de capacité fixé par le 
Gouvernement, pour l''exercice de cette fonction, l''exige. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas au 1er 
septembre 2020 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 3. Pour les membres du personnel temporaire visés au 3° et 4° de 
l''article 293duodecies, leur engagement sera reconduit selon les règles fixées 
en la matière par le chapitre III du décret 1er février 1993 précité, jusqu''à ce 
que le membre du personnel réponde aux conditions d''engagement à titre 
définitif fixées à l''article 42 du même décret, et sous conditions pour lui 
d''avoir, avant le 1er septembre 2020 pour le 2°, et avant le 1er septembre 2021 
pour le 1°: 
1° acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française pour 
autant que le titre de capacité fixé par le Gouvernement, pour l''exercice de 
cette fonction, l''exige; 
2° acquis, dans le cas du 4°, un titre pédagogique, conformément aux 
articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française. 
 
Dans l''hypothèse où le membre du personnel ne répondrait pas à la 
condition fixée par le 1° au 1er septembre 2021°, ou par le 2° au 1er septembre 
2020, il perd à la même date le bénéfice des mesures transitoires fixées par le 
présent décret. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Inséré par D. 19-07-2017 
§ 4. Si le membre du personnel refuse les attributions qui lui sont 
proposées, ou demande la non-reconduction de sa réaffectation temporaire, il 
perd le bénéfice des dispositions transitoires de la présente section. 
 
Inséré par D. 03-05-2019 
§ 5. Par dérogation au § 2 de l''article 34 du décret du 1er février 1993 
précité, les membres du personnel, visés par le présent article et qui 
continuent à répondre au 1er septembre 2021 aux conditions pour pouvoir 
bénéficier des dispositions transitoires, sont réputés être porteur du titre 
requis pour exercer et être nommés dans la fonction de maître de philosophie 
et citoyenneté, sans préjudice du § 3. Cette disposition n''est pas d''application 
pour la fixation du barème. 
 
Inséré par D. 13-07-2016 ; modifié par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 309, 'Article 293quindecies. - Au sein du même établissement, les membres', 'Article 293quindecies. - Au sein du même établissement, les membres 
du personnel bénéficiant des dispositions fixées à la présente section ne 
peuvent, au cours de la même année scolaire, exercer leur nouvelle fonction 
au sein de la même implantation concomitamment avec une charge de maître 
de religion ou de morale non confessionnelle. 
 
Par dérogation à l''alinéa premier, dans l''enseignement spécialisé, un 
membre du personnel peut exercer les deux fonctions susvisées face au même 
élève. 
 
Par dérogation à l''alinéa 1er, et uniquement dans le cadre de 
l''application de l''article 293duodecies, § 1er, alinéa 1er, un membre du 
personnel peut exercer les deux fonctions susvisées dans la même 
implantation, mais pas dans la même classe : 
1° dans les Pouvoirs organisateurs comptant moins de 6 implantations 
qui sans recourir à cette dérogation ne peuvent attribuer les périodes 
conformément à l''article 293duodecies, § 1er, alinéa 1er; 
2° dans les Pouvoirs organisateurs comptant au moins 6 implantations, 
si le respect de l''incompatibilité visée à l''alinéa 1er devait conduire le membre 
du personnel concerné à exercer sa fonction de maître de philosophie et 
citoyenneté et celle de maître de religion ou morale non confessionnelle : 
 a) dans plus de 6 implantations; 
 b) à devoir assurer, pour se rendre dans chaque implantation 
concernée, un déplacement de plus 25 km depuis son domicile ou entraînant 
une durée de déplacement supérieure à quatre heures par jour, à l''aide des 
transports en commun. 
 
Lorsque la dérogation visée à l''alinéa précédent concerne un membre du 
personnel qui exerce les fonctions concernées dans plusieurs Pouvoirs 
organisateurs, la dérogation s''impose au(x) Pouvoir(s) organisateur(s) à 
l''origine de l''incompatibilité. 
 
Insérée par D. 13-07-2016 
Sous-section 4. - Dispositions transitoires relatives à la rémunération 
 
Complété par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 310, 'Article 293sexdecies. - Les membres du personnel nommés ou', 'Article 293sexdecies. - Les membres du personnel nommés ou 
engagés à titre définitif ou visés à l''article 285 du présent décret et visés aux 
sous-sections 1 à 3 de la présente section bénéficient, sans limite de temps, 
des échelles de traitement attachées à la nouvelle fonction de maître de 
 
 
Docu 40701 
 
D. 11-04-2014  
philosophie et de citoyenneté, sauf si l''échelle de traitement afférente à leur 
fonction d''origine leur procure une rémunération plus élevée. 
 
Pour les membres du personnel désignés ou engagé à titre temporaire 
débutant le 1er octobre 2016 et prenant fin, au plus tard, le 30 juin 2017 le 
bénéfice de l''échelle de traitement afférente à la fonction d''origine, lorsqu''elle 
est plus favorable, ne vaut que pour l''année scolaire 2016-2017. 
 
A l''échéance de la mesure transitoire fixée à l''alinéa 1er de l''article 293 
septdecies, à condition d''avoir déjà exercé au 1er septembre 2021 la fonction 
de maître de philosophie et citoyenneté pendant 315 jours acquis sur deux 
ans auprès du même pouvoir organisateur et calculés conformément aux 
dispositions propres à chaque statut, les membres du personnel ayant été 
recrutés en l''absence de certificat en didactique conservent au cours de 
l''année scolaire 2021-2022 l''échelle de traitement qui leur était attribuée 
pour l''exercice de cette fonction avant cette date si celle-ci leur est plus 
favorable. 
 
Insérée par D. 13-07-2016 ; intitulé modifié par D. 11-07-2018 
Sous-section 5. - Dispositions transitoires relatives au certificat en 
didactique de la philosophie et citoyenneté, au classement des 
temporaires prioritaires et la nomination ou engagement à titre 
définitif 
 
Modifié par D. 19-07-2017 ; D. 11-07-2018 ; D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 311, 'Article 293septdecies. - Par mesure transitoire, dans l''attente de la', 'Article 293septdecies. - Par mesure transitoire, dans l''attente de la 
création du certificat prévu à l''article 24bis, alinéa 3 du présent décret et au 
plus tard jusqu''au 1er septembre 2021, la possession de ce certificat pour 
l''exercice de la fonction de maître de philosophie et de citoyenneté n''est pas 
exigée. 
 
Inséré par D. 19-07-2017 
Pour l''enseignement subventionné par la Communauté française, les 
maîtres de philosophie et citoyenneté ne peuvent être désignés en qualité de 
temporaires prioritaires et être nommés qu''à partir du 1er septembre 2021, 
sauf ceux visés par les dispositions transitoires de la section VI du chapitre II 
du titre III du décret du 11 avril 2014. 
 
Inséré par D. 11-07-2018 
Jusqu''au 1er septembre 2021, les maîtres de philosophies et de 
citoyenneté bénéficiant des dispositions transitoires prévues à l''alinéa 
précédent ne peuvent être nommés ou engagés à titre définitif que pour le 
volume de charge qui leur a été attribué au 1er octobre de l''année scolaire où 
doit intervenir la nomination ou engagement à titre définitif. 
 
Inséré par D. 19-07-2017 
Pour l''enseignement organisé par la Communauté française, les maitres 
de philosophie et citoyenneté ne peuvent être désignés en qualité de 
temporaires prioritaires qu''à partir du 1er septembre 2021 et être nommés 
qu''à partir du 1er janvier 2022, sauf ceux visés par les dispositions 
transitoires reprises au chapitre XIquater de l''arrêté royal du 22 mars 1969 
fixant le statut des membres du personnel directeur et enseignant et du 
chapitre Xter l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres et 
des 
professeurs 
de 
religion, 
pour 
l''enseignement 
organisé 
par 
la 
Communauté française 
 
 
Docu 40701 
 
D. 11-04-2014  
Inséré par D. 19-07-2017 
Le membre du personnel dont le titre de capacité fixé par le 
Gouvernement, pour l''exercice de la fonction de maître de philosophie et de 
citoyenneté, exige la possession du certificat prévu à l''article 24bis, alinéa 3, 
ne pourra être nommé que lorsqu''il sera détenteur de ce certificat. 
 
Inséré par D. 19-07-2021 
Dans l''enseignement officiel subventionné, lors de l''année scolaire 2020-
2021, par dérogation aux dispositions de l''alinéa 5 de l''article 31 du décret du 
6 juin 1994 fixant le statut des membres du personnel subsidiés de 
l''enseignement officiel subventionné, l''avis visé au même alinéa est distribué 
à tous les membres du personnel exerçant la fonction maître de philosophie 
et citoyenneté au sein du pouvoir organisateur. 
 
Inséré par D. 19-07-2017 
Section VII. - Dispositions transitoires propres aux fonctions de 
professeurs de philosophie et de citoyenneté exercées dans 
l''enseignement secondaire 
 
Sous-section 1re -Dispositions transitoires propres à 
l''enseignement officiel subventionné 
 
[Les articles 293septdecies/1 et 293septdecies/2 n’ont jamais été 
adoptés] 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 312, 'Article 293septdecies', 'Article 293septdecies/3. - Lors de la création du cours de philosophie 
et citoyenneté au 1er septembre 2017, tous les membres du personnel 
bénéficiant d''une nomination à titre définitif avant le 30 juin 2017 dans une 
fonction de professeur de morale non confessionnelle ou de religion, 
respectivement au degré inférieur ou supérieur, sont réputés perdre la moitié 
de leurs attributions. 
 
Les membres du personnel temporaires désignés dans les mêmes 
fonctions lors de l''année scolaire précédente, sont également réputés ne 
pouvoir être désignés à nouveau que pour un volume de charge équivalent à 
la moitié des attributions dont ils bénéficiaient au 30 juin 2017. 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 313, 'Article 293septdecies', 'Article 293septdecies/4. - Avant d''effectuer les attributions des 
périodes de philosophie et citoyenneté, le Pouvoir organisateur procède en 
son sein, en faveur des membres de son personnel définitifs qui ne 
répondraient pas aux conditions fixées au § 1er de l''article 293septdecies/5 du 
présent décret, à l''application des mesures préalables à la mise en 
disponibilité par défaut d''emploi et à la perte partielle de périodes et opère 
les réaffectations et rappels provisoires à l''activité qui seraient possibles, 
conformément aux dispositions fixées en la matière respectivement par le 
chapitre 9 du décret du 10 mars 2006 relatif aux statuts des maîtres de 
religion et professeurs de religion et par l''arrêté du Gouvernement de la 
Communauté française du 28 août 1995 réglementant la mise en 
disponibilité par défaut d''emploi, la réaffectation et l''octroi d''une subvention-
traitement d''attente dans les enseignements secondaire ordinaire et 
spécialisé, secondaire artistique à horaire réduit, et artistique officiels 
subventionnés. Pour l''application du présent article, les mesures préalables 
 
 
Docu 40701 
 
D. 11-04-2014  
et opérations de réaffectation sont limitées aux fonctions de professeur de 
morale ou religion. 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 314, 'Article 293septdecies (partie 1)', 'Article 293septdecies/5. - § 1er. Lors de l''année scolaire 2017-2018, par dérogation aux règles statutaires fixées au chapitre III du décret du 6 juin 1994 fixant le statut des membres du personnel subsidié de l''enseignement officiel subventionné, les fonctions de professeur de philosophie et de citoyenneté, au degré inférieur ou au degré supérieur, devront d''abord être confiées au sein du Pouvoir organisateur selon l''ordre suivant : 1° au(x) membre(s) du personnel bénéficiant(s) d''une nomination à titre définitif avant le 1er septembre 2017 dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française, au plus tard durant l''année scolaire 2003-2004, sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de périodes qui était le leur au sein du Pouvoir organisateur lors de l''année scolaire précédente au 30 juin. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les professeurs de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les professeurs de religion, à l''article 18 du décret du 10 mars 2006 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction. Docu 40701 D. 11-04-2014 Les membres du personnel qui se voient ainsi attribuer des périodes de philosophie et citoyenneté sont considérés, au prorata du volume de périodes réputé perdu à l''article 293septdecies/3, en réaffectation temporaire, au sens de l''article 79, 4°, du décret du 10 mars 2006 précité et de l''article 2, § 4, de l''arrêté du Gouvernement de la Communauté française du 28 août 1995 précité. Pour les périodes supplémentaires accordées au-delà du volume de périodes réputé perdu visé à l''alinéa précédent, et dans la limite de leurs attributions au 31 août 2017, ils bénéficient d''un congé pour exercer provisoirement une autre fonction dans l''enseignement conformément à l''article 14, § 1er, 3° et 4°, de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendants de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements ; 2° au(x) membre(s) du personnel désigné(s) dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, au cours de l''année scolaire 2016-2017 en qualité de temporaire(s) prioritaire(s), au sens respectivement, pour les professeurs de morale non confessionnelle, de l''article 24 du décret du 6 juin 1994 précité et pour les professeurs de religion, de l''article 23, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 315, 'Article 293septdecies (partie 2)', 'de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''être porteur(s) d''un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française ; 3) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Docu 40701 D. 11-04-2014 Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de charge qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les professeurs de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les professeurs de religion, à l''article 18 du décret du 10 mars 2006 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ; 3° au(x) membre(s) du personnel désigné(s) dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, au cours de l''année scolaire 2016-2017 en qualité de temporaire(s) prioritaire(s), au sens respectivement, pour les professeurs de morale non confessionnelle, de l''article 24 du décret du 6 juin 1994 précité et pour les professeurs de religion, de l''article 23, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de charge qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les professeurs de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les professeurs de religion, à l''article 18 Docu 40701 D. 11-04-2014 du décret du 10 mars 2006 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ;');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 316, 'Article 293septdecies (partie 3)', '4° au(x) membre(s) du personnel en activité de service au 30 juin 2017, ayant acquis une ancienneté de 150 jours au moins, dans une fonction de professeurs de religion ou de morale non confessionnelle, respectivement au degré inférieur ou supérieur, et revêtant la qualité de temporaire, au sens respectivement, pour les professeurs de morale non confessionnelle, de l''article 20 du décret du 6 juin 1994 précité et pour les professeurs de religion, de l''article 20, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''être porteur(s) d''un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française ; 3) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats à concurrence du volume de périodes qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les professeurs de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les professeurs de religion, à l''article 18 du décret du 10 mars 2006 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ; 5° au(x) membre(s) du personnel en activité de service au 30 juin 2017, ayant acquis une ancienneté de 150 jours au moins, dans une fonction de Docu 40701 D. 11-04-2014 professeurs de religion ou de morale non confessionnelle, respectivement au degré inférieur ou supérieur, et revêtant la qualité de temporaire, au sens respectivement, pour les professeurs de morale non confessionnelle, de l''article 20 du décret du 6 juin 1994 précité et pour les professeurs de religion, de l''article 20, § 1er, du décret du 10 mars 2006 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralit');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 317, 'Article 293septdecies (partie 4)', 'visée ci-dessus; 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats à concurrence du volume de périodes qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée respectivement, pour les professeurs de morale non confessionnelle, conformément à l''article 34 du décret du 6 juin 1994 précité, et pour les professeurs de religion, à l''article 18 du décret du 10 mars 2006 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction. § 2. Pour l''application du § 1er, le membre du personnel ne peut pas se voir attribuer un nombre total des périodes de philosophie et citoyenneté supérieur au nombre total de périodes de morale, religion et d''encadrement pédagogique alternatif qui lui étaient attribuées au 30 juin 2017. Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 318, 'Article 293septdecies', 'Article 293septdecies/6. - § 1er. Les professeurs de religion et de 
morale non confessionnelle visés aux 1°, 2°, 3°, 4° et 5° du § 1er de l''article 
293septdecies/5, voient leurs anciennetés de fonction et de service acquises 
respectivement auprès du Pouvoir organisateur dans le cadre du décret du 10 
mars 2006 précité ou du 6 juin 1994 précité, réputées comme ancienneté de 
 
 
Docu 40701 
 
D. 11-04-2014  
fonction acquise au sens de l''article 34 du décret du 6 juin 1994 précité en 
qualité de professeurs de philosophie et de citoyenneté, respectivement au 
degré inférieur ou supérieur selon le cas. 
 
Toutefois, ils ne peuvent se prévaloir de cette valorisation que pour 
prétendre à la même fonction. 
 
§ 2. Les professeurs de religion et de morale non confessionnelle 
temporaires, visés aux 2°, 3°, 4° et 5° du § 1er de l''article 293septdecies/5, 
voient, à partir du 1er septembre 2017, leurs prestations dans la nouvelle 
fonction de professeur de philosophie et citoyenneté comptabilisée à la fois 
dans le calcul d''ancienneté de leur nouvelle et de leur ancienne fonction. 
 
Le bénéficie de la disposition visée à l''alinéa précédent trouve à 
s''appliquer jusqu''à la nomination du membre du personnel dans la nouvelle 
fonction de professeur de philosophie et citoyenneté au prorata des périodes 
concernée par cette nouvelle nomination, et au plus tard jusqu''au 31 août 
2021. 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 319, 'Article 293septdecies', 'Article 293septdecies/7. - A titre transitoire pour la seule année 
scolaire 2017-2018, les professeurs de religion et de morale non 
confessionnelle temporaires prioritaires, visés aux 2° et 3° du § 1er de l''article 
293septdecies/5, ayant fait acte de candidature à la nomination à titre 
définitif dans les conditions et formes requises respectivement à l''article 31 
du décret du 10 mars 2006 et à l''article 30 du décret du 6 juin 1994 au cours 
de l''année scolaire 2016-2017, conservent leur droit à cette nomination à titre 
définitif dans leur ancienne fonction au cours de l''année scolaire 2017-2018, 
même s''ils prestent désormais entièrement au sein du pouvoir organisateur 
en qualité de professeur de philosophie et citoyenneté. 
 
Cette nomination à titre définitif s''effectue dans le respect des règles 
statutaires en vigueur, telles que fixées aux chapitres III, sections 3 du 
décret du 6 juin 1994 et du décret du 10 mars 2006. A sa demande, par 
dérogation à l''article 30, § 1er, dernier alinéa, du décret du 6 juin 1994 précité 
pour le professeur de morale, ou par dérogation à l''article 31, § 1er, dernier 
alinéa, du décret du 10 mars 2006 précité pour le professeur de religion, le 
membre du personnel visé par cet article peut bénéficier de cette nomination 
sans mettre fin à ses fonctions comme professeur de philosophie et 
citoyenneté. Dans ce cas, un congé pour exercer provisoirement une autre 
fonction lui est accordé d''office par son Pouvoir organisateur. 
 
Inséré par D. 19-07-2017 ; modifié par D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 320, 'Article 293septdecies', 'Article 293septdecies/8. - § 1er. La réaffectation temporaire des 
membres du personnel définitifs visés au 1° du § 1er de l''article 
293septdecies/5, sera reconduite automatiquement, selon les règles fixées en 
la matière par l''arrêté du Gouvernement de la Communauté française du 28 
août 1995 précité, jusqu''à ce que le membre du personnel réponde aux 
conditions de nomination fixées à l''article 30 du décret du 6 juin 1994 précité 
à l’exception du 5° de son § 1er, et ce sous condition pour lui d''avoir, avant le 
1er septembre 2021 acquis le certificat en didactique du cours de philosophie 
et de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 
précité, pour autant que le titre fixé par le Gouvernement, pour l''exercice de 
cette fonction l''exige. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Par dérogation, le membre du personnel peut demander auprès de son 
Pouvoir organisateur, sans qu''il puisse la refuser, la non-reconduction de sa 
réaffectation temporaire. La demande doit avoir été faite par courrier 
recommandé avant le 31 mai pour l''année scolaire suivante. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 2. Le congé pour exercer provisoirement une autre fonction dans 
l''enseignement des membres du personnel définitifs visés au 1° du même 
article sera reconduit automatiquement tant que leur désignation sera 
également reconduite selon les règles fixées en la matière par le chapitre III 
du décret 6 juin 1994 précité, et jusqu''à ce que le membre du personnel 
réponde aux conditions de nomination fixées à l''article 30 du même décret du 
6 juin 1994 à l’exception du 5° de son § 1er, et sous condition pour lui d''avoir, 
avant le 1er septembre 2021 acquis le certificat en didactique du cours de 
philosophie et de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 
avril 2014 précité, pour autant que le titre fixé par le Gouvernement, pour 
l''exercice de cette fonction l''exige. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 3. Pour les membres du personnel temporaire visés au 2°, 3°, 4° et 5° 
du § 1er de l''article 293septdecies/5, leur désignation sera reconduite selon les 
règles fixées en la matière par le chapitre III du décret 6 juin 1994 précité, 
jusqu''à ce que le membre du personnel réponde aux conditions de nomination 
fixées à l''article 30 du même décret du 6 juin 1994, et sous condition pour lui 
d''avoir, avant le 1er septembre 2021 : 
 1°) acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 précité 
pour autant que le titre de capacité fixé par le Gouvernement, pour l''exercice 
de cette fonction, l''exige ; 
 2°) acquis, dans le cas du 3° et 5°, un titre pédagogique, conformément 
aux articles 17 et 18 du décret du 11 avril 2014 précité. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 4. Si le membre du personnel refuse les attributions qui lui sont 
proposées, ou demande la non-reconduction de sa réaffectation temporaire, il 
perd le bénéfice des dispositions transitoires de la présente section. 
 
Inséré par D. 03-05-2019 
§ 5. Par dérogation au § 1 de l''article 24 du décret du 6 juin 1994 
précité, les membres du personnel, visés par le présent article et qui 
continuent à répondre au 1er septembre 2021 aux conditions pour pouvoir 
bénéficier des dispositions transitoires, sont réputés être porteur du titre 
requis pour exercer et être nommés dans la fonction de professeur de 
philosophie et citoyenneté au degré dans laquelle ils bénéficient des mesures 
transitoires, sans préjudice du § 3. Cette disposition n''est pas d''application 
pour la fixation du barème. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 321, 'Article 293septdecies', 'Article 293septdecies/9. - Au sein du même établissement, les 
membres du personnel bénéficiant des dispositions fixées à la présente 
section ne peuvent, au cours de la même année scolaire, exercer leur nouvelle 
fonction face au même élève concomitamment avec une charge de professeur 
de religion ou de morale non confessionnelle. 
 
Par dérogation à l''alinéa 1er, dans l''enseignement spécialisé, un membre 
du personnel peut exercer les deux fonctions susvisées face au même élève : 
1° si celui-ci relève de l''enseignement de forme 1 et 2 ; 
ou 
2° si celui-ci relève de l''enseignement de forme 3 et 4 mais que les 
spécificités du public visé le requièrent. Cette spécificité est dûment 
constatée au sein de la commission paritaire locale du pouvoir organisateur 
concerné. 
 
Insérée par D. 19-07-2017 
Sous-section 2. - Dispositions transitoires propres à 
l''enseignement libre subventionné de caractère non confessionnel 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 322, 'Article 293septdecies', 'Article 293septdecies/10. - Lors de la création du cours de philosophie 
et citoyenneté au 1er septembre 2017, tous les membres du personnel 
bénéficiant d''une nomination à titre définitif avant le 30 juin 2017 dans une 
fonction de professeur de morale non confessionnelle ou de religion, 
respectivement au degré inférieur ou supérieur, sont réputés perdre la moitié 
de leurs attributions. 
 
Les membres du personnel temporaires désignés dans les mêmes 
fonctions lors de l''année scolaire précédente, sont également réputés ne 
pouvoir être désignés à nouveau que pour un volume de charge équivalent à 
la moitié des attributions dont ils bénéficiaient au 30 juin 2017. 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 323, 'Article 293septdecies', 'Article 293septdecies/11. - Avant d''effectuer les attributions des 
périodes de philosophie et citoyenneté nouvellement créées, le Pouvoir 
Organisateur procède en son sein, en faveur des membres de son personnel 
définitifs qui ne répondraient pas aux conditions fixées par le § 1er de l''article 
293septdecies/12 du présent décret, à l''application des mesures préalables à 
la mise en disponibilité par défaut d''emploi et à la perte partielle de charge et 
opère les réaffectations et remises au travail qui seraient possibles, 
conformément aux dispositions fixées en la matière par l''arrêté du 
Gouvernement de la Communauté française du 28 août 1995 réglementant la 
mise en disponibilité par défaut d''emploi, la réaffectation et l''octroi d''une 
subvention-traitement d''attente dans les enseignements secondaire ordinaire 
et spécialisé, secondaire artistique à horaire réduit, et artistique libres 
subventionnés. Pour l''application du présent article, les mesures préalables, 
les opérations de réaffectation sont limitées aux fonctions de professeur de 
morale ou religion. 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 324, 'Article 293septdecies (partie 1)', 'Article 293septdecies/12. - § 1er. Lors de l''année scolaire 2017-2018, par dérogation aux règles statutaires fixées au chapitre III du décret du 1er février 1993 fixant le statut des membres du personnel subsidié de l''enseignement libre subventionné, les fonctions de professeur de philosophie et de citoyenneté au degré inférieur ou au degré supérieur devront être Docu 40701 D. 11-04-2014 confiée au sein du Pouvoir Organisateur au membre de son personnel selon l''ordre suivant : 1° au(x) membre(s) du personnel bénéficiant(s) d''une nomination à titre définitif avant le 1er septembre 2017 dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française, au plus tard durant l''année scolaire 2003-2004, sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de charge qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction. Les membres du personnel qui se voient ainsi attribuer des périodes de philosophie et citoyenneté sont considérés, au prorata du volume de charge horaire réputé perdu à l''article 293septdecies/10, en réaffectation temporaire, au sens de l''article 2, § 3, de l''arrêté du Gouvernement de la Communauté française du 28 août 1995 précité. Pour les périodes supplémentaires accordées au-delà du volume de charge réputé perdu visé à l''alinéa précédent, et dans la limite de leurs attributions au 31 août 2017, ils bénéficient d''un congé pour exercer provisoirement une autre fonction dans l''enseignement conformément à l''article 14, § 1er, 3° et 4°, de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire Docu 40701 D. 11-04-2014 d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendants de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements ; 2° au(x) membre(s) du personnel désigné(s) dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, au cours de l''année scolaire 2016-2017 en qualité de temporaire(s) prioritaire(s), au sens de l''article 34 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''être porteur(s) d''un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 régl');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 325, 'Article 293septdecies (partie 2)', 'les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française ; 3) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de périodes qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ; 3° au(x) membre(s) du personnel désigné(s) dans une fonction de professeur de morale non confessionnelle ou de religion, respectivement au degré inférieur ou supérieur, au cours de l''année scolaire 2016-2017 en qualité de temporaire(s) prioritaire(s), au sens de l''article 34 du décret du 1er février 1993 précité, sous conditions pour eux : Docu 40701 D. 11-04-2014 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de périodes qui était le leur au sein du Pouvoir au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ; 4° au(x) membre(s) du personnel en activité de service au 30 juin 2017, ayant acquis une ancienneté de 180 jours au moins, dans une fonction de professeurs de religion ou de morale non confessionnelle, respectivement au degré inférieur ou supérieur, et revêtant la qualité de temporaire, au sens de l''article 30 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement su');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 326, 'Article 293septdecies (partie 3)', 'et l''organisation académique des études au degré supérieur ; 2) d''être porteur(s) d''un titre pédagogique, conformément aux articles 17 et 18 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française ; 3) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement Docu 40701 D. 11-04-2014 «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; 4) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats pour la totalité du volume de charge horaire qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction ; 5° au(x) membre(s) du personnel en activité de service au 30 juin 2017, ayant acquis une ancienneté de 180 jours au moins, dans une fonction de professeurs de religion ou de morale non confessionnelle, respectivement au degré inférieur ou supérieur, et revêtant la qualité de temporaire, au sens de l''article 30 du décret du 1er février 1993 précité, sous conditions pour eux : 1) d''être porteur(s) au moins d''un diplôme de bachelier, graduat, AESI ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré inférieur, ou d''un diplôme de master, licence, AESS ou d''un titre correspondant parmi les titres délivrés en application du décret du 7 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études au degré supérieur ; 2) d''avoir, avant le 1er septembre 2017, bénéficié d''une formation à la neutralité via sa formation initiale, ou réussi l''unité d''enseignement «formation à la neutralité» organisée par l''enseignement de promotion sociale. Pour cette unité d''enseignement : a) si sa fréquentation n''a pu être réalisée faute de places suffisantes, d''apporter la preuve de sa demande d''inscription; b) si elle n''a pas été réussie, d''apporter la preuve de sa réinscription à la première organisation suivante de l''unité d''enseignement, et à la suivante encore, avec l''accord motivé du conseil des études de l''unité d''enseignement, en cas de nouvel échec. Les membres du personnel diplômés d''un établissement d''enseignement officiel organisé ou subventionné par la Communauté française au plus tard durant l''année scolaire 2003-2004 sont réputés satisfaire à la condition de formation à la neutralité visée ci-dessus; Docu 40701 D. 11-04-2014 3) de s''être porté candidat pour cette fonction auprès de son Pouvoir organisateur par lettre recommandée, sous peine de forclusion, avant le 31 juillet 2017. Dans l''enseignement ordinaire, les membres du personnel sont obligatoirement candidats à concurrence du volume de périodes qui était le leur au sein du Pouvoir organisateur au 30 juin 2017. Dans l''hypothèse où le Pouvoir organisateur doit départager plusieurs candidats, il lui revient de désigner celui qui a acquis la plus grande ancienneté de service auprès de lui, calculée conformément à l''article 29bis du décret du 1er février 1993 précité. En cas d''égalité, il est fait référence à l''ancienneté de fonction. § 2. Pour l''application du § 1er, le membre du personnel ne peut pas se voir attribuer un nombre total des périodes de philosophie et citoyenneté supérieur au nombre total de périodes de morale, religion et d''encadrement pédagogique alternatif qui lui étaient attribuées au 30 juin 2017. Si le membre du personnel refuse les attributions qui lui sont proposées, il perd le bénéfice des dispositions transitoires de la section VII. Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 327, 'Article 293septdecies', 'Article 293septdecies/13. -  Les membres du personnel visés aux 1°, 
2°, 3°, 4° et 5° du § 1er de l''article 293septdecies/12, voient leurs anciennetés 
de fonction acquise auprès du Pouvoir organisateur en qualité de professeurs 
de religion ou de morale non confessionnelle, réputées comme ancienneté de 
fonction acquise, au sens de l''article 29bis du décret du 1er février 1993 
précité, en qualité de professeur de philosophie et de citoyenneté, 
respectivement au degré inférieur ou supérieur selon le cas. 
 
Toutefois, ils ne peuvent se prévaloir de cette valorisation que pour 
prétendre à la même fonction. 
 
§ 2 Les professeurs de religion et de morale non confessionnelle 
temporaires, visés aux 2°, 3°, 4° et 5° du § 1er de l''article 293septdecies/12, 
voient, à partir du 1er septembre 2017, leurs prestations dans la nouvelle 
fonction de professeur de philosophie et citoyenneté comptabilisée à la fois 
dans le calcul d''ancienneté de leur nouvelle et de leur ancienne fonction. 
 
Le bénéficie de la disposition visée à l''alinéa précédent trouve à 
s''appliquer jusqu''à la nomination du membre du personnel dans la nouvelle 
fonction de professeur de philosophie et citoyenneté, au prorata de la charge 
concernée par cette nouvelle nomination, et au plus tard jusqu''au 31 août 
2021. 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 328, 'Article 293septdecies', 'Article 293septdecies/14. - A titre transitoire pour la seule année 
scolaire 2017-2018, les professeurs de religion et de morale non 
confessionnelle temporaires prioritaires, visés aux 2° et 3° du § 1er de l''article 
293septdecies/12, ayant fait acte de candidature à l''engagement à titre 
définitif dans les conditions et formes requises à l''article 42 du décret du 1er 
février 1993 au cours de l''année scolaire 2016-2017, conservent leur droit à 
cet engagement à titre définitif dans leur ancienne fonction au cours de 
l''année scolaire 2017-2018, même s''ils prestent désormais entièrement au 
sein du Pouvoir organisateur en qualité de professeur de philosophie et 
citoyenneté. 
 
 
Docu 40701 
 
D. 11-04-2014  
Cet engagement à titre définitif s''effectue dans le respect des règles 
statutaires en vigueur, telles que fixées au chapitre III du décret du 1er 
février 1993 A sa demande, par dérogation à l''article 42 § 1er, 9° du décret du 
1er février 1993 précité, le membre du personnel visé par cet article peut 
bénéficier de cet engagement à titre définitif sans mettre fin à ses fonctions 
comme professeur de philosophie et citoyenneté. Dans ce cas, un congé pour 
exercer provisoirement une autre fonction lui est accordé d''office par son 
Pouvoir organisateur. 
 
Inséré par D. 19-07-2017 ; modifié par D. 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 329, 'Article 293septdecies', 'Article 293septdecies/15. - § 1er. La réaffectation temporaire des 
membres du personnel définitifs visés au 1° du § 1er de l''article 
293septdecies/12, sera reconduite automatiquement, selon les règles fixées en 
la matière par l''arrêté du Gouvernement de la Communauté française du 28 
août 1995, jusqu''à ce que le membre du personnel réponde aux conditions 
d''engagement à titre définitif fixées à l''article 42 du décret du 1er février 1993 
précité à l’exception du 3° de son § 1er, et ce sous condition pour lui d''avoir, 
avant le 1er septembre 2021 acquis le certificat en didactique du cours de 
philosophie et de citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 
avril 2014 précité, pour autant que le titre fixé par le Gouvernement, pour 
l''exercice de cette fonction l''exige. 
 
Par dérogation, le membre du personnel peut demander auprès de son 
Pouvoir organisateur, sans qu''il puisse la refuser, la non-reconduction de sa 
réaffectation temporaire. La demande doit avoir été faite par courrier 
recommandé pour le 15 mai pour l''année scolaire suivante. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 2. Le congé pour exercer provisoirement une autre fonction dans 
l''enseignement des membres du personnel définitifs visés au 1° du même 
article sera reconduit automatiquement tant que leur désignation sera 
également reconduite selon les règles fixées en la matière par le chapitre III 
du décret du 1er février 1993, et jusqu''à ce que le membre du personnel 
réponde aux conditions de nomination fixées à l''article 42 du même décret du 
1er février 1993 à l’exception du 3° de son § 1er, et sous condition pour lui 
d''avoir, avant le 1er septembre 2021 acquis le certificat en didactique du 
cours de philosophie et de citoyenneté visé à l''article 24bis, alinéa 3, du 
décret du 11 avril 2014 précité, pour autant que le titre fixé par le 
Gouvernement, pour l''exercice de cette fonction l''exige. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 3. Pour les membres du personnel temporaire visés au 2°, 3°, 4° et 5° 
du § 1er de l''article 293septdecies/12, leur engagement sera reconduit selon 
les règles fixées en la matière par le chapitre III du décret 1er février 1993 
précité, jusqu''à ce que le membre du personnel réponde aux conditions de 
nomination fixées à l''article 42 du même décret du 1er février 1993, et sous 
condition pour lui d''avoir, avant le 1er septembre 2021 : 
1°) acquis le certificat en didactique du cours de philosophie et de 
citoyenneté visé à l''article 24bis, alinéa 3 du décret du 11 avril 2014 précité, 
 
 
Docu 40701 
 
D. 11-04-2014  
pour autant que le titre fixé par le Gouvernement, pour l''exercice de cette 
fonction l''exige; 
2°) acquis, dans le cas du 3° et 5°, un titre pédagogique, conformément 
aux articles 17 et 18 du décret du 11 avril 2014 précité. 
 
Dans l''hypothèse où le membre du personnel ne répond pas au 1er 
septembre 2021 à ces conditions, il perd à la même date le bénéfice des 
mesures transitoires fixées par le présent décret. 
 
§ 4. Si le membre du personnel refuse les attributions qui lui sont 
proposées, ou demande la non-reconduction de sa réaffectation temporaire, il 
perd le bénéfice des dispositions transitoires de la présente section. 
 
Inséré par D. 03-05-2019 
§ 5. Par dérogation au § 2 de l''article 34 du décret du 1er février 1993 
précité, les membres du personnel, visés par le présent article et qui 
continuent à répondre au 1er septembre 2021 aux conditions pour pouvoir 
bénéficier des dispositions transitoires, sont réputés être porteur du titre 
requis pour exercer et être nommés dans la fonction de professeur de 
philosophie et citoyenneté au degré dans laquelle ils bénéficient des mesures 
transitoires, sans préjudice du § 3. Cette disposition n''est pas d''application 
pour la fixation du barème. 
 
Inséré par D. 19-07-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 330, 'Article 293septdecies', 'Article 293septdecies/16. - Au sein du même établissement, les 
membres du personnel bénéficiant des dispositions fixées à la présente sous-
section ne peuvent, au cours de la même année scolaire, exercer leur nouvelle 
fonction face au même élève, concomitamment avec une charge de professeur 
de religion ou de morale non confessionnelle. 
 
Par dérogation à l''alinéa 1er, dans l''enseignement spécialisé, un membre 
du personnel peut exercer les deux fonctions susvisées face au même élève : 
1° si celui-ci relève de l''enseignement de forme 1 et 2 ; 
ou 
2° si celui-ci relève de l''enseignement de forme 3 et 4 mais que les 
spécificités du public visé le requièrent. Cette spécificité est dûment 
constatée au sein du conseil d''entreprise, ou, à défaut, de la délégation 
syndicale du pouvoir organisateur concerné 
 
Insérée par D. 19-07-2017 
Sous-section 3. - Dispositions transitoires relatives à la 
rémunération 
 
Complété par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 331, 'Article 293septdecies', 'Article 293septdecies/17. - Les membres du personnel nommés ou 
engagés à titre définitif ou réunissant les conditions fixées à l''article 285 du 
présent décret au 31 août 2017 et visés aux sous-sections 1 et 2 du présent 
titre ainsi qu''aux chapitres XIquater de l''arrêté royal du 22 mars 1969 
précité et Xter de l''arrêté royal du 25 octobre 1971 précité, bénéficient 
lorsqu''ils y sont recrutés, sans limite de temps, des échelles de traitement 
attachées aux nouvelles fonctions de professeur de philosophie et de 
citoyenneté, respectivement selon le cas au degré inférieur ou supérieur, sauf 
si l''échelle de traitement afférente à leur fonction d''origine leur procure une 
rémunération plus élevée. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Pour les membres du personnel désignés ou engagés à titre temporaire 
débutant le 1er septembre 2017 et prenant fin, au plus tard, le 30 juin 2018, 
le bénéfice de l''échelle de traitement afférente à la fonction d''origine, 
lorsqu''elle est plus favorable, ne vaut que pour l''année scolaire 2017-2018. 
 
Inséré par D. 19-07-2021 
A l''échéance de la mesure transitoire fixée à l''alinéa 1er de l''article 293 
septdecies/18, à condition d''avoir déjà exercé au 1er septembre 2021 la 
fonction de professeur de philosophie et citoyenneté au DI ou de professeur 
de philosophie et citoyenneté au DS pendant 315 jours acquis sur deux ans 
auprès du même pouvoir organisateur et calculés conformément aux 
dispositions propres à chaque statut, les membres du personnel ayant été 
recrutés en l''absence de certificat en didactique conservent au cours de 
l''année scolaire 2021-2022 l''échelle de traitement qui leur était attribuée 
pour l''exercice de cette fonction avant cette date si celle-ci leur est plus 
favorable. 
 
Insérée par D. 19-07-2017 ; intitulé remplacé par D. 11-07-2018 
Sous-section 4. - Dispositions transitoires relatives au certificat en 
didactique de la philosophie et citoyenneté, au classement des 
temporaires prioritaires et la nomination ou engagement à titre 
définitif 
 
Modifié par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 332, 'Article 293septdecies', 'Article 293septdecies/18. - Par mesure transitoire, dans l''attente de la 
création du certificat prévu à l''article 24bis, alinéa 3 du présent décret et au 
plus tard jusqu''au 1er septembre 2021, la possession de ce certificat pour 
l''exercice de la fonction de professeur de philosophie et de citoyenneté n''est 
pas exigée. 
 
Pour l''enseignement subventionné par la Communauté française, les 
professeurs de philosophie et citoyenneté ne peuvent être désignés en qualité 
de temporaires prioritaires et être nommés qu''à partir du 1er septembre 2021, 
sauf ceux visés par les dispositions transitoires de la section VII du chapitre 
II du titre III du décret du 11 avril 2014. 
 
 
Inséré par D. 11-07-2018 
Jusqu''au 31 août 2021, les professeurs de philosophie et de citoyenneté 
bénéficiant des dispositions transitoires prévues à l''alinéa précédent ne 
peuvent être nommés ou engagés à titre définitif que pour le volume de 
charge qui leur a été attribué dans cette fonction, au 1er octobre de l''année 
scolaire où doit intervenir la nomination ou engagement à titre définitif. 
 
Pour l''enseignement organisé par la Communauté française, les 
professeurs de philosophie et citoyenneté ne peuvent être désignés en qualité 
de temporaires prioritaires qu''à partir du 1er septembre 2021 et être nommés 
qu''à partir du 1er janvier 2022, sauf ceux visés par les dispositions 
transitoires reprises au chapitre XIquater de l''arrêté royal du 22 mars 1969 
fixant le statut des membres du personnel directeur et enseignant et du 
chapitre Xter de l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres 
et des professeurs de religion, pour l''enseignement organisé par la 
Communauté française. 
 
 
 
Docu 40701 
 
D. 11-04-2014  
Le membre du personnel dont le titre de capacité fixé par le 
Gouvernement, pour l''exercice de la fonction de professeur de philosophie et 
de citoyenneté, exige la possession du certificat prévu à l''article 24bis, alinéa 
3, ne pourra être nommé que lorsqu''il sera détenteur de ce certificat. 
 
Inséré par D. 19-07-2021 
Dans l''enseignement officiel subventionné, lors de l''année scolaire 2020-
2021, par dérogation aux dispositions de l''alinéa 5 de l''article 31 du décret du 
6 juin 1994 fixant le statut des membres du personnel subsidiés de 
l''enseignement officiel subventionné, l''avis visé au même alinéa est distribué 
à tous les membres du personnel exerçant la fonction maître de philosophie 
et citoyenneté au sein du pouvoir organisateur. 
 
CHAPITRE III. - Disposition finale 
 
Modifié par D. 19-10-2017');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('40701', 333, 'Article 294. - Le présent décret entre en vigueur le 1er septembre 2016', 'Article 294. - Le présent décret entre en vigueur le 1er septembre 2016 
à l''exception du chapitre 5 du titre I ainsi que de l''article 292 qui entre en 
vigueur au 1er septembre 2014 et des articles 27 et 28 qui entrent en vigueur 
au 1er septembre 2015 et de l''article 29, § 5 qui entre en application le 1er 
novembre 2017. 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur 
belge. 
 
Bruxelles, le 11 avril 2014. 
 
Le Ministre-Président du Gouvernement de la Communauté française, 
R. DEMOTTE 
Le Vice-Président et Ministre de l''Enfance, de la Recherche et de la Fonction 
publique, 
J.-M. NOLLET 
Le Vice-Président et Ministre du Budget, des Finances et des Sports, 
A. ANTOINE 
Le Vice-Président et Ministre de l''Enseignement supérieur, 
J.-Cl. MARCOURT 
La Ministre de la Jeunesse, 
Mme E. HUYTEBROECK 
La Ministre de la Culture, de l''Audiovisuel, de la Santé et de l''Egalité des 
chances, 
Mme F. LAANAN 
La Ministre de l''Enseignement obligatoire et [d’enseignement pour adultes] 
Mme M.-M. SCHYNS');

-- CDA 46287 (54 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 0, '', 'Docu 46287 
 
D. 14-03-2019  
Décret portant diverses dispositions relatives à 
l''organisation du travail des membres du personnel de 
l''enseignement et octroyant plus de souplesse 
organisationnelle aux Pouvoirs organisateurs  
 
D. 14-03-2019  
M.B. 27-03-2019 
 
Modifications : 
D. 17-07-2020  -  M.B. 04-08-2020 
D. 17-06-2021  -  M.B. 06-08-2021 
D. 20-07-2023 – M.B. 22-11-2023 
D. 16-05-2024 – M.B. 24-09-2024  
D. 17-06-2021  -  M.B. 30-07-2021 
D. 19-07-2021  -  M.B. 30-08-2021 
D. 20-11-2025 – M.B. 04-12-2025 
D. 24-02-2022  -  M.B. 12-04-2022 
D. 13-10-2022  -  M.B. 19-12-2022 
D. 27-04-2023  -  M.B. 19-09-2023 
D. 22-06-2023  -  M.B. 25-10-2023 
 
 
Le Parlement de la Communauté française a adopté et Nous, 
Gouvernement, sanctionnons ce qui suit : 
 
TITRE 1er. - Dispositions générales');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 1, 'Article 1er. - Les dispositions du présent décret s''appliquent à', 'Article 1er. - Les dispositions du présent décret s''appliquent à 
l''enseignement maternel, primaire, secondaire de plein exercice et en 
alternance, ordinaire et spécialisé, organisé ou subventionné par la 
Communauté française. 
 
L''article 17 du présent décret s''applique aux internats, homes d''accueil 
et homes d''accueil permanent organisés par la Communauté française. 
 
TITRE II. - Dispositions relatives à la charge des membres du 
personnel enseignant 
 
CHAPITRE 1er. - Les composantes de la charge 
 
Modifié par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 2, 'Article 2. - § 1er. La charge enseignante est composée :', 'Article 2. - § 1er. La charge enseignante est composée : 
1. du travail en classe; 
2. du travail pour la classe; 
3. du service à l''école et aux élèves; 
4. la formation professionnelle continue; [remplacé par D. 17-06-2021] 
5. du travail collaboratif qui est une modalité d''exercice transversale des 
composantes 1° à 4°. 
 
§ 2. Les périodes visées dans les composantes du § 1er sont 
comptabilisées en périodes de 50 minutes. 
 
§ 3. Le règlement de travail est mis en conformité avec le présent décret 
et détermine les modalités de l''exercice des différentes composantes de la 
charge du personnel. 
 
 
 
Docu 46287 
 
D. 14-03-2019  
§ 4. Les membres du personnel assistant aux organes locaux de 
concertation sociale verront une ou plusieurs des composantes de la charge 
visée aux points 1°, 3° ou 5° du § 1er réduites à concurrence de la durée de ces 
séances. 
 
CHAPITRE II. - Le travail en classe 
 
Modifié par D. 19-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 3, 'Article 3. - § 1er.', 'Article 3. - § 1er. 
Dans 
l''enseignement 
ordinaire, 
l''horaire 
hebdomadaire de travail en classe pour une fonction à prestations complètes : 
1. d''instituteur maternel est de 26 périodes; 
2. du maître de psychomotricité, dans l''enseignement maternel, est de 26 
périodes; 
3. d''instituteur primaire est de 24 périodes; 
4. des maîtres de morale, de religion catholique, de religion islamique, de 
religion israélite, de religion orthodoxe, de religion protestante, de philosophie 
et de citoyenneté, d''éducation physique, de seconde langue : néerlandais, de 
seconde langue : anglais, de seconde langue : allemand, dans l''enseignement 
primaire, est de 24 périodes; 
5. de professeur de cours généraux, de cours techniques et de morale non 
confessionnelle ainsi que de religion catholique, de religion islamique, de 
religion israélite, de religion orthodoxe, de religion protestante au degré 
inférieur est de 22 périodes; 
6. de professeur de cours généraux, de cours techniques, de morale non 
confessionnelle ainsi que de religion catholique, de religion islamique, de 
religion israélite, de religion orthodoxe, de religion protestante au degré 
supérieur est de 20 périodes; 
7. de professeur de cours de pratique professionnelle est de 28 périodes, à 
l''exception de l''horaire hebdomadaire des membres du personnel bénéficiant 
des mesures transitoires prévues aux paragraphes 3 des articles 271 et 289 du 
décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française; 
7bis. de professeur de cours de pratique professionnelle (1e degré) est de 
22 périodes, à l''exception de l''horaire hebdomadaire des membres du personnel 
bénéficiant des mesures transitoires prévues aux paragraphes 3 des articles 
271 et 289 du décret du 11 avril 2014 réglementant les titres et fonctions dans 
l''enseignement fondamental et secondaire organisé et subventionné par la 
Communauté française ; [Inséré par D. 19-07-2021] 
8. d''accompagnateur CEFA est de 34 périodes. 
 
§ 2. Dans l''enseignement spécialisé, l''horaire hebdomadaire de travail en 
classe pour une fonction à prestations complètes : 
1. d''instituteur maternel est de 24 périodes; 
2. des maîtres d''éducation physique, dans l''enseignement maternel, est 
de 24 périodes; 
3. d''instituteur primaire est de 22 périodes; 
4. des maîtres de morale, de religion catholique, de religion islamique, de 
religion israélite, de religion orthodoxe, de religion protestante, de philosophie 
et de citoyenneté, d''éducation physique, de seconde langue : néerlandais, de 
seconde langue : anglais, de seconde langue : allemand, dans l''enseignement 
primaire est de 22 périodes; 
5. de professeur de cours généraux au degré inférieur est de 20 périodes; 
6. de professeur de cours techniques au degré inférieur (formes 1, 2 et 3) 
est de 22 périodes; 
 
 
Docu 46287 
 
D. 14-03-2019  
7. de professeur de cours techniques au degré inférieur (forme 4) est de 
20 périodes; 
8. de professeur de pratique professionnelle au degré inférieur (formes 1, 
2 et 3) est de 22 périodes; 
9. de professeur de morale non confessionnelle, de religion catholique, de 
religion islamique, de religion israélite, de religion orthodoxe, de religion 
protestante au degré inférieur est de 20 périodes; 
10. de professeur de pratique professionnelle au degré inférieur (forme 4 
du 1er degré) est de 20 périodes; 
11. de professeur de pratique professionnelle au degré inférieur (forme 4 
du 2ème degré) est de 26 périodes, à l''exception de l''horaire hebdomadaire des 
membres du personnel bénéficiant des mesures transitoires prévues aux 
paragraphes 3 des articles 271 et 289 du décret du 11 avril 2014 réglementant 
les titres et fonctions dans l''enseignement fondamental et secondaire organisé 
et subventionné par la Communauté française; 
12. de professeur de cours généraux au degré supérieur (forme 4) est de 
18 périodes; 
13. de professeur de cours techniques au degré supérieur (forme 4) est de 
18 périodes; 
14. de professeur de morale non confessionnelle, de religion catholique, 
de religion islamique, de religion israélite, de religion orthodoxe, de religion 
protestante au degré supérieur (forme 4) est de 18 périodes; 
15. de professeur de pratique professionnelle au degré supérieur (forme 
4) est de 26 périodes, à l''exception de l''horaire hebdomadaire des membres du 
personnel bénéficiant des mesures transitoires prévues aux paragraphes 3 des 
articles 271 et 289 du décret du 11 avril 2014 réglementant les titres et 
fonctions dans l''enseignement fondamental et secondaire organisé et 
subventionné par la Communauté française. [Inséré par D. 19-07-2021]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 4, 'Article 4. - Par dérogation à l''article 3, dans l''enseignement ordinaire,', 'Article 4. - Par dérogation à l''article 3, dans l''enseignement ordinaire, 
un membre du personnel enseignant peut dépasser cet horaire hebdomadaire 
s''il accepte des périodes additionnelles dans le cadre de l''application de l''article 
5. 
 
Par dérogation à l''article 3, dans l''enseignement spécialisé, un membre 
du personnel enseignant peut dépasser cet horaire hebdomadaire augmenté de 
deux périodes de travail collaboratif, s''il accepte des périodes additionnelles 
dans le cadre de l''application de l''article 5. 
 
Modifié par D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 5, 'Article 5. - § 1er. On entend par «période additionnelle», toute période (partie 1)', 'Article 5. - § 1er. On entend par «période additionnelle», toute période dépassant la notion de fonction à prestations complètes au sens de l''article 4 de l''arrêté royal du 15 avril 1958 portant statut pécuniaire du personnel enseignant, scientifique et assimilé du Ministère de l''Instruction Publique et de l''article 7 de l''arrêté du Gouvernement de la Communauté française du 25 octobre 1993 portant statut pécuniaire des membres du personnel directeur et enseignant et du personnel auxiliaire d''éducation de l''enseignement de promotion sociale de la Communauté française. Les périodes additionnelles ne donnent pas lieu à pécule de vacances, allocation de fin d''année et traitement différé. Sans préjudice des dispositions relatives à la fixation du traitement des enseignants exerçant une fonction principale à prestations complètes, ou incomplètes formant une unité, l''agent qui preste des périodes additionnelles Docu 46287 D. 14-03-2019 dans une seule fonction se voit appliquer l''échelle de traitement relative à la fonction considérée. Lorsque l''agent preste des périodes additionnelles dans plusieurs fonctions, le calcul de la rémunération est opéré pour chaque fonction. § 2. Ces périodes sont attribuées aux membres du personnel de la catégorie du personnel directeur et enseignant par le pouvoir organisateur, dans l''enseignement organisé et subventionné par la Communauté française, après application des règles statutaires de dévolution des emplois aux membres du personnel. Pour l''enseignement maternel et primaire, ces périodes sont en outre attribuées : a soit par défaut de candidat de niveau de titre de capacité listé plus élevé, de même niveau ou d''un niveau juste inférieur à celui du membre du personnel dont on se propose de porter la charge au-delà d''un temps plein pour un maximum de 4 périodes, b soit par défaut de candidat de niveau de titre de capacité listé plus élevé, de même niveau ou d''un niveau juste inférieur à celui du membre du personnel dont on se propose de porter la charge au-delà du temps presté, suite à un congé à temps partiel non rémunéré, pour un maximum de 4 périodes. Pour l''enseignement secondaire, ces périodes sont en outre attribuées : a. soit, en ne dépassant pas deux périodes, en vue d''éviter le fractionnement d''un bloc de cours dispensé par ce même membre du personnel; b. soit par défaut de candidat de niveau de titre de capacité listé plus élevé, de même niveau ou d''un niveau juste inférieur à celui du membre du personnel dont on se propose de porter la charge au-delà d''un temps plein pour un maximum de 4 périodes. Par dérogation, 6 périodes peuvent être attribuées à un même membre du personnel lorsqu''elles forment un seul bloc de cours; c. soit par défaut de candidat de niveau de titre de capacité listé plus élevé, de même niveau ou d''un niveau juste inférieur à celui du membre du personnel dont on se propose de porter la charge au-delà du temps presté, suite à un congé à temps partiel non rémunéré, pour un maximum de 4 périodes. Par dérogation, 6 périodes peuvent être attribuées à un même membre du personnel lorsqu''elles forment un seul bloc de cours. Ces périodes additionnelles ne peuvent être attribuées que pour du travail en classe. Après application des règles statutaires de dévolution des emplois, si plusieurs enseignants revendiquent ces périodes, elles sont attribuées selon un ordre de priorité fixé selon la qualité requise, suffisante, de pénurie ou «autre» du titre du membre du personnel pour la fonction visée telle que définie par l''arrêté du Gouvernement de la Communauté française du 5 juin 2014 relatif aux fonctions, titres de capacité et barèmes portant exécution des articles 7, 16, 50 et 263 du décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française. Alinéa complété par D. 17-07-2020 Les périodes attribuées en vertu des points a) et b) de l''alinéa 2, b) et c) de l''alinéa 3 ne peuvent l''être qu''à un membre du personnel définitif ou un membre du personnel temporaire prioritaire dans l''enseignement organisé ou subventionné par la Communauté française ou à un membre du personnel Docu 46287 D. 14-03-2019 temporaire classé dans les premiers groupes visés à l''article 2 §§ 1 et 2 de l''arrêté royal du 22 juillet 1969, fixant les règles d''après lesquelles sont classés les candidats à une désignation à titre temporaire dans l''enseignement de l''Etat, et ce peu importe son statut dans le pouvoir organisateur dans lequel il preste les périodes additionnelles. Les services prestés dans ce cadre sont valorisables dans le calcul de l''ancienneté de fonction et de service tels que prévus dans les différents statuts en vue de faire valoir des droits statutaires à la priorité à la désignation ou à l''engagement à titre temporaire dans l''enseignement subventionné ou être désigné en qualité de temporaire prioritaire ou protégé dans l''enseignement organisé par la Communauté française. Les p');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 6, 'Article 5. - § 1er. On entend par «période additionnelle», toute période (partie 2)', 'additionnelles n''entrent pas en considération dans les limites des 1560 minutes par semaine ou des 962 heures par an fixées aux articles 18, § 3, 19, § 2, 20, §§ 2 et 3, et 21, §§ 2 et 3, du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement, et aux articles 29, § 2, et 30, §§ 2 et 3, du décret du 3 mars 2004 organisant l''enseignement spécialisé. En aucun cas, l''octroi de périodes additionnelles ne peut conduire à une nomination ou à un engagement à titre définitif au-delà d''une charge complète. Inséré par D. 17-07-2020 § 3. Ne sont pas couverts par la notion de «congé» visé au § 2, alinéa 2, b et au § 2, alinéa 3, c : a) le congé pour interruption de la carrière professionnelle visé dans l''arrêté de l''exécutif de la Communauté française du 3 décembre 1992 relatif à l''interruption de la carrière professionnelle dans l''enseignement et les centres psycho-médico-sociaux; b) la disponibilité précédant la pension de retraite visée dans l''arrêté royal n° 297 du 31 mars 1984 relatif aux charges, traitements, subventions- traitements et congés pour prestations réduites dans l''enseignement et les centres psycho-médico-sociaux; c) le congé pour l''exercice provisoire d''une fonction de sélection visé à l''article 14, § 1er, 1° de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement gardien, primaire, spécial, moyen, technique, artistique et normal de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements; d) le congé pour l''exercice provisoire d''une fonction de promotion visé à l''article 14, § 1er, 2° de l''arrêté royal du 15 janvier 1974 précité; e) le congé pour prestations réduites en cas de maladie ou d''infirmité visé aux articles 19 à 22bis de l''arrêté royal du 15 janvier 1974 précité; f) le congé pour prestations réduites bénéficiant aux membres du personnel en disponibilité pour cause de maladie ou d''infirmité à des fins thérapeutiques visé aux articles 22ter à 22nonies de l''arrêté royal du 15 janvier 1975 précité; g) le congé pour prestations réduites en cas de maladie professionnelle; h) le congé pour prestations réduites en cas d''accident du travail ou d''accident survenu sur le chemin du travail; i) le congé syndical permanent visé à l''article 29 de l''arrêté royal du 15 janvier 1974 précité; Docu 46287 D. 14-03-2019 j) la perte partielle de charge ou disponibilité par défaut d''emploi sans qu''une réaffectation ait eu lieu; k) le congé pour accomplir un stage dans un autre emploi visé à l''article 9, littera b de l''arrêté royal du 15 janvier 1974 précité; l) l''absence de longue durée justifiée par des raisons familiales visées par l''arrêté royal du 25 novembre 1976 relatif aux absences de longue durée justifiées par des raisons familiales; m) les écartements des femmes enceintes ou allaitantes (rémunérés ou non). CHAPITRE III. - Le travail pour la classe');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 7, 'Article 6. - § 1er. Le travail pour la classe visé à l''article 2, § 1er, 2°,', 'Article 6. - § 1er. Le travail pour la classe visé à l''article 2, § 1er, 2°, 
comprend, notamment, les missions suivantes : 
a. la préparation et l''élaboration des séquences d''enseignement; 
b. la préparation des supports des séquences d''enseignement; 
c. la préparation, la correction et l''encodage des évaluations; 
d. la gestion administrative des élèves qui lui sont confiés et de la ou des 
classes qui lui sont confiées; 
e. la gestion pédagogique des élèves qui lui sont confiés et de la ou des 
classes, qui lui sont confiées, le cas échéant avec le centre psycho-médico-social 
et, pour l''enseignement spécialisé, dans le respect de la concertation prévue à 
l''article 2, § 4, du décret du 3 mars 2004 précité. 
 
§ 2. Les membres du personnel visés par le présent titre sont indemnisés 
pour l''utilisation à des fins professionnelles de leur outil informatique privé et 
de leur connexion internet privée, dans le cadre des composantes définies à 
l''article 2, § 1er, notamment 1° et 2°, au titre de remboursement de frais 
propres à l''employeur. 
 
Cette indemnisation correspond à un montant forfaitaire annuel de 100 
euros, liquidé avant le 31 décembre de chaque année civile au cours de laquelle 
le membre du personnel peut se prévaloir d''une ou plusieurs périodes de 
prestations constituant au total au moins 90 jours de prestations 
d''enseignement effectives au cours de l''année civile, à la date du 30 novembre 
incluse. Ce montant est liquidé directement aux membres du personnel par les 
Services du Gouvernement [et ne peut être obtenu qu''une seule fois par année 
civile quel que soit le type ou le niveau d''enseignement.]1 
 
CHAPITRE IV. - Le service à l''école et aux élèves');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 8, 'Article 7. - Les missions du service à l''école et aux élèves visées à l''article', 'Article 7. - Les missions du service à l''école et aux élèves visées à l''article 
2, § 1er, 3°, recouvrent deux types de missions : 
1° les missions obligatoires pour tous les membres du personnel 
enseignant; 
 
2°les missions collectives dont les thématiques sont le cas échéant prises 
en charge au niveau de l''établissement scolaire en en confiant la charge à un 
ou plusieurs membres du personnel déterminés.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 9, 'Article 8. - § 1er. Dans l''enseignement fondamental ordinaire, les (partie 1)', 'Article 8. - § 1er. Dans l''enseignement fondamental ordinaire, les missions visées à l''article 7, 1°, sont les suivantes : 1Inséré par le D. 20-11-2025 Docu 46287 D. 14-03-2019 1. sur la base d''un calendrier annuel ou trimestriel fixé anticipativement, la participation aux réunions entre membres de l''équipe éducative et parents; 2. la participation durant les heures scolaires aux activités socioculturelles et sportives en lien avec le projet d''établissement; 3. la participation aux réunions où sont abordées les évaluations certificatives et formatives, dont celles relatives, le cas échéant, au maintien d''un élève; 4. les minutes de surveillance par semaine comprises dans les 1560 minutes visées aux articles 18, § 3, et 19, § 2, du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement; 5. les autres services rentrant dans les prestations nécessaires à la bonne marche des établissements visées aux articles 17 et 17bis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné; 10 et 10bis du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné et 9 et 9bis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. § 2. Dans l''enseignement secondaire ordinaire et spécialisé de forme 4, les missions visées à l''article 7, 1°, sont les suivantes : 1. sur la base d''un calendrier annuel ou trimestriel fixé anticipativement, la participation aux réunions entre membres de l''équipe éducative et parents; 2. la participation durant les heures scolaires aux activités socioculturelles et sportives en lien avec le projet d''établissement; 3. la participation aux jurys de qualification et aux conseils de guidance; 4. la participation aux conseils de classe - fixés anticipativement dans un calendrier annuel ou trimestriel, ceux où sont abordées les évaluations formatives et certificatives, et ceux où sont prises des décisions en matière de sanction des études. 5. les autres services rentrant dans les prestations nécessaires à la bonne marche des établissements visées aux articles 17 et 17bis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné, 10 et 10bis du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné et 9 et 9bis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. § 3. Dans l''enseignement maternel et primaire spécialisé, les missions visées à l''article 7, 1°, sont les suivantes : 1. sur la base d''un calendrier annuel ou trimestriel fixé anticipativement, la participation aux réunions entre membres de l''équipe éducative et parents; 2. la participation durant les heures scolaires aux activités socioculturelles et sportives en lien avec le projet d''établissement; 3. la participation aux conseils de classe fixés anticipativement dans un calendrier annuel ou trimestriel; Docu 46287 D. 14-03-2019 4. les minutes de surveillances par semaine comprises dans les 1560 minutes visées aux articles 29, § 2, et 30, § 2, du décret du 3 mars 2004 précité; 5. les autres services rentrant dans les prestations nécessaires à la bonne marche des établissements visées aux articles 17 et 17bis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné, 10 et 10bis du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné et 9 et 9bis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. § 4. Dans l''enseignement secondaire spécialisé de formes 1, 2 et 3 les missions visées à l''article 7, 1°, sont les suivantes : 1. sur la base d''un calendrier annuel ou trime');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 10, 'Article 8. - § 1er. Dans l''enseignement fondamental ordinaire, les (partie 2)', 'fixé anticipativement, la participation aux réunions entre membres de l''équipe éducative et parents; 2. la participation durant les heures scolaires aux activités socioculturelles et sportives en lien avec le projet d''établissement; 3. la participation aux jurys de qualification; 4. la participation aux conseils de classe fixés anticipativement dans un calendrier annuel ou trimestriel; 5. les autres services rentrant dans les prestations nécessaires à la bonne marche des établissements visées aux articles 17 et 17bis du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné, 10 et 10bis du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné et 9 et 9bis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements. § 5. Les modalités pratiques de ces missions sont concertées annuellement au sein de l''organe local de concertation sociale. Complété par D. 24-02-2022 ; D. 13-10-2022 ; D. 27-04-2023');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 11, 'Article 9. - § 1er. Les missions visées à l''article 7, 2°, sont les suivantes : (partie 1)', 'Article 9. - § 1er. Les missions visées à l''article 7, 2°, sont les suivantes : 1. délégué en charge de la communication interne à l''établissement; 2. délégué chargé du support administratif et/ou pédagogique à la direction; 3. délégué en charge des relations avec les partenaires extérieurs de l''établissement scolaire; 4. délégué en charge de la confection des horaires; 5. délégué en charge de la coordination des stages des élèves; 6. délégué - référent pour les membres du personnel temporaire autre que débutant; 7. délégué en charge de coordination pédagogique; 8. délégué - référent pour les membres du personnel débutants y compris les temporaires débutants; 9. délégué en charge de la coordination des maîtres de stage; 10. délégué en charge de la coordination des enseignants référents; Docu 46287 D. 14-03-2019 11. délégué en charge des relations avec les parents; 12. délégué - référent numérique; 13. délégué en charge du climat scolaire et du bien-être à l''école ; [modifié par D. 27-04-2023] 14. délégué en charge de l''orientation des élèves; 15. délégué - référent aux besoins spécifiques et aux aménagements raisonnables ; 16° délégué-PECA en charge de la coordination du parcours d''éducation culturelle et artistique. [Inséré par D. 13-10-2022] [17° délégué en charge du mécanisme de soutien et de développement des compétences professionnelles des membres du personnel]2. [18. garant de l''accrochage scolaire visé à l''article 1.7.1-30 du Code de l''enseignement fondamental et de l''enseignement secondaire.]3 § 2. Les missions visées au § 1er, point 7) à 15), requièrent que le membre du personnel à qui la mission est confiée ait suivi ou se soit engagé à démarrer, endéans l''année scolaire, une formation spécifique définie ou reconnue par le pouvoir organisateur. [§2bis. La mission au §1er, point 17. requière que l''enseignant expérimenté à qui la mission est confiée ait suivi la formation préalable aux mécanismes de soutien et de développement des compétences professionnelles ainsi que d''évaluation visée à l''article 6.1.9-5 du Code de l''enseignement fondamental et de l''enseignement secondaire]4. § 3. Le pouvoir organisateur ou son délégué, dans l''enseignement subventionné, et le directeur, dans l''enseignement organisé, attribuent les missions visées au § 1er au terme d''un appel à candidatures lorsqu''y sont liées une ou plusieurs période(s) professeurs ou période(s) du capital-périodes octroyées en vertu du titre 7 du présent décret. Cet appel à candidatures est affiché dans l''école et distribué à tous les membres du personnel de l''établissement. L''appel à candidatures précise : a. le contenu de la mission, b. le nombre de périodes allouées et le temps de prestation, c. la durée de la mission et son caractère éventuellement renouvelable, d. la formation exigée, e. les éventuels critères complémentaires définis par le pouvoir organisateur ou son délégué, dans l''enseignement subventionné, ou par le directeur, dans l''enseignement organisé par la Communauté française. L''appel prévoit une période minimum de 10 jours ouvrables pour le dépôt des candidatures. L''appel est soumis à l''avis préalable, dans l''enseignement organisé par la Communauté française, du comité de concertation de base, dans l''enseignement officiel subventionné par la Communauté française, de la commission paritaire locale, et dans l''enseignement libre subventionné par la Communauté française, du conseil d''entreprise ou, de l''organe local de 2 Ajouté par le décret du 20 juillet 2023 3Inséré par le D. 16-05-2024 4 Ajouté par le décret du 20 juillet 2023 Docu 46287 D. 14-03-2019 concertation sociale, ou à défaut, de la délégation syndicale, avec droit d''évocation du bureau de conciliation en cas de désaccord. Les périodes consacrées à l''exercice des missions précitées doivent être accrochées par le pouvoir organisateur à une fonction de recrutement de la catégorie du personnel directeur et enseignant telle que définie par le décret du 11 avril 2014 précité. Inséré par D. 24-02-2022 § 4. A défaut de candidat et par dérogation aux articles 21 § 1er et 22, le pouvoir organisateur ou son délégué, dans l''enseignement subventionné, et le directeur, dans l''enseignement organisé par la Communauté française, peuvent attribuer, au terme d''un nouvel appel à candidatures, les missions visées au § 1er lorsqu''y sont liées une ou plusieurs période(s) professeurs ou période(s) du capital-périodes octroyées en vertu du titre 7 du présent décret, à un enseignant répondant aux conditions suivantes: 1. il n''a pas fait l''objet d''une évaluation défavorable dans les 10 dernières années; 2. il dispose d''une ancienneté de minimum 5 ans dans l''enseignement organisé ou subventionné par la Communauté française. L''appel à candidatures visé à l''alinéa précédent a lieu selon la procédure définie au § 3. [Le présent paragraphe ne s’applique pas à la mission prévue à l’article 9, §1er, 17°]5. [§5. A défaut de candidat après l''appel visé au §4 et par dérogation aux articles 21, §1er, et 22');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 12, 'Article 9. - § 1er. Les missions visées à l''article 7, 2°, sont les suivantes : (partie 2)', 'le Pouvoir organisateur peut attribuer les missions visées au §1er, lorsqu''y sont liées une ou plusieurs période(s) professeur(s) octroyée(s) en vertu du Titre 7 du présent décret, le cas échéant, à une direction avec charge de classe. Le présent paragraphe ne s''applique pas à la mission prévue à l''article 9, §1er, 17°.]6');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 13, 'Article 10. - Le', 'Article 10. - Le 
pouvoir 
organisateur, 
ou 
son 
délégué, 
dans 
l''enseignement subventionné par la Communauté française, ou le directeur, 
dans l''enseignement organisé par la Communauté française, peut élaborer, 
avec l''équipe éducative, une liste de missions complémentaires aux missions 
visées à l''article 9 dans le cadre du plan de pilotage ou du contrat d''objectifs. 
 
L''attribution de ces missions se fait selon la procédure prévue à l''article 
9, § 3, lorsqu''y sont liées une ou plusieurs période(s) professeurs ou période(s) 
du capital-périodes octroyées en vertu du titre 7 du présent décret.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 14, 'Article 11. - Le', 'Article 11. - Le 
pouvoir 
organisateur 
ou 
son 
délégué, 
dans 
l''enseignement subventionné par la Communauté française, ou le directeur, 
