INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 15, 'Article 12. - La formation professionnelle continue comprend l''ensemble', 'Article 12. - La formation professionnelle continue comprend l''ensemble 
du processus visé par le Titre Ier du Livre 6 du Code de l''enseignement 
fondamental et de l''enseignement secondaire. 
 
CHAPITRE VI. - Le travail collaboratif');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 16, 'Article 13. - Le travail collaboratif est le travail avec les autres membres', 'Article 13. - Le travail collaboratif est le travail avec les autres membres 
du personnel, et le cas échéant la direction, dans le cadre duquel le membre du 
personnel effectue tout ou partie des missions suivantes : 
a. la participation aux réunions des équipes pédagogique et éducative; 
b. le travail de collaboration dans une visée pédagogique, soutenu par la 
direction, avec d''autres membres du personnel, y compris d''autres 
établissements scolaires ou de centres PMS. 
 
Les périodes de travail collaboratif ne sont pas comptabilisées dans le 
capital-périodes ou le nombre total de périodes professeurs de l''établissement, 
sauf dans l''enseignement maternel et primaire spécialisé, où elles sont 
comptabilisées à concurrence des périodes prévues à l''article 14, §§ 2 et 4. 
 
Modifié par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 17, 'Article 14. - § 1er. Dans l''enseignement maternel ordinaire, les', 'Article 14. - § 1er. Dans l''enseignement maternel ordinaire, les 
membres du personnel enseignant exerçant une fonction à prestations 
complètes sont tenus d''accomplir 60 périodes par année scolaire de travail 
collaboratif, en dehors des périodes visées à l''article 3, des missions visées à 
l''article 8 et des jours obligatoires de formation professionnelle continue 
prévus par le Livre 6, Titre Ier, du Code de l''enseignement fondamental et de 
l''enseignement secondaire. 
 
§ 2. Dans l''enseignement maternel spécialisé, les membres du personnel 
enseignant sont tenus d''accomplir en supplément de leur travail en classe 
l''équivalent de : 
1. 2 périodes de travail collaboratif par semaine si leurs prestations sont 
comprises entre 12 et 24 périodes au sein du même pouvoir organisateur; 
2. 1 période de travail collaboratif par semaine si leurs prestations sont 
comprises entre 7 et 11 périodes au sein du même pouvoir organisateur. 
 
En deçà de 7 périodes par semaine au sein du même pouvoir organisateur, 
leurs obligations se limitent à la transmission et à la prise de connaissance des 
informations utiles à la bonne organisation des activités pédagogiques. 
 
Lorsqu''un membre du personnel n''est pas tenu de prester l''équivalent de 
deux périodes de travail collaboratif, il ne peut être considéré comme exerçant 
une fonction à prestations complètes que si les périodes de travail collaboratif 
non prestées sont remplacées par du travail en classe. 
 
 
 
Docu 46287 
 
D. 14-03-2019  
§ 3. Dans l''enseignement primaire ordinaire, les membres du personnel 
enseignant exerçant une fonction à prestations complètes sont tenus 
d''accomplir au moins 60 périodes par année scolaire de travail collaboratif, en 
dehors des périodes visées à l''article 3, des missions visées à l''article 8 et des 
jours obligatoires de formation professionnelle continue prévus par le Livre 6, 
Titre Ier, du Code de l''enseignement fondamental et de l''enseignement 
secondaire. 
 
§ 4. Dans l''enseignement primaire spécialisé, les membres du personnel 
enseignant sont tenus d''accomplir en supplément de leur travail en classe 
l''équivalent de : 
1. 2 périodes de travail collaboratif par semaine si leurs prestations sont 
comprises entre 11 et 22 périodes au sein du même pouvoir organisateur; 
2. 1 période de travail collaboratif par semaine si leurs prestations sont 
comprises entre 7 et 10 périodes au sein du même pouvoir organisateur. 
 
En deçà de 7 périodes par semaine au sein du même pouvoir organisateur, 
leurs obligations se limitent à la transmission et à la prise de connaissance des 
informations utiles à la bonne organisation des activités pédagogiques. 
 
Lorsqu''un membre du personnel n''est pas tenu de prester l''équivalent de 
deux périodes de travail collaboratif, il ne peut être considéré comme exerçant 
une fonction à prestations complètes que si les périodes de travail collaboratif 
non prestées sont remplacées par du travail en classe. 
 
§ 5. Si les membres du personnel visés aux §§ 1 et 3 exercent une fonction 
à prestations incomplètes, leur volume de travail collaboratif est 
proportionnellement réduit. 
 
Modifié par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 18, 'Article 15. - § 1er. - Dans l''enseignement secondaire ordinaire, les', 'Article 15. - § 1er. - Dans l''enseignement secondaire ordinaire, les 
membres du personnel enseignant exerçant une fonction à prestations 
complètes sont tenus d''accomplir 60 périodes par année scolaire de travail 
collaboratif, en dehors des périodes visées à l''article 3, des missions visées à 
l''article 8 et des jours obligatoires de formation professionnelle continue 
prévus par le Livre 6, Titre Ier, du Code de l''enseignement fondamental et de 
l''enseignement secondaire. 
 
S''ils exercent une fonction à prestations incomplètes, leur volume de 
travail collaboratif est proportionnellement réduit. 
 
§ 2. - Dans l''enseignement secondaire spécialisé, les membres du 
personnel enseignant sont tenus d''accomplir en supplément de leur travail en 
classe l''équivalent de : 
1. 2 périodes de travail collaboratif par semaine si leurs prestations sont 
comprises entre 11 et 22 périodes au sein du même pouvoir organisateur; 
2. 1 période de travail collaboratif par semaine si leurs prestations sont 
comprises entre 7 et 10 périodes au sein du même pouvoir organisateur. 
 
En deçà de 7 périodes par semaine au sein du même pouvoir organisateur, 
leurs obligations se limitent à la transmission et à la prise de connaissance des 
informations utiles à la bonne organisation des activités pédagogiques. 
 
Lorsqu''un membre du personnel n''est pas tenu de prester de travail 
collaboratif, les périodes non prestées sont remplacées par du travail en classe. 
 
 
 
Docu 46287 
 
D. 14-03-2019  
Lorsqu''un membre du personnel n''est pas tenu de prester l''équivalent de 
deux périodes de travail collaboratif, il ne peut être considéré comme exerçant 
une fonction à prestations complètes que si les périodes de travail collaboratif 
non prestées sont remplacées par du travail en classe.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 19, 'Article 16. - L''organisation du travail collaboratif, notamment sa', 'Article 16. - L''organisation du travail collaboratif, notamment sa 
répartition sur l''année, est concertée au sein de l''organe local de concertation 
sociale. 
 
TITRE III. - Dispositions relatives aux éducateurs');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 20, 'Article 17. - Les éducateurs exerçant une fonction à prestations', 'Article 17. - Les éducateurs exerçant une fonction à prestations 
complètes sont tenus d''accomplir : 
1. dans l''enseignement maternel ordinaire, 60 périodes de travail 
collaboratif par année scolaire; 
2. dans l''enseignement primaire ordinaire, au moins 60 périodes de 
travail collaboratif par année scolaire; 
3. dans l''enseignement secondaire ordinaire, 60 périodes de travail 
collaboratif par année scolaire; 
4. dans les internats, homes d''accueil ou homes d''accueil permanents 
organisés par la Communauté française, 60 périodes de travail collaboratif par 
année scolaire 
 
S''ils exercent une fonction à prestations incomplètes, leur volume de 
travail collaboratif est proportionnellement réduit. 
 
Les périodes consacrées au travail collaboratif sont comprises dans le 
volume de prestations des éducateurs. 
 
TITRE IV. - Dispositions relatives aux accompagnateurs CEFA.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 21, 'Article 18. - Les accompagnateurs exerçant une fonction à prestations', 'Article 18. - Les accompagnateurs exerçant une fonction à prestations 
complètes sont tenus d''accomplir 60 périodes de travail collaboratif par année 
scolaire. 
 
S''ils exercent une fonction à prestations incomplètes, leur volume de 
travail collaboratif est proportionnellement réduit. 
 
Inséré par D. 17-06-2021 
TITRE IV/1 - Dispositions relatives aux membres du personnel 
accompagnant des pôles territoriaux 
 
Inséré par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 22, 'Article 18', 'Article 18/1. - L''horaire de travail hebdomadaire des membres du 
personnel de l''enseignement spécialisé affectés aux pôles territoriaux, dans le 
cadre d''une fonction à prestations complètes, comporte 36 périodes. Cet horaire 
de travail, qui comprend également le service à l''école et aux élèves et le travail 
en et pour la classe, recouvre :  
1° des missions relatives à l''accompagnement des écoles coopérantes du 
pôle territorial dans lequel ils sont affectés :  
 a) informer les équipes éducatives sur les aménagements raisonnables 
et l''intégration permanente totale ; 
 b) assurer le lien entre les différents partenaires qui jouent un rôle de 
soutien aux élèves, notamment afin de faciliter l''échange d''expériences ; 
 
 
Docu 46287 
 
D. 14-03-2019  
 c) accompagner et soutenir les membres de l''équipe éducative des écoles 
coopérantes dans l''organisation des aménagements raisonnables, notamment 
par le conseil ou la mise à disposition d''outils ; 
 d) accompagner les écoles coopérantes dans l''élaboration de protocoles 
d''aménagements raisonnables lorsqu''une prise en charge individuelle de 
l''élève concerné par le pôle territorial s''avère nécessaire ; 
2° des missions relatives à l''accompagnement des élèves inscrits dans les 
écoles coopérantes du pôle territorial dans lequel ils sont affectés : 
 a) accompagner individuellement les élèves présentant des besoins 
spécifiques dans le cadre de la mise en oeuvre des aménagements raisonnables 
si cela s''avère nécessaire au regard de leurs besoins et de leurs protocoles 
d''aménagements raisonnables ; 
 b) accompagner individuellement les élèves présentant des besoins 
spécifiques sensori-moteurs nécessitant un suivi important dans le cadre de la 
mise en oeuvre des aménagements raisonnables si cela s''avère nécessaire au 
regard de l''échelle des besoins visée à l''article 6.2.5-4 du Code de 
l''enseignement fondamental et de l''enseignement secondaire ;  
 c) collaborer, pour les élèves pris en charge par le pôle territorial, à 
l''évaluation des protocoles d''aménagements raisonnables et, le cas échéant, à 
l''orientation vers l''enseignement spécialisé en cas d''insuffisance des 
aménagements raisonnables pour assurer un apprentissage adapté aux 
besoins spécifiques de l''élève ; 
 d) accompagner les élèves à besoins spécifiques dans le cadre du 
dispositif d''intégration permanente totale pour les élèves issus de 
l''enseignement spécialisé ; 
3° le travail collaboratif : 
 a) avec les autres membres du personnel et le cas échéant le 
coordonnateur affectés dans le pôle territorial ; 
 b) avec les membres du personnel des écoles coopérantes dans le cadre 
des composantes de l''horaire de travail précisées en 1° et 2° ; 
 c) avec les autres partenaires du pôle territorial concernés par les 
besoins spécifiques des élèves, notamment les Centres PMS ; 
4° le processus de formation en cours de carrière visé par le décret du 11 
juillet 2002 relatif à la formation en cours de carrière des membres du 
personnel des établissements d''enseignement fondamental ordinaire et le 
décret du 11 juillet 2002 relatif à la formation en cours de carrière dans 
l''enseignement spécialisé, l''enseignement secondaire ordinaire et les centres 
psycho-médico-sociaux et à la création d''un institut de la formation en cours 
de carrière. 
 
TITRE V. - Dispositions relatives aux fonctions du personnel 
paramédical, social et psychologique');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 23, 'Article 19. - Les membres du personnel exerçant une fonction du', 'Article 19. - Les membres du personnel exerçant une fonction du 
personnel paramédical, social et psychologique à prestations complètes sont 
tenus d''accomplir : 
1. dans l''enseignement primaire ordinaire ou spécialisé, au moins 60 
périodes de travail collaboratif par année scolaire; 
2. dans les autres niveaux et formes d''enseignement, 60 périodes de 
travail collaboratif par année scolaire. 
 
S''ils exercent une fonction à prestations incomplètes, leur volume de 
travail collaboratif est proportionnellement réduit. 
 
 
 
Docu 46287 
 
D. 14-03-2019  
TITRE VI. - Dispositions relatives aux fonctions de sélection et de 
promotion');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 24, 'Article 20. - § 1er. Les membres du personnel exerçant une fonction de', 'Article 20. - § 1er. Les membres du personnel exerçant une fonction de 
sélection et de promotion à prestations complètes, à l''exception des directeurs, 
sont tenus d''accomplir : 
1. dans l''enseignement primaire ordinaire ou spécialisé, au moins 60 
périodes de travail collaboratif par année scolaire; 
2. dans les autres niveaux et formes d''enseignement, 60 périodes de 
travail collaboratif par année scolaire. 
 
S''ils exercent une fonction à prestations incomplètes, leur volume de 
travail collaboratif est proportionnellement réduit. 
 
§ 2. Les membres du personnel visés par le présent titre, à l''exception des 
directeurs, sont indemnisés pour l''utilisation à des fins professionnelles de leur 
outil informatique privé et de leur connexion internet privée, au titre de 
remboursement de frais propres à l''employeur. 
 
Cette indemnisation correspond à un montant forfaitaire annuel de 100 
euros, liquidé avant le 31 décembre de chaque année civile au cours de laquelle 
le membre du personnel peut se prévaloir d''une ou plusieurs périodes de 
prestations constituant au total au moins 90 jours de prestations 
d''enseignement effectives au cours de l''année civile, à la date du 30 novembre 
incluse. Ce montant est liquidé directement aux membres du personnel par les 
Services du Gouvernement [et ne peut être obtenu qu''une seule fois par année 
civile quels que soient le type ou le niveau d''enseignement.]7 
 
TITRE VII. - Dispositions relatives à l''octroi de moyens 
supplémentaires dans le cadre de la future carrière en trois étapes 
 
[Modifié par D. 22-06-2023]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 25, 'Article 21. - § 1er. Dans l''enseignement fondamental et secondaire,', 'Article 21. - § 1er. Dans l''enseignement fondamental et secondaire, 
ordinaire et spécialisé, des moyens supplémentaires pour l''exercice des 
missions du service à l''école et aux élèves visé aux articles 9, § 1er, 10 et 11 
sont octroyés au bénéfice des enseignants expérimentés : 
a. à partir du 1er septembre 2019, 0,33 % du capital-périodes, du cadre 
d''emploi ou du NTPP global; 
b. à partir du 1er septembre 2020, 0,66 % du capital-périodes, du cadre 
d''emploi ou du NTPP global; 
c. à partir du 1er septembre 2021, 1,00 % du capital-périodes, du cadre 
d''emploi ou du NTPP global. 
 
§ 2. La notion de cadre d''emploi visé au § 1er est constituée, pour 
l''enseignement fondamental ordinaire, du complément de direction, des 
périodes d''instituteurs maternels, des périodes de psychomotricité, des 
périodes d''instituteurs primaires, des périodes d''éducation physique, des 
périodes d''accompagnement personnalisé [inséré par D. 22-06-2023] et des 
périodes de langues modernes. Il ne comprend pas les périodes de cours 
philosophiques, les périodes d''encadrement différencié et l''encadrement 
complémentaire destiné au dispositif DASPA ou d''accompagnement FLA. 
 
 
7Inséré par le D. 20-11-2025 
 
 
Docu 46287 
 
D. 14-03-2019  
Les augmentations de cadre dans l''enseignement maternel, prévues aux 
articles 43, 44, 44bis, 44ter du décret du 13 juillet 1998 portant organisation 
de l''enseignement maternel et primaire ordinaire et modifiant la 
réglementation de l''enseignement, ne sont pas prises en considération pour 
établir le cadre d''emploi visé au § 1er.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 26, 'Article 22. - L''enseignant', 'Article 22. - L''enseignant 
expérimenté 
répond 
aux 
conditions 
suivantes : 
1. il n''a pas fait l''objet d''une évaluation défavorable dans les 10 dernières 
années; 
2. il dispose d''une ancienneté de 15 ans dans l''enseignement organisé ou 
subventionné par la Communauté française. 
 
TITRE VIII. - Dispositions modificatives 
 
CHAPITRE 1er. - Dispositions statutaires');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 27, 'Article 23. - A l''article 4 de l''arrêté royal du 15 avril 1958 portant statut', 'Article 23. - A l''article 4 de l''arrêté royal du 15 avril 1958 portant statut 
