INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 28, 'Article 24. - A l''article 18, alinéa 1er, du même arrêté est ajouté un point', 'Article 24. - A l''article 18, alinéa 1er, du même arrêté est ajouté un point 
