INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 29, 'Article 25. - Dans le même arrêté est ajouté un titre IIIquater rédigé / Article 44octies. - Le traitement relatif aux périodes additionnelles', 'Article 25. - Dans le même arrêté est ajouté un titre IIIquater rédigé 
comme suit : 
 
«TITRE IIIquater. - DES PERIODES ADDITIONNELLES.

Article 44octies. - Le traitement relatif aux périodes additionnelles 
