INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 30, 'Article 26. - L''article 3 de l''arrêté royal du 15 mai 1958 fixant les', 'Article 26. - L''article 3 de l''arrêté royal du 15 mai 1958 fixant les 
