INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 31, 'Article 27. - L''article 2 de l''arrêté royal du 31 mars 1984 relatif aux', 'Article 27. - L''article 2 de l''arrêté royal du 31 mars 1984 relatif aux 
