INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 35, 'Article 31. - A l''article 33, § 3, du même décret, un nouvel alinéa est', 'Article 31. - A l''article 33, § 3, du même décret, un nouvel alinéa est 
