INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 36, 'Article 32. - Un paragraphe 5, rédigé comme suit, est ajouté à l''article 7', 'Article 32. - Un paragraphe 5, rédigé comme suit, est ajouté à l''article 7 
