INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 37, 'Article 33. - Un paragraphe 6, rédigé comme suit, est ajouté à l''article 8', 'Article 33. - Un paragraphe 6, rédigé comme suit, est ajouté à l''article 8 
