INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('46287', 52, 'Article 49. - A l''article 149 du décret du 13 septembre 2018 portant', 'Article 49. - A l''article 149 du décret du 13 septembre 2018 portant 
