INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 7, 'Article 5. - A partir du 1er septembre 2028, dans la loi du 19 juillet 1971', 'Article 5. - A partir du 1er septembre 2028, dans la loi du 19 juillet 1971 
relative à la structure générale et à l''organisation de l''enseignement 
secondaire, les termes «au deuxième degré» des articles 4bis, § 3, 4ter, § 2, 
 
2Remplacé par le D. 16-07-2025  
3Remplacé par le D. 16-05-2024 
4Inséré par le D. 16-07-2025  
 
 
Docu 47165 
 
D. 03-05-2019  
4quater, § 1er, 4quinques, § 1er, sont systématiquement remplacés par les 
termes «en quatrième année».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 8, 'Article 6. - L''article 58 de la loi du 21 juin 1985 concernant', 'Article 6. - L''article 58 de la loi du 21 juin 1985 concernant 
l''enseignement est remplacé par ce qui suit: 
«Article 58.- Le présent chapitre s''applique à l''enseignement supérieur 
non universitaire, organisé ou subventionné par la Communauté française.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 9, 'Article 7. - Dans le décret du 24 juillet 1997 définissant les missions', 'Article 7. - Dans le décret du 24 juillet 1997 définissant les missions 
prioritaires de l''enseignement fondamental et de l''enseignement secondaire et 
organisant les structures propres à les atteindre, à l''article 50, § 4, les 
modifications suivantes sont apportées: 
1° à l''alinéa 2, les mots «Par dérogation à l''alinéa précédent» sont 
remplacés par les mots «Par dérogation à l''article 1.3.1-1, 49°, du Code de 
l''enseignement fondamental et de l''enseignement secondaire»; 
2° à l''alinéa 3: 
 a) les mots «Par dérogation à l''alinéa 1er» sont remplacés par les mots 
«Par dérogation à l''article 1.3.1-1, 47°, du Code de l''enseignement fondamental 
et de l''enseignement secondaire»; 
 b) les mots «aux articles 40 et 47, § 2» sont remplacés par les mots «à 
l''article 40 du présent décret et à l''article 1.4.3-2, § 4, alinéa 2, du Code de 
l''enseignement fondamental et de l''enseignement secondaire». 
 
Dans le même décret, dans le Chapitre X, il est inséré un article 94/1, 
rédigé comme suit: 
«Article 94/1. Les dispositions du présent chapitre ne s''appliquent pas au 
degré inférieur de l''enseignement secondaire visé à l''article 1.2.1-4 du Code 
l''enseignement fondamental et de l''enseignement secondaire».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 10, 'Article 8. - L''article 4 du décret du 21 février 2019 fixant l''organisation', 'Article 8. - L''article 4 du décret du 21 février 2019 fixant l''organisation 
de l''enseignement supérieur en Hautes Ecoles est complété par un alinéa 
rédigé comme suit: 
 
«Les Hautes écoles tenues au respect du principe de neutralité ou celles 
qui décident d''y adhérer inscrivent une référence explicite au Livre 1er, Titre 
7, Chapitre 4 du Code de l''enseignement fondamental et de l''enseignement 
secondaire dans leur projet pédagogique, social et culturel.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 11, 'Article 9. - Les termes «et au certificat d''études de base au terme de', 'Article 9. - Les termes «et au certificat d''études de base au terme de 
l''enseignement primaire» sont supprimés de l''intitulé du décret du 2 juin 2006 
relatif à l''évaluation externe des acquis des élèves de l''enseignement 
obligatoire et au certificat d''études de base au terme de l''enseignement 
primaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 12, 'Article 10. - A la suite de l''article 9, dans le Chapitre II du décret du 7', 'Article 10. - A la suite de l''article 9, dans le Chapitre II du décret du 7 
novembre 2013 définissant le paysage de l''enseignement supérieur et 
l''organisation académique des études, il est inséré un article 9/1, rédigé comme 
suit: 
«Article 9/1. - Les établissements tenus au respect du principe de 
neutralité ou ceux qui décident d''y adhérer sont soumis au respect des 
dispositions visées au Livre 1er, Titre 7, Chapitre 4, du Code de l''enseignement 
fondamental et de l''enseignement secondaire.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 13, 'Article 11. - A l''article 11 du décret du 7 février 2019 définissant la', 'Article 11. - A l''article 11 du décret du 7 février 2019 définissant la 
formation initiale des enseignants, l''alinéa suivant est ajouté: 
 
 
 
Docu 47165 
 
D. 03-05-2019  
«Lorsque de nouveaux référentiels sont adoptés ou que des modifications 
substantielles sont apportées à des référentiels existants, le Gouvernement 
examine, après avis de la COCOFIE, l''opportunité de modifier les disciplines 
ou familles de disciplines apparentées.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 14, 'Article 12. - Dans le décret du 16 avril 1991 organisant l''enseignement', 'Article 12. - Dans le décret du 16 avril 1991 organisant l''enseignement 
de promotion sociale, à l''article 1er, il est inséré un paragraphe 4 et un 
paragraphe 5 formulés comme suit: 
 
«§ 4. Par l''intermédiaire des fédérations de pouvoirs organisateurs 
auxquelles ils sont affiliés, les pouvoirs organisateurs visés au paragraphe 2 
participent à la négociation visée au Livre 1er, Titre 6, Chapitre 5, du Code de 
l''enseignement fondamental et de l''enseignement secondaire. 
 
§ 5. Les pouvoirs organisateurs visés au paragraphe 2 relevant de 
l''enseignement officiel sont soumis au principe de neutralité tel que défini au 
Livre 1er, Titre 7, Chapitre 4, du Code de l''enseignement fondamental et de 
l''enseignement secondaire. L''enseignement libre non confessionnel peut 
adhérer au principe de neutralité selon les modalités établies dans ces 
dispositions.».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 15, 'Article 13. - Dans le décret du 2 juin 1998 organisant l''enseignement', 'Article 13. - Dans le décret du 2 juin 1998 organisant l''enseignement 
secondaire artistique à horaire réduit subventionné par la Communauté 
française, l''article 2 est complété d''un alinéa rédigé comme suit: 
 
«Par l''intermédiaire des fédérations de pouvoirs organisateurs auxquelles 
ils sont affiliés, les pouvoirs organisateurs de l''enseignement artistique à 
horaire réduit participent à la négociation visée au Livre 1er, Titre 6, Chapitre 
5, du Code de l''enseignement fondamental et de l''enseignement secondaire.». 
 
Section II. - Dispositions transitoires');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 16, 'Article 14. - Durant les années scolaires 2020-2021 et 2021-2022, pour', 'Article 14. - Durant les années scolaires 2020-2021 et 2021-2022, pour 
les écoles qui n''ont pas encore conclu de contrat d''objectifs conformément au 
Titre 5, Chapitre 2, Section 1re, du présent Code, l''article 13 du décret du 11 
mai 2007 relatif à l''enseignement en immersion linguistique reste applicable 
en sa formulation antérieure au décret du 13 septembre 2018 modifiant le 
décret du 24 juillet 1997 définissant les missions prioritaires de l''enseignement 
fondamental et de l''enseignement secondaire et organisant les structures 
propres à les atteindre afin de déployer un nouveau cadre de pilotage, 
contractualisant les relations entre la Communauté française et les 
établissements scolaires.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 17, 'Article 15. - Durant les années scolaires 2020-2021 et 2021-2022, pour', 'Article 15. - Durant les années scolaires 2020-2021 et 2021-2022, pour 
les écoles qui n''ont pas encore conclu de contrat d''objectifs conformément au 
Titre 5, Chapitre 2, Section 1re, du présent Code, l''article 67/1 du décret du 24 
juillet 1997 définissant les missions prioritaires de l''enseignement 
fondamental et de l''enseignement secondaire et organisant les structures 
propres à les atteindre reste applicable en sa formulation antérieure au décret 
du 13 septembre 2018 modifiant le décret du 24 juillet 1997 définissant les 
missions prioritaires de l''enseignement fondamental et de l''enseignement 
secondaire et organisant les structures propres à les atteindre afin de déployer 
un nouveau cadre de pilotage, contractualisant les relations entre la 
Communauté française et les établissements scolaires. 
 
 
 
Docu 47165 
 
D. 03-05-2019  
[Article 15/1. - Par dérogation aux articles 1.5.2-1, alinéa 1er, et 1.5.2-9, 
§1er, alinéa 1er, du Code de l''enseignement fondamental et de l''enseignement 
secondaire, la durée des contrats d''objectifs des écoles qui l''ont conclu entre le 
1er août 2019 et le 31 décembre 2023 est de sept années et leur évaluation 
intervient au cours de leur septième année d''exécution. 
 
Par dérogation à l''alinéa 1er, s''il l''estime nécessaire, le pouvoir 
organisateur d''une école, en concertation avec le directeur, peut demander au 
directeur de zone, au plus tard avant la fin de la cinquième année d''exécution 
du contrat, d''organiser l''évaluation au cours de la sixième année d''exécution 
conformément à l''article 1.5.2-9, §1er, alinéa 1er, du Code de l''enseignement 
fondamental et de l''enseignement secondaire. Dans ce cas, la durée du contrat 
d''objectifs de l''école concernée reste d''une durée de six années.]5');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 18, 'Article 16. - Le rapport annuel visé à l''article 1.5.2-2, alinéa 5, du Code / Article 17. - L''article 1.7.2-2, § 2, est applicable à la troisième année de', 'Article 16. - Le rapport annuel visé à l''article 1.5.2-2, alinéa 5, du Code 
est remis pour la première fois au Parlement durant l''année 2021.

Article 17. - L''article 1.7.2-2, § 2, est applicable à la troisième année de 
l''enseignement maternel ordinaire durant l''année scolaire 2020-2021.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 19, 'Article 18. - L''article 1.7.2-2, § 1er, n''est pas applicable aux élèves de la', 'Article 18. - L''article 1.7.2-2, § 1er, n''est pas applicable aux élèves de la 
troisième année de l''enseignement maternel ordinaire durant l''année scolaire 
2020-2021. 
 
Par dérogation à l''article 1.7.2-2, § 1er, alinéa 2, 2° et 3°, dans 
l''enseignement maternel, ordinaire et spécialisé, si un pouvoir organisateur 
démontre s''être contractuellement engagé avant le 14 mars 2019 dans le cadre 
de l''organisation d''une activité culturelle ou sportive, ou d''un séjour 
pédagogique prévu lors des années scolaires 2020-2021 ou 2021-2022, il n''est 
pas tenu d''observer les montants maximaux fixés par le Gouvernement pour 
l''organisation de cette activité ou ce séjour. 
 
Les Services du Gouvernement sont habilités à contrôler le respect de la 
condition prévue à l''alinéa précédent. 
 
Inséré par D. 18-12-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 20, 'Article 18', 'Article 18/1. - Les propositions relatives aux référentiels de compétences 
initiales et aux référentiels du Tronc commun transmises par les groupes de 
travail à la Commission des référentiels avant le 31 décembre 2019, en 
application des articles 60sexies et 60septies du décret du 24 juillet 1997 
définissant les missions prioritaires de l''enseignement fondamental et de 
l''enseignement secondaire et organisant les structures propres à les atteindre, 
sont réputées avoir été établies conformément aux articles 1.4.4-1 et 1.4.4-2 et 
constituent des projets de référentiels au sens de l''article 1.6.2-1, § 2, alinéa 3. 
 
Inséré par D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 21, 'Article 18', 'Article 18/2. - Sans préjudice de l''organisation en tronc commun visée à 
l''article 20, les articles 2.3.1-3, 2.3.1-4 et 2.3.1-6 du Code de l''enseignement 
fondamental et de l''enseignement secondaire ne s''appliquent pas durant 
l''année scolaire 2022-2023. 
 
Par dérogation à l''article 4, 3° et 4°, e., l''article 1er, paragraphe 1er, alinéa 
2 et paragraphe 4bis, 2° et 3° de la loi du 29 juin 1983 concernant l''obligation 
 
5Inséré par le D. 16-07-2025 
 
 
Docu 47165 
 
D. 03-05-2019  
scolaire et l''article 15, alinéa 2, 1°, du décret du 24 juillet 1997 définissant les 
missions prioritaires de l''enseignement fondamental et de l''enseignement 
secondaire et organisant les structures propres à les atteindre restent en 
vigueur durant l''année scolaire 2022-2023. 
 
[Inséré par D. 22-06-2023]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 22, 'Article 18', 'Article 18/3. - Par dérogation à l''article 2.2.1-2, alinéa 4, du Code de 
l''enseignement fondamental et de l''enseignement secondaire, durant les 
années scolaires 2023-2024 et 2024-2025, dans les communes dotées d''un 
régime spécial visées à l''article 1.8.1-1, 1°, et dans les communes de la région 
bilingue de Bruxelles-Capitale, l''horaire hebdomadaire des élèves peut être 
maintenu à 28 périodes. 
 
[Article 18/4. - Durant les années scolaires 2025-2026 et 2026-2027, le 
Certificat d''études de base visé à l''article 2.3.2-2 du Code de l''enseignement 
fondamental et de l''enseignement secondaire est délivré et l''épreuve externe 
commune certificative octroyant le Certificat d''études de base visée à l''article 
2.3.2-3 du même Code est organisée conformément aux articles 19 à 34 du 
décret du 02 juin 2006 relatif à l''évaluation externe des acquis des élèves de 
l''enseignement obligatoire.]6 
 
[Article 18/5. - L''évaluation externe diagnostique visée à l''article 1.6.3-2 
du Code de l''Enseignement fondamental et de l''enseignement secondaire est 
organisée, conformément à la Section 2 du Chapitre 3 du Titre 6 du Livre 1er 
du Code précité et est conçue par le groupe de travail visé à l''article 1.6.3-6 du 
même Code à partir de l''année scolaire 2025-2026 en vue de sa passation pour 
la première fois entre le 15 septembre et le 1er octobre 2026.]7 
 
Section III. - Entrée en vigueur 
 
Modifié par D. 18-12-2019; D. 17-07-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 23, 'Article 19. - Le présent décret entre en vigueur le 1er septembre 2020, à', 'Article 19. - Le présent décret entre en vigueur le 1er septembre 2020, à 
l''exception des articles 1.4.4-1 et 1.4.4-2 qui entrent en vigueur le 1er janvier 
2020, des articles 1.7.9-4 et 1.7.9-11 qui entrent en vigueur le 6 septembre 2020 
et des dispositions du Livre 1er, Titre 6, Chapitre 2 et Chapitre 4, qui entrent 
en vigueur le jour de la publication au Moniteur belge. 
 
Modifié par A.Gt 11-02-2021 ; D. 28-10-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('47165', 24, 'Article 20. - Les trois années de l''enseignement maternel sont', 'Article 20. - Les trois années de l''enseignement maternel sont 
organisées en tronc commun à partir de l''année scolaire 2020-2021. Les deux 
premières années de l''enseignement primaire sont organisées en tronc 
commun à partir de l''année scolaire 2022-2023 et la troisième et la quatrième 
années de l''enseignement primaire sont organisées en tronc commun à partir 
de l''année scolaire 2023-2024. Chaque année scolaire ultérieure, une année de 
l''enseignement primaire supplémentaire est organisée en tronc commun de 
sorte que la sixième année primaire est organisée selon ces modalités à partir 
de l''année scolaire 2025-2026 [à l''exception des articles 2.3.2-1 à 2.3.2-13 du 
Code de l''enseignement fondamental et de l''enseignement secondaire qui 
seront mis en application à partir de l''année scolaire 2027-2028]8. 
 
 
6Inséré par le D. 16-07-2025  
7Inséré par le D. 04-12-2025 
8Inséré par le D. 16-07-2025  
 
 
Docu 47165 
 
D. 03-05-2019  
Le degré inférieur de l''enseignement secondaire est organisé en tronc 
commun à partir de l''année scolaire 2026-2027 s''agissant de la première 
année, de l''année scolaire 2027-2028 s''agissant de la deuxième année, et de 
l''année scolaire 2028-2029 s''agissant de la troisième année. 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur 
belge. 
 
Bruxelles, le 3 mai 2019. 
 
 
 
 
 
Docu 47165 
 
D. 03-05-2019  
