INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 1, 'Article 1.', 'Article 1.1.1-1. - Le 
présent 
Code 
s''applique 
à 
l''enseignement 
fondamental et à l''enseignement secondaire, ordinaires et spécialisés, 
organisés ou subventionnés par la Communauté française. 
 
Le présent Code ne s''applique pas à l''[enseignement pour adultes] et à 
l''enseignement secondaire artistique à horaire réduit.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 2, 'Article 1.', 'Article 1.1.1-2. - Dans ce Code, l''emploi des noms masculins pour les 
titres et fonctions est épicène, en vue d''assurer la lisibilité du texte, nonobstant 
les dispositions du décret du 21 juin 1993 relatif à la féminisation des noms de 
métier, fonction, grade ou titre.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 3, 'Article 1.', 'Article 1.1.1-3. - Le Gouvernement peut adapter la rédaction de 
dispositions non reprises dans le présent Code en vue d''assurer la cohérence 
avec les définitions visées à l''article 1.3.1-1. Il peut remplacer les références 
aux législations auxquels le Code se substitue par des références aux 
dispositions correspondantes du Code. Il peut également adapter la 
numérotation des dispositions du présent Code. 
 
TITRE II. - Structure générale de l''enseignement fondamental et de 
l''enseignement secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 4, 'Article 1. / Article 1.', 'Article 1.2.1-1. - L''enseignement fondamental comprend le niveau 
maternel et le niveau primaire. 
 
Complété par D. 09-07-2020 ; modifié par D. 31-03-2022(1)

Article 1.2.1-2. - L''enseignement maternel s''adresse aux élèves âgés d''au 
moins deux ans et six mois. Il précède l''enseignement primaire. 
 
 
Docu 49466 
 
Code 03-05-2019 
Par dérogation à l''alinéa 1er, les élèves qui atteignent deux ans et six mois 
au 30 septembre peuvent fréquenter l''enseignement maternel à partir du 
premier jour de l''année scolaire concernée. 
 
L''élève fréquentera régulièrement la troisième année de l''enseignement 
maternel à partir du premier jour de l''année scolaire de l''année civile au cours 
de laquelle il a atteint l''âge de cinq ans. [Inséré par D. 09-07-2020] 
 
Modifié par D. 09-07-2020 ; D. 31-03-2022(1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 5, 'Article 1.', 'Article 1.2.1-3. - L''enseignement primaire est organisé en six années. Il 
s''adresse aux enfants à partir du premier jour de l''année scolaire de l''année 
civile au cours de laquelle ils atteignent l''âge de six ans. Il précède 
l''enseignement secondaire. 
 
[Par dérogation à l''alinéa 1er, un élève peut, après avis du directeur et 
du centre PMS et décision des parents, fréquenter la première année de 
l''enseignement primaire, à partir du premier jour de l''année scolaire de l''année 
civile au cours de laquelle il atteint l''âge de cinq ans. En outre, un élève âgé de 
six ans au premier jour de l''année scolaire concernée peut exceptionnellement 
fréquenter l''enseignement maternel selon les modalités de l''article 2.3.1-5.]1');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 6, 'Article 1.', 'Article 1.2.1-4. - L''enseignement secondaire ordinaire et spécialisé de 
forme 4 est organisé en six ou sept années. Les trois premières années forment 
le degré inférieur. Les années suivantes forment le degré supérieur. 
 
Par dérogation à l''alinéa 1er, un enseignement professionnel secondaire 
complémentaire comprenant au moins deux années peut être suivi après la 
sixième année de l''enseignement secondaire. 
 
L''enseignement secondaire spécialisé de forme 1 est organisé en une 
phase. 
 
L''enseignement secondaire spécialisé de forme 2 est organisé en deux 
phases. 
 
L''enseignement secondaire spécialisé de forme 3 est organisé en trois 
phases.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 7, 'Article 1.', 'Article 1.2.1-5. - L''enseignement maternel, l''enseignement primaire et 
le degré inférieur de l''enseignement secondaire sont organisés en un tronc 
commun polytechnique et pluridisciplinaire selon le continuum pédagogique 
dont les modalités sont déterminées par le Livre 2. 
 
Sur proposition conjointe du Conseil général de l''enseignement 
fondamental et du Conseil général de l''enseignement secondaire, le 
Gouvernement peut adapter le continuum pédagogique pour l''enseignement 
spécialisé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 8, 'Article 1.', 'Article 1.2.1-6. - Le degré supérieur de l''enseignement secondaire 
ordinaire et de l''enseignement spécialisé de forme 4 sont organisés en une 
section de transition et en une section de qualification. Ces deux sections 
assurent une formation humaine et citoyenne dans la perspective des missions 
prioritaires définies à l''article 1.4.1-1. 
 
1Remplacé par le D. 16-07-2025 
 
 
Docu 49466 
 
Code 03-05-2019 
La section humanités de transition vise essentiellement à la préparation 
à l''enseignement supérieur. Elle peut aussi permettre l''entrée dans la vie 
professionnelle. 
 
La section humanités de qualification vise essentiellement à préparer 
l''entrée dans la vie professionnelle. Elle peut aussi permettre l''accès aux 
études supérieures.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 9, 'Article 1. / Article 
1.', 'Article 1.2.1-7. - L''enseignement secondaire est organisé en plein 
exercice ou en alternance, selon les modalités visées par le présent Code.

Article 
1.2.1-8. - L''enseignement 
fondamental 
et 
l''enseignement 
secondaire sont organisés dans le cadre d''un enseignement ordinaire et d''un 
enseignement spécialisé destiné aux élèves à besoins spécifiques qui n''ont pu 
être inclus dans l''enseignement ordinaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 10, 'Article 1.', 'Article 1.2.1-9.  - § 1er. L''enseignement spécialisé se scinde en plusieurs 
types. 
 
Chacun de ces types correspond à l''enseignement adapté aux besoins 
éducatifs généraux et particuliers des élèves relevant de l''enseignement 
spécialisé appartenant à un même groupe, besoins qui sont déterminés en 
fonction du handicap principal commun à ce groupe. 
 
Pour les élèves atteints de handicaps multiples, le type d''enseignement 
spécialisé est déterminé, compte tenu des besoins éducatifs qui, eu égard à 
l''âge et aux capacités des intéressés, doivent être satisfaits par priorité. 
 
§ 2. Les types suivants d''enseignement spécialisé peuvent être organisés, 
subventionnés ou reconnus par la Communauté française: 
1° le type 1 répond aux besoins éducatifs et de formation des élèves 
présentant un retard mental léger; 
2° le type 2 répond aux besoins éducatifs et de formation des élèves 
présentant un retard mental modéré ou sévère; 
3° le type 3 répond aux besoins éducatifs et de formation des élèves 
présentant des troubles du comportement; 
4° le type 4 répond aux besoins éducatifs et de formation des élèves 
présentant des déficiences physiques; 
5° le type 5 répond aux besoins éducatifs et de formation des élèves 
malades et/ou convalescents; 
6° le type 6 répond aux besoins éducatifs et de formation des élèves 
présentant des déficiences visuelles; 
7° le type 7 répond aux besoins éducatifs et de formation des élèves 
présentant des déficiences auditives; 
8° le type 8 répond aux besoins éducatifs et de formation des élèves 
présentant des troubles des apprentissages. 
 
§ 3. Toute modification de la typologie est soumise à l''avis préalable du 
Conseil supérieur de l''enseignement spécialisé visé au Chapitre XIV du décret 
du 3 mars 2004 organisant l''enseignement spécialisé.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 11, 'Article 1.', 'Article 1.2.1-10. - Dans l''enseignement secondaire spécialisé, peuvent 
être organisées, suivant les types d''enseignement spécialisé et selon les 
possibilités des élèves, les formes d''enseignement suivantes: 
 
 
Docu 49466 
 
Code 03-05-2019 
1° l''enseignement secondaire spécialisé d''adaptation sociale, dénommé 
«enseignement secondaire spécialisé de forme 1»; 
2° 
l''enseignement 
secondaire 
spécialisé 
d''adaptation 
sociale 
et 
professionnelle, dénommé «enseignement secondaire spécialisé de forme 2»; 
3° 
l''enseignement 
secondaire 
professionnel 
spécialisé, 
dénommé 
«enseignement secondaire spécialisé de forme 3»; 
4° l''enseignement secondaire de transition ou de qualification, dénommé 
«enseignement secondaire spécialisé de forme 4». 
 
TITRE III. - Définitions 
 
Modifié par D. 17-06-2021; D. 24-02-2022; D. 31-03-2022; D. 31-03-
2022(1) ; D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 12, 'Article 1. (partie 1)', 'Article 1.3.1-1. - Dans le présent Code, il faut entendre par: 1° aménagements raisonnables: les mesures appropriées, prises en fonction des besoins spécifiques reconnus dans une situation concrète, afin de permettre à un élève présentant des besoins spécifiques d''accéder aux activités organisées dans le cadre de son parcours scolaire, ainsi que de participer et de progresser dans ce parcours, sauf si ces mesures imposent à l''égard de l''école qui doit les adopter une charge disproportionnée, conformément à l''article 3, 9° du décret du 12 décembre 2008 relatif à la lutte contre certaines formes de discrimination; 1°/1 année scolaire: cycle dans l''organisation des missions de l''enseignement fondamental et secondaire, tel que défini à l''article 1.9.1-1 du même Code ; [inséré par D. 31-03-2022(1)] 2° apprentissage par immersion: le processus pédagogique visant à assurer la maitrise des attendus en assurant tout ou partie des cours et des activités pédagogiques de la grille horaire dans une langue autre que le français en vue de l''acquisition progressive de cette autre langue; 3° association de parents: le groupement de parents d''élèves inscrits dans une école, destiné à les représenter; 4° attendu: le niveau de maitrise des contenus d''apprentissage visé pour les élèves au terme d''une année donnée ou d''un curriculum. La maitrise des attendus au terme d''un curriculum donne lieu à la délivrance d''un certificat; 5° besoins spécifiques: les besoins reconnus résultant d''une particularité, d''un trouble, d''une situation permanents ou semi-permanents d''ordre psychologique, mental, physique, psychoaffectif faisant obstacle au projet d''apprentissage et requérant, au sein de l''école, un soutien supplémentaire pour permettre à l''élève de poursuivre de manière régulière et harmonieuse son parcours scolaire dans l''enseignement ordinaire ou dans l''enseignement spécialisé; 6° Cellule de concertation locale: la cellule visée à l''article 4, § 3, du décret du 21 novembre 2013 organisant des politiques conjointes de l''Enseignement obligatoire et de l''Aide à la Jeunesse en faveur du bien-être des jeunes à l''école, de l''accrochage scolaire, de la prévention de la violence et de l''accompagnement des démarches d''orientation; 7° Cellule de soutien et d''accompagnement: la cellule visée à l''article 3 du décret du 28 mars 2019 relatif aux cellules de soutien et d''accompagnement de l''enseignement organisé ou subventionné par la Communauté française et au statut des conseillers au soutien et à l''accompagnement; 8° Centre PMS: le centre psycho-médico-social visé par la loi du 1er avril 1960 relative aux centres psycho-médico-sociaux; Ce 9° sera abrogé au 25 août 2025 (D. 20-07-2022 – N° 50485) 9° Certification par unités d''acquis d''apprentissage (CPU): le dispositif organisant la certification des savoirs, aptitudes et compétences professionnels en unités d''acquis d''apprentissage; Docu 49466 Code 03-05-2019 9° /1 Commission de pilotage (COPI) : la Commission de pilotage visée à l''article 1.6.1-1 ; [inséré par D. 17-06-2021] 10° compétence: l''aptitude à mettre en oeuvre un ensemble organisé de savoirs, de savoir-faire et de savoir-être permettant d''accomplir un certain nombre de tâches; 11° compétence disciplinaire: la compétence à acquérir spécifiquement dans une discipline scolaire; 12° compétence transversale: les attitudes, démarches mentales et démarches méthodologiques communes aux différentes disciplines à acquérir et à mettre en oeuvre au cours de l''élaboration des différents savoirs et savoir- faire; leur maitrise vise une autonomie croissante d''apprentissage des élèves; 13° confession: dans l''enseignement de caractère confessionnel, la religion à laquelle se réfère le projet éducatif et pédagogique du pouvoir organisateur; [modifié par D. 24-02-2022] [14° 14° Conseil de classe : dans l''enseignement secondaire ordinaire, l''ensemble des membres du personnel directeur et enseignant chargés de former un groupe déterminé d''élèves. Dans l''enseignement spécialisé, l''ensemble des membres du personnel directeur et enseignant, du personnel paramédical, psychologique et social et du personnel auxiliaire d''éducation qui a la charge de l''instruction et de l''éducation des élèves d''une classe déterminée et qui en porte la responsabilité ;]2 15° Conseil général de l''enseignement fondamental: le Conseil créé par le Chapitre V du décret du 14 mars 1995 relatif à la promotion de la réussite dans l''enseignement fondamental; 16° Conseil général de l''enseignement secondaire: le Conseil créé par le décret du 27 octobre 1994 organisant la concertation pour l''enseignement secondaire; 17° contenus d''apprentissage: l''ensemble de savoirs, savoir-faire et compétences identifiant les contenus à enseigner pour une année d''étude donnée; 18° continuum pédagogique: le parcours d''apprentissage dans lequel un ensemble d''attendus annuels assurent la progression des élèves en vue d''atteindre les attendus définis au terme du tronc commun et où les apprentissages de base s');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 13, 'Article 1. (partie 2)', 'travaillés dans l''ensemble des disciplines; 18°/1 contrat d''objectifs : le contrat visé à l''article 1.5.2-2 ; [inséré par D. 17-06-2021] 18°/2 : DAccE : le dossier d''accompagnement de l''élève visé au Titre 10, du présent Livre ; [Inséré par D. 31-03-2022] 19° délégué coordonnateur: le délégué coordonnateur visé à l''article 3 du décret du 13 septembre 2018 portant création du service général de pilotage des écoles et centres psycho-médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs; 20° délégué au contrat d''objectifs: le délégué des services du Gouvernement tel que désigné par l''article 3 du décret du 13 septembre 2018 portant création du service général de pilotage des écoles et centres psycho- médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs; 21° directeur: le membre du personnel exerçant l''une des fonctions de directeur définies par le décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement; 22° directeur de zone: le délégué des services du Gouvernement tel que désigné par l''article 3 du décret du 13 septembre 2018 portant création du service général de pilotage des écoles et centres psycho-médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs; 2Remplacé par le D. 16-05-2024 Docu 49466 Code 03-05-2019 22° /1 dispositif d''ajustement: le dispositif visé à l''article 1.5.2-16 ; [inséré par D. 24-02-2022] 23° école: l''établissement d''enseignement composé d''une ou de plusieurs implantations, placé sous la direction d''un directeur et organisé par un pouvoir organisateur; 24° école confessionnelle ou école de caractère confessionnel: l''école dont le projet éducatif et pédagogique du pouvoir organisateur est construit en référence à l''une des religions reconnues et dont l''enseignement est donné avec l''accord de l''autorité compétente du culte concerné; [complété par D. 24-02-2022] 25° école libre: l''école subventionnée par la Communauté française et organisée par une personne morale de droit privé; 26° école non confessionnelle ou école de caractère non confessionnel: l''école officielle ou l''école libre dont le pouvoir organisateur ne se réclame d''aucune confession; 27° école officielle: l''école organisée par les communes, les provinces, la Commission communautaire française, Wallonie-Bruxelles Enseignement ou toute autre personne morale de droit public; 28° école organisée: l''école organisée par la Communauté française en vertu de l''article 24, § 1er, alinéa 3, de la Constitution; 29° école subventionnée: l''école dont le pouvoir organisateur perçoit des subventions de la Communauté française; 30° élève régulièrement inscrit: l''élève qui, répondant aux conditions d''admission, est inscrit pour l''ensemble des cours d''une forme d''enseignement, d''une section et d''une orientation d''études déterminées; 31° enseignement à domicile: l''enseignement qui n''est pas dispensé dans une école visée à l''article 1.7.1-2, § 2; 32° équipe éducative: le personnel directeur et enseignant, [les puériculteurs,]3 le personnel paramédical, le personnel social, le personnel psychologique et le personnel auxiliaire d''éducation exerçant tout ou partie de leur fonction dans une même école ou dans une même implantation; 33° équipe pédagogique: le personnel directeur et le personnel enseignant exerçant tout ou partie de leur fonction dans une même école ou dans une même implantation; 33° /1 équipe pluridisciplinaire du Centre PMS : les directeurs et les autres membres du personnel technique du Centre PMS ; [inséré par D. 17-06-2021] 33°/2 équipe pluridisciplinaire du pôle territorial : le coordonnateur et les autres membres du personnel du pôle territorial [inséré par D. 17-06-2021] 33° /3 ETNIC : l''Entreprise publique des technologies Numériques de l''information et de la communication, organisée par le décret du 25 octobre 2018 relatif à l''Entreprise publique des Technologies Numériques de l''Information et de la Communication de la Communauté française (ETNIC) ; [Inséré par D. 31-03-2022] 34° évaluation certificative: l''évaluation qui intervient dans la délivrance d''un certificat d''enseignement; 35° évaluation externe: l''évaluation dont la conception et la mise en oeuvre sont confiées à des instances extérieures à l''équipe pédagogique d''une école; 36° évaluation formative: l''évaluation effectuée en cours d''apprentissage et visant à apprécier le progrès accompli par l''élève, à mesurer les acquis de l''élève et à comprendre la nature des difficultés qu''il rencontre lors d''un apprentissage; elle a pour but d''améliorer, de corriger ou de réajuster le cheminement de l''élève face aux apprentissages et aux attendus visés; elle peut se fonder en partie sur l''auto-évaluation; 3Inséré par le décret du 04-04-2024 Docu 49466 Code 03-05-2019 37° évaluation sommative: l''ensemble des épreuves permettant aux enseignants d''établir un bilan des acquis des élèves par rapport aux attendus au terme d''une');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 14, 'Article 1. (partie 3)', 'ou de plusieurs séquences d''apprentissage; 38° Fédération de pouvoirs organisateurs: l''organe qui assure la représentation et la coordination des pouvoirs organisateurs qui y sont affiliés; 39° frais scolaires: les frais afférents à des services et fournitures portant sur des activités organisées dans le cadre de l''enseignement dispensé par les écoles organisées ou subventionnées durant les périodes d''apprentissages prévues dans l''horaire des élèves. Sont aussi considérés comme frais scolaires les droits d''accès à la piscine, les droits d''accès aux activités culturelles et sportives et les frais liés aux séjours pédagogiques avec nuitée(s); 40° grille horaire: la liste des différents cours assurés hebdomadairement avec mention du nombre de périodes affectées à chacun; 41° implantation: le bâtiment ou l''ensemble de bâtiments où l''on dispense de l''enseignement; 41° /1 Institut de la Formation professionnelle continue : l''Institut interréseaux de la Formation professionnelle continue (IFPC) créé par l''article 25 du décret du 11 juillet 2002 relatif à l''Institut interréseaux de la Formation professionnelle continue (IFPC) [Inséré par D. 17-06-2021 – M.B. 30-07-2021] 41°/2 intégration permanente totale : le dispositif visé au chapitre X du décret du 3 mars 2004 organisant l''enseignement spécialisé ; [inséré par D. 17- 06-2021] 42° jours ouvrables scolaires: le lundi, le mardi, le mercredi, le jeudi, le vendredi, à l''exception des jours qui tombent un jour férié, pendant les vacances scolaires ou tout autre jour de congé scolaire fixé par le Gouvernement; [modifié par D. 24-02-2022] 43° Ministre: le ministre qui a l''Enseignement fondamental et l''Enseignement secondaire dans ses attributions; 44° organes locaux de concertation sociale: les instances de concertation locale instituées en vertu de la loi du 19 décembre 1974 organisant les relations entre les autorités publiques et les syndicats des agents relevant de ces autorités, de la loi du 20 septembre 1948 portant organisation de l''économie, de l''arrêté du Gouvernement de la Communauté française du 13 septembre 1995 relatif à la création, à la composition et aux attributions des commissions paritaires locales dans l''enseignement officiel subventionné, des arrêtés du Gouvernement de la Communauté française du 27 mars 1996 rendant obligatoire la décision du 24 janvier 1996 de la Commission paritaire de l''Enseignement fondamental libre confessionnel relative à la création d''une instance de concertation locale entre pouvoirs organisateurs et délégations syndicales et de l''arrêté du Gouvernement de la Communauté française du 18 juin 1999 rendant obligatoire la décision du 31 mai 1999 de la Commission paritaire de l''enseignement fondamental libre non confessionnel relative à la création d''une instance de concertation locale entre pouvoirs organisateurs et délégations syndicales; 44°/1 Parcours d''enseignement qualifiant (PEQ): le dispositif visé à l''article 4 du décret 20 juillet 2022 relatif au parcours d''enseignement qualifiant (PEQ); [inséré par D. 20-07-2022] 45° parent: toute personne investie de l''autorité parentale, selon les principes définis par l''ancien Code civil ou par le Code civil, ou qui assume la garde en droit ou en fait d''un enfant mineur soumis à l''obligation scolaire; [modifié par D. 31-03-2022] 45°/1 plan de pilotage : le plan visé à l''article 1.5.2-1 ; [inséré par D. 17-06- 2021] 45°/2 pôle territorial : le pôle territorial chargé de soutenir les écoles de l''enseignement ordinaire dans la mise en oeuvre des aménagements Docu 49466 Code 03-05-2019 raisonnables et de l''intégration permanente totale visé à l''article 6.2.2-1 ; [inséré par D. 17-06-2021] 46° Pouvoir organisateur: la personne morale de droit public ou la personne morale de droit privé qui assume la responsabilité de l''école; 47° profil de certification: le document de référence définissant le lien entre une option de base groupée ou une formation et un ou des profil(s) de formation élaboré(s) par le Service francophone des métiers et des qualifications et dument approuvé(s) par le Gouvernement; 48° profil de formation: le profil composé des unités d''acquis d''apprentissage associées aux activités clés du métier, d''un profil d''évaluation, d''un indice d''appréciation temporelle et d''un profil d''équipement; le profil de formation est élaboré par le Service francophone des métiers et des qualifications et est approuvé par le Gouvernement. Pour les options de base groupées pour lesquelles un profil de certification n''a pas encore été défini, le profil de formation correspond au document de référence élaboré par la Commission communautaire des Professions et des Qualifications (CCPQ) ; [complété par D. 20-07-2022] 49° programmes d''études: l''ensemble d''orientations méthodologiques, de dispositifs et de situations pédagogiques, intégrant les contenus d''apprentissage, c''est-à-dire les savoirs, savoir-faire, et compétences, et les attendus définis dans les référentiels visés au Titre 4, Chapitres');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 15, 'Article 1. (partie 4)', '2 et 3; [49° /1. Propagande politique : action exercée sur des élèves ou à destination des parents pour les amener à soutenir un mandataire ou un parti politique, ou pour les persuader d’adhérer à des idées politiques, à l’exception des activités menées dans un cadre garantissant l’expression d’un pluralisme d’opinions ;]4 [49°/2. Protocole de collaboration : le protocole visé à l’article 1.5.2-17, §2 ;]5 50° référentiel: le référentiel présentant de manière structurée les savoirs, savoir-faire et les compétences à acquérir dans une discipline ou plusieurs disciplines; 51° savoir: fait ou ensemble de faits, définition, concept, théorie, modèle ou outil linguistique; 52° savoir-être: l''attitude ou l''ensemble d''attitudes permettant de s''adapter à divers contextes sociaux; 53° savoir-faire: procédure, geste, technique, schéma de résolution, standardisés et automatisés par l''apprentissage et l''entrainement; 53° /1 scolarité : période durant laquelle l''élève soumis ou non à l''obligation scolaire, et inscrit et fréquente une école d''enseignement maternel, primaire, fondamental ou secondaire, ordinaire ou spécialisé, organisé ou subventionné par la Communauté française; [inséré par D. 31-03-2022] 54° Service de promotion de la santé à l''école: le service exerçant, dans les écoles subventionnées, les missions prévues par le décret du 14 mars 2019 relatif à la promotion de la santé à l''école et dans l''enseignement supérieur hors universités; 55° Service francophone des métiers et des qualifications: le service institué par l''accord de coopération du 29 octobre 2015 entre la Communauté française, la Région wallonne et la Commission communautaire française concernant le Service Francophone des Métiers et des Qualifications (en abrégé SFMQ), auquel assentiment a été donné par le décret du 10 décembre 2015; 56° Service général de l''inspection: le service visé à l''article 3 du décret du 10 janvier 2019 relatif au Service général de l''Inspection; 4Remplacé par le décret du 18 janvier 2024 5Inséré par le décret du 18 janvier 2024 Docu 49466 Code 03-05-2019 57° Services d''accrochage scolaire (SAS): les structures créées par le Titre I, Chapitre 3, du décret du 21 novembre 2013 organisant des politiques conjointes de l''Enseignement obligatoire et de l''Aide à la Jeunesse en faveur du bien-être des jeunes à l''école, de l''accrochage scolaire, de la prévention de la violence et de l''accompagnement des démarches d''orientation; 58° suivi statistique de l''élève: le suivi du parcours des élèves dans le système éducatif, quel que soit le niveau scolaire considéré, depuis l''entrée dans celui-ci jusqu''à sa sortie, en ce compris l''enseignement non obligatoire; 59° tâche: l''activité proposée à l''élève visant à initier, entrainer ou évaluer un apprentissage particulier ou un ensemble d''apprentissages intégrés; 60° travail personnel: l''activité dont la réalisation peut être demandée à l''élève par un membre de l''équipe pédagogique ou par un membre du personnel auxiliaire d''éducation; 61° travail à domicile: le travail personnel réalisé en dehors des heures de cours; 61°/1 type : l''un des types d''enseignement spécialisé définis à l''article 1.2.1-9. ; [Inséré par D. 17-06-2021] 62° Wallonie-Bruxelles Enseignement: l''organe public autonome auquel la Communauté française a délégué ses compétences de pouvoir organisateur en vertu du décret spécial du 7 février 2019 portant création de l''organisme public chargé de la fonction de Pouvoir organisateur de l''Enseignement organisé par la Communauté; 63° zones: les zones de concertation telles que définies par le Gouvernement sur la base de l''article 24, alinéa 1er, 3°, du décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice et de l''article 13 du décret du 14 mars 1995 relatif à la promotion d''une école de la réussite dans l''enseignement fondamental. TITRE IV. - Missions de l''enseignement fondamental et de l''enseignement secondaire CHAPITRE 1er. - Des missions prioritaires');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 16, 'Article 1.', 'Article 1.4.1-1. - La Communauté française, les pouvoirs organisateurs 
et les équipes éducatives remplissent simultanément et sans hiérarchie les 
missions prioritaires suivantes: 
1° promouvoir la confiance en soi et le développement de la personne de 
chacun des élèves; 
2° amener tous les élèves à s''approprier des savoirs et des savoir-faire et 
à acquérir des compétences, dont la maîtrise de la langue française, qui les 
rendent aptes à apprendre toute leur vie et à prendre une place active dans la 
vie économique, sociale et culturelle; 
3° préparer tous les élèves à être des citoyens responsables, capables de 
contribuer au développement d''une société démocratique, solidaire, pluraliste, 
respectueuse de l''environnement et ouverte aux autres cultures; 
4° assurer à tous les élèves des chances égales d''émancipation sociale. 
 
Modifié par D. 24-02-2022 ; D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 17, 'Article 1.', 'Article 1.4.1-2. - Les savoirs, les savoir-faire et les compétences sont 
placés dans la perspective de ces missions prioritaires. Ils assurent 
l''acquisition de connaissances constitutives d''une culture commune, de clés de 
compréhension et d''actions sur le monde, d''aptitudes et de savoir-être citoyens. 
 
 
 
Docu 49466 
 
Code 03-05-2019 
Les savoirs, les savoir-faire et les compétences s''acquièrent tant dans les 
cours que dans les autres activités éducatives et, de manière générale, dans 
l''organisation de la vie quotidienne de l''école. A cet effet, la Communauté 
française, les pouvoirs organisateurs et les équipes éducatives veillent à ce que 
l''école: 
1° mette l''élève dans des situations qui l''incitent à mobiliser dans une 
même démarche des savoirs, des savoir-faire et des compétences disciplinaires 
ou transversales; 
2° privilégie des activités de découverte, de production et de création; 
3° articule théorie et pratique, permettant notamment la construction de 
concepts à partir de la pratique; 
4° équilibre les temps de travail individuel et collectif et développe la 
capacité de consentir des efforts pour atteindre un but; 
5° fasse respecter par chaque élève l''obligation de participer à toutes les 
activités liées aux évaluations externes certificatives et non certificatives par 
l''école et d''accomplir les tâches qui en découlent; [modifié par D. 24-02-2022] 
6° accorde la place nécessaire aux activités physiques, au bien-être et à 
la santé, en mettant en place pour tous les élèves les conditions du 
développement de leurs capacités physiques, de leur bien-être, ainsi que les 
conditions de leur santé physique; 
7° intègre l''orientation au sein même du processus éducatif, notamment 
en favorisant l''éveil aux professions et aux métiers et en informant les élèves 
à propos des filières de formation; 
8° recoure aux technologies de la communication et de l''information et 
aux technologies et outils numériques, dans la mesure où ils sont des outils de 
développement, d''accès à l''autonomie et d''individualisation des parcours 
d''apprentissage; 
9° suscite le goût de la culture, la sensibilité et l''expression artistiques, 
stimule la créativité et favorise la participation à des activités culturelles et 
artistiques par une collaboration avec les acteurs concernés et en offrant à tous 
les élèves un parcours d''éducation culturelle et artistique conformément aux 
articles 1.4.5-1 et suivants; [complété par D. 13-10-2022] 
10° stimule l''engagement et l''esprit d''entreprendre en tant qu''aptitudes 
à associer les actes aux idées; [modifié par D. 13-10-2022] 
11° développe l''esprit critique; 
12° éduque au respect de la personnalité et des convictions de chacun, au 
devoir de proscrire la violence tant morale que physique, à la vie relationnelle, 
affective et sexuelle et mette en place des pratiques démocratiques de 
citoyenneté responsable au sein de l''école; 
13° participe à la vie de son quartier ou de son village et, partant, de sa 
commune, et s''y intègre de manière harmonieuse notamment en ouvrant ses 
portes au débat démocratique. 
 
Pour remplir ces missions, l''équipe éducative peut associer des 
intervenants externes. Lorsqu''elle existe, cette collaboration n''enlève pas à 
l''équipe éducative la responsabilité première dans la réalisation de ces 
missions.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 18, 'Article 1.', 'Article 1.4.1-3. - Les pouvoirs organisateurs adaptent la définition des 
programmes d''études et leur projet pédagogique: 
1° aux missions prioritaires de l''enseignement fondamental et de 
l''enseignement secondaire définies aux articles 1.4.1-1 et 1.4.1-2; 
2° à l''apprentissage, à la maitrise et à l''approfondissement de la langue 
française; 
3° à l''apprentissage des outils de la mathématique; 
 
 
Docu 49466 
 
Code 03-05-2019 
4° à l''intérêt de connaitre des langues autres que le français et, 
principalement, de communiquer dans ces langues; 
5° à l''importance des arts, de l''éducation aux médias et de l''expression 
corporelle; 
6° à la compréhension des sciences et des techniques et à leur 
interdépendance; 
7° à la transmission de l''héritage culturel dans tous ses aspects et à la 
découverte d''autres cultures, qui, ensemble, donnent des signes de 
reconnaissance et contribuent à tisser le lien social; 
8° à la sauvegarde de la mémoire des évènements qui aident à 
comprendre le passé et le présent, dans la perspective d''un attachement 
personnel et collectif aux idéaux qui fondent la démocratie; 
9° à la compréhension du milieu de vie, de l''histoire et, plus 
particulièrement, aux raisons et aux conséquences de l''unification européenne; 
10° à la compréhension du système politique belge; 
11° à l''éducation à la philosophie et à la citoyenneté telle que visée au 
Titre 7, Chapitre 6.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 19, 'Article 1.', 'Article 1.4.1-4. - Tout pouvoir organisateur veille à: 
1° proscrire toute mesure susceptible d''instaurer une hiérarchie entre 
écoles ou entre sections d''enseignement; 
2° considérer l''enseignement ordinaire et l''enseignement spécialisé, les 
différentes sections et les différents types comme différentes manières de 
remplir les missions prioritaires du présent Chapitre; 
3° assurer aux filles et aux garçons un accès et une participation égaux à 
toutes les formations.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 20, 'Article 1.', 'Article 1.4.1-5. - Les pouvoirs organisateurs veillent à ce que les écoles 
dont ils sont responsables prennent en compte les origines sociales et 
culturelles des élèves afin d''assurer à chacun des chances égales d''insertion 
sociale, professionnelle et culturelle. 
 
CHAPITRE II. - Des missions spécifiques au tronc commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 21, 'Article 1.', 'Article 1.4.2-1. -  § 1er. Dans l''enseignement maternel, les élèves sont 
amenés à développer les savoirs, savoir-faire et compétences présentés de 
manière structurée dans le référentiel de compétences initiales. Ce dernier 
vise à assurer la transition harmonieuse entre l''enseignement maternel et 
l''enseignement primaire sans donner lieu à une certification. 
 
§ 2. Le référentiel de compétences initiales accorde la priorité au 
développement psychomoteur, intellectuel, social, affectif et artistique de 
l''élève. 
 
Il définit les habilités et/ou apprentissages visés en matière: 
1° de développement de l''autonomie, de la créativité et de la pensée; 
2° de maitrise de la langue et de la culture scolaire; 
3° d''une approche de la lecture, du calcul et de différentes disciplines 
artistiques; 
4° des premiers outils d''expérimentation, de structuration, de 
catégorisation et d''exploration du monde. 
 
Il fixe le cadre des activités physiques et culturelles à développer. 
 
Sur proposition du Conseil général de l''enseignement fondamental, les 
priorités visées aux paragraphes 1er et 2 sont adaptées aux troubles 
 
 
Docu 49466 
 
Code 03-05-2019 
d''apprentissage et aux difficultés rencontrées par les élèves à besoins 
spécifiques qui fréquentent l''enseignement ordinaire ou l''enseignement 
spécialisé. 
 
§ 3. Le référentiel de compétences initiales s''inscrit dans le tronc commun 
défini à l''article 1.2.1-5. 
 
Il est adopté selon les modalités prescrites à l''article 1.4.4-1. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 22, 'Article 1.', 'Article 1.4.2-2.  - § 1er. De la première année de l''enseignement primaire 
au terme du degré inférieur de l''enseignement secondaire, les élèves sont 
amenés à développer les savoirs, savoir-faire et compétences présentés de 
manière structurée dans les référentiels du tronc commun, sous forme de 
contenus d''apprentissages et d''attendus. 
 
Sur proposition conjointe du Conseil général de l''enseignement 
fondamental et du Conseil général de l''enseignement secondaire, le référentiel 
est adapté aux troubles d''apprentissage et aux difficultés rencontrées par les 
élèves à besoins spécifiques qui fréquentent l''enseignement ordinaire ou 
l''enseignement spécialisé. 
 
§ 2. Les référentiels du tronc commun sont adoptés selon les modalités 
prescrites à l''article 1.4.4-1. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 23, 'Article 1.', 'Article 1.4.2-3. - Les cours et les activités du tronc commun s''inscrivent 
dans les huit domaines d''apprentissage suivants: 
1° le domaine «Français, Arts et Culture»; 
2° le domaine «Langues modernes»; 
3° le domaine «Mathématiques, Sciences et Techniques»; 
4° le domaine «Sciences humaines et éducation à la philosophie et à la 
citoyenneté, religion ou morale»; 
5° le domaine «Education physique, Bien-être et Santé»; 
6° le domaine «Créativité, Engagement et Esprit d''entreprendre»; 
7° le domaine «Apprendre à apprendre et Poser des choix» ; 
8° le domaine «Apprendre à s''orienter. [Inséré par D. 24-02-2022]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 24, 'Article 1.', 'Article 1.4.2-4. - De l''enseignement maternel au terme du degré 
inférieur de l''enseignement secondaire, le contrôle du niveau des études visé 
aux articles 1.5.1-1 et 1.7.3-1, § 2, comprend aussi la vérification: 
1° de l''adéquation entre les activités proposées aux élèves et les 
référentiels; 
2° du respect des référentiels; 
3° de l''équivalence du niveau des épreuves d''évaluation administrées aux 
élèves à celui des épreuves produites par la Commission des outils d''évaluation 
du tronc commun visée à l''article 1.4.4-4. 
 
CHAPITRE III. - Des missions spécifiques au degré supérieur de 
l''enseignement secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 25, 'Article 1.', 'Article 1.4.3-1. - § 1er. Dans le degré supérieur de l''enseignement 
secondaire de transition, l''élève est amené à développer: 
1° les compétences terminales et savoirs communs requis de l''ensemble 
des élèves; 
 
 
Docu 49466 
 
Code 03-05-2019 
2° les compétences terminales et savoirs requis dans les différentes 
disciplines de la section de transition; 
3° les compétences minimales en matière de communication dans une 
langue moderne autre que le français à l''issue de la section de transition. 
 
§ 2. Ces compétences et savoirs requis sont présentés de manière 
structurée dans des référentiels adoptés selon les modalités visées à l''article 
1.4.4-1. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 26, 'Article 1.', 'Article 1.4.3-2. - § 1er. Dans le degré supérieur de l''enseignement 
secondaire de qualification, l''enseignement consiste en des cours généraux et 
en une formation qualifiante. 
 
§ 2. Dans les cours généraux, l''élève est amené à développer: 
1° les compétences terminales et les savoirs communs requis de 
l''ensemble des élèves à l''issue de la section de qualification; 
2° les compétences minimales en mathématiques à l''issue de la section de 
qualification, 
lorsque 
l''apprentissage 
des 
mathématiques 
figure 
au 
programme d''études; 
3° les acquis d''apprentissage minimaux dans une langue moderne autre 
que le français à l''issue de la section de qualification. 
 
Dans l''enseignement secondaire spécialisé de forme 3, l''élève est amené 
à développer les compétences terminales et les savoirs communs requis de 
l''ensemble des élèves à l''issue de la troisième phase débouchant sur la 
délivrance d''un certificat d''enseignement secondaire inférieur équivalant au 
certificat d''enseignement secondaire du deuxième degré. 
 
Ces compétences et savoirs requis sont présentés de manière structurée 
dans des référentiels adoptés selon les modalités visées à l''article 1.4.4-1. 
 
§ 3. La formation qualifiante vise la maitrise des acquis d''apprentissage 
fixés par un profil de certification. 
 
§ 4. Après avoir sollicité l''avis du Conseil général de l''enseignement 
secondaire et après avoir obtenu l''avis de conformité visé à l''article 17, 10°, b, 
de l''accord de coopération du 29 octobre 2015 entre la Communauté française, 
la Région wallonne et la Commission communautaire française concernant le 
Service francophone des métiers et des qualifications, conformément à son 
article 30, le Gouvernement définit les profils de certification applicables: 
1° à l''enseignement secondaire ordinaire ou spécialisé de forme 4, de plein 
exercice ou en alternance; 
2° 
aux 
options 
de 
l’enseignement 
secondaire 
professionnel 
complémentaire; [modifié par D. 24-02-2022] 
3° aux formations de l''enseignement secondaire en alternance visé à 
l''article 2bis, § 1er, 2°, du décret du 3 juillet 1991 organisant l''enseignement en 
alternance; 
4° aux formations de l''enseignement secondaire spécialisé de forme 3. 
 
Le Gouvernement peut définir des profils de certification spécifiques à 
l''enseignement secondaire spécialisé de forme 4, dans le respect des conditions 
visées à l''alinéa 1er. 
 
Le Gouvernement peut conclure des conventions avec la Commission 
communautaire française ou avec la Région wallonne visant à la mise en 
 
 
Docu 49466 
 
Code 03-05-2019 
oeuvre de profils de formation communs aux différents opérateurs de 
formation professionnelle dans le respect des compétences de la Communauté 
française en matière de certification.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 27, 'Article 1.', 'Article 1.4.3-3. - Dans le degré supérieur de l''enseignement secondaire, 
le contrôle du niveau des études visé aux articles 1.5.1-1 et 1.7.3-1, § 2, 
comprend aussi la vérification: 
1° de l''adéquation entre les activités proposées aux élèves et les 
référentiels; 
2° du respect des référentiels; 
3° de l''équivalence du niveau des épreuves d''évaluation administrées aux 
élèves à celui des épreuves produites par les commissions des outils 
d''évaluation visées à l''article 1.4.4-4. 
 
CHAPITRE IV. - De l''élaboration des référentiels, des outils 
pédagogiques et des outils d''évaluation 
 
Modifié par D. 23-06-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 28, 'Article 1.', 'Article 1.4.4-1. - § 1er. Le Gouvernement détermine les référentiels. 
 
Les arrêtés sont soumis à la confirmation du Parlement dans les six mois 
suivant leur adoption. 
 
Il peut être dérogé aux référentiels conformément à la procédure de 
dérogation visée à l''article 1.4.4-6. 
 
§ 2. Des groupes de travail sont créés afin d''élaborer les référentiels. Le 
Gouvernement fixe la composition et les modalités de fonctionnement de ces 
groupes. 
 
Les services du Gouvernement désignent un de ses membres pour assurer 
le secrétariat. 
 
Les groupes de travail entendent, à titre d''expert, toute personne qu''ils 
jugent utile. 
 
Chaque fois qu''un des groupes de travail visés au présent article s''occupe 
d''adaptation à l''enseignement spécialisé, il doit entendre des experts ou des 
représentants de l''enseignement spécialisé. 
 
La composition des groupes de travail intègre, pour les profils de 
certification, à minima: 
1° un représentant du Ministre, qui préside et fixe le calendrier des 
réunions; 
2° des représentants des fédérations de pouvoirs organisateurs et de 
l''enseignement organisé par la Communauté française; 
3° un représentant du Service général de l''inspection; 
4° un représentant des services du Gouvernement; 
5° des représentants des cellules de soutien et d''accompagnement. 
 
§ 3. Pour baliser les activités des groupes de travail, le Gouvernement 
adopte une charte des référentiels qui détermine un ensemble de balises 
rédactionnelles et un canevas d''écriture. Le Gouvernement transmet un cahier 
des charges spécifique à chacun des groupes de travail. Ce document apporte 
notamment des précisions sur le cadre de la mission, le mode de 
 
 
Docu 49466 
 
Code 03-05-2019 
fonctionnement du groupe de travail, les visées de la discipline traitée et les 
livrables spécifiques attendus. 
 
§ 4. Un comité de lecture est attaché à chaque groupe de travail. 
 
Le comité de lecture dispose de toute latitude pour commenter les 
productions du groupe de travail, pour proposer l''intégration de contenus 
d''apprentissages, pour évaluer le réalisme, la cohérence, la précision et 
l''intelligibilité des contenus d''apprentissages proposés. En tant qu''instance 
d''avis, le comité de lecture n''a cependant pas le pouvoir d''exiger l''application 
effective de ses recommandations. 
 
Le fonctionnement et la composition des comités de lecture sont 
déterminés par le Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 29, 'Article 1.', 'Article 1.4.4-2. - La Commission des référentiels et des programmes du 
tronc commun visée à l''article 1.6.2-1 coordonne les travaux des groupes de 
travail élaborant le référentiel de compétences initiales et les différentes 
composantes du référentiel du tronc commun. Ces référentiels sont rédigés 
sous forme de contenus d''apprentissages identifiant les savoirs, savoir-faire et 
compétences devant faire l''objet d''un enseignement et les attendus qui y sont 
relatifs. Au besoin, la Commission des référentiels et des programmes du tronc 
commun donne des injonctions quant aux orientations des groupes de travail 
qui doivent s''y conformer.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 30, 'Article 1.', 'Article 1.4.4-3. - Les services pédagogiques des différents pouvoirs 
organisateurs et fédérations de pouvoirs organisateurs produisent des 
programmes et des outils pédagogiques qui permettent d''atteindre les 
attendus des référentiels visés aux Chapitres 2 et 3. Ces outils pédagogiques 
et ces programmes peuvent être utilisés et doivent être consultables par 
n''importe quelle école organisée ou subventionnée par la Communauté 
française. 
 
Le Gouvernement, après avoir pris l''avis du Conseil général de 
l''enseignement fondamental et du Conseil général de l''enseignement 
secondaire arrête les modalités de leur diffusion au bénéfice de l''ensemble des 
pouvoirs organisateurs. 
 
Des outils pédagogiques propres à l''enseignement spécialisé peuvent 
également être créés en complément aux outils communs à tous.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 31, 'Article 1.', 'Article 1.4.4-4. - Il est créé une Commission des outils d''évaluation du 
tronc commun, une Commission des outils d''évaluation de la section de 
transition du degré supérieur de l''enseignement secondaire et une Commission 
des outils d''évaluation de la section de qualification du degré supérieur de 
l''enseignement secondaire, selon les modalités que fixe le Gouvernement. 
 
Ces commissions produisent, sous la coordination de la Commission des 
évaluations visée à l''article 1.6.4-1, des batteries d''épreuves d''évaluation et des 
pistes didactiques relatives aux épreuves d''évaluation correspondant aux 
référentiels visés aux Chapitres 2 et 3. 
 
Le Gouvernement les diffuse, à titre indicatif, auprès de toutes les écoles 
organisées ou subventionnées par la Communauté française, selon les 
modalités qu''il définit. Ces batteries d''épreuves sont également communiquées 
 
 
Docu 49466 
 
Code 03-05-2019 
aux institutions chargées de la formation initiale ou continuée des 
enseignants. 
 
Ces batteries d''épreuves d''évaluation peuvent également être adaptées 
pour l''enseignement spécialisé, en fonction des besoins spécifiques des élèves 
concernés et en complément des batteries communes à tous.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 32, 'Article 1.', 'Article 1.4.4-5. - La Commission des outils d''évaluation du tronc 
commun comprend: 
1° huit membres désignés par le Ministre sur proposition du Conseil 
général de l''enseignement fondamental; 
2° huit membres désignés par le Ministre sur proposition du Conseil 
général de l''enseignement secondaire; 
3° trois représentants de l''inspection désignés par le Ministre sur 
proposition des Inspecteurs généraux; 
4° un délégué de l''Administration générale désigné par le Ministre sur 
proposition de l''Administrateur général. 
 
La Commission des outils d''évaluation de la section de transition du 
degré supérieur de l''enseignement secondaire et la Commission des outils 
d''évaluation de la section de qualification du degré supérieur de 
l''enseignement secondaire comprennent chacune: 
1° huit membres désignés par le Ministre sur proposition du Conseil 
général de l''enseignement secondaire; 
2° deux représentants de l''inspection désignés par le Ministre sur 
proposition des inspecteurs généraux; 
3° un délégué de l''Administration générale, désigné par le Ministre sur 
proposition de l''Administrateur général. 
 
Les mandats sont d''une durée de quatre ans. Ils sont renouvelables. Leur 
rétribution est fixée par le Gouvernement. 
 
Chaque Commission des outils d''évaluation choisit son président. Elle 
rend ses avis à la majorité des deux tiers. 
 
Inséré par D. 23-06-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 33, 'Article 1. (partie 1)', 'Article 1.4.4-6 - § 1er. Tout pouvoir organisateur et toute fédération de pouvoirs organisateurs qui s''est vu déléguer par un ou des pouvoir(s) organisateur(s) l''élaboration de son programme peut introduire une demande de dérogation aux référentiels aux conditions et selon la procédure définie au présent article. La demande de la fédération de pouvoirs organisateurs précise le ou les pouvoirs organisateurs concernés par la demande de dérogation. Ces demandes de dérogation visent l''ensemble des référentiels ou des parties de référentiels. § 2. Aucune dérogation ne peut avoir pour effet de porter atteinte à la cohérence du système éducatif, tel qu''il résulte de la mise en oeuvre des principes constitutionnels en matière d''enseignement. Elle ne peut notamment avoir pour effet de porter atteinte à la qualité de l''enseignement, au contenu de base ou à l''équivalence des diplômes et certificats, ou encore de restreindre la liberté des parents de changer leur enfant d''école l''année scolaire suivante. Docu 49466 Code 03-05-2019 Aucune dérogation ne peut être accordée à un pouvoir organisateur ou à une fédération de pouvoirs organisateurs dont le projet n''aurait pas pour effet de garantir les droits et libertés consacrés dans la Constitution, la Convention européenne de sauvegarde des droits de l''homme et des libertés fondamentales, ainsi que la Convention relative aux droits de l''enfant. § 3. Dans la demande de dérogation, le pouvoir organisateur ou la fédération de pouvoirs organisateurs : 1° indique les contenus et les attendus déclinés dans le référentiel ou les référentiels pour le(s)quel(s) il/elle souhaite obtenir une dérogation dont il/elle estime le caractère trop contraignant pour lui laisser une latitude suffisante pour mettre en oeuvre son propre projet pédagogique, en motivant les raisons pour lesquelles ces contenus et attendus restreignent cette mise en oeuvre ; 2° décrit les contenus et les attendus alternatifs qu''il/elle entend mettre en oeuvre ; 3° justifie comment le remplacement qu''il/elle opère respecte les conditions énoncées au paragraphe 2. § 4. La demande de dérogation précise les références exactes des suppressions et des insertions demandées. Une copie du projet pédagogique est jointe à la demande. Sous peine d''être irrecevables, la demande de dérogation et ses annexes sont introduites, par envoi recommandé, auprès du gouvernement, au plus tard six mois avant le début de l''année scolaire à partir de laquelle elle doit entrer en vigueur. § 5. Il est créé une Commission chargée de donner un avis au gouvernement sur les demandes de dérogation. La Commission, présidée par l''Administrateur général de l''Administration Générale de l''Enseignement ou son délégué, est composée comme suit : 1° un fonctionnaire général de la Direction générale du Pilotage du Système Educatif ou son délégué désignés par le gouvernement ; 2° trois membres du Service de l''Inspection du continuum pédagogique, à raison de deux pour le niveau primaire, et d''un pour le niveau secondaire du degré inférieur, désignés par le gouvernement, sur proposition de l''Inspecteur général coordonnateur et avis de l''Inspecteur coordonnateur de l''Enseignement du continuum pédagogique ; 3° deux membres de la Direction générale du pilotage du système éducatif, désignés par le gouvernement ; 4° le président et le vice-président du Conseil général de l''enseignement fondamental ou leur délégué respectif, sauf si l''un de ceux-ci est déjà membre de la commission à un autre titre auquel cas ledit Conseil général désigne un autre de ses membres ; 5° s''il s''agit d''une demande de dérogation portant sur l''une des composantes du référentiel du tronc commun, le président et le vice-président du Conseil général de concertation pour l''enseignement secondaire ou leur délégué respectif, sauf si l''un de ceux-ci est déjà membre de la commission à un autre titre auquel cas ledit Conseil général désigne un autre de ses membres ; 6° trois experts universitaires ou de Hautes Ecoles en pédagogie désignés par le gouvernement sur proposition de l''ARES ; 7° un représentant du ministre de l''Education, siégeant avec voix consultative. Docu 49466 Code 03-05-2019 Le gouvernement désigne un membre suppléant pour chacun des membres visés à l''alinéa 1er, 2°, 3°, 6° et 7°. Le mandat des membres de la Commission est d''une durée de quatre ans, renouvelable. Le mandat des membres de la Commission est gratuit. Les membres visés à l''alinéa 1er, 6°, sont remboursés de leurs frais de déplacement selon les modalités applicables aux agents des Services du gouvernement. La Commission est convoquée par le président. La convocation contient l''ordre du jour. La Commission ne peut délibérer valablement que si la moitié de ses membres est présente. Si ce quorum n''est pas atteint, la Commission peut, après une deuxième convocation, délibérer valablement sur le même ordre du jour, quel que soit le nombre de membres présents. En cas de parité des voix, la voix du président est prépondérante. Po');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 34, 'Article 1. (partie 2)', 'ce qui concerne les autres modalités de fonctionnement, la Commission fixe son règlement d''ordre intérieur qui est soumis pour approbation au gouvernement, dans un délai de deux mois à partir de la première réunion de ladite Commission. § 6. Dès réception de la demande de dérogation, le gouvernement la transmet, avec ses annexes, à la Commission. Dans un délai de deux mois commençant à courir à compter de la transmission de la demande de dérogation, avec ses annexes, par le gouvernement à la Commission, celle-ci transmet au gouvernement un avis motivé sur : 1° le caractère nécessaire du remplacement des contenus et attendus eu égard à la mise en oeuvre du projet pédagogique du pouvoir organisateur ou de la fédération de pouvoirs organisateurs ; 2° le respect du paragraphe 2. Ce délai est suspendu entre le 15 juillet et le 15 août. Le gouvernement transmet l''avis de la Commission au pouvoir organisateur ou à la fédération de pouvoirs organisateurs concerné par envoi recommandé dans les 15 jours calendrier de la réception de l''avis. Le pouvoir organisateur ou la fédération de pouvoirs organisateurs dispose d''un délai d''un mois à dater de la réception de l''avis de la commission pour faire valoir ses observations. Lorsque le pouvoir organisateur ou la fédération de pouvoirs organisateurs n''a pas notifié ses observations dans les délais requis, la procédure est poursuivie sans qu''il soit tenu compte des observations tardives. § 7. Au terme de la procédure visée au paragraphe 6, le gouvernement prend une décision motivée sur la demande de dérogation, dans un délai d''un mois à partir de la réception des observations du pouvoir organisateur ou de la fédération de pouvoirs organisateurs. Si une dérogation est accordée, en tout ou en partie, le gouvernement la soumet à la confirmation du Parlement. Docu 49466 Code 03-05-2019 § 8. Si la dérogation est confirmée par le Parlement, elle est immédiatement communiquée à la Commission des référentiels et des programmes du Tronc commun visée à l''article 1.6.2.2 du Code. Le pouvoir organisateur ou la fédération de pouvoirs organisateurs communique à la Commission des référentiels et des programmes du Tronc commun le programme qu''il veut appliquer en fonction des dérogations obtenues. Inséré par D. 23-06-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 35, 'Article 1.', 'Article 1.4.4-7. - Le gouvernement détermine les documents 
thématiques destinés aux équipes pédagogiques portant sur les référentiels 
visés aux chapitres II et III. Ces documents sont soumis à la confirmation du 
Parlement dans les six mois de leur adoption. 
 
Ces documents visent à offrir une lecture coordonnée et transversale des 
référentiels sur un thème ou un enjeu particulier sans constituer de 
prescription nouvelle ni de savoir, savoir-faire et compétence supplémentaire 
ou différent par rapport aux référentiels visés aux chapitres II et III. 
 
Le document thématique relatif à l''éducation aux médias est mis à 
disposition dès la mise en oeuvre du tronc commun. 
 
(Le document thématique est repris : 
http://www.ejustice.just.fgov.be/mopdf/2022/10/20_1_3.pdf#Page320 
Inséré par D. 13-10-2022 
CHAPITRE V - Du parcours d''éducation culturelle et artistique 
 
Section 1re  - Dispositions générales 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 36, 'Article 1.', 'Article 1.4.5-1. Pour l''application du présent chapitre, on entend par: 
1° Ecole supérieure des Arts ou ESA: l''établissement d''enseignement 
supérieur défini à l''article 1er, 2°, du décret du 20 décembre 2001 fixant les 
règles spécifiques à l''Enseignement supérieur artistique organisé en Ecoles 
supérieures des Arts; 
2° Enseignement secondaire artistique à horaire réduit ou ESAHR: 
l''enseignement défini à l''article 1er, 2°, du décret du 2 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française; 
3° Opérateur culturel: toute personne physique ou morale dont les 
activités s''inscrivent dans le cadre des politiques culturelles et qui bénéficie à 
ce titre d''une reconnaissance ou d''un soutien de la Communauté française; 
4° Plateforme territoriale PECA: la plateforme visée aux articles 1.4.5-20 
et 1.4.5-21; 
5° Politiques culturelles: les politiques menées par la Communauté 
française dans les matières culturelles visées par l''article 4, 1°, 3° à 6°, 8°, 10°, 
13° et 14°, de la loi spéciale de réformes institutionnelles du 8 août 1980; 
6° Référents culturels: les référents culturels visés à l''article 5, alinéa 1er, 
1°, du décret du 28 mars 2019 relatif aux cellules de soutien et 
d''accompagnement de l''enseignement organisé ou subventionné par la 
Communauté française et au statut des conseillers au soutien et à 
l''accompagnement; 
7° Référent scolaire: opérateur culturel ou un groupement d''opérateurs 
culturels ayant formalisé par écrit leur collaboration par le biais d''une 
convention, dont l''un des membres est désigné coordinateur et représente 
 
 
Docu 49466 
 
Code 03-05-2019 
l''ensemble vis-à-vis du Gouvernement et dont les missions sont visées à 
l''article 1.4.5-17, § 1er. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 37, 'Article 1.', 'Article 1.4.5-2. Le parcours d''éducation culturelle et artistique, en 
abrégé PECA, a pour objectif de permettre à chaque élève, dans une optique 
de démocratisation culturelle et de développement culturel: 
1° d''accéder à la vie culturelle, de rencontrer des oeuvres, des artistes et 
des pratiques culturelles, et de fréquenter des lieux culturels; 
2° d''acquérir des savoirs, des connaissances et des compétences en 
matière culturelle et artistique, dans une perspective de développement de 
l''esprit critique et de l''expression personnelle; 
3° d''expérimenter des pratiques culturelles et artistiques, individuelles 
et collectives, et de prendre une part active dans la vie culturelle; 
4° d''accéder et de participer à la diversité des vies culturelles et 
artistiques et de se familiariser avec des expressions culturelles provenant de 
différents horizons, exprimant différentes représentations du monde. 
 
Le parcours d''éducation culturelle et artistique contribue également: 
1° à la lutte contre l''échec scolaire par la diversification des pratiques 
pédagogiques; 
2° à sensibiliser les acteurs de l''enseignement sur l''intérêt d''une 
démarche culturelle et artistique, continue et plurielle dans sa diversité 
d''expression et sa dimension interdisciplinaire; 
3° à renforcer et à valoriser les collaborations entre les opérateurs 
culturels et les acteurs de l''enseignement. 
 
[Dans le cadre du parcours d’éducation culturelle et artistique, les élèves 
participants ne peuvent être soumis à aucune forme de violence physique ou 
psychique, soit l’ensemble des violences physiques, psychiques ou verbales, en 
ce compris celles exercées avec une visée éducative sur un enfant visant à 
corriger certains comportements ou à le punir.]6 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 38, 'Article 1.', 'Article 1.4.5-3. - Le parcours d''éducation culturelle et artistique est mis 
en oeuvre: 
1° au niveau de la Communauté française, par le Gouvernement et ses 
services; 
2° au niveau territorial, par l''intermédiaire d''un référent scolaire et d''une 
plateforme PECA; 
3° au niveau de Wallonie-Bruxelles Enseignement et des fédérations de 
pouvoirs organisateurs, avec la collaboration de référents culturels; 
4° par les écoles, notamment via les délégués-PECA visés à l''article 1.4.5-
15; 
5° par l''ESAHR. 
 
Insérée par D. 13-10-2022 
Section 2. - Du Conseil de l''éducation culturelle et artistique 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 39, 'Article 1.', 'Article 1.4.5-5. - § 1er. Il est créé un Conseil de l''éducation culturelle et 
artistique, en abrégé CECA, chargé de formuler, d''initiative ou à la demande 
 
6Inséré par le décret du 05 octobre 2023 
 
 
Docu 49466 
 
Code 03-05-2019 
du 
Gouvernement 
ou 
du 
Parlement, 
des 
avis, 
propositions 
et 
recommandations: 
1° sur toute question concernant les orientations, les objectifs et la mise 
en oeuvre du parcours d''éducation culturelle et artistique et des collaborations 
entre la culture et l''enseignement, ce comprenant l''affectation des budgets 
dont il est question à l''article 1.4.5-22, § 4; 
2° sur tout avant-projet de décret ou tout projet d''arrêté règlementaire 
adopté dans le cadre de la mise en oeuvre du parcours d''éducation culturelle 
et artistique et des collaborations entre la culture et l''enseignement; 
3° dans le cadre de l''évaluation par les services du Gouvernement des 
législations et règlementations relatifs au parcours d''éducation culturelle et 
artistique et aux collaborations entre la Culture et l''Enseignement; 
4° dans le cadre de la conception par les services du Gouvernement du 
plan d''actions visé à l''article 1.4.5-13. 
 
La consultation préalable du Conseil est obligatoire dans les cas 
mentionnés à l''alinéa 1er, 2° à 4°. 
 
§ 2. Dans le cadre de ses missions, le Conseil contribue: 
1° à définir les priorités et les actions susceptibles de faire l''objet de 
campagnes thématiques; 
2° à faciliter la bonne adéquation entre l''offre culturelle et artistique 
d''une part, et les besoins du public scolaire d''autre part; 
3° à identifier les inégalités en termes d''accès du public scolaire à la 
culture et à déterminer les solutions pour y remédier. 
 
Pour ce faire, il s''appuie notamment sur les travaux des différentes 
plateformes PECA. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 40, 'Article 1.', 'Article 1.4.5-6. Le Conseil de l''éducation culturelle et artistique est 
composé des membres effectifs suivants, disposant d''une voix délibérative: 
1° le Secrétaire général du Ministère, ou son délégué; 
2° un représentant par référent scolaire; 
3° deux représentants du Conseil supérieur de la Culture, institué par le 
décret du 28 mars 2019 sur la nouvelle gouvernance culturelle; 
4° dix référents culturels; 
5° un représentant du Conseil général de l''enseignement secondaire 
artistique à horaire réduit; 
6° un représentant de chacune des organisations représentatives des 
parents et associations de parents d''élèves visées à l''article 1.6.6-1; 
7° le Directeur général de la Direction générale du pilotage du système 
éducatif, ou son délégué; 
8° le Directeur général adjoint expert en transversalité culturelle, ou son 
délégué: 
 
Pour chaque membre effectif, il est désigné un membre suppléant. 
 
En ce qui concerne les référents culturels visés à l''alinéa 1er, 4°, ils sont 
répartis comme suit: 
1° quatre référents culturels de l''enseignement libre subventionné 
confessionnels; 
2° deux référents culturels pour l''enseignement fondamental officiel 
subventionné; 
 
 
Docu 49466 
 
Code 03-05-2019 
3° un référent culturel pour l''enseignement secondaire officiel 
subventionné; 
4° deux référents culturels pour Wallonie-Bruxelles Enseignement; 
5° un référent culturel pour l''enseignement libre subventionné non 
confessionnel. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 41, 'Article 1.', 'Article 1.4.5-7. Les membres effectifs et suppléants sont désignés par le 
Gouvernement pour un mandat de cinq ans, renouvelable. 
 
Le Gouvernement met fin au mandat d''un membre: 
1° à la demande de ce membre; 
2° suite à la perte par le membre de la qualité pour laquelle il avait été 
désigné. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 42, 'Article 1.', 'Article 1.4.5-8. Sont invités et peuvent participer, avec voix consultative, 
aux travaux du Conseil de l''éducation culturelle et artistique: 
1° l''Administrateur général de la Culture, ou son délégué; 
2° l''Administrateur général de l''Enseignement, ou son délégué; 
3° le Coordinateur de l''Observatoire des politiques culturelles, ou son 
délégué; 
4° un représentant du Service général de l''Inspection de la Culture; 
5° un représentant du Service général de l''Inspection; 
6° un représentant du service en charge du pilotage du PECA; 
7° un représentant des ESA, désigné sur proposition de la Chambre des 
Ecoles supérieures des arts de l''ARES. 
 
Le Conseil de l''éducation culturelle et artistique peut également inviter, 
en fonction de l''ordre du jour, toute personne qu''il juge utile d''entendre pour 
éclairer ses travaux. Les personnes invitées ont voix consultative. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 43, 'Article 1.', 'Article 1.4.5-9. § 1er. La présidence est exercée par le Secrétaire général 
du Ministère, ou son délégué. 
 
§ 2. La présidence assure les tâches qui lui sont conférées par le 
règlement d''ordre intérieur. 
 
Elle participe aux débats, les organise et les conclut. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 44, 'Article 1.', 'Article 1.4.5-10. Le secrétariat du Conseil de l''éducation culturelle et 
artistique est assuré par les services du Gouvernement. 
 
En concertation avec le président, le secrétariat est chargé: 
1° de la fixation et de la tenue de l''ordre du jour des réunions et de la 
rédaction du procès-verbal; 
2° de veiller au respect de la législation et du règlement d''ordre intérieur; 
3° de relayer auprès des membres la position et les propositions des 
services du Gouvernement quant à la mise en oeuvre du PECA. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 45, 'Article 1.', 'Article 1.4.5-11. Le Conseil de l''éducation culturelle et artistique établit, 
sur proposition du secrétariat, son règlement d''ordre intérieur. 
 
 
Docu 49466 
 
Code 03-05-2019 
Insérée par D. 13-10-2022 
Section 3.  - Du pilotage du PECA 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 46, 'Article 1.', 'Article 1.4.5-12. Le Gouvernement assure, par l''intermédiaire de ses 
services, le pilotage du parcours d''éducation culturelle et artistique. 
 
A cet effet, il est chargé: 
1° de veiller à l''intégration structurelle, systématique et généralisée du 
PECA dans l''ensemble des écoles organisées ou subventionnées par la 
Communauté française; 
2° de sensibiliser et de stimuler les différents acteurs; 
3° de susciter l''innovation et l''expérimentation; 
4° de stimuler l''offre culturelle et artistique à destination des publics 
scolaires et d''assurer sa diffusion; 
5° de communiquer et de diffuser des informations au sujet du PECA; 
6° de veiller à la bonne articulation des différents acteurs et projets, en 
assurant un rôle de mise en relation, notamment en participant aux travaux 
des plateformes territoriales PECA visées à l''article 1.4.5-21; 
7° d''analyser et d''évaluer la mise en oeuvre du PECA, et de procéder si 
nécessaire à des améliorations; 
8° d''établir un cadastre des démarches culturelles et artistiques réalisées 
dans les écoles. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 47, 'Article 1.', 'Article 1.4.5-13. § 1er. Le Gouvernement adopte tous les cinq ans, après 
avis du Conseil de l''éducation culturelle et artistique, un plan d''actions PECA 
définissant les stratégies, les objectifs chiffrés, le programme d''actions, et le 
calendrier de mise en oeuvre envisagés pour les cinq ans à venir. 
 
Le plan identifie les publics prioritaires et les actions à mettre en oeuvre 
en priorité et comprend la mise en place de campagnes thématiques. A cet 
égard, une attention particulière est accordée aux implantations bénéficiaires 
de l''encadrement différencié conformément au décret du 30 avril 2009 
organisant un encadrement différencié au sein des établissements scolaires de 
la Communauté française afin d''assurer à chaque élève des chances égales 
d''émancipation sociale dans un environnement pédagogique de qualité et aux 
élèves scolarisés dans l''enseignement spécialisé. 
 
§ 2. Le plan d''actions PECA peut être adapté en cours de mise en oeuvre, 
après avis du Conseil de l''éducation culturelle et artistique. 
 
 
Le Conseil de l''éducation culturelle et artistique se réunit au moins trois 
fois par année scolaire 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 48, 'Article 1.', 'Article 1.4.5-14. Le Gouvernement met en place, sous la forme d''un outil 
numérique accessible en ligne, un centre de ressources documentaires 
concernant le parcours d''éducation culturelle et artistique. 
 
L''outil numérique mentionné à l''alinéa 1er: 
1° agrège, répertorie et met en réseau les offres culturelles et artistiques 
existantes à destination des publics scolaires; 
 
 
Docu 49466 
 
Code 03-05-2019 
2° permet de récolter les demandes d''interventions culturelles et 
artistiques introduites par les écoles; 
3° agrège, répertorie et met à disposition les outils pédagogiques 
disponibles en libre accès; 
4° agrège, répertorie et diffuse les pratiques inspirantes en termes de 
médiation culturelle vers les publics scolaires; 
5° agrège et répertorie les analyses et études concernant l''accès et la 
participation des publics scolaires à la vie culturelle, et met à disposition celles 
qui sont disponibles en libre accès. 
 
L''outil numérique est accessible à l''ensemble des équipes éducatives, des 
opérateurs culturels, des artistes, des chercheurs, des étudiants et de toute 
personne intéressée. 
 
 
 
Insérée par D. 13-10-2022 
Section 4.  - Des délégués-PECA 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 49, 'Article 1.', 'Article 1.4.5-15. Chaque école peut identifier en son sein au moins un 
délégué-PECA au sein de l''équipe pédagogique, parmi les volontaires. 
 
Le cas échéant, le délégué-PECA exerce, avec l''appui et le soutien des 
référents culturels de Wallonie-Bruxelles Enseignement ou de la fédération de 
pouvoirs organisateurs dont il relève, les missions suivantes: 
1° répercuter dans son école les informations reçues au niveau de la 
plateforme territoriale PECA; 
2° être à l''écoute des besoins et des aspirations de son école par rapport 
au parcours d''éducation culturelle et artistique, et porter sa représentation au 
niveau de la plateforme territoriale PECA; 
3° participer à la mise en place de projets au niveau de la plateforme 
territoriale PECA; 
4° le cas échéant, formuler des propositions au directeur en vue de 
l''intégration ou du renforcement du parcours d''éducation culturelle et 
artistique dans le contrat d''objectif de l''école. 
 
Insérée par D. 13-10-2022 
Section 5.  - Des référents scolaires 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 50, 'Article 1.', 'Article 1.4.5-16. § 1er. Le Gouvernement désigne, par zone ou selon un 
découpage territorial qu''il détermine, un opérateur culturel ou un groupement 
d''opérateurs culturels pour assurer le rôle de référent scolaire. 
 
Lorsqu''un groupement d''opérateurs assure le rôle de référent scolaire, les 
prescriptions suivantes sont d''application: 
1° les membres du groupement formalisent par écrit leur collaboration 
par le biais d''une convention; 
2° un de ses membres est désigné coordinateur et représente l''ensemble 
vis-à-vis du Gouvernement. 
 
§ 2. Le référent scolaire ou, en cas de groupement, le coordinateur visé au 
paragraphe 1er, alinéa 2, 2°, doivent être constitué sous la forme d''une 
personne morale. 
 
 
Docu 49466 
 
Code 03-05-2019 
Les référents scolaires sont désignés pour une période de 5 ans, 
renouvelable, prenant cours le 30 septembre de l''année de leur désignation. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 51, 'Article 1.', 'Article 1.4.5-17. § 1er. Le référent scolaire exerce, sur le territoire pour 
lequel il est désigné, les missions suivantes: 
1° initier, agréger, coordonner, développer et compléter, dans une 
dynamique inter-réseaux, une offre rendant compte de la diversité des 
disciplines culturelles et artistiques; 
2° organiser la mise en relation entre, d''une part, les écoles et, d''autre 
part, les artistes, les opérateurs culturels et l''ESAHR; 
3° organiser et animer une plateforme territoriale de concertation PECA; 
4° contribuer à alimenter le cadastre mentionné à l''article 1.4.5-12, alinéa 
2, 8°, et le centre de ressources documentaires. 
 
§ 2. Le référent scolaire détaille la manière dont il compte exercer ses 
missions dans un plan d''actions évalué et actualisé annuellement. Ce plan 
repose sur une analyse collective du territoire, visant à s''assurer: 
1° de la participation de l''ensemble des écoles; 
2° de la participation de l''ensemble des opérateurs culturels; 
3° que les projets concernent tous les domaines culturels et artistiques et 
que l''offre à destination des écoles soit variée et adaptée à leurs besoins. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 52, 'Article 1.', 'Article 1.4.5-18. Les référents scolaires sont désignés sur la base d''un 
appel à candidatures prenant en compte les critères suivants: 
1° les spécificités géographiques et sociales du territoire; 
2° l''expérience du référent scolaire dans la mise en place, le 
développement et le suivi de partenariats culture-école; 
3° la capacité du référent scolaire à mettre en relation les écoles, d''une 
part et, d''autre part, les artistes, les opérateurs culturels et l''ESAHR; 
4° la capacité du référent scolaire à assurer ses missions sur l''ensemble 
du territoire; 
5° la pertinence des pistes envisagées pour améliorer la couverture 
territoriale et garantir à tous les élèves un accès à la culture; 
6° la qualité et la quantité des partenariats envisagés. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 53, 'Article 1.', 'Article 1.4.5-19. Le Gouvernement accorde à chaque référent scolaire 
une subvention de 100.000 euros destinée à couvrir les frais de personnel et de 
fonctionnement liés aux missions visées à l''article 1.4.5-17. 
 
Le montant mentionné à l''alinéa 1er est indexé annuellement en fonction 
du rapport entre l''indice santé applicable au 1er janvier de l''exercice concerné 
avec celui applicable au 1er janvier 2022. 
 
Insérée par D. 13-10-2022 
Section 6.  - Des plateformes territoriales PECA 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 54, 'Article 1.', 'Article 1.4.5-20. Il est créé, auprès de chaque référent scolaire, une 
plateforme territoriale. 
 
La plateforme territoriale PECA est composée: 
 
 
Docu 49466 
 
Code 03-05-2019 
1° d''un représentant du service du pilotage PECA; 
2° du référent scolaire; 
3° de cinq délégués-PECA, chaque fédération de pouvoirs organisateurs 
et Wallonie-Bruxelles Enseignement, en désignant un; 
4° d''un référent culturel de Wallonie-Bruxelles Enseignement et de 
chaque fédération de pouvoirs organisateurs; 
5° d''un représentant de l''ESAHR, désigné sur proposition du Conseil 
général de l''enseignement secondaire artistique à horaire réduit. 
 
La présidence des réunions, en ce compris la fixation de l''agenda et de 
l''ordre du jour, est assurée conjointement par le représentant du service du 
pilotage PECA et le référent scolaire. 
 
Les décisions de la plateforme territoriale PECA sont prises au 
consensus. 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 55, 'Article 1.', 'Article 1.4.5-21. La plateforme territoriale PECA vise à: 
1° organiser et formaliser la rencontre, le contact direct et la mise en 
réseau des acteurs du PECA; 
2° assurer la concertation entre les acteurs du PECA relativement aux 
besoins des écoles et aux offres culturelles et artistiques disponibles; 
3° assurer la diffusion et l''échange d''informations sur les dispositifs de 
médiation culturelle disponibles; 
4° affiner et actualiser le cadastre mentionné à l''article 1.4.5-12, alinéa 2, 
8°, sur le territoire concerné; 
5° favoriser le développement, la mise en oeuvre et la diffusion de projets 
inter-écoles, inter-réseaux et inter-opérateurs culturels; 
6° contribuer à l''élaboration du plan d''actions visé à l''article 1.4.5-13 et à 
sa mise en oeuvre sur le territoire. 
 
Insérée par D. 13-10-2022 
Section 7.  - Du financement du PECA 
 
Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 56, 'Article 1. (partie 1)', 'Article 1.4.5-22. § 1er. Sans préjudice des subventions pouvant être accordées en vertu d''autres législations, le Gouvernement peut soutenir, selon les modalités qu''il arrête, les projets et activités: 1° qui contribuent aux objectifs définis à l''article 1.4.5-2; 2° et qui s''inscrivent dans le cadre des stratégies et priorités définies par le plan d''actions visé à l''article 1.4.5-13. Le soutien visé à l''alinéa 1er peut consister: 1° en l''octroi de subventions aux opérateurs culturels qui portent le projet ou développent les activités; 2° en une assistance matérielle des services du Gouvernement en vue du développement, de la réalisation ou de la promotion des projets et activités concernés. § 2. Pour pouvoir bénéficier du soutien mentionné au paragraphe 1er, les projets et activités concernés doivent répondre aux conditions cumulatives suivantes: 1° mettre en relation des élèves avec des artistes, des oeuvres ou des opérateurs culturels; Docu 49466 Code 03-05-2019 2° se dérouler dans le cadre scolaire, à l''intérieur ou à l''extérieur de l''école; 3° reposer sur une articulation cohérente entre les éléments suivants: a) les objectifs poursuivis; b) les savoirs et compétences transversales visées; c) le lien avec les référentiels, transmis sous forme d''un document de synthèse, (savoirs, savoir-faire ou compétences,) du niveau d''enseignement concerné; d) les activités prévues et leurs modalités d''organisation; e) le public concerné; f) les partenaires en présence; g) l''implication des différentes parties prenantes; h) les indicateurs d''évaluation; 4° être complémentaire par rapport aux projets et activités existants; 5° contribuer progressivement à une couverture optimale des différents territoires et de la population scolaire de la Communauté française; 6° être organisés dans le respect des dispositions relatives à la gratuité visées aux articles 1.7.2-1 et 1.7.2-2. [7° les élèves participants ne peuvent être soumis à aucune forme de violence physique ou psychique, soit l’ensemble des violences physiques, psychiques ou verbales, en ce compris celles exercées avec une visée éducative sur un enfant visant à corriger certains comportements ou à le punir.]7 Les projets et activités subventionnés en vertu du présent article sont répertoriés dans le cadastre visé à l''article 1.4.5-12, selon les conditions établies par le Gouvernement. § 3. Sans préjudice des budgets alloués aux activités culturelles à destination de l''enseignement dans le cadre d''autres dispositifs, les montants suivants sont affectés annuellement à la mise en oeuvre du présent chapitre: 1° au cours de l''exercice 2022: 3.827.619 €; 2° au cours de l''exercice 2023: 4.453.585 €; 3° au cours de l''exercice 2024: 4.956.393 €; 4° au cours de l''exercice 2025: 5.512.389 €; [5° au cours de l''exercice 2026 : 5.759.886 € ;]8 6° au cours de l''exercice 2027: 6.636.378 €; 7° au cours de l''exercice 2028: 7.268.378 €; 8° au cours de l''exercice 2029: 7.463.378 €; 9° à partir de l''exercice 2030: 7.637.378 €. Les montants mentionnés à l''alinéa 1er sont indexés annuellement en fonction du rapport entre l''indice santé applicable au 1er janvier de l''exercice concerné avec celui applicable au 1er janvier 2022. § 4. Le Gouvernement répartit les montants annuels mentionnés au paragraphe 3 en trois enveloppes: 1° entre 70 et 80 % sont destinés au renforcement du subventionnement des opérateurs qui bénéficient d''un soutien pluriannuel et dont tout ou partie des activités s''adressent au jeune public, et plus particulièrement au public scolaire; la subvention prévue à l''article 1.4.5-19 est incluse dans cette enveloppe; 7Inséré par le décret du 05 octobre 2023 8Remplacé par le D. 17-12-2025 Docu 49466 Code 03-05-2019 2° entre 10 et 20 % sont destinés au renforcement des programmes développés par les services du Gouvernement en application du paragraphe 1er, alinéa 1er, 3° ; 3° entre 10 et 20 % sont destinés à soutenir de nouveaux projets à destination des publics scolaires. Le Gouvernement précise l''affectation des moyens au sein de chaque enveloppe, en accordant une attention prioritaire: 1° aux écoles à indice socio-économique faible dans la mesure où dans le classement des implantations réalisées en application de l''article 4, alinéa 4, du décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité, elles relèvent des classes 1 à 8; 2° aux classes dont le cadastre mentionné à l''article 1.4.5-12, alinéa 2, 8°, révèle qu''elles ne participent pas ou peu à des activités culturelles.; 3° aux écoles situées sur un territoire où les opérateurs culturels sont absents ou peu nombreux. Insérée par D. 13-10-2022 Section 8. - De l''évaluation de la mise en oeuvre des dispositions relatives au parcours d''éducation culturelle et artistique Inséré par D. 13-10-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 57, 'Article 1.', 'Article 1.4.5-23. Le Gouvernement évalue la mise en oeuvre des 
dispositions du présent chapitre tous les quatre ans et pour la première fois 
durant l''année scolaire 2026-2027 et en fait rapport au Parlement. 
 
[[CHAPITRE 6. - De l''approche éducative de l''orientation]9 
 
Section 1. - Dispositions générales');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 58, 'Article 1.', 'Article 1.4.6-1. - Dans le présent chapitre, il faut entendre par : 
 
1° « acteurs scolaires de l''orientation » : les acteurs visés à l''article 1.4.63, 
§2 ; 
 
2° « délégué en charge de l''orientation des élèves » : le délégué visé par 
l''article 9, §1er, 14°, du décret du 14 mars 2019 portant diverses dispositions 
relatives à l''organisation du travail des membres du personnel de 
l''enseignement et octroyant plus de souplesse organisationnelle aux pouvoirs 
organisateurs et exerçant les missions visées à l''article 1.4.6-4 ; 
 
3° « partenaires zonaux de l''orientation » : les partenaires visés à l''article 
1.4.6-3, §3 ; 
 
4° « partenaires externes des activités portant sur l''orientation » : les 
partenaires visés à l''article 1.4.6-3, §4.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 59, 'Article 1.', 'Article 1.4.6-2. - L''approche éducative de l''orientation vise à : 
 
 
9Chapitre inséré par le D. 16-05-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
1° développer la capacité de l''élève à pouvoir agir sur son parcours, mais 
aussi prendre conscience des contraintes et des limites qui pèsent sur ce savoir-
agir ; 
 
2° repérer et critiquer les facteurs, explicites et implicites, qui influencent 
les choix, y compris en ce qui concerne le choix d''orientation à poser en fin de 
tronc commun ; 
 
3° transformer des connaissances et des observations en choix et en 
actions qui les concrétisent ; 
 
4° développer divers scénarios de son avenir et être capable de s''y projeter 
; 
 
5° se sensibiliser au caractère ouvert de ses choix et aux perspectives 
offertes par l''apprentissage tout au long de la vie, notamment dans le contexte 
des évolutions professionnelles ; 
 
6° découvrir différents milieux professionnels et leur diversité et être 
sensibilisé tant aux contributions sociétales qu''aux enjeux éthiques et 
perspectives d''insertion socioprofessionnelle liés à ces divers mondes 
socioprofessionnels ; 
 
7° relier des savoir, savoir-faire ou compétences disciplinaires ou 
transversaux, travaillés en classe, avec des filières et des options qui s''ouvrent 
après le tronc commun et avec des sphères professionnelles et des métiers ; 
 
8° découvrir différentes possibilités de formation ultérieures qui 
s''ouvrent en fin de parcours de tronc commun ; 
 
9° rencontrer différents types d''acteurs pour pouvoir construire ses 
démarches d''orientation. 
 
Section 2. - Des acteurs et partenaires de l''approche éducative de 
l''orientation');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 60, 'Article 1.', 'Article 1.4.6-3. - §1er. L''approche éducative de l''orientation implique 
différents acteurs scolaires et des partenaires qui peuvent être sollicités par 
l''école pour la mise en place des activités portant sur l''orientation : 
 
1° les acteurs scolaires de l''orientation visés au paragraphe 2 ; 
 
2° les partenaires zonaux de l''orientation visés au paragraphe 3 ; 
 
3° les partenaires externes des activités portant sur l''orientation visés au 
paragraphe 4. 
 
§2. Les acteurs scolaires de l''orientation sont : 
 
1° les élèves ; 
 
2° l''équipe éducative ; 
 
3° le centre PMS ; 
 
 
 
Docu 49466 
 
Code 03-05-2019 
4° le délégué en charge de l''orientation des élèves, lorsqu''il est engagé ou 
désigné au sein de l''école ; 
 
5° les pôles territoriaux, à l''égard des élèves auprès desquels il effectue 
un accompagnement individuel ; 
 
6° l''association de parents lorsqu''elle est sollicitée par le pouvoir 
organisateur et qu''elle souhaite se mobiliser en la matière ; 
 
7° les équipes éducatives d''autres écoles relevant d''un même pouvoir 
organisateur ou de pouvoirs organisateurs ou fédérations de pouvoirs 
organisateurs distincts. 
 
§3. Les partenaires zonaux de l''orientation sont notamment : 
 
1° les Centres de compétence de Wallonie et les Centres de référence 
professionnelle de Bruxelles ; 
 
2° les Centres de technologies avancées définis par l''article 1er de l''accord 
de coopération du 20 mars 2014 conclu entre la Région wallonne et la 
Communauté française relatif à l''équipement mis à disposition dans le cadre 
de la refondation de l''enseignement qualifiant et à la collaboration entre les 
Centres de technologies avancées et les Centres de compétence et de référence 
; 
 
3° les Cités des Métiers - Carrefours des Métiers en Région wallonne et 
la Cité des Métiers en Région bruxelloise ; 
 
4° les établissements d''enseignement supérieur et en particulier leurs 
dispositifs et services dédiés à l''orientation ; 
 
5° les établissements d''[enseignement pour adultes] et en particulier 
leurs dispositifs et services dédiés à l''orientation ; 
 
6° les offices régionaux pour l''emploi ; 
 
7° les opérateurs de formation ; 
 
8° les Centres d''information jeunesse ; 
 
9° les services d''Action en milieu ouvert (AMO) ; 
 
10° les associations des organisations de jeunesse sollicitées en matière 
d''orientation ; 
 
11° les acteurs institutionnels de l''orientation. 
 
Les partenaires zonaux de l''orientation peuvent être sollicités par les 
écoles pour organiser des partenariats ou des activités portant sur l''orientation 
et, le cas échéant, pour soutenir les écoles dans l''organisation d''activités 
portant sur l''orientation en collaboration avec des partenaires externes. 
 
§4. Les partenaires externes des activités portant sur l''orientation sont 
notamment : 
 
1° des entreprises publiques et privées ; 
 
 
Docu 49466 
 
Code 03-05-2019 
2° des acteurs du secteur non-marchand ; 
 
3° des secteurs professionnels ; 
 
4° des indépendants et des artisans. 
 
Les partenaires externes des activités portant sur l''orientation peuvent 
être sollicités par les écoles pour organiser des partenariats ou des activités 
portant sur l''orientation. 
 
La mobilisation par les écoles de partenaires externes et les activités que 
ces partenaires organisent avec les élèves s''inscrivent dans le respect de 
l''article 1.7.3-3.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 61, 'Article 1.', 'Article 1.4.6-4. - L''école peut identifier en son sein un délégué en charge 
de l''orientation des élèves au sein de l''équipe pédagogique. 
 
Le délégué en charge de l''orientation des élèves exerce une des missions 
collectives du service à l''école et aux élèves visées à l''article 7, 2°, du décret du 
14 mars 2019 portant diverses dispositions relatives à l''organisation du travail 
des membres du personnel de l''enseignement et octroyant plus de souplesse 
organisationnelle aux pouvoirs organisateurs. 
 
Le délégué en charge de l''orientation des élèves veille, avec les acteurs 
concernés et sous la responsabilité du directeur, à : 
 
1° l''identification des besoins de l''école ; 
 
2° la coordination et la complémentarité des dispositifs et activités 
portant sur l''orientation ; 
 
3° la prise en charge des initiatives, projets, actions et activités mis en 
place par l''école ou en partenariat avec les partenaires visés à l''article 1.4.3-6, 
§§ 3 et 4 ; 
 
4° l''information et la communication au sein de l''école, notamment au 
sujet des actions, projets, dispositifs et ressources disponibles ; 
 
5° l''information sur les offres de services existantes en matière 
d''orientation, notamment celles liées à l''information sur les filières et les 
métiers au niveau d''un bassin ou d''une zone donnée. 
 
Il est la personne de contact et l''interlocuteur privilégié pour les 
partenaires zonaux de l''orientation et les partenaires externes des activités 
portant sur l''orientation. 
 
Section 3. - Des dispositifs de l''approche éducative de l''orientation');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 62, 'Article 1.', 'Article 1.4.6-5. - Dans le tronc commun, les cours et activités portant sur 
le domaine visé à l''article 1.4.2-3, 8°, s''inscrivent dans l''approche éducative de 
l''orientation. 
 
Dans les années du tronc commun de l''enseignement secondaire, des 
périodes dont le nombre est fixé à l''article 2.2.2-1, §3, alinéa 2, sont consacrées 
 
 
Docu 49466 
 
Code 03-05-2019 
d''une part aux activités visées à l''article 1.4.6-6 et, de manière transversale, 
au travers des cours de la grille horaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 63, 'Article 1.', 'Article 1.4.6-6. - §1er. Les activités portant sur l''orientation consistent 
en tout dispositif visant à mettre concrètement en œuvre l''approche éducative 
de l''orientation et mobilisant un ou plusieurs services, outils, ressources ou 
rencontres, notamment : 
 
1° des services d''accompagnement et de conseil individuel ou collectif ; 
 
2° des supports didactiques ; 
 
3° des outils d''autoévaluation des forces et intérêts ; 
 
4° des outils d''information sur les métiers et les filières d''études et sur les 
options possibles ; 
 
5° des ressources documentaires et multimédias ; 
 
6° des expériences pratiques au moyen de visites d''entreprises ou 
d''institutions, des visites d''institutions éducatives, ou des stages ; 
 
7° des rencontres avec les professionnels des métiers, y compris 
organisées dans le cadre d''activités de collaboration avec les parents et les 
proches des élèves. 
 
§2. Les activités portant sur l''orientation sont conçues de manière à 
refléter une diversité de filières d''études, de secteurs et métiers. 
 
§3. Les activités portant sur l''orientation sont conçues conformément aux 
critères fixés par l''équipe éducative, concernant leur finalité, leur accessibilité 
et leur objectivité. 
 
Les activités visent à promouvoir une orientation positive et à développer 
la capacité de l''élève à s''orienter, en particulier à mener une réflexion sur les 
aspects suivants : 
 
1° la connaissance de soi et des autres ; 
 
2° la connaissance des filières de l''enseignement, des études, des métiers, 
du monde professionnel et du marché du travail ; 
 
3° l''acquisition d''expérience notamment au travers d''activités pratiques ; 
 
4° l''ouverture aux différentes possibilités, à travers la recherche et l''accès 
à l''information pertinente. 
 
Les activités portant sur l''orientation sont accessibles à l''élève, en étant 
notamment : 
 
1° adaptées à chaque étape de la scolarité et particulièrement lors de 
transitions importantes, de manière à fournir une information complète ; 
 
2° offertes aux lieux, heures et sous les formes qui correspondent aux 
différents besoins ; 
 
 
 
Docu 49466 
 
Code 03-05-2019 
3° gratuites pour l''élève ; 
 
4° conçues pour éviter le risque d''exclusion sociale lié à l''accès à 
l''information et aux services. 
 
Les activités portant sur l''orientation sont tenues de répondre à des 
impératifs, de neutralité et d''objectivité, notamment en ce qui concerne : 
 
1° la préservation de l''indépendance vis-à-vis des intérêts d''entreprises, 
d''organismes, d''associations ou d''institutions spécifiques ; 
 
2° la prévention du risque d''étiquetage, de stéréotype et de préjugé, 
notamment en ce qui concerne le genre, l''origine (notamment sociale et 
culturel), le statut socio-économique ou certains métiers et filières ; 
 
3° l''alignement sur les exigences professionnelles clairement identifiées 
en collaboration avec les praticiens et partenaires impliqués. 
 
4° les filières et options organisées par l''école de l''élève au-delà du tronc 
commun. 
 
§4. Afin de mettre en place les activités portant sur l''orientation, l''école 
mobilise des acteurs et partenaires visés à l''article 1.4.6-3. Lorsqu''elle élabore 
des partenariats avec des partenaires zonaux ou des partenaires externes, 
l''école veille à refléter la diversité de filières d''études, et la pluralité des 
secteurs et métiers. 
 
Dans le tronc commun, les types d''activités et les partenariats envisagés 
sont renseignés dans le contrat d''objectifs de l''école, conformément à l''article 
1.5.2-3, §1er , 6°. 
 
Section 4. - De la plateforme numérique relative à l''approche 
éducative de l''orientation');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 64, 'Article 1.', 'Article 1.4.6-7. - Afin d''aider les élèves, les acteurs et partenaires 
sollicités pour l''orientation, le Gouvernement met à leur disposition un site 
internet, offrant : 
 
1° des informations de qualité sur les études, les filières et les formations 
; 
 
2° des contenus sur les métiers et le marché du travail ; 
 
3° des outils d''aide à l''autoévaluation et d''aide au choix.]10 
 
TITRE V. - De l''autonomie des écoles, de leur pilotage et de la 
participation 
 
CHAPITRE 1er. - De l''autonomie des écoles 
 
Section 1ère. - Du projet éducatif et du projet pédagogique 
 
 
10Chapitre inséré par le D. 16-05-2024 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 65, 'Article 1.', 'Article 1.5.1-1. - Chaque pouvoir organisateur est libre en matière de 
méthodes pédagogiques. 
 
A condition de respecter les prescriptions du présent Code en matière 
d''horaire des élèves et de jours de classe, chaque pouvoir organisateur jouit de 
la liberté d''aménager ses horaires, et sous réserve d''approbation par le 
Gouvernement en vue d''assurer le niveau des études, d''élaborer ses 
programmes.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 66, 'Article 1.', 'Article 1.5.1-2. - Chaque pouvoir organisateur établit son projet éducatif 
et son projet pédagogique. 
 
Le projet éducatif définit, dans le respect des missions prioritaires et 
spécifiques fixées au Titre 4, l''ensemble des valeurs, des choix de société et des 
références à partir desquels un pouvoir organisateur ou une fédération de 
pouvoirs organisateurs détermine ses objectifs éducatifs. 
 
Le projet pédagogique définit les orientations pédagogiques et les choix 
méthodologiques qui permettent à un pouvoir organisateur ou à une fédération 
de pouvoirs organisateurs de mettre en oeuvre son projet éducatif. 
 
Le projet éducatif et le projet pédagogique sont fournis sur demande et 
peuvent faire l''objet d''un document unique. 
 
Chaque pouvoir organisateur tient son projet éducatif et son projet 
pédagogique à la disposition des services du Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 67, 'Article 1.', 'Article 1.5.1-3. - Chaque fédération de pouvoirs organisateurs établit son 
projet éducatif. Elle précise également les axes majeurs du projet pédagogique 
qu''elle entend privilégier. 
 
Il doit y avoir cohérence entre le projet éducatif et pédagogique d''un 
pouvoir organisateur qui a adhéré à une fédération de pouvoirs organisateurs 
et le projet éducatif et pédagogique de ladite fédération. 
 
Section II. - Des programmes d''études');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 68, 'Article 1.', 'Article 1.5.1-4. - § 1er. Les programmes d''études sont de la compétence 
des pouvoirs organisateurs qui peuvent la déléguer à la fédération de pouvoirs 
organisateurs à laquelle ils adhèrent. 
 
Dans l''enseignement officiel subventionné, la durée de la délégation visée 
à l''alinéa 1er ne peut excéder le terme du mandat électif du pouvoir 
organisateur. 
 
Dans l''enseignement libre, la durée de la délégation visée à l''alinéa 1er 
est de six ans renouvelables. 
 
Le Gouvernement détermine les modalités de la délégation. 
 
§ 2. Le Gouvernement approuve les programmes d''études, après avoir 
pris l''avis de la Commission des référentiels et des programmes du tronc 
commun visée à l''article 1.6.2-1 ou d''une commission des programmes visée à 
l''article 1.6.2-4. 
 
 
 
Docu 49466 
 
Code 03-05-2019 
Section III. - Du projet d''école');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 69, 'Article 1.', 'Article 1.5.1-5. -  § 1er. Toute école dispose d''un projet d''école. 
 
Le projet d''école définit les priorités éducatives et pédagogiques et les 
actions concrètes particulières que l''équipe éducative de l''école entend mettre 
en oeuvre en collaboration avec l''ensemble des membres du conseil de 
participation visés à l''article 1.5.3-2, pour réaliser les projets éducatif et 
pédagogique du pouvoir organisateur. 
 
Le projet d''école est un outil pour atteindre les missions prioritaires et les 
missions spécifiques du système éducatif. Il définit les modalités par 
lesquelles, dans le tronc commun, chaque école met en place les pratiques de 
différenciation et l''évaluation formative visées à l''article 2.3.1-1. 
 
Le projet d''école est élaboré en tenant compte: 
1° des élèves inscrits dans l''école, de leurs caractéristiques tant 
culturelles que sociales, de leurs besoins et de leurs ressources dans les 
processus d''acquisition des compétences et savoirs; 
2° des aspirations des élèves et de leurs parents en matière de projet de 
vie et de poursuite des études; 
3° de l''environnement social, culturel et économique de l''école; 
4° de l''environnement naturel, du quartier, de la ville, du village dans 
lesquels l''école est implantée. 
 
Si nécessaire, le projet d''école est adapté afin d''assurer sa cohérence par 
rapport au plan de pilotage, visé à l''article 1.5.2-1. 
 
§ 2. Toute école organisant l''enseignement fondamental, maternel, 
primaire ou le degré inférieur de l''enseignement secondaire définit, dans son 
projet d''école, les moyens qu''elle mettra en oeuvre pour faciliter la transition 
entre l''enseignement maternel et l''enseignement primaire, d''une part, et entre 
les deux dernières années de l''enseignement primaire et le degré inférieur de 
l''enseignement secondaire, d''autre part.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 70, 'Article 1.', 'Article 1.5.1-6. -  § 1er. Tout pouvoir organisateur peut autoriser les 
écoles qu''il organise, dans le cadre de son projet d''école, à aménager l''horaire 
hebdomadaire de façon à mettre en oeuvre des activités, par discipline ou pour 
un ensemble de disciplines, permettant de remplir les missions prioritaires 
définies à l''article 1.4.1-1. 
 
§ 2. Dans le cadre du projet éducatif et du projet pédagogique de son 
pouvoir organisateur, chaque école secondaire peut répartir les volumes 
horaires réservés à une, plusieurs ou toutes les disciplines dans des ensembles 
fonctionnels d''études s''étendant sur plusieurs semaines. 
 
Elle peut aussi regrouper le temps réservé à plusieurs disciplines pour 
des activités interdisciplinaires ou culturelles. 
 
La seule obligation de l''école, lorsqu''elle fait appel à la présente 
disposition, est d''indiquer comment les procédures particulières qu''elle met en 
oeuvre sont de nature à remplir les missions prioritaires visées à l''article 1.4.1-
1 et les savoirs, savoir-faire et compétences définies par les référentiels, dans 
le cadre des programmes d''études adoptés par son pouvoir organisateur. 
 
 
 
Docu 49466 
 
Code 03-05-2019 
A l''exception du cours d''éducation physique, les cours qui comptent un 
volume horaire de moins de trois périodes hebdomadaires peuvent être 
regroupés sur un semestre par année.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 71, 'Article 1.', 'Article 1.5.1-7. - Le projet d''école et ses modifications ultérieures sont 
soumis pour approbation au pouvoir organisateur, dans les délais fixés par le 
Gouvernement. 
 
Dans l''enseignement officiel, le projet d''école est transmis à l''organe local 
de concertation sociale afin d''y vérifier sa conformité au projet éducatif du 
pouvoir organisateur. Les implications éventuelles sur les conditions de travail 
et les situations statutaires des membres du personnel sont négociées au sein 
de l''organe local de concertation sociale. 
 
Section IV. - Du règlement des études');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 72, 'Article 1.', 'Article 1.5.1-8. - § 1er. Tout pouvoir organisateur établit, pour chaque 
niveau d''enseignement, son règlement des études. Il peut prévoir un règlement 
des études distinct pour chacune de ses implantations. 
 
[Le règlement des études définit notamment : 
 
1° les critères d''un travail scolaire de qualité ; 
 
2° les procédures d''évaluation et de délibération des conseils de classe et 
la communication de leurs décisions ; 
 
3° la communication des décisions prises à la suite de la délibération de 
fin d''année et, le cas échéant, de la concertation, aux élèves et à leurs parents ; 
 
4° pour les écoles concernées, le déroulement de la procédure de maintien 
exceptionnel dans le tronc commun]11. 
 
§ 2. Les critères du travail scolaire de qualité définissent, de la manière 
la plus explicite possible, la tâche exigée de l''élève dans le cadre des missions 
prioritaires et spécifiques fixées par le présent Code. 
 
A cet effet, le règlement des études aborde notamment, et de la manière 
appropriée au niveau d''enseignement concerné, les aspects suivants: 
1° les travaux individuels; 
2° les travaux de groupes; 
3° les travaux de recherche; 
4° les leçons collectives; 
5° le travail personnel; 
6° les travaux à domicile; 
7° les moments d''évaluation formelle. 
 
§ 3. Le travail scolaire de qualité implique notamment les exigences 
suivantes: 
 
1° satisfaire volontairement aux demandes institutionnelles en 
respectant: 
 a. les règles fixées par le Pouvoir organisateur et l''équipe éducative; 
 
11 Remplacé par le décret du 20 juillet 2023 
 
 
Docu 49466 
 
Code 03-05-2019 
 b. les horaires; 
 c. les échéances et les délais; 
 d. les consignes données sans exclure le sens critique; 
2° développer une méthode de travail contribuant à la compréhension de 
but des apprentissages, de développer un sentiment d''efficacité personnelle et 
de témoigner de l''intérêt pour les savoirs enseignés; 
3° accepter l''appartenance à un groupe en ce compris: 
 a. le respect des adultes et des autres élèves; 
 b. la capacité à s''intégrer dans une équipe et à œuvrer solidairement à 
l''accomplissement d''une tâche; 
4° participer activement aux activités scolaires en montrant de l''écoute, 
de l''implication, de la prise d''initiative, de l''engagement et du sens des 
responsabilités. 
 
§ 4. Sans préjudice de l''article 2.5.1-1, tout pouvoir organisateur a la 
faculté de prévoir des travaux à domicile pour chaque niveau d''enseignement. 
 
Section V. - Du règlement d''ordre intérieur de l''école');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 73, 'Article 1.', 'Article 1.5.1-9. - Le pouvoir organisateur fixe le règlement d''ordre 
intérieur de l''école s''appliquant aux élèves. Il comprend notamment les règles 
relatives à la vie en commun, aux sanctions disciplinaires, aux procédures de 
recours qui peuvent leur être opposées et aux faits graves visés à l''article 1.7.9-
2. 
 
Section VI. - De l''accès aux écoles');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 74, 'Article 1.', 'Article 1.5.1-10. - Les membres du personnel, les élèves ainsi que les 
membres des centres PMS et du service de promotion de la santé à l''école 
oeuvrant dans les écoles ont accès aux locaux pendant et hors des heures de 
classe, en fonction des nécessités du service et des activités pédagogiques, 
selon les modalités définies par le pouvoir organisateur ou son délégué. 
 
Les parents ont également accès à l''école selon les modalités définies par 
le pouvoir organisateur ou son délégué. 
 
Sauf autorisation expresse du pouvoir organisateur ou de son délégué, les 
parents n''ont pas accès aux locaux où se donnent les cours et les différentes 
activités pédagogiques pendant la durée de ceux-ci.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 75, 'Article 1.', 'Article 1.5.1-11. - § 1er. Dans l''exercice de leurs fonctions, ont également 
accès aux écoles: 
1° les délégués du Gouvernement; 
2° les délégués du pouvoir organisateur pour l''enseignement qu''il 
organise; 
3° les inspecteurs et vérificateurs dument désignés à cet effet par la 
Communauté française; 
4° les délégués au contrat d''objectifs, les directeurs de zone et le délégué 
coordonnateur; 
5° les inspecteurs et délégués des différents services de l''Etat chargés des 
inspections en matière de santé publique et de respect de la législation du 
travail; 
6° le bourgmestre et ses délégués en matière de prévention des incendies; 
 
 
Docu 49466 
 
Code 03-05-2019 
7° les officiers de police judiciaire, les officiers du Ministère public, les 
services de police dument munis d''un mandat d''amener, d''un mandat d''arrêt 
ou d''un mandat de perquisition ou dans les cas de flagrant crime ou délit; 
8° le personnel médical et infirmier dont l''intervention a été demandée. 
 
Hors le cas d''urgence ou de flagrant crime ou délit, toute personne visée 
à l''alinéa 1er se présente préalablement auprès du directeur ou de son délégué 
et en annonçant explicitement l''objet de sa visite. 
 
§ 2. Dans l''enseignement de caractère non confessionnel, les chefs de 
culte et leurs délégués ont accès de droit aux locaux où se donnent les cours de 
religion, pendant la durée de ceux-ci. 
 
Ils se présentent d''abord au directeur ou à son délégué. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 76, 'Article 1.', 'Article 1.5.1-12. - § 1er. Toute personne qui ne se trouve pas dans les 
conditions des articles 1.5.1-10 à 1.5.1-11 doit solliciter préalablement du 
directeur d''école ou de son délégué l''autorisation de pénétrer dans les locaux. 
 
§ 2. Toute personne s''introduisant dans les locaux d''une école contre la 
volonté du directeur ou de son délégué, soit à l''aide de menaces ou de violences 
contre les personnes, soit au moyen d''effraction, d''escalade ou de fausses clés 
est passible des sanctions prévues à l''article 439 du Code pénal. 
 
§ 3. Lors des journées portes ouvertes, les écoles perdent la protection 
accordée à leur qualité de domicile. 
 
CHAPITRE II. - Du pilotage des écoles 
 
Section Ière. - Du plan de pilotage et des contrats d''objectifs 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 77, 'Article 1.', 'Article 1.5.2-1. - Chaque école est tenue d''élaborer un plan de pilotage, 
en cohérence avec son projet d''école, qui constituera, au terme du processus de 
contractualisation visé à l''article 1.5.2-5, son contrat d''objectifs pour une 
période de six ans. Les écoles peuvent, dans leur plan de pilotage, distinguer 
des objectifs spécifiques par implantation. Les plans de pilotage doivent être 
élaborés selon les éléments et les modalités que le Gouvernement détermine. 
 
[Les plans de pilotage sont transmis, pour la première fois, au délégué au 
contrat d''objectifs entre le 1er janvier et le 30 avril de l''année qui suit l''année 
de création de l''école.]12 
 
[Les écoles qui ont déjà conclu un contrat d''objectifs remettent leur plan 
de pilotage au délégué au contrat d''objectifs entre 65 et 110 jours ouvrables 
scolaires après la réception du rapport d''évaluation finale de la mise en œuvre 
du contrat d''objectifs réalisé par le délégué au contrat d''objectifs.]13 
 
Modifié par D. 24-02-2022 ; D. 20-07-2022 
 
12Remplacé par le D. 18-04-2024 
13Inséré par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 78, 'Article 1.', 'Article 1.5.2-2. - Dans le cadre de l''élaboration des plans de pilotage et 
de la contractualisation de ceux-ci en contrats d''objectifs, les écoles 
poursuivent les objectifs d''amélioration permettant au système éducatif: 
1° d''améliorer significativement les savoirs, les savoir-faire et les 
compétences des élèves; 
2° d''augmenter la part des jeunes diplômés de l''enseignement secondaire 
supérieur; 
3° de réduire les différences entre les résultats des élèves les plus 
favorisés et ceux des élèves les moins favorisés d''un point de vue socio-
économique; 
4° de réduire progressivement le redoublement et le décrochage; 
5° de réduire les changements d''école au sein du tronc commun; 
6° d''augmenter progressivement l''inclusion des élèves à besoins 
spécifiques dans l''enseignement ordinaire; 
7° d''accroitre les indices du bien-être à l''école et de l''amélioration du 
climat scolaire. 
 
Les indicateurs et valeurs de référence liés à ces objectifs sont annexés 
au présent Code. 
 
Le Gouvernement peut, au besoin, fixer des objectifs particuliers pour 
certaines catégories d''écoles en tenant compte du niveau d''enseignement, du 
type d''école et des spécificités des zones auxquelles ces écoles sont rattachées, 
notamment en vue de renforcer la mixité sociale. 
 
Les catégories d''écoles visées à l''alinéa 3 peuvent notamment concerner: 
1° les écoles dont une ou plusieurs implantations bénéficient de 
l''encadrement différencié; 
2° […] Abrogé par D. 20-07-2022; 
3° les écoles organisant un apprentissage par immersion, tel que défini à 
l''article 1.3.1-1, 2°; 
4° les écoles organisant le degré inférieur de l''enseignement secondaire 
ordinaire; 
5° les écoles organisant l''enseignement spécialisé. 
 
Le Gouvernement veille à la cohérence générale des objectifs que se fixent 
les écoles, au regard de leur situation de départ, par rapport aux objectifs 
d''amélioration du système éducatif. Le Gouvernement évalue annuellement 
l''atteinte des objectifs d''amélioration visés à l''alinéa 1er et, le cas échéant, des 
objectifs particuliers visés à l''alinéa 3 et en fait rapport au Parlement. 
 
Complété par D. 17-06-2021 ; modifié par D. 24-02-2022 ; D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 79, 'Article 1. (partie 1)', 'Article 1.5.2-3. - § 1er. Le plan de pilotage de chaque école est établi dans le cadre des objectifs d''amélioration du système éducatif et, le cas échéant, des objectifs particuliers, et comprend notamment les éléments suivants: 1° les objectifs spécifiques à atteindre par l''école pour contribuer aux objectifs d''amélioration, et le cas échéant, aux objectifs particuliers; 2° un diagnostic collectif établi par le directeur, en collaboration avec l''équipe éducative de l''école, et reprenant les forces et faiblesses de l''école au regard des objectifs d''amélioration et, le cas échéant, des objectifs particuliers ainsi que leurs causes. Ce diagnostic est établi en tenant compte des indicateurs propres à la situation de l''école transmis par les services du Gouvernement au directeur et au pouvoir organisateur de l''école, sans préjudice d''autres éléments que l''école est libre de développer. La catégorisation des indicateurs est fixée par le Gouvernement. Sans préjudice des éléments de diagnostic présentés, à l''occasion de la présentation du plan Docu 49466 Code 03-05-2019 de pilotage aux organes locaux de concertation sociale et au conseil de participation visé à l''article 1.5.3-1, ce diagnostic, à l''usage exclusif et confidentiel de l''équipe éducative, du directeur, des services du Gouvernement et du pouvoir organisateur concerné ne peut faire l''objet d''aucune communication à des tiers à l''école, sauf, le cas échéant, à la fédération de pouvoirs organisateurs à laquelle l''école est affiliée ou avec laquelle elle est conventionnée ou dans les cas fixés par le Gouvernement, notamment pour des fins académiques ou scientifiques. Les destinataires de ce document sont soumis à une obligation de confidentialité; 3° une annexe détaillant, selon les modalités fixées par le Gouvernement, les valeurs de référence chiffrées annuelles et pluriannuelles que l''école se propose d''atteindre sur la base de sa situation, pour chacun de ses objectifs spécifiques pour lesquels il existe un indicateur quantitatif. Cette annexe, à l''usage exclusif de l''équipe éducative, du directeur, des services du Gouvernement et du pouvoir organisateur concerné, ne peut faire l''objet d''aucune communication à des tiers à l''école, sauf, le cas échéant, à la fédération de pouvoirs organisateurs à laquelle l''école est affiliée ou avec laquelle elle est conventionnée ou dans les cas fixés par le Gouvernement, notamment pour des fins académiques ou scientifiques. Les destinataires de ce document sont soumis à une obligation de confidentialité; 4° les modalités du travail collaboratif de l''ensemble de l''équipe éducative de l''école permettant notamment l''élaboration du plan de pilotage et la mise en oeuvre du contrat d''objectifs; [modifié par D. 24-02-2022] 5° le plan de formation visé par l''article 6.1.4-1; [remplacé par D. 17-06-2021] 6° les modalités de la mise en oeuvre du continuum pédagogique visant, tout au long du tronc commun, à assurer à tous les élèves les compétences initiales et les savoirs, les savoir-faire et les compétences du référentiel du tronc commun nécessaires à leur épanouissement personnel, à leur insertion sociale et à la poursuite de leurs études, dans la mesure et au rythme suivant lesquels l''école est concernée, y compris les modalités de la différenciation des apprentissages et de l''accompagnement personnalisé [ainsi que les modalités de l''approche éducative de l''orientation, y compris les types d''activités et les partenariats de l''équipe éducative avec les partenaires concernés]14; 7° les stratégies à mettre en place par l''école pour atteindre les objectifs spécifiques visés au 1°; 8° le mode d''évaluation annuelle du contrat d''objectifs a opérer par l''école, sans préjudice de l''article 1.5.2-9 ; 9° pour les écoles sièges d''un pôle territorial, l''annexe relative au pôle territorial visée à l''article 6.2.4-1. [Inséré par D. 17-06-2021] § 2. Dans le cadre de l''élaboration des stratégies visées au paragraphe 1er, 7°, l''école identifie parmi les thématiques suivantes celles qui nécessitent des actions nouvelles à mettre en oeuvre prioritairement: 1° les actions pédagogiques déployées pour conduire chaque élève vers la réussite et lui permettre de maitriser les apprentissages et d''atteindre les objectifs attendus, y compris les modalités d''évaluation de l''acquisition des savoirs, savoir-faire et compétences; 2° les dispositifs d''accrochage scolaire; 3° les dispositifs d''adaptation et d''encadrement spécifiques, dont ceux à destination des primo-arrivants; 4° les aménagements raisonnables pour les élèves à besoins spécifiques reconnus ainsi que l''intégration des élèves dans l''enseignement ordinaire, conformément aux dispositions du Chapitre X du décret du 3 mars 2004 organisant l''enseignement spécialisé; 14Inséré par le D. 16-05-2024 Docu 49466 Code 03-05-2019 5° l''orientation des élèves et la promotion des outils d''orientation tout au long du parcours de chaque élève; 6° la promotion de la citoyenneté, de la santé, de l''éducation aux mé');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 80, 'Article 1. (partie 2)', 'de l''environnement et du développement durable; 7° la prévention et la prise en charge des discriminations et des violences au sein de l''école, y compris des dispositifs spécifiques concernant le harcèlement, le cyber harcèlement et les évènements d''exception ainsi que les partenariats avec les services de l''Aide à la jeunesse [et du service intégré d''assistance aux écoles visé à l''article 1.7.11-2]15; 8° l''insertion des outils numériques dans les apprentissages et la gouvernance de l''école, ainsi que l''équipement numérique; 9° l''accueil et l''accompagnement des nouveaux enseignants; 10° le partenariat et la collaboration avec les parents des élèves de l''école, en concertation avec le conseil de participation; 11° l''apprentissage et l''accès à la culture et à la lecture ainsi que les collaborations nouées avec les institutions culturelles et les institutions de lecture publique de la zone; 12° l''apprentissage et l''accès aux sports ainsi que les collaborations avec les institutions sportives de la zone; 13° en cas d''offre d''enseignement qualifiant, les partenariats noués avec les entreprises et employeurs du secteur concerné; 14° la maintenance et l''amélioration des infrastructures scolaires; 15° la politique de l''école en matière de frais scolaires. L''école décrit par ailleurs les actions existantes qu''elle continue à mettre en oeuvre dans le cadre de chacune de ces thématiques en tenant compte du contexte spécifique de l''école, du projet d''école, des lignes directrices fixées par le pouvoir organisateur et des moyens disponibles. Les catégories d''écoles visées à l''article 1.5.2-2, alinéa 4, précisent, chacune pour ce qui la concerne, par quelles actions concrètes et avec quelles ressources seront atteints les objectifs visés par: 1° l''article 2 du décret du 30 avril 2009 organisant un encadrement différencié au sein des établissements scolaires de la Communauté française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans un environnement pédagogique de qualité, en développant notamment les actions des thématiques 1°, 2° et 7°, pour les écoles dont une ou plusieurs implantations bénéficient de l''encadrement différencié; elles détaillent également l''affectation des moyens de fonctionnement et des moyens humains octroyés dans le cadre et le respect du décret précité; 2° […] Abrogé par D. 20-07-2022 3° l''article 1.8.3-1, en développant notamment les stratégies 1° et 8°, pour les écoles organisant l''apprentissage par immersion; 4° l''article 1.5.2-3, § 3, en développant notamment les actions de la thématique 1° visée à l''article 1.5.2-3, § 1er, pour les écoles organisant le degré inférieur de l''enseignement secondaire; 5° le Chapitre X du décret du 3 mars 2004 organisant l''enseignement spécialisé, en développant notamment les actions de la thématique 4° visées à l''article 1.5.2-3, § 1er, pour les écoles organisant l''enseignement spécialisé. § 3. Dans le cadre de son plan de pilotage, chaque école organisant le degré inférieur de l''enseignement secondaire ordinaire définit les actions et dispositifs spécifiques à mettre en place par l''équipe éducative, en articulation 15Remplacé par le D. 16-05-2024 Docu 49466 Code 03-05-2019 avec l''équipe du centre PMS, permettant aux élèves d''atteindre les attendus visés au terme du tronc commun. Modifié par D. 24-02-2022 ; D. 31-03-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 81, 'Article 1.', 'Article 1.5.2-4. -  Le plan de pilotage est établi par le directeur, en 
collaboration avec l''équipe éducative de l''école et en concertation, le cas 
échéant, avec les équipes du centre PMS et les représentants des parents de 
l''école, en tenant compte du contexte spécifique de l''école, du projet d''école, des 
lignes directrices fixées par le pouvoir organisateur et des moyens disponibles. 
 
La cellule de soutien et d''accompagnement offre son appui à l''école pour 
l''élaboration du plan de pilotage, son adaptation, le cas échéant, et la mise en 
oeuvre du contrat d''objectifs. A cette fin, une convention d''accompagnement et, 
s''il échet, de suivi, est établie, dans l''enseignement organisé par la 
Communauté française, entre le directeur et le service de soutien et 
d''accompagnement et, dans l''enseignement subventionné, entre le pouvoir 
organisateur et la fédération de pouvoirs organisateurs à laquelle l''école est 
affiliée ou avec laquelle elle est conventionnée. 
 
Moyennant l''accord du pouvoir organisateur concerné, les services du 
Gouvernement communiquent aux fédérations de pouvoirs organisateurs ou 
au pouvoir organisateur de l''enseignement organisé par la Communauté 
française les indicateurs visés à l''article 1.5.2-3, § 1er, 2°, qui concernent des 
écoles qui leur sont affiliées ou conventionnées. Les indicateurs communiqués 
visent à permettre à chaque fédération de pouvoirs organisateurs et au pouvoir 
organisateur de l''enseignement organisé par la Communauté française de 
disposer des informations nécessaires au soutien de l''école dans le cadre de 
l''élaboration du plan de pilotage, à son accompagnement et, le cas échéant, à 
son suivi. Il est interdit de faire état de ces indicateurs à des tiers sauf dans 
les cas déterminés par le Gouvernement. 
 
Le plan de pilotage est présenté, par le directeur, selon les conditions de 
forme fixées par le Gouvernement, par l''intermédiaire de l''application élaborée 
par l’ETNIC, au délégué au contrat d''objectifs, après avis des organes locaux 
de concertation sociale et du conseil de participation, recueillis dans le respect 
des règles de confidentialité prévues à l''article 1.5.2-3, § 1er, et après 
l''approbation du pouvoir organisateur. Le Gouvernement arrête les règles 
d''accès à cette application. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 82, 'Article 1. (partie 1)', 'Article 1.5.2-5. - § 1er. [Dans un délai de 50 jours calendrier suivis de 10 jours ouvrables scolaires après le dépôt du plan de pilotage]16, le délégué au contrat d''objectifs analyse, après concertation avec le directeur et le pouvoir organisateur, l''adéquation du plan de pilotage aux objectifs d''amélioration et, le cas échéant, aux objectifs particuliers visés à l''article 1.5.2-2 et sa conformité aux articles 1.5.2-1 à 1.5.2-4, selon la procédure et les modalités définies par le Gouvernement. L''analyse de l''adéquation du plan de pilotage de l''école aux objectifs d''amélioration et, le cas échéant, aux objectifs particuliers visés à l''article 1.5.2-2 consiste en la détection de l''existence d''une éventuelle erreur manifeste d''appréciation dans la fixation des objectifs spécifiques que contient le plan de pilotage de l''école eu égard aux objectifs d''amélioration et, le cas échéant aux 16Remplacé par le D. 18-04-2024 Docu 49466 Code 03-05-2019 objectifs particuliers visés à l''article 1.5.2-2, ou dans les stratégies définies pour les mettre en oeuvre. Pour réaliser cette analyse, le délégué au contrat d''objectifs peut entre autres rencontrer le pouvoir organisateur, le directeur, l''équipe éducative de l''école, les représentants des parents, les représentants des organes locaux de concertation sociale et, pour l''enseignement secondaire, les représentants des élèves. § 2. Si à l''issue de cette analyse le plan de pilotage est approuvé, il est renvoyé à l''école signé par le directeur de zone et contresigné par le délégué au contrat d''objectifs dans le délai visé au paragraphe 1er, alinéa 1er, et selon les modalités fixées par le Gouvernement. Il constitue dès lors le contrat d''objectifs de l''école. Il est conclu entre le pouvoir organisateur et le Gouvernement. Il est contresigné par le directeur de l''école en fonction au moment de la signature du contrat. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. Dans les cas exceptionnels où le délégué au contrat d''objectifs n''a pas respecté le délai visé au paragraphe 1er, alinéa 1er, l''analyse de l''adéquation du plan de pilotage telle que visée au paragraphe 1er est réalisée par le directeur de zone qui dispose de 20 jours calendrier complémentaires. § 3. Si le plan de pilotage n''est pas jugé en adéquation avec les objectifs d''amélioration et, le cas échéant, avec les objectifs particuliers visés à l''article 1.5.2-2 ou n''a pas été établi conformément aux articles 1.5.2-1 à 1.5.2-4 et à leurs arrêtés d''exécution, le délégué au contrat d''objectifs émet des recommandations motivées à l''attention du directeur et du pouvoir organisateur afin que le plan de pilotage soit adapté. Les recommandations formulées s''inscrivent dans le respect de la liberté du pouvoir organisateur en matière de méthodes pédagogiques. Le directeur, en collaboration avec l''équipe éducative de l''école et en concertation, le cas échéant, avec le délégué au contrat d''objectifs et avec les équipes du centre PMS et les représentants des parents, adapte le plan de pilotage. Il le soumet pour avis aux organes locaux de concertation sociale et au conseil de participation et à l''approbation du pouvoir organisateur. Le plan de pilotage adapté est renvoyé au délégué au contrat d''objectifs dans un délai de 40 jours ouvrables scolaires à partir de la notification des recommandations du délégué au contrat d''objectifs, aux fins d''une nouvelle analyse de son adéquation aux objectifs visés à l''article 1.5.2-2 et de sa conformité aux articles 1.5.2-1 à 1.5.2-4 et à leurs arrêtés d''exécution. Le délégué au contrat d''objectifs dispose ensuite de [11 jours calendrier suivis de 10 jours ouvrables scolaires]17 pour procéder à une nouvelle analyse de l''adéquation du plan de pilotage aux objectifs visés à l''article 1.5.2-2 et de sa conformité aux articles 1.5.2-1 à 1.5.2-4 et à leurs arrêtés d''exécution. Dans le cadre de cette analyse, le délégué au contrat d''objectifs peut rencontrer le pouvoir organisateur, le directeur, l''équipe éducative de l''école, les représentants des parents, les représentants des organes locaux de 17Remplacé par le D. 18-04-2024 Docu 49466 Code 03-05-2019 concertation sociale et, pour l''enseignement secondaire, les représentants des élèves. S''il est approuvé, il est renvoyé à l''école signé par le directeur de zone et contresigné par le délégué au contrat d''objectifs. Il constitue dès lors le contrat d''objectifs de l''école. Il est conclu entre le pouvoir organisateur et le Gouvernement. Il est contresigné par le directeur de l''école en fonction au moment de la signature du contrat. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. Modifié par D. 31-03-2022 (1)');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 83, 'Article 1.', 'Article 1.5.2-6. - Dans le respect des règles de confidentialité prévues à 
l''article 1.5.2-3, § 1er, le directeur présente le contrat d''objectifs: 
1° à l''équipe éducative de l''école; 
2° aux équipes du centre PMS, si ces équipes ont participé à son 
élaboration; 
3° à la cellule de soutien et d''accompagnement, si cette cellule a participé 
à son élaboration; 
4° aux organes locaux de concertation sociale; 
5° au conseil de participation visé à l''article 1.5.3-1 et suivants. 
 
Le contrat d''objectifs est mis en oeuvre au plus tard [dans les 120 jours 
calendrier suivant la signature de celui-ci. Dans le respect de ce délai, le 
premier jour de la mise en œuvre du contrat d''objectif coïncide avec le premier 
jour ouvrable scolaire qui suit une des périodes de vacances visées à l''article 
19.1-1, §2.]18');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 84, 'Article 1.', 'Article 1.5.2-7. - En cas de désaccord persistant entre une école et le 
délégué au contrat d''objectifs à propos de l''appréciation de ce dernier sur 
l''adéquation d''un plan de pilotage avec les objectifs d''amélioration et, le cas 
échéant, avec les objectifs particuliers visés à l''article 1.5.2-2 ou sur sa 
conformité aux articles 1.5.2-1 à 1.5.2-4 et à leurs arrêtés d''exécution, l''école 
peut saisir, sur la base d''une demande motivée, une instance collégiale 
composée du Délégué coordonnateur et du directeur de zone concerné dans le 
délai prévu pour l''adaptation du plan de pilotage. Le cas échéant, cette 
instance peut adapter les recommandations du délégué au contrat d''objectifs 
et prolonger le délai laissé à l''école pour s''y conformer. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 85, 'Article 1.', 'Article 1.5.2-8.  - En cas de refus ou d''incapacité de l''école à établir un 
plan de pilotage, un processus de suivi rapproché est mis en place par le 
délégué au contrat d''objectifs. 
 
Dans ce cadre, une procédure d''audit externe peut être réalisée par le 
Service général de l''inspection selon les modalités fixées par le Gouvernement, 
à la demande du directeur de zone ou du pouvoir organisateur. Sur la base des 
résultats de l''audit, le plan de pilotage est établi par l''école, le cas échéant en 
concertation avec le délégué au contrat d''objectifs conformément aux articles 
précédents. Dans cette hypothèse, une fois le contrat d''objectifs approuvé, dans 
le cas où le suivi rapproché se prolonge après la contractualisation, le délégué 
au contrat d''objectifs revient annuellement dans l''établissement pour évaluer 
sa mise en oeuvre. A défaut pour l''école de respecter ce processus de suivi, la 
procédure visée à l''article 1.5.2-11 est initiée par le directeur de zone. 
 
18Remplacé par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 86, 'Article 1. (partie 1)', 'Article 1.5.2-9. - § 1er. Le contrat d''objectifs fait l''objet d''une évaluation intermédiaire après trois années d''exécution et est modifié, si nécessaire, conformément au paragraphe 2. Il fait aussi l''objet d''une évaluation finale au cours de sa sixième année d''exécution. Ces évaluations sont réalisées par le délégué au contrat d''objectifs, selon les modalités fixées par le Gouvernement. Les évaluations portent sur la mise en oeuvre des stratégies et sur leur efficacité en regard des objectifs spécifiques fixés, à la lumière notamment des valeurs chiffrées mentionnées dans l''annexe visée à l''article 1.5.2-3, § 1er, 3°. Pour ce faire, le délégué au contrat d''objectifs peut entre autres rencontrer le pouvoir organisateur, le directeur, l''équipe éducative, les représentants des parents, les représentants des organes locaux de concertation sociale et les délégués des élèves. Les évaluations sont motivées par le délégué au contrat d''objectifs et s''inscrivent dans le respect de la liberté du pouvoir organisateur en matière de méthodes pédagogiques. § 2. Lorsque l''évaluation intermédiaire visée au paragraphe 1er révèle que la mise en oeuvre du contrat d''objectifs ne permet pas de rencontrer ses objectifs, lorsque les objectifs particuliers visés à l''article 1.5.2-2 ont été adaptés par le Gouvernement ou lorsque les moyens disponibles visés à l''article 1.5.2-4, alinéa 1er, ont évolué, le directeur propose une modification de ce contrat dans les 75 jours ouvrables scolaires de la notification de l''évaluation intermédiaire. La modification proposée est élaborée en collaboration avec l''équipe éducative et en concertation, le cas échéant, avec les équipes du centre PMS, avec le délégué au contrat d''objectifs et avec les représentants des parents. Elle est soumise à l''avis des organes locaux de concertation sociale et du conseil de participation et à l''approbation du pouvoir organisateur. Pour la modification du contrat d''objectifs et son suivi, la cellule de soutien et d''accompagnement [offre]19 son appui à l''école. [Dans les 20 jours calendrier suivis de 10 jours ouvrables scolaires]20 du dépôt de la proposition de modification du contrat d''objectifs, le délégué au contrat d''objectifs analyse cette modification avec le directeur et le pouvoir organisateur. S''il estime cette modification conforme aux objectifs d''amélioration et, le cas échéant, aux objectifs particuliers visés à l''article 1.5.2-2, il soumet le contrat d''objectifs modifié à la signature du directeur de zone. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. Si la proposition de modification du contrat d''objectifs n''est pas jugée en adéquation aux objectifs d''amélioration du système éducatif et, le cas échéant, aux objectifs particuliers visés à l''article 1.5.2-2, le délégué au contrat d''objectifs émet des recommandations motivées à l''attention du directeur et du pouvoir organisateur afin que le contrat d''objectifs soit adapté. Les 19Remplacé par le D. 18-04-2024 20Remplacé par le D. 18-04-2024 Docu 49466 Code 03-05-2019 recommandations formulées s''inscrivent dans le respect de la liberté du pouvoir organisateur en matière de méthodes pédagogiques. Le directeur, en collaboration avec l''équipe éducative et en concertation, le cas échéant, avec les équipes du centre PMS, adapte la proposition de modification du contrat d''objectifs. Il la soumet pour avis aux organes locaux de concertation sociale et au conseil de participation et à l''approbation du pouvoir organisateur. La proposition de modification du contrat d''objectifs adaptée est renvoyée au délégué au contrat d''objectifs dans un délai de 40 jours ouvrables scolaires à partir de la notification des recommandations du délégué au contrat d''objectifs. Le délégué au contrat d''objectifs dispose ensuite de [11 jours calendrier suivis de 10 jours ouvrables scolaires]21 pour procéder à une nouvelle analyse de son adéquation aux objectifs visés à l''article 1.5.2-2. S''il estime cette modification conforme aux objectifs d''amélioration et, le cas échéant, aux objectifs particuliers visés à l''article 1.5.2-2, il soumet le contrat d''objectifs modifié à la signature du directeur de zone. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. § 3. En cas de désaccord persistant entre une école et le délégué au contrat d''objectifs sur l''évaluation d''un contrat d''objectifs, l''école peut saisir, sur la base d''une demande motivée, une instance collégiale composée du Délégué coordonnateur et du directeur de zone concerné dans le délai prévu pour l''adaptation du contrat d''objectifs. Le cas échéant, cette instance peut adapter les recommandations du délégué au contrat d''objectifs et prolonger le délai laissé à l''école pour s''y conformer. Modifié pa');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 87, 'Article 1.', 'Article 1.5.2-10. - Lorsque l''évaluation intermédiaire visée à l''article 
1.5.2-9 révèle une mauvaise volonté manifeste de mettre en oeuvre le contrat 
d''objectifs ou une incapacité manifeste à atteindre les objectifs y visés [ou en 
cas de refus ou d''incapacité de l''école à modifier son contrat d''objectifs]22, un 
processus de suivi rapproché de la mise en oeuvre du contrat d''objectifs est mis 
en place par le délégué au contrat d''objectifs. 
 
Le délégué au contrat d''objectifs revient annuellement dans l''école pour 
évaluer la mise en oeuvre du contrat d''objectifs. 
 
Dans ce cadre, une procédure d''audit externe peut être réalisée par le 
Service général de l''inspection selon les modalités fixées par le Gouvernement, 
à la demande du directeur de zone ou du pouvoir organisateur. Sur la base des 
résultats de l''audit, le directeur de zone peut également approuver une 
modification du contrat d''objectifs, après concertation entre le délégué au 
contrat d''objectifs, le directeur et le pouvoir organisateur. 
 
A cette fin, le directeur, en collaboration avec l''équipe éducative et en 
concertation, le cas échéant, avec les équipes du centre PMS et avec le délégué 
au contrat d''objectifs, propose la modification du contrat d''objectifs. Il la 
soumet pour avis aux organes locaux de concertation sociale et au conseil de 
 
21Remplacé par le D. 18-04-2024 
22Inséré par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
participation et à l''approbation du pouvoir organisateur. Au besoin, la lettre 
de mission du directeur est modifiée conformément aux articles 26 et 27 du 
décret du 2 février 2007 fixant le statut des directeurs et des directrices dans 
l''enseignement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 88, 'Article 1.', 'Article 1.5.2-11. - § 1er. Dans les cas où un contrat d''objectifs ne peut 
être modifié en application de l''article 1.5.2-9, § 2, et/ou si un processus de 
suivi, tel que visé à l''article 1.5.2-8 ou 1.5.2-10, ne peut être mis en place ou 
n''est pas respecté par l''école ou par le pouvoir organisateur, le directeur de 
zone adresse un courrier recommandé avec accusé de réception au pouvoir 
organisateur, lui enjoignant ou de modifier le contrat d''objectifs ou de respecter 
le processus de suivi dans un délai de 30 jours ouvrables scolaires. Une copie 
de ce courrier est adressée pour information à la fédération de pouvoirs 
organisateurs concernée. 
 
§ 2. A défaut pour le pouvoir organisateur d''y satisfaire, le Gouvernement 
peut décider de réduire de 5 %, au plus, pour l''enseignement organisé par la 
Communauté française, les dotations de fonctionnement visées à l''article 3 de 
la loi du 29 mai 1959 modifiant certaines dispositions de la législation de 
l''enseignement ou, pour l''enseignement subventionné, les subventions de 
fonctionnement de l''école visées à l''article 32 de la loi du 29 mai 1959 susvisée. 
 
Préalablement à toute décision de réduction des dotations ou des 
subventions de fonctionnement, le Gouvernement adresse une lettre de mise 
en demeure au pouvoir organisateur en l''invitant à faire connaitre ses 
observations par écrit uniquement. Celui-ci dispose d''un délai de trente jours 
ouvrables scolaires, à compter de la notification postale par envoi recommandé 
avec accusé de réception de cette mise en demeure, pour faire valoir ses 
observations. 
La 
réduction 
des 
dotations 
ou 
des 
subventions 
de 
fonctionnement court à compter de la notification de la décision du 
Gouvernement jusqu''à ce que le pouvoir organisateur collabore à l''élaboration 
ou à la bonne mise en oeuvre du contrat d''objectifs. 
 
§ 3. Lorsque le Gouvernement prononce une décision de réduction des 
dotations ou des subventions de fonctionnement et à défaut pour l''école d''avoir 
apporté la preuve qu''elle a satisfait à l''injonction du Gouvernement dans un 
délai de six mois à compter de la notification de la décision visée au paragraphe 
2, alinéa 2, le Gouvernement supprime, dans l''enseignement organisé par la 
Communauté française, les traitements et dotations de fonctionnement visées 
à l''article 3 de la loi du 29 mai 1959 modifiant certaines dispositions de la 
législation de l''enseignement ou, dans l''enseignement subventionné par la 
Communauté française, les subventions-traitements et les subventions de 
fonctionnement visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 
susvisée.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 89, 'Article 1. (partie 1)', 'Article 1.5.2-12. - § 1er. Le Gouvernement peut toutefois, sur la base des observations écrites visées à l''article 1.5.2-11, § 2, alinéa 2, en lieu et place de cette réduction, enjoindre au pouvoir organisateur de désigner un manager de crise. A cet effet, le Gouvernement lui adresse un courrier recommandé avec accusé de réception en lui enjoignant de désigner un manager de crise dans un délai de 30 jours calendrier. Dans l''enseignement subventionné, le pouvoir organisateur peut, pour la désignation du manager de crise, habiliter la fédération de pouvoirs Docu 49466 Code 03-05-2019 organisateurs à laquelle il est affilié si les statuts de celle-ci ou la résolution d''adhésion à celle-ci contiennent une telle habilitation ou si le pouvoir organisateur a fourni cette habilitation par écrit, mentionnant la fédération de pouvoirs organisateurs à laquelle le pouvoir organisateur est affilié. Dans ce cas, une copie du courrier enjoignant au pouvoir organisateur de désigner un manager de crise est adressée pour information à cette fédération de pouvoirs organisateurs. Le manager de crise est désigné selon les règles qui sont propres au pouvoir organisateur ou, le cas échéant, à la fédération de pouvoirs organisateurs habilitée à cet effet, et à leur charge. Si le pouvoir organisateur ou, le cas échéant, sa fédération de pouvoirs organisateurs si celle-ci est habilitée à le faire, ne désigne pas un manager de crise dans le délai de 30 jours prévu à l''alinéa 2, le Gouvernement lui adresse une mise en demeure par laquelle il l''invite à procéder à cette désignation dans un délai de quinze jours calendrier à compter de la notification postale par envoi recommandé avec accusé de réception de cette mise en demeure. Si, à l''échéance de ce délai de quinze jours calendrier, le pouvoir organisateur ou, le cas échéant, la fédération de pouvoirs organisateurs si elle est habilitée à le faire, n''a pas apporté la preuve de la désignation d''un manager de crise, le Gouvernement supprime, dans l''enseignement organisé par la Communauté française, les traitements et dotations de fonctionnement visées à l''article 3 de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement ou, dans l''enseignement subventionné par la Communauté française, les subventions-traitements et les subventions de fonctionnement visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 susvisée. § 2. Le manager de crise est désigné, pour une ou plusieurs périodes dont la durée est concertée avec le directeur de zone, avec un maximum de 36 mois. L''organe local de concertation sociale et le conseil de participation sont informés de la désignation du manager de crise préalablement à son entrée en fonction. Dans le cadre de l''exécution de sa mission, le manager de crise analyse la situation de l''école sur la base du rapport d''évaluation intermédiaire visé à l''article 1.5.2-9, de l''évaluation de l''évolution du processus de suivi rapproché et de l''audit externe visés aux articles 1.5.2-8 et 1.5.2-10. Il formule des propositions, après consultation du directeur, de l''équipe éducative de l''école, et le cas échéant, des équipes du centre PMS en vue de rencontrer les objectifs du contrat d''objectifs ou de modifier celui-ci. Il en informe les organes locaux de concertation sociale et le conseil de participation. Il soumet ces propositions pour approbation au pouvoir organisateur. Sur la base de ces propositions, le contrat d''objectifs fait l''objet, le cas échéant, d''une proposition en vue de sa modification par le pouvoir organisateur, en concertation avec le manager de crise. Cette proposition de modification est adressée au directeur de zone. S''il l''approuve, elle fait partie intégrante du contrat d''objectifs de l''école. Au Docu 49466 Code 03-05-2019 besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. Le manager de crise met en oeuvre le contrat d''objectifs en collaboration avec le directeur, l''équipe éducative de l''école, le pouvoir organisateur et, le cas échéant, les équipes du centre PMS, dans le cadre d''un processus de suivi rapproché tel que visé à l''article 1.5.2-10. § 3. Le directeur de zone et le délégué au contrat d''objectifs évaluent au plus tard un mois avant l''échéance de la fin de la mission du manager de crise l''accomplissement et le résultat de cette mission en concertation avec le pouvoir organisateur et, le cas échéant, sa fédération de pouvoirs organisateurs habilitée à cet effet si celle-ci a désigné le manager de crise. Au terme de cette évaluation, le directeur de zone communique au Gouvernement, après consultation du pouvoir organisateur et, le cas échéant, de sa fédération de pouvoirs organisateurs si elle a participé au processus de désignation du manager de crise, un rapport au terme duquel il conclut à la mise en oeuvre satisfaisante ou insatisfaisante du contrat d''objectifs');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 90, 'Article 1. (partie 2)', 'Lorsque le rapport conclut à la mise en oeuvre insatisfaisante du contrat d''objectifs, le Gouvernement supprime, dans l''enseignement organisé par la Communauté française, les traitements et dotations de fonctionnement visées à l''article 3 de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement ou, dans l''enseignement subventionné par la Communauté française, les subventions-traitements et les subventions de fonctionnement visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 susvisée. Préalablement à cette décision de suppression du financement des traitements et dotations ou des subventions, le Gouvernement adresse une lettre de mise en demeure au pouvoir organisateur en l''invitant à faire connaitre ses observations par écrit uniquement. Celui-ci dispose d''un délai de trente jours ouvrables scolaires, à compter de la notification postale par envoi recommandé avec accusé de réception de cette mise en demeure, pour faire valoir ses observations. § 4. Le directeur concerné conserve, durant la période de désignation du manager de crise, le bénéfice de sa désignation en qualité de directeur à titre temporaire ou de sa désignation en qualité de directeur admis au stage ou de sa nomination ou de son engagement à titre définitif en tant que directeur ainsi que de sa rémunération, sans préjudice toutefois de l''article 43 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement, des Chapitres IX et IXbis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, [pour adultes] et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, des Chapitres VIII et IX du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné, des Chapitres IX et X du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné. Sans préjudice des éventuelles procédures disciplinaires ou de licenciement pouvant être mises en oeuvre par le pouvoir organisateur en cas Docu 49466 Code 03-05-2019 de fait grave et probant, le directeur ou un membre de l''équipe éducative peut faire l''objet d''une procédure de suspension préventive conformément aux dispositions qui régissent sa fonction, lorsque la désignation du manager de crise est fondée sur: 1° le refus ou l''incompétence du directeur à élaborer le plan de pilotage; 2° la mauvaise volonté manifeste du directeur à mettre en oeuvre le contrat d''objectifs et/ou, une incapacité à réaliser les objectifs y visés; 3° l''impossibilité imputable au directeur de modifier le contrat d''objectifs ou d''assurer la mise en oeuvre d''un processus de suivi rapproché; 4° la mauvaise volonté manifeste ou la carence manifeste et répétée du membre de l''équipe éducative dans le cadre de l''élaboration du plan de pilotage, de la mise en oeuvre du contrat d''objectifs, ou de la mise en oeuvre d''un processus de suivi rapproché. Durant cette suspension préventive, des objectifs de développement peuvent être fixés au membre du personnel par le pouvoir organisateur, en accord avec le délégué au contrat d''objectifs de l''école. Une évaluation de la réalisation de ces objectifs est faite à l''issue de la période fixée par le pouvoir organisateur. Les constats posés dans le cadre de cette évaluation peuvent constituer des éléments graves et probants pouvant amener le pouvoir organisateur à entamer sur cette base une procédure disciplinaire ou de licenciement. La durée de validité de cette évaluation est cependant limitée à douze mois prenant cours à la date de son établissement. Toutefois, lorsqu''une procédure disciplinaire ou de licenciement est entamée sur la base de celle-ci, dans ce délai, l''évaluation demeure valable jusqu''à la date à laquelle la décision définitive de sanction ou licenciement est notifiée au membre du personnel. Sans préjudice de l''article 124 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement, le manager de crise le remplace jusqu''à la désignation d''un nouveau directeur. Section II. - Du dispositif d''ajustement et du protocole de collaboration Complété par D. 09-12-2020');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 91, 'Article 1.', 'Article 1.5.2-13. - Le Gouvernement précise, après avis de la 
Commission de pilotage visée à l''article 1.6.1-1, la notion de performances 
présentant un écart significatif en dessous de la moyenne des écoles 
comparées. 
 
A cette fin, il s''appuie sur une analyse comparée d''indicateurs croisés et 
récurrents pour un ensemble d''écoles présentant un même profil, et 
appartenant à un même groupe de classes, la classe étant définie à l''article 4 
du décret du 30 avril 2009 organisant un encadrement différencié au sein des 
établissements scolaires de la Communauté française afin d''assurer à chaque 
élève des chances égales d''émancipation sociale dans un environnement 
pédagogique de qualité. Les indicateurs choisis sont liés au climat de l''école, 
aux parcours et résultats des élèves et aux équipes pédagogiques. 
 
L''identification des écoles présentant un écart significatif de performance 
en-dessous de la moyenne des écoles comparées au sens de l''alinéa 1er est 
confidentielle. Tout membre des services du Gouvernement, du Service général 
de l''Inspection, du Service général du Pilotage des écoles et des centres psycho-
 
 
Docu 49466 
 
Code 03-05-2019 
médico- sociaux, de Wallonie-Bruxelles-Enseignement, des fédérations de 
pouvoirs organisateurs, du personnel et des pouvoirs organisateurs des écoles 
et toute autre personne ayant connaissance de cette identification sont tenus 
à cet égard par le secret professionnel. En cas d''infraction, l''article 458 du Code 
pénal s''applique. [Inséré par D. 09-12-2020] 
 
La divulgation de l''identification des écoles présentant un écart 
significatif de performance en-dessous de la moyenne des écoles comparées 
constitue également une pratique déloyale au sens de l''article 1.7.3-3 du Code. 
[Inséré par D. 09-12-2020] 
 
Par dérogation aux alinéas 3 et 4, après s''être concerté avec le directeur, 
le pouvoir organisateur d''une école peut décider de rendre publique 
l''identification de son école. Il en informe le directeur de zone compétent et, le 
cas échéant, sa fédération de pouvoirs organisateurs. [Inséré par D. 09-12-2020]');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 92, 'Article 1.', 'Article 1.5.2-14. Le Service général de l''inspection réalise un audit à 
l''issue duquel il établit un diagnostic de l''école dont les performances 
présentent un écart significatif au sens de l''article 1.5.2-13. 
 
Le Gouvernement détermine les modalités selon lesquelles l''audit, le 
rapport et le diagnostic sont réalisés. 
 
Remplacé par D. 14-07-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 93, 'Article 1. (partie 1)', 'Article 1.5.2-15. § 1er. Le délégué au contrat d''objectifs ou le directeur de zone compétent fixe les objectifs d''ajustement de l''école qui tiennent compte du diagnostic visé à l''article 1.5.2-14. Le Gouvernement détermine les modalités selon lesquelles le diagnostic et les objectifs d''ajustement sont présentés et communiqués au directeur et au pouvoir organisateur, en présence de la fédération de pouvoirs organisateurs à laquelle l''école est affiliée ou avec laquelle elle a conclu une convention ou en présence de Wallonie-Bruxelles-Enseignement pour les écoles ayant conclu une convention avec ce dernier. § 2. Le délégué au contrat d''objectifs propose également les supports ou ressources, dont la liste et les modalités sont arrêtées par le Gouvernement, qui pourront être mis(es) à disposition de l''école par celui-ci dans le cadre de la mise en oeuvre du protocole de collaboration visé à l''article 1.5.2-17 afin d''assurer la réalisation de ses objectifs d''ajustement. Les supports visés à l''alinéa 1er consistent en un appui de seconde ligne apporté notamment par : 1° les services du Gouvernement; [2° le service intégré d''assistance aux écoles visé à l''article 1.7.11-2]23; 3° la médiation scolaire visée par le décret du 21 novembre 2013 organisant divers dispositifs scolaires favorisant le bien-être des jeunes à l''école, l''accrochage scolaire, la prévention de la violence à l''école et l''accompagnement des démarches d''orientation scolaire. Les ressources visées à l''alinéa 1er comprennent notamment : 1° des projets de recherches spécifiquement adaptés aux écoles en difficulté; 2° des projets-actions proposés avec des acteurs du monde associatif; 23Remplacé par le D. 16-05-2024 Docu 49466 Code 03-05-2019 3° des demi-jours de formation supplémentaires; 4° l''accès au programme prioritaire des travaux lorsque des problèmes d''infrastructure se présentent; 5° l''acquisition ou la modernisation d''équipements pédagogiques et 6° l''octroi de personnel engagé sous contrat «d''Aide à la promotion de l''emploi» (APE) ou «d''Agents contractuels subventionnés» (ACS). § 3. Un montant annuel de minimum 1.721.000 euros est alloué notamment aux ressources suivantes : 1° des projets de recherches spécifiquement adaptés aux écoles en difficulté; 2° des projets-actions proposés avec des acteurs du monde associatif; 3° l''acquisition ou la modernisation d''équipements pédagogiques; 4° le coût estimatif de l''encadrement de stabilisation prévu à l''article 22quater du décret du 29 juillet 1992 portant organisation de l''enseignement secondaire de plein exercice, et à l''article 26, § 3 du décret du 13 juillet 1998 portant organisation de l''enseignement maternel et primaire ordinaire et modifiant la réglementation de l''enseignement. Par équipement pédagogique, il faut entendre le matériel utile : 1° à l''amélioration des résultats des élèves dans un ou plusieurs domaines d''apprentissages ou disciplines; 2° au renforcement du parcours des élèves. Par projet-actions, il faut entendre une approche menée, avec un ou des acteurs du monde associatif, comportant une partie réflexive et une partie active en vue de la réalisation des actions envisagées. Le montant visé à l''alinéa 1er est indexé annuellement en fonction du rapport entre l''indice général des prix à la consommation du mois de janvier de l''année en cours et celui du mois de janvier de l''année précédente. Le coût estimatif visé à l''alinéa 1er, 4°, est estimé sur la base de la formule suivante : nombre de périodes compensées multiplié par le coût annuel moyen de la période considérée. Le Gouvernement déduit le coût estimatif visé à l''alinéa 1er, 4°, du montant annuel visé à l''alinéa 1er. Il répartit le solde entre les ressources visées à l''alinéa 1er, 1° à 3°. Le Gouvernement délègue cette compétence au Ministre qui a l''enseignement obligatoire dans ses attributions. § 4. Les projets de recherche, visés au paragraphe 2, alinéa 3, 1°, sont sélectionnés par le Gouvernement à l''issue d''un appel à projets selon les modalités arrêtées par le Gouvernement. Les projets de recherche doivent viser l''adaptation de dispositifs déjà mis en place et validés dans d''autres systèmes éducatifs, au contexte d''écoles en grande difficulté. Les projets de recherche doivent reposer sur des principes d''organisation soutenables et flexibles pour les équipes éducatives et permettre aux écoles participantes de faire perdurer le dispositif et/ou ses effets après la fin de la recherche. Ils doivent viser l''amélioration de la situation des écoles soutenues dans un ou plusieurs des domaines suivants : Docu 49466 Code 03-05-2019 1° les résultats des élèves dans un ou plusieurs domaines d''apprentissages ou disciplines; 2° les parcours des élèves (échec, retard, redoublement, décrochage, etc.); 3° les thèmes en lien avec le climat scolaire; 4° les questions qui ont plus particulièrement trait à la dynamique des équipes éducatives dans des contextes de tension ou de démotivation. Les projets de recherche doivent prévoir l''accompa');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 94, 'Article 1. (partie 2)', 'des écoles visées à l''article 1.5.2-13 pendant toute la durée du protocole de collaboration conclu conformément à la présente section. § 5. Les écoles visées à l''article 1.5.2-13 proposent des projets-actions à réaliser en collaboration avec des acteurs du monde associatif, selon les modalités fixées par le Gouvernement. Par acteurs du monde associatif, il faut entendre les associations ou les fondations au sens des articles 1 :2 et 1 :3 du Code des sociétés et des associations, actives dans un environnement proche de l''école initiatrice du projet. § 6. Par dérogation aux dispositions prévues aux articles 28 à 34 du décret du 4 mai 2005 portant exécution du Protocole d''accord du 7 avril 2004 entre le Gouvernement de la Communauté française et les organisations syndicales représentatives au sein du Comité de négociation de secteur IX et du Comité des services publics provinciaux et locaux - section II et aux articles 5, 6, et 23 du décret du 2 juin 2006 relatif au cadre organique et au statut des puériculteurs des établissements d''enseignement maternel ordinaire organisés et subventionnés par la Communauté française, le Gouvernement peut octroyer du personnel engagé sous contrat «d''Aide à la promotion de l''emploi» (APE) ou «d''Agents contractuels subventionnés» (ACS). Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 95, 'Article 1.', 'Article 1.5.2-16. - § 1er. Une proposition de «dispositif d''ajustement» 
adaptée à la situation de l''école et au diagnostic et qui vise la rencontre des 
objectifs d''ajustement tels que définis à l''article 1.5.2-15, est élaborée par le 
directeur, en collaboration avec l''équipe éducative et en concertation, le cas 
échéant, avec les équipes du centre PMS, selon les éléments et les modalités 
fixés par le Gouvernement. 
 
Pour rédiger la proposition de «dispositif d''ajustement», la cellule de 
soutien et d''accompagnement apporte son appui au directeur et à son équipe 
éducative dans le cadre d''une convention d''accompagnement et de suivi. 
[Lorsque le Pouvoir organisateur, le directeur et/ou la cellule de soutien et 
d''accompagnement l''estime nécessaire, une ou plusieurs réunion(s) de 
concertation peuvent être organisées entre le délégué au contrat d''objectifs et 
les différentes parties durant la phase d''élaboration de la proposition de « 
dispositif d''ajustement ».]24 
 
La proposition de «dispositif d''ajustement» comprend notamment les 
éléments suivants: 
1. les actions prioritaires à mettre en oeuvre pour atteindre les objectifs 
d''ajustement tels que définis à l''article 1.5.2-15, les méthodes de mesure et 
d''évaluation des résultats attendus ainsi que les délais dans lesquels ceux-ci 
sont attendus; 
 
24Inséré par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
2. les modalités du travail collaboratif de l''ensemble de l''équipe éducative 
de l''école permettant notamment l''élaboration du dispositif d''ajustement et la 
mise en oeuvre du protocole de collaboration; 
3. le plan de formation visé par l''article 6.1.4-1; 
4. les modalités de la mise en oeuvre du continuum pédagogique visant, 
tout au long du tronc commun, à assurer à tous les élèves les compétences 
initiales et les savoirs, les savoir-faire et les compétences du référentiel du 
tronc commun nécessaires à leur épanouissement personnel, à leur insertion 
sociale et à la poursuite de leurs études, dans la mesure et au rythme suivant 
lesquels l''école est concernée, y compris les modalités de la différenciation des 
apprentissages et de l''accompagnement personnalisé. 
 
La proposition définit également les ressources à solliciter en interne 
auprès du pouvoir organisateur et, le cas échéant, de sa fédération de pouvoirs 
organisateurs, et les supports ou ressources à solliciter en externe, notamment 
auprès du Gouvernement sur la base de la liste visée à l''article 1.5.2-15. 
 
§ 2. La proposition de «dispositif d''ajustement» est soumise pour avis aux 
organes locaux de concertation sociale, ainsi qu''à la cellule de soutien et 
d''accompagnement. 
 
Elle doit ensuite être approuvée par le pouvoir organisateur, 
préalablement à sa présentation au délégué au contrat d''objectifs. 
 
§ 3. La proposition de «dispositif d''ajustement» visée au paragraphe 1er 
est présentée, selon les conditions de forme fixées par le Gouvernement, au 
délégué au contrat d''objectifs dans les 55 jours ouvrables scolaires qui suivent 
la communication du diagnostic et des objectifs d''ajustement visée à l''article 
1.5.2-15, alinéa 3. 
 
Modifié par D. 09-12-2020 ; D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 96, 'Article 1. (partie 1)', 'Article 1.5.2-17. - § 1er. Dans les 20 jours calendrier du dépôt de la proposition de «dispositif d''ajustement», le délégué au contrat d''objectifs analyse, après concertation avec le directeur, le pouvoir organisateur et, le cas échéant, la fédération de pouvoirs organisateurs, l''adéquation de la proposition de «dispositif d''ajustement» aux objectifs d''ajustement visés à l''article 1.5.2-15 et au diagnostic visé à l''article 1.5.2-14, selon la procédure et les modalités définies par le Gouvernement. Cette concertation permet notamment d''envisager l''adéquation et la cohérence des ressources sollicitées en interne et en externe. [Alinéa remplacé par D. 09-12-2020] L''analyse de l''adéquation du «dispositif d''ajustement» aux objectifs d''ajustement visés à l''article 1.5.2-15 et au diagnostic visé à l''article 1.5.2-14 consiste en la détection de l''existence d''une éventuelle erreur manifeste d''appréciation quant à l''adéquation entre le «dispositif d''ajustement», le diagnostic et les objectifs poursuivis. Alinéa inséré par D. 09-12-2020 En outre, le délégué au contrat d''objectifs procède à une analyse des supports ou ressources sollicités auprès du Gouvernement par l''école dans son «dispositif d''ajustement» en vue d''être communiquée au Gouvernement. Pour ce faire, le délégué au contrat d''objectifs vérifie, au préalable, que les ressources demandées appartiennent bien à la liste visée à l''article 1.5.2-15. Il applique ensuite les critères suivants: 1° la pertinence au regard des actions prioritaires; 2° la pertinence au regard des objectifs d''ajustement; Docu 49466 Code 03-05-2019 3° leur cohérence au regard des supports ou ressources sollicitées en interne ou en externe auprès d''autres acteurs que le Gouvernement conformément à l''article 1.5.2-16, § 1er, alinéa 4. 4° la pertinence au regard du diagnostic visé à l''article 1.5.2-14; 5° la pertinence au regard des indicateurs visés à l''article 1.5.2-13; 6° tout autre critère fixé dans d''autres lois ou décrets. Dans les cas exceptionnels où le délégué au contrat d''objectifs n''a pas respecté le délai visé à l''alinéa 1er, l''analyse de l''adéquation de la proposition de «dispositif d''ajustement», telle que visée à l''alinéa 1er est réalisée par le directeur de zone qui dispose pour ce faire d''un délai complémentaire de 14 jours calendrier. Alinéa inséré par D. 09-12-2020 A l''exception de celles des écoles visées par l''article 1.5.2-20, le délégué coordonnateur transmet au Gouvernement l''analyse visée à l''alinéa 3 pour l''ensemble des écoles identifiées au regard des indicateurs visés à l''article 1.5.2-13 au cours d''une année scolaire. Sur la base de cette analyse et selon les modalités qu''il fixe, le Gouvernement répartit les supports ou ressources entre les écoles et fixe les modalités de cette attribution. L''octroi de ces supports ou ressources est conditionné à la conclusion du protocole de collaboration. [Pour les écoles visées par l''article 1.5.2-20, les ressources seront prises dans l''enveloppe budgétaire de l''année de la signature des protocoles de collaboration.]25 § 2. Si à l''issue de ces analyses, le dispositif d''ajustement est approuvé, il est renvoyé à l''école signé par le directeur de zone et contresigné par le délégué au contrat d''objectifs. Ce «dispositif d''ajustement» ainsi approuvé constitue dès lors le protocole de collaboration conclu entre le pouvoir organisateur, sa fédération de pouvoirs organisateurs et le Gouvernement. Il est signé par l''ensemble des parties et contresigné par le directeur de l''école en fonction au moment de la signature du protocole de collaboration. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. § 3. Si le dispositif d''ajustement n''est pas jugé en adéquation avec les objectifs d''ajustement visés à l''article 1.5.2-15 et au diagnostic visé à l''article 1.5.2-14 ou si les supports ou ressources sollicités ne sont pas pertinents au regard des critères visés au paragraphe 1er, alinéa 3, le délégué au contrat d''objectifs émet des recommandations motivées à l''attention du pouvoir organisateur et de sa fédération de pouvoirs organisateurs, afin que le «dispositif d''ajustement» soit adapté. Les recommandations formulées s''inscrivent dans le respect de la liberté du pouvoir organisateur en matière de méthodes pédagogiques. Pour adapter le «dispositif d''ajustement», le directeur, en collaboration avec l''équipe éducative et, le cas échéant, en concertation avec le délégué au contrat d''objectifs, avec les équipes du centre PMS, dispose de 35 jours ouvrables scolaires pour renvoyer au délégué au contrat d''objectifs le «dispositif d''ajustement», après avis et approbation comme précisé à l''article 1.5.2-16, § 2. 25Inséré par le D. 18-04-2024 Docu 49466 Code 03-05-2019 Le délégué au contrat d''objectifs dispose ensuite de 21 jours calendrier pour procéder à une nouvelle analyse de l''adéquation du dispositif d''a');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 97, 'Article 1. (partie 2)', 'avec les objectifs d''ajustement visés à l''article 1.5.2-15 et au diagnostic visé à l''article 1.5.2-14. Il effectue également une nouvelle analyse des supports ou ressources sollicités auprès du Gouvernement conformément au paragraphe 1er, alinéa 3. Sur la base de cette analyse et selon les modalités qu''il fixe, le Gouvernement attribue les supports ou ressources et fixe les modalités de cette attribution. L''octroi de ces supports ou ressources est conditionné à la conclusion du protocole de collaboration. [Complété par D. 09-12- 2020] S''il est approuvé, il est renvoyé à l''école signé par le directeur de zone et contresigné par le délégué au contrat d''objectifs. Il constitue dès lors le protocole de collaboration conclu entre le pouvoir organisateur, sa fédération de pouvoirs organisateurs et le Gouvernement. Il est signé par l''ensemble des parties et contresigné par le directeur de l''école en fonction au moment de la signature du protocole de collaboration. Au besoin, il est procédé à une modification de la lettre de mission du directeur conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. § 4. Le protocole de collaboration est à l''usage exclusif et confidentiel de l''équipe éducative, du directeur, des services du Gouvernement, du pouvoir organisateur concerné et de la fédération de pouvoirs organisateurs à laquelle l''école est affiliée ou avec laquelle elle est conventionnée, et ne peut faire l''objet d''aucune communication à des tiers à l''école, sauf dans les cas fixés par le Gouvernement, notamment pour des fins académiques ou scientifiques. Les destinataires de ce document sont soumis à une obligation de confidentialité. Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 98, 'Article 1.', 'Article 1.5.2-18. - En cas de désaccord persistant entre une école et le 
délégué au contrat d''objectifs à propos de l''appréciation de ce dernier sur 
l''adéquation d''un «dispositif d''ajustement» aux objectifs d''ajustement visés à 
l''article 1.5.2-15 et au diagnostic visé à l''article 1.5.2-14, l''école peut saisir, sur 
la base d''une demande motivée, une instance collégiale composée du Délégué 
coordonnateur et du directeur de zone concerné dans le délai prévu pour 
l''adaptation du dispositif d''ajustement. Le cas échéant, cette instance peut 
adapter les recommandations du délégué au contrat d''objectifs et prolonger le 
délai laissé à l''école pour s''y conformer.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 99, 'Article 1.', 'Article 1.5.2-19. - Le directeur et le pouvoir organisateur présentent le 
protocole de collaboration à l''équipe éducative de l''école, aux équipes du centre 
PMS en présence de la cellule de soutien et d''accompagnement, aux organes 
locaux de concertation sociale et au conseil de participation. 
 
Le protocole de collaboration est mis en oeuvre dès la signature de celui-
ci. Concomitamment, un processus de suivi rapproché de la mise en oeuvre du 
protocole de collaboration est mis en place par le délégué au contrat d''objectifs. 
 
Le Gouvernement fixe les modalités de l''évaluation de la mise en oeuvre 
du protocole de collaboration par le délégué au contrat d''objectifs.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 100, 'Article 1.', 'Article 1.5.2-20. -  En cas de refus ou d''incapacité de l''école à établir un 
dispositif d''ajustement et à permettre l''approbation et la signature du 
protocole de collaboration, conformément à l''article 1.5.2-17, ou lorsque 
 
 
Docu 49466 
 
Code 03-05-2019 
l''évaluation de la mise en oeuvre du protocole de collaboration révèle une 
mauvaise volonté ou une incapacité manifeste à atteindre les objectifs 
d''ajustement du protocole, le directeur de zone adresse un courrier 
recommandé avec accusé de réception au pouvoir organisateur. 
 
Ce courrier enjoint au directeur et au pouvoir organisateur: 
1° soit d''établir un dispositif d''ajustement en vue de permettre 
l''approbation et la signature du protocole de collaboration; 
2° soit de respecter le protocole de collaboration et le processus de suivi 
de sa mise en oeuvre. 
 
Le cas échéant, une copie de ce courrier est envoyée à la fédération de 
pouvoirs organisateurs concernée. 
 
A défaut pour l''école d''avoir satisfait à l''injonction dans un délai de 30 
jours ouvrables scolaires, le Gouvernement peut décider de réduire de 5 %, au 
plus, pour l''enseignement organisé par la Communauté française, les 
dotations de fonctionnement visées à l''article 3 de la loi du 29 mai 1959 
modifiant certaines dispositions de la législation de l''enseignement ou, pour 
l''enseignement subventionné, les subventions de fonctionnement de l''école 
visées à l''article 32 de la loi du 29 mai 1959 susvisée. 
 
Préalablement à toute décision de réduction des dotations ou des 
subventions de fonctionnement, le Gouvernement adresse une lettre de mise 
en demeure au pouvoir organisateur en l''invitant à faire connaitre ses 
observations par écrit uniquement. Celui-ci dispose d''un délai de 30 jours 
ouvrables scolaires, à compter de la notification postale par envoi recommandé 
avec accusé de réception de cette mise en demeure pour faire valoir ses 
observations. La réduction des dotations ou subventions de fonctionnement 
court à compter de la notification de la décision du Gouvernement jusqu''à ce 
que le pouvoir organisateur collabore à l''élaboration ou à la bonne mise en 
oeuvre du protocole de collaboration et du processus de suivi de sa mise en 
oeuvre. 
 
Lorsque le Gouvernement prononce une décision de réduction des 
dotations ou des subventions de fonctionnement et à défaut pour l''école d''avoir 
apporté la preuve qu''elle a satisfait à l''injonction du Gouvernement dans un 
délai de six mois à compter de la notification de la décision visée à l''alinéa 5, 
le Gouvernement supprime, dans l''enseignement organisé par la Communauté 
française, les traitements et dotations de fonctionnement visées à l''article 3 de 
la loi du 29 mai 1959 modifiant certaines dispositions de la législation de 
l''enseignement ou, dans l''enseignement subventionné par la Communauté 
française, les subventions-traitements et les subventions de fonctionnement 
visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 susvisée');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 101, 'Article 1. (partie 1)', 'Article 1.5.2-21. - § 1er. Le Gouvernement peut toutefois, sur la base des observations écrites visées à l''article 1.5.2-20, en lieu et place de cette réduction, enjoindre au pouvoir organisateur la désignation d''un manager de crise. A cet effet, le Gouvernement lui adresse un courrier recommandé avec accusé de réception en lui enjoignant de désigner un manager de crise dans un délai de 30 jours calendrier. Dans l''enseignement subventionné, le pouvoir organisateur peut, pour la désignation du manager de crise, habiliter la fédération de pouvoirs Docu 49466 Code 03-05-2019 organisateurs à laquelle il est affilié si les statuts de celle-ci ou la résolution d''adhésion à celle-ci contiennent une telle habilitation ou si le pouvoir organisateur a fourni cette habilitation par écrit, mentionnant la fédération de pouvoirs organisateurs à laquelle le pouvoir organisateur est affilié. Dans ce cas une copie du courrier enjoignant au pouvoir organisateur de désigner un manager de crise est adressée pour information à cette fédération de pouvoirs organisateurs. § 2. Le manager de crise est désigné selon les règles qui sont propres au pouvoir organisateur ou, le cas échéant, à la fédération de pouvoirs organisateurs habilitée à cet effet, et à leur charge. Si le pouvoir organisateur ou, le cas échéant, sa fédération de pouvoirs organisateurs, si celle-ci est habilitée à le faire, ne désigne pas un manager de crise dans le délai de 30 jours prévu à l''alinéa 2 de l''article 1.5.2-21, § 1er, le Gouvernement lui adresse une mise en demeure par laquelle il l''invite à procéder à cette désignation dans un délai de 15 jours calendrier à compter de la notification postale par envoi recommandé avec accusé de réception de cette mise en demeure. Si, à l''échéance de ce délai de 15 jours calendrier, le pouvoir organisateur ou, le cas échéant, sa fédération de pouvoirs organisateurs, si elle est habilitée à le faire, n''a pas apporté la preuve de la désignation d''un manager de crise, le Gouvernement supprime, dans l''enseignement organisé par la Communauté française, les traitements et dotations de fonctionnement visées à l''article 3 de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement ou, dans l''enseignement subventionné par la Communauté française, les subventions-traitements et les subventions de fonctionnement visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 susvisée. Le manager de crise est désigné, pour une ou plusieurs périodes avec un maximum de 36 mois en concertation avec le directeur de zone. L''organe local de concertation sociale et le conseil de participation sont informés de la désignation du manager de crise préalablement à son entrée en fonction. Dans le cadre de l''exécution de sa mission, le manager de crise analyse la situation de l''école sur la base du diagnostic visé à l''article 1.5.2-14 et, s''il échet, de l''évaluation de la mise en oeuvre du protocole de collaboration visée à l''article 1.5.2-19. Il formule des propositions, après consultation du pouvoir organisateur, du directeur, de l''équipe éducative, de la fédération de pouvoirs organisateurs concernée et le cas échéant, des équipes du centre PMS en vue de rencontrer les objectifs du protocole de collaboration ou de modifier celui-ci. Il en informe les organes locaux de concertation sociale et le conseil de participation. Il soumet ces propositions pour approbation au pouvoir organisateur. Sur la base de ces propositions, le protocole de collaboration fait l''objet, le cas échéant, d''une proposition en vue de sa modification par le pouvoir organisateur, en concertation avec le manager de crise. Docu 49466 Code 03-05-2019 Cette proposition de modification est alors adressée au directeur de zone. S''il l''approuve, elle fait partie intégrante du protocole de collaboration de l''école. Au besoin, la lettre de mission du directeur est modifiée conformément aux articles 26 et 27 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement. Le manager de crise met en oeuvre le protocole de collaboration en collaboration avec le pouvoir organisateur, le directeur, l''équipe éducative de l''école, et le cas échéant, les équipes du centre PMS dans le cadre d''un processus de suivi rapproché tel que visé à l''article 1.5.2-19, alinéa 2. § 3. Le directeur de zone et le délégué au contrat d''objectifs évaluent au plus tard un mois avant l''échéance de la fin de la mission du manager de crise l''accomplissement et le résultat de cette mission en concertation avec le pouvoir organisateur et, le cas échéant, sa fédération de pouvoirs organisateurs habilitée à cet effet si celle-ci a désigné le manager de crise. Au terme de cette évaluation, le directeur de zone communique au Gouvernement, après consultation du pouvoir organisateur et, le cas échéant, de sa fédération de pouvoirs organisateurs si elle a participé au processus de désignation du manager de crise, un rapport au terme duquel il conclut à la');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 102, 'Article 1. (partie 2)', 'mise en oeuvre satisfaisante ou insatisfaisante du protocole de collaboration. Lorsque le rapport conclut à la mise en oeuvre insatisfaisante du protocole de collaboration, le Gouvernement supprime, dans l''enseignement organisé par la Communauté française, les traitements et dotations de fonctionnement visées à l''article 3 de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement ou, dans l''enseignement subventionné, les subventions-traitements et les subventions de fonctionnement visées aux articles 26 à 28 et 32 de la loi du 29 mai 1959 susvisée. Préalablement à la décision de suppression des dotations, des traitements ou subventions, le Gouvernement adresse une lettre de mise en demeure au pouvoir organisateur en l''invitant à faire connaitre ses observations par écrit uniquement. Celui-ci dispose d''un délai de 30 jours calendrier, à compter de la notification postale par envoi recommandé avec accusé de réception de cette mise en demeure pour faire valoir ses observations. § 4. Le directeur concerné conserve, durant la période de désignation du manager de crise, le bénéfice de sa désignation en qualité de directeur à titre temporaire ou de sa désignation en qualité de directeur admis au stage ou de sa nomination à titre définitif en tant que directeur ainsi que de sa rémunération, sans préjudice toutefois de l''article 43 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement, des Chapitres IX et IXbis de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécialisé, moyen, technique, [pour adultes] et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, des Chapitres VIII et IX du décret du 6 juin 1994 fixant le statut des membres du personnel subsidiés de l''enseignement officiel subventionné, des Chapitres IX et X du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné. Docu 49466 Code 03-05-2019 Sans préjudice des éventuelles procédures disciplinaires ou de licenciement pouvant être mises en oeuvre par le pouvoir organisateur en cas de fait grave et probant, le directeur ou un membre de l''équipe éducative peut faire l''objet d''une procédure de suspension préventive conformément aux dispositions qui régissent sa fonction, lorsque la désignation du manager de crise est fondée sur: 1° le refus ou l''incompétence du directeur à élaborer le dispositif d''ajustement; 2° la mauvaise volonté manifeste du directeur à mettre en oeuvre le protocole de collaboration et/ou une incapacité à réaliser les objectifs y visés; 3° l''impossibilité imputable au directeur de modifier le protocole de collaboration ou d''assurer la mise en oeuvre d''un processus de suivi rapproché; 4° la mauvaise volonté manifeste ou la carence manifeste et répétée du membre de l''équipe éducative dans le cadre de l''élaboration du dispositif d''ajustement, de la mise en oeuvre du protocole de collaboration, ou de la mise en oeuvre d''un processus de suivi rapproché. Durant cette suspension préventive, des objectifs de développement peuvent être fixés au membre du personnel par le pouvoir organisateur, en accord avec le délégué au contrat d''objectifs de l''école. Une évaluation de la réalisation de ces objectifs est faite à l''issue de la période fixée par le pouvoir organisateur. Les constats posés dans le cadre de cette évaluation peuvent constituer des éléments graves et probants pouvant amener le pouvoir organisateur à entamer sur cette base une procédure disciplinaire ou de licenciement. La durée de validité de cette évaluation est cependant limitée à un délai de douze mois prenant cours à la date de son établissement. Toutefois, lorsqu''une procédure disciplinaire ou de licenciement est entamée sur la base de celle-ci, dans ce délai, l''évaluation demeure valable jusqu''à la date à laquelle la décision définitive de sanction ou licenciement est notifiée au membre du personnel. Sans préjudice de l''article 124 du décret du 2 février 2007 fixant le statut des directeurs et des directrices dans l''enseignement, le manager de crise le remplace jusqu''à la désignation d''un nouveau directeur. [Article 1.5.2-22. - Le protocole de collaboration est conclu pour une période de maximum trois ans. Il remplace le contrat d''objectifs préalablement conclu par l''école.]26 [A l''issue de l''évaluation qui clôture la mise en œuvre du protocole de collaboration, l''école qui a conclu un protocole de collaboration : [1° est tenue de conclure un nouveau protocole de collaboration si elle a été identifiée une nouvelle fois comme présentant un écart significatif de performance en-dessous de la moyenne des écoles comparées, conformément à l''article 1.5.2-13, au cours');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 103, 'Article 1. (partie 3)', 'de la troisième année d''exécution de son protocole de collaboration ; 2° est tenue d''élaborer un nouveau plan de pilotage conformément aux dispositions de la Section 1 si elle n''a pas été identifiée une nouvelle fois comme 26Remplacé par le D. 18-04-2024 Docu 49466 Code 03-05-2019 présentant un écart significatif de performance en-dessous de la moyenne des écoles comparées, conformément à l''article 1.5.2-13, au cours de la troisième année d''exécution de son protocole de collaboration.]27 [28Lorsqu''elle est tenue d''élaborer un nouveau plan de pilotage en application de l''alinéa 2, 2°, l''école remet son plan de pilotage au délégué au contrat d''objectifs entre 65 et 110 jours ouvrables scolaires après la réception du rapport relatif à l''évaluation précitée. Cette école ne peut pas être identifiée une nouvelle fois comme présentant un écart significatif de performance en dessous de la moyenne des écoles comparées avant l''année scolaire qui suit l''évaluation intermédiaire du contrat d''objectifs conclu immédiatement après l''expiration d''un protocole de collaboration.] Section III. - De l''évaluation des mesures en matière du pilotage des écoles');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 104, 'Article 1.', 'Article 1.5.2-23. - Le Gouvernement évalue la mise en oeuvre des 
dispositions du présent Chapitre et en fait rapport au Parlement au cours de 
l''[année scolaire 2024-2025]29. 
 
CHAPITRE III. - De la participation 
 
Section 1ère. - Du conseil de participation 
 
Complété par D. 17-06-2021 ; modifié par D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 105, 'Article 1.', 'Article 1.5.3-1. - § 1er. Il est créé dans chaque école un conseil de 
participation. 
 
Par dérogation à l''alinéa 1er, le pouvoir organisateur qui organise 
plusieurs écoles peut constituer un conseil de participation commun à deux, 
trois ou quatre écoles, après avoir pris avis des conseils de participation 
concernés. 
 
Lorsqu''il est fait usage de la dérogation prévue à l''alinéa 2, pour chacune 
des catégories visées à l''article 1.5.3-2, § 1er, alinéa 3, 1° et 2°, un représentant 
de chaque école au moins est membre du conseil de participation. 
 
Sur avis favorable du conseil de participation, le pouvoir organisateur 
peut soit renoncer au regroupement, soit le modifier. Le regroupement ou sa 
modification ne peuvent intervenir qu''après trois années de fonctionnement 
du conseil de participation concerné. 
 
§ 2. Le conseil de participation est chargé: 
1° de débattre et d''émettre un avis sur le projet d''école en se fondant 
notamment sur des propositions émises par les délégués du pouvoir 
organisateur, de l''amender et de le compléter, et de le proposer à l''approbation 
du pouvoir organisateur; 
2° de proposer des adaptations au projet d''école conformément à l''article 
1.5.1-5, § 1er; 
 
27Remplacé par le D. 16-07-2025 
28Inséré par le D. 16-07-2025 
29Remplacé par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
3° de mener une réflexion globale sur les frais scolaires réclamés en cours 
d''année, notamment ceux qui sont liés à des activités culturelles et sportives 
s''inscrivant dans le projet d''école; 
4° d''étudier et de proposer la mise en place d''un mécanisme de solidarité 
entre les élèves pour le paiement des frais scolaires visés au 3°; 
5° d''étudier et de proposer les actions de soutien et d''accompagnement à 
l''attention des élèves inscrits sur la base de l''indice socio-économique de leur 
école fondamentale ou primaire d''origine; 
6° de remettre un avis sur le plan de pilotage conformément aux articles 
1.5.2-4, alinéa 4, et 1.5.2-5, § 3, alinéa 5, et sur la proposition de modification 
du contrat d''objectifs, conformément à l''article 1.5.2-9, § 2, alinéas 1er et 6, et 
à l''article 1.5.2-10, alinéa 4, en formulant toutes propositions utiles à ce sujet; 
7° de débattre et de remettre un avis sur le règlement d''ordre intérieur 
de l''école et, le cas échéant, de l''amender et de le compléter; 
8° d''informer les parents ou les élèves majeurs sur les dispositions 
décrétales et règlementaires applicables en matière de gratuité d''accès à 
l''enseignement et de veiller à leur bonne application au sein de l''école; 
9° de recevoir une information claire et transparente de la part du pouvoir 
organisateur concernant les moyens relatifs à la gratuité d''accès reçus ou 
collectés, directement ou indirectement, et l''utilisation de ceux-ci ; 
10° de mener annuellement, pour les écoles de l''enseignement ordinaire, 
une réflexion globale sur le caractère inclusif de l''école. A cette occasion, le 
conseil de participation invite les parents des élèves pour lesquels le pôle 
assure la mise en oeuvre d''une intégration permanente totale ou 
d''aménagements raisonnables et peut entendre un représentant du pôle 
territorial ; [inséré par D. 17-06-2021] 
11° d''être informé, pour les écoles de l''enseignement ordinaire, au 
moment de la conclusion de la convention de coopération entre l''école et son 
pôle territorial, en particulier sur les modalités d''information et de 
collaboration avec les élèves et les parents des élèves auprès desquels le pôle 
intervient ; [inséré par D. 17-06-2021] 
12° de remettre un avis, pour les écoles de l''enseignement ordinaire, sur 
la collaboration de l''école avec le pôle territorial, avant l''évaluation 
intermédiaire et l''évaluation finale de l''annexe visée à l''article 6.2.4-1. A cette 
occasion, le conseil de participation entend un représentant du pôle territorial 
et invite les parents des élèves pour lesquels le pôle assure la mise en oeuvre 
d''une intégration permanente totale ou d''aménagements raisonnables. Cet 
avis est communiqué au pôle territorial compétent ; [Inséré par D. 17-06-2021] 
13° de mener annuellement, pour les écoles concernées par la mise en 
oeuvre du Tronc commun, une réflexion globale sur les modalités pratiques de 
la différenciation des apprentissages et de l''accompagnement personnalisé, en 
cohérence avec les éléments énoncés dans le contrat d''objectifs de l''école 
conformément à l''article 1.5.2-3, § 1er, 6°. [Inséré par D. 20-07-2022] 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 106, 'Article 1. (partie 1)', 'Article 1.5.3-2. - § 1er. Le conseil de participation comprend des membres de droit, des membres élus et des membres représentant l''environnement social, culturel et économique de l''école. Les membres de droit sont le directeur et les délégués que désigne le pouvoir organisateur. Les membres élus comprennent: 1° les représentants du personnel enseignant, auxiliaire d''éducation, psychologique, social et paramédical; Docu 49466 Code 03-05-2019 2° les représentants des parents, en ce compris les parents dont les enfants sont inscrits dans l''enseignement spécialisé et qui font l''objet d''un projet d''intégration dans l''enseignement ordinaire; [remplacé par D. 24-02-2022] 3° les représentants des élèves, sans préjudice du paragraphe 4; 4° un représentant du personnel ouvrier et administratif, là où il est attaché à l''école. Les membres représentant l''environnement social, culturel et économique de l''école sont désignés par le pouvoir organisateur ou son délégué. Chaque membre du conseil de participation peut se faire remplacer par un suppléant désigné ou élu, selon les mêmes modalités que le membre effectif. Le nombre de représentants visés à l''alinéa 3, 1°, 2° et 3°, est identique pour chaque catégorie. Ce nombre est fixé par le pouvoir organisateur ou son délégué. Il ne peut être inférieur à trois ni supérieur à six. Ni les délégués du pouvoir organisateur ni les membres représentant l''environnement social, culturel et économique de l''école ne peuvent être en nombre supérieur à celui attribué à chacune des catégories visées à l''alinéa 3, 1°, 2° et 3°. Toutefois, lorsqu''il est fait usage de la dérogation prévue à l''article 1.5.3- 1, § 1er, alinéa 2, la délégation du pouvoir organisateur peut comprendre un nombre supérieur à celui attribué à chacune des catégories visées à l''alinéa 3, 1°, 2° et 3°, de manière à ce que le nombre de délégués du pouvoir organisateur qui ne sont pas directeurs soit supérieur d''une unité au nombre de directeurs. § 2. Les représentants du personnel visé au paragraphe 1er, alinéa 3, 1°, comprennent: 1° dans l''enseignement officiel, des délégués élus en leur sein et au scrutin secret par l''ensemble des membres du personnel concerné nommés à titre définitif ou désignés à titre temporaire pour une année scolaire complète; 2° dans l''enseignement libre, a) trois délégués, membres du personnel de l''école pour une année scolaire complète, désignés par les organisations syndicales représentatives suivant une proportionnalité conforme à celle du résultat des élections sociales dans l''école, c''est-à-dire aux conseils d''entreprise, ou, à défaut, au comité pour la protection du travail, ou, à défaut, dans les instances de concertation locales; b) un maximum de trois délégués élus en leur sein et au scrutin secret par l''ensemble des membres du personnel concerné engagés à titre définitif ou engagés à titre temporaire pour une année scolaire complète. Les représentants visés à l''alinéa 1er, 2°, ne peuvent faire partie ni du conseil d''administration ni de l''assemblée générale du pouvoir organisateur. Le Gouvernement peut accorder dérogation à cette disposition lorsque tous les membres du personnel sont membres de droit du pouvoir organisateur. Les représentants du personnel visés au paragraphe 1er, alinéa 3, 1° et 4°, doivent obligatoirement prester au moins un mi-temps dans l''école. § 3. Les représentants des élèves sont élus, en leur sein, après appel aux candidats, soit par l''ensemble des élèves de l''école, soit par l''ensemble des Docu 49466 Code 03-05-2019 élèves du niveau secondaire de l''école, soit par l''ensemble des élèves du degré supérieur de l''enseignement secondaire. Le mandat ne peut entrainer ni préjudice ni privilège pour celui qui l''exerce. Le choix entre les trois modalités fixées à l''alinéa 1er est de la compétence du pouvoir organisateur qui peut le déléguer. § 4. Dans l''enseignement fondamental, le pouvoir organisateur, sur proposition de deux tiers au moins des membres du conseil de participation, peut décider d''élargir le conseil de participation à des délégués d''élèves, soit de manière permanente, soit de manière occasionnelle. § 5. Lorsqu''il existe au sein de l''école une association de parents membre de l''une des organisations représentatives des parents et associations de parents d''élèves visées à l''article 1.6.6-1, l''organisation de l''élection des représentants des parents est réglée par cette organisation. A défaut, la première réunion générale des parents est faite à l''initiative du pouvoir organisateur ou de son délégué. Dans l''un comme dans l''autre cas, l''assemblée générale des parents élit au scrutin secret ses représentants. La convocation et le procès-verbal de toute assemblée générale sont portés à la connaissance de l''ensemble des parents. Chaque parent présent lors de l''assemblée générale peut participer au scrutin et se porter candidat sans autre condition. Les représentants des parents visés au paragraphe 1er, alinéa 3, ne peuvent faire partie ni du conseil d''admini');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 107, 'Article 1. (partie 2)', 'ni de l''assemblée générale du pouvoir organisateur, ni être membres du personnel de l''école. Le Gouvernement peut accorder dérogation à cette disposition lorsque tous les parents sont membres de droit du pouvoir organisateur. § 6. Le personnel ouvrier et administratif élit son représentant. § 7. Les membres élus représentant les enseignants et les membres représentant l''environnement social, culturel et économique exercent un mandat renouvelable d''une durée de quatre ans. Les membres élus représentant les parents et les élèves exercent un mandat renouvelable d''une durée de deux ans. Tout membre qui ne remplit plus les conditions d''éligibilité est remplacé selon les modalités fixées par le règlement d''ordre intérieur visé à l''article 1.5.3-3, § 3. Lorsque pour une catégorie déterminée, le nombre de candidats ne dépasse pas le nombre de postes à pourvoir, les candidats sont élus d''office. § 8. Le conseil de participation peut coopter des membres avec voix consultative. Ceux-ci ne peuvent pas être en nombre supérieur à celui attribué à chacune des catégories visées au paragraphe 1er, alinéa 3, 1°, 2°, 3°. Docu 49466 Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 108, 'Article 1.', 'Article 1.5.3-3.  - § 1er. Le conseil de participation se réunit au moins 
quatre fois par an. Il doit en outre être convoqué sur demande adressée à son 
président de la moitié de ses membres au moins. 
 
Les représentants des différentes catégories membres du conseil de 
participation veillent à organiser des assemblées de leurs mandants afin de 
débattre des questions soulevées au conseil de participation. 
 
Le pouvoir organisateur ou son délégué désigne le président du conseil de 
participation. 
 
§ 2. Le conseil de participation tend à rendre ses avis par consensus. 
 
A défaut, dans l''enseignement officiel, l''avis est rendu à la majorité des 
deux tiers des membres présents, pour autant que la majorité soit aussi réunie: 
1° parmi les membres présents visés à l''article 1.5.3-2, § 1er, alinéa 2; 
2° parmi les membres présents visés à l''article 1.5.3-2, § 1er, alinéas 3 et 
4, les abstentions n''intervenant pas dans le décompte des voix. 
 
A défaut, dans l''enseignement libre, l''avis est rendu à la majorité des 
deux tiers des membres présents, pour autant que la majorité soit aussi réunie: 
1° parmi les membres présents visés à l''article 1.5.3-2, § 1er, alinéa 2; 
2° parmi les membres présents visés l''article 1.5.3-2, § 1er, alinéa 3, 2°, 3° 
et 4°, et alinéa 5; 
3° parmi les membres présents visés l''article 1.5.3-2, § 2, alinéa 1er, 2°, 
les abstentions n''intervenant pas dans le décompte des voix. 
 
Lorsque l''avis ne recueille pas le consensus, chaque catégorie visée à 
l''article 1.5.3-2, § 1er, peut déposer une note de minorité. 
 
§ 3. Le conseil de participation élabore son règlement d''ordre intérieur et 
le soumet à l''approbation du pouvoir organisateur. 
 
Section II. - Des délégués d''élèves');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 109, 'Article 1.', 'Article 1.5.3-4. - Des délégués d''élèves sont élus en cinquième et sixième 
années primaires, ainsi que dans l''enseignement secondaire. 
 
Dans le type 2 de l''enseignement fondamental spécialisé et dans la forme 
1 de l''enseignement secondaire spécialisé ainsi que dans l''enseignement 
spécialisé pour élèves polyhandicapés, pour élèves avec autisme, pour élèves 
aphasiques ou dysphasiques ou pour élèves avec handicaps physiques lourds, 
la désignation d''un délégué de classe est laissée à l''appréciation du directeur 
ou du pouvoir organisateur en fonction des élèves qui composent les classes 
concernées.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 110, 'Article 1.', 'Article 1.5.3-5. - Le pouvoir organisateur ou son délégué définit les 
modalités d''élection des délégués d''élèves et reconnait l''existence des conseils 
des délégués d''élèves. 
 
Les dispositions visées à l''alinéa 1er prévoient notamment l''élection des 
délégués d''élèves et de leurs suppléants par leurs pairs, au début de chaque 
année scolaire, au sein de chaque classe.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 111, 'Article 1.', 'Article 1.5.3-6. - § 1er. Il existe un conseil des délégués d''élèves 
respectivement pour les délégués d''élèves: 
 
 
Docu 49466 
 
Code 03-05-2019 
1° des cinquième et sixième années primaires; 
2° du degré inférieur de l''enseignement secondaire; 
3° du degré supérieur de l''enseignement secondaire. 
 
Le conseil des délégués d''élèves est un espace de parole destiné à analyser 
des problèmes relatifs à l''école ou à certaines classes. 
 
Il a pour mission de centraliser et de relayer les questions, demandes, 
avis et propositions des élèves au sujet de la vie de l''école auprès du conseil de 
participation, du directeur et du pouvoir organisateur. Il a également pour 
mission d''informer les élèves des différentes classes des réponses données par 
le conseil de participation, le directeur ou le pouvoir organisateur. 
 
§ 2. Chaque conseil des délégués d''élèves établit son règlement d''ordre 
intérieur. Il se réunit au moins six fois par an. 
 
§ 3. L''ensemble des conseils de délégués d''élèves se réunit au moins une 
fois par an pour débattre de questions prioritaires et, le cas échéant, élire les 
délégués d''élèves siégeant au conseil de participation.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 112, 'Article 1.', 'Article 1.5.3-7. - Pour chaque catégorie visée à l''article 1.5.3-6, § 1er, 
alinéa 1er, deux membres de l''équipe pédagogique au moins sont désignés 
accompagnateurs du projet «Conseil des délégués d''élèves». 
 
Ceux-ci participent, à titre d''expert, aux réunions du conseil des délégués 
d''élèves des années d''études dans lesquelles ils exercent.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 113, 'Article 1.', 'Article 1.5.3-8. - Par dérogation aux dispositions définies aux articles 
1.5.3-4 à 1.5.3-7, quand le nombre d''élèves de cinquième et sixième années 
primaires inscrits dans l''école ou dans l''implantation est inférieur à 15, le 
pouvoir organisateur ou son délégué organise la participation des élèves selon 
des modalités adaptées à ce nombre réduit d''élèves.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 114, 'Article 1. / Article 1.', 'Article 1.5.3-9. - La formation à la délégation d''élèves ou à la médiation 
par les pairs vise à construire une dynamique positive et à faire émerger des 
pratiques démocratiques au sein des écoles.

Article 1.5.3-10. - § 1er. Le Gouvernement fixe les critères de sélection 
des opérateurs de formation et définit la liste des opérateurs pouvant être 
subventionnés, notamment sur base de l''expertise dont ils peuvent témoigner 
et en veillant à une répartition équilibrée de ceux-ci. 
 
§ 2. Comme suite à un appel à candidatures, il sélectionne, sur 
proposition de la Commission visée au paragraphe 3, les écoles dont des 
représentants seront admis à suivre la formation visée à l''article 1.5.3-9, en 
veillant à une juste répartition entre les réseaux et en privilégiant les écoles 
n''ayant pas encore bénéficié de cette formation. 
 
Il fixe les critères de sélection des candidatures d''écoles. 
 
§ 3. Il est créé une Commission de sélection des candidatures visées au 
paragraphe 2. 
 
Elle est composée, dans le respect de l''équilibre des caractères, de sept 
représentants proposés par les fédérations de pouvoirs organisateurs, d''un 
 
 
Docu 49466 
 
Code 03-05-2019 
représentant proposé par Wallonie-Bruxelles Enseignement, ainsi que du 
Directeur général de l''enseignement obligatoire ou son délégué, qui la préside. 
 
Le Gouvernement en désigne les membres, en fixe les modalités de 
fonctionnement. 
 
Le secrétariat de la Commission est assuré par les services du 
Gouvernement. 
 
Section III. - Des associations de parents d''élèves');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 115, 'Article 1.', 'Article 1.5.3-11. - Une association de parents d''élèves peut être créée par 
les parents d''une école maternelle, primaire, fondamentale ou secondaire. 
 
L''association de parents regroupe exclusivement les parents d''élèves 
régulièrement inscrits.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 116, 'Article 1.', 'Article 1.5.3-12. - L''association de parents s''inscrit dans le cadre du 
projet pédagogique de l''école. 
 
Elle a pour mission de faciliter les relations entre les parents et 
l''ensemble de la communauté éducative, dans l''intérêt de tous les élèves, de 
leur réussite et de leur épanouissement dans le respect des droits et obligations 
de chacun. 
 
L''association de parents organise une veille passive et active en vue 
d''informer le plus objectivement possible tous les parents. 
 
Complété par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 117, 'Article 1.', 'Article 1.5.3-13. - § 1er. En l''absence d''initiative des parents d''une école, 
le pouvoir organisateur ou son délégué organise chaque année, avant le 1er 
novembre, une première assemblée générale des parents en vue de la création 
de l''association de parents, en fonction des contraintes propres à l''école ou 
selon les pratiques existantes. La collaboration du conseil de participation et 
de l''organisation représentative des parents et associations de parents d''élèves 
sera sollicitée dans le cadre de cette démarche. 
 
§ 2. Le pouvoir organisateur ou son délégué convoque une assemblée 
générale des parents de l''école au moins une fois par an. Cette assemblée devra 
se tenir avant le 1er novembre. Au cours de celle-ci, il évoque plus 
particulièrement le rôle et le fonctionnement du conseil de participation et le 
rôle d''une association de parents. 
 
Cette assemblée générale des parents peut être associée à la réunion 
générale des parents visant à élire les représentants des parents au conseil de 
participation telle que définie à l''article 1.5.3-2, § 5. 
 
§ 3. Tout parent d''élève mineur ou majeur est membre de droit de 
l''association de parents de l''école où l''élève est régulièrement inscrit.  
 
Les parents dont les enfants sont inscrits dans l''enseignement spécialisé 
et qui font l''objet d''un projet d''intégration dans l''enseignement ordinaire sont 
également membres de droit de l''association de parents de l''école ordinaire 
concernée. 
 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 118, 'Article 1.', 'Article 1.5.3-14. - § 1er. Le comité de l''association de parents représente 
l''association de parents entre deux assemblées générales des parents. Il est 
composé de trois membres au moins, élus au scrutin secret pour deux ans 
maximum, renouvelables, par et parmi les parents membres de l''association 
de parents, réunis en assemblée générale. Le comité définit son règlement 
d''ordre intérieur lors de sa première réunion. 
 
Pour garantir l''indépendance des débats au sein du comité, ne peuvent 
être membres du comité: 
1° les membres du pouvoir organisateur; 
2° les membres de la direction; 
3° les membres du personnel pédagogique; 
4° tout autre membre du personnel. 
 
Il peut être dérogé à l''alinéa 2, 1°, lorsque tous les parents sont membres 
de droit du pouvoir organisateur. 
 
Les parents élus au conseil de participation peuvent faire partie du 
comité de l''association de parents. 
 
§ 2. Le comité de l''association des parents a pour missions: 
1° d''organiser, conjointement avec la direction de l''école, une assemblée 
générale des parents, au moins une fois par an; 
2° de réunir des parents afin de débattre notamment des questions 
soulevées au conseil de participation; 
3° d''assurer la circulation de l''information entre les parents d''élèves de 
l''école et leurs éventuels organes représentatifs; 
4° de susciter la participation active de tous les parents d''élèves de l''école 
en vue de leur permettre de jouer pleinement un rôle actif et responsable au 
sein de l''école de leurs enfants; 
5° d''émettre d''initiative des avis et/ou des propositions aux acteurs 
concernés. 
 
§ 3. Est réputé démissionnaire le membre du comité ou le représentant 
qui n''a plus d''enfant régulièrement inscrit dans l''école. Tout membre 
démissionnaire du comité est remplacé lors de l''assemblée générale suivante 
conformément au paragraphe 1er. 
 
§ 4. Pour que l''association de parents puisse être reconnue comme 
membre d''une organisation représentative des parents et associations de 
parents d''élèves visée à l''article 166-1, ses statuts ou règles de fonctionnement 
doivent être conformes au présent Code et aux statuts de l''organisation 
concernée. 
 
§ 5. Si nécessaire, l''association de parents, réunie en assemblée générale, 
élit également pour deux ans un représentant chargé des relations avec 
l''organisation représentative des parents et associations de parents d''élèves 
concernée et un suppléant. Le comité est chargé d''informer de cette 
désignation l''organisation représentative dont il ressort. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 119, 'Article 1.', 'Article 1.5.3-15. - § 1er. Le pouvoir organisateur assure à l''association de 
parents la mise à disposition des infrastructures et du matériel nécessaires à 
la réalisation de ses missions, sans nuire au bon fonctionnement de l''école et 
selon des modalités concertées entre le comité de l''association de parents et le 
 
 
Docu 49466 
 
Code 03-05-2019 
pouvoir organisateur ou son délégué, notamment en matière de convention et 
d''assurance pour ce qui concerne l''occupation des locaux. 
 
§ 2. Le comité de l''association de parents doit être en mesure de se faire 
connaitre de l''ensemble des parents d''élèves de l''école. A cette fin, les 
coordonnées des membres du comité seront portées à la connaissance de tous 
les parents en début d''année par le directeur. 
 
Dans chaque école, l''association de parents pourra disposer d''un tableau 
d''affichage, dans un endroit facilement accessible aux parents, avec, 
éventuellement, la mention des noms et coordonnées des membres du comité 
de l''association de parents. 
 
§ 3. Le Gouvernement, les services du Gouvernement et les pouvoirs 
organisateurs veilleront à identifier clairement les circulaires et directives 
dont l''objet concerne les associations de parents. 
 
Le comité de l''association de parents a accès à ces documents nécessaires 
à l''exercice de ses missions dans les mêmes conditions que les autres 
partenaires de la communauté éducative. Le pouvoir organisateur ou son 
représentant au sein de l''école est invité à transmettre ces documents en temps 
utile. 
 
§ 4. Le pouvoir organisateur ou son délégué veillera à la diffusion des 
documents de l''association de parents, qui devront être clairement identifiés 
comme émanant de ladite association de parents. 
 
Les modalités de cette diffusion seront définies en concertation entre le 
pouvoir organisateur et le comité de l''association de parents. 
 
Toute décision de refus de diffusion de documents émanant de 
l''association de parents prise par le pouvoir organisateur doit faire l''objet d''une 
motivation auprès de l''association de parents. 
 
Le contenu des documents diffusés par l''association de parents doit 
notamment respecter les dispositions relatives à la protection de la vie privée 
et doit s''interdire de toute propagande, de toute activité commerciale ou toute 
attitude relevant de la concurrence déloyale entre les écoles, conformément à 
l''article 1.7.3-3. Dans les écoles concernées, il doit respecter les obligations 
liées à la neutralité définie par le Titre 7, Chapitre 4, du présent Code. 
 
TITRE VI. - De la gouvernance du système éducatif 
 
CHAPITRE 1er. - Du pilotage du système éducatif 
 
Section Ière. - De la Commission de pilotage');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 120, 'Article 1.', 'Article 1.6.1-1. - II est créé une Commission de pilotage de 
l''enseignement fondamental et secondaire. 
 
Les missions, le fonctionnement et la composition de la Commission de 
pilotage sont déterminés par le décret du 27 mars 2002 relatif au pilotage du 
système éducatif de la Communauté française. 
 
 
 
 
Docu 49466 
 
Code 03-05-2019 
Section II. - De la Cellule intermédiaire de coordination 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 121, 'Article 1. (partie 1)', 'Article 1.6.1-2. - § 1er. Il est créé au sein du Ministère une Cellule intermédiaire de coordination dont les membres sont: 1° le fonctionnaire général en charge de la Direction générale du Pilotage du Système éducatif ou son délégué; 2° l''Inspecteur général coordonnateur du Service général de l''Inspection ou son délégué; 3° le Délégué coordonnateur. La Cellule intermédiaire de coordination: 1° assure la coordination entre le Service général de l''Inspection et le Service général du Pilotage des Ecoles et des Centres psycho-médico-sociaux, ainsi que son rôle de coordination entre les deux Services généraux précités et les services et directions qui sont placés au sein de la Direction générale du Pilotage du Système éducatif; 2° exerce les missions qui lui sont confiées par le décret du 10 janvier 2019 relatif au Service général de l''Inspection; 3° exerce les missions qui lui sont confiés par le décret du 13 septembre 2018 portant création du Service général de pilotage des Ecole et des Centres psycho-médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs; 4° exerce toute autre mission qui lui est confiée par le Gouvernement. § 2. La Cellule intermédiaire de coordination fixe son règlement d''ordre intérieur. Il est approuvé par le Gouvernement. Il prévoit au moins que: 1° le fonctionnaire en charge de la Direction générale du Pilotage du Système Educatif ou son délégué la préside et en fixe l''ordre du jour; 2° la Cellule intermédiaire de coordination se réunit au moins une fois par mois sauf pendant les mois de juillet et aout et prévoit les modalités de concertation en urgence, notamment dans les cas des missions d''investigation et des missions de contrôle spécifiques; 3° les décisions sont prises dans le respect de la règle du consensus; 4° lorsque la Cellule intermédiaire de coordination exerce une mission visée au paragraphe 1er, alinéa 2, 2°, le Délégué coordonnateur du Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux ou son délégué siège en qualité d''observateur; 5° lorsque la Cellule intermédiaire de coordination exerce une mission visée au paragraphe 1er, alinéa 2, 3°, l''Inspecteur général coordonnateur du Service général de l''Inspection ou son délégué siège en qualité d''observateur; 6° si la Cellule intermédiaire de coordination exerce une mission liée aux articles 4, § 2 et 5, [1°, 2° et 3°]30 5, § 2, 3, et 8, 6, § 1er et 4, et 7, § 2 et 5, du décret du 10 janvier 2019 relatif au Service général de l''Inspection, elle invite le Directeur de la Direction des standards éducatifs et des évaluations ainsi que le fonctionnaire général en charge du Service général de l''analyse et de la prospective qui siègent en tant qu''observateurs; 7° si la Cellule intermédiaire de coordination exerce une mission liée aux articles 5, § 1er, 5°, et 7, § 1er, 4, du décret du 13 septembre 2018 portant création du Service général de pilotage des écoles et Centres psycho-médico- sociaux et fixant le statut des directeurs de zone et délégués au contrat d''objectifs, elle invite le Directeur de la Direction des standards éducatifs et 30Inséré par le D. 18-04-2024 Docu 49466 Code 03-05-2019 des évaluations ainsi que le fonctionnaire général en charge du Service général de l''analyse et de la prospective qui siègent en tant qu''observateurs ; [8° si la Cellule intermédiaire de coordination exerce une mission liée à l''article 4, §5, 4°, du décret du 10 janvier 2019 relatif au Service général de l''Inspection, elle invite le fonctionnaire général en charge du Service général du Numérique éducatif ou son délégué, qui siège en tant qu''observateur.]31 [Section 3 - Des études scientifiques et des initiatives contribuant à l''amélioration de la qualité du système éducatif]32 [Article 1.6.1-3.]33 - Pour l''application de la présente section, il y a lieu d''entendre par : 1° « établissement d''enseignement supérieur » : les Universités, les Hautes Ecoles et les Ecoles supérieures des Arts visées par les articles 10 à 12 du décret du 07 novembre 2013 définissant le paysage de l''enseignement supérieur et l''organisation académique des études ; 2° « enquête internationale » : toute enquête comparative organisée à l''échelle internationale et visant à mesurer les acquis des élèves, les pratiques des enseignants ou le fonctionnement des systèmes éducatifs ; 3° « étude scientifique » : toute étude ou recherche menée par un établissement d''enseignement supérieur ou un organisme de recherche reconnu, contribuant à l''évaluation, au pilotage, ou à l''amélioration du système éducatif. [Article 1.6.1-4.]34 - §1er. Le Gouvernement assure : 1° l''organisation d''études liées à la participation de la Communauté française à des enquêtes internationales, selon les modalités visées au paragraphe 2 ; 2° l''organisation et la mise en œuvre d''un agenda des études scientifiques pour la qualité du système éducatif, selon les modalités visées au paragraphe 3 ; 3° l''organisation et la mise en œuvre d''un dispositi');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 122, 'Article 1. (partie 2)', 'de pôles d''expertises didactiques et pédagogiques, selon les modalités visées au paragraphe 4. §2. La Communauté française, par son Ministère ou le Gouvernement, participe à des enquêtes internationales menées auprès des élèves, des parents d''élèves et des membres du personnel de l''enseignement. A cette fin, le Gouvernement définit les modalités de participation de la Communauté française aux instances stratégiques internationales de pilotage des enquêtes. Les Services du Gouvernement assurent le suivi de la mise en œuvre de cette participation, préparent et publient les rapports des enquêtes internationales. 31Inséré par le D. 18-04-2024 32Inséré par le D. 17-12-2025 33Inséré par le D. 17-12-2025 34Inséré par le D. 17-12-2025 Docu 49466 Code 03-05-2019 Le Gouvernement organise les études liées à la participation de la Communauté française aux enquêtes internationales en vue de mesurer, d''analyser et de comparer les différentes dimensions de la qualité des systèmes éducatifs. Le Gouvernement assure le financement lié à la participation de la Communauté française aux enquêtes internationales et octroie des subventions ou des dotations aux établissements d''enseignement supérieur désignés pour réaliser les études qui y sont liées. Le Gouvernement arrête : 1° les modalités de sélection des établissements d''enseignement supérieur et les modalités de conclusion des conventions ou partenariats qui visent à assurer la participation aux enquêtes internationales et aux études qui en découlent conformément aux protocoles méthodologiques prévus par les organisations ou associations internationales ; 2° les modalités d''octroi, d''utilisation et de justification des subventions ou des dotations ; 3° les modalités permettant d''assurer la supervision et le suivi des enquêtes et études, en fixant notamment les missions, les modalités de fonctionnement et la composition du comité chargé de superviser les enquêtes. §3. Le Gouvernement organise la mise en œuvre d''un agenda des études scientifiques pour contribuer aux objectifs d''amélioration du système éducatif tel que fixé par l''article 1.5.2-2. Ce dispositif porte sur l''organisation d''études qui soutiennent le développement et l''évaluation des politiques éducatives, le recueil de données et d''information, l''analyse qualitative et quantitative et l''innovation dans les domaines éducatifs et pédagogiques, en vue de contribuer à la qualité de l''information dans le domaine des politiques et des pratiques éducatives, et à l''analyse des défis éducatifs et sociétaux. Le Gouvernement peut lancer un appel à projets ou répondre à une demande de subvention ou de dotation. Le Gouvernement, dans la limite des crédits budgétaires, peut octroyer des subventions ou des dotations aux établissements d''enseignement supérieur pour financer les études visées à l''alinéa 1er. 1° les domaines et thèmes de l''agenda ; 2° les modalités d''organisation des appels à projets ou d''introduction des demandes de subventions ou de dotations, les conditions et modalités d''admissibilité des demandes et d''évaluation du projet introduit ; 3° les modalités d''octroi, d''utilisation et de justification de la subvention ou de dotation ; 4° les modalités de gouvernance et de suivi des études, en fixant notamment les missions, les modalités de fonctionnement et la composition de l''instance chargée de piloter et de suivre les études ; 5° les modalités d''évaluation de l''agenda des études scientifiques. Docu 49466 Code 03-05-2019 §4. Le Gouvernement organise un dispositif de pôles d''expertises didactiques et pédagogiques. Ce dispositif porte sur l''organisation des études scientifiques qui visent à expérimenter, au sein d''écoles organisées ou subventionnées par la Communauté française, des outils didactiques et leurs dispositifs pédagogiques et, le cas échéant, en documentant et en démontrant leur efficacité, en vue de contribuer au développement d''un écosystème d''étude en éducation et de diffuser les résultats et contributions d''étude scientifique auprès de la communauté éducative. Tous les deux ans, le Gouvernement fixe le nombre de pôles d''expertises didactiques et pédagogiques à constituer et lance un appel à projets auprès des établissements d''enseignement supérieur. Le Gouvernement, dans la limite des crédits budgétaires, peut octroyer des subventions ou des dotations aux établissements d''enseignement supérieur pour financer le dispositif de pôles d''expertises didactiques et pédagogiques. Le Gouvernement arrête : 1° la liste des domaines et thèmes de l''étude des pôles d''expertises ; 2° les modalités de l''appel à projets, les modalités de constitution du dispositif de pôles d''expertise, les principes et modalités de gouvernance du dispositif de pôles d''expertises ; 3° les modalités d''octroi, d''utilisation et de justification de la subvention ou de la dotation ; 4° les modalités de coordination et d''accompagnement des actions des pôles d''expertises didactiques et pédagogiques, en fixant notamment les missions, les modalité');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 123, 'Article 1. (partie 3)', 'de fonctionnement et la composition du comité chargé de piloter et suivre le dispositif des pôles d''expertise ; 5° les modalités d''évaluation du dispositif de pôles d''expertises didactiques et pédagogiques. [Article 1.6.1-5.]35 - Le Gouvernement, dans la limite des crédits budgétaires, octroie des subventions ou des dotations aux établissements d''enseignement supérieur, aux acteurs du secteur associatif reconnus par la Communauté française œuvrant dans le champ de l''éducation, ou aux organismes de recherche reconnus pour financer des projets qui ont pour objectif d''accompagner, d''analyser, de documenter et, le cas échéant, évaluer les dynamiques de changement et l''innovation au sein de la communauté scolaire, en déployant des dispositifs s''appuyant sur la participation des publics scolaires à des fins d''information, de consultation ou de diffusion de pratiques. Le Gouvernement peut, dans le respect des conditions visées au présent article, lancer un appel à projets ou répondre à une demande de subvention ou de dotation. Le Gouvernement arrête : 35Inséré par le D. 17-12-2025 Docu 49466 Code 03-05-2019 1° les modalités d''organisation des appels à projets et d''introduction des demandes de subvention ou de dotation, les conditions et modalités d''admissibilité des demande et d''évaluation du projet introduit ; 2° les modalités d''octroi, d''utilisation et de justification de la subvention ou de la dotation ; 3° la gouvernance et les modalités d''accompagnement du projet ; 4° les modalités d''évaluation des dispositifs de participation des publics scolaires. [Article 1.6.1-6.]36 - Le Gouvernement dans la limite des crédits budgétaires et dans le cadre du respect des critères fixés au présent aliéna ainsi qu''aux alinéas 3 et 4, octroie des subventions portant sur des initiatives mises en place par les acteurs du secteur associatif qui développent, au sein des écoles organisées ou subventionnées par la Communauté française ou avec ses publics, des activités, des interventions ou des outils, qui soutiennent les apprentissages et le parcours des élèves, le bien-être à l''école et le climat scolaire, les dynamiques éducatives, le soutien aux personnels de l''enseignement, et l''ouverture de l''école sur le monde extérieur. Le Gouvernement peut répondre à une demande de subvention ou lancer un appel à projets. Pour chaque initiative admissible, la sélection se base sur cinq critères : 1° le public ou l''audience touché par le projet qui doit être au bénéfice du plus grand nombre ; 2° le caractère inédit, innovant, original et/ou expérimental développé par le projet en rapport à la législation actuelle ; 3° la justification du montant de la subvention proposée au regard de l''impact attendu du projet et des ressources propres des acteurs associatifs bénéficiaires ; 4° l''adéquation avec au moins une des missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire définies à l''article 1.4.1-1 ; 5° l''adéquation avec au moins un des objectifs d''amélioration du système éducatif prévu à l''article 1.5.2-2. Le Gouvernement arrête : 1° les modalités d''introduction des demandes de subvention, les conditions et modalités d''admissibilité des demandes ainsi que les modalités d''organisation des appels à projets et d''évaluation des initiatives introduites ; 2° les modalités d''octroi, d''utilisation et de justification de la subvention ; 3° la gouvernance et les modalités d''accompagnement des initiatives ; 36Inséré par le D. 17-12-2025 Docu 49466 Code 03-05-2019 4° les modalités d''évaluation des activités, des interventions ou des outils. [Article 1.6.1-7.]37 - Le rapport prévu à l''article 1.5.2-2 intègre une partie spécifique décrivant les contributions des dispositifs visés aux articles 1.6.1- 4, §§ 3 et 4, 1.6.1-5 et 1.6.1-6, aux objectifs d''amélioration du système scolaire visés à l''article 1.5.2-2, alinéa 1er. CHAPITRE II. - De la Commission des référentiels et des programmes du tronc commun et des commissions des programmes Section 1ère. - De la Commission des référentiels et des programmes du tronc commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 124, 'Article 1.', 'Article 1.6.2-1. - § 1er. Il est créé une Commission des référentiels et des 
programmes du tronc commun. 
 
§ 2. En ce qui concerne les référentiels, la Commission des référentiels et 
des programmes du tronc commun veille: 
1° à la bonne application de la charte des référentiels visée à l''article 
1.4.4-1, § 3, en particulier au respect des qualités attendues et des orientations 
fixées par cette dernière; 
2° à la cohérence des référentiels, à la fois entre années et niveaux 
d''enseignement, et entre domaines et disciplines; 
3° à ce que les contenus d''apprentissage et les attendus définissant les 
niveaux de maitrise soient définis pour chaque domaine et discipline; 
4° à ce que les approches transversales et interdisciplinaires du tronc 
commun soient effectivement prises en charge par les groupes de travail qui 
élaborent les référentiels; 
5° au réalisme, à la lisibilité, à la précision et à l''intelligibilité des 
référentiels pour les différents utilisateurs et à la motivation des choix 
effectués; 
6° à la mise en place des comités de lecture en lien avec chaque groupe de 
travail pour l''élaboration des référentiels; 
7° au respect de la liberté des pouvoirs organisateurs en matière de 
méthodes pédagogiques visée à l''article 1.5.1-1. 
 
La Commission des référentiels et des programmes du tronc commun 
exerce un rôle d''arbitrage des différends au sein des groupes de travail ou entre 
ces derniers. 
 
Lorsqu''au terme de leurs travaux, les groupes de travail chargés d''écrire 
un projet de référentiel remettent ces projets de référentiels à la Commission 
des référentiels et des programmes du tronc commun, la Commission des 
référentiels et des programmes du tronc commun peut procéder aux 
modifications qu''elle juge nécessaires avant transmission au Gouvernement 
des projets de référentiels ainsi que de son avis sur ceux-ci. La Commission 
des référentiels motive dans son avis les modifications apportées aux projets 
initiaux des groupes de travail référentiels. 
 
Le président de la Commission des référentiels et des programmes du 
tronc commun fait rapport au Parlement de l''état d''avancement des travaux 
des groupes de travail lorsqu''il en fait la demande. 
 
 
37Inséré par le D. 17-12-2025 
 
 
Docu 49466 
 
Code 03-05-2019 
[Lorsque le Comité de monitoring des référentiels visé à l''article 2.6.1-2, 
§1er suggère des propositions de modifications d''un ou plusieurs référentiel(s) 
dans son rapport annuel, le Gouvernement peut, tout en se basant également 
sur l''avis de la Commission de pilotage visée à l''article 1.6.1-1, et s''il l''estime 
pertinent, charger la Commission des référentiels et des programmes de 
proposer des adaptations aux référentiels adoptés conformément à l''article 
1.4.4-1, §1er , accompagnées d''un avis motivé. Lorsque la Commission des 
référentiels et des programmes propose des adaptations qui s''écartent de la 
proposition initiale, elle les motive également dans son avis.]38 
 
[Les référentiels du tronc commun ainsi modifiés sont adoptés 
conformément à la procédure prévue à l`article 1.4.4-1, §1er.]39 
 
§ 3. En ce qui concerne les programmes, la Commission des référentiels 
et des programmes du tronc commun vérifie si les programmes d''études 
permettent d''atteindre les attendus définis dans les référentiels de 
compétences initiales et du tronc commun visés au Titre 4, Chapitre 2. 
 
Elle vérifie, pour l''enseignement spécialisé de forme 4, que les 
programmes d''études permettent aux élèves à besoins spécifiques d''évoluer de 
manière optimale. 
 
Le contrôle de la Commission des référentiels et des programmes du tronc 
commun ne porte pas sur les méthodes pédagogiques. 
 
Complété par D. 18-12-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 125, 'Article 1.', 'Article 1.6.2-2. - La Commission des référentiels et des programmes du 
tronc commun est présidée par l''Administrateur général de l''Administration 
Générale de l''Enseignement ou une personne désignée par celui-ci. 
 
Elle est composée comme suit: 
1° un représentant du Ministre; 
2° deux représentants du Service général de l''inspection en la personne 
de l''Inspecteur général de l''enseignement fondamental et de l''Inspecteur 
général de l''enseignement secondaire; 
3° deux membres de la Direction générale du pilotage du système 
éducatif, participant à la Commission des évaluations visée à l''article 1.6.4-1; 
4° sept représentants des pouvoirs organisateurs dont: 
 a) trois représentants des pouvoirs organisateurs visés à l''article 1.6.5-
2, § 1er, alinéa 5, 3°; 
 b) un représentant des pouvoirs organisateurs visés à l''article 1.6.5-
2, § 1er, alinéa 5, 4°; 
 c) un représentant les pouvoirs organisateurs visés à l''article 1.6.5-
2, § 1er, alinéa 5, 1°; 
 d) un représentant les pouvoirs organisateurs visés à l''article 1.6.5-
2, § 1er, alinéa 5, 2°; 
 e) un représentant de Wallonie-Bruxelles - Enseignement; 
5° cinq experts issus des établissements d''enseignement supérieur ayant 
une expérience ou une compétence en matière de curriculums scolaires ou dans 
l''un des domaines visés à l''article 1.4.2-3, 1° à 5°. 
 
Les membres visés à l''alinéa 2, 5°, sont désignés sur proposition du 
Ministre. 
 
38Inséré par le D. 18-04-2024 
39Inséré par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019 
Les membres de la Commission des référentiels et des programmes du 
tronc commun sont désignés par le Gouvernement. A l''exception des experts, 
pour chaque membre effectif, il est désigné un membre suppléant. 
 
Les membres visés à l''alinéa 2, 4° et 5°, sont remboursés de leurs frais de 
déplacement selon les modalités établies par le Gouvernement. 
 
La Commission des référentiels et des programmes du tronc commun 
peut organiser ses travaux en créant des groupes spécifiques.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 126, 'Article 1.', 'Article 1.6.2-3. - La Commission des référentiels et des programmes du 
tronc commun établit ses règles de fonctionnement, dans le respect des 
modalités établies par le Gouvernement et sans préjudice de l''article 1.4.4-2. 
 
La Commission des référentiels et des programmes du tronc commun 
peut auditionner à son initiative les comités de lecture. 
 
Lorsque la Commission des référentiels et des programmes du tronc 
commun émet un avis sur un programme, elle prend ses décisions à la majorité 
des deux tiers. Les membres visés à l''article 1.6.2-2, alinéa 2, 4°, ne participent 
pas à la prise de décision. Ils peuvent s''ils le souhaitent être entendu à titre 
consultatif. 
 
Section II. - Des commissions des programmes');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 127, 'Article 1.', 'Article 1.6.2-4. -  Il est créé une Commission des programmes pour la 
section de transition du degré supérieur de l''enseignement secondaire 
ordinaire, une Commission des programmes pour la section de qualification du 
degré supérieur de l''enseignement secondaire ordinaire et une Commission des 
programmes de l''enseignement spécialisé. 
 
Les commissions des programmes vérifient si les programmes d''études 
sont de nature à permettre d''atteindre les attendus définis dans les 
référentiels correspondants. 
 
Le contrôle des commissions des programmes ne porte pas sur les 
méthodes pédagogiques.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 128, 'Article 1.', 'Article 1.6.2-5. -  Chaque commission des programmes comprend: 
1° huit membres désignés par le Ministre sur proposition du Conseil 
général de l''enseignement secondaire; 
2° deux représentants de l''inspection désignés par le Ministre sur 
proposition des inspecteurs généraux; 
3° un délégué de l''Administration générale de l''enseignement, désigné 
par le Ministre sur proposition de l''Administrateur général de l''enseignement, 
qui préside la Commission. 
 
Les mandats sont d''une durée de quatre ans. Ils sont renouvelables.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 129, 'Article 1.', 'Article 1.6.2-6. - Chaque commission de programme établit ses règles de 
fonctionnement, dans le respect des modalités établies par le Gouvernement. 
Les avis des commissions des programmes sont adoptés à la majorité des deux 
tiers. 
 
 
 
Docu 49466 
 
Code 03-05-2019 
[CHAPITRE III. - Des évaluations externes non certificatives]40 
 
Section Ière. - Définition et objectifs 
 
Modifié par D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 130, 'Article 1. / Article 1.', 'Article 1.6.3-1. -  Les écoles sont tenues de soumettre leurs élèves aux 
évaluations externes non certificatives qui les concernent.

Article 1.6.3-2. - Les évaluations externes non certificatives portent sur 
la maitrise des savoirs, savoir-faire et des compétences tels que définis dans 
les référentiels visés aux articles 1.4.2-2, 1.4.3-1 et 1.4.3-2.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 131, 'Article 1.', 'Article 1.6.3-3. -  Les évaluations externes non certificatives informent 
sur le niveau d''avancement des élèves, en poursuivant au moins un des 
objectifs suivants: 
1° permettre à chaque équipe pédagogique d''apprécier l''efficacité de son 
action en établissant l''état des acquis de ses élèves par rapport aux attendus 
annuels et en situant les résultats de ses élèves par rapport aux résultats 
globaux des élèves fréquentant l''ensemble des écoles organisées ou 
subventionnées par la Communauté française et, le cas échéant sur demande 
du pouvoir organisateur auprès du délégué au contrat d''objectifs, par rapport 
aux résultats fournis par indice socio-économique en quartile; 
2° permettre d''apprécier également l''efficacité de cette action au niveau 
de chaque zone; 
3° informer les autorités et l''ensemble des acteurs sur les acquis des 
élèves d''une année d''étude ou d''un âge donné fréquentant l''ensemble des écoles 
organisées ou subventionnées par la Communauté française; 
4° informer les autorités et l''ensemble des acteurs sur l''évolution des 
acquis de cohortes d''élèves à différents moments du cursus scolaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 132, 'Article 1.', 'Article 1.6.3-4. -  Sans préjudice des dispositions définies à l''article 1.6.3-
14, § 1er, alinéa 5, les résultats des élèves et des écoles aux évaluations 
externes non certificatives sont maintenus anonymes sauf pour l''école 
concernée, les cellules de soutien et d''accompagnement, et le Service général 
de pilotage des écoles et des Centres psycho-médico-sociaux, sans préjudice des 
dispositions prévues à l''article 1.6.3-15, § 2. 
 
Il est interdit d''en faire état, notamment à des fins de publicité ou de 
concurrence entre écoles. 
 
Les résultats obtenus à l''évaluation externe non certificative ne peuvent 
permettre aucun classement des élèves ou des écoles à l''exception des besoins 
résultant de l''application pour les services du Gouvernement des dispositions 
décrétales et règlementaires. 
 
Les membres du service général de l''inspection, les membres du Service 
général de pilotage des écoles et des Centres psycho-médico-sociaux, les agents 
de l''Administration Générale de l''Enseignement, les membres des cellules de 
soutien et d''accompagnement, les membres du personnel et les pouvoirs 
organisateurs des écoles qui ont connaissance des résultats obtenus à 
l''évaluation externe non certificative sont tenus à cet égard par le secret 
professionnel. En cas d''infraction, l''article 458 du Code pénal s''applique. 
 
40Ce chapitre est remplacé par le D. 04-12-2025 (voir en dessous) et entre en vigueur le 24 
août 2026. 
 
 
Docu 49466 
 
Code 03-05-2019 
Le non-respect de l''interdiction de divulgation constitue une pratique 
déloyale au sens de l''article 1.7.3-3. 
 
Section II. - Organisation 
 
Modifié par D. 24-02-2022 ; D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 133, 'Article 1.', 'Article 1.6.3-5. -  § 1er. En ce qui concerne le Tronc commun défini à 
l''article 1.2.1-5, tous les cinq ans, sur proposition de la Commission des 
évaluations instituée par l''article 1.6.4-1 et sur avis de la Commission de 
pilotage dont les missions sont visées à l''article 3 du décret du 27 mars 2002 
relatif au pilotage du système éducatif de la Communauté française, le 
Gouvernement arrête un plan quinquennal qui présente le calendrier de 
l''ensemble des évaluations externes non certificatives organisées pour 
l''ensemble des élèves de troisième et cinquième années de l''enseignement 
primaire, en précisant: 
1° les évaluations externes non certificatives qui portent sur l''ensemble 
des écoles et celles qui portent sur un échantillon représentatif d''entre elles; 
2° les disciplines ou parties de disciplines visées ainsi que les années 
d''études ou les classes d''âge concernées; 
3° le temps de passation et de correction alloué à chaque évaluation; 
4° s''il échet, les types et les formes d''enseignement spécialisé visés. 
 
Le plan quinquennal prévoit au minimum une évaluation chaque année 
pour les élèves de troisième et cinquième années de l''enseignement primaire. 
 
§ 2. […]41 
 
§ 3. Les élèves sont soumis aux évaluations externes non certificatives 
visées aux paragraphes 1er et 2, entre le 1er et le 31 octobre de la même année 
scolaire. 
 
L''ensemble des élèves concernés sont soumis durant la même période à 
chacune des évaluations visées à l''alinéa 1er. 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 134, 'Article 1.', 'Article 1.6.3-6. - § 1er. Pour la conception de chaque évaluation externe 
non certificative, le Gouvernement crée un groupe de travail remplissant ses 
missions sous la coordination de la Commission des évaluations visée à l''article 
1.6.4-1. Il est composé de la manière suivante: 
1° le président de la Commission des évaluations ou son délégué, qui 
assure la présidence du groupe de travail; 
2° une équipe de recherche universitaire ou inter-universitaire; 
3° quatre membres du Service général de l''inspection désignés par le 
Gouvernement sur proposition de l''Administrateur général de l''enseignement; 
4° six enseignants assurant tout ou partie de leur charge dans l''année 
d''étude concernée par l''évaluation, désignés par le Gouvernement sur 
proposition, en ce qui concerne l''enseignement subventionné, des fédérations 
de pouvoirs organisateurs et après accord de leur pouvoir organisateur, et, en 
ce 
qui 
concerne 
l''enseignement 
organisé, 
de 
Wallonie-Bruxelles 
Enseignement; 
 
41Abrogé par le D. 04-12-2025 
 
 
Docu 49466 
 
Code 03-05-2019 
5° un ou des membre(s) des cellules de soutien et d''accompagnement 
désignés par le Gouvernement sur proposition de Wallonie-Bruxelles 
Enseignement ou de la fédération de pouvoirs organisateurs dont ils relèvent. 
 
En ce qui concerne l''enseignement primaire, les enseignants visés à 
l''alinéa 1er, 4°, sont répartis comme suit: trois enseignants exerçant tout ou 
partie de leur charge dans l''enseignement officiel subventionné, deux 
enseignants exerçant tout ou partie de leur charge dans l''enseignement libre 
et un enseignant exerçant tout ou partie de sa charge dans l''enseignement 
organisé par la Communauté française. 
 
En ce qui concerne l''enseignement secondaire, les enseignants visés à 
l''alinéa 1er, 4°, sont répartis comme suit: un ou deux enseignant(s) exerçant 
tout ou partie de leur charge dans l''enseignement officiel subventionné, trois 
enseignants exerçant tout ou partie de leur charge dans l''enseignement libre 
et deux ou un enseignant(s) exerçant tout ou partie de leur charge dans 
l''enseignement organisé par la Communauté française. 
 
Ces enseignants sont chargés d''une mission au sens du décret du 24 juin 
1996 portant règlementation des missions, des congés pour mission et des 
mises en disponibilité pour mission spéciale dans l''enseignement organisé ou 
subventionné par la Communauté française. 
 
Le Gouvernement fixe les modalités de détachement des enseignants qui 
participent aux groupes de travail chargés des épreuves externes non 
certificatives. 
 
En ce qui concerne l''enseignement primaire, les membres visés à l''alinéa 
1er, 5°, sont répartis comme suit: trois membres issus de la cellule de soutien 
et d''accompagnement de l''enseignement officiel subventionné, deux membres 
issus d''une cellule de soutien et d''accompagnement de l''enseignement libre 
subventionné et un membre issu de la cellule de soutien et d''accompagnement 
de l''enseignement organisé par la Communauté française. 
 
En ce qui concerne l''enseignement secondaire, les membres visés à 
l''alinéa 1er, 5°, sont répartis comme suit: un ou deux membre(s) issu(s) de la 
cellule 
de 
soutien 
et 
d''accompagnement 
de 
l''enseignement 
officiel 
subventionné, 
trois 
membres 
issus 
d''une 
cellule 
de 
soutien 
et 
d''accompagnement de l''enseignement libre subventionné et deux ou un 
membre(s) issu(s) de la cellule de soutien et d''accompagnement de 
l''enseignement organisé par la Communauté française. 
 
Si Wallonie-Bruxelles Enseignement ou si une fédération de pouvoirs 
organisateurs ne propose pas de représentant ou l''entièreté des représentants 
qu''elle doit proposer, le groupe de travail est néanmoins réputé correctement 
constitué. 
 
Le secrétariat du groupe de travail est assuré par un agent de 
l''Administration générale de l''enseignement. 
 
§ 2. Les enseignants chargés d''une mission telle que définie au 
paragraphe 1er du présent article sont remboursés de leurs frais de 
déplacement selon les modalités mises en oeuvre par le Gouvernement. 
 
Modifié par D. 24-02-2022 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 135, 'Article 1.', 'Article 1.6.3-7. - Chaque groupe de travail, pour ce qui concerne 
l''évaluation externe non certificative dont il est en charge, remplit les missions 
suivantes: 
1° élaboration de l''épreuve permettant l''évaluation externe non 
certificative; 
2° conception de l''information relative à l''épreuve précitée; 
3° définition des consignes de passation et de correction de l''épreuve; 
4° production d''un questionnaire socioculturel destiné à l''élève et d''un 
questionnaire relatif aux pratiques pédagogiques destiné à l''enseignant; 
5° la production de pistes didactiques en lien avec l''évaluation externe 
non certificative.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 136, 'Article 1.', 'Article 1.6.3-8. - Les membres des groupes de travail et les équipes de 
recherche universitaire ainsi que toute autre personne qui serait associée aux 
travaux sont tenus au secret professionnel quant au contenu des épreuves - 
hors les communications autorisées selon les modalités fixées par le 
Gouvernement. En cas d''infraction, l''article 458 du Code pénal s''applique.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 137, 'Article 1. / Article 1.', 'Article 1.6.3-9. - L''Administration générale de l''enseignement est 
chargée de l''organisation des épreuves.

Article 1.6.3-10. - Le respect des consignes et des modalités de passation 
est placé sous la responsabilité du directeur de l''école. Celui-ci est tenu à la 
confidentialité quant au contenu des épreuves jusqu''au moment de la 
passation. 
 
Le respect des consignes et des modalités de correction est placé sous la 
responsabilité de chaque inspecteur pour les écoles au sein desquelles il exerce 
ses missions. 
 
Dans ce cadre, il veille à organiser une répartition des protocoles 
complétés par les élèves de telle façon qu''un enseignant n''ait pas à corriger les 
protocoles complétés par les élèves dont il a la charge ni, sauf situation 
exceptionnelle, ceux complétés par les élèves fréquentant une école au sein 
duquel il exerce sa fonction. 
 
Tous les enseignants concernés procèdent aux corrections des évaluations 
externes non certificatives. 
 
Lorsqu''ils participent aux corrections, les enseignants sont considérés 
comme étant en activité de service. 
 
Les écoles transmettent les résultats des évaluations externes non 
certificatives de leurs élèves à l''Administration générale de l''Enseignement 
selon les modalités fixées par elle. 
 
 
 
Modifié par D. 24-02-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 138, 'Article 1.', 'Article 1.6.3-11. -  § 1er. Le groupe de travail est chargé de l''analyse et 
de la présentation des résultats de l''évaluation externe non certificative dont 
il a été chargé. 
 
Cette présentation doit permettre d''apprécier tant le niveau de maitrise 
de l''ensemble des savoirs, savoir-faire et des compétences évalués que celui de 
 
 
Docu 49466 
 
Code 03-05-2019 
chacun d''entre eux, en prenant non seulement en considération le niveau 
moyen, mais aussi la dispersion des résultats entre élèves et entre écoles. 
 
Cette présentation doit également permettre d''apprécier le niveau de 
maitrise atteint par les élèves en tenant compte des spécificités des publics 
scolaires. 
 
Cette présentation doit permettre que soit rendue possible la disposition 
définie à l''article 1.6.3-14, § 1er, alinéa 5. 
 
Cette présentation ne doit en aucun cas permettre l''identification des 
élèves ou des écoles. 
 
§ 2. Le groupe de travail est chargé de la production de pistes didactiques 
en lien avec l''évaluation externe non certificative dont il a été chargé. 
 
Ce document doit aider les équipes pédagogiques à analyser les réponses 
et productions de leurs élèves face aux items qui faisaient partie de 
l''évaluation externe non certificative et à améliorer la maitrise des savoirs, 
savoir-faire et des compétences évalués notamment à travers la mise en place 
d''activités permettant de remédier aux erreurs constatées.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 139, 'Article 1.', 'Article 1.6.3-12. - Les résultats et l''analyse des évaluations externes non 
certificatives sont remis par les présidents des groupes de travail au président 
de la Commission de pilotage. 
 
Section III. - Exploitation des résultats');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 140, 'Article 1.', 'Article 1.6.3-13. - Le rapport et l''analyse des évaluations externes non 
certificatives sont remis par le président de la Commission de pilotage au 
Gouvernement. 
 
Sur la base des résultats de chaque évaluation externe non certificative, 
la Commission de pilotage adresse au Gouvernement un avis reprenant, le cas 
échéant, les recommandations susceptibles d''améliorer ces résultats.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 141, 'Article 1.', 'Article 1.6.3-14. - § 1er. Outre les résultats relatifs à l''ensemble de ses 
élèves ainsi qu''à chacun d''entre eux, chaque pouvoir organisateur et chaque 
école disposent des résultats globalisés de l''ensemble des élèves de la 
Communauté française qui lui sont communiqués sous la présentation visée à 
l''article 1.6.3-11, par l''Administration générale de l''enseignement et le cas 
échéant sur demande du pouvoir organisateur auprès du délégué au contrat 
d''objectifs, par indice socio-économique en quartile. 
 
Les membres du personnel et les pouvoirs organisateurs des écoles qui 
ont connaissance des résultats obtenus à l''évaluation externe non certificative 
sont tenus à cet égard par le secret professionnel. En cas d''infraction, l''article 
458 du Code pénal s''applique. 
 
La communication des résultats commentés de l''évaluation externe non 
certificative est suivie de propositions qui peuvent prendre la forme d''outils 
pédagogiques visant à répondre aux difficultés décelées. 
 
Chaque pouvoir organisateur ou son délégué veille à ce qu''il soit procédé 
à un travail d''analyse et d''exploitation des résultats avec, le cas échéant, l''aide 
du service de soutien et d''accompagnement de l''enseignement organisé par la 
 
 
Docu 49466 
 
Code 03-05-2019 
Communauté française ou des fédérations de pouvoirs organisateurs, selon le 
cas. L''exploitation des résultats consiste notamment dans la construction et la 
mise en oeuvre de stratégies pédagogiques ou organisationnelles susceptibles 
d''améliorer ces résultats. 
 
Chaque pouvoir organisateur ou son délégué veille à ce que chaque parent 
ait accès aux résultats de l''enfant dont il a la charge par rapport aux résultats 
globalisés de l''ensemble des élèves de la Communauté française. 
 
§ 2. Les résultats rendus anonymes sont également établis au niveau de 
l''ensemble des écoles d''une même zone et transmis aux conseils de zone.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 142, 'Article 1.', 'Article 1.6.3-15. - § 1er. Chaque école met les résultats de ses élèves à 
disposition des membres du Service général de pilotage des écoles et des 
Centres psycho-médico-sociaux, des services d''inspection concernés et de la 
cellule de soutien et d''accompagnement concernée afin que ceux-ci, outre les 
résultats globalisés de l''ensemble des élèves de la Communauté française, 
disposent de l''ensemble des résultats des élèves de chaque école au sein 
desquelles ils exercent leurs missions. 
 
Les membres du Service général de pilotage des écoles et des Centres 
psycho-médico-sociaux, les inspecteurs et les conseillers au soutien et à 
l''accompagnement qui ont connaissance des résultats obtenus à l''évaluation 
externe non certificative sont tenus à cet égard par le secret professionnel. En 
cas d''infraction, l''article 458 du Code pénal s''applique. 
 
Les services d''inspection concernés et les conseillers au soutien et à 
l''accompagnement veillent à intégrer ces résultats aux apports de leurs 
propres investigations dans le cadre de leurs missions respectives d''évaluation 
du niveau des études et de soutien et d''accompagnement. Ils apportent leur 
appui aux écoles dans l''analyse et l''exploitation des résultats. 
 
§ 2. En ce qui concerne la transmission des résultats des élèves des écoles 
considérées une par une, la transmission à la cellule de soutien et 
d''accompagnement concernée ne concerne que les écoles relevant soit de 
l''enseignement organisé par la Communauté française, soit d''un pouvoir 
organisateur affilié à une fédération de pouvoirs organisateurs. Dans ce 
dernier cas, la transmission est subordonnée à l''accord donné par le pouvoir 
organisateur. Le Gouvernement définit les modalités selon lesquelles le 
pouvoir organisateur fait part de cet accord. 
 
Section IV. - Des mesures de protection de la confidentialité du 
contenu des épreuves externes non certificatives');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 143, 'Article 1.', 'Article 1.6.3-16. - Les membres des services du Gouvernement et du 
Service général de l''inspection sont tenus au secret professionnel quant au 
contenu des épreuves permettant les évaluations externes non certificatives et 
certificatives. 
 
L''agent qui aura divulgué tout ou partie du contenu de ces épreuves avant 
la finalisation desdites épreuves par les élèves - hors les communications 
autorisées selon les modalités fixées par le Gouvernement - commettra une 
infraction. En cas d''infraction, l''article 458 du Code pénal s''applique. 
 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 144, 'Article 1.', 'Article 1.6.3-17. - Le directeur, les membres du personnel travaillant 
dans les écoles et, le cas échéant, le personnel sous contrat de bénévolat 
exerçant des prestations dans les écoles sont tenus au secret professionnel 
quant au contenu des épreuves externes et à toutes les informations qui 
permettent d''y accéder. En cas de violation de l''obligation de secret, l''article 
458 du Code pénal s''applique.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 145, 'Article 1. (partie 1)', 'Article 1.6.3-18. - Toute personne qui aura ouvert- en violation des consignes et modalités de passation - un paquet scellé contenant un ou plusieurs exemplaires des épreuves avant son utilisation dans le cadre desdites épreuves sera punie des mêmes peines que celles prévues à l''article 460 du Code pénal. Toute personne qui aura, avant son utilisation dans le cadre des épreuves, recelé, reçu en échange ou à titre gratuit, possédé sous quelque forme que ce soit, acheté, reproduit ou transféré par quelque moyen que ce soit tout ou partie du contenu de ces épreuves sans y avoir été autorisé par le Gouvernement ou son délégué sera punie des mêmes peines. [Chapitre III. - De l''évaluation externe diagnostique « CLÉ » (Calculer, Lire, Ecrire)]42 [Section 1ère. - Définition et objectifs]43 [Article 1.6.3-1.]44 - Les écoles d''enseignement ordinaire sont tenues de soumettre leurs élèves de quatrième année primaire à l''évaluation externe diagnostique. L''évaluation externe est également accessible aux élèves de l''enseignement spécialisé sur décision du conseil de classe. [Article 1.6.3-2.]45 - L''évaluation externe porte nécessairement sur la maitrise des savoirs, savoir- faire et des compétences en mathématiques et en français tels que définis dans les référentiels du tronc commun visés à l''article 1.4.2-2. [Article 1.6.3-3.]46 - L''évaluation externe diagnostique est une évaluation non-certificative. Elle informe sur le niveau d''avancement des élèves, en poursuivant les objectifs suivants : 1° permettre à chaque équipe pédagogique d''apprécier l''efficacité de son action en établissant l''état des acquis de ses élèves par rapport aux attendus annuels et en situant les résultats de ses élèves par rapport aux résultats globaux des élèves fréquentant l''ensemble des écoles organisées ou subventionnées par la Communauté française et par rapport aux résultats des écoles de même catégorie d''indice socio- économique ; 2° permettre à chaque équipe pédagogique d''identifier les élèves en difficulté afin de mettre en place, le cas échéant, un accompagnement personnalisé ; 3° informer les autorités et l''ensemble des acteurs sur les acquis des élèves d''une année d''étude ou d''un âge donné fréquentant l''ensemble des écoles organisées ou subventionnées par la Communauté française. 42Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 43Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 44Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 45Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 46Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 Docu 49466 Code 03-05-2019 [Article 1.6.3-4.]47 - Sans préjudice des articles 1.6.3-13 et 1.6.3-15, alinéa 4, les résultats des élèves et des écoles à l''évaluation externe diagnostique sont maintenus anonymes sauf pour les membres du personnel de l''école concernée, les cellules de soutien et d''accompagnement, et le Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux, et sans préjudice de la transmission prévue à l''article 1.6.3-16, §2. Il est interdit d''en faire état, notamment à des fins de publicité ou de concurrence entre écoles. Les résultats obtenus à l''évaluation externe diagnostique ne peuvent permettre aucun classement des élèves ou des écoles. Les membres du Service général de l''Inspection, les membres du Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux, les agents de l''Administration générale de l''Enseignement, les membres des cellules de soutien et d''accompagnement, les membres du personnel et les Pouvoirs organisateurs des écoles qui ont connaissance des résultats obtenus à l''évaluation externe diagnostique sont tenus à cet égard par le secret professionnel. En cas d''infraction, l''article 352 du Code pénal s''applique. Le non-respect par les Pouvoirs organisateurs des écoles et les membres du personnel du secret professionnel visé à l''alinéa précédent constitue une pratique déloyale au sens de l''article 1.7.3-3. [Section 2. – Organisation]48 [Article 1.6.3-5.]49 - Sur proposition de la Commission des évaluations visée à l''article 1.6.4-1, le Gouvernement arrête la liste des parties de disciplines visées et le temps de passation alloué à l''évaluation externe diagnostique. Les élèves visés à l''article 1.6.3-1 sont soumis à l''évaluation externe diagnostique entre le 15 septembre et le 1er octobre. [Article 1.6.3-6.]50 - Pour la conception de l''évaluation externe diagnostique, le Gouvernement crée un groupe de travail sur proposition de la Commission des évaluations visée à l''article 1.6.4-1, qui remplit ses missions sous la coordination de ladite Commission des évaluations. Il est composé de la manière suivante : 1° le Président de la Commission des évaluations ou son délégué, qui assure la présidence du groupe de travail ; 2° quatre membres du Service général de l''Inspection désignés par le Gouvernement sur proposition de l''Administrateur général de l''Enseignement ; 3°');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 146, 'Article 1. (partie 2)', 'six enseignants assurant tout ou partie de leur charge dans l''enseignement primaire, désignés par le Gouvernement sur proposition, en ce qui concerne l''enseignement subventionné, des fédérations de pouvoirs organisateurs après accord de leur Pouvoir organisateur, et, en ce qui concerne l''enseignement organisé, de Wallonie-Bruxelles Enseignement ; 4° six membres des cellules de soutien et d''accompagnement désignés par le Gouvernement sur proposition de Wallonie-Bruxelles Enseignement ou de la fédération de pouvoirs organisateurs dont ils relèvent. 47Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 48Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 49Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 50Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 Docu 49466 Code 03-05-2019 Les enseignants visés à l''alinéa 2, 3°, sont chargés d''une mission au sens du décret du 24 juin 1996 portant règlementation des missions, des congés pour mission et des mises en disponibilité pour mission spéciale dans l''enseignement organisé ou subventionné par la Communauté française. Le Gouvernement fixe les modalités de détachement des enseignants qui participent au groupe de travail chargé de l''évaluation externe diagnostique. Les enseignants visés à l''alinéa 2, 3°, sont répartis comme suit : trois enseignants exerçant tout ou partie de leur charge dans l''enseignement officiel subventionné, deux enseignants exerçant tout ou partie de leur charge dans l''enseignement libre subventionné et un enseignant exerçant tout ou partie de sa charge dans au sein de Wallonie-Bruxelles Enseignement. Le groupe de travail comprendra trois membres issus de la cellule de soutien et d''accompagnement de l''enseignement officiel subventionné, deux membres issus d''une cellule de soutien et d''accompagnement de l''enseignement libre subventionné et un membre issu de la cellule de soutien et d''accompagnement de Wallonie-Bruxelles Enseignement. Si Wallonie-Bruxelles Enseignement ou une fédération de pouvoirs organisateurs ne propose pas de représentant ou ne propose pas la totalité des représentants qu''elle doit proposer selon l''alinéa 2, 3° et 4°, le groupe de travail est néanmoins réputé correctement constitué. Le secrétariat du groupe de travail est assuré par un agent de l''Administration générale de l''Enseignement. Les enseignants chargés d''une mission sont remboursés de leurs frais de déplacement selon les modalités mises en œuvre par le Gouvernement. [Article 1.6.3-7.]51 - Le groupe de travail remplit, sur la base des propositions du sous-groupe de rédaction prévu à l''article 1.6.3-8, les missions suivantes : 1° la validation du projet d''évaluation externe diagnostique ; 2° la validation des consignes de passation et de correction de l''évaluation externe diagnostique ; 3° le cas échéant, la validation du questionnaire socioculturel destiné à l''élève et du questionnaire relatif aux pratiques pédagogiques destiné à l''enseignant ; 4° le cas échéant, la validation des pistes didactiques au vu des résultats de l''évaluation externe diagnostique. Ce document doit aider les équipes pédagogiques à analyser les réponses et productions de leurs élèves face aux items qui faisaient partie de l''évaluation externe diagnostique et à améliorer la maitrise des savoirs, savoir-faire et des compétences évalués. [Article 1.6.3-8.]52 - Un sous-groupe chargé de la rédaction de l''évaluation externe diagnostique est créé au sein du groupe de travail, selon les modalités fixées par la Commission des évaluations visée à l''article 1.6.4-1. Le sous-groupe de rédaction est constitué des enseignants visés à l''article 1.6.3-6, alinéa 2, 3° et le cas échéant d''une équipe de recherche universitaire, sous la responsabilité du Président de la Commission des évaluations ou de son délégué. Ce sous-groupe remplit les missions suivantes : 1° la rédaction de propositions de questions ou d''items de l''évaluation externe diagnostique ; 51Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 52Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 Docu 49466 Code 03-05-2019 2° la proposition de consignes de passation et de correction de l''évaluation externe diagnostique ; 3° le cas échéant, la production d''une proposition de questionnaire socioculturel destiné à l''élève et d''une proposition de questionnaire relatif aux pratiques pédagogiques destiné à l''enseignant ; 4° le cas échéant, la rédaction de propositions de pistes didactiques. [Article 1.6.3-9.]53 - Les Services du Gouvernement sont chargés de l''analyse et de la présentation des résultats de l''évaluation externe diagnostique. Cette présentation doit permettre d''apprécier tant le niveau de maitrise de l''ensemble des savoirs, savoir-faire et des compétences évalués que celui de chacun d''entre eux, en prenant notamment en considération le niveau moyen mais aussi la dispersion des résultats entre élèves et entre écoles. Cette présentation doit également pe');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 147, 'Article 1. (partie 3)', 'd''apprécier le niveau de maitrise atteint par les élèves en tenant compte des spécificités des publics scolaires. Cette présentation doit permettre que soit rendue possible la disposition définie à l''article 1.6.3-15, alinéa 4. Cette présentation ne doit en aucun cas permettre l''identification des élèves ou des écoles. En outre, les Services du Gouvernement sont chargés de concevoir les rapports à destination de chaque parent présentant les résultats de son enfant, lesquels sont transmis aux écoles concernées. Le Gouvernement arrête les modalités et les délais de transmission des rapports aux écoles. [Article 1.6.3-10.]54 - Les membres du groupe de travail et l''équipe de recherche universitaire ainsi que toute autre personne qui serait associée aux travaux sont tenus au secret professionnel quant au contenu de l''évaluation externe diagnostique, hors les communications autorisées selon les modalités fixées par le Gouvernement. En cas d''infraction, l''article 352 du Code pénal s''applique. [Article 1.6.3-11.]55 - L''Administration générale de l''Enseignement est chargée de l''organisation de l''évaluation externe diagnostique. [Article 1.6.3-12.]56 - Le respect des consignes de passation et de correction est placé sous la responsabilité du directeur de l''école. Les enseignants en charge des élèves procèdent aux corrections de l''évaluation externe diagnostique. Lorsqu''ils participent aux corrections et à l''encodage, les enseignants sont considérés comme étant en activité de service. [Article 1.6.3-13.]57 - §1er. Les écoles transmettent les données relatives à l''identification de leurs élèves et leurs résultats à l''évaluation externe diagnostique à l''Administration générale de l''Enseignement via un outil informatique mis à disposition des écoles par les Services du Gouvernement et visant à permettre une circulation fluide et sécurisée de l''information entre ces écoles et les Services du Gouvernement. 53Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 54Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 55Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 56Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 57Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 Docu 49466 Code 03-05-2019 Le traitement des données à caractère personnel qui est réalisé dans le cadre de cette transmission vise à répondre aux finalités suivantes : 1° permettre la transmission des résultats à l''épreuve externe diagnostique de chaque élève et de chaque classe de quatrième primaire par les écoles aux services du Gouvernement ; 2° permettre aux Services du Gouvernement d''analyser les résultats de l''évaluation externe diagnostique au niveau individuel, au niveau de la classe, au niveau de l''implantation, au niveau de l''école et au niveau de la Communauté française ; 3° permettre aux Services du Gouvernement de concevoir les rapports à destination de chaque parent présentant les résultats de l''élève et de les transmettre via l''école ; 4° permettre des traitements statistiques ultérieurs dans le cadre du pilotage du système éducatif. Dans ce cas, les données sont préalablement pseudonymisées ; 5° permettre un accompagnement personnalisé des élèves pour lesquels des difficultés ont été identifiées. §2. Les catégories de données traitées au paragraphe 1er sont les suivantes : 1° données relatives à l''identification de l''élève et de l''école qu''il fréquente, notamment les nom, prénom, année de naissance et sexe de l''élève ; 2° données relatives aux résultats à l''épreuve externe diagnostique. §3. Les personnes suivantes peuvent accéder aux données visées au paragraphe 2, via des accès sécurisés et personnalisés, aux fins suivantes : 1° le directeur de l''école ou son délégué. Celui-ci peut : a) consulter les données visées au paragraphe 2 ; b) encoder, saisir, modifier ou supprimer les données visées au paragraphe 2 ; 2° les Services du Gouvernement. Ceux-ci peuvent : a) consulter les données visées au paragraphe 2 ; b) saisir, modifier ou supprimer les données visées au paragraphe 2. §4. Le directeur de l''école ou son délégué visé au paragraphe 3, 1°, dispose d''un accès à l''outil informatique visé au paragraphe 1er, alinéa 1er, pour l''ensemble des élèves inscrits dans son école. §5. Dans le cadre des finalités visées au paragraphe 1er, les Services du Gouvernement et leurs sous- traitants ont accès à toutes les données visées au paragraphe 2. Dans le cadre de la finalité visée au paragraphe 1er, 4°, les Services du Gouvernement et leurs sous- traitants peuvent accéder aux données nominatives en vue de leur pseudonymisation ou anonymisation. Les Services du Gouvernement, leurs sous-traitants, et les personnes chargées d''une mission de recherche scientifique peuvent accéder aux données pseudonymisées ou anonymisées. Les données visées au paragraphe 2 relatives à l''année scolaire en cours sont consultables par les personnes visées au paragraphe 3. Docu 49466 Code 03-05-2019 Les d');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 148, 'Article 1. (partie 4)', 'visées au paragraphe 2 font ensuite l''objet d''une conservation passive pendant un délai de 10 ans à compter du terme de l''année scolaire à laquelle elles se rapportent. §6. Les membres du Service général de l''Inspection, du Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux et de la cellule de soutien et d''accompagnement concernée peuvent consulter les données visées au paragraphe 2 via l''école qui les met à leur disposition. §7. Le Ministère de la Communauté française est responsable du traitement des données à caractère personnel dans l''application informatique visée par le présent article au sens de l''article 4, 7), du règlement (UE) 2016/679 du Parlement européen et du Conseil du 27 avril 2016 relatif à la protection des personnes physiques à l''égard du traitement des données à caractère personnel et à la libre circulation de ces données, et abrogeant la directive 95/46/CE « (règlement général sur la protection des données) », ci- après « RGPD ». Les Pouvoirs organisateurs ont la qualité de sous-traitants au sens de l''article 4, 8), du RGPD, lorsqu''ils accèdent à l''outil informatique visée par le présent article. [Section 3. - Exploitation des résultats]58 [Article 1.6.3-14.]59 - Les résultats globaux et l''analyse de l''évaluation externe diagnostique sont remis par le Président du groupe de travail au Président de la Commission des évaluations visée à l''article 1.6.4- 1 et de la Commission du pilotage visée à l''article 1.6.1-1. [Article 1.6.3-15.]60 - Outre les résultats relatifs à l''ensemble de ses élèves ainsi qu''à chacun d''entre eux, chaque Pouvoir organisateur et chaque école dispose de ses propres résultats au regard des résultats globalisés de l''ensemble des élèves de la Communauté française qui lui sont communiqués sous la présentation visée à l''article 1.6.3-9, par l''Administration générale de l''Enseignement. Les membres du personnel et les Pouvoirs organisateurs des écoles qui ont connaissance des résultats obtenus à l''évaluation externe diagnostique sont tenus à cet égard par le secret professionnel. En cas d''infraction, l''article 352 du Code pénal s''applique. Chaque Pouvoir organisateur ou son délégué veille à ce qu''il soit procédé à un travail d''analyse et d''exploitation des résultats avec, le cas échéant, l''aide de la cellule de soutien et d''accompagnement de Wallonie-Bruxelles-Enseignement ou des fédérations de pouvoirs organisateurs, selon le cas. L''exploitation des résultats consiste notamment dans la construction et la mise en œuvre de stratégies pédagogiques ou organisationnelles susceptibles d''améliorer ces résultats. Chaque Pouvoir organisateur ou son délégué veille à ce que chaque parent ait accès aux résultats de l''enfant dont il a la charge conformément à la définition de l''article 1.3.1-1, 45°. [Article 1.6.3-16.]61 - §1er. Chaque école met les résultats de ses élèves à disposition des membres du Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux, des services d''inspection du Service général de l''Inspection concernés et de la cellule de soutien et d''accompagnement concernée afin que ceux-ci, outre les résultats globalisés de l''ensemble des élèves de la Communauté française, disposent de l''ensemble des résultats des élèves de chaque école au sein desquelles ils exercent leurs missions. Les membres du Service général de Pilotage des Ecoles et des Centres psycho-médico-sociaux, les inspecteurs et les conseillers au soutien et à l''accompagnement qui ont connaissance des résultats obtenus à l''évaluation externe diagnostique sont tenus à cet égard par le secret professionnel. En cas d''infraction, l''article 352 du Code pénal s''applique. 58Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 59Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 60Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 61Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 Docu 49466 Code 03-05-2019 Les services d''inspection concernés et les conseillers au soutien et à l''accompagnement veillent à intégrer ces résultats aux apports de leurs propres investigations dans le cadre de leurs missions respectives. §2. En ce qui concerne la transmission des résultats des élèves des écoles considérées une par une, la transmission à la cellule de soutien et d''accompagnement concernée ne concerne que les écoles relevant soit de Wallonie-Bruxelles-Enseignement, soit d''un Pouvoir organisateur affilié à une fédération de pouvoirs organisateurs. Dans ce dernier cas, la transmission est subordonnée à l''accord du Pouvoir organisateur. Le Gouvernement détermine les modalités selon lesquelles le Pouvoir organisateur fait part de cet accord. [Section 4. - Mesures de protection]62 [Article 1.6.3-17.]63 - Les membres des Services du Gouvernement sont tenus au secret professionnel quant au contenu de l''évaluation externe diagnostique. L''agent qui aura divulgué tout ou partie du contenu de l''évaluation avant la finalisation de cell');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 149, 'Article 1. (partie 5)', 'par les élèves, hors les communications autorisées selon les modalités fixées par le Gouvernement, commettra une infraction. En cas d''infraction, l''article 352 du Code pénal s''applique. [Article 1.6.3-18.]64 - Le directeur, les membres du personnel travaillant dans les écoles et, le cas échéant, le personnel sous contrat de volontariat exerçant des prestations dans les écoles sont tenus au secret professionnel quant au contenu de l''évaluation externe diagnostique et à toutes les informations qui permettent d''y accéder. Le directeur ou le membre du personnel visé au premier alinéa, qui aura divulgué tout ou partie du contenu de l''évaluation avant la finalisation de celle-ci par les élèves, hors les communications autorisées selon les modalités fixées par le Gouvernement, commettra une infraction. En cas d''infraction, l''article 352 du Code pénal s''applique. [Article 1.6.3-19.]65 - Toute personne qui aura, avant son utilisation dans le cadre de l''évaluation externe diagnostique, recelé, reçu en échange ou à titre gratuit, possédé sous quelque forme que ce soit, acheté, reproduit ou transféré par quelque moyen que ce soit tout ou partie du contenu de cette évaluation sans y avoir été autorisé par le Gouvernement ou son délégué sera punie des mêmes peines que celles prévues à l''article 347 du Code pénal. CHAPITRE IV. - De la Commission des évaluations Modifié par D. 20-07-2022');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 150, 'Article 1.', 'Article 1.6.4-1. - Il est créé une Commission des évaluations notamment 
chargée: 
1° de coordonner et d''assurer la cohérence des évaluations externes, 
certificatives ou non, et des outils d''évaluation visés à l''article 1.4.4-4; 
2° de garantir la correspondance des évaluations et des référentiels; 
3° de définir un calendrier global des évaluations externes, en tenant 
compte des évaluations internationales; 
4° d''harmoniser les modalités de passation des épreuves externes 
certificatives au sein des écoles, en ce compris l''organisation ou non d''une 
seconde session; 
5° de proposer au Gouvernement des documents-cadres des évaluations; 
6° de valider les objets d''évaluation et de vérifier leur adéquation avec les 
documents-cadres; 
 
62Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 
63Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 
64Remplacé par le D. 04-12-2025 et entre en vigueur le 24 août 2026 
65Inséré par le D. 04-12-2025 et entre en vigueur le 24 août 2026 
 
 
Docu 49466 
 
Code 03-05-2019 
7° de piloter les groupes de travail chargés de la conception des 
évaluations externes ou des batteries d''épreuves visées à l''article 1.4.4-4 ; 
8° remettre au Gouvernement une proposition de plan quinquennal visé 
à l''article 1.6.3-5, § 1er. [Inséré par D. 20-07-2022] 
 
Les documents-cadres visés à l''alinéa 1er, 5°, précisent, pour chaque objet 
d''évaluation: 
1° l''objectif poursuivi, le public visé, la nature de l''épreuve et sa forme; 
2° la composition du groupe de travail chargé de la conception de 
l''évaluation; 
3° le calendrier de passation de ces objets dans le curriculum; 
4° les canevas à respecter. 
 
 
 
Complété par D. 18-12-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 151, 'Article 1.', 'Article 1.6.4-2. - La Commission des évaluations est présidée par 
l''Administrateur général de l''Administration générale de l''enseignement ou 
une personne désignée par celui-ci. Selon les modalités établies par le 
Gouvernement, elle comporte des représentants: 
1° de la Direction générale du pilotage du système éducatif; 
2° du Service général de l''Inspection; 
3° de la Commission des référentiels et des programmes du tronc commun 
et des commissions des programmes; 
4° de Wallonie-Bruxelles Enseignement et des fédérations de pouvoirs 
organisateurs d''enseignement; 
5° du Gouvernement; 
6° du monde académique spécialisé dans la pédagogie générale ou la 
docimologie. 
 
Les membres visés à l''alinéa 1er, 4° et 6°, sont remboursés de leurs frais 
de déplacement selon les modalités établies par le Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 152, 'Article 1. / Article 1.', 'Article 1.6.4-3. - Le Gouvernement arrête les modalités du 
fonctionnement de la Commission des évaluations. 
 
CHAPITRE V. - De la négociation entre le Gouvernement et les 
pouvoirs organisateurs

Article 1.6.5-1. - Les réformes fondamentales de l''enseignement font 
l''objet d''une négociation préalable entre le Gouvernement, Wallonie-Bruxelles 
Enseignement et les fédérations de pouvoirs organisateurs reconnues par le 
Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 153, 'Article 1. (partie 1)', 'Article 1.6.5-2. - § 1er. Le Gouvernement reconnait comme fédération de pouvoirs organisateurs tout organe qui répond aux conditions suivantes: 1° affilier au minimum 20 % de l''ensemble des pouvoirs organisateurs, au sein d''un même réseau et d''un même caractère, des trois premières des catégories suivantes: a) pouvoirs organisateurs organisant des écoles fondamentales, primaires et maternelles ordinaires; b) pouvoirs organisateurs organisant des écoles secondaires ordinaires; c) pouvoirs organisateurs organisant des écoles spécialisées; d) pouvoirs organisateurs organisant des écoles [pour adultes]; e) pouvoirs organisateurs organisant des centres PMS; Docu 49466 Code 03-05-2019 f) pouvoirs organisateurs organisant des écoles d''enseignement secondaire artistique à horaire réduit. 2° affilier au minimum 10 % des pouvoirs organisateurs, au sein de ce réseau et de ce caractère, dans au moins deux provinces et dans l''arrondissement de Bruxelles-Capitale, et ce, pour chacune des trois dites catégories dans chacune des trois zones administratives susvisées; 3° affilier des pouvoirs organisateurs organisant des écoles fréquentées par au moins 20 % de la population scolaire de l''ensemble constitué, au sein de ce réseau et de ce caractère, par les élèves fréquentant des écoles d''enseignement fondamental, primaire et maternel ordinaire, des écoles d''enseignement secondaire ordinaire et des écoles d''enseignement spécialisé. Sur la base d''une demande dument motivée, le Gouvernement peut déroger aux critères définis à l''alinéa 1er. Dans la mesure où la fédération de pouvoirs organisateurs affilie des pouvoirs organisateurs organisant des écoles secondaires, l''ensemble de celles- ci doit comprendre des écoles organisant la section de transition et des écoles organisant la section de qualification. Un pouvoir organisateur qui renonce à son affiliation à une fédération de pouvoirs organisateurs ne peut être pris en compte pour la reconnaissance d''une autre fédération qu''au plus tôt six mois après la notification dudit renoncement. Le Gouvernement reconnait au minimum, s''il échet par dérogation à l''alinéa 1er: 1° une fédération représentant des Pouvoirs publics subventionnés organisant des écoles fondamentales, maternelles et primaires ordinaires et spécialisées, des écoles secondaires spécialisées et des écoles d''enseignement secondaire artistique à horaire réduit; 2° une fédération représentant des Pouvoirs publics subventionnés organisant des écoles secondaires ordinaires; 3° une fédération représentant des pouvoirs organisateurs d''enseignement libre de caractère confessionnel; 4° une fédération représentant des pouvoirs organisateurs d''enseignement libre de caractère non confessionnel. § 2. Pour qu''une fédération obtienne la reconnaissance du Gouvernement: 1° il doit y avoir cohérence entre les projets éducatif et pédagogique d''un pouvoir organisateur qui adhère à cette fédération et le projet éducatif et les axes majeurs du projet pédagogique de cette fédération; 2° la fédération: a) prévoit dans ses statuts que l''assemblée générale est constituée: - pour au moins 80 % de pouvoirs organisateurs affiliés ou de représentants élus en leur sein par plusieurs pouvoirs organisateurs; - pour un maximum de 20 % de membres cooptés par les premiers; b) prévoit dans ses statuts que ladite assemblée générale prend les décisions relatives aux modifications desdits statuts, à la définition du montant de la cotisation éventuelle prévue conformément à l''article 1.6.5-5 et à la désignation du conseil d''administration, celui-ci étant désigné pour une durée maximale de six ans renouvelables; c) assure la publicité des informations destinées à ses membres ainsi que des règles d''adhésion à la fédération et d''accès aux activités, programmes et services offerts par celle-ci; Docu 49466 Code 03-05-2019 d) transmet au Gouvernement, lors de sa demande de reconnaissance, une copie des résolutions d''adhésion des pouvoirs organisateurs affiliés, les noms et prénoms des membres des différentes instances le composant ainsi qu''une copie de ses statuts et règlements et, par la suite, dès qu''elle est adoptée, toute modification relative à ces divers éléments. 3° le conseil d''administration de la fédération: a) est composé d''une majorité de membres choisis parmi ceux définis au premier tiret du point 2°, a), premier tiret; b) désigne, pour une durée maximale de six ans renouvelables, les personnes habilitées à signer, en son nom, les protocoles concluant les concertations visées à l''article 1.6.5-1. § 3. La reconnaissance accordée vaut pour une durée indéterminée. § 4. Le Gouvernement retire la reconnaissance aux fédérations de pouvoirs organisateurs qui cessent de répondre aux conditions fixées paragraphes 1er et 2. Le Gouvernement arrête la procédure de reconnaissance, de refus de reconnaissance et de retrait de reconnaissance. La procédure visée à l''alinéa 2 prévoit au moins: 1° que la fédération introduit une demande de reconnaissance auprès du Gouv');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 154, 'Article 1. (partie 2)', 'au plus tard le 15 novembre de l''année qui précède la première année de l''entrée en application de cette reconnaissance; 2° les modalités d''introduction de la demande de reconnaissance; 3° la possibilité pour la fédération d''introduire un recours contre une décision de refus ou de retrait de reconnaissance ainsi que ses formes et délais; 4° la possibilité pour la fédération d''être entendue lors d''un recours; 5° les délais endéans lesquels doivent être prises les décisions d''octroi, de refus ou de retrait en matière de reconnaissance.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 155, 'Article 1.', 'Article 1.6.5-3. - Chaque fédération de pouvoirs organisateurs est 
chargée d''une mission générale de représentation, de coordination, de soutien 
et d''accompagnement des pouvoirs organisateurs qu''elle affilie ou avec 
lesquels elle a conclu une convention et ce, selon les termes fixés dans cette 
convention. 
 
Dans ce cadre, chaque fédération de pouvoirs organisateurs conclut avec 
le Gouvernement le contrat visé à l''article 14 du décret du 28 mars 2019 relatif 
aux cellules de soutien et d''accompagnement de l''enseignement organisé ou 
subventionné par la Communauté française et au statut des conseillers au 
soutien et à l''accompagnement, et bénéficie de la subvention visée à l''article 
12, alinéa 1er, du même décret, aux conditions et selon les modalités qu''il fixe.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 156, 'Article 1.', 'Article 1.6.5-4. - Wallonie-Bruxelles Enseignement est chargé d''une 
mission générale de représentation, de coordination, de soutien et 
d''accompagnement des écoles qu''il organise et celles avec lesquelles il a conclu 
une convention en application de l''article 1.7.3-1, § 2, 5°, et ce, selon les termes 
fixés dans cette convention. 
 
Dans ce cadre, Wallonie-Bruxelles Enseignement conclut avec le 
Gouvernement le contrat visé à l''article 14 du décret du 28 mars 2019 relatif 
aux cellules de soutien et d''accompagnement de l''enseignement organisé ou 
subventionné par la Communauté française et au statut des Conseillers au 
 
 
Docu 49466 
 
Code 03-05-2019 
soutien et à l''accompagnement, et bénéficie de la subvention visée à l''article 
12, alinéa 1er, du même décret, aux conditions et selon les modalités qu''il fixe.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 157, 'Article 1.', 'Article 1.6.5-5. - Chaque pouvoir organisateur peut prélever sur les 
dotations ou les subventions de fonctionnement des écoles qu''il organise le 
montant de la cotisation qu''il verse à une des fédérations de pouvoirs 
organisateurs. 
 
Modifié par D. 17-06-2021');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 158, 'Article 1.', 'Article 1.6.5-6. - Il est créé un Comité de négociation entre le 
Gouvernement 
de 
la 
Communauté 
française, 
Wallonie-Bruxelles 
Enseignement et les fédérations de pouvoirs organisateurs. 
 
Sont pris, après négociation du Comité et pour autant qu''ils aient une 
incidence directe sur l''action des pouvoirs organisateurs, les avant-projets de 
décret et les projets d''arrêté du Gouvernement relatifs aux matières suivantes: 
1° les missions prioritaires et spécifiques de l''enseignement fondamental 
et de l''enseignement secondaire; 
2° les orientations générales, les missions, l''organisation des centres 
PMS; 
3° les orientations générales ou la durée des études; 
4° la structure générale et l''organisation de l''enseignement; 
5° les conditions d''admission, d''inscription, de réinscription, d''exclusion, 
d''accès et de passage des élèves ou étudiants; 
6° le règlement général des études et des examens, là où ils existent; 
7° la régulation de l''offre d''enseignement, la programmation, les lieux et 
les règles de la négociation, les normes de création et de maintien; 
8° le mode de définition et de révision des référentiels; 
9° les modalités d''approbation des programmes d''études par le 
Gouvernement; 
10° l''évaluation externe; 
11° la politique de discrimination positive et d''encadrement différencié; 
12° le financement et ses modalités; 
13° les modes de vérification et de publicité des comptes annuels dans la 
mesure où ils imposeraient des règles complémentaires aux règles déjà 
applicables et propres à la nature juridique des pouvoirs organisateurs; 
14° le financement des bâtiments; 
15° les modalités de la gratuité de l''enseignement et son application; 
16° la politique, la répartition et la mise à disposition d''équipements 
spécifiques des écoles; 
17° les avantages sociaux et autres accordés aux écoles; 
18° le financement, le fonctionnement et l''équipement des pouvoirs 
organisateurs en ce compris le bénéfice et la répartition globale des contrats 
ACS (agent contractuel subventionné), APE (aide à la promotion de l''emploi), 
PTP (programme de transition professionnelle)(...); 
19° les règles statutaires du personnel; 
20° la réaffectation et la gestion des emplois; 
21° la formation initiale des membres du personnel et la formation 
professionnelle continue. [Remplacé par D. 17-06-2021] 
[22° le pilotage des écoles ;]66 
[23° les orientations générales, les missions, le pilotage et l''organisation 
des pôles territoriaux.]67 
 
 
66Inséré par le D. 18-04-2024 
67Inséré par le D. 18-04-2024 
 
 
Docu 49466 
 
Code 03-05-2019');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 159, 'Article 1.', 'Article 1.6.5-7. - § 1er. Le Comité de négociation est composé d''une 
délégation de l''autorité, d''une délégation de Wallonie-Bruxelles Enseignement 
et d''une délégation des fédérations de pouvoirs organisateurs. 
 
§ 2. La délégation de l''autorité, y compris le président et le cas échéant, 
le(s) vice(s) président(s), se compose au maximum de 12 membres. La 
délégation de l''autorité comprend le ministre qui a l''Enseignement dans ses 
attributions, le ministre du Budget, ou leurs délégués dument mandatés. Les 
autres membres de la délégation de l''autorité sont choisis par le président 
parmi les personnes qui, à quelque titre que ce soit, ont qualité pour engager 
le Gouvernement de la Communauté française. 
 
Le président et le(s) vice(s) président(s) sont désignés par le 
Gouvernement. Ils peuvent se faire remplacer par un délégué dument 
mandaté. 
 
La délégation de l''autorité peut se faire accompagner par des techniciens. 
Le nombre de techniciens ne peut cependant excéder le nombre de membres 
présents. 
 
§ 3. La délégation des pouvoirs organisateurs se compose de 12 membres. 
Wallonie-Bruxelles Enseignement et les fédérations de pouvoirs organisateurs 
choisissent librement leurs représentants. 
 
La délégation se compose au maximum de: 
1° 4 membres représentant les pouvoirs organisateurs visés à l''article 
1.6.5-2, § 1er, alinéa 5, 3°; 
2° 1 membre représentant les pouvoirs organisateurs visés à l''article 
1.6.5-2, § 1er, alinéa 5, 4°; 
3° 3 membres représentant les pouvoirs organisateurs visés à l''article 
1.6.5-2, § 1er, alinéa 5, 1°; 
4° 2 membres représentant les pouvoirs organisateurs visés à l''article 
1.6.5-2, § 1er, alinéa 5, 2°; 
5° 2 membres représentant Wallonie-Bruxelles Enseignement. 
 
La délégation des pouvoirs organisateurs peut se faire accompagner par 
des techniciens. Le nombre de techniciens de chaque délégation ne peut 
cependant excéder le nombre de membres qui constituent cette dernière.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 160, 'Article 1.', 'Article 1.6.5-8. - Le président veille au bon fonctionnement du Comité et 
désigne le secrétaire de celui-ci, ainsi que le service administratif qui organise 
le secrétariat. Le Comité établit son règlement d''ordre intérieur. Celui-ci est 
approuvé par le Gouvernement.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 161, 'Article 1.', 'Article 1.6.5-9. - Une question est soumise à la négociation au sein du 
comité de négociation à l''initiative de l''autorité, de Wallonie-Bruxelles 
Enseignement ou d''une fédération de pouvoirs organisateurs. 
 
En vue de la négociation, Wallonie-Bruxelles Enseignement et les 
fédérations de pouvoirs organisateurs reçoivent toute documentation 
nécessaire.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 162, 'Article 1.', 'Article 1.6.5-10. - Le président établit l''ordre du jour en tenant compte 
des initiatives visées à l''article 1.6.5-9. Il fixe la date des réunions. Il dirige les 
débats et assure l''ordre des réunions. 
 
 
 
Docu 49466 
 
Code 03-05-2019 
L''ordre du jour mentionne dans lequel des deux délais prévus à l''article 
1.6.5-14 la négociation doit être terminée.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 163, 'Article 1.', 'Article 1.6.5-11. - § 1er. Le secrétaire fait parvenir les convocations 
contenant l''ordre du jour et la documentation nécessaire aux délégations au 
moins dix jours ouvrables scolaires avant la date de la réunion. 
 
Dans les cas où le président estime qu''il y a urgence, il peut réduire le 
délai à trois jours ouvrables scolaires, sans que cela entraine nécessairement 
l''application de l''article 1.6.5-14. 
 
§ 2. Le président peut organiser la négociation par voie électronique 
lorsqu''un point a fait l''objet au préalable d''un accord unanime au sein d''une 
instance consultative dans laquelle Wallonie-Bruxelles Enseignement et les 
fédérations de pouvoirs organisateurs sont représentées. 
 
L''objection notifiée par courrier électronique dans les trois jours 
ouvrables scolaires à compter de la réception de la convocation de Wallonie-
Bruxelles Enseignement ou d''une seule fédération de pouvoirs organisateurs 
suffit à ce que la procédure prévue au paragraphe 1er s''applique.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 164, 'Article 1.', 'Article 1.6.5-12. - En réunion, toute délégation a le droit de proposer des 
modifications à l''ordre du jour. Celles-ci, pour être effectives, doivent être 
acceptées à l''unanimité par les délégations présentes.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 165, 'Article 1. / Article 1.', 'Article 1.6.5-13. - L''absence d''un ou de plusieurs membres 
régulièrement convoqués ne vicie pas la validité de la négociation.

Article 1.6.5-14. - La négociation se termine dans le délai de trente jours 
à compter de celui de la réunion au cours de laquelle le point est abordé pour 
la première fois. Le délai peut être prorogé de commun accord entre les 
délégations présentes. 
 
Le président peut réduire le délai jusqu''à dix jours s''il estime qu''un point 
doit être traité d''urgence.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 166, 'Article 1.', 'Article 1.6.5-15. - A l''issue de la négociation, le Comité consigne les 
conclusions de la négociation dans un protocole mentionnant: 
1° soit l''accord unanime de toutes les parties; 
2° soit l''accord entre la délégation de l''autorité et la délégation de 
Wallonie-Bruxelles Enseignement ou d''une ou plusieurs fédérations de 
pouvoirs organisateurs ainsi que la position des autres membres de cette 
délégation; 
3° soit la position respective de chaque délégation.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 167, 'Article 1.', 'Article 1.6.5-16. - Le secrétaire rédige les procès-verbaux des réunions. 
Le procès-verbal de chaque réunion mentionne: 
1° l''ordre du jour; 
2° le nom des membres de la délégation de l''autorité, présents, excusés 
ou absents; 
3° le nom des membres de Wallonie-Bruxelles Enseignement présents, 
excusés ou absents; 
4° la dénomination des fédérations de pouvoirs organisateurs présentes, 
excusées ou absentes et le nom des membres des délégations de ces fédérations, 
qui sont présents ou excusés; 
5° le nom des techniciens; 
 
 
Docu 49466 
 
Code 03-05-2019 
6° le résumé succinct des discussions. 
 
Les procès-verbaux sont signés par le président et le secrétaire. 
 
Ils sont envoyés aux délégations composant le Comité.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 168, 'Article 1.', 'Article 1.6.5-17. - § 1er. Dans les quinze jours qui suivent la réunion, une 
copie du protocole est envoyée, sous pli recommandé à la poste, aux membres 
de la délégation de l''autorité et aux membres de la délégation des pouvoirs 
organisateurs intéressés. 
 
§ 2. Les membres de la délégation de l''autorité et de la délégation des 
pouvoirs organisateurs disposent d''un délai de quinze jours ouvrables après 
l''envoi du protocole, pour communiquer leurs observations au président. La 
date de la poste fait foi de l''envoi. 
 
Toutefois, sur proposition d''une délégation et après avoir entendu les 
autres délégations intéressées dans le délai précité de quinze jours ouvrables, 
le président peut modifier ce délai. Si aucune modification de texte n''est 
proposée dans le délai, le protocole devient définitif. La demande de 
rectification est soumise par le président au Comité lors de sa plus prochaine 
réunion. 
 
Si aucun accord n''est trouvé, les positions divergentes sont actées au 
protocole. 
 
§ 3. Une copie du protocole est adressée: 
1° au ministre ayant l''Enseignement dans ses attributions; 
2° au ministre du Budget; 
3° au Ministre-Président.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 169, 'Article 1.', 'Article 1.6.5-18. - § 1er. Lorsque l''examen d''une question est propre soit 
à 
l''enseignement 
officiel 
subventionné 
soit 
à 
l''enseignement 
libre 
subventionné, le président du Comité de négociation peut décider de la confier 
à un sous-comité. 
 
Ce sous-comité est composé de la délégation de l''autorité et des 
représentants du réseau d''enseignement visé au sein de la délégation des 
fédérations de pouvoirs organisateurs. 
 
§ 2. Lorsque l''examen d''une question est propre soit à l''enseignement 
confessionnel soit à l''enseignement non-confessionnel, le président du Comité 
de négociation peut décider de la confier à un sous-comité. 
 
Ce sous-comité est composé de la délégation de l''autorité et des 
représentants des pouvoirs organisateurs concernés visés au sein de la 
délégation des pouvoirs organisateurs. 
 
§ 3. La procédure de négociation s''applique mutatis mutandis aux 
réunions des sous-comités créés par les paragraphes 1er et 2.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 170, 'Article 1.', 'Article 1.6.5-19. Au sein du Comité, il peut être convenu que les 
communications visées aux articles 1.6.5-9, 1.6.5-11, 1.6.5-16 et 1.6.5-17, 
soient transmises par voie électronique. Les règles plus précises concernant la 
transmission et la communication électronique sont déterminées le cas 
échéant dans le règlement d''ordre intérieur. 
 
 
Docu 49466 
 
Code 03-05-2019 
CHAPITRE VI. - Des organisations représentatives des parents et 
associations de parents d''élèves');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 171, 'Article 1.', 'Article 1.6.6-1. § 1er. Les organisations représentatives des parents et 
associations de parents d''élèves sont: 
1° la Fédération des associations de parents de l''enseignement officiel 
(FAPEO) pour les écoles officielles; 
2° l''Union francophone des associations de parents de l''enseignement 
catholique (UFAPEC) pour les écoles libres catholiques. 
 
§ 2. Les membres de chaque organisation représentative des parents et 
associations de parents d''élèves sont élus en assemblée générale des parents 
qu''ils représentent, suivant les modalités propres à leurs statuts respectifs. 
 
Les organisations représentatives des parents et associations de parents 
d''élèves sont constituées sous forme d''ASBL. Elles communiquent au 
Gouvernement une copie de leurs statuts et règlements ainsi que leurs 
comptes et bilans de l''année écoulée.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 172, 'Article 1.', 'Article 1.6.6-2. § 1er. Les organisations représentatives des parents 
d''élèves ont des missions qui s''adressent à tout le public scolaire: 
1° défendre et promouvoir les intérêts de tous les élèves; 
2° susciter la participation active de tous les parents en vue de leur 
permettre de jouer pleinement leur rôle de citoyens actifs et responsables au 
sein de la société et des écoles; 
3° assurer la circulation de l''information auprès et en provenance des 
parents et des associations de parents; 
4° proposer à tous les parents des formations spécifiques en vue de leur 
permettre de jouer pleinement leur rôle de représentants de parents; 
5° exercer une mission de conciliation, en cas de non-respect des articles 
1.5.3-11 à 1.5.3-15 et 1.5.3-2, § 5, ou en cas de difficulté en ce qui concerne le 
fonctionnement d''une association de parents. 
 
§ 2. Pour remplir les missions définies au paragraphe 1er, il est alloué, en 
fonction des moyens budgétaires disponibles, une subvention annuelle d''au 
minimum 100 000 euros à chaque organisation représentative des parents et 
associations de parents d''élèves. 
 
A partir de l''exercice budgétaire 2010, ce montant est indexé 
annuellement sur base de l''évolution de l''indice général des prix à la 
consommation du mois de janvier.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 173, 'Article 
1.', 'Article 
1.6.6-3. 
Le 
Gouvernement 
consulte 
les 
organisations 
représentatives des parents et associations de parents d''élèves sur les mesures 
d''exécution prévues dans le présent Chapitre, et sur tout avant-projet de décret 
ou tout projet d''arrêté à portée règlementaire qui, à la fois, modifie le 
fonctionnement des écoles, a une incidence directe sur le vécu des élèves et 
touche à l''exercice de la responsabilité parentale. 
 
Le Gouvernement fixe les modalités de consultation des organisations 
représentatives des parents et associations de parents d''élèves.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('49466', 174, 'Article 1.', 'Article 1.6.6-4. - Les organisations représentatives des parents et 
associations de parents d''élèves sont seules habilitées à reconnaitre les 
 
 
Docu 49466 
 
