INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 0, '', 'Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024 
Décret modifiant le décret du 02 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit 
subventionné par la Communauté française 
 
D. 21-09-2023  
M.B. 19-01-2024 
 
 
 
Le Parlement de la Communauté française a adopté et Nous, 
Gouvernement, sanctionnons ce qui suit : 
 
CHAPITRE 1er - Dispositions modificatives');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 1, 'Article 1er. - A l''article 1er du décret du 02 juin 1998 organisant', 'Article 1er. - A l''article 1er du décret du 02 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française, les modifications suivantes sont apportées : 
 
a) le 5° est remplacé par ce qui suit : 
 
« 5° la filière : la subdivision administrative d''un cours artistique de base, 
qui le structure en étapes d''enseignement. » ; 
 
b) le 6° est remplacé par ce qui suit : 
 
« 6° la compétence : l''aptitude à mettre en œuvre un ensemble organisé 
de savoirs, de savoir-faire et de savoir-être permettant d''accomplir un certain 
nombre de tâches ; ».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 2, 'Article 2. - Dans le même décret, le second article 2bis, tel qu''inséré par', 'Article 2. - Dans le même décret, le second article 2bis, tel qu''inséré par 
le décret du 07 juillet 2022 modifiant le décret du 02 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française, est renuméroté article 2ter.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 3, 'Article 3. - A l''article 4 du même décret, les modifications suivantes sont', 'Article 3. - A l''article 4 du même décret, les modifications suivantes sont 
apportées : 
 
a) le §2 est remplacé par ce qui suit : 
 
« §2. Dans chaque domaine visé au §1er, peuvent être organisés : 
 
- des cours artistiques de base ; 
 
- des cours artistiques complémentaires ; 
 
- des accompagnements de cours ; 
 
- de la remédiation. 
 
Dans les cours artistiques de base, quatre filières peuvent être 
organisées : 
 
a) une filière préparatoire qui comprend les cours d''initiation aux 
pratiques artistiques ; 
 
 
Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024 
 
b) une filière de formation qui, hors filière préparatoire, comprend 
les premières années des cours ; 
 
c) une filière de qualification qui comprend les années terminales 
des cours, dans une forme minimale d''organisation des études ; 
 
d) une filière de transition qui comprend les années terminales des 
cours, dans une forme renforcée d''organisation des études, 
représentant la structure maximale. 
 
Le Gouvernement fixe la liste des cours artistiques de base et 
complémentaires organisables et détermine les cours pouvant bénéficier de 
l''accompagnement et de la remédiation. 
 
Sur avis du Conseil des études visé à l''article 20, le Pouvoir organisateur 
choisit les cours artistiques de base, les cours artistiques complémentaires, les 
accompagnements et la remédiation qu''il organise. » ; 
 
b) le §3 est remplacé par ce qui suit : 
 
« §3. Dans chaque domaine visé au §1er, 
 
1° les cours artistiques de base sont définis en termes : 
 
a) de structure ; 
 
b) de conditions d''admission et d''obtention des certificats et 
diplômes ; 
 
c) d''objectifs d''éducation et de formation artistiques ; 
 
d) de compétences à exercer et à maitriser par les élèves ; 
 
2° les cours artistiques complémentaires sont définis en termes : 
 
a) de structure ; 
 
b) de conditions d''admission ; 
 
c) d''objectifs d''éducation et de formation artistiques ; 
 
d) de compétences à exercer par les élèves. 
 
La structure des cours comporte : 
 
- le nombre d''années d''études organisables ; 
 
- le nombre de périodes hebdomadaires de cours organisables. 
 
Les compétences prennent en compte : 
 
- l''intelligence artistique de l''élève, à savoir sa capacité de perception 
de la cohérence d''un langage artistique ; 
 
 
 
 
Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024 
 
- la maitrise technique de l''élève, à savoir sa capacité de dominer 
l''utilisation des éléments techniques propres à chaque cours ou 
spécialité ; 
 
- l''autonomie de l''élève, à savoir sa capacité de découvrir, de 
développer et de produire seul une activité artistique de qualité 
équivalente à celle que la formation lui a permis d''atteindre ; 
 
- la créativité de l''élève, à savoir sa capacité de se servir librement 
d''un langage artistique connu de lui ou élaboré par lui en vue d''une 
réalisation originale. 
 
Tous les cours organisés ont pour objectifs : 
 
1° de faire acquérir les capacités permettant le maintien et la progression 
de l''élève dans le processus de l''enseignement secondaire artistique à horaire 
réduit ; 
 
2° de permettre la pratique d''une activité artistique. 
 
Le Gouvernement précise la structure des cours, les objectifs d''éducation 
et de formation artistiques et les compétences à exercer et à maitriser par les 
élèves. 
 
Les conditions d''admission sont fixées conformément aux dispositions de 
l''article 8. 
 
Les conditions d''obtention des certificats et diplômes sont fixées 
conformément aux dispositions de l''article 16. 
 
Sur avis du Conseil des études visé à l''article 20, le Pouvoir organisateur 
choisit les filières, années d''études et périodes de cours qu''il organise, dans le 
respect des dispositions de l''article 7. Il peut décider de réunir certaines années 
d''études en groupes d''années d''études. ».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 4, 'Article 4. - A l''article 6 du même décret, les termes « article 4, §3 » sont / Article 5. - A l''article 8 du même décret, les modifications suivantes sont', 'Article 4. - A l''article 6 du même décret, les termes « article 4, §3 » sont 
