INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 7, 'Article 8. - A l''article 16 du même décret, les modifications suivantes', 'Article 8. - A l''article 16 du même décret, les modifications suivantes 
