INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 8, 'Article 9. - L''article 17 du même décret est supprimé. / Article 10. - A l''article 21, alinéa 2, du même décret, les modifications', 'Article 9. - L''article 17 du même décret est supprimé.

