INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 9, 'Article 11. - A l''article 22 du même décret, après le 6° et les mots « de la', 'Article 11. - A l''article 22 du même décret, après le 6° et les mots « de la 
