INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 13, 'Article 15. - A l''article 100, §5, du même décret, un troisième alinéa est', 'Article 15. - A l''article 100, §5, du même décret, un troisième alinéa est 
ajouté, rédigé comme suit : 
 
 
 
 
Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024 
 
« Pour le domaine de la danse, à l''exception des fonctions relatives à 
l''accompagnement, le Gouvernement peut reconnaitre, sur avis du Service de 
l''Inspection de l''Enseignement artistique, que l''ensemble de la formation 
artistique suivie par le requérant lui permet d''exercer la fonction considérée. 
Le Gouvernement évalue tous les quatre ans le maintien de la nécessité de 
cette mesure. ».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 14, 'Article 16. - A l''article 104 du même décret, le 5° de l''alinéa 1er est', 'Article 16. - A l''article 104 du même décret, le 5° de l''alinéa 1er est 
remplacé par ce qui suit : 
 
« 5° au membre du personnel qui présente sa candidature à un emploi de 
professeur de formation pluridisciplinaire en étant nommé à titre définitif 
dans toute autre fonction du domaine des arts plastiques, visuels et de l''espace 
visée à l''article 51, §2, à l''exception des fonctions de professeur d''histoire de 
l''art et analyse esthétique, de professeur de techniques artistiques et de 
professeur de technologie de la terre et des émaux. ».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 15, 'Article 17. - A l''article 105 du même décret, les modifications suivantes (partie 1)', 'Article 17. - A l''article 105 du même décret, les modifications suivantes sont apportées : a) l''intitulé du 3° « professeur des métiers d''art, de recherches graphiques et picturales, d''image imprimée, d''aménagement, de création textile, d''arts monumentaux, de volumes et des arts du feu : » est remplacé par ce qui suit : « 3° professeur : - d''aménagement d''intérieur et décoration ; - d''art du livre : reliure ; - d''art du livre : typographie et étude de la lettre ; - d''art du verre ; - d''arts monumentaux ; - d''arts numériques ; - de bijouterie ; - de céramique ; - de cinégraphie ; - de cinéma d''animation ; - de création textile ; - de design ; - de dessin ; - de dessin d''architecture et maquettisme ; - d''ébénisterie ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - de ferronnerie ; - de gravure ; - d''illustration et bande dessinée ; - d''infographie ; - de lithographie ; - de métal ; - de peinture ; - de photographie ; - de poterie ; - de publicité et communication visuelle ; - de restauration d''œuvres et d''objets d''art ; - de scénographie ; - de sculpture ; - de sérigraphie ; - de stylisme, parures et masques ; - de vidéographie ; - de vitrail. » ; b) le 3°, c) est remplacé par ce qui suit : « c) titres d''aptitude pédagogique à l''enseignement : - AESS du domaine des arts plastiques, visuels et de l''espace ; - AESS du domaine des arts du spectacle et techniques de diffusion et de communication ; - CAPE du cours à enseigner ; - autre CAPE : - pour la fonction de professeur d''aménagement d''intérieur et décoration : CAPE de décoration ou CAPE d''ensemblier - décorateur ou CAPE d''ensemblier/décorateur - décoration ; - pour la fonction de professeur d''art du livre : reliure : CAPE d''art du livre : reliure dorure/typographie et étude de la lettre ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - pour la fonction de professeur d''art du livre : typographie et étude de la lettre : CAPE d''art du livre : reliure dorure/typographie et étude de la lettre ; - pour la fonction de professeur d''arts monumentaux : CAPE de peinture monumentale ou CAPE de sculpture monumentale ; - pour la fonction de professeur de cinégraphie : CAPE de cinégraphie, vidéographie et technique son ; - pour la fonction de professeur d''illustration et bande dessinée : CAPE de dessin ; - pour la fonction de professeur d''infographie : CAPE d''arts numériques ; - pour la fonction de professeur de peinture : CAPE de peinture monumentale ; - pour la fonction de professeur de sculpture : CAPE de sculpture monumentale ; - pour la fonction de professeur de stylisme, parures et masques : CAPE de création de costumes, de décors et de masques ; - pour la fonction de professeur de vidéographie : CAPE de cinégraphie, vidéographie et technique son. » ; c) le 4° est remplacé par ce qui suit : « 4° professeur de techniques artistiques : a) titres requis : - diplôme de master en infographie ou en arts numériques, délivré par un établissement d''enseignement supérieur, complété par un titre d''aptitude pédagogique ; - diplôme de licence ou de master du domaine des arts plastiques, visuels et de l''espace, complété par un titre d''aptitude pédagogique ; - diplôme de master didactique du domaine des arts plastiques, visuels et de l''espace ; - diplôme de licence ou de master du domaine des arts du spectacle et techniques de diffusion et de communication, complété par un titre d''aptitude pédagogique ; - diplôme de master didactique du domaine des arts du spectacle et techniques de diffusion et de communication ; - la reconnaissance d''expérience utile, complétée par un titre d''aptitude pédagogique ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - une notoriété telle que visée à l''article 100, §2, en relation avec la fonction et les cours à conférer, complétée par un titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE de techniques artistiques ; - AESS délivré par une Ecole Supérieure des Arts ou en infographie ou en arts numériques par un établissement d''enseignement supérieur. » ; d) un 6° est ajouté, rédigé comme suit : « 6° professeur de technologie de la terre et des émaux : a) titres requis : - diplôme d''ingénieur, de master en pharmacie ou de master en chimie, délivré par un établissement universitaire, complété par un titre d''aptitude pédagogique ; - diplôme de licence ou de master du domaine des arts plastiques, visuels et de l''espace, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - diplôme de master didactique du domaine des arts plastiques, visuels et de l''espace complété par la reconnaissance d''expérience utile ; - la reconnaissance d''expérience utile, complétée par un titre d''aptitude pédagogique ; - une notoriété telle que visée à l''article 100, §2, en relation avec la fonction et le cours à conférer, complétée par un titre d''aptitude pédagogique ; b) titres jugés suffi');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 16, 'Article 17. - A l''article 105 du même décret, les modifications suivantes (partie 2)', ': - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE de technologie de la terre et des émaux ; - AESS du domaine des arts plastiques, visuels et de l''espace ; - AESS délivrée par un établissement universitaire. ». Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 17, 'Article 18. - A l''article 106 du même décret, les modifications suivantes (partie 1)', 'Article 18. - A l''article 106 du même décret, les modifications suivantes sont apportées : a) au 1° : - au point a), les termes suivants sont ajoutés : « - tout diplôme de master en musique, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master didactique en musique, complété par la reconnaissance d''expérience utile. » ; - le point b) est remplacé par ce qui suit : « - les titres repris sub a) sans titre d''aptitude pédagogique ; » ; b) au 2° : - dans l''intitulé, les mots « d''ensemble » sont remplacés par le mot « choral » ; - le point b) est remplacé par : « - les titres repris sub a) sans titre d''aptitude pédagogique ; » ; - au c) le titre suivant est ajouté : « - CAPE du chant choral. » ; c) dans l''intitulé du 3°, les mots « musique - analyse » sont remplacés par les mots « musique et analyse musicale » ; d) dans l''intitulé du 4°, les mots « d''écriture musicale - analyse » sont remplacés par les mots « d''analyse et écriture musicales » ; e) le 6° « professeur de formation instrumentale » est remplacé par ce qui suit : « 6° professeur de formation instrumentale, pour chacune des spécialités suivantes : - accordéon chromatique ; - alto ; - basson ; - basson baroque et classique ; - clarinette ; - clavecin ; - contrebasse ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - cor ; - cor naturel ; - cornemuse et musette ; - flûte à bec ; - flûte traversière ; - flûte traversière baroque et classique ; - guitare ; - harpe ; - hautbois ; - hautbois baroque et classique ; - luth ; - mandoline ; - orgue ; - percussions ; - piano ; - pianoforte ; - saxophone ; - trombone à coulisse ; - trompette ; - trompette naturelle ; - tuba ; - viole de gambe ; - violon ; - violon baroque ; - violoncelle ; - violoncelle baroque. » ; f) un 6° bis est inséré après le 6°, rédigé comme suit : Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 « 6° bis professeur de formation instrumentale, pour chacune des spécialités suivantes : - accordéon diatonique ; - carillon ; - cornet à bouquin ; - guitare électrique : a) titres requis : - tout diplôme de master en musique, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master didactique en musique, complété par la reconnaissance d''expérience utile ; - la reconnaissance d''expérience utile, complétée par un titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE de formation instrumentale de la spécialité à enseigner ; - AESS du domaine de la musique. » ; g) dans l''intitulé du 7°, les mots « et d''ensemble jazz » sont supprimés ; h) au 7°, c), premier tiret, les mots « et d''ensemble jazz » sont remplacés par les mots « de la spécialité à enseigner » ; i) dans l''intitulé du 10°, les mots « vue - transposition » sont remplacés par les mots « vue et transposition » ; j) dans l''intitulé du 11°, les mots « et de musique de chambre vocale » sont supprimés ; k) dans l''intitulé du 13°, les mots « (continuo et accompagnement spécifique) » sont supprimés ; l) le 16° est remplacé par ce qui suit : « 16° professeur de rythmes et rythmiques : a) titres requis : Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - diplôme de bachelier en rythmes et rythmiques complété par un titre d''aptitude pédagogique ; - diplôme de fin d''études de l''Institut de Rythmique Jaques-Dalcroze de Belgique, délivré dans la spécialité rythmique, complété par un titre d''aptitude pédagogique ; - tout diplôme de l''enseignement artistique supérieur, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master en musique, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master didactique en musique, complété par la reconnaissance d''expérience utile ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE de rythmique ; - CAPE de pratique des rythmes musicaux du monde ; - CAPE de rythmes et rythmiques ; - AESS du domaine de la musique. » ; m) le 17° est remplacé par ce qui suit : « 17° professeur d''expression corporelle : a) titres requis : - diplôme de fin d''études de l''Institut de Rythmique Jaques-Dalcroze de Belgique, délivré dans la spécialité expression corporelle, complété par un titre d''aptitude pédagogique ; - tout diplôme de l''enseignement artistique supérieur, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master en musique, en théâtre et arts de la parole ou en arts du spectacle et techniques de diffusion et communication, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master didactique en musique, en théâtre et arts de la parole ou en arts du spectacle et');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 18, 'Article 18. - A l''article 106 du même décret, les modifications suivantes (partie 2)', 'Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 techniques de diffusion et communication complété par la reconnaissance d''expérience utile ; - bachelier en arts du spectacle et techniques de diffusion et de communication : arts du cirque ; - la reconnaissance d''expérience utile en danse contemporaine, complétée par un titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE d''expression corporelle ; - AESS du domaine de la musique ; - AESS du domaine des arts de la parole et du théâtre. » ; n) dans l''intitulé du 18°, les mots « et ensemble jazz » sont supprimés ; o) dans l''intitulé du 19°, les mots « composition de » sont insérés entre les mots « de » et « musique » ; p) le 20° est supprimé ; q) dans l''intitulé du 21°, le mot « musicale » est ajouté après le mot « improvisation » ; r) dans l''intitulé du 22°, les mots « d''instruments patrimoniaux » sont remplacés par les mots « de formation instrumentale de tradition locale » et au c), le titre suivant est ajouté : « - CAPE de formation instrumentale de tradition locale » ; s) aux 21°, a), et 22°, a), les termes suivants sont ajoutés : « - diplôme de l''enseignement supérieur artistique ou artistique supérieur, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master en musique, complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; - tout diplôme de master didactique en musique, complété par la reconnaissance d''expérience utile. » ; t) aux 21°, c), et 22°, c), deuxième tiret, les mots « de la » sont insérés entre les mots « domaine » et « musique » ; u) dans l''intitulé du 24°, les mots « et ensemble pop » sont supprimés. Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 19, 'Article 19. - A l''article 107 du même décret, les modifications suivantes', 'Article 19. - A l''article 107 du même décret, les modifications suivantes 
sont apportées : 
 
a) au 2°, a), au huitième tiret, le mot « utile » est ajouté après les termes 
« - diplôme de master didactique du domaine du théâtre et des arts de la parole, 
option arts oratoires, complété par la reconnaissance d''expérience » ; 
 
b) au 3°, c), les termes suivants sont ajoutés : 
 
« - AESS en langues et littératures romanes. » ; 
 
c) le 4° est remplacé par ce qui suit : 
 
« 4° professeur d''expression corporelle : 
 
a) titres requis : 
 
- diplôme de fin d''études de l''Institut de Rythmique 
Jaques-Dalcroze de Belgique, délivré dans la spécialité 
expression corporelle, complété par un titre d''aptitude 
pédagogique ; 
 
- tout diplôme de l''enseignement artistique supérieur, 
complété par la reconnaissance d''expérience utile et un 
titre d''aptitude pédagogique ; 
 
- tout diplôme de master en musique, en théâtre et arts de 
la parole ou en arts du spectacle et techniques de diffusion 
et communication complété par la reconnaissance 
d''expérience utile et un titre d''aptitude pédagogique ; 
 
- tout diplôme de master didactique en musique, en 
théâtre et arts de la parole ou en arts du spectacle et 
techniques de diffusion et communication complété par la 
reconnaissance d''expérience utile ; 
 
- bachelier en arts du spectacle et techniques de diffusion 
et de communication : arts du cirque ; 
 
- 
la 
reconnaissance 
d''expérience 
utile 
en 
danse 
contemporaine, complétée par un titre d''aptitude 
pédagogique ; 
 
b) titres jugés suffisants : 
 
- les titres repris sub a) sans titre d''aptitude pédagogique ; 
 
c) titres d''aptitude pédagogique à l''enseignement : 
 
- CAPE d''expression corporelle ; 
 
- AESS du domaine de la musique ; 
 
- AESS du domaine des arts de la parole et du théâtre. ». 
 
 
 
Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 20, 'Article 20. - L''article 108 du même décret est remplacé par ce qui suit : (partie 1)', 'Article 20. - L''article 108 du même décret est remplacé par ce qui suit : « Article 108. - Les titres requis, les titres jugés suffisants et les titres d''aptitude pédagogique à l''enseignement pour les fonctions visées à l''article 51, §5, que peuvent exercer les membres du personnel enseignant dans le domaine de la danse sont fixés comme suit : 1° professeur de danse classique : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de danse classique ; 2° professeur de danse contemporaine : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de danse contemporaine ; 3° professeur de danse jazz : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de danse jazz ; 4° professeur de claquettes : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de claquettes ; 5° professeur de danse traditionnelle : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de danse traditionnelle ; 6° professeur de danses urbaines : a) titres requis : - la reconnaissance d''expérience utile, complétée par le titre d''aptitude pédagogique ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - la reconnaissance de l''ensemble de la formation artistique telle que visée à l''article 100, §5, alinéa 3, complétée par le titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE de danses urbaines ; 7° professeur chargé de l''accompagnement au piano dans le domaine de la danse : a) titres requis : - diplôme de licence ou de master en musique, section formation instrumentale, option claviers, spécialité piano ou accompagnement au piano, complété par un titre d''aptitude pédagogique ; - diplôme de licence ou de master en musique, section jazz, spécialité piano jazz ou claviers jazz, complété par un titre d''aptitude pédagogique ; - diplôme de master didactique en musique, section formation instrumentale, option claviers, spécialité piano ou accompagnement au piano ; - diplôme de master didactique en musique, section jazz, spécialité piano jazz ou claviers jazz ; - diplôme de l''enseignement artistique supérieur de piano, de piano jazz ou de claviers jazz, complété par un titre d''aptitude pédagogique ; - certificat final de piano d''accompagnement complété par la reconnaissance d''expérience utile et un titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titre d''aptitude pédagogique à l''enseignement : - CAPE d''accompagnement au piano des cours de danse classique ; - CAPE d''accompagnement au piano dans le domaine de la danse ; - AESS du domaine de la musique ; 8° professeur chargé de l''accompagnement aux percussions dans le domaine de la danse : Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 a) titres requis : - diplôme de licence ou de master en musique, section formation instrumentale, option percussions, complété par un titre d''aptitude pédagogique ; - diplôme de master didactique en musique, section formation instrumentale, option percussions ; - diplôme de l''enseignement artistique supérieur de percussions, de percussio');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 21, 'Article 20. - L''article 108 du même décret est remplacé par ce qui suit : (partie 2)', 'jazz ou de batterie jazz, complété par un titre d''aptitude pédagogique ; - diplôme de master en musique, section jazz, option batterie jazz, complété par un titre d''aptitude pédagogique ; - diplôme de master didactique en musique, section jazz, option batterie jazz ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE d''accompagnement des cours de danse contemporaine et de danse jazz ; - CAPE d''accompagnement aux percussions dans le domaine de la danse ; - AESS du domaine de la musique ; 9° professeur chargé de l''accompagnement des cours de danse traditionnelle : a) titres requis : - diplôme de licence ou de master en musique, section formation instrumentale, toutes options, complété par la reconnaissance d''expérience utile un titre d''aptitude pédagogique ; - diplôme de master didactique en musique, section formation instrumentale, toutes options, complété par la reconnaissance d''expérience utile ; - la reconnaissance d''expérience utile, complétée par un titre d''aptitude pédagogique ; b) titres jugés suffisants : - les titres repris sub a) sans titre d''aptitude pédagogique ; c) titres d''aptitude pédagogique à l''enseignement : - CAPE d''accompagnement des cours de danse traditionnelle ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - AESS du domaine de la musique. ». CHAPITRE 2. - Dispositions transitoires et finales');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 22, 'Article 21. - Un délai de deux années scolaires à partir de l''année', 'Article 21. - Un délai de deux années scolaires à partir de l''année 
scolaire 2023-2024 est accordé pour permettre aux élèves inscrits en troisième 
et quatrième années d''études durant l''année scolaire 2022-2023 en filière de 
transition du cours de formation musicale, de mener à bonne fin les études 
entreprises.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 23, 'Article 22. - §1er. Le membre du personnel nommé ou engagé à titre', 'Article 22. - §1er. Le membre du personnel nommé ou engagé à titre 
définitif au 26 août 2024 dans une fonction telle qu''elle existait avant l''entrée 
en vigueur du présent décret est réputé nommé ou engagé à titre définitif à 
partir du 26 août 2024, s''il échet, dans la fonction nouvelle correspondante 
portant le même intitulé ou résultant d''une fusion ou d''un changement 
d''intitulé selon le tableau de correspondance repris en annexe 1redu présent 
décret. 
 
§2. Dans le cas d''un maintien, d''une fusion ou d''un changement d''intitulé 
de fonction, les services rendus dans la fonction antérieure à l''entrée en 
vigueur du présent décret par le membre du personnel temporaire, sont 
réputés l''avoir été dans la fonction nouvelle correspondante selon le tableau de 
correspondance repris en annexe 1redu présent décret. 
 
Dans ce cadre, pour l''année scolaire 2024-2025, les membres du personnel 
ayant introduit leur candidature pour les fonctions antérieures à l''entrée en 
vigueur du présent décret sont réputés l''avoir fait pour les fonctions nouvelles 
dans les formes et délais.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 24, 'Article 23. - §1er. Dans le cas où l''application du présent décret entraine', 'Article 23. - §1er. Dans le cas où l''application du présent décret entraine 
une scission de fonction, le membre du personnel nommé ou engagé à titre 
définitif au 26 août 2024 dans une fonction telle qu''elle existait avant l''entrée 
en vigueur du présent décret, est réputé nommé ou engagé à titre définitif à 
partir du 26 août 2024, dans chacune des nouvelles fonctions correspondantes 
sur base du tableau de correspondance repris en annexe du présent décret si 
le membre du personnel dispose d''un titre de capacité requis ou jugé suffisant 
pour cette ou ces nouvelles fonctions ou si le membre du personnel a 
effectivement dispensé l''instrument de musique ou la spécialité dans le 
pouvoir organisateur concerné avant le 26 août 2024 durant 150 jours pour 
l''enseignement officiel subventionné et durant 180 jours pour l''enseignement 
libre subventionné, calculés selon les modalités propres à chaque statut. 
L''application de cette disposition ne peut toutefois avoir pour effet de modifier 
le volume de charge global dont le membre du personnel bénéficiait à titre 
définitif à la veille de l''entrée en vigueur du présent décret. 
 
§2. Dans le cas d''une scission de fonction, les services rendus dans la 
fonction antérieure à l''entrée en vigueur du présent décret par le membre du 
personnel temporaire, sont réputés l''avoir été dans chacune des nouvelles 
fonctions correspondantes sur base du tableau de correspondance repris à 
l''annexe 1redu présent décret si le membre du personnel dispose d''un titre de 
capacité requis ou jugé suffisant pour cette ou ces nouvelles fonctions ou si le 
membre du personnel a effectivement dispensé l''instrument de musique ou la 
spécialité dans le pouvoir organisateur concerné avant le 26 août 2024 durant 
150 jours pour l''enseignement officiel subventionné et durant 180 jours pour 
 
 
Docu 51784 
 
D. 21-09-2023  
Version initiale au 19/01/2024 
l''enseignement libre subventionné, calculés selon les modalités propres à 
chaque statut. 
 
Dans ce cadre, pour l''année scolaire 2024-2025, les membres du personnel 
ayant introduit leur candidature pour les fonctions antérieures à l''entrée en 
vigueur du présent décret sont réputés l''avoir fait pour les fonctions nouvelles 
dans les formes et délais.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 25, 'Article 24. - Les membres du personnel nommés ou engagés à titre', 'Article 24. - Les membres du personnel nommés ou engagés à titre 
définitif pour une charge à prestation incomplète conservent, dans la ou les 
nouvelle(s) fonction(s), le bénéfice du droit à étendre leur charge conformément 
aux dispositions statutaires dont ils relèvent. 
 
Les membres du personnel temporaires prioritaires conservent la 
possibilité d''être nommés ou engagés à titre définitif ainsi que d''être désignés 
ou engagés en qualité de temporaires prioritaires dans la ou les nouvelle(s) 
fonction(s), selon les conditions statutaires dont ils relèvent.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 26, 'Article 25. - Dans le cadre des règles prévues au présent chapitre, le', 'Article 25. - Dans le cadre des règles prévues au présent chapitre, le 
membre du personnel nommé ou temporaire qui s''est vu reconnaitre une 
expérience utile pour une fonction avant le 26 août 2024 conserve le bénéfice 
de cette reconnaissance dans l''exercice de sa (ses) nouvelle(s) fonction(s) sur 
base du tableau de correspondance repris à l''annexe du présent décret.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 27, 'Article 26. - Les membres du personnel réputés nommés ou engagés à', 'Article 26. - Les membres du personnel réputés nommés ou engagés à 
titre définitif ou temporaires prioritaires bénéficient de l''échelle de traitement 
attachée à leur(s) nouvelle(s) fonction(s) conformément au tableau de 
correspondance figurant à l''annexe du présent décret, sauf si l''échelle de 
traitement afférente à leur fonction d''origine leur procure une rémunération 
plus élevée.');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 28, 'Article 27. - Les membres du personnel réputés nommés ou engagés à', 'Article 27. - Les membres du personnel réputés nommés ou engagés à 
titre définitif ou temporaires prioritaires qui ont bénéficié des mesures 
transitoires visées par l''article 32 du décret du 10 janvier 2019 modifiant le 
décret du 02 juin 1998 organisant l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française et qui, pour l''une 
des nouvelles fonctions, bénéficient de l''échelle de traitement visées à l''article 
2, point 3, a), alinéa 2, de l''arrêté du Gouvernement de la Communauté 
française du 25 juin 1998 fixant les échelles de traitement des membres du 
personnel directeur et enseignant et du personnel auxiliaire d''éducation de 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française, bénéficient de cette échelle de traitement pour toutes 
les nouvelles fonctions issues de la fonction telle qu''elle existait avant l''entrée 
en vigueur du décret du 10 janvier 2019 précité, sur base du tableau de 
correspondance repris en annexe de ce décret et intitulé « Des fonctions issues 
de la scission d''anciennes fonctions ».');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content) VALUES ('51784', 29, 'Article 28. - Le présent décret produit ses effets le 28 août 2023, à (partie 1)', 'Article 28. - Le présent décret produit ses effets le 28 août 2023, à l''exception des mesures suivantes qui entrent en vigueur le 26 août 2024 : - les articles 5 à 7, 14, 16, 17 et 22 à 26 ; - l''article 18, à l''exception des points a) et m), qui produisent leurs effets en même temps que le présent décret ; Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 - dans l''article 20, les points 1° à 3° de l''article 108 du décret du 02 juin 1998 organisant l''enseignement secondaire artistique à horaire réduit subventionné par la Communauté française, tel que modifié, qui produisent leurs effets en même temps que le présent décret. Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur belge. Bruxelles, le 21 septembre 2023. Le Ministre-Président, en charge des Relations internationales, des Sports et de l''Enseignement de Promotion sociale P.-Y. JEHOLET Le Vice-Président et Ministre du Budget, de la Fonction publique, de l''Egalité des Chances et de la Tutelle su Wallonie-Bruxelles Enseignement F. DAERDEN La Vice-Présidente et Ministre de l''Enfance, de la Santé, de la Culture, des Médias et des Droits des Femmes B. LINARD La Ministre de l''Enseignement supérieur, de la Recherche scientifique, des Hôpitaux universitaires, de l''Aide à la Jeunesse, des Maisons de Justice, de la Jeunesse et de la Promotion de Bruxelles, F. BERTIEAUX La Ministre de l''Education, C. DESIR Docu 51784 D. 21-09-2023 Version initiale au 19/01/2024 ANNEXE Domaine des arts plastiques, visuels et de l’espace Fonctions fusionnées Situation ancienne : professeur : Situation nouvelle : professeur : de techniques artistiques pour chacune des spécialités suivantes : de techniques artistiques - dessin technique - technologie de la photographie - technologie du verre - technologie des métaux de volum